INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いちゃった…\nそうだ。騎士クンも\n一緒にお昼食べない？", 0, 2, 2, 2, 1, 1, 100202, 90);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\nそろそろ寝なくちゃ\nおやすみなさい", 0, 3, 3, 2, 1, 1, 100202, 91);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よし…\nこれなら\n褒めてもらえるかな？", 0, 1, 0, 3, 1, 1, 100202, 92);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("がんばることも\n必要だけど\nお休みも大切だよね", 0, 2, 0, 3, 1, 1, 100202, 93);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい～♪\n騎士クンは\nこういうのって好き？", 0, 3, 0, 3, 1, 1, 100202, 94);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦う前にもこうやって\n落ち着けたら\nいいのに", 0, 4, 0, 3, 1, 1, 100202, 95);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…！\nよ、良かったら\n一緒に…！", 0, 5, 0, 3, 1, 1, 100202, 96);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンと一緒に\n冒険するなら\n体力がないと…！", 0, 6, 0, 3, 1, 1, 100202, 97);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近服のサイズが\n合わないんだけど…\n食べ過ぎなのかな？", 0, 7, 0, 3, 1, 1, 100202, 98);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…やっぱり\n月刊恋愛指南は\nためになる…", 0, 8, 0, 3, 1, 1, 100202, 99);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("装備の手入れでも\nしようかな…", 0, 1, 0, 1, 1, 1, 100301, 101);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次に鍛えるべきは\n肉体面か精神面か\nどちらにしよう…？", 0, 2, 0, 1, 1, 1, 100301, 102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツムギが作ってくれた\nこの服…一体\nいつサイズを…？", 0, 3, 0, 1, 1, 1, 100301, 103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間なんていらない\nそう思ってた頃も\nあったな…", 0, 4, 0, 1, 1, 1, 100301, 104);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("考えごとをしていると\nつい部屋中を\n歩いてしまうな", 0, 5, 0, 1, 1, 1, 100301, 105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼は\nどこまで強くなるのか\n私も負けられないな", 0, 101, 0, 1, 4, 1, 100301, 106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が一本を取られる\nなんてね…願い事は\nもう決まったのかな？", 0, 102, 0, 1, 8, 1, 100301, 107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、キミだったのか\n人の気配がしたから\n誰かと思ったよ", 0, 1, 0, 2, 1, 1, 100301, 108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("斬りかかるつもりなら\nちゃんとかかってきて\n…呼んだだけ？", 0, 2, 0, 2, 1, 1, 100301, 109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに？　私に相談？\n戦いについてなら\n喜んで", 0, 3, 0, 2, 1, 1, 100301, 110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今のが突き？\n軽い！　もっと鋭く！\nさあ、もう一回！", 0, 4, 0, 2, 1, 1, 100301, 111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっ！　ど、どこを\n触ってるの！？\n…油断した", 0, 101, 0, 2, 4, 1, 100301, 112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミにはこれからも\n私のそばに…\nいや、なんでもない", 0, 102, 0, 2, 8, 1, 100301, 113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう\n今日も充実した\n一日にしていこう", 0, 1, 1, 2, 1, 1, 100301, 114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ\nお茶の時間か\nキミも一緒にどう？", 0, 2, 2, 2, 1, 1, 100301, 115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遅くまで大変だね\nまだ仕事があるなら\n手伝おうか？", 0, 3, 3, 2, 1, 1, 100301, 116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦いを経てもなお\n美しくあるように…\nこれでよし♪", 0, 1, 0, 3, 1, 1, 100301, 117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦ってばかりで\n休まないと、また\nユイに怒られるな", 0, 2, 0, 3, 1, 1, 100301, 118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒヨリみたいに\n練習相手に…\nいや、やめておこう", 0, 3, 0, 3, 1, 1, 100301, 119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはいい…\n戦いの前の精神統一に\nもってこいじゃないか", 0, 4, 0, 3, 1, 1, 100301, 120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時々は落ち着いた\n時間を過ごすのも\n悪くない…", 0, 5, 0, 3, 1, 1, 100301, 121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼に負けないよう\n私も更に強くなろう\n共に戦うために！", 0, 6, 0, 3, 1, 1, 100301, 122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事は大切だけど\n食べ過ぎには\n注意しておこう…", 0, 7, 0, 3, 1, 1, 100301, 123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユイ…！\nこ、こんな本を\n読んでいたのか…！", 0, 8, 0, 3, 1, 1, 100301, 124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海だけじゃなくて\n川でも釣りがしたいな\n道具も新調しよう", 0, 1, 0, 1, 1, 1, 100302, 126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツムギが作ってくれた\nこの服…一体\nいつサイズを…？", 0, 2, 0, 1, 1, 1, 100302, 127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼は\nどこまで強くなるのか\n私も負けられないな", 0, 3, 0, 1, 1, 1, 100302, 128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ修行の\n内容を新しくしよう\nより厳しいものにね", 0, 4, 0, 1, 1, 1, 100302, 129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強くなって…誰にも\n妨げられない自由な\n生き方がしたい", 0, 5, 0, 1, 1, 1, 100302, 130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか風邪を引くとは\n彼の看病のおかげで\nすっかり良く\nなったけど", 0, 101, 0, 1, 8, 1, 100302, 131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が一本を取られる\nなんてね…願い事は\nもう決まったのかな？", 0, 102, 0, 1, 8, 1, 100302, 132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\nなんでもない？\nそれなら良かった", 0, 1, 0, 2, 1, 1, 100302, 133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんまり突っつくと\nお返しするよ？\n覚悟は出来てる？", 0, 2, 0, 2, 1, 1, 100302, 134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、今度また\n釣りに行かない？\n大きいのを狙おう", 0, 3, 0, 2, 1, 1, 100302, 135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("修行がしたいの？\nそれを早く言ってよ\nすぐに出発しよう！", 0, 4, 0, 2, 1, 1, 100302, 136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひょっとして\n今のも一本だなんて\n言わないよね？", 0, 101, 0, 2, 8, 1, 100302, 137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミにはこれからも\n私のそばに…\nいや、なんでもない", 0, 102, 0, 2, 8, 1, 100302, 138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は仕事？\nそれとも修行？\n良ければ付き合うよ", 0, 1, 1, 2, 1, 1, 100302, 139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休息も時には\n必要だと、仲間から\n教わったよ", 0, 2, 2, 2, 1, 1, 100302, 140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遅くまで大変だね\nまだ仕事があるなら\n手伝おうか？", 0, 3, 3, 2, 1, 1, 100302, 141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("髪の長さを少し\n変えてみようかな…\nわ、私は何を…！", 0, 1, 0, 3, 1, 1, 100302, 142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休息があってこそ\n万全な状態で\n戦えるんだ", 0, 2, 0, 3, 1, 1, 100302, 143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒヨリみたいに\n練習相手に…\nいや、やめておこう", 0, 3, 0, 3, 1, 1, 100302, 144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体と同様に\n心もほぐれるね…\nはぁ…", 0, 4, 0, 3, 1, 1, 100302, 145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休む時は休む\nヒヨリもそろそろ\n覚えて欲しいな…", 0, 5, 0, 3, 1, 1, 100302, 146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼に負けないよう\n私も更に強くなろう\n共に戦うために！", 0, 6, 0, 3, 1, 1, 100302, 147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("修行のせいか\n最近食べる量が\n増えてきたような…", 0, 7, 0, 3, 1, 1, 100302, 148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユイ…！\nこ、こんな本を\n読んでいたのか…！", 0, 8, 0, 3, 1, 1, 100302, 149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お宝の予感！\n部屋中を\n探検しちゃうぞ～", 0, 1, 0, 1, 1, 1, 100401, 151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落とし穴…どこに\n作ったんだっけ？", 0, 2, 0, 1, 1, 1, 100401, 152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うえ～ん！\n…嘘泣きしたら\n相手は油断するかな", 0, 3, 0, 1, 1, 1, 100401, 153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハニートラップって\nすごく甘いお菓子で\nイタズラするのかな？", 0, 4, 0, 1, 1, 1, 100401, 154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かくれんぼする人\nこの指、と～まれ！", 0, 5, 0, 1, 1, 1, 100401, 155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギ以外の人に\nイタズラされちゃ\nダメだよ！", 0, 101, 0, 1, 4, 1, 100401, 156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギと遊ぶ？\nミソギに遊ばれる？", 0, 102, 0, 1, 8, 1, 100401, 157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいこと思いついた！\nい、イタズラとかじゃ\nないよ～", 0, 1, 0, 2, 1, 1, 100401, 158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うわっ！？\n　にいちゃんが、\nミソギにイタズラ？", 0, 2, 0, 2, 1, 1, 100401, 159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんの\n通りそうなところに\nバナナの皮を…", 0, 3, 0, 2, 1, 1, 100401, 160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんのオデコと\nホッペと鼻と目と耳に\n落書きを…", 0, 4, 0, 2, 1, 1, 100401, 161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ、ミソギ探検隊の\n基地にしようよ！", 0, 101, 0, 2, 4, 1, 100401, 162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("だ～れだ…って？\nにいちゃんの声くらい\nわかるよ！\n大好きだもん♪", 0, 102, 0, 2, 8, 1, 100401, 163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃん、おはよ！\n目覚まし時計を\n止めておいたのに、\nよく起きられたね～♪", 0, 1, 1, 2, 1, 1, 100401, 164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんが\n昼寝したら、\nイタズラし放題♪", 0, 2, 2, 2, 1, 1, 100401, 165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の探検も\nおもしろそう！\nねぇ出かけちゃダメ？", 0, 3, 3, 2, 1, 1, 100401, 166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イタズラには\nお色気も必要…\nうん、完璧！", 0, 1, 0, 3, 1, 1, 100401, 167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("座ったら、ブーッって\nいう音が出たら、\nおもしろいな～♪", 0, 2, 0, 3, 1, 1, 100401, 168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい！\nミソギ探検隊の\nマスコットにしよう♪", 0, 3, 0, 3, 1, 1, 100401, 169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸うとくしゃみが\n止まらなくなるお香を\nここに…くしゅっ！", 0, 4, 0, 3, 1, 1, 100401, 170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にひひ…イタズラの\n証拠、ここで\n燃やしちゃおう～！", 0, 5, 0, 3, 1, 1, 100401, 171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("探検家は\n体力勝負だよー！", 0, 6, 0, 3, 1, 1, 100401, 172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなに分けて\nあげようかな～\n激辛ソースも\n入れちゃうけどね！", 0, 7, 0, 3, 1, 1, 100401, 173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう所に\n宝の地図が\n隠れてるんだよね～", 0, 8, 0, 3, 1, 1, 100401, 174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お宝の予感！\n部屋中を\n探検しちゃうぞ～", 0, 1, 0, 1, 1, 1, 100402, 176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ、探検に出たい！\nじっとしてなんか\nいられないよ～！", 0, 2, 0, 1, 1, 1, 100402, 177);
