INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリン、プリン、\nプリン、プリン、\nプリン、プリン～♪", 0, 1, 0, 1, 1, 1, 100701, 251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ら～め～し～や～\nなの～♪", 0, 2, 0, 1, 1, 1, 100701, 252);
