INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツがいて、\nプリンもある。\nきっとここが天国なの", 0, 101, 0, 1, 4, 1, 100701, 256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツはプリンセス\nナイトじゃなくて\nプリンナイトなの～", 0, 102, 0, 1, 8, 1, 100701, 257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("姿を消して、オマエを\n見張ってやるの～\nむふふ～♪", 0, 1, 0, 2, 1, 1, 100701, 258);
