INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("右にプリン左にプリン\n後ろにもプリン♪\n前にはオマエなの～！", 0, 3, 0, 2, 1, 1, 100701, 260);
