INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさんオマエと\n遊べて、\n成仏しそうなくらい\nうれしいの～！", 0, 101, 0, 2, 4, 1, 100701, 262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエのこと\n気に入ったからずっと\nとり憑いてやるの～", 0, 102, 0, 2, 8, 1, 100701, 263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～　眠いの…\n二度目の二度寝を\nするの…", 0, 1, 1, 2, 1, 1, 100701, 264);
