INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクが触った瞬間に\nこの本は美を\n携えてしまうんだ", 0, 8, 0, 3, 1, 1, 100802, 349);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「第１０部２０章\n終焉戦争、開幕」\n…これでよし！", 0, 1, 0, 1, 1, 1, 100901, 351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度シグルドに\n私の魔法を一つ\n伝授してやるか", 0, 2, 0, 1, 1, 1, 100901, 352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでは風が\n吹いてこないな…\n換気したい！", 0, 3, 0, 1, 1, 1, 100901, 353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、ナナカに\nこの間借りた本を\n返さないと…", 0, 4, 0, 1, 1, 1, 100901, 354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まずは包帯をとって\n手から龍の形の\n炎を出して…", 0, 5, 0, 1, 1, 1, 100901, 355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルド…\n今頃何処で何を\nしているのだろう…", 0, 101, 0, 1, 4, 1, 100901, 356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、彼の姿が\nまぶしく見える…\nどうして…？", 0, 102, 0, 1, 8, 1, 100901, 357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("辞書を知らないか？\n…探している\n理由は聞くな", 0, 1, 0, 2, 1, 1, 100901, 358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ！\n貴様の技にも\n名前をつけてやろう！", 0, 2, 0, 2, 1, 1, 100901, 359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私に触れても力を\n奪われないのは\n貴様くらいだぞ？", 0, 3, 0, 2, 1, 1, 100901, 360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何事だ？\nまさか我が瞳に\n魅入られたのか？", 0, 4, 0, 2, 1, 1, 100901, 361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴様がそばにいると\nとても安心できる…\n…不思議だ", 0, 101, 0, 2, 4, 1, 100901, 362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("い、いきなり目の前に\n現れるな！　ドキドキ\nするだろうがぁ！", 0, 102, 0, 2, 8, 1, 100901, 363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「覚醒」めたか…\n行くぞ、悪を討つ\n戦いに出発だ！", 0, 1, 1, 2, 1, 1, 100901, 364);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼間は「ヤツら」も\n襲ってはこない…\n束の間の休息だ", 0, 2, 2, 2, 1, 1, 100901, 365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうした？　夜はまだ\nこれから…ふぁ…\nね、眠くなどないぞ！", 0, 3, 3, 2, 1, 1, 100901, 366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か足りないな…\n暗黒騎士の紋章を\n作ろうかな", 0, 1, 0, 3, 1, 1, 100901, 367);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くっ…！\n私を眠りの国へ\n誘うつもりか！", 0, 2, 0, 3, 1, 1, 100901, 368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このようなものに\n懐柔されるものか！\n…されるものか！", 0, 3, 0, 3, 1, 1, 100901, 369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを使えば\nもっとそれっぽい\n雰囲気が出そうだ", 0, 4, 0, 3, 1, 1, 100901, 370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これが我らの求めた\n安寧か…\n悪くない…", 0, 5, 0, 3, 1, 1, 100901, 371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この程度\n前世での激闘に\n比べれば…！", 0, 6, 0, 3, 1, 1, 100901, 372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近金欠でな…\nいやぁありがたい…", 0, 7, 0, 3, 1, 1, 100901, 373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにも\n前世の記憶が\n眠っていたとは…", 0, 8, 0, 3, 1, 1, 100901, 374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「第１３部１章\n閃光のシグルド」\n…ついに登場だな", 0, 1, 0, 1, 1, 1, 100902, 376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何故だ…何故\nこうもあっさり金欠に\n逆戻りするのだ！？", 0, 2, 0, 1, 1, 1, 100902, 377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やはり転生者という\n設定はカッコイイ…\n天才だな、私！", 0, 3, 0, 1, 1, 1, 100902, 378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、ナナカに\nこの間借りた本を\n返さないと…", 0, 4, 0, 1, 1, 1, 100902, 379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ今日の分の\n魔力を溜めないと\nまた魔力切れが…", 0, 5, 0, 1, 1, 1, 100902, 380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近奴がそばに\nいるだけで、鼓動が\n早くなるのは何故だ？", 0, 101, 0, 1, 1, 1, 100902, 381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シ、シグルド…！\nだめだ…妄想でも\n上手く言えない…", 0, 102, 0, 1, 8, 1, 100902, 382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ？　新たな\n賞金の情報を\n持ってきたのか？", 0, 1, 0, 2, 8, 1, 100902, 383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("名乗りやポーズは\nその強度で相手を\n圧倒する技術だ", 0, 2, 0, 2, 1, 1, 100902, 384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいか、魔法の\n詠唱中は絶対に\n声をかけるなよ？", 0, 3, 0, 2, 1, 1, 100902, 385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おお、ちょうど今\n貴様専用の設定集を\n作成中だぞ！", 0, 4, 0, 2, 1, 1, 100902, 386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴様がそばにいると\nとても安心できる…\n…不思議だ", 0, 101, 0, 2, 1, 1, 100902, 387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("い、いきなり目の前に\n現れるな！　ドキドキ\nするだろうがぁ！", 0, 102, 0, 2, 8, 1, 100902, 388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしのせいか\nまだ眠気が…いや！\nこれは組織の罠だ！", 0, 1, 1, 2, 8, 1, 100902, 389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("平穏な時に\n出来るだけ魔力を\n溜めておかねば…", 0, 2, 2, 2, 1, 1, 100902, 390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜になると、力が\n増した気分になるな\n…なりませんか？", 0, 3, 3, 2, 1, 1, 100902, 391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か足りないな…\n暗黒騎士の紋章を\n作ろうかな", 0, 1, 0, 3, 1, 1, 100902, 392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、おのれ\nヒュプノス…\n私は負けないぞ…", 0, 2, 0, 3, 1, 1, 100902, 393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くっくっくっ…\n貴様は特別団員に\nしてやろう", 0, 3, 0, 3, 1, 1, 100902, 394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを使えば\nもっとそれっぽい\n雰囲気が出そうだ", 0, 4, 0, 3, 1, 1, 100902, 395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これが我らの求めた\n安寧か…\n悪くない…", 0, 5, 0, 3, 1, 1, 100902, 396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新たな戦いに備えて\n魔力だけでなく\n体力も鍛えねば！", 0, 6, 0, 3, 1, 1, 100902, 397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事は魔力に\n変換する体力の\n元になるのだ！", 0, 7, 0, 3, 1, 1, 100902, 398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フフフ…\nこれを覚えれば\nもっと強く…！", 0, 8, 0, 3, 1, 1, 100902, 399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんほんまに\nはんなりしてて、\n王子はんって感じやわ", 0, 1, 0, 1, 1, 1, 101001, 401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この絵本の王子はん、\n王子はんみたいで\nええなぁ♪", 0, 2, 0, 1, 1, 1, 101001, 402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちがガラスの靴を\n落としたら、王子はん\n見つけてくれるやろか", 0, 3, 0, 1, 1, 1, 101001, 403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホマホ王国\n次期国王の王子はん\n…見てみたいわ～", 0, 4, 0, 1, 1, 1, 101001, 404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんのために\n糸を紡いで、\n編み物でもしまひょか", 0, 5, 0, 1, 1, 1, 101001, 405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホ姫と王子はん、\n絵本の世界より\nベストカップルや", 0, 101, 0, 1, 4, 1, 101001, 406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんと\n一緒にいると\n胸がせわしのー\nうごいてかなん", 0, 102, 0, 1, 8, 1, 101001, 407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちら並んでたら\nお雛様みたいに\n見えると思いまへん？", 0, 1, 0, 2, 1, 1, 101001, 408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんを\n国に連れて帰ったら\nみんな大歓迎して\nくれるやろなぁ", 0, 2, 0, 2, 1, 1, 101001, 409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんは、\n絵本から出てきた人\nみたいやね～", 0, 3, 0, 2, 1, 1, 101001, 410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの話し方\nのんびりしてます\nやろか？", 0, 4, 0, 2, 1, 1, 101001, 411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホ姫の手は\nつべたいから、\n王子はんが温めて？", 0, 101, 0, 2, 4, 1, 101001, 412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちがもし悪い魔法に\nかかったら、王子はん\n口づけしてくれはる？", 0, 102, 0, 2, 8, 1, 101001, 413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は小鳥はんも\nおなかがすいてるから\nよう飛び回りはるねえ", 0, 1, 1, 2, 1, 1, 101001, 414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お茶請けはお大福が\nよろしおすけど\nクッキーもええなあ", 0, 2, 2, 2, 1, 1, 101001, 415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うち、普段から\n夢見がちやけど…\nほんに眠い時間やわぁ", 0, 3, 3, 2, 1, 1, 101001, 416);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんに\n会いに行くなら、\nおめかしせな\nあかんなぁ", 0, 1, 0, 3, 1, 1, 101001, 417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はんなりした\nええお椅子やわぁ\nほっこりしますなあ", 0, 2, 0, 3, 1, 1, 101001, 418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かいらしもんが\nいっぱいで、\nマホマホ王国みたい\nやわぁ", 0, 3, 0, 3, 1, 1, 101001, 419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心地ええどす。まるで\nお花畑にいるようやね", 0, 4, 0, 3, 1, 1, 101001, 420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかどす。\n心まであったかく\nなりますわぁ", 0, 5, 0, 3, 1, 1, 101001, 421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁはぁ、お姫はんは\n激しい運動は\nしぃひんもんどす～", 0, 6, 0, 3, 1, 1, 101001, 422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…あんまり\n速う食べられへんけど\n美味しいわぁ", 0, 7, 0, 3, 1, 1, 101001, 423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵本、絵本～\n幸せやわぁ♪", 0, 8, 0, 3, 1, 1, 101001, 424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんにとって\n自慢の姫になるえ～", 0, 1, 0, 1, 1, 1, 101002, 426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャの馬車に\nガラスの靴…\n欲しいなぁ", 0, 2, 0, 1, 1, 1, 101002, 427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちがガラスの靴を\n落としたら、王子はん\n見つけてくれるやろか", 0, 3, 0, 1, 1, 1, 101002, 428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホマホ王国\n次期国王の王子はん\n…見てみたいわ～", 0, 4, 0, 1, 1, 1, 101002, 429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほんまなぁ\nこの絵本が面白いんよ\n王子はんに\n読んであげよ", 0, 5, 0, 1, 1, 1, 101002, 430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホ姫と王子はん\n絵本の世界より\nベストカップルや", 0, 101, 0, 1, 8, 1, 101002, 431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんと\n一緒にいると\n胸がせわしのー\nうごいてかなん", 0, 102, 0, 1, 8, 1, 101002, 432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには、王子はんの\n好きな絵本も\n知りたいな～", 0, 1, 0, 2, 1, 1, 101002, 433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんを\n国に連れて帰ったら\nみんな大歓迎して\nくれるやろなぁ", 0, 2, 0, 2, 1, 1, 101002, 434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そのうち、王子はんの\nお国にも連れてって\nもらえますやろか？", 0, 3, 0, 2, 1, 1, 101002, 435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵本読むんも\nええなぁ…", 0, 4, 0, 2, 1, 1, 101002, 436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちがもし悪い魔法に\nかかったら、王子はん\n口づけしてくれはる？", 0, 101, 0, 2, 8, 1, 101002, 437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちら並んでたら\nお雛様みたいに\n見えると思いまへん？", 0, 102, 0, 2, 8, 1, 101002, 438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は小鳥はんも\nおなかがすいてるから\nよう飛び回りはるねえ", 0, 1, 1, 2, 1, 1, 101002, 439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホマホ王国では\nこの時分は\nみんなお昼寝\nしてたんよ", 0, 2, 2, 2, 1, 1, 101002, 440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜に飛んだり鳴いたり\nする鳥はんもおるんよ\n昼は寝てはるんかねぇ", 0, 3, 3, 2, 1, 1, 101002, 441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんに\n会いに行くなら\nおめかしせな\nあかんなぁ", 0, 1, 0, 3, 1, 1, 101002, 442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんも一緒に\nゆっくりしていっても\nええんよ？", 0, 2, 0, 3, 1, 1, 101002, 443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かいらしい子やねぇ\nうちとお友だちに\nなってくれるん？", 0, 3, 0, 3, 1, 1, 101002, 444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("癒しアイテムって\nほんま、好っきゃわぁ", 0, 4, 0, 3, 1, 1, 101002, 445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちのお城にも\nほしいわぁ。帰ったら\nさっそく準備せな\nあかんなぁ", 0, 5, 0, 3, 1, 1, 101002, 446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の中で運動\nできるのも、なかなか\n面白いもんやわぁ", 0, 6, 0, 3, 1, 1, 101002, 447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいひいわ～\nマホマホ王国には\nない味やわぁ", 0, 7, 0, 3, 1, 1, 101002, 448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり知識を\n身につけんと\n魔法も使えへん\nからなぁ", 0, 8, 0, 3, 1, 1, 101002, 449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("１、２、３、４…\nあれ？　いま、\n何段目まで\n編んだっけ？", 0, 1, 0, 1, 1, 1, 101101, 451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやつのケーキは\n苺かチョコ…\nどっちも食べよう！", 0, 2, 0, 1, 1, 1, 101101, 452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("い、いけない！\n縫い針落としちゃった", 0, 3, 0, 1, 1, 1, 101101, 453);
