INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリームついてた！？\nさっき食べた、\nケーキかも…！", 0, 2, 0, 2, 1, 1, 101101, 459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("勉強、見てくれるん\nですか？　やった～♪", 0, 3, 0, 2, 1, 1, 101101, 460);
