INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「どうだ！妹暮らし」\nってことわざ\nなかったっけ？", 0, 5, 0, 1, 1, 1, 101102, 480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんに、\nお洋服でも\n作ろうかな？", 0, 101, 0, 1, 8, 1, 101102, 481);
