INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な、ナデナデとか\n恥ずかしいな～", 0, 102, 0, 2, 8, 1, 101102, 488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も１日\n勉強がんばります！\n…少しは遊ぼうかな", 0, 1, 1, 2, 1, 1, 101102, 489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼休憩に\n甘いものが\n食べたいです～", 0, 2, 2, 2, 1, 1, 101102, 490);
