INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで寝ちゃったら\n受験勉強が～…\nぐーー", 0, 2, 0, 3, 1, 1, 101102, 493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい♪\n私が服を作って\nあげよっか？", 0, 3, 0, 3, 1, 1, 101102, 494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いまならどんな試験も\n合格できそうです！", 0, 4, 0, 3, 1, 1, 101102, 495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("のんびりしたら\nまた勉強しよっと！", 0, 5, 0, 3, 1, 1, 101102, 496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんを\n守るためには\n毎日、鍛えなくちゃ！", 0, 6, 0, 3, 1, 1, 101102, 497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいし～！\nお兄ちゃんにも\nおすそ上げしますね！", 0, 7, 0, 3, 1, 1, 101102, 498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本の服\nかわいいなぁ♪\n私に作れるかな？", 0, 8, 0, 3, 1, 1, 101102, 499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、今なら\nどこでだって\n眠れちゃいそう…", 0, 1, 0, 1, 1, 1, 101201, 501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさん寝すぎて、\n夢の中か現実か\nわかんなく\nなっちゃうんだよね～", 0, 2, 0, 1, 1, 1, 101201, 502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…はっ！？\nね、寝てないよ？\nホントだよっ", 0, 3, 0, 1, 1, 1, 101201, 503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐっすり眠って\nパワーを\nフルチャージっ☆", 0, 4, 0, 1, 1, 1, 101201, 504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし、超能力のことが\nバレたら…ブルブル", 0, 5, 0, 1, 1, 1, 101201, 505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テレパシーで\nキミの心を覗けたら\n…なんてね！", 0, 101, 0, 1, 4, 1, 101201, 506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミを抱き枕に…\nじょ、冗談冗談！", 0, 102, 0, 1, 8, 1, 101201, 507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、なになに？\n一緒にお昼寝する？", 0, 1, 0, 2, 1, 1, 101201, 508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("忘れ物しちゃった。\nま、いっか！\nえ、ダメ？", 0, 2, 0, 2, 1, 1, 101201, 509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおっ、相談ごと？\nなにかな\nなにかな～？", 0, 3, 0, 2, 1, 1, 101201, 510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、もしかして\nキミにも仲良しになる\n超能力があるのかも！", 0, 4, 0, 2, 1, 1, 101201, 511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむ～…どう？\nテレパシーで、私の\n気持ちを送ったよ！", 0, 101, 0, 2, 4, 1, 101201, 512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えっ？　私とキミとの\n相性？　むむ～…\nうん、バッチリだよ☆", 0, 102, 0, 2, 8, 1, 101201, 513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだこんな時間？\nベッドに行って、\n二度寝しなくちゃ～", 0, 1, 1, 2, 1, 1, 101201, 514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適度なお昼寝は\n健康にいいんだって！\n８時間くらいかな？", 0, 2, 2, 2, 1, 1, 101201, 515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなにお昼寝しても\n夜は眠いんだ～", 0, 3, 3, 2, 1, 1, 101201, 516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、また寝癖…\nいっつも\n寝てるからかなぁ？", 0, 1, 0, 3, 1, 1, 101201, 517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一休み、一休み…\nどうせなら百休み\nくらいしようかな…", 0, 2, 0, 3, 1, 1, 101201, 518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ…可愛い！\nシオリンに\n届けてあげたい！", 0, 3, 0, 3, 1, 1, 101201, 519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～…気分爽快！\nそれじゃ、おやすみ～\n…すやぁ…", 0, 4, 0, 3, 1, 1, 101201, 520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいい…\nはっ！　ダメダメ！\nまた寝るとこだった！", 0, 5, 0, 3, 1, 1, 101201, 521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠くならないように、\n運動しよっと！", 0, 6, 0, 3, 1, 1, 101201, 522);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹いっぱいになると\n眠くなるよね～", 0, 7, 0, 3, 1, 1, 101201, 523);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("睡眠学習って\n本を読みながら\n寝るんだっけ？", 0, 8, 0, 3, 1, 1, 101201, 524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、今なら\nどこでだって\n眠れちゃいそう…", 0, 1, 0, 1, 1, 1, 101202, 526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっといっぱい\n超能力使えたら\nいいのにな～", 0, 2, 0, 1, 1, 1, 101202, 527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえねえ、\n今から人助け、\n付き合ってほしいなー", 0, 3, 0, 1, 1, 1, 101202, 528);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐっすり眠って\nパワーを\nフルチャージっ☆", 0, 4, 0, 1, 1, 1, 101202, 529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人助け、頑張ったら\nなんだか、眠く…\n…はっ、ダメダメ！", 0, 5, 0, 1, 1, 1, 101202, 530);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒なら、\nなんだって出来る！\n間違いない！", 0, 101, 0, 1, 8, 1, 101202, 531);
