INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("忘れ物しちゃった\nま、いっか！\nえ、ダメ？", 0, 1, 0, 2, 1, 1, 101202, 533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに？　困ってる？\nちょうど良かった！\n今は体力満タンだよ☆", 0, 2, 0, 2, 1, 1, 101202, 534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に\nお出かけしたいなー\nデートしよっ！", 0, 3, 0, 2, 1, 1, 101202, 535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うんうん、そうだねっ\n困ってる人がいたら\n見過ごせないよねっ！", 0, 4, 0, 2, 1, 1, 101202, 536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむ～…どう？\nテレパシーで、私の\n気持ちを送ったよ！", 0, 101, 0, 2, 8, 1, 101202, 537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～だんだん眠く…\nねぇ一緒に寝よ？", 0, 102, 0, 2, 8, 1, 101202, 538);
