INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\n声出しして、お芝居の\n練習しなくちゃ", 0, 1, 1, 2, 1, 1, 102102, 789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お茶にしますか？\nクッキー焼いたので、\nよかったら…", 0, 2, 2, 2, 1, 1, 102102, 790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝る前に\n台本を読むと、\n覚えやすいんです", 0, 3, 3, 2, 1, 1, 102102, 791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い女の子に変身！\n出来ますように…♪", 0, 1, 0, 3, 1, 1, 102102, 792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぅ…\nフッカフカァ…\n癒されちゃいます…", 0, 2, 0, 3, 1, 1, 102102, 793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子を相手に\n演技の練習～", 0, 3, 0, 3, 1, 1, 102102, 794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リボンや服に\n染み込ませておこう\nいつでもいい匂い♪", 0, 4, 0, 3, 1, 1, 102102, 795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ\nぽっかぽかです…", 0, 5, 0, 3, 1, 1, 102102, 796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、演劇には\nた、体力も重要\nだから～", 0, 6, 0, 3, 1, 1, 102102, 797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("残さず\n食べますね…！", 0, 7, 0, 3, 1, 1, 102102, 798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戯曲を読んで\n自分が演じるところを\n想像するの…", 0, 8, 0, 3, 1, 1, 102102, 799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、人見知りを\n治すための練習に\n付き合ってくれない？", 0, 1, 0, 1, 1, 1, 102201, 801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリみたいに\nかわいくなるには、\nどうすればいいのかな", 0, 2, 0, 1, 1, 1, 102201, 802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レアカードをゲット！\nねえねえ、\nすごいでしょ！？", 0, 3, 0, 1, 1, 1, 102201, 803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ア、アイツと同じ\n部屋にいるのよね…\nって、だから何よ！？", 0, 4, 0, 1, 1, 1, 102201, 804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽しいゲームって\nやめどきが\n見つからないわ", 0, 5, 0, 1, 1, 1, 102201, 805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっと女の子らしく\nなったらアイツも\n嬉しいかな…って、\n何考えてるの！？", 0, 101, 0, 1, 4, 1, 102201, 806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ…最近、\nアイツを見るとなんか\nドキドキするのよね", 0, 102, 0, 1, 8, 1, 102201, 807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゲームに負けた罰\nだからって、\nくすぐるのは…\nあはは…ダメだって！", 0, 1, 0, 2, 1, 1, 102201, 808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタと話すのは割と\n緊張しないのよね\n…なんでかな", 0, 2, 0, 2, 1, 1, 102201, 809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("待ちきれない…\n新作ゲームの発売日が\n待ちきれない…", 0, 3, 0, 2, 1, 1, 102201, 810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタは人見知り\nしないタチよね？\nいいなあ～…", 0, 4, 0, 2, 1, 1, 102201, 811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ア、アンタってさ\n好きな人とかい…\nなな、何でもない！", 0, 101, 0, 2, 4, 1, 102201, 812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタと…そ、その\nこうして話してるのも\nわわ、悪くないわね！", 0, 102, 0, 2, 8, 1, 102201, 813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおおおはよう！\n…よし！　ちゃんと\nあいさつできたわ！", 0, 1, 1, 2, 1, 1, 102201, 814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にごはんとか…\nううん、やっぱいい！\nなんでもないからっ！", 0, 2, 2, 2, 1, 1, 102201, 815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜はこれからよ！\n朝まで\nゲームするからね！", 0, 3, 3, 2, 1, 1, 102201, 816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリみたいに\n可愛くなるのは\n難しいかな", 0, 1, 0, 3, 1, 1, 102201, 817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝っ転がりながら\nゲームができれば\n気分が良さそう", 0, 2, 0, 3, 1, 1, 102201, 818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い…けど、\n私には似合わないかな", 0, 3, 0, 3, 1, 1, 102201, 819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ、リラックスして\nゲームができるわ", 0, 4, 0, 3, 1, 1, 102201, 820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん…暖かくて、\n寝落ちしちゃいそう", 0, 5, 0, 3, 1, 1, 102201, 821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゲーム感覚でやると、\n体動かすのも\n楽しいわね", 0, 6, 0, 3, 1, 1, 102201, 822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゲームは頭使うから\nそのぶん\n栄養がいるのよ", 0, 7, 0, 3, 1, 1, 102201, 823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ、なるほど\n友だちを作るには\n笑顔が大事っと…", 0, 8, 0, 3, 1, 1, 102201, 824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、今日は\n何のゲームで\n遊ぼうかな？", 0, 1, 0, 1, 1, 1, 102202, 826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にゲームができる\n人がいるっていうのも\n新鮮だな…", 0, 2, 0, 1, 1, 1, 102202, 827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レアカードをゲット！\nすごいでしょ！？", 0, 3, 0, 1, 1, 1, 102202, 828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリってどうやって\n友達作ってるんだろ？\nコツがあるのかな…", 0, 4, 0, 1, 1, 1, 102202, 829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽しいゲームって\nやめどきが\n見つからないわ", 0, 5, 0, 1, 1, 1, 102202, 830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ…最近\nアイツを見るとなんか\nドキドキするのよね", 0, 101, 0, 1, 8, 1, 102202, 831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、ねえ\nもう少しその…\n一緒にゲームしない？", 0, 102, 0, 1, 8, 1, 102202, 832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、人見知りを\n治すための練習に\n付き合ってくれない？", 0, 1, 0, 2, 1, 1, 102202, 833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("欲しいゲームが\n見つからなくて…\n探すの手伝って！", 0, 2, 0, 2, 1, 1, 102202, 834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、見て！\n新しいゲームを\n買って来たの！", 0, 3, 0, 2, 1, 1, 102202, 835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゲームに負けた罰\nだからって、くすぐる\nのは…あ、あはは！\nだ、ダメだって！", 0, 4, 0, 2, 1, 1, 102202, 836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ア、アンタってさ\n好きな人とかい…\nなな、何でもない！", 0, 101, 0, 2, 8, 1, 102202, 837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あのさ…\nもう少し、そこに\nいてくれてもいいわよ", 0, 102, 0, 2, 8, 1, 102202, 838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおおおはよう！\n…よし！　ちゃんと\nあいさつできたわ！", 0, 1, 1, 2, 1, 1, 102202, 839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にごはんとか…\nううん、やっぱいい！\nなんでもないからっ！", 0, 2, 2, 2, 1, 1, 102202, 840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜はこれからよ！\n朝まで\nゲームするからね！", 0, 3, 3, 2, 1, 1, 102202, 841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっと女の子らしく\nなったらアイツも\n嬉しいかな…って、\n何考えてるの！？", 0, 1, 0, 3, 1, 1, 102202, 842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふああ…\n徹夜明けには\n辛い誘惑だな…", 0, 2, 0, 3, 1, 1, 102202, 843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い…けど、\n私には似合わないかな", 0, 3, 0, 3, 1, 1, 102202, 844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのに詳しいと\n女の子っぽく\n見えたりするのかな", 0, 4, 0, 3, 1, 1, 102202, 845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い日は\nここでゲームするのが\n最高のぜいたくよね", 0, 5, 0, 3, 1, 1, 102202, 846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近ゲームばかりだし\nたまにはいいかな？", 0, 6, 0, 3, 1, 1, 102202, 847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゲームは頭使うから\nそのぶん\n栄養がいるのよ", 0, 7, 0, 3, 1, 1, 102202, 848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ、なるほど\n友だちを作るには\n笑顔が大事っと…", 0, 8, 0, 3, 1, 1, 102202, 849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じゃんけんぽん！\nあっち向いてほい！\nあ～ん、負けたぁ\n　『勝ったぜ！』", 0, 1, 0, 1, 1, 1, 102301, 851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちがいれば、\nなんでも出来ちゃうよ", 0, 2, 0, 1, 1, 1, 102301, 852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("発声練習しよっと\nぷうきち\nフルスイ～ング！", 0, 3, 0, 1, 1, 1, 102301, 853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで、ぷうきち\nフルスイングは、\nまずいかな～？", 0, 4, 0, 1, 1, 1, 102301, 854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋、ぷうきちを\n置く場所はないのかな", 0, 5, 0, 1, 1, 1, 102301, 855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんって…\nちょっとぷうきちに\n似てるかも♪", 0, 101, 0, 1, 4, 1, 102301, 856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんにも、\nぷうきちのこと\n好きになって\nもらいたいな～", 0, 102, 0, 1, 8, 1, 102301, 857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやつは、\n私とぷうきちの\n二人分用意してね♪", 0, 1, 0, 2, 1, 1, 102301, 858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちが、お腹\nペコペコだって～\n何かちょうだい！", 0, 2, 0, 2, 1, 1, 102301, 859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『アヤネに手出したら\n…坊ちゃんでも、\n分かってんな？』", 0, 3, 0, 2, 1, 1, 102301, 860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちとの\n連携を磨いてるの！\nもっと仲良くなるよ！", 0, 4, 0, 2, 1, 1, 102301, 861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特別だからね？\nもっと触っていいよ\n…ぷうきちのこと", 0, 101, 0, 2, 4, 1, 102301, 862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんのこと、\n「ぷう兄」って\n呼ぼうかな？", 0, 102, 0, 2, 8, 1, 102301, 863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんって\n朝早いんだね～\n私はまだ眠いよ～", 0, 1, 1, 2, 1, 1, 102301, 864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～…ぷうきちと\nお昼寝してくるね…", 0, 2, 2, 2, 1, 1, 102301, 865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちと\nおしゃべりしてたら\nもうこんな時間…", 0, 3, 3, 2, 1, 1, 102301, 866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『座り心地がいいな』\nぷうきちは座れない\nでしょ？", 0, 2, 0, 3, 1, 1, 102301, 868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい～！\nぷうきちのお友達に\nしちゃおうかな？", 0, 3, 0, 3, 1, 1, 102301, 869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいニオイ～♪\nぷうきちも\n気に入ったみたい！", 0, 4, 0, 3, 1, 1, 102301, 870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽわぽわする～\nぷうきちも\n気持ちいい？", 0, 5, 0, 3, 1, 1, 102301, 871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい～\nぷうきちも\n食べてみる？", 0, 7, 0, 3, 1, 1, 102301, 873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきち！\nこの本、読んで～！", 0, 8, 0, 3, 1, 1, 102301, 874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうして失敗ばっかり\nこうなったら\n腹を切るしか～！", 0, 1, 0, 1, 1, 1, 102501, 901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ？　あれ？\nお部屋の中で迷子に\nなっちゃいました～", 0, 2, 0, 1, 1, 1, 102501, 902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたら転ばなく\nなるんでしょうか？", 0, 3, 0, 1, 1, 1, 102501, 903);
