INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様が寝ている時\n私は…クスクス\nこれ以上は言えません", 0, 4, 0, 2, 1, 1, 102702, 986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("想像の中のあなた様は\nすっかり私の虜なのに\n現実は…\nもどかしいですわね", 0, 101, 0, 2, 8, 1, 102702, 987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様の前では\n普通の女の子…\n少し毒薬づくりが\n得意なだけの…", 0, 102, 0, 2, 8, 1, 102702, 988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n一晩中、あなた様の\n寝顔を見ていましたわ", 0, 1, 1, 2, 1, 1, 102702, 989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、お食事ですよ\n味は保証しますわ\n特製ソースで少しだけ\n体が痺れますけど…", 0, 2, 2, 2, 1, 1, 102702, 990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様が眠るまで\nお傍で見守りますわ\n…あの、どうして\n眠らないのですか？", 0, 3, 3, 2, 1, 1, 102702, 991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私ももう少し\n外見に気を配る\nべきでしょうか…", 0, 1, 0, 3, 1, 1, 102702, 992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はっ！\nリラックスしたら\n閃きましたわ！", 0, 2, 0, 3, 1, 1, 102702, 993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この私を差し置いて\nあなた様に媚びるなど\n言語道断…っ！", 0, 3, 0, 3, 1, 1, 102702, 994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお部屋は\n良い香りがしますわ\nはっ、あなた様の匂い\nなのでは…！？", 0, 4, 0, 3, 1, 1, 102702, 995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵なぬくもり…\nまるであの方に\n抱きしめられたような", 0, 5, 0, 3, 1, 1, 102702, 996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この運動エネルギー\n何かにうまく\n利用できないかしら？", 0, 6, 0, 3, 1, 1, 102702, 997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しい。あの方にも\n差し上げましょう…\n薬を入れて…", 0, 7, 0, 3, 1, 1, 102702, 998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの方を虜にする\n方法がどこかに\n載ってるはずですわ", 0, 8, 0, 3, 1, 1, 102702, 999);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子供たちの遊びって\nあたしが子供の頃と\nあまり変わらないのね", 0, 1, 0, 1, 1, 1, 102801, 1001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("使えるものは\n再利用しないと\n…あ、これとか\nまだ使えるわね", 0, 2, 0, 1, 1, 1, 102801, 1002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("贅沢は敵！　とはいえ\n気持ちに余裕のない\n暮らしはダメよね", 0, 3, 0, 1, 1, 1, 102801, 1003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いたわね、\n残り物で\n何か作ろうかしら", 0, 4, 0, 1, 1, 1, 102801, 1004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("商売はノンゼロサムが\n理想だなぁ。誰も損を\nしないってことだもの", 0, 5, 0, 1, 1, 1, 102801, 1005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが手伝って\nくれるから、仕事も\n前より楽しいのよね♪", 0, 101, 0, 1, 4, 1, 102801, 1006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("焼きそばパンが\n食べたいな～\nあいつと…", 0, 102, 0, 1, 8, 1, 102801, 1007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇあんた、どこか\n安いお店知らない？", 0, 1, 0, 2, 1, 1, 102801, 1008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたし、エレガントに\n振る舞えてる？\n…そう？　嬉しい♪", 0, 2, 0, 2, 1, 1, 102801, 1009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい働いて遊んで\nよく休んでまた働く。\nそれが健全な生活よね", 0, 3, 0, 2, 1, 1, 102801, 1010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に部屋の\n整頓でもする？\nハマると楽しいわよ♪", 0, 4, 0, 2, 1, 1, 102801, 1011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたがいると\n子供たちも喜ぶわ♪\nもちろんあたしもね！", 0, 101, 0, 2, 4, 1, 102801, 1012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、あんた今、幸せ？\n何びっくりしてるのよ\n大事なことじゃないの", 0, 102, 0, 2, 8, 1, 102801, 1013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("面倒な用事は午前中に\n片づけてしまうのが、\n時間の使い方のコツよ", 0, 1, 1, 2, 1, 1, 102801, 1014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午後のティータイム\nとかどう？\n良いカフェがあるの♪", 0, 2, 2, 2, 1, 1, 102801, 1015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ、エレガントな夜を\n楽しみましょ。\nモダンな音楽でも\nかけましょうか？", 0, 3, 3, 2, 1, 1, 102801, 1016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レディたるもの\n身嗜みはしっかりとね\n見本にならないと♪", 0, 1, 0, 3, 1, 1, 102801, 1017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで仕事は一段落ね\nちょっと休憩…", 0, 2, 0, 3, 1, 1, 102801, 1018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ、\nかわいいものを\n見るのは幸せね～", 0, 3, 0, 3, 1, 1, 102801, 1019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋中がいい香り…\nなんだかすごい贅沢\nしてる気分♪", 0, 4, 0, 3, 1, 1, 102801, 1020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪を引かないように\n身体を温めなくちゃ", 0, 5, 0, 3, 1, 1, 102801, 1021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっ！　家の中でも\n効率的に\nトレーニングよ！", 0, 6, 0, 3, 1, 1, 102801, 1022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…はっ、\n口の周り、\n汚れてないわよね？", 0, 7, 0, 3, 1, 1, 102801, 1023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知識から過去を学んで\n未来に活かすわよ", 0, 8, 0, 3, 1, 1, 102801, 1024);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安売りのお店の情報\n整理しないと…", 0, 1, 0, 1, 1, 1, 102802, 1026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなに苦労してても\nそう見せないのが真の\nエレガントなレディよ", 0, 2, 0, 1, 1, 1, 102802, 1027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安く済んであいつが\n喜ぶ料理とか…\nないかしら", 0, 3, 0, 1, 1, 1, 102802, 1028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子供たちの遊びって\nあたしが子供の頃と\nあまり変わらないのね", 0, 4, 0, 1, 1, 1, 102802, 1029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("商売はノンゼロサムが\n理想だなぁ。誰も損を\nしないってことだもの", 0, 5, 0, 1, 1, 1, 102802, 1030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("焼きそばパンが\n食べたいな～\nあいつと…", 0, 101, 0, 1, 8, 1, 102802, 1031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと一緒に…\n色々なところに\nいきたいな", 0, 102, 0, 1, 8, 1, 102802, 1032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度買い物に\n付き合いなさい\nセールがあるのよ", 0, 1, 0, 2, 1, 1, 102802, 1033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたがいると子供\nたちも喜ぶわ♪\nもちろんあたしもね♪", 0, 2, 0, 2, 1, 1, 102802, 1034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい働いて遊んで\nよく休んでまた働く\nそれが健全な生活よね", 0, 3, 0, 2, 1, 1, 102802, 1035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたとこうして\nのんびりするのも\nいいものね", 0, 4, 0, 2, 1, 1, 102802, 1036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、今度遊びに\n行きたいな\nもちろん一緒に、よ", 0, 101, 0, 2, 8, 1, 102802, 1037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが手伝って\nくれるから、仕事も\n前より楽しいのよね♪", 0, 102, 0, 2, 8, 1, 102802, 1038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("面倒な用事は午前中に\n片づけてしまうのが\n時間の使い方のコツよ", 0, 1, 1, 2, 1, 1, 102802, 1039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランチにして午後の\n仕事に備えましょ！\nやることは一杯よ♪", 0, 2, 2, 2, 1, 1, 102802, 1040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ～\nもうこんな時間\n子供たちは\nもう寝たかしら", 0, 3, 3, 2, 1, 1, 102802, 1041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("忙しい時こそ\n身だしなみは隙なく\nぴしっとね！", 0, 1, 0, 3, 1, 1, 102802, 1042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで仕事は一段落ね\nちょっと休憩…", 0, 2, 0, 3, 1, 1, 102802, 1043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふふ\nずっと眺めてたく\nなっちゃうわね", 0, 3, 0, 3, 1, 1, 102802, 1044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋中がいい香り…\nなんだかすごい贅沢\nしてる気分♪", 0, 4, 0, 3, 1, 1, 102802, 1045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪を引かないように\n身体を温めなくちゃ", 0, 5, 0, 3, 1, 1, 102802, 1046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっ！　家の中でも\n効率的に\nトレーニングよ！", 0, 6, 0, 3, 1, 1, 102802, 1047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり食べて\n栄養補給、栄養補給！", 0, 7, 0, 3, 1, 1, 102802, 1048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知識から過去を学んで\n未来に活かすわよ", 0, 8, 0, 3, 1, 1, 102802, 1049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い子が\nいっぱいいるなぁ…\n誰か私とユニット\n組んでくれないかな？", 0, 1, 0, 1, 1, 1, 102901, 1051);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のライブ会場、\nいつもより大きいから\n楽しみなんだ～！", 0, 2, 0, 1, 1, 1, 102901, 1052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新曲の衣装、もうすぐ\n出来あがるんだって！\n楽しみだな～", 0, 3, 0, 1, 1, 1, 102901, 1053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼とデュエット\nしてみたいな～♪", 0, 4, 0, 1, 1, 1, 102901, 1054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キラキラ無病息災、\nドキドキ一日一善…\n作詞って難しい～", 0, 5, 0, 1, 1, 1, 102901, 1055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ファンはもちろん\n大事だけど…\n彼のことは、もっと\n大切にしたいな…", 0, 101, 0, 1, 4, 1, 102901, 1056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("写真集見なくても、\n本物がここに\nいるのにな～", 0, 102, 0, 1, 8, 1, 102901, 1057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("握手会の練習、\n付き合ってくれない？", 0, 1, 0, 2, 1, 1, 102901, 1058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("写真集のポーズ\n練習中～！\nど、どうかな？", 0, 2, 0, 2, 1, 1, 102901, 1059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何て書いてあるか\n読めないって？\nもー！\nこれは私のサイン！", 0, 3, 0, 2, 1, 1, 102901, 1060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、次のライブ\n観に来てくれる？\nいい席とっとくから！", 0, 4, 0, 2, 1, 1, 102901, 1061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、台本読むの\nつきあってくれる？\n恋人役に\nなってほしいんだ", 0, 101, 0, 2, 4, 1, 102901, 1062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新曲、聞いてくれた？\nキミとのことを\nテーマにしたんだよ。\nどこかは秘密だけど♪", 0, 102, 0, 2, 8, 1, 102901, 1063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の発声練習に\n行くけど、キミも\n一緒に来ない？", 0, 1, 1, 2, 1, 1, 102901, 1064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間は\nお腹すくけど…\n水着撮影があるから\nお昼抜いてるんだ", 0, 2, 2, 2, 1, 1, 102901, 1065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の帳が二人を包み\n…こういう方向性の\n歌詞も悪くないなぁ。", 0, 3, 3, 2, 1, 1, 102901, 1066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身だしなみオッケー！\nアイドルはいつでも\n完璧でいなくちゃ！", 0, 1, 0, 3, 1, 1, 102901, 1067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…\nこんな姿、ファンには\n見せられないな～", 0, 2, 0, 3, 1, 1, 102901, 1068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい～♪\nこれは強力な\nライバル登場かな！", 0, 3, 0, 3, 1, 1, 102901, 1069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ステキな香り～♪\n歌詞のイメージが\n浮かんできそう！", 0, 4, 0, 3, 1, 1, 102901, 1070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体も暖まったし！\nダンスレッスンに\n行こうかな♪", 0, 5, 0, 3, 1, 1, 102901, 1071);
