INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("疾風怒濤、威風堂々\n獅子奮迅、唯我独尊…\nラブソングの作詞って\n難しいな～", 0, 5, 0, 1, 1, 1, 102902, 1080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ファンはもちろん\n大事だけど…\n彼のことは、もっと\n大切にしたいな…", 0, 101, 0, 1, 8, 1, 102902, 1081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トップアイドルの\nさらに先…\n彼とならその景色も\n見られるかな", 0, 102, 0, 1, 8, 1, 102902, 1082);
