INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私との相性ですか？\nそれなら占う必要は\nありませんよ…\nふふっ♪", 0, 102, 0, 1, 8, 1, 103101, 1157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女難の相が\n出ていますね…\n気をつけてください", 0, 1, 0, 2, 1, 1, 103101, 1158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のあなたの運勢は\n大きょ…\n大吉です", 0, 2, 0, 2, 1, 1, 103101, 1159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("父と散歩中です。\n毎日決まったコースを\n散歩させないと、\nストレスが溜まるので", 0, 3, 0, 2, 1, 1, 103101, 1160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小僧！\nシノブに触るとは\nいい度胸じゃねぇか！", 0, 4, 0, 2, 1, 1, 103101, 1161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたに触られると、\n動悸が早くなります\nもしかして心霊現象？", 0, 101, 0, 2, 4, 1, 103101, 1162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もたくさんの幽霊\nに慕われていますね。\n素敵です", 0, 102, 0, 2, 8, 1, 103101, 1163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日の運勢を\n占いましょうか？", 0, 1, 1, 2, 1, 1, 103101, 1164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のラッキー\nアイテムはドクロです\n良ければ父を\nお貸ししましょうか？", 0, 2, 2, 2, 1, 1, 103101, 1165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のあなたの運気は\n最高潮でした。\nもうすぐ今日は\n終わりますが", 0, 3, 3, 2, 1, 1, 103101, 1166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん。\nいつも、身だしなみに\n気を使ってるけど、\nあまり変わってないよ", 0, 1, 0, 3, 1, 1, 103101, 1167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一休みしましょう。\n憑かれて疲れました", 0, 2, 0, 3, 1, 1, 103101, 1168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい…\n付喪神が宿らないかな", 0, 3, 0, 3, 1, 1, 103101, 1169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、\nリラックスし過ぎると\n成仏しちゃうよ？", 0, 4, 0, 3, 1, 1, 103101, 1170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいいです…\n極楽浄土みたい…", 0, 5, 0, 3, 1, 1, 103101, 1171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁはぁ…\nお、お父さん、\n代わりに運動して…", 0, 6, 0, 3, 1, 1, 103101, 1172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さんも\n食べたいの？\n死んでるのに？", 0, 7, 0, 3, 1, 1, 103101, 1173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本…\nもしかして予言書？", 0, 8, 0, 3, 1, 1, 103101, 1174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいる幽霊は\nみんな幸せそうです", 0, 1, 0, 1, 1, 1, 103102, 1176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さんが\n女の子ばかりに\n声をかけるので\n困っています", 0, 2, 0, 1, 1, 1, 103102, 1177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("成仏はうれしいこと\nです…でも友達が\n減るのは寂しいですね", 0, 3, 0, 1, 1, 1, 103102, 1178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊に好かれる人は\n素敵な方です\nもちろん、あなたも", 0, 4, 0, 1, 1, 1, 103102, 1179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、そろそろ\n子離れを…しない？\nそうですか…", 0, 5, 0, 1, 1, 1, 103102, 1180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生きている人に\n好かれるには、\nどうすればいい\nのでしょう？", 0, 101, 0, 1, 8, 1, 103102, 1181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、どうしたら\nあの人のことを\n認めてくれますか？", 0, 102, 0, 1, 8, 1, 103102, 1182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋、風水的にも\n運気が上がりそうです", 0, 1, 0, 2, 1, 1, 103102, 1183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シノブには指一本\n触れさせん！\nガブッ！！", 0, 2, 0, 2, 1, 1, 103102, 1184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの手相は…\nて、手を握るのって\n緊張しますね", 0, 3, 0, 2, 1, 1, 103102, 1185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラップ音？\nいえ、父のいびきです", 0, 4, 0, 2, 1, 1, 103102, 1186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私との相性ですか？\nそれなら占う必要は\nありませんよ…\nふふっ♪", 0, 101, 0, 2, 8, 1, 103102, 1187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("前世って信じますか？\n私とあなたは\nもしかすると…", 0, 102, 0, 2, 8, 1, 103102, 1188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のラッキー\nアイテムはドクロです\n良ければ父を\nお貸ししましょうか？", 0, 1, 1, 2, 1, 1, 103102, 1189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明るい時間は\nあまり得意では\nないんです…", 0, 2, 2, 2, 1, 1, 103102, 1190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜のお散歩に\n行きませんか？\n知り合いの幽霊に\n挨拶して回るんです", 0, 3, 3, 2, 1, 1, 103102, 1191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん\nいつも、身だしなみに\n気を使ってるけど\nあまり変わってないよ", 0, 1, 0, 3, 1, 1, 103102, 1192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うとうと…\nあれ…\n走馬灯が見える…", 0, 2, 0, 3, 1, 1, 103102, 1193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい…\nお父さんみたい…", 0, 3, 0, 3, 1, 1, 103102, 1194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん\nリラックスし過ぎると\n成仏しちゃうよ？", 0, 4, 0, 3, 1, 1, 103102, 1195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("快適です…\n幽霊もどんどん\n集まってきますね…", 0, 5, 0, 3, 1, 1, 103102, 1196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁはぁ…\nお、お父さん、\n代わりに運動して…", 0, 6, 0, 3, 1, 1, 103102, 1197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さんの分も、\n私が食べるね", 0, 7, 0, 3, 1, 1, 103102, 1198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本の占い\n私の占いと違う…", 0, 8, 0, 3, 1, 1, 103102, 1199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私だって、一人で\n買い物ぐらい\nできますわ…きっと", 0, 1, 0, 1, 1, 1, 103201, 1201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ新しい\n案件を始めないと\nいけませんわね", 0, 2, 0, 1, 1, 1, 103201, 1202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日も早く、\n一人前の商人に\nなりたいものです", 0, 3, 0, 1, 1, 1, 103201, 1203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("平和を買うのには\nどれほどのお金が\n必要なのかしら？", 0, 4, 0, 1, 1, 1, 103201, 1204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここももう少し広いと\n落ち着くのですけど。\n改築しませんこと？", 0, 5, 0, 1, 1, 1, 103201, 1205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの方はお金で雇った\nわけではないのに\n私といてくださる…", 0, 101, 0, 1, 4, 1, 103201, 1206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たとえ私が間違っても\nきっとあの方が\n正してくれますわ…", 0, 102, 0, 1, 8, 1, 103201, 1207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私と、庶民向けの\nお店へ一緒に\n参りませんか？", 0, 1, 0, 2, 1, 1, 103201, 1208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("資産運用？\nお幾らほど\n増やしたいのです？", 0, 2, 0, 2, 1, 1, 103201, 1209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんぶり勘定だとよく\n言われるのですが…\n例えが小さすぎます！", 0, 3, 0, 2, 1, 1, 103201, 1210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お金で解決するのは\n悪いことでは\nありませんわよね？", 0, 4, 0, 2, 1, 1, 103201, 1211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("その、よろしければ\n私とお散歩など\nいかがです？", 0, 101, 0, 2, 4, 1, 103201, 1212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしあなたさまが\n道に迷われるなら、\n私もお供いたします！", 0, 102, 0, 2, 8, 1, 103201, 1213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きは三ルピの徳と\n申しますが…\nもっとお得ですわね", 0, 1, 1, 2, 1, 1, 103201, 1214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食は町の屋台で\n立ったまま食べて\nみたいですわ！", 0, 2, 2, 2, 1, 1, 103201, 1215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よろしければ\nお休み前のミルクを\n御一緒にいかが？", 0, 3, 3, 2, 1, 1, 103201, 1216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("だらしない身なりでは\n取引相手に信用して\nいただけませんものね", 0, 1, 0, 3, 1, 1, 103201, 1217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この感触と安らぎ…\n素晴らしい\n費用対効果ですわ…", 0, 2, 0, 3, 1, 1, 103201, 1218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何の見返りも求めず\nただひたすら愛でて\nいたいのです！", 0, 3, 0, 3, 1, 1, 103201, 1219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("目に見えないものに\nお金をかけるのが\n真の贅沢ですわ！", 0, 4, 0, 3, 1, 1, 103201, 1220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰ひとり寒い思いを\nしない町にするために\n私にできる事は…", 0, 5, 0, 3, 1, 1, 103201, 1221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("健康はお金では\n買えませんが\n運動器具は別ですわ！", 0, 6, 0, 3, 1, 1, 103201, 1222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか\n美味ですわ\nシェフはどちらに？", 0, 7, 0, 3, 1, 1, 103201, 1223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("経済の仕組みを\nしっかりと\n学ばなくては…", 0, 8, 0, 3, 1, 1, 103201, 1224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ新しい\n案件を始めないと\nいけませんわね", 0, 1, 0, 1, 1, 1, 103202, 1226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええと、これは\nおいくらで買ったん\nでしたっけ？", 0, 2, 0, 1, 1, 1, 103202, 1227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お金を見せたら\n態度が変わる人は\n信用できませんわ", 0, 3, 0, 1, 1, 1, 103202, 1228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("地図が読めずとも\n道に迷わない方って\nいらっしゃるのですね", 0, 4, 0, 1, 1, 1, 103202, 1229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この狭さも\n慣れれば\n快適ですわ♪", 0, 5, 0, 1, 1, 1, 103202, 1230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの方はお金で雇った\nわけではないのに\n私といてくださる…", 0, 101, 0, 1, 8, 1, 103202, 1231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たとえ私が間違っても\nきっとあの方が\n正してくれますわ…", 0, 102, 0, 1, 8, 1, 103202, 1232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一人前の商人に\n相応しい居振る舞いを\nしたいものですわ", 0, 1, 0, 2, 1, 1, 103202, 1233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幼い頃\nお店屋さんごっこを\nなさいましたか？", 0, 2, 0, 2, 1, 1, 103202, 1234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("資産運用？\nお幾らほど\n増やしたいのです？", 0, 3, 0, 2, 1, 1, 103202, 1235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度一緒に…\nパーティにでも\n行きませんこと？", 0, 4, 0, 2, 1, 1, 103202, 1236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("その、よろしければ\n私とお散歩など\nいかがです？", 0, 101, 0, 2, 8, 1, 103202, 1237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたさまの優しさは\nお金には\n代えられませんわね", 0, 102, 0, 2, 8, 1, 103202, 1238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なぜだか\n眠り足りないような\n感じがしますわ…", 0, 1, 1, 2, 1, 1, 103202, 1239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食は町の屋台で\n立ったまま食べて\nみたいですわ！", 0, 2, 2, 2, 1, 1, 103202, 1240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よろしければ\nお休み前のミルクを\n御一緒にいかが？", 0, 3, 3, 2, 1, 1, 103202, 1241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドレスは汚れていない\nようですが…やだ\n髪がほつれてますわ！", 0, 1, 0, 3, 1, 1, 103202, 1242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういったものに\n腰を沈めると…\nき、気が緩んで…", 0, 2, 0, 3, 1, 1, 103202, 1243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何の見返りも求めず\nただひたすら愛でて\nいたいのです！", 0, 3, 0, 3, 1, 1, 103202, 1244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りは質のいいものと\nそうでないものが\nはっきり分かりますわ", 0, 4, 0, 3, 1, 1, 103202, 1245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰ひとり寒い思いを\nしない町にするために\n私にできる事は…", 0, 5, 0, 3, 1, 1, 103202, 1246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("目標は遠くに\n置いた方が励みに\nなりますわ！", 0, 6, 0, 3, 1, 1, 103202, 1247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか\n美味ですわ\nシェフはどちらに？", 0, 7, 0, 3, 1, 1, 103202, 1248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("商人って、物語では\n悪役にされやすいの\nですね…", 0, 8, 0, 3, 1, 1, 103202, 1249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家の中のものを使って\n物ボケ、考えるべ！", 0, 1, 0, 1, 1, 1, 103301, 1251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日の日課…それは\n炊事、洗濯、大喜利\nだべ！", 0, 2, 0, 1, 1, 1, 103301, 1252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちに塀ができたら、\nへー、って言いたい！", 0, 3, 0, 1, 1, 1, 103301, 1253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オラが作る料理は\nこの後スタッフで\n美味しくいただくべよ", 0, 4, 0, 1, 1, 1, 103301, 1254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エリザベスも\n連れてきてぇ～", 0, 5, 0, 1, 1, 1, 103301, 1255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんも、\nエリザベスと同じ位\nめんこいべ♪", 0, 101, 0, 1, 4, 1, 103301, 1256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オラとあんちゃん、\n息がぴったりに\nなってきたべ…！", 0, 102, 0, 1, 8, 1, 103301, 1257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おぉ！　そんな急に\nツッコまれたら、\nびっくらこくべやー！", 0, 1, 0, 2, 1, 1, 103301, 1258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネタはオラが書くけど\nあんちゃんが\n書きたかったら\n書いてもいいんだぞ？", 0, 2, 0, 2, 1, 1, 103301, 1259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃん、オラには\n容赦なんかせずに\nツッコんでくれて\nいいから！", 0, 3, 0, 2, 1, 1, 103301, 1260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("押すなよ、\n絶対押すなよ\n…なんて\n言ってないべさ？", 0, 4, 0, 2, 1, 1, 103301, 1261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…あんちゃんに\nツッコまれたくて\nうずうずしてきたべ～", 0, 101, 0, 2, 4, 1, 103301, 1262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("将来的には夫婦漫才\nってのも…あ、ひ、\nひとりごとだべさ～！", 0, 102, 0, 2, 8, 1, 103301, 1263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！　一緒に\n牛の乳しぼりいくべ？", 0, 1, 1, 2, 1, 1, 103301, 1264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼だ～腹が減っては\n笑いはできぬ～！", 0, 2, 2, 2, 1, 1, 103301, 1265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もよく働いたべ！\nさ、今からは\nお笑いの練習だ～！", 0, 3, 3, 2, 1, 1, 103301, 1266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞台に上がる前に\n身なりは整えねぇと\nだめだべ～！", 0, 1, 0, 3, 1, 1, 103301, 1267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナイスなイスに\n座りたい、\nなんちゃって！", 0, 2, 0, 3, 1, 1, 103301, 1268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("めんこいのは、\nスベっても許される\nからずるいべな～？", 0, 3, 0, 3, 1, 1, 103301, 1269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("必要以上に\n癒されちまうべや～", 0, 4, 0, 3, 1, 1, 103301, 1270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかだ…\nウケた会場みてぇだ", 0, 5, 0, 3, 1, 1, 103301, 1271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お笑い芸人は、\n体が資本だべさ～！", 0, 6, 0, 3, 1, 1, 103301, 1272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nボケることも\n忘れちまう美味さだ～", 0, 7, 0, 3, 1, 1, 103301, 1273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネタ作りのヒントが\n載ってねぇか探すべ", 0, 8, 0, 3, 1, 1, 103301, 1274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁ今日も張り切って\n漫才の練習するべさ！", 0, 1, 0, 1, 1, 1, 103302, 1276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋でも、商品\n売っていいんだべか？", 0, 2, 0, 1, 1, 1, 103302, 1277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眼鏡を頭の上に乗せて\n「メガネメガネ～」\nって言う練習した方が\nいいべか？", 0, 3, 0, 1, 1, 1, 103302, 1278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("漫才を持ち時間に\n収めるには、何度も\n練習するしかねぇべ", 0, 4, 0, 1, 1, 1, 103302, 1279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エリザベスも\n連れてきてぇ～", 0, 5, 0, 1, 1, 1, 103302, 1280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…あんちゃんに\nツッコまれたくて\nうずうずしてきたべ～", 0, 101, 0, 1, 8, 1, 103302, 1281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんに\n採れたての食材を\n食わしてやりてぇ～", 0, 102, 0, 1, 8, 1, 103302, 1282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("押すなよ\n絶対押すなよ\n…なんて\n言ってないべさ？", 0, 1, 0, 2, 1, 1, 103302, 1283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃん、百連\nツッコミ特訓だ～！", 0, 2, 0, 2, 1, 1, 103302, 1284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃん、オラには\n容赦なんかせずに\nツッコんでくれて\nいいから！", 0, 3, 0, 2, 1, 1, 103302, 1285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「なんでだべ～！」\nって言いながら\nツッコむといいべ！", 0, 4, 0, 2, 1, 1, 103302, 1286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはは～あんちゃんの\nツッコミはやっぱり\n気持ちいいなぁ～", 0, 101, 0, 2, 8, 1, 103302, 1287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("将来的には夫婦漫才\nってのも…あ、ひ\nひとりごとだべさ～！", 0, 102, 0, 2, 8, 1, 103302, 1288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n今日もいい\nネタ作り日和だ！", 0, 1, 1, 2, 1, 1, 103302, 1289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼だな\nご飯を食べたら、\nネタの練習するべ！", 0, 2, 2, 2, 1, 1, 103302, 1290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間だべ\nネタ作りは\n明日にするべ…", 0, 3, 3, 2, 1, 1, 103302, 1291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…衣装、\nずれてねぇべか？", 0, 1, 0, 3, 1, 1, 103302, 1292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナイスなイスに\n座りたい\nなんちゃって！", 0, 2, 0, 3, 1, 1, 103302, 1293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はう～\nなまらめんこいべや～", 0, 3, 0, 3, 1, 1, 103302, 1294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("必要以上に\n癒されちまうべや～", 0, 4, 0, 3, 1, 1, 103302, 1295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("笑いをとることを\n忘れるほど\nあったけぇべ～", 0, 5, 0, 3, 1, 1, 103302, 1296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさん運動して\n動きでも笑いがとれる\nように頑張るべ～！", 0, 6, 0, 3, 1, 1, 103302, 1297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nボケることも\n忘れちまう美味さだ～", 0, 7, 0, 3, 1, 1, 103302, 1298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幅広く教養を\n身につけて\nいいネタ作るべ！", 0, 8, 0, 3, 1, 1, 103302, 1299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("通りにいる\nカップル…爆発\nすればいいのに…", 0, 1, 0, 1, 1, 1, 103401, 1301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、仕事なんて\nしないで、\n飲んでたいな～", 0, 2, 0, 1, 1, 1, 103401, 1302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は一日、\n外に出ない！\nもう決めたわ！", 0, 3, 0, 1, 1, 1, 103401, 1303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いた…\nけど、外に出るのは\n面倒だなぁ", 0, 4, 0, 1, 1, 1, 103401, 1304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ…頭がガンガン\nする…昨日、\n飲み過ぎたかな…", 0, 5, 0, 1, 1, 1, 103401, 1305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("デートとか…\n誘っても嫌がられ\nないかな…？", 0, 101, 0, 1, 4, 1, 103401, 1306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしかして運命の\n相手だったり…\nするのかな", 0, 102, 0, 1, 8, 1, 103401, 1307);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり一杯目が\n一番おいしいわ～！\n…え、見てた！？", 0, 1, 0, 2, 1, 1, 103401, 1308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頼れるお姉さんだって\nところ、もっと見せて\nあげるからね", 0, 2, 0, 2, 1, 1, 103401, 1309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、一緒に買い物に\n行かない？　その…\nの、飲み物とか…", 0, 3, 0, 2, 1, 1, 103401, 1310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひっく、うふふ…\nもっとお姉さんと\nお話しようよ～", 0, 4, 0, 2, 1, 1, 103401, 1311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("極力人付き合いは\nしない主義なんだけど\nキミは例外かも…", 0, 101, 0, 2, 4, 1, 103401, 1312);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか…\nキミと一緒に飲めたら\n楽しいだろうな", 0, 102, 0, 2, 8, 1, 103401, 1313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう…朝は\nちょっとつらいな…\n低血圧なのよ…", 0, 1, 1, 2, 1, 1, 103401, 1314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっひるー♪\nなに食べよっかな～♪", 0, 2, 2, 2, 1, 1, 103401, 1315);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…\n眠る前にちょっと\n一杯…冗談よ", 0, 3, 3, 2, 1, 1, 103401, 1316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…\n髪がボサボサ…\nちゃんとしなきゃ…", 0, 1, 0, 3, 1, 1, 103401, 1317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自然体でゴロゴロ\nするのって\n幸せだなぁ…", 0, 2, 0, 3, 1, 1, 103401, 1318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうの男の子に\nプレゼントして\nもらいたいな…", 0, 3, 0, 3, 1, 1, 103401, 1319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うわあ、\nこれ、私の好きな\n香りだー！", 0, 4, 0, 3, 1, 1, 103401, 1320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽっかぽか…\nあとは熱い一杯が\nあれば…！", 0, 5, 0, 3, 1, 1, 103401, 1321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家でゴロゴロして\n付いちゃったお肉を\n落とさないと…！", 0, 6, 0, 3, 1, 1, 103401, 1322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nおーいしー！\n…太らないよね？", 0, 7, 0, 3, 1, 1, 103401, 1323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人の女らしく\n色んなことを学んで\nおかなくっちゃ", 0, 8, 0, 3, 1, 1, 103401, 1324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事終わりの一杯の\nために、今日も\n頑張らないと", 0, 1, 0, 1, 1, 1, 103402, 1326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は\nのんびり\n過ごそうかな～", 0, 2, 0, 1, 1, 1, 103402, 1327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ…\nお皿、洗って\nなかった…", 0, 3, 0, 1, 1, 1, 103402, 1328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう少し、大人の\n魅力が出せるように\nなりたいな", 0, 4, 0, 1, 1, 1, 103402, 1329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な彼氏…\n欲しいなぁ…", 0, 5, 0, 1, 1, 1, 103402, 1330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と私\n釣り合うかな…\n大丈夫よね？", 0, 101, 0, 1, 8, 1, 103402, 1331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今後のために\nちょっとは花嫁修業\nしてみようかな…？", 0, 102, 0, 1, 8, 1, 103402, 1332);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何事も\nお姉さんと一緒に\n楽しく頑張りましょ？", 0, 1, 0, 2, 1, 1, 103402, 1333);
