INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大切な人に\n本をすすめるのって\nけっこう難しいなぁ", 0, 5, 0, 1, 1, 1, 103802, 1380);
