INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子を作って、\nみなさんに振る舞って\n友達作戦！　とか…", 0, 3, 0, 1, 1, 1, 104001, 1403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ新しい\n草人形を作って\n友達作りの特訓を…", 0, 4, 0, 1, 1, 1, 104001, 1404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("植物のお世話って、\nぼっちにとっては、\n救い…なんです…", 0, 5, 0, 1, 1, 1, 104001, 1405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ＢＢ団の活動日…\nまだかな…\nうふふふっ", 0, 101, 0, 1, 4, 1, 104001, 1406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっともっとあの人の\nそばで、一緒に友達を\n作っていきたいな…", 0, 102, 0, 1, 8, 1, 104001, 1407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、こんにちは！\n今日もＢＢ団で\nお世話になります！", 0, 1, 0, 2, 1, 1, 104001, 1408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…私の友達作りの\n練習方法、間違って\nませんよね…？", 0, 2, 0, 2, 1, 1, 104001, 1409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、今度、\n森に一緒に木の苗を\n植えに行きませんか？", 0, 3, 0, 2, 1, 1, 104001, 1410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人とお話するのって、\n私、大好きです！\n友達ふやすぞ～！", 0, 4, 0, 2, 1, 1, 104001, 1411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと話してると、\nまるで私がぼっちじゃ\nないみたいです！", 0, 101, 0, 2, 4, 1, 104001, 1412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("友達もほしいけど…\nあなたに会えたことが\n私の一番の幸せです", 0, 102, 0, 2, 8, 1, 104001, 1413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n今日もＢＢ団、\nがんばるぞー！", 0, 1, 1, 2, 1, 1, 104001, 1414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか、お腹が\n空いてきました。\nお昼ごはんー♪", 0, 2, 2, 2, 1, 1, 104001, 1415);
