INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私がもっと\n可愛ければ、\n友達できるかなあ？", 0, 1, 0, 3, 1, 1, 104001, 1417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…のんびり\nしすぎないように\n気を付けなきゃです", 0, 2, 0, 3, 1, 1, 104001, 1418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいなあ。\nこの子とも\n友達になりたい…", 0, 3, 0, 3, 1, 1, 104001, 1419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りです…\n精神統一して\n友達のイメトレ…", 0, 4, 0, 3, 1, 1, 104001, 1420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("灯りを見てると、\n心がなごみます～", 0, 5, 0, 3, 1, 1, 104001, 1421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nおいしいです…！\nみなさんもぜひ！", 0, 6, 0, 3, 1, 1, 104001, 1422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいです…\n私に友達がいたら、\n分けてあげたいな", 0, 7, 0, 3, 1, 1, 104001, 1423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("友達作りの\n参考になりそうなこと\n書いてないかな～？", 0, 8, 0, 3, 1, 1, 104001, 1424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("友達作りは、焦らず\n慌てず、じっくりと…", 0, 1, 0, 1, 1, 1, 104002, 1426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひとつ屋根の下\nって感じ…\nいいですねえ…", 0, 2, 0, 1, 1, 1, 104002, 1427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("煮汁、煮汁が\n噴きこぼれて\nいませんか～", 0, 3, 0, 1, 1, 1, 104002, 1428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、みなさんと\nピクニックとか…\nいってみたいな", 0, 4, 0, 1, 1, 1, 104002, 1429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼっちでもいい\nたくましく育てば\n…なんて", 0, 5, 0, 1, 1, 1, 104002, 1430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、毎日あの人の\nこと考えちゃいます\nどうしてだろう…", 0, 101, 0, 1, 8, 1, 104002, 1431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっともっとあの人の\nそばで、一緒に友達を\n作っていきたいな…", 0, 102, 0, 1, 8, 1, 104002, 1432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ！　ＢＢ団の活動\nですか？　嬉しくて\n飛び跳ねちゃいます！", 0, 1, 0, 2, 1, 1, 104002, 1433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとのお話で友達\n作りの練習になるなら\n一石二鳥です！", 0, 2, 0, 2, 1, 1, 104002, 1434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私少しは人と話しても\nテンパらなくなって\nきましたかね…？", 0, 3, 0, 2, 1, 1, 104002, 1435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、友達作りの\n新しい作戦\n考えてみたんですっ！", 0, 4, 0, 2, 1, 1, 104002, 1436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとお話する時の\nこの気持ち、私の宝物\nなんです…えへへ", 0, 101, 0, 2, 8, 1, 104002, 1437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("友達もほしいけど…\nあなたに会えたことが\n私の一番の幸せです", 0, 102, 0, 2, 8, 1, 104002, 1438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ですね！\nこんないい朝は\n友達作りのチャンス！", 0, 1, 1, 2, 1, 1, 104002, 1439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…そろそろお腹\nすきませんか？\nお昼ごはんは…", 0, 2, 2, 2, 1, 1, 104002, 1440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう眠いかもです…\n明日は友達\nできるといいなあ…", 0, 3, 3, 2, 1, 1, 104002, 1441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私…見た目\nそこまで変じゃ\nないですよね…？", 0, 1, 0, 3, 1, 1, 104002, 1442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほわあ～…\nふかふかって\nいいものですね～", 0, 2, 0, 3, 1, 1, 104002, 1443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子みたいな\nあいくるしさを\n目指したいです！", 0, 3, 0, 3, 1, 1, 104002, 1444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("灯りを見てると\n心がなごみます～", 0, 4, 0, 3, 1, 1, 104002, 1445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬくぬくで、なんだか\n眠くなっちゃいますね", 0, 5, 0, 3, 1, 1, 104002, 1446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身体を鍛えて\nみなさんを\n守ります！", 0, 6, 0, 3, 1, 1, 104002, 1447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nおいしいです…！\nみなさんもぜひ！", 0, 7, 0, 3, 1, 1, 104002, 1448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("友達作りの\n参考になりそうなこと\n書いてないかな～？", 0, 8, 0, 3, 1, 1, 104002, 1449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("唱喚の歌は、みだりに\n歌っていいものでは\nないんです", 0, 1, 0, 1, 1, 1, 104201, 1451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでアイドルの\n練習は、さすがに\n迷惑ですよね？", 0, 2, 0, 1, 1, 1, 104201, 1452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("練習してもあんまり\n疲れなくなった…\nアイドルのおかげかな", 0, 3, 0, 1, 1, 1, 104201, 1453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人々の平和を守る旅に\n同行してくれる人を\n探していて…", 0, 4, 0, 1, 1, 1, 104201, 1454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あとで曲を復習して\nおかないと…", 0, 5, 0, 1, 1, 1, 104201, 1455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("踊りを見られるのは\nまだ恥ずかしいけど\nあの人になら…", 0, 101, 0, 1, 4, 1, 104201, 1456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("浜辺で曲を書こうと\n思うんですけど…\n一緒に行きませんか？", 0, 102, 0, 1, 8, 1, 104201, 1457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつも応援ありがとう\nございます♪　これは\nあ、握手の練習です！", 0, 1, 0, 2, 1, 1, 104201, 1458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、もう練習の時間？\nごめんなさい\nすぐ準備します！", 0, 2, 0, 2, 1, 1, 104201, 1459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("守るべき人たちに\n笑顔でいてもらうのも\n大切なんですね", 0, 3, 0, 2, 1, 1, 104201, 1460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌える曲を増やそうと\n思って。どんな曲が\n聞きたいですか？", 0, 4, 0, 2, 1, 1, 104201, 1461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("～～♪　あれ？\n今私、歌ってました？\n気づきませんでした", 0, 101, 0, 2, 4, 1, 104201, 1462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…歌って欲しい？\n喜んで♪\nどの歌にしましょう？", 0, 102, 0, 2, 8, 1, 104201, 1463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\n少し歌の練習を\nしてきますね", 0, 1, 1, 2, 1, 1, 104201, 1464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお昼なんですか？\n練習に夢中で\n気づきませんでした", 0, 2, 2, 2, 1, 1, 104201, 1465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日の予定は…\nアイドルはやることが\n多いみたいで…", 0, 3, 3, 2, 1, 1, 104201, 1466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見た目については\n前よりも気をつけてと\nノゾミに言われてます", 0, 1, 0, 3, 1, 1, 104201, 1467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌の調子をよくする\nためには休息も\n必要ですよね…", 0, 2, 0, 3, 1, 1, 104201, 1468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子たちを\n相手に練習して\nみようかな…♪", 0, 3, 0, 3, 1, 1, 104201, 1469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…疲れてるのかな\n落ち着けているのが\n自分でもわかります", 0, 4, 0, 3, 1, 1, 104201, 1470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると\n穏やかな旋律が\n浮かんできます…", 0, 5, 0, 3, 1, 1, 104201, 1471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌うためには\n体力づくりは\n欠かせません", 0, 6, 0, 3, 1, 1, 104201, 1472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌った後は\nお腹が空いて\nしまうんです", 0, 7, 0, 3, 1, 1, 104201, 1473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("音楽について\n理論も勉強\nしないと…", 0, 8, 0, 3, 1, 1, 104201, 1474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌うことの楽しさ\n分かってきました\nもっと歌いたいな…", 0, 1, 0, 1, 1, 1, 104202, 1476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("練習してもあんまり\n疲れなくなった…\nアイドルのおかげかな", 0, 2, 0, 1, 1, 1, 104202, 1477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊も強くなったし\nもっとたくさんの人を\n守りたいです", 0, 3, 0, 1, 1, 1, 104202, 1478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、よく頭の中に\n歌が浮かんできます\n不思議な感覚…", 0, 4, 0, 1, 1, 1, 104202, 1479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽譜を買いました\n思いついた歌を\n書き留めておくために", 0, 5, 0, 1, 1, 1, 104202, 1480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("浜辺で曲を書こうと\n思うんですけど…\n一緒に行きませんか？", 0, 101, 0, 1, 8, 1, 104202, 1481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の中にある\n私だけの歌…\n作ってみようかな？", 0, 102, 0, 1, 8, 1, 104202, 1482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("守るべき人たちに\n笑顔でいてもらうのも\n大切なんですね", 0, 1, 0, 2, 1, 1, 104202, 1483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌える曲を増やそうと\n思って。どんな曲が\n聞きたいですか？", 0, 2, 0, 2, 1, 1, 104202, 1484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物退治ですか！？\n…違います？\n良かった…", 0, 3, 0, 2, 1, 1, 104202, 1485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつも応援ありがとう\nございます♪　これは\nあ、握手の練習です！", 0, 4, 0, 2, 1, 1, 104202, 1486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…歌って欲しい？\n喜んで♪\nどの歌にしましょう？", 0, 101, 0, 2, 8, 1, 104202, 1487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("～～♪　あれ？\n今私、歌ってました？\n気づきませんでした", 0, 102, 0, 2, 8, 1, 104202, 1488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("呼吸を深く、大きく…\nこれでちゃんと\n目が覚めますよ", 0, 1, 1, 2, 1, 1, 104202, 1489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し休んだら\n午後の練習に\n行ってきますね", 0, 2, 2, 2, 1, 1, 104202, 1490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("曲を作っていたら\nもうこんな時間…\nおやすみなさい", 0, 3, 3, 2, 1, 1, 104202, 1491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見た目については\n前よりも気をつけてと\nノゾミに言われてます", 0, 1, 0, 3, 1, 1, 104202, 1492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ～…♪\nよく体がほぐれます…\nいい歌が歌えそうです", 0, 2, 0, 3, 1, 1, 104202, 1493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいと思う\n気持ちを、歌にしても\nいいかも知れませんね", 0, 3, 0, 3, 1, 1, 104202, 1494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…疲れてるのかな\n落ち着けているのが\n自分でもわかります", 0, 4, 0, 3, 1, 1, 104202, 1495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると\n穏やかな旋律が\n浮かんできます…", 0, 5, 0, 3, 1, 1, 104202, 1496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっと体力をつけて\n最高のライブを\nファンに届けます！", 0, 6, 0, 3, 1, 1, 104202, 1497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これでも一応\n体形には気をつけて\n食べてるんですよ？", 0, 7, 0, 3, 1, 1, 104202, 1498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("読書は歌に\n新しい風を\n吹き込んでくれます", 0, 8, 0, 3, 1, 1, 104202, 1499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("店の新メニューでも\n考えるかな", 0, 1, 0, 1, 1, 1, 104301, 1501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの店から、\n出前を届けようか？", 0, 2, 0, 1, 1, 1, 104301, 1502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パトロール、\nパトロール…\nここは異常なしかな？", 0, 3, 0, 1, 1, 1, 104301, 1503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹へったら食う！\n悩んだら寝る！\nそれが一番だろ？", 0, 4, 0, 1, 1, 1, 104301, 1504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("のんびりし過ぎるのも\n…性に合わねぇな", 0, 5, 0, 1, 1, 1, 104301, 1505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろあいつ、\n腹すかしてるん\nじゃないかな？", 0, 101, 0, 1, 4, 1, 104301, 1506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の献立は…\nあいつの好きなものに\nしてやるか", 0, 102, 0, 1, 8, 1, 104301, 1507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強くなりたいなら、\nあたしがビシバシ\n鍛えてやるよ", 0, 1, 0, 2, 1, 1, 104301, 1508);
