INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じっとしてると\nドＳさんのことばかり\n考えてしまいますね", 0, 101, 0, 1, 8, 1, 104502, 1581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妄想が止まらなくて\nクウカどうにかなって\nしまいそうです！", 0, 102, 0, 1, 8, 1, 104502, 1582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんといると体が\n火照って…クウカは\nいやらしい子です！", 0, 1, 0, 2, 1, 1, 104502, 1583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ…\nジロジロ見てたの\n気づいちゃいました？", 0, 2, 0, 2, 1, 1, 104502, 1584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんのおかげで\n新しい扉が開けそう\nです…じゅるり", 0, 3, 0, 2, 1, 1, 104502, 1585);
