INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くつろいで油断\nしているスキに何を\nされるのでしょう！？", 0, 2, 0, 3, 1, 1, 104502, 1593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「見た目とは裏腹に\nそれは激しく攻め\nたてて」…ぐふふふ", 0, 3, 0, 3, 1, 1, 104502, 1594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは禁断の香り…\nああっ一段階上の\n妄想が開花するうぅ！", 0, 4, 0, 3, 1, 1, 104502, 1595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああっ、暖気がまるで\nロウソクのように\nクウカを攻めますっ！", 0, 5, 0, 3, 1, 1, 104502, 1596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("激しい攻めを受けきる\nためには、鍛えないと\nいけないのですね", 0, 6, 0, 3, 1, 1, 104502, 1597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにいっぱい\n入りません…\nお腹にっ！", 0, 7, 0, 3, 1, 1, 104502, 1598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんな本も\nよく見ると\nいやらしいです…！", 0, 8, 0, 3, 1, 1, 104502, 1599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この前遊んだ猫、\nモッフモフ\nだったにゃあ…♪", 0, 1, 0, 1, 1, 1, 104601, 1601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほっぺやお腹が、\n肉球ぐらいぷにぷに…\nこれはまずいにゃ…", 0, 2, 0, 1, 1, 1, 104601, 1602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大きな仕事が\n決まったにゃ！\n腕が鳴るにゃ～♪", 0, 3, 0, 1, 1, 1, 104601, 1603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやつのたい焼き、\nつぶあんとこしあん、\nどっちに\nしようかにゃ？", 0, 4, 0, 1, 1, 1, 104601, 1604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うにゃー…\nもうちょっとお昼寝\nしたかったにゃ…\nむにゃむにゃ…", 0, 5, 0, 1, 1, 1, 104601, 1605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミに呼ばれると、\n猫まっしぐらな気分に\nなっちゃうにゃ♪", 0, 101, 0, 1, 4, 1, 104601, 1606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミのおかげで\nギルドの仕事も\n大成功だにゃ♪\nありがとにゃ♪", 0, 102, 0, 1, 8, 1, 104601, 1607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うずうず…その指、\nじゃれついても\nいいかにゃ？", 0, 1, 0, 2, 1, 1, 104601, 1608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃ？　あたしに何か\nご入り用かにゃ？\nお安くしとくにゃ～♪", 0, 2, 0, 2, 1, 1, 104601, 1609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、なんだか\n退屈にゃ～\n遊んで、遊んで～？", 0, 3, 0, 2, 1, 1, 104601, 1610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素早い動きのコツ？\nタダじゃ教えて\nあげられないにゃ～♪", 0, 4, 0, 2, 1, 1, 104601, 1611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そんなにあたしを\nなでたいにゃ？\nキミならなでさせて\nあげてもいいかにゃー", 0, 101, 0, 2, 4, 1, 104601, 1612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃあ、ねえねえ、\n一緒にゴロゴロ\nしようにゃあ？", 0, 102, 0, 2, 8, 1, 104601, 1613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい朝にゃ！\n顔を洗ってくるにゃ！", 0, 1, 1, 2, 1, 1, 104601, 1614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むーん、そろそろ\nお昼…猫たちにも\n猫缶を…", 0, 2, 2, 2, 1, 1, 104601, 1615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…眠いにゃ…\n猫は布団で\n丸くなるにゃ", 0, 3, 3, 2, 1, 1, 104601, 1616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("客商売では、\n外見のチェックも\n欠かせないのにゃ！", 0, 1, 0, 3, 1, 1, 104601, 1617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うにゃ～！\nお昼寝に\nぴったりにゃ", 0, 2, 0, 3, 1, 1, 104601, 1618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ…量産したら\n子どもにバカ売れ\nしそうだにゃ！", 0, 3, 0, 3, 1, 1, 104601, 1619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この灯り、まるで\n猫みたいな\n癒し効果にゃ！", 0, 4, 0, 3, 1, 1, 104601, 1620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃあ、\nあったかいと猫は丸く\nなっちゃうのにゃあ…", 0, 5, 0, 3, 1, 1, 104601, 1621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本当は外で\n運動したいん\nだけどにゃ", 0, 6, 0, 3, 1, 1, 104601, 1622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むーん、\n美味しいにゃー！\nたい焼きに\n匹敵するにゃ！", 0, 7, 0, 3, 1, 1, 104601, 1623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…猫の\nしつけ方は、と…", 0, 8, 0, 3, 1, 1, 104601, 1624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいネコの置物を\nゲットしたにゃ！\nどこに飾ろうか\nにゃ～♪", 0, 1, 0, 1, 1, 1, 104602, 1626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事の交渉がうまく\n行ったにゃ～♪\nいい気分だにゃ～♪", 0, 2, 0, 1, 1, 1, 104602, 1627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねこじゃらしには\n食いついちゃうにゃ\nびしっ！　びしっ！", 0, 3, 0, 1, 1, 1, 104602, 1628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほっぺやお腹が、肉球\nぐらいぷにぷに…\nこれはまずいにゃ…", 0, 4, 0, 1, 1, 1, 104602, 1629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっきのたいやき\nおいしかったにゃ♪\nごろごろごろ…", 0, 5, 0, 1, 1, 1, 104602, 1630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手作りのたい焼き\nあいつは食べて\nくれるかにゃ…？", 0, 101, 0, 1, 8, 1, 104602, 1631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつには、いつか\nたっぷり恩返しが\nしたいにゃ…", 0, 102, 0, 1, 8, 1, 104602, 1632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃーに？　あたしの\nことがそんなに気に\nなるのかにゃ？", 0, 1, 0, 2, 1, 1, 104602, 1633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしのこと…\nしっかり捕まえ\nといてにゃ？", 0, 2, 0, 2, 1, 1, 104602, 1634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの力が\n必要かにゃ？　猫の手\n貸してあげるにゃ♪", 0, 3, 0, 2, 1, 1, 104602, 1635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たいやきとクレープを\n合わせれば…\n新しい商売のニオイが\nするにゃ…！", 0, 4, 0, 2, 1, 1, 104602, 1636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃあ、ねえねえ\n一緒にゴロゴロ\nしようにゃあ？", 0, 101, 0, 2, 8, 1, 104602, 1637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒にいると\n楽しくなってつい\nじゃれちゃうにゃ！", 0, 102, 0, 2, 8, 1, 104602, 1638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい朝にゃ！\n顔を洗ってくるにゃ！", 0, 1, 1, 2, 1, 1, 104602, 1639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろおっひる～\nにゃーんか\n食べたい…", 0, 2, 2, 2, 1, 1, 104602, 1640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、眠くなって\nきたにゃ。あたしは\n夜行性じゃないのにゃ", 0, 3, 3, 2, 1, 1, 104602, 1641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃにゃ…\n髪が乱れてるにゃ", 0, 1, 0, 3, 1, 1, 104602, 1642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっかふかにゃ～\n猫がねころん\nじゃうにゃ", 0, 2, 0, 3, 1, 1, 104602, 1643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、猫と匹敵する\nぐらいかわいいにゃ！", 0, 3, 0, 3, 1, 1, 104602, 1644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫でもこわくない\n優しい灯りにゃ！", 0, 4, 0, 3, 1, 1, 104602, 1645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽっかぽか\nしあわせな気分にゃ～", 0, 5, 0, 3, 1, 1, 104602, 1646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("雨の日でも運動\nできるのは、濡れ\nなくて便利だにゃ！", 0, 6, 0, 3, 1, 1, 104602, 1647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しいにゃ～！\nこれ、朝昼晩\n食べたいにゃ！", 0, 7, 0, 3, 1, 1, 104602, 1648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本を読んで\n猫の気持ちを\n勉強するのにゃ！", 0, 8, 0, 3, 1, 1, 104602, 1649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("内職手伝える人\nいないかしら？", 0, 1, 0, 1, 1, 1, 104801, 1651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の依頼は、\nこういう計画で…\nうん、完璧ね！", 0, 2, 0, 1, 1, 1, 104801, 1652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の特売セールに\n向けて、しっかり\n準備しないと！", 0, 3, 0, 1, 1, 1, 104801, 1653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("配達の後に売り子\n次に採取のバイト…\nうん、効率的ね", 0, 4, 0, 1, 1, 1, 104801, 1654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日に受ける\nバイトの数、もう少し\n増やしたいわね", 0, 5, 0, 1, 1, 1, 104801, 1655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("師匠として\n頼りにされたいし\nもっと頑張らなきゃ！", 0, 101, 0, 1, 4, 1, 104801, 1656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男の子と効率的に\n仲良くなる方法…\nこればっかりは難題ね", 0, 102, 0, 1, 8, 1, 104801, 1657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、\nちょうどよかった\n今から一緒に\nバイトでもどう？", 0, 1, 0, 2, 1, 1, 104801, 1658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("相談事かしら？\nそれくらいなら\n無料でいいわよ", 0, 2, 0, 2, 1, 1, 104801, 1659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("背後の気配なら\nすぐ分かるわ\n試してみる？", 0, 3, 0, 2, 1, 1, 104801, 1660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("道具やお金の管理は\n大丈夫？　手伝うから\nいつでも言って", 0, 4, 0, 2, 1, 1, 104801, 1661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇ができたから\n働きたいけど…\nキミとの時間も大切ね", 0, 101, 0, 2, 4, 1, 104801, 1662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、あの…\n私はキミにとって…\nいや、何でもないわ", 0, 102, 0, 2, 8, 1, 104801, 1663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n今日も朝から\nバイトよ！", 0, 1, 1, 2, 1, 1, 104801, 1664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼時ね。\n少し休憩したら、\nまた働くわよ！", 0, 2, 2, 2, 1, 1, 104801, 1665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間！\n明日もバイトで\n朝早いのよ…", 0, 3, 3, 2, 1, 1, 104801, 1666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("接客業の依頼が\nある時は、外見も\nキレイにしないとね", 0, 1, 0, 3, 1, 1, 104801, 1667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～バイトで\n疲れたから癒される～", 0, 2, 0, 3, 1, 1, 104801, 1668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを内職で\n作ったら\n儲かるかしら？", 0, 3, 0, 3, 1, 1, 104801, 1669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リフレッシュできたわ\nこれでまた、バリバリ\n働けるわね！", 0, 4, 0, 3, 1, 1, 104801, 1670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪を引いたら効率が\n落ちちゃうから、\n暖めないと！", 0, 5, 0, 3, 1, 1, 104801, 1671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("働き続けるには\n健康第一！　それには\n運動が一番よ", 0, 6, 0, 3, 1, 1, 104801, 1672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\n腹が減っては\n戦ができぬ、よ！", 0, 7, 0, 3, 1, 1, 104801, 1673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日々絶えず学んで、\n生活に活かすのよ！", 0, 8, 0, 3, 1, 1, 104801, 1674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家計簿をつけなきゃ！\n覚えている時に\nやっておかないとね", 0, 1, 0, 1, 1, 1, 104802, 1676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の依頼は\nこういう計画で…\nうん、完璧ね！", 0, 2, 0, 1, 1, 1, 104802, 1677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドの経費\nあとちょっとだけ\n削れそうね…", 0, 3, 0, 1, 1, 1, 104802, 1678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少しでも時給のいい\nバイトがしたいけど\nなかなか\n出会えないのよ", 0, 4, 0, 1, 1, 1, 104802, 1679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のバイトも\nなかなか大変そう\nね…腕が鳴るわ", 0, 5, 0, 1, 1, 1, 104802, 1680);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男の子と効率的に\n仲良くなる方法…\nこればっかりは難題ね", 0, 101, 0, 1, 8, 1, 104802, 1681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、どうしたんだろ？\n仕事中もずっと\n彼のこと考えてる…", 0, 102, 0, 1, 8, 1, 104802, 1682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この間はヘルプに\n来てくれてありがとう\n頼んで正解だったわ", 0, 1, 0, 2, 1, 1, 104802, 1683);
