INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい♪　けど\n大人はこんなもの…\nでも、かわいいし～！", 0, 3, 0, 3, 1, 1, 105001, 1769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オシャレ～♪\n大人なレディって\n感じよね♪", 0, 4, 0, 3, 1, 1, 105001, 1770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかーい♪\nここで宿題\nしようかしら？", 0, 5, 0, 3, 1, 1, 105001, 1771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("運動したら成長\nしないかしら？\n背とか胸とか…", 0, 6, 0, 3, 1, 1, 105001, 1772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べすぎると\n太っちゃうな…\nでも、おいしいし～っ", 0, 7, 0, 3, 1, 1, 105001, 1773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おもしろーい！\n…でも絵本って\n子供っぽいかしら？", 0, 8, 0, 3, 1, 1, 105001, 1774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レディは、どんな時も\nおしとやかに…って\nアタシも騒ぎたいー！", 0, 1, 0, 1, 1, 1, 105002, 1776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("恋人にするなら\nイケメンか\nただイケよね～", 0, 2, 0, 1, 1, 1, 105002, 1777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう少し背が欲しいな\n…もっと牛乳を\n飲まなくちゃ！", 0, 3, 0, 1, 1, 1, 105002, 1778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝顔の観察したら\n理系女子になれる\nかしら？", 0, 4, 0, 1, 1, 1, 105002, 1779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、これは補習の\nお知らせプリント！\nアイツに見つかる前に\n隠さなくちゃ！", 0, 5, 0, 1, 1, 1, 105002, 1780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツおっそいなー\n別に会いたいわけじゃ\nないけど…\n来ないと気になる…", 0, 101, 0, 1, 8, 1, 105002, 1781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシが待ってる\nなんて、アイツは\n幸せものよねー ", 0, 102, 0, 1, 8, 1, 105002, 1782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なーに？\nアタシに甘えたいの？", 0, 1, 0, 2, 1, 1, 105002, 1783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシに合う服\n雑誌で探そうっと！\nサイズじゃないわ\nデザインとかの話よ！", 0, 2, 0, 2, 1, 1, 105002, 1784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭撫でないで！\nお子様みたいに\nあつかわないでって\n言ってるのに～！", 0, 3, 0, 2, 1, 1, 105002, 1785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("壁ドンの練習…\nあれ？　壁ドンって\n男がするんだっけ？", 0, 4, 0, 2, 1, 1, 105002, 1786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねーねー！\nアタシ、かわいい？\nかわいいわよね？", 0, 101, 0, 2, 8, 1, 105002, 1787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これから出かけるの？\nしっかりアタシを\nエスコートしてね！", 0, 102, 0, 2, 8, 1, 105002, 1788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レディの朝は\n忙しいのよ", 0, 1, 1, 2, 1, 1, 105002, 1789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すいたー\nダイエット\nやめちゃおうかなー", 0, 2, 2, 2, 1, 1, 105002, 1790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エイジングケアを\nしないとねー", 0, 3, 3, 2, 1, 1, 105002, 1791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身だしなみチェック\nオッケー！　これで\nいつアイツが来ても\n大丈夫ね！", 0, 1, 0, 3, 1, 1, 105002, 1792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ！　これ雑誌で\n見たことあるわ～\nだからきっと\nオシャレなのよ！", 0, 2, 0, 3, 1, 1, 105002, 1793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしがもっと\nオシャレにかわいく\nしてあげようか？", 0, 3, 0, 3, 1, 1, 105002, 1794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オシャレ～♪\n大人なレディって\n感じよね♪", 0, 4, 0, 3, 1, 1, 105002, 1795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかーい♪\nここで宿題\nしようかしら？", 0, 5, 0, 3, 1, 1, 105002, 1796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("運動したら成長\nしないかしら？\n背とか胸とか…", 0, 6, 0, 3, 1, 1, 105002, 1797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レディは、食べ物にも\n気を使うのよ", 0, 7, 0, 3, 1, 1, 105002, 1798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おもしろーい！\n…でも絵本って\n子供っぽいかしら？", 0, 8, 0, 3, 1, 1, 105002, 1799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法と科学\nどっちも極めて\nみせるわ", 0, 1, 0, 1, 1, 1, 105101, 1801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事も片付いたし\n部屋で\n実験実験…♪", 0, 2, 0, 1, 1, 1, 105101, 1802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまった治療代の\n請求書を\nまとめないと…", 0, 3, 0, 1, 1, 1, 105101, 1803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新薬が出来たし\nすぐに試したいけど…\n実験台がいないわ", 0, 4, 0, 1, 1, 1, 105101, 1804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋にこもりすぎると\n曜日の感覚が\nなくなるわね", 0, 5, 0, 1, 1, 1, 105101, 1805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子の記憶を\n取り戻せる薬…\n作れないものかしら", 0, 101, 0, 1, 4, 1, 105101, 1806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("好意に気づいて貰える\n薬って、どうすれば\n作れるのかしら", 0, 102, 0, 1, 8, 1, 105101, 1807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、ヒマなら\n薬草の整理を\n手伝って", 0, 1, 0, 2, 1, 1, 105101, 1808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしかして実験に\n付き合ってくれるの？\nえ？　違う？", 0, 2, 0, 2, 1, 1, 105101, 1809);
