INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("植物に興味あるの？\nなら教えてあげるわ\n色々とね…", 0, 4, 0, 2, 1, 1, 105101, 1811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの傍にいるだけで\n高揚しちゃうのは\n何故かしら…？", 0, 101, 0, 2, 4, 1, 105101, 1812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私はおしおきする\n側のことが多いけど…\nキミにはされたいかも", 0, 102, 0, 2, 8, 1, 105101, 1813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼までに調合用の\n花を集めたいの\n手伝ってくれる？", 0, 1, 1, 2, 1, 1, 105101, 1814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、もうお昼？\nそろそろ一息\n入れましょうか", 0, 2, 2, 2, 1, 1, 105101, 1815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も更けて来たわね\n私は朝まで実験だけど\n見学していく？", 0, 3, 3, 2, 1, 1, 105101, 1816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("医者たるもの\nいつだって\n清潔に…♪", 0, 1, 0, 3, 1, 1, 105101, 1817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいわねこれ\n仮眠の時に\n使わせてもらうわ", 0, 2, 0, 3, 1, 1, 105101, 1818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみなら\n動物も…", 0, 3, 0, 3, 1, 1, 105101, 1819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\n仕事場にも\n置いてみようかしら", 0, 4, 0, 3, 1, 1, 105101, 1820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると\nついウトウト\nしちゃうわ…", 0, 5, 0, 3, 1, 1, 105101, 1821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("座ってる時間が多いと\n運動不足になるし\nたまにはいいわね", 0, 6, 0, 3, 1, 1, 105101, 1822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("研究していると\nつい食べるのを\n忘れちゃうのよね", 0, 7, 0, 3, 1, 1, 105101, 1823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実験もいいけど\nいつか成果を\n本にしないと…", 0, 8, 0, 3, 1, 1, 105101, 1824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("徹夜はツラいけど\n集中すると時間の\n感覚がなくなって…", 0, 1, 0, 1, 1, 1, 105102, 1826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("痛みに悶える顔って\nどうしてあんなに\n興奮するのかしら？", 0, 2, 0, 1, 1, 1, 105102, 1827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼に罵られたら\nどんな気分かしら\n意外と快感かも？", 0, 3, 0, 1, 1, 1, 105102, 1828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毒を薄めると\n薬になるのって\n今でも不思議だわ", 0, 4, 0, 1, 1, 1, 105102, 1829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("綺麗なバラには\nトゲがあるけど\n魅力の一つよね", 0, 5, 0, 1, 1, 1, 105102, 1830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カレをさりげなく\n惚れさせる方法を\n研究するわよ…♪", 0, 101, 0, 1, 8, 1, 105102, 1831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("好意に気づいて貰える\n薬って、どうすれば\n作れるのかしら", 0, 102, 0, 1, 8, 1, 105102, 1832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("構って欲しいの？\nじゃあ、君の体を\n調べさせて？", 0, 1, 0, 2, 1, 1, 105102, 1833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実験に付き合って\n大丈夫よ、試すのは\nただの栄養剤だから", 0, 2, 0, 2, 1, 1, 105102, 1834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("欲しい薬が\nあったら言ってね\n調合してみるから", 0, 3, 0, 2, 1, 1, 105102, 1835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おしおきされたいの？\nキミにだったら\nいつでもしてあげる", 0, 4, 0, 2, 1, 1, 105102, 1836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの傍にいるだけで\n高揚しちゃうのは\n何故かしら…？", 0, 101, 0, 2, 8, 1, 105102, 1837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私はおしおきする\n側のことが多いけど…\nキミにはされたいかも", 0, 102, 0, 2, 8, 1, 105102, 1838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝しか取れない\n植物があるの\n採取しに行くわよ", 0, 1, 1, 2, 1, 1, 105102, 1839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼時ってやけに\n眠たくなるわよね\n…調べたくなるわ", 0, 2, 2, 2, 1, 1, 105102, 1840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日くらいは\nゆっくり眠りたいわ\n…キミと一緒にね", 0, 3, 3, 2, 1, 1, 105102, 1841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身なりについて\n研究するのも\n楽しそうね", 0, 1, 0, 3, 1, 1, 105102, 1842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休息に必要な道具は\n妥協せずに選ぶ！\nこれだけは譲れないわ", 0, 2, 0, 3, 1, 1, 105102, 1843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはこういう\n可愛らしいものに\n触れないとね♪", 0, 3, 0, 3, 1, 1, 105102, 1844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\n仕事場にも\n置いてみようかしら", 0, 4, 0, 3, 1, 1, 105102, 1845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事がなかったら\nこのまますーっと\n眠りたいのに…", 0, 5, 0, 3, 1, 1, 105102, 1846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("運動しないと\n体型の維持が…", 0, 6, 0, 3, 1, 1, 105102, 1847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適度な食事も\n大切よね", 0, 7, 0, 3, 1, 1, 105102, 1848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか私が\n恋愛読本を読む\n日が来るなんて…", 0, 8, 0, 3, 1, 1, 105102, 1849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぺっぺっ！\n…い、いけないっ！", 0, 1, 0, 1, 1, 1, 105201, 1851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっけな～い！\nひづめで床に傷が！", 0, 2, 0, 1, 1, 1, 105201, 1852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("太っちゃったかも～！\n伐採でダイエット\nしなくっちゃ！", 0, 3, 0, 1, 1, 1, 105201, 1853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きちんと生活すると\n毛づやが良くなる\nみたいなのよね～", 0, 4, 0, 1, 1, 1, 105201, 1854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな、体重\nどれくらいなのかな？", 0, 5, 0, 1, 1, 1, 105201, 1855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体力なら自信\nあるんだけど…\n恋にはちょっぴり\n臆病になっちゃう", 0, 101, 0, 1, 4, 1, 105201, 1856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか人間の女の子\nみたいなデート、\nしてみたいな～♪", 0, 102, 0, 1, 8, 1, 105201, 1857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私ね「どこにでもいる\n普通の女の子」って\n言葉が憧れなんだ～♪", 0, 1, 0, 2, 1, 1, 105201, 1858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チャームポイント？\n自分では分からない\nけど…まつげかなぁ？", 0, 2, 0, 2, 1, 1, 105201, 1859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リマリマ～♪\nはっ！？\nわ、私ったら今何を？", 0, 3, 0, 2, 1, 1, 105201, 1860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("力仕事ならまかせて！", 0, 4, 0, 2, 1, 1, 105201, 1861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人間になりたいな～\nそれか、あなたが\n私みたいな姿に…♪", 0, 101, 0, 2, 4, 1, 105201, 1862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しょうがないなあ、\nこんなにモフらせるの\nあなただけだよ？", 0, 102, 0, 2, 8, 1, 105201, 1863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今朝は寝癖がひどいわ\nしっぽの辺りとか～", 0, 1, 1, 2, 1, 1, 105201, 1864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランチは\nおしゃれなカフェで\nしてみたいな～♪", 0, 2, 2, 2, 1, 1, 105201, 1865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お肌のケアに\nパックしながら\n寝ようかな～", 0, 3, 3, 2, 1, 1, 105201, 1866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やだっ、\nまた寝ぐせついてる！\n直さないと！", 0, 1, 0, 3, 1, 1, 105201, 1867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミシッっていった！\n私、重すぎるかも！？", 0, 2, 0, 3, 1, 1, 105201, 1868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ！　あなたも\n美人さんね～♪", 0, 3, 0, 3, 1, 1, 105201, 1869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、まったり…\n四足歩行しちゃい\nそうだわ…", 0, 4, 0, 3, 1, 1, 105201, 1870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い♪\n…私、毛皮だから\n暑すぎるかも", 0, 5, 0, 3, 1, 1, 105201, 1871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な、なんだか野生に\n帰っちゃいそう！", 0, 6, 0, 3, 1, 1, 105201, 1872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぱくぱく、もぐもぐ、\nぺっぺっ…\nやだ、はしたない！", 0, 7, 0, 3, 1, 1, 105201, 1873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃーーー！\nこの恋愛小説\nとっても\nドキドキしちゃう～", 0, 8, 0, 3, 1, 1, 105201, 1874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵ね～、居るだけで\n女子力があがりそうな\nお部屋だわ～", 0, 1, 0, 1, 1, 1, 105202, 1876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、大丈夫かしら？\n他の子に怖がられたり\nしないかな…？", 0, 2, 0, 1, 1, 1, 105202, 1877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("動物苑…って\n嫌なギルド名ね…", 0, 3, 0, 1, 1, 1, 105202, 1878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("好き、嫌い、好き…\nあっ！　うっかりして\n花占いのお花\n食べちゃった！", 0, 4, 0, 1, 1, 1, 105202, 1879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ、女の子らしい\nものでいっぱいね～！\nときめいちゃうわ～♪", 0, 5, 0, 1, 1, 1, 105202, 1880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体力なら自信\nあるんだけど…\n恋にはちょっぴり\n臆病になっちゃう", 0, 101, 0, 1, 8, 1, 105202, 1881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人が\n来てくれるまで薪割り\nでもしてよっかな？", 0, 102, 0, 1, 8, 1, 105202, 1882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にお出かけ？\nうれしいけど…\n心の準備が！\nはわわわ！", 0, 1, 0, 2, 1, 1, 105202, 1883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\n急に抱きついてきて…\n癒されたいの？", 0, 2, 0, 2, 1, 1, 105202, 1884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぺっぺっ！\n…い、いけないっ！", 0, 3, 0, 2, 1, 1, 105202, 1885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メタモルアップルを\nここで食べたら、\nみんな驚くわよね", 0, 4, 0, 2, 1, 1, 105202, 1886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しょうがないなあ、\nこんなにモフらせるの\nあなただけだよ？", 0, 101, 0, 2, 8, 1, 105202, 1887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人間になりたいな～\nそれか、あなたが\n私みたいな姿に…♪", 0, 102, 0, 2, 8, 1, 105202, 1888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今朝は寝癖がひどいわ\nしっぽの辺りとか～", 0, 1, 1, 2, 1, 1, 105202, 1889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダイエット中だから\nお昼は抜いてるの～", 0, 2, 2, 2, 1, 1, 105202, 1890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お肌のケアに\nパックしながら\n寝ようかな～", 0, 3, 3, 2, 1, 1, 105202, 1891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんとかわいく\nしてないと刈られ…\n狩られちゃうもんね！", 0, 1, 0, 3, 1, 1, 105202, 1892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミシッっていった！\n私、重すぎるかも！？", 0, 2, 0, 3, 1, 1, 105202, 1893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ！　あなたも\n美人さんね～♪", 0, 3, 0, 3, 1, 1, 105202, 1894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～\n森の中にいるみたいに\nとっても落ち着く～", 0, 4, 0, 3, 1, 1, 105202, 1895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵～♪　…\nきゃっ！　私の毛が\nたいへんなことに～！", 0, 5, 0, 3, 1, 1, 105202, 1896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な、なんだか野生に\n帰っちゃいそう！", 0, 6, 0, 3, 1, 1, 105202, 1897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何を食べるかより\n誰と食べるかが\n大事なのよね", 0, 7, 0, 3, 1, 1, 105202, 1898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃーーー！\nこの恋愛小説\nとっても\nドキドキしちゃう～", 0, 8, 0, 3, 1, 1, 105202, 1899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴァイスフリューゲル\nを盛り上げる方法、\n共に語らおう！", 0, 1, 0, 1, 1, 1, 105301, 1901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私は子供ではない…！\nが、お菓子は\nいただこう！", 0, 2, 0, 1, 1, 1, 105301, 1902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋はきちんと\n片づけておかなくては\n部屋の汚れは\n心の汚れだ", 0, 3, 0, 1, 1, 1, 105301, 1903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむむ…明日\n目が覚めたら、身長が\n伸びていないものか…", 0, 4, 0, 1, 1, 1, 105301, 1904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子が常備されて\nいる部屋。そんな\nものが、私の好みだ…", 0, 5, 0, 1, 1, 1, 105301, 1905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつとの新たな\n鍛錬が\n待ち遠しいな…！", 0, 101, 0, 1, 4, 1, 105301, 1906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、あいつと\n過ごしていて、毎日が\n充実しているな…", 0, 102, 0, 1, 8, 1, 105301, 1907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("軍人の本分は日々の\n研鑽にあるからな。\n今日も鍛錬に\n行かないか？", 0, 1, 0, 2, 1, 1, 105301, 1908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日牛乳を飲んでいる\nのだが、なかなか背が\n伸びないものだな…", 0, 2, 0, 2, 1, 1, 105301, 1909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公にも、飴をくれて\nやろうか？\nあまいぞ～！\n美味しいぞ～！", 0, 3, 0, 2, 1, 1, 105301, 1910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私ともっと高く、\n共に飛ぼう！", 0, 4, 0, 2, 1, 1, 105301, 1911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公は、本当に頼りに\nなる男だな…いや、\nふとそう思っただけだ", 0, 101, 0, 2, 4, 1, 105301, 1912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公と共にいられる\nことは私の喜びだ。\nこれからも\nよろしく頼むぞ", 0, 102, 0, 2, 8, 1, 105301, 1913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ、いい朝だ。\n本国の夜明けを\n思い出してしまうな！", 0, 1, 1, 2, 1, 1, 105301, 1914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ昼食に\nするか。腹が減っては\n戦はできないからな", 0, 2, 2, 2, 1, 1, 105301, 1915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわああ…私は子供\nではないが…眠い時は\n眠いのだ…", 0, 3, 3, 2, 1, 1, 105301, 1916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身だしなみは、心の\n在りようを映すから\n気をつけなくてはな", 0, 1, 0, 3, 1, 1, 105301, 1917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう…軍人たるもの\n常日頃、油断は\nできないのだが…\nお、落ち着くな…", 0, 2, 0, 3, 1, 1, 105301, 1918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ…このかわいさ…\n本国に持って\n帰りたい…", 0, 3, 0, 3, 1, 1, 105301, 1919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このともし火、戦いに\n明け暮れる我らの心を\n癒すものだな…", 0, 4, 0, 3, 1, 1, 105301, 1920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ～、ぽかぽか…\nい、いや！\n気を緩めないぞっ！", 0, 5, 0, 3, 1, 1, 105301, 1921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うおおおおおっ！\n鍛錬、鍛錬、\n鍛錬っ！！", 0, 6, 0, 3, 1, 1, 105301, 1922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつ戦いになっても\n困らぬように、\n腹八分目に\nしておくのだ！", 0, 7, 0, 3, 1, 1, 105301, 1923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを読んで、新たな\n戦術を編み出すぞっ！", 0, 8, 0, 3, 1, 1, 105301, 1924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには掃除でも\nするか。部屋が\n綺麗になるのは\n喜ばしいことだ", 0, 1, 0, 1, 1, 1, 105302, 1926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の中では\n剣を振り回せないのが\n玉に瑕だな…", 0, 2, 0, 1, 1, 1, 105302, 1927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子が常備されて\nいる部屋。そんな\nものが、私の好みだ…", 0, 3, 0, 1, 1, 1, 105302, 1928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日牛乳を飲んでいる\nのだが、なかなか背が\n伸びないものだな…", 0, 4, 0, 1, 1, 1, 105302, 1929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家庭を守れない者が\n国を守れるはずが\nない。この部屋も\n私が守るぞ！", 0, 5, 0, 1, 1, 1, 105302, 1930);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつは今頃、何を\nしているのだろうな…\nふふっ", 0, 101, 0, 1, 8, 1, 105302, 1931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと会える日が\nこんなにも待ち遠しく\nなるとはな…", 0, 102, 0, 1, 8, 1, 105302, 1932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("軍人の本分は日々の\n研鑽にあるからな\n今日も鍛錬に\n行かないか？", 0, 1, 0, 2, 1, 1, 105302, 1933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おお、今日も鍛錬の\n時間だったか！\nすまないな\nすぐ行く！", 0, 2, 0, 2, 1, 1, 105302, 1934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私は子供ではない！\nが…たまには童心に\n帰りたい時もある…", 0, 3, 0, 2, 1, 1, 105302, 1935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公にも、飴を\nくれてやろうか？\nあまいぞ～！\n美味しいぞ～！", 0, 4, 0, 2, 1, 1, 105302, 1936);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私と歩きたいのか…？\nそうだな。二人で\n散歩でも行こうか", 0, 101, 0, 2, 8, 1, 105302, 1937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公と共にいられる\nことは私の喜びだ\nこれからも\nよろしく頼むぞ", 0, 102, 0, 2, 8, 1, 105302, 1938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ、いい朝だ\n本国の夜明けを\n思い出してしまうな！", 0, 1, 1, 2, 1, 1, 105302, 1939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ昼時だな\n鍛錬の手を緩めて\n昼食にするか", 0, 2, 2, 2, 1, 1, 105302, 1940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝る前に…あと少し\nだけ、鍛錬を…", 0, 3, 3, 2, 1, 1, 105302, 1941);
