INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このふかふかの優しさ\n主さまのようです", 0, 2, 0, 3, 1, 1, 105901, 2118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい♪\n主さまにそっくり♪", 0, 3, 0, 3, 1, 1, 105901, 2119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("故郷の香りとは\n違いますが、これも\n心地よいものです…", 0, 4, 0, 3, 1, 1, 105901, 2120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで洗濯物を\n乾かせるでしょうか", 0, 5, 0, 3, 1, 1, 105901, 2121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("都会の人々は\nこんなふうに\n運動を…！？", 0, 6, 0, 3, 1, 1, 105901, 2122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…主さまにも\n食べさせて\n差し上げたい…\nあーんって♪", 0, 7, 0, 3, 1, 1, 105901, 2123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よく学んで、\n主さまのお役に\n立たなければ", 0, 8, 0, 3, 1, 1, 105901, 2124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまがいつ戻って\n来ても平気なよう\n部屋を綺麗に保たねば", 0, 1, 0, 1, 1, 1, 105902, 2126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("節約のためにも\n自家菜園などするのは\nどうでしょう…　", 0, 2, 0, 1, 1, 1, 105902, 2127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アメスさまへの\nお祈りができそうな\n場所は…", 0, 3, 0, 1, 1, 1, 105902, 2128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("瞑想をすると\n心が安らぎます…", 0, 4, 0, 1, 1, 1, 105902, 2129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("都会の方の身なりを\n勉強した方が\n良いのでしょうか？", 0, 5, 0, 1, 1, 1, 105902, 2130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたくしの居場所は\n主さまのお傍です\nずっと、ずっと…♪", 0, 101, 0, 1, 8, 1, 105902, 2131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまの隣には\nわたくしが…\nわたくしの隣には\n主さまが…幸せです", 0, 102, 0, 1, 8, 1, 105902, 2132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、なにか\nしてほしいことは\nありませんか？\n欲しいものは？", 0, 1, 0, 2, 1, 1, 105902, 2133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたくし、背が伸び\nましたでしょうか？\n…そうですか", 0, 2, 0, 2, 1, 1, 105902, 2134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お出かけですか？\nわたくしもお供\nいたします", 0, 3, 0, 2, 1, 1, 105902, 2135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃん！\n主さま…\nいじわるです", 0, 4, 0, 2, 1, 1, 105902, 2136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、なにか御用は\nありませんか？\nわたくし、主さまの\nお役にたちたいのです", 0, 101, 0, 2, 8, 1, 105902, 2137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまの優しさに\nわたくしはいつも\n癒されています…", 0, 102, 0, 2, 8, 1, 105902, 2138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\n主さまの可愛らしい\n寝顔、堪能致しました", 0, 1, 1, 2, 1, 1, 105902, 2139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("のんびりした時間帯\nですね…ふぁ～…\nし、失礼致しました", 0, 2, 2, 2, 1, 1, 105902, 2140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、都会は夜でも\nこんなにも、にぎやか\nなのですね", 0, 3, 3, 2, 1, 1, 105902, 2141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまに会う前に\n身なりを整えなくては\nいけませんね", 0, 1, 0, 3, 1, 1, 105902, 2142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このふかふかの優しさ\n主さまのようです", 0, 2, 0, 3, 1, 1, 105902, 2143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい♪\n主さまにそっくり♪", 0, 3, 0, 3, 1, 1, 105902, 2144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この心地よさ…\n主さまのようです♪", 0, 4, 0, 3, 1, 1, 105902, 2145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで洗濯物を\n乾かせるでしょうか　", 0, 5, 0, 3, 1, 1, 105902, 2146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁっはぁっはぁっ\n…すべては\n主さまのため…", 0, 6, 0, 3, 1, 1, 105902, 2147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("都会の味…\nとてもおいしいです\n…もぐもぐもぐ", 0, 7, 0, 3, 1, 1, 105902, 2148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("都会のことを\n学ばないと…\nふむふむ", 0, 8, 0, 3, 1, 1, 105902, 2149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～…あっ\n見られちゃい\nましたか？", 0, 1, 0, 2, 1, 1, 190801, 2151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスの\n使い心地は\nどうですか？", 0, 2, 0, 2, 1, 1, 190801, 2152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご用があれば\nなんでも言って\nくださいね～♪", 0, 3, 0, 2, 1, 1, 190801, 2153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ときどきみなさんと\nクエストに行きたいな\nって思っちゃいます", 0, 4, 0, 2, 1, 1, 190801, 2154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\nお掃除の方、\nはじめていきますね", 0, 1, 1, 2, 1, 1, 190801, 2155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆さん、お昼ごはんの\nご要望がありましたら\n用意致しますよ♪", 0, 2, 2, 2, 1, 1, 190801, 2156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは夜でも\nにぎやかですね", 0, 3, 3, 2, 1, 1, 190801, 2157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…\n少しうとうと\nしてしまった", 0, 1, 0, 1, 1, 1, 104701, 2158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("室内だし兜を脱ぐか\n…いや\nやはりやめておこう", 0, 2, 0, 1, 1, 1, 104701, 2159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋にいると\n鎧が蒸し暑くなるが\n我慢せねば…", 0, 3, 0, 1, 1, 1, 104701, 2160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事が門番だからか\n部屋にいても\nじっとしてしまう…", 0, 4, 0, 1, 1, 1, 104701, 2161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年と会話したことを\n思いだすと\n自然と楽しくなるな", 0, 5, 0, 1, 1, 1, 104701, 2162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年のことを考えると\n顔がにやけてしまう", 0, 101, 0, 1, 4, 1, 104701, 2163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年は今頃\n平和に過ごせて\nいるかな…", 0, 102, 0, 1, 8, 1, 104701, 2164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　悪いが\n兜は脱がないぞ", 0, 1, 0, 2, 1, 1, 104701, 2165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私と遊びたいのか？\nそう言われても\n何をしていいやら…", 0, 2, 0, 2, 1, 1, 104701, 2166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鎧が重くないかって？\n大丈夫。けっこう\n鍛えているからな", 0, 3, 0, 2, 1, 1, 104701, 2167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年、寒くはないか？\nいや自分がこうなので\n人が薄着に見えてね", 0, 4, 0, 2, 1, 1, 104701, 2168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君といると、兜の中が\nいつもより暑いんだ", 0, 101, 0, 2, 4, 1, 104701, 2169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私としゃべりたい？\n物好きだな\nでも、嬉しいよ", 0, 102, 0, 2, 8, 1, 104701, 2170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早いな少年\nえ？　私の仕事に\n合わせてくれたのか", 0, 1, 1, 2, 1, 1, 104701, 2171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食の誘い？\n嬉しいけど\n人前では食べないんだ", 0, 2, 2, 2, 1, 1, 104701, 2172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王宮騎士団の\n日報を書かなければ…\n『何事もなし』、と", 0, 3, 3, 2, 1, 1, 104701, 2173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鎧を着ているから\n感触が分かりづらい\nのが残念だ…", 0, 2, 0, 3, 1, 1, 104701, 2175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいいな…\n私には似合わないが\nぎゅ…ってしよう", 0, 3, 0, 3, 1, 1, 104701, 2176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い香りだ…\n普段はどうしても\n鉄くさくなるからな", 0, 4, 0, 3, 1, 1, 104701, 2177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わかっていたけど\n鎧を着たまま暖炉に\nあたると暑い…", 0, 5, 0, 3, 1, 1, 104701, 2178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兜を脱がずに食べる\nうん、段々コツが\n掴めてきた…", 0, 7, 0, 3, 1, 1, 104701, 2180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兜があっても\n意外と本くらいは\n難なく読めるんだ", 0, 8, 0, 3, 1, 1, 104701, 2181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("居心地よくて\nゴロゴロしちゃうよ～\n…いつも通りだね", 0, 1, 0, 1, 1, 1, 102601, 2183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドングリの木\n近くに生えてない？", 0, 2, 0, 1, 1, 1, 102601, 2184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("快適な寝床があれば\nそれだけで幸せだねぇ", 0, 3, 0, 1, 1, 1, 102601, 2185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしと一緒に\nだらけてくれる人が\nいそうだねぇ", 0, 4, 0, 1, 1, 1, 102601, 2186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここなら牧場よりも\n速く配達が\n届きそうだね～", 0, 5, 0, 1, 1, 1, 102601, 2187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんパン買ったし\nあいつにも\n分けてあげよう", 0, 101, 0, 1, 4, 1, 102601, 2188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと一緒に\nだらけられたら\n最高に幸せだね", 0, 102, 0, 1, 8, 1, 102601, 2189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドングリでも\nつまみながら\n一緒にゲームしようよ", 0, 1, 0, 2, 1, 1, 102601, 2190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("横になりたいから\n枕になっておくれよ～\nあんたあったかいしさ", 0, 2, 0, 2, 1, 1, 102601, 2191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドングリあげるから\nあんパン買ってきて～", 0, 3, 0, 2, 1, 1, 102601, 2192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～\n疲れちゃったよ～\nおんぶして運んで～", 0, 4, 0, 2, 1, 1, 102601, 2193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたといると\nリア充って\n感じがするよ", 0, 101, 0, 2, 4, 1, 102601, 2194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが一生\n世話してくれたら\n人生安泰なんだけどね", 0, 102, 0, 2, 8, 1, 102601, 2195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわ～っ…\nおはよう…あたしは\nまだ眠いよ", 0, 1, 1, 2, 1, 1, 102601, 2196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろお昼寝でも\nしたい気分だねぇ", 0, 2, 2, 2, 1, 1, 102601, 2197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("徹夜でゲームするけど\nあんたもどうだい？\nあたしは強いよ", 0, 3, 3, 2, 1, 1, 102601, 2198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ…だめだこれ。\n気持ち良くて\n落ちそう…", 0, 2, 0, 3, 1, 1, 102601, 2200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいものに\n囲まれて寝るのも\nよさそうだねぇ…", 0, 3, 0, 3, 1, 1, 102601, 2201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心身ともに\nリラックスした状態で\nぐうたら出来そうだね", 0, 4, 0, 3, 1, 1, 102601, 2202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふい～…\nごくらくごくらく…\n暖かいねぇ", 0, 5, 0, 3, 1, 1, 102601, 2203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べてすぐ寝ると\n牛になるって\n本当なのかな？", 0, 7, 0, 3, 1, 1, 102601, 2205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おー！　この本なら\nあたしも居眠りせずに\n読めそうだよ", 0, 8, 0, 3, 1, 1, 102601, 2206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソル…\nおっきな街だなぁ…", 0, 1, 0, 1, 1, 1, 106301, 2208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ロザリア…\nきっと、いるよね？", 0, 2, 0, 1, 1, 1, 106301, 2209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、弓の練習\nサボっちゃってるな…", 0, 3, 0, 1, 1, 1, 106301, 2210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の私は\n森番じゃなくて\n家番だよ！", 0, 4, 0, 1, 1, 1, 106301, 2211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとだけ\n慣れてきたかも？", 0, 5, 0, 1, 1, 1, 106301, 2212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか、\nあの人と一緒に…", 0, 101, 0, 1, 4, 1, 106301, 2213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…なんか最近、\nあの人のこと\nばっかり…", 0, 102, 0, 1, 8, 1, 106301, 2214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしよかったら\n街に出かけない？", 0, 1, 0, 2, 1, 1, 106301, 2215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋、\n妖精さんも\n気に入るかも！", 0, 2, 0, 2, 1, 1, 106301, 2216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は\nなににしよっか？", 0, 3, 0, 2, 1, 1, 106301, 2217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はどこ行く？", 0, 4, 0, 2, 1, 1, 106301, 2218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには二人で…\nな、なんちゃって！", 0, 101, 0, 2, 4, 1, 106301, 2219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、\nずっと楽しいんだ！\nあなたのおかげかな", 0, 102, 0, 2, 8, 1, 106301, 2220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n今日も一緒に\n頑張ろうね！", 0, 1, 1, 2, 1, 1, 106301, 2221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はどうする？\nあなたのオススメに\n連れて行って欲しいな", 0, 2, 2, 2, 1, 1, 106301, 2222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルは\n夜でも賑やかだね！", 0, 3, 3, 2, 1, 1, 106301, 2223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁっ！\nすっごく\nふわふわだよ！", 0, 2, 0, 3, 1, 1, 106301, 2225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわい～！\nぎゅってしたく\nなっちゃうかも！", 0, 3, 0, 3, 1, 1, 106301, 2226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん\nなんか…いい匂い？", 0, 4, 0, 3, 1, 1, 106301, 2227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すっごいなー\nあったかいなー！", 0, 5, 0, 3, 1, 1, 106301, 2228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁっ、おいしい！\nもっと食べたい\nかも…！", 0, 7, 0, 3, 1, 1, 106301, 2230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("も、文字は苦手…\nでも、頑張らないと\nだよね…！", 0, 8, 0, 3, 1, 1, 106301, 2231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にんじんとピーマンを\n食べないでいい方法\nないかな…", 0, 1, 0, 1, 1, 1, 103601, 2233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カップケーキが\n食べたいな…", 0, 2, 0, 1, 1, 1, 103601, 2234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("予習が終わりました！\nさて、次は復習を\nしないと…", 0, 3, 0, 1, 1, 1, 103601, 2235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人の部屋にいる\n私って…もしかして\nふしんしゃなんじゃ？", 0, 4, 0, 1, 1, 1, 103601, 2236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男の人は、みんな\nへんたいだと\n聞きました…", 0, 5, 0, 1, 1, 1, 103601, 2237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人に、一緒に\n遊んでほしいけど…\nな、なんていえば？", 0, 101, 0, 1, 4, 1, 103601, 2238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早く大人になりたいな\n…あの人と同じくらい", 0, 102, 0, 1, 8, 1, 103601, 2239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼ、防犯魔石を\n鳴らしますよ！？", 0, 1, 0, 2, 1, 1, 103601, 2240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へんたい！？　…\nあ、あなたでしたか～\nやっぱりへんたーい！", 0, 2, 0, 2, 1, 1, 103601, 2241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ宿題です\nやっておいて\nくださいね", 0, 3, 0, 2, 1, 1, 103601, 2242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、遅刻ですよ\n待っていたんですから", 0, 4, 0, 2, 1, 1, 103601, 2243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にらめっこですか？\nあ、あなたの前で変顔\nするのはちょっと…", 0, 101, 0, 2, 4, 1, 103601, 2244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…何歳まで\n子供だと思いますか？", 0, 102, 0, 2, 8, 1, 103601, 2245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("顔を洗って、着替えて\n朝ごはんを食べて、\n歯を磨いて…", 0, 1, 1, 2, 1, 1, 103601, 2246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("て、鉄棒の練習！？　\nほ、他のことを\nしませんか？", 0, 2, 2, 2, 1, 1, 103601, 2247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、眠くないです\n子供ではありません\nから…ふわぁ", 0, 3, 3, 2, 1, 1, 103601, 2248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひと休みしよっと\n………うん、\nひと休みおしまい♪", 0, 2, 0, 3, 1, 1, 103601, 2250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つ、つぶらな瞳には\n弱いんです", 0, 3, 0, 3, 1, 1, 103601, 2251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リラックスできますね\n集中力も\n上がりそうです", 0, 4, 0, 3, 1, 1, 103601, 2252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいと\n眠くなっちゃうな…\n勉強しなくちゃなのに", 0, 5, 0, 3, 1, 1, 103601, 2253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ピーマンもこれくらい\nおいしければ\nいいのに…", 0, 7, 0, 3, 1, 1, 103601, 2255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本、むずかしい\n…もっと勉強\nがんばらなくちゃ", 0, 8, 0, 3, 1, 1, 103601, 2256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はみんなに\nなにを読んで\nあげようかしら", 0, 1, 0, 1, 1, 1, 101501, 2258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちと同じ\n目線で考えるのが\n大事よね", 0, 2, 0, 1, 1, 1, 101501, 2259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お天気が良い日は\nみんなでお散歩に\n行きたいわね～", 0, 3, 0, 1, 1, 1, 101501, 2260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鬼ごっこにかくれんぼ\n…みんなは\nどっちが好きかしら", 0, 4, 0, 1, 1, 1, 101501, 2261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お遊戯会の配役、\n考え出すと\n大変だわ～", 0, 5, 0, 1, 1, 1, 101501, 2262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼は優しいから、\nきっと良い\nお父さんになるわね", 0, 101, 0, 1, 4, 1, 101501, 2263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼には私がいないと\n…っていうのは少し\n過保護すぎるかしら？", 0, 102, 0, 1, 8, 1, 101501, 2264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("保育園の行事を\n考えてるんだけど…\n良い案ないかしら？", 0, 1, 0, 2, 1, 1, 101501, 2265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、子どもたちと\nおやつを作るから、\n食べに来てね", 0, 2, 0, 2, 1, 1, 101501, 2266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よかったら一緒に\n絵本を作らない？", 0, 3, 0, 2, 1, 1, 101501, 2267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたはいつも元気ね\n先生も見習わないと♪", 0, 4, 0, 2, 1, 1, 101501, 2268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先生は\nずーっと、ずーっと、\nあなたの味方だからね", 0, 101, 0, 2, 4, 1, 101501, 2269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたみたいな\nいい子をお世話できて\n先生は幸せものだわ", 0, 102, 0, 2, 8, 1, 101501, 2270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう～\nちゃんと朝ごはんは\n食べた？", 0, 1, 1, 2, 1, 1, 101501, 2271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼寝の時間ね♪\nあなたも一緒に\n寝ましょうか", 0, 2, 2, 2, 1, 1, 101501, 2272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すっかり真っ暗ね。\n今日も一日、\nよくできました♪", 0, 3, 3, 2, 1, 1, 101501, 2273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかねぇ♪\n年甲斐もなく、\n飛び跳ねちゃいそう", 0, 2, 0, 3, 1, 1, 101501, 2275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらあら、かわいい！\n保育園のみんなに\n見せてあげたいわ", 0, 3, 0, 3, 1, 1, 101501, 2276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね～\n保育園にも\n置こうかしら", 0, 4, 0, 3, 1, 1, 101501, 2277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い日は、ここで\n子どもたちに絵本を\n読んであげましょ♪", 0, 5, 0, 3, 1, 1, 101501, 2278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しい～♪\n遠足に持っていったら\nみんな喜びそう", 0, 7, 0, 3, 1, 1, 101501, 2280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなが\n楽しめる読み聞かせの\n方法特集♪　素敵ねぇ", 0, 8, 0, 3, 1, 1, 101501, 2281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界の前に、\nこの部屋を征服\nしてやろう♪", 0, 1, 0, 1, 1, 1, 104401, 2283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("拠点とはやはり\n斯くあるべきじゃの", 0, 2, 0, 1, 1, 1, 104401, 2284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属の物はわらわの物\n故に、この部屋は\nわらわの部屋じゃな！", 0, 3, 0, 1, 1, 1, 104401, 2285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("永く眠っている間に\n随分と世界は変わった\nようじゃな…", 0, 4, 0, 1, 1, 1, 104401, 2286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うるさいのう～\nまったく、近頃の\n若いもんは…", 0, 5, 0, 1, 1, 1, 104401, 2287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あやつが来てから\n動悸が治まらぬ…\n如何ような病で\nあろうかの…", 0, 101, 0, 1, 4, 1, 104401, 2288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属よ、どこに行った\nのじゃ？\nわらわの世話を\n許可するのじゃ", 0, 102, 0, 1, 8, 1, 104401, 2289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いずれ世界は\n我が手中に収まる\nふふふ、\n楽しみじゃのう", 0, 1, 0, 2, 1, 1, 104401, 2290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属よ、わらわから\n離れてはならんぞ！\n子供に戻ってしまう\nではないか！", 0, 2, 0, 2, 1, 1, 104401, 2291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トマトジュースが\n欲しいのじゃ！\n野菜ジュースでは\nダメだぞ！", 0, 3, 0, 2, 1, 1, 104401, 2292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("蚊にくわれたぞ！\nわらわの血を吸う\nとは～！", 0, 4, 0, 2, 1, 1, 104401, 2293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こら、頭をなでるな\nお主はこの姿でも\n子供扱いするのか？", 0, 101, 0, 2, 4, 1, 104401, 2294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お主が望むなら世界の\n半分をくれてやっても\n良いのじゃぞ？", 0, 102, 0, 2, 8, 1, 104401, 2295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝早くから感心じゃの\nさすがわらわの\n眷属じゃ", 0, 1, 1, 2, 1, 1, 104401, 2296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("太陽は苦手じゃ…\nこの部屋の中で\n過ごそうぞ", 0, 2, 2, 2, 1, 1, 104401, 2297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も更けてきた！\nわらわ達の時間は\nこれからじゃ～♪", 0, 3, 3, 2, 1, 1, 104401, 2298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よい座り心地じゃ\nわらわの玉座としよう", 0, 2, 0, 3, 1, 1, 104401, 2300);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛いではないか\nわらわの眷属に\nしてやろうかのう", 0, 3, 0, 3, 1, 1, 104401, 2301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ、良い気持ちじゃ\nこれを作った者、\n褒めてつかわすぞ", 0, 4, 0, 3, 1, 1, 104401, 2302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい…\n身も心も\n浄化されるようじゃ", 0, 5, 0, 3, 1, 1, 104401, 2303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼のわらわが、\nこのようなもの…\nうまい♪", 0, 7, 0, 3, 1, 1, 104401, 2305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このまま大人の姿を\n保つ方法…どこかに\n書いてないかのう", 0, 8, 0, 3, 1, 1, 104401, 2306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いろんな人がいて\nいろんな服を着てて…\n目の保養になります♪", 0, 1, 0, 1, 1, 1, 105401, 2308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レイ様への新作\nどんな服にしよう…\n方向性が絞れない～！", 0, 2, 0, 1, 1, 1, 105401, 2309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("忘れないうちに\n隠し糸のメンテナンス\nやっておこうっと！", 0, 3, 0, 1, 1, 1, 105401, 2310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むっ！　あの人の\nスリーサイズは…\nほほう…なるほど♪", 0, 4, 0, 1, 1, 1, 105401, 2311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ノゾミさんの\n衣装はああして\nチカさんのは…", 0, 5, 0, 1, 1, 1, 105401, 2312);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私がアイドル…\n…実感ないけど\n精一杯やってみよう", 0, 101, 0, 1, 4, 1, 105401, 2313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか私が\nアイドルになるなんて\n思ってなかったです", 0, 102, 0, 1, 8, 1, 105401, 2314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんですかぁ？\n衣装作りで疲れて\n眠いんですぅ…", 0, 1, 0, 2, 1, 1, 105401, 2315);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーっ！　また\n服がほつれてる…\nしょうがないですね", 0, 2, 0, 2, 1, 1, 105401, 2316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はっ！　ちょうど今\n新しいデザインが\n思い浮かびました！", 0, 3, 0, 2, 1, 1, 105401, 2317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇そうですね？\n時間あるなら仕事\n手伝ってください！", 0, 4, 0, 2, 1, 1, 105401, 2318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしました？\n新しい服が\n欲しくなりましたか？", 0, 101, 0, 2, 4, 1, 105401, 2319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんのおかげで\nカルミナでも\n頑張れてますよ！", 0, 102, 0, 2, 8, 1, 105401, 2320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます…\nなんで朝って毎日\nやってくるんでしょう", 0, 1, 1, 2, 1, 1, 105401, 2321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空きましたね\n騎士さんはちゃんと\n御飯食べましたか？", 0, 2, 2, 2, 1, 1, 105401, 2322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の方が\n作業が捗るのは\n私だけですかね？", 0, 3, 3, 2, 1, 1, 105401, 2323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このふかふか具合\nいい素材を\n使ってますね", 0, 2, 0, 3, 1, 1, 105401, 2325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小さくて可愛い♪\nそうだ！　レイ様の\nぬいぐるみを…！", 0, 3, 0, 3, 1, 1, 105401, 2326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう時くらい\n何も考えずに\nリラックスしないと♪", 0, 4, 0, 3, 1, 1, 105401, 2327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("炎を使った服って\nカッコ良いかも…\nでも材料がな～…", 0, 5, 0, 3, 1, 1, 105401, 2328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何をするにも\n食事は大切！\n体力が資本です！", 0, 7, 0, 3, 1, 1, 105401, 2330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私もいつか\nデザインを\nまとめて本に…", 0, 8, 0, 3, 1, 1, 105401, 2331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またお魚を\n捕りにいこうかな♪", 0, 1, 0, 1, 1, 1, 107501, 2333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろみんなも\nお腹が空くころ\nじゃないですか～？", 0, 2, 0, 1, 1, 1, 107501, 2334);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここなら、\n日焼けの心配は\nありませんね！", 0, 3, 0, 1, 1, 1, 107501, 2335);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お刺身に焼き貝…\nお腹が魚介類を\n求めてますっ！", 0, 4, 0, 1, 1, 1, 107501, 2336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐのも食べるのも\n大得意です！", 0, 5, 0, 1, 1, 1, 107501, 2337);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人と二人で\n浜辺を散歩…\n素敵ですねぇ", 0, 101, 0, 1, 4, 1, 107501, 2338);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人に水着を\n褒めてもらえたら、\nすごく嬉しいなぁ", 0, 102, 0, 1, 8, 1, 107501, 2339);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには釣りじゃなく\n一緒に素潜りでも\n行きませんか？", 0, 1, 0, 2, 1, 1, 107501, 2340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男の子に水着を\n見られるのって\n少し緊張しちゃいます", 0, 2, 0, 2, 1, 1, 107501, 2341);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスの\nみんなとも、\n海に行きたいですね！", 0, 3, 0, 2, 1, 1, 107501, 2342);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの水着、\n私が選んであげます！", 0, 4, 0, 2, 1, 1, 107501, 2343);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎの練習なら\n付き合いますよ！\n手取り足取り♪", 0, 101, 0, 2, 4, 1, 107501, 2344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿が好きなら\nいくらでも\n着てあげますよぉ♪", 0, 102, 0, 2, 8, 1, 107501, 2345);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の海も\n幻想的で\nいいですよねぇ～！", 0, 1, 1, 2, 1, 1, 107501, 2346);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はみんなで、\n海鮮バーベキューとか\nどうでしょう！", 0, 2, 2, 2, 1, 1, 107501, 2347);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海は星が\nきれいですよ！\n見に行きましょう！", 0, 3, 3, 2, 1, 1, 107501, 2348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎ疲れたので\nちょっと休憩です～", 0, 2, 0, 3, 1, 1, 107501, 2350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたにも、\n可愛い水着を\n着せてあげたいです", 0, 3, 0, 3, 1, 1, 107501, 2351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか、\nリゾート気分です…", 0, 4, 0, 3, 1, 1, 107501, 2352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふい～、泳ぎで冷えた\n身体を暖めましょう～", 0, 5, 0, 3, 1, 1, 107501, 2353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいひ～です～\nこれ、海水浴にも\n持っていきたいですね", 0, 7, 0, 3, 1, 1, 107501, 2355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("南国のフルーツ図鑑\n…じゅるり…", 0, 8, 0, 3, 1, 1, 107501, 2356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ～♪　おいしそ…\nか、かわいいですね～", 0, 10, 0, 3, 1, 1, 107501, 2358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これくらい大きな貝…\n食べたいな～\n食べたいな～～", 0, 11, 0, 3, 1, 1, 107501, 2359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好で\n部屋をうろつくのは\n不思議な感じがします", 0, 1, 0, 1, 1, 1, 107601, 2360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("南国の果実を使って\n主さまにデザートを\nお作りしましょう", 0, 2, 0, 1, 1, 1, 107601, 2361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの水着ですし\nこれから定期的に\n海水浴に行きたいです", 0, 3, 0, 1, 1, 1, 107601, 2362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の生き物も、\n森の生き物に負けず\n可愛かったです…", 0, 4, 0, 1, 1, 1, 107601, 2363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クロールの練習なら、\n部屋でもできそうです", 0, 5, 0, 1, 1, 1, 107601, 2364);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまに、水着姿を\n褒めていただけた…\nえへへ♪", 0, 101, 0, 1, 4, 1, 107601, 2365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で主さまの\nお世話をしたら、\n喜びますでしょうか…", 0, 102, 0, 1, 8, 1, 107601, 2366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お疲れでしたら\nわたくしの膝を\nお使いくださいね", 0, 1, 0, 2, 1, 1, 107601, 2367);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、海の家で\nつかうおこづかいを\n渡しておきますね", 0, 2, 0, 2, 1, 1, 107601, 2368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の美しさは、\n森とはちがう\n魅力がありました", 0, 3, 0, 2, 1, 1, 107601, 2369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この髪飾りですか？\n造花ですから\n水の中も平気です", 0, 4, 0, 2, 1, 1, 107601, 2370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着でくっついて\n眠ると、いつもより\n密着して暖かいです", 0, 101, 0, 2, 4, 1, 107601, 2371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はじめての海が、\n主さまと一緒で\n幸せです♪", 0, 102, 0, 2, 8, 1, 107601, 2372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます。\n泳ぎに行く準備は\n万端です", 0, 1, 1, 2, 1, 1, 107601, 2373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午後は泳ぐのをやめて\nスイカ割りなど\nいかがでしょう？", 0, 2, 2, 2, 1, 1, 107601, 2374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も更けてきました…\n波の音を聞きながら\n少しお話しませんか？", 0, 3, 3, 2, 1, 1, 107601, 2375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あぅ…この家具には、\n人をダメにする魔法が\nかけられています…", 0, 2, 0, 3, 1, 1, 107601, 2377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ♪\nあなたも、海水浴に\n行きますか？", 0, 3, 0, 3, 1, 1, 107601, 2378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\nきっと主さまも\n気に入ります", 0, 4, 0, 3, 1, 1, 107601, 2379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは暖かいです…\n後ほど主さまと一緒に\nあたりましょう", 0, 5, 0, 3, 1, 1, 107601, 2380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳いだ後の食事は\n一段と美味しく\n感じます", 0, 7, 0, 3, 1, 1, 107601, 2382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("深海魚の生態…\nこれは主さまにも\nお伝えしなくては…", 0, 8, 0, 3, 1, 1, 107601, 2383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("顔立ちが、主さまに\n似ております…\nかわいらしい♪", 0, 10, 0, 3, 1, 1, 107601, 2385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかですね\n主さまのようです♪", 0, 11, 0, 3, 1, 1, 107601, 2386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除、お掃除\nふんふふ～ん☆\nあ、聞かれてました？", 0, 1, 0, 1, 1, 1, 107701, 2387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日焼けには回復魔法が\n効きますよ。どうして\n逃げるんですか～！", 0, 2, 0, 1, 1, 1, 107701, 2388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はドジを\nしませんように！", 0, 3, 0, 1, 1, 1, 107701, 2389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("接客業を極めれば\nメイドとして\n成長できるかも？", 0, 4, 0, 1, 1, 1, 107701, 2390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着って\n動きやすいんですけど\n人の目が気になります", 0, 5, 0, 1, 1, 1, 107701, 2391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人の気持ちを知る\n魔法とかあれば…\nな、なんでもないです", 0, 101, 0, 1, 4, 1, 107701, 2392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着でご奉仕したら、\nあの人は喜ぶかな？", 0, 102, 0, 1, 8, 1, 107701, 2393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑いのでしたら、\n私が魔法で涼しく…\nえ？　いらない？", 0, 1, 0, 2, 1, 1, 107701, 2394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か御用ですか？\n特にないのでしたら、\nお話ししましょう♪", 0, 2, 0, 2, 1, 1, 107701, 2395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿でも\nメイドはメイドです\nご奉仕しますよ！", 0, 3, 0, 2, 1, 1, 107701, 2396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっ！　あ、危うく\n転ぶところでした…\n…きゃうっ！", 0, 4, 0, 2, 1, 1, 107701, 2397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしましたか？\nあなたの御用なら、\n喜んでお受けしますよ", 0, 101, 0, 2, 4, 1, 107701, 2398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿をあなたに\n見られると、\nドキドキしちゃいます", 0, 102, 0, 2, 8, 1, 107701, 2399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は暑くてやる気が\n出ない？　でしたら、\nえぇい、元気になぁれ", 0, 1, 1, 2, 1, 1, 107701, 2400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹がぺこぺこなら、\nお昼は海の家で\n食べましょう♪", 0, 2, 2, 2, 1, 1, 107701, 2401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の浜辺でお散歩も\nいいですね。たくさん\n転びそうですけど…", 0, 3, 3, 2, 1, 1, 107701, 2402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩しながら、\nお掃除すれば\n一石二鳥です！", 0, 2, 0, 3, 1, 1, 107701, 2404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きれいにすれば\nかわいさも倍増\nですよ～♪", 0, 3, 0, 3, 1, 1, 107701, 2405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な香りです～\n救護院に置けば、\nみんな喜ぶかも～", 0, 4, 0, 3, 1, 1, 107701, 2406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいですね…\nはっ！　いけません！\nメイドがサボるなんて", 0, 5, 0, 3, 1, 1, 107701, 2407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理のできない\nメイドなんて…\nはぐはぐ、おいしい♪", 0, 7, 0, 3, 1, 1, 107701, 2409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿で接客をすると\n売り上げが倍になる\n…本当ですか、これ", 0, 8, 0, 3, 1, 1, 107701, 2410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ♪\n南の島まで\n乗せてください！", 0, 10, 0, 3, 1, 1, 107701, 2412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか、\n人魚姫に\nなった気分です♪", 0, 11, 0, 3, 1, 1, 107701, 2413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなで過ごす\n休日っていいわよね…\nずっと続かないかな", 0, 1, 0, 1, 1, 1, 107801, 2414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に浮輪でぷかぷか\n浮かぶのって\n癖になりそう", 0, 2, 0, 1, 1, 1, 107801, 2415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビーチにいると\n日焼けが心配だわ", 0, 3, 0, 1, 1, 1, 107801, 2416);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿って楽よね。\n室内だとちょっと\n落ち着かないけど…", 0, 4, 0, 1, 1, 1, 107801, 2417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、泳ぎの練習なんて\nしないからね！", 0, 5, 0, 1, 1, 1, 107801, 2418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽しすぎて立場を\n忘れそう…あんたの\nせいなんだから！", 0, 101, 0, 1, 4, 1, 107801, 2419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなで遊んで\n美味しいもの食べて\nほんっとに楽しいっ♪", 0, 102, 0, 1, 8, 1, 107801, 2420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マジであっついわね…\nよっし！　海に入って\n涼みましょ！", 0, 1, 0, 2, 1, 1, 107801, 2421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シャワー浴びたばかり\nなのに…また、遊び\nたくなってきたわ！", 0, 2, 0, 2, 1, 1, 107801, 2422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遊び足りないって？\nしょうがないわね…\n付き合ってあげるわ♪", 0, 3, 0, 2, 1, 1, 107801, 2423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一応伝えておくけど\n猫って水が苦手なの！\nわかった！？", 0, 4, 0, 2, 1, 1, 107801, 2424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしと話したいの？\nふふ。\nまぁ、いいわよ。\nほら隣に座りなさい", 0, 101, 0, 2, 4, 1, 107801, 2425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなに楽しいの\n初めてかも…\nずっと続けばいいのに", 0, 102, 0, 2, 8, 1, 107801, 2426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("は、早起きしたのは、\n楽しみで眠れなかった\nからじゃないわよ！", 0, 1, 1, 2, 1, 1, 107801, 2427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食後のストレッチ\n終わり！　さあ、\nビーチが待ってるわ！", 0, 2, 2, 2, 1, 1, 107801, 2428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海に散歩に\n行こうかな～\nあんたも来なさいよ☆", 0, 3, 3, 2, 1, 1, 107801, 2429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海ではしゃぎすぎて\n疲れたわ…ちょっと\n休もうかしら？", 0, 2, 0, 3, 1, 1, 107801, 2431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな魔物がいたら\n操るのも楽しいかも", 0, 3, 0, 3, 1, 1, 107801, 2432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃう～♪\nまるで南国にいる\n気分ね♪", 0, 4, 0, 3, 1, 1, 107801, 2433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかぁい♪\n身体が冷えてきたから\n丁度いいわ！", 0, 5, 0, 3, 1, 1, 107801, 2434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("運動後のご飯って\nなんでこんなに\n美味しいんだろ♪", 0, 7, 0, 3, 1, 1, 107801, 2436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなカナヅチでも、\n絶対必ず泳げる方法、\n書いてないかしら？", 0, 8, 0, 3, 1, 1, 107801, 2437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたもあたしが\n操ってあげる！\nなんてね～♪", 0, 10, 0, 3, 1, 1, 107801, 2439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リゾートリゾートっ\nのんびりしましょ♪", 0, 11, 0, 3, 1, 1, 107801, 2440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここなら思う存分\nデスクワークに\n励めるわね！", 0, 1, 0, 1, 1, 1, 108001, 2441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("武器のメンテナンスも\nしっかりしないと\n最高効率は望めないわ", 0, 2, 0, 1, 1, 1, 108001, 2442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("準備をしっかり整えて\nもっともっと\n稼がなくちゃね！", 0, 3, 0, 1, 1, 1, 108001, 2443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し休んだら\n次のバイトに\n行ってくるわね！", 0, 4, 0, 1, 1, 1, 108001, 2444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好でここに\nいるのって\n気恥ずかしいわね…", 0, 5, 0, 1, 1, 1, 108001, 2445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミが望むなら\n今日のバイト\n休んでもいいわよ？", 0, 101, 0, 1, 4, 1, 108001, 2446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミだけね…\n私のことをここまで\n理解してくれるのは", 0, 102, 0, 1, 8, 1, 108001, 2447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段と違う格好\nだからって\nそんなに見ないでよ…", 0, 1, 0, 2, 1, 1, 108001, 2448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミを立派な\nバイト戦士にするのが\n師匠としての役目よね", 0, 2, 0, 2, 1, 1, 108001, 2449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ次のバイトに\n行かないと…\nキミも一緒に来る？", 0, 3, 0, 2, 1, 1, 108001, 2450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("効率は大事だけど\nゆっくりするのも\n悪くないわね", 0, 4, 0, 2, 1, 1, 108001, 2451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒の時間が楽しくて\nバイトのことを\n忘れちゃいそうね", 0, 101, 0, 2, 4, 1, 108001, 2452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒なら\nどんなミッションも\n楽勝ね！", 0, 102, 0, 2, 8, 1, 108001, 2453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう、いい朝ね！\n今日もめいっぱい\n稼ぐわよ！", 0, 1, 1, 2, 1, 1, 108001, 2454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお昼だったのね…\n内職のバイトに\n集中しすぎちゃったわ", 0, 2, 2, 2, 1, 1, 108001, 2455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スケジュールは、と…\nこういう管理の徹底が\n効率を生み出すのよ♪", 0, 3, 3, 2, 1, 1, 108001, 2456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり働いて休む…\n最高効率にまた一歩\n近づいたわね", 0, 2, 0, 3, 1, 1, 108001, 2458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なごんじゃうわね…\nよぉし、次のバイトも\n頑張らないと！", 0, 3, 0, 3, 1, 1, 108001, 2459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね…\n働く意欲が\n湧いてくるわ", 0, 4, 0, 3, 1, 1, 108001, 2460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身体が冷えたから\n助かるわ…冷えは\n女の天敵だもの", 0, 5, 0, 3, 1, 1, 108001, 2461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海のバイトは\n体力勝負よ\nエネルギーはしっかり\n摂取しないとね！", 0, 7, 0, 3, 1, 1, 108001, 2463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("座学も大切ね\nもっと知識を\n身につけないと…", 0, 8, 0, 3, 1, 1, 108001, 2464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の楽園みたいね…\n今だけは効率を\n忘れちゃいそう…", 0, 10, 0, 3, 1, 1, 108001, 2466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着くわ…\n海とひとつになった\n気分ね！", 0, 11, 0, 3, 1, 1, 108001, 2467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと休憩にゃ～\n潮風は体に\n良くないにゃ～", 0, 1, 0, 1, 1, 1, 107901, 2468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫グッズで\n海の家を飾りたいにゃ", 0, 2, 0, 1, 1, 1, 107901, 2469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の幸は美味しいけど\n水はイヤだにゃ…", 0, 3, 0, 1, 1, 1, 107901, 2470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("開店にゃ！\nこのたい焼きなら\nきっと大繁盛にゃ！", 0, 4, 0, 1, 1, 1, 107901, 2471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海と言えば水着にゃ\n似合ってるかにゃ？", 0, 5, 0, 1, 1, 1, 107901, 2472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミが頼むなら\n手伝ってあげても\nいいにゃ", 0, 101, 0, 1, 4, 1, 107901, 2473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの宝は\nここにあるにゃ～", 0, 102, 0, 1, 8, 1, 107901, 2474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃ？\nそんなに見つめても\n何も出ないにゃ", 0, 1, 0, 2, 1, 1, 107901, 2475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今からキミを\nあたしの相棒に\n任命するにゃ！", 0, 2, 0, 2, 1, 1, 107901, 2476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これから\n開店の準備にゃ\nキミも手伝って\nくれるのかにゃ？", 0, 3, 0, 2, 1, 1, 107901, 2477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の家で出す\n新しいメニューを\n考え中なのにゃ～", 0, 4, 0, 2, 1, 1, 107901, 2478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒なら\n売上げナンバーワンに\nなれるにゃ！", 0, 101, 0, 2, 4, 1, 107901, 2479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒にいると\n楽しくて、もっと\nいたくなるにゃ", 0, 102, 0, 2, 8, 1, 107901, 2480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようにゃ！\n今日も頑張って\nいくにゃー！", 0, 1, 1, 2, 1, 1, 107901, 2481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すいたにゃ～…\nお魚、ちょっとだけ、\nつまみ食いするにゃ", 0, 2, 2, 2, 1, 1, 107901, 2482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日の準備は万端にゃ\nいつでも\n出発できるにゃ", 0, 3, 3, 2, 1, 1, 107901, 2483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このふかふか具合\nまるで子猫の\n毛並みのようにゃ～", 0, 2, 0, 3, 1, 1, 107901, 2485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃにゃ～\nなんてかわいさにゃ～", 0, 3, 0, 3, 1, 1, 107901, 2486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い…\nもう少し香ばしいと\nいいかもしれないにゃ", 0, 4, 0, 3, 1, 1, 107901, 2487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃ～…\nあったかくて\nぬくぬくだにゃ～", 0, 5, 0, 3, 1, 1, 107901, 2488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("働くにはまず体力にゃ\nしっかり食べて\nスタミナアップ\nだにゃ!", 0, 7, 0, 3, 1, 1, 107901, 2490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nここにお宝が\n眠ってるんだにゃ", 0, 8, 0, 3, 1, 1, 107901, 2491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シードレイクにゃ！\n本物は怖かったけど、\nぬいぐるみなら\nかわいいにゃ～", 0, 10, 0, 3, 1, 1, 107901, 2493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貝なのにふかふかの\nクッションにゃ！\n屋台の前にも\n置いてみたいにゃあ", 0, 11, 0, 3, 1, 1, 107901, 2494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人の家って、道場とは\n違った香りがするね", 0, 1, 0, 1, 1, 1, 103701, 2495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと退屈だね…\nあの人をからかいに\n行こうかな♪", 0, 2, 0, 1, 1, 1, 103701, 2496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普通の女の子みたいに\n遊びたいって思う\nこともあるんだよね", 0, 3, 0, 1, 1, 1, 103701, 2497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("剣の手入れを怠らない\nようにしないと。\nいざという時、困るし", 0, 4, 0, 1, 1, 1, 103701, 2498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっと\n上手く立ち回って\n出世したいな", 0, 5, 0, 1, 1, 1, 103701, 2499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おかえりなさい！\nふふ、なんだか奥さん\nになった気分だよ♪", 0, 101, 0, 1, 4, 1, 103701, 2500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("恥ずかしくて、あなた\nを見られないよ…\n私らしくないなぁ…", 0, 102, 0, 1, 8, 1, 103701, 2501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、お話好きなんだ。\nどうせなら楽しい話を\nしたいな♪", 0, 1, 0, 2, 1, 1, 103701, 2502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女の子っぽい子と、\n男勝りな子、あなたは\nどっちが好き？", 0, 2, 0, 2, 1, 1, 103701, 2503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ見回りの\n時間かな。あなたも\n一緒に行く？", 0, 3, 0, 2, 1, 1, 103701, 2504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("構って欲しいのかな？\nそれじゃ一緒に\nランニングに行こうか", 0, 4, 0, 2, 1, 1, 103701, 2505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("二人で出かけるなら、\n手を繋がないとね。\nあはは、冗談冗談♪", 0, 101, 0, 2, 4, 1, 103701, 2506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、あなた♪\nおや、顔が真っ赤だ！\n…ふふ、私も、かな？", 0, 102, 0, 2, 8, 1, 103701, 2507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私は朝から鍛錬だよ。\n慣れてるけど大変だ。\nお互いに頑張ろうね", 0, 1, 1, 2, 1, 1, 103701, 2508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鍛錬でお腹ぺこぺこ。\nお昼ごはんが\n楽しみだね", 0, 2, 2, 2, 1, 1, 103701, 2509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日見回りと\n鍛錬を頑張ったよ。\nあなたもお疲れさま", 0, 3, 3, 2, 1, 1, 103701, 2510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いざという時のため\nにも、休憩は大事だね", 0, 2, 0, 3, 1, 1, 103701, 2512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうものには\n今まで\n縁がなかったけど。\nうん、可愛いね♪", 0, 3, 0, 3, 1, 1, 103701, 2513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精神統一に通じる\nものがあるね。\nふぅ、癒されるなぁ", 0, 4, 0, 3, 1, 1, 103701, 2514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいなぁ。\nたまにはのんびり\nしようか", 0, 5, 0, 3, 1, 1, 103701, 2515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鍛錬後はすごくお腹が\n空くんだよね。\nう～ん、おいしい♪", 0, 7, 0, 3, 1, 1, 103701, 2517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("剣術書だけで強くなる\nには飛びぬけた才能と\n努力が必要だよね", 0, 8, 0, 3, 1, 1, 103701, 2518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正義の刃で\n悪を挫く！\n…キマったッス♪", 0, 1, 0, 1, 1, 1, 100501, 2520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローの\n秘密特訓を\n始めるッスよ～！", 0, 2, 0, 1, 1, 1, 100501, 2521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正義の味方目指して\n今日も明日も\n全力ッスよ♪", 0, 3, 0, 1, 1, 1, 100501, 2522);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日一善！\nヒーローだったら\n当たり前ッス♪", 0, 4, 0, 1, 1, 1, 100501, 2523);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうッスか\nこのポーズ！\nイイ感じッスか？", 0, 5, 0, 1, 1, 1, 100501, 2524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("た、たまには\nよく頑張ったねって\n褒めてほしいッス…", 0, 101, 0, 1, 4, 1, 100501, 2525);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分を信じてくれる\nあんたと一緒なら\n何でもやれるッス！", 0, 102, 0, 1, 8, 1, 100501, 2526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おつかれッス♪\n冒険の準備は\nばっちりッスよ！", 0, 1, 0, 2, 1, 1, 100501, 2527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたんッスか？\n…はっ！　もしや敵が\n迫ってるんスかっ！？", 0, 2, 0, 2, 1, 1, 100501, 2528);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("べ、別に\n頭を撫でてほしいとか\n思ってないッスよ？", 0, 3, 0, 2, 1, 1, 100501, 2529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スーパーヒーロー\nトラタイガーは\n絶対無敵ッス！", 0, 4, 0, 2, 1, 1, 100501, 2530);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと自分で\n正義の心を燃やして\n悪を一網打尽ッス！", 0, 101, 0, 2, 4, 1, 100501, 2531);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと一緒だと\n幸せな気持ちに\nなるんッス…♪", 0, 102, 0, 2, 8, 1, 100501, 2532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、早いッスね～♪\n今日も一日一善\nよろしくッス！", 0, 1, 1, 2, 1, 1, 100501, 2533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一休みしながら\nヒーローについて\n語り合うッスよ～！", 0, 2, 2, 2, 1, 1, 100501, 2534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜のパトロールで\n一緒に平和を\n守るッス！", 0, 3, 3, 2, 1, 1, 100501, 2535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅぅ…\n落ち着くッスね\n戦士の休息ッス♪", 0, 2, 0, 3, 1, 1, 100501, 2537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くぅぅ、可愛いッス…\nヒーローが守るべき\n愛らしさッスね！", 0, 3, 0, 3, 1, 1, 100501, 2538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんスかこの香り？\nすぅぅ…ふぅぅ…\n力がみなぎるッス！", 0, 4, 0, 3, 1, 1, 100501, 2539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("優しい光ッスね…\nヒーローの優しさ\nそのものッス！", 0, 5, 0, 3, 1, 1, 100501, 2540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あむあむあむ…\nんぅう、元気が溢れて\n止まらないッス！", 0, 7, 0, 3, 1, 1, 100501, 2542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トラタイガーのお話は\n笑いあり涙ありで\n超おすすめッス！", 0, 8, 0, 3, 1, 1, 100501, 2543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハッピーハロウィン\nお父さん、お菓子は…\n食べられないね", 0, 1, 0, 1, 1, 1, 108101, 2545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トリックオアトリート\nお菓子をくれないと\n不吉な占いをします", 0, 2, 0, 1, 1, 1, 108101, 2546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、あなたの後ろで\n霊のみなさんが\n踊り始めました", 0, 3, 0, 1, 1, 1, 108101, 2547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("霊感がいつも以上に\n冴えているので\n占いの調子も良好です", 0, 4, 0, 1, 1, 1, 108101, 2548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("父はハロウィンが\n大好きだそうです\n大胆な格好をする子が\n多いので…", 0, 5, 0, 1, 1, 1, 108101, 2549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたは霊たちにも\n大人気ですよね\n私も見てほしいな…", 0, 101, 0, 1, 4, 1, 108101, 2550);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンの賑やかさ\n今は好きです…\nあなたといられるので", 0, 102, 0, 1, 8, 1, 108101, 2551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("霊のみなさんとの\nダンスパーティー…\n楽しみです", 0, 1, 0, 2, 1, 1, 108101, 2552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、元気だね\nえ？　ここは色んな\n女の子に会えて幸せ？", 0, 2, 0, 2, 1, 1, 108101, 2553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンのお菓子\n食べすぎちゃったな…\nでも、美味しかった…", 0, 3, 0, 2, 1, 1, 108101, 2554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの女難の相…\n悪化していますね\nお祓いが必要かも", 0, 4, 0, 2, 1, 1, 108101, 2555);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、霊のみなさんが\nあなたと踊りたいと…\nえっと、私も…", 0, 101, 0, 2, 4, 1, 108101, 2556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと手を繋ぐと\n胸が苦しくなります\nでも、繋ぎたいな…", 0, 102, 0, 2, 8, 1, 108101, 2557);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハッピーハロウィン…\n父が元気なので\n今日の運気は良好です", 0, 1, 1, 2, 1, 1, 108101, 2558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("父はお昼寝中です\n本当に寝ているかは\n私にも分かりませんが", 0, 2, 2, 2, 1, 1, 108101, 2559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、\nもう眠っちゃったの？\n…眠れるんだったっけ", 0, 3, 3, 2, 1, 1, 108101, 2560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着きますね…\n霊のみなさんも\n喜んでいます", 0, 2, 0, 3, 1, 1, 108101, 2562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つん、つん。ふふっ♪\n癒やされます…", 0, 3, 0, 3, 1, 1, 108101, 2563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精神が研ぎ澄まされる\n香りですね…\n占いが捗ります", 0, 4, 0, 3, 1, 1, 108101, 2564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいね\nお父さん…\nえ？　分からない？", 0, 5, 0, 3, 1, 1, 108101, 2565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("霊のみなさんは\n食べられないので…\n私がいただきます", 0, 7, 0, 3, 1, 1, 108101, 2567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さんを元に戻す\n手掛かり…\n書かれていないかな？", 0, 8, 0, 3, 1, 1, 108101, 2568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、お菓子が沢山…", 0, 12, 0, 3, 1, 1, 108101, 2570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無料でプリンが\nもらえるなんて、\nハロウィンはすごいの", 0, 1, 0, 1, 1, 1, 108201, 2572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生きてるときも、\nミヤコはハロウィンが\n好きだった気がするの", 0, 2, 0, 1, 1, 1, 108201, 2573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなに仮装を\n見せつけて、\nプリンをもらうの～", 0, 3, 0, 1, 1, 1, 108201, 2574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この仮装で、\nみんなに恐怖を\n教えてやるの！", 0, 4, 0, 1, 1, 1, 108201, 2575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アオーン、アオーン！\nミヤコ、狼女に\nなりきってるの～", 0, 5, 0, 1, 1, 1, 108201, 2576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツに秘密で、\nパーティーの\n飾り付けをするの♪", 0, 101, 0, 1, 4, 1, 108201, 2577);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツが狼男の\n仮装をすれば、\nおそろいなの～", 0, 102, 0, 1, 8, 1, 108201, 2578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンをくれなきゃ、\nオマエをカボチャに\nしてやるの～", 0, 1, 0, 2, 1, 1, 108201, 2579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンは幽霊でも\n参加できるから\n楽しいの～！", 0, 2, 0, 2, 1, 1, 108201, 2580);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンがないなら\nカボチャプリンを\n食べればいいの！", 0, 3, 0, 2, 1, 1, 108201, 2581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンの可能性は\n無限大なの～", 0, 4, 0, 2, 1, 1, 108201, 2582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエの隣で\nプリンを食べると、\nいつもより美味しいの", 0, 101, 0, 2, 4, 1, 108201, 2583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエが死んでも、\nミヤコはずーっと\n一緒にいてやるの～", 0, 102, 0, 2, 8, 1, 108201, 2584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ごはんは\nカボチャプリンなの！\nハロウィンっぽいの～", 0, 1, 1, 2, 1, 1, 108201, 2585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランチは豪華に\nプリンアラモードなの", 0, 2, 2, 2, 1, 1, 108201, 2586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は幽霊たちと\nハロウィンするの！\nオマエも来るの！", 0, 3, 3, 2, 1, 1, 108201, 2587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊にも休息は\n必要なの！\nプリンもってこいなの", 0, 2, 0, 3, 1, 1, 108201, 2589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエもミヤコの\nパーティーに\n招待してあげるの～", 0, 3, 0, 3, 1, 1, 108201, 2590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("癒されるの～\nまるで天国なの～", 0, 4, 0, 3, 1, 1, 108201, 2591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでなら、\n焼きプリンが\n作れるの！", 0, 5, 0, 3, 1, 1, 108201, 2592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹が減っては\nハロウィンは\nできぬなの！", 0, 7, 0, 3, 1, 1, 108201, 2594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("丸ごとカボチャ\nプリン特集！？\n美味しそうなの～♪", 0, 8, 0, 3, 1, 1, 108201, 2595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子がたくさんで、\nミヤコはとっても\nハッピーなの♪", 0, 12, 0, 3, 1, 1, 108201, 2597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔女以外にも、\n色々な仮装を\nしてみたいわね", 0, 1, 0, 1, 1, 1, 108301, 2599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チョコやアメよりも、\nアタシに相応しい\nスイーツがあるはず…", 0, 2, 0, 1, 1, 1, 108301, 2600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子の食べ過ぎは、\nお母さんに\n怒られるかも…", 0, 3, 0, 1, 1, 1, 108301, 2601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好で学院に\n行ったら、\nみんな驚くかしら", 0, 4, 0, 1, 1, 1, 108301, 2602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人のレディは、\nどういうハロウィンを\n過ごすべきかしら…？", 0, 5, 0, 1, 1, 1, 108301, 2603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子、アイツの分も\nとっといてあげよ！\n大人の余裕ってやつね", 0, 101, 0, 1, 4, 1, 108301, 2604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツを魅了する\n魔法とかないかしら？", 0, 102, 0, 1, 8, 1, 108301, 2605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おしゃれスイーツを\nくれなきゃ\nイタズラするわよ！", 0, 1, 0, 2, 1, 1, 108301, 2606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシの大人センスで\nアンタに似合う仮装を\n選んであげるわ！", 0, 2, 0, 2, 1, 1, 108301, 2607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不気味よねぇ…\nジャックオーランタン\nこ、怖くないわよ？", 0, 3, 0, 2, 1, 1, 108301, 2608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンが楽しくて\n宿題やり忘れてたわ…\nて、手伝って～！", 0, 4, 0, 2, 1, 1, 108301, 2609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子をもらうのも\nアンタと一緒なら\n恥ずかしくないわ！", 0, 101, 0, 2, 4, 1, 108301, 2610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシのエスコートを\n任せられるのは、\nアンタだけなんだから", 0, 102, 0, 2, 8, 1, 108301, 2611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝食はオシャレに\nグリーンスムージー！\n…に、にがぁ", 0, 1, 1, 2, 1, 1, 108301, 2612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼下がりはカフェで\n優雅なティータイム\n…憧れるわ～", 0, 2, 2, 2, 1, 1, 108301, 2613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンナイトの\nはじまりよ！\n街に繰り出しましょ！", 0, 3, 3, 2, 1, 1, 108301, 2614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あう～、お菓子の\n食べすぎで\n動けな～い", 0, 2, 0, 3, 1, 1, 108301, 2616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタも仮装する？\nいまよりもーっと\nかわいくなるわよ！", 0, 3, 0, 3, 1, 1, 108301, 2617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人な香りに\n包まれてる～♪", 0, 4, 0, 3, 1, 1, 108301, 2618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカね～♪\n…ああー！\nチョコが溶けてる！", 0, 5, 0, 3, 1, 1, 108301, 2619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい～♪\n…じゃなくて！\nび、美味ですわ～", 0, 7, 0, 3, 1, 1, 108301, 2621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服かわい～♪\nって、なにこの値段！\nお小遣い何年分よ！？", 0, 8, 0, 3, 1, 1, 108301, 2622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、お菓子なんかで\n喜ぶほど、子供じゃ…", 0, 12, 0, 3, 1, 1, 108301, 2624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はどんな策で団長を\nからかってみようか…", 0, 1, 0, 1, 1, 1, 107101, 2626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("む？\n血の臭いがするな\n祭りの時間か☆", 0, 2, 0, 1, 1, 1, 107101, 2627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("平和に飼い殺される\n前に、混沌の愛を\n育みたいね", 0, 3, 0, 1, 1, 1, 107101, 2628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本気を出した団長と\nいつか手加減なしに\n殺り合いたいな", 0, 4, 0, 1, 1, 1, 107101, 2629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おばさん呼ばわりする\n新米騎士の小娘を\n懲らしめてやろうか", 0, 5, 0, 1, 1, 1, 107101, 2630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("胸を触られるまで\n誓約のことなど\nすっかり忘れていたな", 0, 101, 0, 1, 4, 1, 107101, 2631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさかこのワタシが\nプロポーズするとはな\n…笑えるじゃないか", 0, 102, 0, 1, 8, 1, 107101, 2632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("面白い暇つぶしを\n思いついたんだ\n戯れに付き合え☆", 0, 1, 0, 2, 1, 1, 107101, 2633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈で死にそうだ\n愉しい話題を\nワタシに提供してくれ", 0, 2, 0, 2, 1, 1, 107101, 2634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ、暇なのか？\n心躍ることでも探しに\n出かけようではないか", 0, 3, 0, 2, 1, 1, 107101, 2635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このワタシを愉快に\nさせてくれる事でも\nあったのか？", 0, 4, 0, 2, 1, 1, 107101, 2636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシに求婚した男の\n数だと？\nいちいち覚えてないな", 0, 101, 0, 2, 4, 1, 107101, 2637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最強無敵の女と\n結婚できるんだ\n誇りに思えよ☆", 0, 102, 0, 2, 8, 1, 107101, 2638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにか愉快なことが\n起こりそうな朝だ☆\nワクワクするね", 0, 1, 1, 2, 1, 1, 107101, 2639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーむ、腹がすいたな\n愉快なことで\nこの空腹を満たしたい", 0, 2, 2, 2, 1, 1, 107101, 2640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからは大人の\n時間だ。愉しみ方を\n知りたいのかい？", 0, 3, 3, 2, 1, 1, 107101, 2641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このワタシとした事が\n穏やかな気分に\nなってしまうとは…", 0, 2, 0, 3, 1, 1, 107101, 2643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い姿をしたものが\n惨たらしい\n醜態を晒すのを\n想像してしまう", 0, 3, 0, 3, 1, 1, 107101, 2644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪くはない香りだ\nだが、ワタシは血の\n臭いを嗅ぎたいぞ☆", 0, 4, 0, 3, 1, 1, 107101, 2645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬるい、ぬるすぎる！\n地獄の業火には\nほど遠い熱さだ！", 0, 5, 0, 3, 1, 1, 107101, 2646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシの腕前に\n勝るとも劣らない\nなかなかの味だ", 0, 7, 0, 3, 1, 1, 107101, 2648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("意中の男性を絶対に\n落とす方法…？\nく、下らんっ！", 0, 8, 0, 3, 1, 1, 107101, 2649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日はあの釣り場に\n行くとしようかな\nあの子も誘ってみるか", 0, 1, 0, 1, 1, 1, 105601, 2651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷはーっ！\n体を動かしたあとの\n一杯は格別だね", 0, 2, 0, 1, 1, 1, 105601, 2652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("天気が良いと\n昼寝か釣りかで\n迷っちまうな…", 0, 3, 0, 1, 1, 1, 105601, 2653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大物が釣れたときの\n快感は、他じゃ\n味わえないね", 0, 4, 0, 1, 1, 1, 105601, 2654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふあぁ～…\n昼寝でもするか", 0, 5, 0, 1, 1, 1, 105601, 2655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…\nあの子、見た目より\n根性あるんだね", 0, 101, 0, 1, 4, 1, 105601, 2656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子が強くなるには\nどんな魚を食べさせて\nあげればいいのやら…", 0, 102, 0, 1, 8, 1, 105601, 2657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("姉御って呼ぶんじゃ\nないよ。からかうと\nタダじゃおかないよ", 0, 1, 0, 2, 1, 1, 105601, 2658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("釣りのコツ？\n何事も経験が大事だ\n今から行くかい？", 0, 2, 0, 2, 1, 1, 105601, 2659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたのさ？\n助太刀が必要かい？\nアタシにまかせときな", 0, 3, 0, 2, 1, 1, 105601, 2660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困ってる人がいたら\nまた力を貸しておくれ\n頼りにしてるよ", 0, 4, 0, 2, 1, 1, 105601, 2661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにか困りごとかい？\nどうやら昼寝は\nまた今度だね", 0, 101, 0, 2, 4, 1, 105601, 2662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よしよし！\nお人好しのお前さんを\n労ってあげるよ", 0, 102, 0, 2, 8, 1, 105601, 2663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう、お前さん\n魚屋は早起きでなきゃ\nつとまらないよ？", 0, 1, 1, 2, 1, 1, 105601, 2664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯かい？　今朝\n仕入れた魚があるんだ\n食べてみるかい？", 0, 2, 2, 2, 1, 1, 105601, 2665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜釣りにぴったりの\n月が出てるよ\nいい釣りが出来そうだ", 0, 3, 3, 2, 1, 1, 105601, 2666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コイツに座って\nのんびり釣りが\nできりゃいいのにな", 0, 2, 0, 3, 1, 1, 105601, 2668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よしよし…♪\nおっと、かわいい物も\nつい抱きしめちまうな", 0, 3, 0, 3, 1, 1, 105601, 2669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで魚の臭いを\n消せれば、猫も\n寄らなくなるのかね", 0, 4, 0, 3, 1, 1, 105601, 2670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冬場の釣りも\nこれくらい暖かけりゃ\nいいんだけどね", 0, 5, 0, 3, 1, 1, 105601, 2671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹が減っては\n釣りもできぬ、ってな\nまずは腹ごしらえだ", 0, 7, 0, 3, 1, 1, 105601, 2673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へぇ…こんな魚が\nいたとは…いつか\n釣りたいもんだね", 0, 8, 0, 3, 1, 1, 105601, 2674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("流石に室内で\n魔法ぶっぱしたら\n怒られるよねぇ", 0, 1, 0, 1, 1, 1, 101301, 2676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("可愛い女の子が\nたくさんいる！\nここは楽園か！？", 0, 2, 0, 1, 1, 1, 101301, 2677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなに漫画とか\n勧めてみようかな！\n布教用のがあるし！", 0, 3, 0, 1, 1, 1, 101301, 2678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ、私一人の\n部屋じゃないから\n色々自重せねば！", 0, 4, 0, 1, 1, 1, 101301, 2679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「ぬるぽ」\n…くっ、\n誰も反応なしか！", 0, 5, 0, 1, 1, 1, 101301, 2680);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はどの漫画を\n貸そうかなー♪", 0, 101, 0, 1, 4, 1, 101301, 2681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の定期巡回で\nとっておきの店に\n連れてってあげよう！", 0, 102, 0, 1, 8, 1, 101301, 2682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君に似合いそうな\n衣装を買ったよ！\n君もいざ魔法少女に！", 0, 1, 0, 2, 1, 1, 101301, 2683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ！\n暇なら定期巡回に\nレッツラゴー！", 0, 2, 0, 2, 1, 1, 101301, 2684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦闘だけじゃなくて、\n日常にも役立つ\n魔法を習得したいね！", 0, 3, 0, 2, 1, 1, 101301, 2685);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新魔法思いついた！\n私って天才！？", 0, 4, 0, 2, 1, 1, 101301, 2686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("決め台詞は超大事！\n君の決め台詞も\n私が考えてあげよう！", 0, 101, 0, 2, 4, 1, 101301, 2687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私ってもしやリア充？\n…そんなバカな！\n非リア代表のはずが！", 0, 102, 0, 2, 8, 1, 101301, 2688);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよー…\n徹夜で本読んでたから\nまだ眠い～", 0, 1, 1, 2, 1, 1, 101301, 2689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯食べて、\n午後の定期巡回も\n頑張りましょー！", 0, 2, 2, 2, 1, 1, 101301, 2690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜からが、\nオタ活本番でしょ！", 0, 3, 3, 2, 1, 1, 101301, 2691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふいー！\nくつろいで本を読む！\n最高だねー！", 0, 2, 0, 3, 1, 1, 101301, 2693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君、可愛いね～♪\n魔法少女の\n使い魔みたい！", 0, 3, 0, 3, 1, 1, 101301, 2694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い匂いに\n釣られてしまった…\nまさか、孔明の罠！？", 0, 4, 0, 3, 1, 1, 101301, 2695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かいけど、\nここで本を読むのは\nちょっち危ないかな", 0, 5, 0, 3, 1, 1, 101301, 2696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウマ―！\nこれの詳細きぼんぬ！", 0, 7, 0, 3, 1, 1, 101301, 2698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、古代語の本！？\n現代語でおk…", 0, 8, 0, 3, 1, 1, 101301, 2699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふふっ♪\n次はどんな悪戯を\nしてやろうかしら♪", 0, 1, 0, 1, 1, 1, 190901, 2701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幻影湖の霧を吸った\n人間たちの\nリアクションって、\nサイコーよねぇ～♪", 0, 2, 0, 1, 1, 1, 190901, 2702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("室内だけとはいえ…\n自由に動けるって、\nやっぱりいいわ～♪", 0, 3, 0, 1, 1, 1, 190901, 2703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("改めて見ると良い\n部屋ね…悪戯とか\nしやすそうだしぃ♪", 0, 4, 0, 1, 1, 1, 190901, 2704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私を封じていた部屋\nなのに…急に居心地が\n良くなったわね♪", 0, 5, 0, 1, 1, 1, 190901, 2705);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたの頭、座り心地\n良いわね…私専用の\n椅子にしてあげる♪", 0, 1, 0, 2, 1, 1, 190901, 2706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外は大変みたいねぇ…\nまあ、私は好き勝手に\nやらせてもらうわ♪", 0, 2, 0, 2, 1, 1, 190901, 2707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("顔に落書された？\n誰か知らないけど、\n悪いことする奴も\nいるものねぇ～♪", 0, 3, 0, 2, 1, 1, 190901, 2708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フィオのやつ…\nどこをウロチョロ\nしてるのかしら？", 0, 4, 0, 2, 1, 1, 190901, 2709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人間の朝は大変ねぇ…\n私はその様を見ながら\nゆっくりするわね♪", 0, 1, 1, 2, 1, 1, 190901, 2710);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～私も、お日様を\n浴びながら、お外を\nお散歩したーい！", 0, 2, 2, 2, 1, 1, 190901, 2711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この暗さ…閉じ込め\nられていた時を\n思い出すわね…", 0, 3, 3, 2, 1, 1, 190901, 2712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪戯しすぎて\n疲れたから、ちょっと\n休憩しよっと♪", 0, 2, 0, 3, 1, 1, 190901, 2714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガイド妖精たる私が、\nこんな造形物に\n惹かれる…わけが……\nかわいい♪", 0, 3, 0, 3, 1, 1, 190901, 2715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香りを囮にして、\n周りに悪戯を仕込む…\n完璧ね♪", 0, 4, 0, 3, 1, 1, 190901, 2716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不思議ねぇ…私は\n温度とか関係ないのに\n離れられないわ", 0, 5, 0, 3, 1, 1, 190901, 2717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事の必要がない体…\nつまり、食べたければ\n食べていいのよね～♪", 0, 7, 0, 3, 1, 1, 190901, 2719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へぇ…最近はこんな\n悪戯もあるのねぇ…\nあいつで試さないと♪", 0, 8, 0, 3, 1, 1, 190901, 2720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\n歌で幸せを\n届けます…！", 0, 1, 0, 1, 1, 1, 108401, 2722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと出会えたのは\n偶然ではなくて…\nクリスマスの奇跡だと\n思うんです", 0, 2, 0, 1, 1, 1, 108401, 2723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスは華やかで\nつい子供のように\nはしゃいでしまいます", 0, 3, 0, 1, 1, 1, 108401, 2724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("曲が書けるのは\nあなたが側に\nいてくれるからです…", 0, 4, 0, 1, 1, 1, 108401, 2725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("感動を与えられる歌…\nあなたと一緒になら\n生み出せるはず…", 0, 5, 0, 1, 1, 1, 108401, 2726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの幸せを\nあなたと\n感じ合えたらな…", 0, 101, 0, 1, 4, 1, 108401, 2727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの幸せを願った\nクリスマスソング…\nいつか披露しますね", 0, 102, 0, 1, 8, 1, 108401, 2728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなさんの笑顔を\n守りたいから…\n私は歌い続けます", 0, 1, 0, 2, 1, 1, 108401, 2729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌を届ける\nサンタさんに\nなりたいな…", 0, 2, 0, 2, 1, 1, 108401, 2730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お暇でしたら\nクリスマスのお祝いを\nしませんか？", 0, 3, 0, 2, 1, 1, 108401, 2731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ステージに立つ前に\n喉を整えないと…\n発声練習は念入りに…", 0, 4, 0, 2, 1, 1, 108401, 2732);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まわりはかわいい子\nばっかりだけど…\nこの服なら\nアピールになるかな？", 0, 101, 0, 2, 4, 1, 108401, 2733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌でならいくらでも\nあの人への気持ちを\n込められるのに…", 0, 102, 0, 2, 8, 1, 108401, 2734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\n幸せな歌で世界が\n包まれますように…", 0, 1, 1, 2, 1, 1, 108401, 2735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お茶を飲みながら\n好きな音楽を\n語り合いませんか？", 0, 2, 2, 2, 1, 1, 108401, 2736);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、寝かしつけの\n子守唄を\nお望みですか？", 0, 3, 3, 2, 1, 1, 108401, 2737);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかですね\n心地良すぎて\n眠ってしまいそう…", 0, 2, 0, 3, 1, 1, 108401, 2739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵…\n優しい歌みたいに\n気持ちが落ち着く…", 0, 3, 0, 3, 1, 1, 108401, 2740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("インスピレーションが\n溢れてくる…\nいい曲が書けそう…", 0, 4, 0, 3, 1, 1, 108401, 2741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この光みたいに\n灯火になるような\n歌を歌いたい…", 0, 5, 0, 3, 1, 1, 108401, 2742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("喉の健康のためにも\n食事はしっかり\nとるようにしています", 0, 7, 0, 3, 1, 1, 108401, 2744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("物語には\n曲作りのヒントが\n詰まっているんです", 0, 8, 0, 3, 1, 1, 108401, 2745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵が飛び出してくる\nなんて…精霊が宿って\nいるのでしょうか？", 0, 14, 0, 3, 1, 1, 108401, 2747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、可愛い…♪\nちょっとだけ触っても\nいいですよね…？", 0, 15, 0, 3, 1, 1, 108401, 2748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスでも、\n演劇の練習は\nしっかりやらないと！", 0, 1, 0, 1, 1, 1, 108501, 2749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あうぅ…\nクリスマスの準備が\n終わらないよぅ…", 0, 2, 0, 1, 1, 1, 108501, 2750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アヤネちゃんが\n摘み食いしないように\n見ておかないと…", 0, 3, 0, 1, 1, 1, 108501, 2751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンタさんみたいに、\n皆に笑顔で接する…\nうぅ…私には無理ぃ…", 0, 4, 0, 1, 1, 1, 108501, 2752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいお洋服～♪\nスズメお姉ちゃんに\nお礼をいわないと♪", 0, 5, 0, 1, 1, 1, 108501, 2753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんの為に、\nプレゼントを\n用意しないと♪", 0, 101, 0, 1, 4, 1, 108501, 2754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマス…\n恋人の日…ひゃわっ！\nわ、私ってば何を…！", 0, 102, 0, 1, 8, 1, 108501, 2755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリー\nクリスマスです、\nお兄ちゃん♪", 0, 1, 0, 2, 1, 1, 108501, 2756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そ、そんなに\n見られると…\n恥ずかしいよぉ…", 0, 2, 0, 2, 1, 1, 108501, 2757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃわぁっ！？\n急に触られると、\n驚くからやめてぇ…", 0, 3, 0, 2, 1, 1, 108501, 2758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ…クリスマスの\n準備を手伝って\nくれるんですか？", 0, 4, 0, 2, 1, 1, 108501, 2759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんと\n過ごすクリスマス、\n楽しみですぅ…♪", 0, 101, 0, 2, 4, 1, 108501, 2760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスはその…\n二人で…あうぅ…\nなんでもないですぅ…", 0, 102, 0, 2, 8, 1, 108501, 2761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…パーティーが\n楽しみで、あんまり\n眠れなかったよぅ…", 0, 1, 1, 2, 1, 1, 108501, 2762);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ケーキを食べられなく\nなっちゃうから、\nお昼は軽めにしないと", 0, 2, 2, 2, 1, 1, 108501, 2763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと眠いけど…\n今日は少しだけ\n夜更かししたいです♪", 0, 3, 3, 2, 1, 1, 108501, 2764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかぁ…\nクリスマスの準備中に\n眠くなっちゃいますぅ", 0, 2, 0, 3, 1, 1, 108501, 2766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子と一緒に\nおままごとしたいな♪", 0, 3, 0, 3, 1, 1, 108501, 2767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂い…♪\nみんなで\nアロマパーティー\nしたいなぁ…♪", 0, 4, 0, 3, 1, 1, 108501, 2768);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬっくぬく…♪\nもう、ここから\n離れたくないよぉ…♪", 0, 5, 0, 3, 1, 1, 108501, 2769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむ…♪\nクリスマスのお料理\nより美味しいかも～♪", 0, 7, 0, 3, 1, 1, 108501, 2771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごい…\nクリスマスの\n演劇って、\nこんなにあるんだ…", 0, 8, 0, 3, 1, 1, 108501, 2772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごい…まるで、\nクリスマスの演劇を\n観てるようですぅ…♪", 0, 14, 0, 3, 1, 1, 108501, 2774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっても可愛いです♪\nお芝居の相手役に\nしたいなぁ…♪", 0, 15, 0, 3, 1, 1, 108501, 2775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘ぁいケーキも、\nデッカイ七面鳥も、\nぜーんぶ私のだー♪", 0, 1, 0, 1, 1, 1, 108601, 2776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日が\nクリスマスだったら\nいいのにな～♪", 0, 2, 0, 1, 1, 1, 108601, 2777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントはあるし、\n料理は美味しいし、\nクリスマス最高ー♪", 0, 3, 0, 1, 1, 1, 108601, 2778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでぷうきちの\nクリスマス一発芸♪\n『無茶ぶりするな！』", 0, 4, 0, 1, 1, 1, 108601, 2779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちがいつもより\n重いかも…太ったの？\n『衣装の重さだよ！』", 0, 5, 0, 1, 1, 1, 108601, 2780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんが\n一緒にいてくれると\nクリスマス楽しいね♪", 0, 101, 0, 1, 4, 1, 108601, 2781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんに抱きつく\nと、なんだかドキドキ\nする…なんでかな？", 0, 102, 0, 1, 8, 1, 108601, 2782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス♪\nプレゼントは、\nいつでも受付中だよ♪", 0, 1, 0, 2, 1, 1, 108601, 2783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このクマさん耳\n可愛いでしょ♪\nぷうきちと\nお揃いなんだー♪", 0, 2, 0, 2, 1, 1, 108601, 2784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん…私、\n甘ぁいケーキが\n食べたいなぁ…♪", 0, 3, 0, 2, 1, 1, 108601, 2785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスぷうきちは\nぬくぬく感が凄いよ！\nお兄ちゃんもさわる？", 0, 4, 0, 2, 1, 1, 108601, 2786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…お兄ちゃんの\n手は、大きくて、\n暖かくて大好き～♪", 0, 101, 0, 2, 4, 1, 108601, 2787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年のクリスマスも、\nこうやって\nお兄ちゃんに\n甘えていたいな～♪", 0, 102, 0, 2, 8, 1, 108601, 2788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれぇ…\n私のケーキはぁ…？\n『ちゃんと起きろ』", 0, 1, 1, 2, 1, 1, 108601, 2789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はデッカイ\n七面鳥が食べたーい♪\n『夜まで我慢しろ』", 0, 2, 2, 2, 1, 1, 108601, 2790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『もう寝る時間だぞ』\nサンタさんが来る\nまで起きてるぅ…", 0, 3, 3, 2, 1, 1, 108601, 2791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このふかふか具合…\nぷうきち！\n負けてられないよ！", 0, 2, 0, 3, 1, 1, 108601, 2793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子、\nすっごくかわいい～♪\n『ライバル登場か！』", 0, 3, 0, 3, 1, 1, 108601, 2794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い匂い…あっ！\nぷうきちにこの\n匂いを移せば…！\n『匂い袋にするな』", 0, 4, 0, 3, 1, 1, 108601, 2795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い♪\nえへへ、ぷうきちも\nあっためてあげる♪", 0, 5, 0, 3, 1, 1, 108601, 2796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきち！　これ、\nとってもおいしいよ♪\n『食べすぎるなよ』", 0, 7, 0, 3, 1, 1, 108601, 2798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、大人の私なら、\nこれぐらい…読め…\n『無理するな…』", 0, 8, 0, 3, 1, 1, 108601, 2799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵が飛び出す…\nぷうきちに絵本を\n入れれば、イタズラに\n使えるかも…♪", 0, 14, 0, 3, 1, 1, 108601, 2801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、可愛いけど…\nぷうきちサンタの方が\n可愛いんだからぁ…！", 0, 15, 0, 3, 1, 1, 108601, 2802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物も慣れると\n動きやすいものさ", 0, 1, 0, 1, 1, 1, 108901, 2803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鼻緒が緩んでしまった\n下駄で修業は\n無理があったかな…", 0, 2, 0, 1, 1, 1, 108901, 2804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小腹が空いた…\nユイが作った餅、\nまだ食べられるかな？", 0, 3, 0, 1, 1, 1, 108901, 2805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("服装も変わったし\nいつもと違う戦い方を\n想定しないと…", 0, 4, 0, 1, 1, 1, 108901, 2806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ヒヨリは動きすぎて\n着崩れしてないか\n心配だ", 0, 5, 0, 1, 1, 1, 108901, 2807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからもずっと\n仲間と、彼と\n一緒に…", 0, 101, 0, 1, 4, 1, 108901, 2808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("願いを叶えるために\nもっと自分を\n鍛えていかないと！", 0, 102, 0, 1, 8, 1, 108901, 2809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭の飾りがずれてた？\nそうか、直してくれて\nありがとう", 0, 1, 0, 2, 1, 1, 108901, 2810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物がそんなに\n珍しい？\nキミも着てみる？\n…冗談だよ", 0, 2, 0, 2, 1, 1, 108901, 2811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("肩掛けの触り心地が\n気に入った？\nならもっと触る？", 0, 3, 0, 2, 1, 1, 108901, 2812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、この刀？\n釣り仲間に見繕って\nもらったんだ", 0, 4, 0, 2, 1, 1, 108901, 2813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミといると\n気持ちが段々と\n安らいでいくよ", 0, 101, 0, 2, 4, 1, 108901, 2814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミは私の行く先を\n照らしてくれる\n光のような存在だよ", 0, 102, 0, 2, 8, 1, 108901, 2815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう\n朝の修行を始めるけど\nキミもどう？", 0, 1, 1, 2, 1, 1, 108901, 2816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間に軽く\n休憩をとるといい\n能率がよくなるよ", 0, 2, 2, 2, 1, 1, 108901, 2817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう夜か…\n明日もまた頑張ろう\nそれじゃ、おやすみ", 0, 3, 3, 2, 1, 1, 108901, 2818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…疲れていたのかな\nもう少しで眠る\nところだった…", 0, 2, 0, 3, 1, 1, 108901, 2820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、正月衣装を\n着せてやるのも\nよさそうだ", 0, 3, 0, 3, 1, 1, 108901, 2821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…いい香りだ\n慌ただしい日々から\n心が解放される", 0, 4, 0, 3, 1, 1, 108901, 2822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この心地よさ…\n寝てしまわないよう\n気をつけないと", 0, 5, 0, 3, 1, 1, 108901, 2823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいけど\n帯がきつくなる前に\n手を止めよう…", 0, 7, 0, 3, 1, 1, 108901, 2825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外を出歩くのも\nいいけど、中で\n読書もありだな", 0, 8, 0, 3, 1, 1, 108901, 2826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…騎士クンって\nおせち料理で\n何が好きなんだろう？", 0, 1, 0, 1, 1, 1, 108801, 2828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物でお掃除や\nお洗濯するの\n慣れてきた♪", 0, 2, 0, 1, 1, 1, 108801, 2829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年は\nどんな福袋を\n買おうかな…♪", 0, 3, 0, 1, 1, 1, 108801, 2830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お餅に使う調味料\nみんなで違うから\n色々用意しなきゃ", 0, 4, 0, 1, 1, 1, 108801, 2831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほっぺがお餅みたいに\nぷにぷに…\n食べ過ぎちゃった…", 0, 5, 0, 1, 1, 1, 108801, 2832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年も、再来年も\nみんなで一緒に\n新年を迎えたいな", 0, 101, 0, 1, 4, 1, 108801, 2833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お願いです…\nいつかこの気持ちが\n伝わりますように…", 0, 102, 0, 1, 8, 1, 108801, 2834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("髪飾りが落ちそう？\nじゃあ…騎士クン\nつけ直してくれる？", 0, 1, 0, 2, 1, 1, 108801, 2835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物が着たいの？\nじゃあ今度一緒に\n買いに…行く？", 0, 2, 0, 2, 1, 1, 108801, 2836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、騎士クン\nお雑煮のお餅\nいくつ入れたい？", 0, 3, 0, 2, 1, 1, 108801, 2837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外、寒かったよね？\nはいこれ。熱い甘粥\n飲むと温まるよ", 0, 4, 0, 2, 1, 1, 108801, 2838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年は騎士クンと…\nえっ？　騎士クン！？\nな、なんでもないよ！", 0, 101, 0, 2, 4, 1, 108801, 2839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの願い事\nわたしが\n叶えてあげたいな…", 0, 102, 0, 2, 8, 1, 108801, 2840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう\n太陽の光に当たると\n元気が出るよ", 0, 1, 1, 2, 1, 1, 108801, 2841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはん\n作らなきゃ…\n騎士クンも食べる？", 0, 2, 2, 2, 1, 1, 108801, 2842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日が終わるのは\nあっという間だよね\n一年も同じなのかな？", 0, 3, 3, 2, 1, 1, 108801, 2843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…\n帯も少し\nゆるめちゃおう…", 0, 2, 0, 3, 1, 1, 108801, 2845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月用に\n着物を縫って\nあげたいな", 0, 3, 0, 3, 1, 1, 108801, 2846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これでお肌が\n保湿出来たら\nいいのになぁ", 0, 4, 0, 3, 1, 1, 108801, 2847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～…\nぬくぬくしてて\n動きたくないよ～", 0, 5, 0, 3, 1, 1, 108801, 2848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…冬眠しないのに\n熊さんみたいに\n食べちゃいそう", 0, 7, 0, 3, 1, 1, 108801, 2850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年末年始は\n告白のチャンス…\nむ、無理無理！", 0, 8, 0, 3, 1, 1, 108801, 2851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな忙しそう…\n待っててね、\nすぐ助けるから！", 0, 1, 0, 1, 1, 1, 108701, 2853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユイちゃんと\nレイさん…よし！\nどっちも手伝おう！", 0, 2, 0, 1, 1, 1, 108701, 2854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、着崩れてる！\nわわっ、どうしよ！\n帯が結べないよー！", 0, 3, 0, 1, 1, 1, 108701, 2855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣楽しみー！\n出店はどこから\n行こうかな？", 0, 4, 0, 1, 1, 1, 108701, 2856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月だし\nみんなで楽しく\n遊んじゃおー！", 0, 5, 0, 1, 1, 1, 108701, 2857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…\n騎士くんはお正月\n何してるんだろ…", 0, 101, 0, 1, 4, 1, 108701, 2858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ううぅー…\n騎士くんを見てると\nドキってなっちゃう…", 0, 102, 0, 1, 8, 1, 108701, 2859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしから\nおいしそうな匂い？\nくんくん…ソースだ！", 0, 1, 0, 2, 1, 1, 108701, 2860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヘアピンが…\n拾ってくれたんだ！\nありがとう騎士くん！", 0, 2, 0, 2, 1, 1, 108701, 2861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("髪飾りがかわいい？\n耳の近く触りたい？\n…優しくね？　", 0, 3, 0, 2, 1, 1, 108701, 2862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グローブで食べるの\n大変そう？　特訓して\n今はお箸も使えるよ！", 0, 4, 0, 2, 1, 1, 108701, 2863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えっ、ほっぺが赤い？\nそうかな…？\n気のせい気のせい！", 0, 101, 0, 2, 4, 1, 108701, 2864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くんといるとね…\nなんでもない！\nまだ内緒っ！", 0, 102, 0, 2, 8, 1, 108701, 2865);
