INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くんは\n私にとって\n最高の相棒だよ☆", 0, 102, 0, 2, 8, 1, 101401, 2965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝はいいひらめきが\n得られるんだ…\nさあ捜査を始めよう！", 0, 1, 1, 2, 1, 1, 101401, 2966);
