INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("脳を酷使した後は\nゆっくり休む…\nこれも仕事だよ？", 0, 2, 0, 3, 1, 1, 101401, 2970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この愛らしさ…\n要捜査対象だね！", 0, 3, 0, 3, 1, 1, 101401, 2971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思考が活性化される\n素敵な香りだね…", 0, 4, 0, 3, 1, 1, 101401, 2972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くぅ、心地よすぎる…\n今だけは捜査も\n一休みだね♪", 0, 5, 0, 3, 1, 1, 101401, 2973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べて\nいっぱい考える\n探偵の本分だね！", 0, 7, 0, 3, 1, 1, 101401, 2975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("探偵だからね\nミステリには\n一家言あるんだ", 0, 8, 0, 3, 1, 1, 101401, 2976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩、素敵だなぁ…\nもっと近づければ\nいいのに…", 0, 1, 0, 1, 1, 1, 105501, 2978);
