INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩になら\n観察されてもいいなぁ", 0, 102, 0, 1, 8, 1, 105501, 2984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイト先に新しい子が\n入って来たんです…\nわ、私、先輩です♪", 0, 1, 0, 2, 1, 1, 105501, 2985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩…？\nえっと、あの、その、\nあわわわわ…！", 0, 2, 0, 2, 1, 1, 105501, 2986);
