INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩のそばに\n居られて、私\n今、とっても\n幸せです…", 0, 102, 0, 2, 8, 1, 105501, 2990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩…！\nおひゃっ！\nおはようございます！", 0, 1, 1, 2, 1, 1, 105501, 2991);
