INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩と一緒に\nぬくぬくできたら\n最高なんだけどなぁ", 0, 5, 0, 3, 1, 1, 105501, 2998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいし～\nこれは\n先輩も好きな味かな", 0, 7, 0, 3, 1, 1, 105501, 3000);
