INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…\n落ち着くな…", 0, 2, 0, 1, 1, 1, 109401, 3054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マナリアはいつも\n賑やかなんだ…", 0, 3, 0, 1, 1, 1, 109401, 3055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな…\n今頃何してるかな？", 0, 4, 0, 1, 1, 1, 109401, 3056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか違う世界に\n来ちゃうなんて…\nびっくりだよね…", 0, 5, 0, 1, 1, 1, 109401, 3057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人と話すのは\n得意じゃないな…", 0, 101, 0, 1, 4, 1, 109401, 3058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここのみんなと一緒に\n学院に通えたら…\nちょっと面白いかも", 0, 102, 0, 1, 8, 1, 109401, 3059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり、私の翼や\n尻尾…気になる？", 0, 1, 0, 2, 1, 1, 109401, 3060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一番得意なのは、\nやっぱり炎魔法かな…\n加減は難しいけど…", 0, 2, 0, 2, 1, 1, 109401, 3061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の故郷は竜の国…\n険しい山脈を\n越えた先にあるんだ", 0, 3, 0, 2, 1, 1, 109401, 3062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アン…？\nあっ、ご、ごめんね！\n間違えちゃった…", 0, 4, 0, 2, 1, 1, 109401, 3063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふん…ふん…♪\n…わっ！\n今の、聞いてた…？\nは、恥ずかしい…", 0, 101, 0, 2, 4, 1, 109401, 3064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私に手伝えること、\nなにかある…？\nなんでも言ってね", 0, 102, 0, 2, 8, 1, 109401, 3065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の空気って\nすごく\n静かで透き通ってて…\nなんだか落ち着くよね", 0, 1, 1, 2, 1, 1, 109401, 3066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院食堂のランチも\n美味しいけど…\nここのご飯も好きかな", 0, 2, 2, 2, 1, 1, 109401, 3067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろベッドに\n行かないとだね\n…寝相、今夜こそ\n気を付けよう…！", 0, 3, 3, 2, 1, 1, 109401, 3068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("羽を伸ばしたく\nなっちゃうね…ふふ", 0, 2, 0, 3, 1, 1, 109401, 3070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ、私が持つには\nかわいすぎるかな…\nでも、素敵だね", 0, 3, 0, 3, 1, 1, 109401, 3071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\nこれ、\nアンも好きそう…", 0, 4, 0, 3, 1, 1, 109401, 3072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火を見ていると\n少し落ち着くんだ…\nへ、変かな？", 0, 5, 0, 3, 1, 1, 109401, 3073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ、美味しい…！\nこれ、どうやって\n作ったのかな…？", 0, 7, 0, 3, 1, 1, 109401, 3075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本…アンにも\n見せてあげたら\n喜ぶかな、ふふっ", 0, 8, 0, 3, 1, 1, 109401, 3076);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物はきれいですが\n歩きにくいです…\nいっそ脱いで…ぐふふ", 0, 1, 0, 1, 1, 1, 109501, 3078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、いけません\n着物がはだけて…はっ\nもしやドＳさんが…！", 0, 2, 0, 1, 1, 1, 109501, 3079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋は妄想する\nのにうってつけです…\nぐふふ…じゅるり", 0, 3, 0, 1, 1, 1, 109501, 3080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("扇をゆっくりと開く\nこの感触…なぜだか\n艶めかしさを感じます", 0, 4, 0, 1, 1, 1, 109501, 3081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「マッサージをすると\n言いながらドＳさんの\n手は次第に」…ぐふふ", 0, 5, 0, 1, 1, 1, 109501, 3082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ドＳさんの視線を\n思い出しながら踊りの\n練習です…イイ！", 0, 101, 0, 1, 4, 1, 109501, 3083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よいではないか\nよいではないか～\nいけませんご堪忍を～", 0, 102, 0, 1, 8, 1, 109501, 3084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ～れ～～～！\nドＳさんもお好きな人\nですねぇ…ぐふふ", 0, 1, 0, 2, 1, 1, 109501, 3085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこにいてもドＳさん\nの気配を感じ取れる\nようになりました…", 0, 2, 0, 2, 1, 1, 109501, 3086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな場所で\nなんというプレイを！\n…妄想でした", 0, 3, 0, 2, 1, 1, 109501, 3087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカを押し倒して\nそのまま…じゅるり\nああっ、着物が…！", 0, 4, 0, 2, 1, 1, 109501, 3088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんは優しいです\n優しいのにドＳとは\nさすが人格破綻者…！", 0, 101, 0, 2, 4, 1, 109501, 3089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんの考えている\nことが伝わってきます\nはい…クウカ脱ぎます", 0, 102, 0, 2, 8, 1, 109501, 3090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眩しい朝日がクウカの\n体を焦がします\n…それもイイ！", 0, 1, 1, 2, 1, 1, 109501, 3091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼のランチは\nクウカがいいだなんて\n大胆過ぎです…じゅる", 0, 2, 2, 2, 1, 1, 109501, 3092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…今夜のドＳさんは\n大胆です…ぐふふ…\nはっ、視線が…！？", 0, 3, 3, 2, 1, 1, 109501, 3093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この心地良さ、\n心が休まりすぎて\n体が疼いてきます…！", 0, 2, 0, 3, 1, 1, 109501, 3095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごく愛らしいです…\n妄想も出てこない\nくらい…じゅるり", 0, 3, 0, 3, 1, 1, 109501, 3096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香りに包まれて\nいると、いい気持ちに\nなって…いきますぅ…", 0, 4, 0, 3, 1, 1, 109501, 3097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「熱を帯びた体は\nどうしようもなく\n誰かを求め…」ぐふふ", 0, 5, 0, 3, 1, 1, 109501, 3098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹が膨らんで\nいきます…それは\nまるで…ぐふふ", 0, 7, 0, 3, 1, 1, 109501, 3100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカの探している\nジャンルはどこに\nありますかね？", 0, 8, 0, 3, 1, 1, 109501, 3101);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カチョーフーゲツは\nトーゴクの心を\n表した言葉デスね", 0, 1, 0, 1, 1, 1, 109601, 3103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オー！　新しい忍法を\n思いついたデス！\nさっそく試すデス！", 0, 2, 0, 1, 1, 1, 109601, 3104);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トーゴクの天気には\n槍が降る日も\nあるそうデス…", 0, 3, 0, 1, 1, 1, 109601, 3105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("我がショーグンは\n永遠にフメツデース\nいざ出陣デース！", 0, 4, 0, 1, 1, 1, 109601, 3106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("壁に耳あり\n障子に…ん？\nメアリーって誰デス？", 0, 5, 0, 1, 1, 1, 109601, 3107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグンがいれば\nワタシはどんな\n忍法も使いこなせマス", 0, 101, 0, 1, 4, 1, 109601, 3108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不届き者はどこで\nゴザルデス？　忍法で\n退治してくれヨウ！", 0, 102, 0, 1, 8, 1, 109601, 3109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグン！　新しい\n忍法を覚えたデス！\n見てほしいデース！", 0, 1, 0, 2, 1, 1, 109601, 3110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッツ手裏剣道デス！\n投げてソウロウで\nゴザルデース！", 0, 2, 0, 2, 1, 1, 109601, 3111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふりかかる火の粉は\nワタシが払うデス！\nバンバン！", 0, 3, 0, 2, 1, 1, 109601, 3112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっておきの忍法が\n吹き荒れるデス！\nよそ見はダメデスヨ？", 0, 4, 0, 2, 1, 1, 109601, 3113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグンは\n何階建てのお城を\n建てたいデスか？", 0, 101, 0, 2, 4, 1, 109601, 3114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テンシュカクから\n平和な城下町を\n眺めてみたいデス…", 0, 102, 0, 2, 8, 1, 109601, 3115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございマス！\n本日はオヒガラモヨク\n良い日になりそうデス", 0, 1, 1, 2, 1, 1, 109601, 3116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すいたデース…\nショーグンもご飯に\nしまショウ！", 0, 2, 2, 2, 1, 1, 109601, 3117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("闇討ちに遭わぬよう\n夜は気を付けて\n歩くデスよー？", 0, 3, 3, 2, 1, 1, 109601, 3118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("天下分け目の\n戦いに備えて…\nマッタリデース", 0, 2, 0, 3, 1, 1, 109601, 3120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("口寄せの術で\n召喚したいくらい\nかわいいデース", 0, 3, 0, 3, 1, 1, 109601, 3121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂いデ～ス\n香り玉の開発の\n参考になりそうデスね", 0, 4, 0, 3, 1, 1, 109601, 3122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシの懐よりも\nゾーリが暖まりマス…\nライバル出現デス…！", 0, 5, 0, 3, 1, 1, 109601, 3123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹が減っては\n戦はできぬデース！\n天下統一に向けて\n腹ごしらえデス！", 0, 7, 0, 3, 1, 1, 109601, 3125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ムム、暗号文デス！？\n解読には時間が\nかかりそうデース…", 0, 8, 0, 3, 1, 1, 109601, 3126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("掃除も終わりましたし\nそろそろ、食事の\n準備をしなくては", 0, 1, 0, 1, 1, 1, 109701, 3128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("異世界の演劇…\n許されるならば、\n観てみたいです", 0, 2, 0, 1, 1, 1, 109701, 3129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらの世界には、\nマヨネーズが普通に\n存在するのですね…", 0, 3, 0, 1, 1, 1, 109701, 3130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらの世界は食材も\n面白い物が多いですね\nなにかレシピを\n考えてみましょうか", 0, 4, 0, 1, 1, 1, 109701, 3131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みょんみょんみょん…\n魔法の練習は\nこれぐらいですね", 0, 5, 0, 1, 1, 1, 109701, 3132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("倒木の撤去で思わぬ\n収入となりました\nサレン様に\nお渡ししておかないと", 0, 101, 0, 1, 4, 1, 109701, 3133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理を美味しく\n召し上がって頂けると\nメイド冥利につきます", 0, 102, 0, 1, 8, 1, 109701, 3134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お出かけでしたら、\nレムも同行\nさせてくださいね", 0, 1, 0, 2, 1, 1, 109701, 3135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レムにできること\nでしたら、なんでも\nお申し付けください", 0, 2, 0, 2, 1, 1, 109701, 3136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じーー。いえ、\nその髪の長さが少し、\nとても少し、かなり\n少し気になったもので", 0, 3, 0, 2, 1, 1, 109701, 3137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鉄球ですか？\nあれは護身用ですので\n問題はありませんよ？", 0, 4, 0, 2, 1, 1, 109701, 3138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("計算の勉強は\n進んでおりますか？\nレムでよろしければ、\nいつでもお教えします", 0, 101, 0, 2, 4, 1, 109701, 3139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はもっと、大きな\n魔物料理に挑戦します\nワイバーンの姿焼き\nなんてどうでしょうか", 0, 102, 0, 2, 8, 1, 109701, 3140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n朝食の準備が\nできておりますので、\n食卓におこしください", 0, 1, 1, 2, 1, 1, 109701, 3141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食の時間ですね\n何か食べたいものは\nありますか？", 0, 2, 2, 2, 1, 1, 109701, 3142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝ないのか、ですか？\nメイドの就寝は、\n屋敷で最後と\n決まっておりますので", 0, 3, 3, 2, 1, 1, 109701, 3143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんわり…\nこのふんわりさは、\n鬼をも黙らせます…", 0, 2, 0, 3, 1, 1, 109701, 3145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…異世界でも\nかわいいものは\n共通なのですね", 0, 3, 0, 3, 1, 1, 109701, 3146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よい香りですね\n魔女教の悪臭とは\n大違いです", 0, 4, 0, 3, 1, 1, 109701, 3147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬくぬくです…はっ！\nこれはいけません！\n人を…いえ、\n鬼をだめにします！", 0, 5, 0, 3, 1, 1, 109701, 3148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむ…美味しい！\nこの味を再現できたら\n褒めてもらえる\nかもしれません…！", 0, 7, 0, 3, 1, 1, 109701, 3150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵がいっぱい…\n異世界の本は\nとても面白いですね", 0, 8, 0, 3, 1, 1, 109701, 3151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("異世界であろうと、\nラムのやるべきことは\n変わらないわ\nまずは休憩するわよ", 0, 1, 0, 1, 1, 1, 109801, 3153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マヨネーズがある\nということは、\nバルスの故郷が近い\nのかもしれないわね", 0, 2, 0, 1, 1, 1, 109801, 3154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界では、バルス\nの言う言葉が使われる\nときがあるのね\n忌々しいかぎりだわ", 0, 3, 0, 1, 1, 1, 109801, 3155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラムたち以外にも\nメイドが居るのね\nラムが…いえ、\n仕事を押しつけるわ", 0, 4, 0, 1, 1, 1, 109801, 3156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…千里眼で視るかぎり\n周囲に異変はないわね\n危険がないなら、\nあとはレムに任せるわ", 0, 5, 0, 1, 1, 1, 109801, 3157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ラムもまた、\n「お姉ちゃん」って\n呼ばれる日が\nくるのかしらね", 0, 101, 0, 1, 4, 1, 109801, 3158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハッ！　ラムが作る\n蒸かし芋は完璧ね\n…気が向いたら、また\n作ってやろうかしら", 0, 102, 0, 1, 8, 1, 109801, 3159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラムに構う暇が\nあるなら働きなさい\nそうすれば、\nラムが楽をできるわ", 0, 1, 0, 2, 1, 1, 109801, 3160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラムに何かを\n期待しても無駄よ\nラムに命令できるのは\nロズワール様だけだわ", 0, 2, 0, 2, 1, 1, 109801, 3161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇なら買い物に\n付き合いなさい\n荷物を\n持たせてあげるわ", 0, 3, 0, 2, 1, 1, 109801, 3162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラムになんの用？\nふざけた内容なら\nねじ切るわよ", 0, 4, 0, 2, 1, 1, 109801, 3163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえば、あなたは\n記憶喪失だったわね…\n思い出す努力をなさい\n…家族が悲しむわよ", 0, 101, 0, 2, 4, 1, 109801, 3164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("蒸かし芋が欲しい？\n随分と厚かましいわね\n…まだ残りがあるから\n好きに食べなさい", 0, 102, 0, 2, 8, 1, 109801, 3165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("だらしない顔ね\n顔を洗って\nしゃんとなさい", 0, 1, 1, 2, 1, 1, 109801, 3166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹が空く時間ね\nラムの昼食を\n用意させてあげるわ", 0, 2, 2, 2, 1, 1, 109801, 3167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メイドが寝るのは\n屋敷で最後…\nラムが寝るために、\nさっさと寝なさい", 0, 3, 3, 2, 1, 1, 109801, 3168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ここから動かない\nという、誓いを\n立てたくなるわね", 0, 2, 0, 3, 1, 1, 109801, 3170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…かわいいわね\nもちろん、\nラムほどではないけど", 0, 3, 0, 3, 1, 1, 109801, 3171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…香炉かしら？\nこちらの世界にも\n質のよい物があるのね", 0, 4, 0, 3, 1, 1, 109801, 3172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見つけてしまったの\nかもしれないわ…\nラムの楽園を！", 0, 5, 0, 3, 1, 1, 109801, 3173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…はむっ\nラムの蒸かし芋ほど\nではないけど、\nなかなかいけるわね", 0, 7, 0, 3, 1, 1, 109801, 3175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("異世界ならではの\n面白い内容もあるわね\nとても興味深いわ", 0, 8, 0, 3, 1, 1, 109801, 3176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえパック、\nにゃんにゃか\nにゃかにゃんしよっか", 0, 1, 0, 1, 1, 1, 109901, 3178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時間もあるし、\nこっちの世界の石で\n石積みしようかな", 0, 2, 0, 1, 1, 1, 109901, 3179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私もお姉さんだし、\nサレンさんを\n見習わないと…うん！\n私、すごーく頑張る！", 0, 3, 0, 1, 1, 1, 109901, 3180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界は、銀髪で\nハーフエルフでも受け\n入れてくれるのね…\nなんだか嬉しいな", 0, 4, 0, 1, 1, 1, 109901, 3181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のご飯…\nピーマルは\n入ってないわよね…？", 0, 5, 0, 1, 1, 1, 109901, 3182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また、みんなで\n一緒に買い物に\n行きたいな", 0, 101, 0, 1, 4, 1, 109901, 3183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パック以外から\n家族って呼ばれたの\n初めて…ふふっ♪\nちょっと嬉しいかも！", 0, 102, 0, 1, 8, 1, 109901, 3184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今からパックの\n毛繕いをするけど…\n一緒にする？", 0, 1, 0, 2, 1, 1, 109901, 3185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私も何かお手伝いを…\nあ、そうだ！\n料理とかどうかな！", 0, 2, 0, 2, 1, 1, 109901, 3186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、ここで\n歌の練習って、\nしてもいいかな？", 0, 3, 0, 2, 1, 1, 109901, 3187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あ、ごめんなさい！\n話しかけられるのって\nあまり慣れてなくて…", 0, 4, 0, 2, 1, 1, 109901, 3188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごーく頑張るから、\nこれからも勉強を\n手伝ってね", 0, 101, 0, 2, 4, 1, 109901, 3189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せーの、びくとりー！\nふふっ…また、一緒に\nラジーオタイソー\nしようね♪", 0, 102, 0, 2, 8, 1, 109901, 3190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんと起きてる？\nふふっ…よかった。\nあ、べ、別に心配した\nわけじゃないからね？", 0, 1, 1, 2, 1, 1, 109901, 3191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯が楽しみね♪\nあ、こっちの世界って\nまよねーずはあるの？", 0, 2, 2, 2, 1, 1, 109901, 3192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝る時間よ。\n夜更かししたら、\nめっ！　だからね！", 0, 3, 3, 2, 1, 1, 109901, 3193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("勉強も終わったし…\nちょっ、ちょっとだけ\n休んでもいいよね…？", 0, 2, 0, 3, 1, 1, 109901, 3195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…！\nパックのかわいさに\n匹敵するかも…！", 0, 3, 0, 3, 1, 1, 109901, 3196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い香り…\nロズワールの屋敷にも\nこういうのって\nあるのかな？", 0, 4, 0, 3, 1, 1, 109901, 3197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nずっとここに…はっ！\nダメダメ！　王選の\nために勉強しないと！", 0, 5, 0, 3, 1, 1, 109901, 3198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ…これ美味しい！\nこっちの世界は色んな\n食べ物があるのね。", 0, 7, 0, 3, 1, 1, 109901, 3200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知らないことが\nいっぱい書いてある…\n異世界の本って、\n面白いのね", 0, 8, 0, 3, 1, 1, 109901, 3201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海ってマジ最高！\nビーチの撮影も\n超楽しいしー♪", 0, 1, 0, 1, 1, 1, 110001, 3203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("20パーって何パ？\n今度ヒデサイに\n聞いてみよっ！", 0, 2, 0, 1, 1, 1, 110001, 3204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の思い出を\nヒデサイと一緒に\n作りたいな～", 0, 3, 0, 1, 1, 1, 110001, 3205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テンションあがる\n水着ゲットして\n超ラッキーだよ～♪", 0, 4, 0, 1, 1, 1, 110001, 3206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩が終わったら\n撮影にもどらないと！\n気合入れてこ♪", 0, 5, 0, 1, 1, 1, 110001, 3207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイとビーチで\nパーティーしたいな～\n超楽しそうだよね！", 0, 101, 0, 1, 4, 1, 110001, 3208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイといると\n楽しくてうれしくて…\nカレシってこんな感じ\nなのかなぁ？", 0, 102, 0, 1, 8, 1, 110001, 3209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見て見て～！\n夏らしいネイルに\nしてみたんだ～♪", 0, 1, 0, 2, 1, 1, 110001, 3210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイ～\nこの水着どうかな？\nイケてるっしょ♪", 0, 2, 0, 2, 1, 1, 110001, 3211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿の写真？\nもちいいよ！\nかわいく撮ってね！", 0, 3, 0, 2, 1, 1, 110001, 3212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちだって\n夏の海みたいに\nキラキラしちゃうよ！", 0, 4, 0, 2, 1, 1, 110001, 3213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイとうちの\nフィーリングって\nめっちゃエモいよね♪", 0, 101, 0, 2, 4, 1, 110001, 3214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねーねーヒデサイ！\n一緒に泳ぎにいこっ！\nほら、手繋いで♪", 0, 102, 0, 2, 8, 1, 110001, 3215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着オッケー！\nネイルもばっちり！\n朝から遊んじゃおー♪", 0, 1, 1, 2, 1, 1, 110001, 3216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼食べたら\n昼寝して\nリフレッシュしよー♪", 0, 2, 2, 2, 1, 1, 110001, 3217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着ってマジで\n最強かも…このまま\nお風呂にも入れるし♪", 0, 3, 3, 2, 1, 1, 110001, 3218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マジ気持ちいいー♪\nおに癒やされるん\nですけど～！", 0, 2, 0, 3, 1, 1, 110001, 3220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やばばばばー！\nかわいすぎだってば！\nマジらぶだよ～♪", 0, 3, 0, 3, 1, 1, 110001, 3221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、この香り超好き！\nモデル仲間に\n教えたげよ～♪", 0, 4, 0, 3, 1, 1, 110001, 3222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い♪\n夏の太陽みたい！", 0, 5, 0, 3, 1, 1, 110001, 3223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マジ美味しいねこれ♪\nビーチで\n流行っちゃうかも！", 0, 7, 0, 3, 1, 1, 110001, 3225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏のために\n最新ファッションを\n勉強ちう！", 0, 8, 0, 3, 1, 1, 110001, 3226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにコレもにカワ～♪\nなんて生き物？\nヒデサイ知ってる？", 0, 10, 0, 3, 1, 1, 110001, 3228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うわっ超フカフカ～\nなんかうち眠く\nなってきちゃった…", 0, 11, 0, 3, 1, 1, 110001, 3229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の家でのんびり\n過ごしましょう\n熱中症には注意してね", 0, 1, 0, 1, 1, 1, 110101, 3230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、どうやったら\n泳げるように\nなれるのかしら～", 0, 2, 0, 1, 1, 1, 110101, 3231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で日焼け止めを\n塗らないと、あとで\n大変なことになるわよ", 0, 3, 0, 1, 1, 1, 110101, 3232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("久しぶりに水着を\n着たんだけど\n変じゃなかったかな…", 0, 4, 0, 1, 1, 1, 110101, 3233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("波の音って落ち着くわ\n授業中に聞いたら\nみんな寝ちゃうかも？", 0, 5, 0, 1, 1, 1, 110101, 3234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海が楽しいって\n思えたのも\nあの子のおかげね", 0, 101, 0, 1, 4, 1, 110101, 3235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子と二人で海に\n来られてよかったわ\n一日があっという間ね", 0, 102, 0, 1, 8, 1, 110101, 3236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男の子と海だなんて\n少女漫画みたいで\n憧れてたの～", 0, 1, 0, 2, 1, 1, 110101, 3237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みの宿題は\nちゃんとやった？\n遊んでばかりではダメ", 0, 2, 0, 2, 1, 1, 110101, 3238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼の海と夜の海\nどっちが好き？　私は\n君といる海が一番よ", 0, 3, 0, 2, 1, 1, 110101, 3239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう、疲れたわ～\n冷たいジュースで\n元気回復ね！", 0, 4, 0, 2, 1, 1, 110101, 3240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で見た君の背中\nすごく大きく見えたわ\nやっぱり男の子なのね", 0, 101, 0, 2, 4, 1, 110101, 3241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君と一緒に見た\n夜の海…\n忘れられそうにないわ", 0, 102, 0, 2, 8, 1, 110101, 3242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("準備ができたら\n海に出かけようよ\n今日も楽しみましょう", 0, 1, 1, 2, 1, 1, 110101, 3243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、もうお昼？\n海の家でランチに\nしましょ♪", 0, 2, 2, 2, 1, 1, 110101, 3244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海岸についてきて\nくれる？　暗がりは\n一人じゃ怖くて…", 0, 3, 3, 2, 1, 1, 110101, 3245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐ練習をしたら\n疲れちゃったわ～\nちょっと一休み…", 0, 2, 0, 3, 1, 1, 110101, 3247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいわね～\n浮き輪に乗せて\n海に浮かべたいわ～", 0, 3, 0, 3, 1, 1, 110101, 3248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い…\nなんだか夏の海を\n思い出すわ～", 0, 4, 0, 3, 1, 1, 110101, 3249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海風で冷えない\nように、しっかりと\n身体を暖めましょうね", 0, 5, 0, 3, 1, 1, 110101, 3250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で遊ぶ前に\nしっかり食べて\n体力つけましょう", 0, 7, 0, 3, 1, 1, 110101, 3252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休み中でも\nしっかりお勉強\nしないと！", 0, 8, 0, 3, 1, 1, 110101, 3253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子に乗れば\n海の上でも\nすいすい進めるかしら", 0, 10, 0, 3, 1, 1, 110101, 3255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビーナスの誕生！\n…なんちゃって\nはしゃぎすぎかしら？", 0, 11, 0, 3, 1, 1, 110101, 3256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の海には商機が\nあるはず…\nのがす手はないわね♪", 0, 1, 0, 1, 1, 1, 110301, 3257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしが作った\n日焼け止め…\nこれは売れそうね！", 0, 2, 0, 1, 1, 1, 110301, 3258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちのために\n浮き輪を用意して\nおかないと…", 0, 3, 0, 1, 1, 1, 110301, 3259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海っていいわよね！\nみんなで羽を伸ばしに\n行きたいわ！", 0, 4, 0, 1, 1, 1, 110301, 3260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("波の音を聞いて\nのんびりするのも\n悪くないわね…", 0, 5, 0, 1, 1, 1, 110301, 3261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ただの砂遊びも\nあんたと一緒なら\n楽しいから不思議ね…", 0, 101, 0, 1, 4, 1, 110301, 3262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたがあたしの\nなんであれ、大切な\n存在ではあるのよね…", 0, 102, 0, 1, 8, 1, 110301, 3263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の海って\nすごい人よね…\n迷子にならないでよ？", 0, 1, 0, 2, 1, 1, 110301, 3264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼんやり海に浮かんで\n波に揺られるのも\n悪くないわよ？", 0, 2, 0, 2, 1, 1, 110301, 3265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビーチで子どもたちと\n一緒に砂のお城を\n作りたいわ♪", 0, 3, 0, 2, 1, 1, 110301, 3266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で食べる\n焼きそばパン…\nいいかもしれないわね", 0, 4, 0, 2, 1, 1, 110301, 3267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの水着\n似合ってる？\nそう、ありがとう♪", 0, 101, 0, 2, 4, 1, 110301, 3268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが居ると\nうれしい…って、\n子どもたちが\n言ってたわ！", 0, 102, 0, 2, 8, 1, 110301, 3269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の浜辺って\nいいわよね\n散歩しに行きたいわ", 0, 1, 1, 2, 1, 1, 110301, 3270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の家のご飯って\nなんであんなに\nおいしいのかしら♪", 0, 2, 2, 2, 1, 1, 110301, 3271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海って、\nロマンチックよね。\nずっと眺めてたいわ…", 0, 3, 3, 2, 1, 1, 110301, 3272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やわらかくて\n気持ちいい…\nこのまま寝ちゃいそう", 0, 2, 0, 3, 1, 1, 110301, 3274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に一緒に入れる\nぬいぐるみとか\nないかしら？", 0, 3, 0, 3, 1, 1, 110301, 3275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏らしい\nいい香りね…\nなんの香りかしら？", 0, 4, 0, 3, 1, 1, 110301, 3276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\n濡れた体を乾かすには\nちょうどいいわね♪", 0, 5, 0, 3, 1, 1, 110301, 3277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳いだ後の食事は\n普段の何倍も\nおいしく感じるわね！", 0, 7, 0, 3, 1, 1, 110301, 3279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行く前にいろいろ\n調べなきゃね。備え\nあれば憂いなしよ！", 0, 8, 0, 3, 1, 1, 110301, 3280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の守り神？\nずいぶんかわいらしい\n神様ね♪", 0, 10, 0, 3, 1, 1, 110301, 3282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このぐらい\n大きな貝があったら\n食費も浮くかしら？", 0, 11, 0, 3, 1, 1, 110301, 3283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("浜辺で食うものって\nなんであんなに\nうまいのかな～", 0, 1, 0, 1, 1, 1, 110401, 3284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いてて…\nちょっと日焼け\nしすぎたかな", 0, 2, 0, 1, 1, 1, 110401, 3285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("砂浜で走ると\nいいトレーニングに\nなるんだぜ", 0, 3, 0, 1, 1, 1, 110401, 3286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏ならではの\n料理…か\n何がいいかな…", 0, 4, 0, 1, 1, 1, 110401, 3287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりここは\n涼しくて快適だな", 0, 5, 0, 1, 1, 1, 110401, 3288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎの練習だったら\nいつでも付き合って\nやるからな！", 0, 101, 0, 1, 4, 1, 110401, 3289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で部屋の中に\nいるのって\n変な感じだな…", 0, 102, 0, 1, 8, 1, 110401, 3290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うおっ！\nきゅ、急に\n触るなって…\nびっくりした", 0, 1, 0, 2, 1, 1, 110401, 3291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、砂がついてた？\n払ってくれたのか\nありがとよ", 0, 2, 0, 2, 1, 1, 110401, 3292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテしてないか？\nここで休んでけよ", 0, 3, 0, 2, 1, 1, 110401, 3293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…そう見られると\n照れるっていうか…", 0, 4, 0, 2, 1, 1, 110401, 3294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カキ氷とか\n食いたくないか？\n氷、削ってやるよ", 0, 101, 0, 2, 4, 1, 110401, 3295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おまえと\n夏の思い出ができて\nよかったよ", 0, 102, 0, 2, 8, 1, 110401, 3296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう…\n朝一番で泳ぐの\nやっぱ気持ちいいな", 0, 1, 1, 2, 1, 1, 110401, 3297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一番あちぃ時間だ\n水分補給は\nこまめにな！", 0, 2, 2, 2, 1, 1, 110401, 3298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もお疲れ\n明日のパトロールも\nよろしくな", 0, 3, 3, 2, 1, 1, 110401, 3299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎ疲れたからな\n少し休憩だ…", 0, 2, 0, 3, 1, 1, 110401, 3301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…\nいや、なんでもねぇ！", 0, 3, 0, 3, 1, 1, 110401, 3302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り落ち着くな\nこういうのも\n悪くねーかも…", 0, 4, 0, 3, 1, 1, 110401, 3303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったけえ…！\n泳ぎ終わった後って\nけっこう体冷えてよ…", 0, 5, 0, 3, 1, 1, 110401, 3304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で食べると\nまた一味違うよな", 0, 7, 0, 3, 1, 1, 110401, 3306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏のサバイバル特集…\nちょっと読んでみるか", 0, 8, 0, 3, 1, 1, 110401, 3307);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へー！　こいつ、\nよくできてんな！\nいいなあ、実物も\n乗れたらいいのに", 0, 10, 0, 3, 1, 1, 110401, 3309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわ…！\nいや、じゃなくて\nあ、あたしがここに\n寝ていいのか…？", 0, 11, 0, 3, 1, 1, 110401, 3310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("故郷の花を飾っても\nいいかな～？\n部屋が楽しくなるよ～", 0, 1, 0, 1, 1, 1, 110501, 3311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で歩いてると\n泳ぎたくなるさ～\n我慢できないさ～！", 0, 2, 0, 1, 1, 1, 110501, 3312);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏が眩しいのは\nてぃーだがにこにこ\n笑ってるからさ～！", 0, 3, 0, 1, 1, 1, 110501, 3313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎ疲れたら\n涼しい木陰で\nお昼寝するさ～", 0, 4, 0, 1, 1, 1, 110501, 3314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クロールも\n犬かきも\n大得意さ～！", 0, 5, 0, 1, 1, 1, 110501, 3315);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか歌いたい\n気分さ～\nキミもどう～？", 0, 101, 0, 1, 4, 1, 110501, 3316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の近くに住んで\nキミと歌って踊って\nそれが理想さ～！", 0, 102, 0, 1, 8, 1, 110501, 3317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私とキミ\nどっちがたくさん\n泳げるか\n競争するさ～！", 0, 1, 0, 2, 1, 1, 110501, 3318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミも三線に興味が\nあるのかな～？\n私が教えるさ～！", 0, 2, 0, 2, 1, 1, 110501, 3319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("嫌なことがあっても\n私と歌って踊れば\nなんくるないさー！", 0, 3, 0, 2, 1, 1, 110501, 3320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには時間を忘れて\n私とのーんびり\n海を眺めるさ～", 0, 4, 0, 2, 1, 1, 110501, 3321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぶるぶるぶるっ！\n毛が濡れちゃっても\nへっちゃらさ～！", 0, 101, 0, 2, 4, 1, 110501, 3322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐ前は準備体操～！\n背中押してあげるから\nしっかりやるさ～！", 0, 102, 0, 2, 8, 1, 110501, 3323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の浜辺は\nちゅらさんよ～\n一緒に歩こうよー！", 0, 1, 1, 2, 1, 1, 110501, 3324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯は\n決まったかな～？\n私はタコライスさ～！", 0, 2, 2, 2, 1, 1, 110501, 3325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("星と波音の中で\n三線鳴らすのも\nオツなものさ～", 0, 3, 3, 2, 1, 1, 110501, 3326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどよかったさー\nゆっくり休んだら\nまた泳ぎに行くさ～！", 0, 2, 0, 3, 1, 1, 110501, 3328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("砂浜に飾って\nおきたいさ～\nきっとかわいいさ～！", 0, 3, 0, 3, 1, 1, 110501, 3329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…はあ\n癒されるさ…\n故郷の夏の匂いさ～", 0, 4, 0, 3, 1, 1, 110501, 3330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおー…！\n濡れた髪が\nみるみる乾いてくさ～", 0, 5, 0, 3, 1, 1, 110501, 3331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～！　これ、\n海で食べたら\nもっとおいしいさ～", 0, 7, 0, 3, 1, 1, 110501, 3333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の生物図鑑ね～\nこの前みかけた魚も\n載ってるかな～？", 0, 8, 0, 3, 1, 1, 110501, 3334);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ～！　みてみて！\n背中に乗れるさー！\nキミと一緒に\n乗りたいさ～！", 0, 10, 0, 3, 1, 1, 110501, 3336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかさ～\n海の底の\n人魚になった気分さ～", 0, 11, 0, 3, 1, 1, 110501, 3337);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人が\nわたしの騎士だったら\nいいのにな…", 0, 103, 0, 1, 12, 1, 105801, 3338);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたのおかげで\nわたしの心はいつも\nお腹いっぱいです♪", 0, 103, 0, 2, 12, 1, 105801, 3339);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("許されるのならば、\n今すぐにでも、\n主さまのおそばに\n行きたいです…", 0, 103, 0, 1, 12, 1, 105901, 3340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま…\nお慕いしております…\nいつまでも、おそばに\n居させてください…", 0, 103, 0, 2, 12, 1, 105901, 3341);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんか最近、\nあいつのことしか\n考えてない…\nあたし…どうしよう…", 0, 103, 0, 1, 12, 1, 106001, 3342);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そ、外に行くなら、\n連れていきなさいよね\nその…あたしが\n守ってあげるから…", 0, 103, 0, 2, 12, 1, 106001, 3343);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の中は涼しくて\n気持ちええどすなぁ\n天国やわぁ", 0, 1, 0, 1, 1, 1, 110601, 3344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クラゲはんって\nフリルいっぱいの\nドレスみたいやねぇ", 0, 2, 0, 1, 1, 1, 110601, 3345);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外でセミはんが\n元気に鳴いてはるねぇ\n今日もええ天気やわぁ", 0, 3, 0, 1, 1, 1, 110601, 3346);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こないに暑いと\n海に入って\n涼みたくなるわぁ", 0, 4, 0, 1, 1, 1, 110601, 3347);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか\nマホマホ王国にも\n海の家作りまひょ♪", 0, 5, 0, 1, 1, 1, 110601, 3348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちも\n付き合いますえ\n泳ぎの練習しまひょ♪", 0, 101, 0, 1, 4, 1, 110601, 3349);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの里帰り\n王子はんも一緒に\n来まへんか？", 0, 102, 0, 1, 8, 1, 110601, 3350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんは日焼けより\n色白美人の方が\n好きでっしゃろか？", 0, 1, 0, 2, 1, 1, 110601, 3351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちと一緒に\n浮き輪で海、\nプカプカしまへん？", 0, 2, 0, 2, 1, 1, 110601, 3352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日が落ちたら\n線香花火\nやりたいわぁ♪", 0, 3, 0, 2, 1, 1, 110601, 3353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("木陰でのんびり\nお昼寝…\n最高やね～", 0, 4, 0, 2, 1, 1, 110601, 3354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お祭ではぐれても\n王子はんなら見つけて\nくれはります？", 0, 101, 0, 2, 4, 1, 110601, 3355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽しい夏やわぁ\nずっとこんな日が\nつづくとええね", 0, 102, 0, 2, 8, 1, 110601, 3356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちにしては早起き？\n暑くて目が早う\n覚めてもうたんどす", 0, 1, 1, 2, 1, 1, 110601, 3357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は冷たい\nおそうめんとか\nどうでっしゃろ", 0, 2, 2, 2, 1, 1, 110601, 3358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は星がきれいやね\n二人で浜辺でも\n行きまへんか？", 0, 3, 3, 2, 1, 1, 110601, 3359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、遊び疲れた\n身体にちょうどええ\nほっこり具合やわぁ", 0, 2, 0, 3, 1, 1, 110601, 3361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かいらしい子は\nみーんな\nマホマホ王国の\n住人どすえ♪", 0, 3, 0, 3, 1, 1, 110601, 3362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\n南国にいる気分やねぇ\n癒されるわぁ～", 0, 4, 0, 3, 1, 1, 110601, 3363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで\n冷えた身体も\nポカポカやねぇ", 0, 5, 0, 3, 1, 1, 110601, 3364);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外はまだ暑いやろうし\nバテんよう\nしっかり食べんとね", 0, 7, 0, 3, 1, 1, 110601, 3366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の中にもお城が\nあるんやねぇ\n行ってみたいわぁ", 0, 8, 0, 3, 1, 1, 110601, 3367);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子、ふかふかやね\nこのままマホマホ王国\n乗せてってくれはる？", 0, 10, 0, 3, 1, 1, 110601, 3369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人魚姫になっても\n最後は王子はんと\nハッピーエンド\nどすえ～", 0, 11, 0, 3, 1, 1, 110601, 3370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真似したくなる\n人がここには\n大勢いますね", 0, 1, 0, 1, 1, 1, 107001, 3371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("偽物を一人\n紛れこませました\n…冗談です", 0, 2, 0, 1, 1, 1, 107001, 3372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("動物に変身して\nその辺りを\n散歩してきます", 0, 3, 0, 1, 1, 1, 107001, 3373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("失った記憶は\nどの程度回復するの\nでしょうね", 0, 4, 0, 1, 1, 1, 107001, 3374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人や物だけでなく\nいずれは世界すら\n真似てみせます", 0, 5, 0, 1, 1, 1, 107001, 3375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次は彼に\nどんなことを\n教えましょうか…", 0, 101, 0, 1, 4, 1, 107001, 3376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知識はともかく\n私の力はまだ\n必要なようですね", 0, 102, 0, 1, 8, 1, 107001, 3377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしました？\n…何でもない？\n…そうですか", 0, 1, 0, 2, 1, 1, 107001, 3378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈しています\n芸でもして\n楽しませなさい", 0, 2, 0, 2, 1, 1, 107001, 3379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("研究のためです\n少し話し相手に\nなりなさい", 0, 3, 0, 2, 1, 1, 107001, 3380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か真似して欲しい？\n私の能力を何だと\n思っているのですか", 0, 4, 0, 2, 1, 1, 107001, 3381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴方にはまだ色々と\n教えるべきことが\nありますね", 0, 101, 0, 2, 4, 1, 107001, 3382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("随分多くの女性と\n知り合いなのですね\n驚きました", 0, 102, 0, 2, 8, 1, 107001, 3383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…\nおはようございます\n…まだ朝ですよ", 0, 1, 1, 2, 1, 1, 107001, 3384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事にします\n…どうしました？\n早く持ってきなさい", 0, 2, 2, 2, 1, 1, 107001, 3385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早く寝なさい\n夜更かしすると\n背が伸びませんよ？", 0, 3, 3, 2, 1, 1, 107001, 3386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マサキより\n座り心地は\nいいですね", 0, 2, 0, 3, 1, 1, 107001, 3388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("意外に複雑な\n構造ですね", 0, 3, 0, 3, 1, 1, 107001, 3389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真似るなら\n香りまで\n再現しなくては", 0, 4, 0, 3, 1, 1, 107001, 3390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("発火現象の\n模倣…なかなか\n難しいものです", 0, 5, 0, 3, 1, 1, 107001, 3391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("偽物や分身を作るには\nエネルギーが\n必要不可欠なのです", 0, 7, 0, 3, 1, 1, 107001, 3393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇つぶしには\nちょうどよさそうです\n…", 0, 8, 0, 3, 1, 1, 107001, 3394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院かぁ…\n友達の作り方の\n授業はないかな？", 0, 1, 0, 1, 1, 1, 110701, 3396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院でぼっちに\nなったときのために、\n避難場所を\n探しておかないと…", 0, 2, 0, 1, 1, 1, 110701, 3397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼっちの私が学院…\nな、なんだか\n目まいがしてきました", 0, 3, 0, 1, 1, 1, 110701, 3398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クラスメイトに\n話しかける練習…\nむ、難しすぎます…！", 0, 4, 0, 1, 1, 1, 110701, 3399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("目指せ友達100人…\n無理かな…10人…\nや、やっぱり一人！", 0, 5, 0, 1, 1, 1, 110701, 3400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと学院生活が\n送れるなんて、\nとっても\nうれしいです！", 0, 101, 0, 1, 4, 1, 110701, 3401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…\n学院でも、\nあなたと一緒に\n居られてうれしいな♪", 0, 102, 0, 1, 8, 1, 110701, 3402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("が、学院ってあんなに\n人が居るんですね…\n友達作りのイメトレを\nやり直さないと！", 0, 1, 0, 2, 1, 1, 110701, 3403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私にとって\n部活動とはＢＢ団！\n今日もたくさん\n活動しましょうね！", 0, 2, 0, 2, 1, 1, 110701, 3404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休み時間は寝たふり…\nご飯はおトイレ…\nぼっち対策は完璧です", 0, 3, 0, 2, 1, 1, 110701, 3405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院で友達を作る\n勉強は完璧ですよ！\n購買部でパンを買って\n渡すんですよね！", 0, 4, 0, 2, 1, 1, 110701, 3406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院でも、\nＢＢ団の活動を\nしていきましょうね♪", 0, 101, 0, 2, 4, 1, 110701, 3407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼっちに学院生活は\n厳しいですね…でも、\nあなたと一緒なら\n乗りこえられそうです", 0, 102, 0, 2, 8, 1, 110701, 3408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\nあの…一緒に学院に\n行ってくれませんか？", 0, 1, 1, 2, 1, 1, 110701, 3409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですね！\n言ってくれれば、\nパンでもお握りでも\n買ってきますよ！", 0, 2, 2, 2, 1, 1, 110701, 3410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もぼっち…\nいつか友達と一緒に、\nパジャマパーティー\nしたいなぁ…", 0, 3, 3, 2, 1, 1, 110701, 3411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森とは違う\n心地良さが…このまま\n眠っちゃいそうです…", 0, 2, 0, 3, 1, 1, 110701, 3413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい…この子を、\n話す練習の相手役に\nしてみようかな？", 0, 3, 0, 3, 1, 1, 110701, 3414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\nいつ友達ができても\nいいように、私の\n部屋にも置こうかな", 0, 4, 0, 3, 1, 1, 110701, 3415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、これは…\nぼっちで\n日陰者の私には\n暖かすぎます！", 0, 5, 0, 3, 1, 1, 110701, 3416);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい…！\nお弁当にして、学院に\n持っていけないかな？", 0, 7, 0, 3, 1, 1, 110701, 3418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院の授業に\nついていくためにも、\n勉強しておこうかな…", 0, 8, 0, 3, 1, 1, 110701, 3419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんた、何してんの。\nいいけど、なんでも", 0, 1, 0, 1, 1, 1, 110801, 3421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("邪魔。どいて。\nいや怒ってないし。\nコレがフツーだから", 0, 2, 0, 1, 1, 1, 110801, 3422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいけど、\n散らかしめの部屋だと\n片付けたくなるよね…", 0, 3, 0, 1, 1, 1, 110801, 3423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇なときは明日の\nコーデ考えてるよ。\n考えるのはタダだし", 0, 4, 0, 1, 1, 1, 110801, 3424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昔よくシオリン\n構いすぎてハツネに\n文句言われたなァ…", 0, 5, 0, 1, 1, 1, 110801, 3425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんかさ。あんたって\n謎に女子トモ多いよね\n…いいけど、べつに", 0, 101, 0, 1, 4, 1, 110801, 3426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ。あのさあ。\nあんた弁当で好きな\n具とかってあんの", 0, 102, 0, 1, 8, 1, 110801, 3427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ？　何。なんか用。\nや、ないならないで\nいいけど、べつに", 0, 1, 0, 2, 1, 1, 110801, 3428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごめ、ちょっと\n黙っててくんない。\n明日の試験ヤバだから", 0, 2, 0, 2, 1, 1, 110801, 3429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歩き方が静か？\n癖になってるんだよね\n足音を殺すの", 0, 3, 0, 2, 1, 1, 110801, 3430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの血液型？\n大雑把のОだけど。\nなんか文句あんの", 0, 4, 0, 2, 1, 1, 110801, 3431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃんっ！\nや、だからさ…急に\n話しかけんなっての", 0, 101, 0, 2, 4, 1, 110801, 3432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な、何…あんまジッと\n見ないでくんない…\nなんか、その、ハズい", 0, 102, 0, 2, 8, 1, 110801, 3433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きは得意な方だと\n思うけど。昔から\nそれがデフォだったし", 0, 1, 1, 2, 1, 1, 110801, 3434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな時間か…\n昼ごはん\nサクッと作っちゃお", 0, 2, 2, 2, 1, 1, 110801, 3435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ？　夜遊び？\nはッ…そんなん\n５歳で卒業したっての", 0, 3, 3, 2, 1, 1, 110801, 3436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーヤバじゃんコレ…\nふかついてる場合\nじゃないっつーのに…", 0, 2, 0, 3, 1, 1, 110801, 3438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだこれ\nかわいいかよ", 0, 3, 0, 3, 1, 1, 110801, 3439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふーん。\nこの匂い…\nなんかいいじゃん", 0, 4, 0, 3, 1, 1, 110801, 3440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖炉はアドじゃん。\n煮物、焼き物、蒸し物\nいろいろ作れそう", 0, 5, 0, 3, 1, 1, 110801, 3441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何コレ\n食べ物困んないじゃん\nうちにも一台くんない", 0, 7, 0, 3, 1, 1, 110801, 3443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本かァー…んー\n学校の勉強だけで\nいいかなァ…", 0, 8, 0, 3, 1, 1, 110801, 3444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イタズラってなにを\nしたらいいのかな？", 0, 1, 0, 1, 1, 1, 111101, 3446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カップケーキ\n上手に作れました\n食べてくれるかな…", 0, 2, 0, 1, 1, 1, 111101, 3447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人、\nお菓子くれるかな？\nくれなかったら…ふふ", 0, 3, 0, 1, 1, 1, 111101, 3448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オバケ…いないよね？\n怖くなんてないけど！", 0, 4, 0, 1, 1, 1, 111101, 3449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンは\n楽しいけどオバケの\nお祭りなんだよね…", 0, 5, 0, 1, 1, 1, 111101, 3450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃ～、にゃお～！\nちゃんと怖いかな？\n早く帰ってこないかな", 0, 101, 0, 1, 4, 1, 111101, 3451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人のことだから\nお菓子欲しがるよね…\n準備はバッチリです♪", 0, 102, 0, 1, 8, 1, 111101, 3452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ。猫さんのお耳\nよく出来てるでしょ？", 0, 1, 0, 2, 1, 1, 111101, 3453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("触りましたね？\nイタズラしましたね？\nへんた～い！", 0, 2, 0, 2, 1, 1, 111101, 3454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フー！　頭を撫でたら\n怒りますよ！　あれ？\n猫みたいでした？", 0, 3, 0, 2, 1, 1, 111101, 3455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃっ！　も、もう、\n脅かさないでください\n怖くありませんけど！", 0, 4, 0, 2, 1, 1, 111101, 3456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子ですか？\nありがとうございます\nハッピーハロウィン♪", 0, 101, 0, 2, 4, 1, 111101, 3457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゴロゴロ…\nね、猫さんの真似です\n…似てましたか？", 0, 102, 0, 2, 8, 1, 111101, 3458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁ、お菓子作りを\n始めますよ。下準備は\n大事ですからね！", 0, 1, 1, 2, 1, 1, 111101, 3459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今、つまみ食い\nしましたね！？　あっ\nおやつの時間でしたか", 0, 2, 2, 2, 1, 1, 111101, 3460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁ、ハロウィンの\n始まりです…ふぁ…\nね、眠くありません！", 0, 3, 3, 2, 1, 1, 111101, 3461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと疲れたかも…\nパーティの時間まで\nひと休みしなきゃ", 0, 2, 0, 3, 1, 1, 111101, 3463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私も今、こんな感じ\nなのかな？　こんなに\nかわいいといいなぁ", 0, 3, 0, 3, 1, 1, 111101, 3464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘い匂いがいっぱい…\nお菓子の香りかな？", 0, 4, 0, 3, 1, 1, 111101, 3465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かくなると、\n丸まりたくなって…\n…猫になっちゃう！？", 0, 5, 0, 3, 1, 1, 111101, 3466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニンジンもこれくらい\nおいしければ\nいいのに…", 0, 7, 0, 3, 1, 1, 111101, 3468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンの本、\nオバケがたくさん\n載ってて怖いかも…", 0, 8, 0, 3, 1, 1, 111101, 3469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しそうなお菓子が\nいっぱい…これなら\nイタズラされませんね", 0, 12, 0, 3, 1, 1, 111101, 3471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさんいたずら\nできるから\nハロウィン大好き！", 0, 1, 0, 1, 1, 1, 111201, 3473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンだから\nいつもよりすごい\nいたずらしたいな～！", 0, 2, 0, 1, 1, 1, 111201, 3474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャを綺麗に\nくり抜いてすごく怖い\nランタン作っちゃお！", 0, 3, 0, 1, 1, 1, 111201, 3475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子がたくさんで\nどれから食べるか\n迷っちゃうな～！", 0, 4, 0, 1, 1, 1, 111201, 3476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうすればみんなを\nびっくりさせられる\nかな～？", 0, 5, 0, 1, 1, 1, 111201, 3477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャ見てたら\nお腹空いて来たな～\nお菓子食べちゃお♪", 0, 101, 0, 1, 4, 1, 111201, 3478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんには\n特別ないたずらを\n用意してあげるね！", 0, 102, 0, 1, 8, 1, 111201, 3479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャにクラッカー\nを仕掛けて…わっ！？\nみ、見ちゃダメだよ！", 0, 1, 0, 2, 1, 1, 111201, 3480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　なぁに？\nお菓子ほしいの？\nもう、しかたないな～", 0, 2, 0, 2, 1, 1, 111201, 3481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんの\n面白い仮装が\n見てみたいな～！", 0, 3, 0, 2, 1, 1, 111201, 3482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子くれたお礼に\nとびっきりの\nいたずらしちゃうね！", 0, 4, 0, 2, 1, 1, 111201, 3483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんは\nハロウィンでも最高の\nいたずら相手だよ！", 0, 101, 0, 2, 4, 1, 111201, 3484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんと一緒に\nハロウィンパレード\n歩きたいな～！", 0, 102, 0, 2, 8, 1, 111201, 3485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようにいちゃん！\n仮装して出かける\n準備しなきゃ！", 0, 1, 1, 2, 1, 1, 111201, 3486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すいたな～\nもらったお菓子\n食べちゃだめかな？", 0, 2, 2, 2, 1, 1, 111201, 3487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさんいたずらして\nもうクタクタ～\nミソギもう寝るね…", 0, 3, 3, 2, 1, 1, 111201, 3488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やわらか～い…\nここでひと休みして\nまたいたずらしよう！", 0, 2, 0, 3, 1, 1, 111201, 3490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいもので\n油断させてわっ！\nってするのどうかな？", 0, 3, 0, 3, 1, 1, 111201, 3491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいにお～い！\nいたずらのアイデアが\nわいてくるよ！", 0, 4, 0, 3, 1, 1, 111201, 3492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もらったお菓子\nあったかくしたら\nおいしいかな～？", 0, 5, 0, 3, 1, 1, 111201, 3493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子ばっかりじゃ\n飽きちゃうもんね！\nご飯も食べよう！", 0, 7, 0, 3, 1, 1, 111201, 3495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本のなかに\nいたずらのヒント\nないかな～？", 0, 8, 0, 3, 1, 1, 111201, 3496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子がたくさん！\n一人で食べていいの？\nやっぱりだめか～！", 0, 12, 0, 3, 1, 1, 111201, 3498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お勉強は順調ですよ\nやっぱりお兄ちゃんの\nおかげなんでしょうか", 0, 103, 0, 1, 12, 1, 101101, 3500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんとの\n思い出の場所\nまた行きましょうね", 0, 103, 0, 2, 12, 1, 101101, 3501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ～♪\nハロウィンの\nミイラさんうさぎさん\nぴょんぴょ～ん！", 0, 1, 0, 1, 1, 1, 111301, 3502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("るんたった～\nハロウィンハロウィン\n楽しいな～♪", 0, 2, 0, 1, 1, 1, 111301, 3503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンって\nどんなお菓子を\nもらえるのかな～？", 0, 3, 0, 1, 1, 1, 111301, 3504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子をもらう\n練習をしなくちゃ！\nトリックオア\nトリート～♪", 0, 4, 0, 1, 1, 1, 111301, 3505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんと\nハロウィンするの\nミミ楽しみだな～♪", 0, 5, 0, 1, 1, 1, 111301, 3506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんと\nいっしょにお菓子を\n食べたいな～", 0, 101, 0, 1, 4, 1, 111301, 3507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんと\n毎日ハロウィン\nできたらいいな～♪", 0, 102, 0, 1, 8, 1, 111301, 3508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ～\nおにいちゃん！\nハッピーハロウィン♪", 0, 1, 0, 2, 1, 1, 111301, 3509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんも\nいっしょに\nハロウィンパレード\nしようね～！", 0, 2, 0, 2, 1, 1, 111301, 3510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミイラさんうさぎさん\nだぞ～…えへへ\nミミこわかったかな？", 0, 3, 0, 2, 1, 1, 111301, 3511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃん！\nハロウィンのお菓子\nおいしいね～♪", 0, 4, 0, 2, 1, 1, 111301, 3512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんと\nいっしょなら\nおばけさんも\nこわくないよ！", 0, 101, 0, 2, 4, 1, 111301, 3513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミね\nハロウィンも\nおにいちゃんも\nだ～いすき♪", 0, 102, 0, 2, 8, 1, 111301, 3514);
