INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねーねー、\nルナとお出かけして！", 0, 101, 0, 2, 4, 1, 111401, 3540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいさんと、\n遊びたいなー！", 0, 102, 0, 2, 8, 1, 111401, 3541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ！\nなんかまぶしいね！", 0, 1, 1, 2, 1, 1, 111401, 3542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ルナ、お腹空いたな", 0, 2, 2, 2, 1, 1, 111401, 3543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこに行こうかな？", 0, 3, 3, 2, 1, 1, 111401, 3544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ルナ、これ好きだな", 0, 2, 0, 3, 1, 1, 111401, 3546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい！　好き！", 0, 3, 0, 3, 1, 1, 111401, 3547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんかいい匂い！", 0, 4, 0, 3, 1, 1, 111401, 3548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいねー", 0, 5, 0, 3, 1, 1, 111401, 3549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ\nおいしいね", 0, 7, 0, 3, 1, 1, 111401, 3551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ルナ、\n眠くなっちゃう…", 0, 8, 0, 3, 1, 1, 111401, 3552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ。あの人と\nランドソルでデート\nできたらうれしいな♪", 0, 103, 0, 1, 12, 1, 105201, 3554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとなら\nどんなことだって\nできる気がするわ♪", 0, 103, 0, 2, 12, 1, 105201, 3555);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーあ、退屈だな\nカレでも探しに\nいこうかな", 0, 1, 0, 1, 1, 1, 106501, 3556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この前のケンカは\n最高に燃えたなぁ\n…拳が疼いてきたぜ", 0, 2, 0, 1, 1, 1, 106501, 3557);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一体、この世界は\nどうなっちまったって\nいうんだ…？", 0, 3, 0, 1, 1, 1, 106501, 3558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう仕事の時間か\nボスも人使いが荒いぜ\n…ま、いいけどさ！", 0, 4, 0, 1, 1, 1, 106501, 3559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オレたち以外に\nドラゴン族はあと何人\nいるんだろうな…", 0, 5, 0, 1, 1, 1, 106501, 3560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カレの真剣な顔\n面白かったな\nまた遊びたいぜ", 0, 101, 0, 1, 4, 1, 106501, 3561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしてカレがそばに\nいると、腹の底から\n力が湧いてくるんだ？", 0, 102, 0, 1, 8, 1, 106501, 3562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よっす！\nなんかオイシイ話でも\nあったりしない？", 0, 1, 0, 2, 1, 1, 106501, 3563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なあ、オレと遊ぼうぜ\n心配すんなよ。危ない\nことはよしとくからさ", 0, 2, 0, 2, 1, 1, 106501, 3564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうした。オレに\nケンカ売ろうってか？\n…ははは、冗談だよ！", 0, 3, 0, 2, 1, 1, 106501, 3565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうど退屈してた\nところだ、特訓に\n付き合ってくれよ", 0, 4, 0, 2, 1, 1, 106501, 3566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ったくよぉ…\nオレがかわいいなんて\n冗談はもうよせよ？", 0, 101, 0, 2, 4, 1, 106501, 3567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の仕事も一緒に\n来るだろ？　断っても\n連れて行くけどな！", 0, 102, 0, 2, 8, 1, 106501, 3568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！　今日の\n予定はまずケンカして\nで、その後もケンカだ", 0, 1, 1, 2, 1, 1, 106501, 3569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よっす！\n腹ごしらえが済んだら\nオレと遊ぼうぜ！", 0, 2, 2, 2, 1, 1, 106501, 3570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は危ないから\nあんま出歩くな？\n…だから面白えんだろ", 0, 3, 3, 2, 1, 1, 106501, 3571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のケンカに備えて\n今は休んでおくか…\n全力で暴れたいからな", 0, 2, 0, 3, 1, 1, 106501, 3573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボスの飼ってる\nラーゴが、中に\n入ってるんじゃ？", 0, 3, 0, 3, 1, 1, 106501, 3574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、たぎる匂いが\nする…ひと暴れ\nしたくなってきた！", 0, 4, 0, 3, 1, 1, 106501, 3575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおぉ…\nオレの拳もなんだか\n熱くなってきたぜ…！", 0, 5, 0, 3, 1, 1, 106501, 3576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつでも全力で\nケンカするために\n力を蓄えないとな", 0, 7, 0, 3, 1, 1, 106501, 3578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりな…オレが\n知ってる地図とは\nまるで違ってやがる", 0, 8, 0, 3, 1, 1, 106501, 3579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁプレゼントで\n埋め尽くしてやろう！\n大いに喜ぶがいいよ！", 0, 1, 0, 1, 1, 1, 111501, 3581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス☆\n聖夜の宴だ\n派手に楽しむとしよう", 0, 2, 0, 1, 1, 1, 111501, 3582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("煙突から入る？\nいいや、ワタシは\nいつでも正面からさ♪", 0, 3, 0, 1, 1, 1, 111501, 3583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンタクロースの\nお出ましだ！\n歓迎するがいいよ♪", 0, 4, 0, 1, 1, 1, 111501, 3584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("飾り付けが足りん！\nワタシが演出して\nやろうじゃないか！", 0, 5, 0, 1, 1, 1, 111501, 3585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人の喜ぶ顔を見るのも\n悪くはないな…おっと\nワタシらしくないな☆", 0, 101, 0, 1, 4, 1, 111501, 3586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントはまだか？\nワタシを喜ばせたら\nお返しは弾むぞ♪", 0, 102, 0, 1, 8, 1, 111501, 3587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシを呼んだか？\n退屈な要件だったら\n覚悟しておくことだ", 0, 1, 0, 2, 1, 1, 111501, 3588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ？\nワタシへの挑戦か？\nよし、受けた♪", 0, 2, 0, 2, 1, 1, 111501, 3589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと、当たらんよ\nワタシの乱数聖域は\n絶対だからな…♪", 0, 3, 0, 2, 1, 1, 111501, 3590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ、オマエも\n暇なのか？\n奇遇だな、ワタシもさ", 0, 4, 0, 2, 1, 1, 111501, 3591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにか愉しいことでも\nしようじゃないか\nさぁ、何をする？", 0, 101, 0, 2, 4, 1, 111501, 3592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうもワタシに\n気安く触れるのは\nオマエくらいだよ…♪", 0, 102, 0, 2, 8, 1, 111501, 3593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝だろうと関係ない！\nさぁ愉しく苛烈に\n騒ごうじゃないか♪", 0, 1, 1, 2, 1, 1, 111501, 3594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("調子の出てくる時間だ\nしっかりワタシを\n愉しませてくれよ♪", 0, 2, 2, 2, 1, 1, 111501, 3595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠いなどと言わせんぞ\nまだまだ一日は\n終わらんからな！", 0, 3, 3, 2, 1, 1, 111501, 3596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい具合じゃないか\nこのまま持って帰って\nしまおうか…♪", 0, 2, 0, 3, 1, 1, 111501, 3598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか愛らしい\n造形をしているな？\nワタシには負けるがな", 0, 3, 0, 3, 1, 1, 111501, 3599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほう、悪くない香りだ\n戦いの匂いをうまく\n隠してくれそうだ…♪", 0, 4, 0, 3, 1, 1, 111501, 3600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体が温まってくると\nひと暴れしたくなるな", 0, 5, 0, 3, 1, 1, 111501, 3601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシの舌は厳しいぞ\n…ふーむ、なるほど\n認めざるをえんな", 0, 7, 0, 3, 1, 1, 111501, 3603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスティーナさんは\n知識の収集も\n欠かさないんだよ", 0, 8, 0, 3, 1, 1, 111501, 3604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは驚いたな\nだがもっと、もっとだ\nワタシを退屈させるな", 0, 14, 0, 3, 1, 1, 111501, 3606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな戯れだって\n軽くこなしてしまう\nクリスティーナさんさ", 0, 15, 0, 3, 1, 1, 111501, 3607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\nさあ、パーティーを\n盛り上げるよ！", 0, 1, 0, 1, 1, 1, 111601, 3608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("衣装一つで全然\n気分が違うね！\n最高のクリスマスに\nなりそうだよ！", 0, 2, 0, 1, 1, 1, 111601, 3609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツリーのてっぺんの\n星って、なんだか\n欲しくなるんだよね", 0, 3, 0, 1, 1, 1, 111601, 3610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("めいっぱい\nクリスマスを楽しむよ\n遊びだって本気\nなんだからね！", 0, 4, 0, 1, 1, 1, 111601, 3611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("赤、白、緑、金\nクリスマスカラー\nってお洒落だよね", 0, 5, 0, 1, 1, 1, 111601, 3612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("雪、降らないかな？\nホワイトクリスマス\nってちょっと\n憧れるなぁ", 0, 101, 0, 1, 4, 1, 111601, 3613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと過ごすこの\n楽しい時間がずーっと\n続けばいいのにな", 0, 102, 0, 1, 8, 1, 111601, 3614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスライブ\nチケット用意するから\n絶対来てよね！", 0, 1, 0, 2, 1, 1, 111601, 3615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カンパーイ！\nジュースだけど\nちょっと大人の\n気分だね", 0, 2, 0, 2, 1, 1, 111601, 3616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマス衣装どう？\nかわいいでしょ\nあっ、どこ見てるの！", 0, 3, 0, 2, 1, 1, 111601, 3617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、後で街に\n行こうよ\n大きなツリーを\n一緒に見たいんだ♪", 0, 4, 0, 2, 1, 1, 111601, 3618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、ダンスの練習に\n付き合ってくれない？\n大丈夫、手取り足取り\n教えてあげるから♪", 0, 101, 0, 2, 4, 1, 111601, 3619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年のクリスマスも\n隣にキミが\nいてくれたら\nうれしいのにな", 0, 102, 0, 2, 8, 1, 111601, 3620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスって朝から\nドキドキしちゃうね\nなんだか子どもみたい", 0, 1, 1, 2, 1, 1, 111601, 3621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パーティーの準備も\n大分進んだね\n一息ついて\nランチにしよっか", 0, 2, 2, 2, 1, 1, 111601, 3622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("静かな夜だね\n心臓の音まで\n聞こえちゃいそう…", 0, 3, 3, 2, 1, 1, 111601, 3623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ～、この絶妙な\n柔らかさ…\nいい仕事してるなぁ…", 0, 2, 0, 3, 1, 1, 111601, 3625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドル顔負けの\nかわいさ、ズルい！\nでもかわいい！", 0, 3, 0, 3, 1, 1, 111601, 3626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、落ち着くなぁ\n今日はゆっくり\n眠れそうだよ", 0, 4, 0, 3, 1, 1, 111601, 3627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬくぬく～\nどうしよう、ここから\n動きたくないなぁ", 0, 5, 0, 3, 1, 1, 111601, 3628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダンスの練習もしたし\nちょっとくらいなら\nいいよね！", 0, 7, 0, 3, 1, 1, 111601, 3630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルといえど\nかわいいだけじゃダメ\n知識も必要だよね", 0, 8, 0, 3, 1, 1, 111601, 3631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("面白ーい！\nこの演出、ライブでも\nできないかな？", 0, 14, 0, 3, 1, 1, 111601, 3633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もふもふ～♪\n寒い日には最高の\n抱き心地だね！", 0, 15, 0, 3, 1, 1, 111601, 3634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼ともっとお話し\nしたいな…もう少し\n補習を増やそうかしら", 0, 103, 0, 1, 12, 1, 101801, 3635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君のこともっともっと\n教えて欲しいな。私に\n補習授業してくれる？", 0, 103, 0, 2, 12, 1, 101801, 3636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿ならあやつも\n子ども扱いできまい！\n…じゃがなぜか、少し\n物足りないような…", 0, 1, 0, 1, 1, 1, 111701, 3637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時間もあるし、\n聖夜の宴の\n準備をするかのう♪", 0, 2, 0, 1, 1, 1, 111701, 3638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…わらわの知る聖夜と\n随分違うが、宴は宴\n楽しませて\nもらおうかのう♪", 0, 3, 0, 1, 1, 1, 111701, 3639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人の姿で\nできること…ふむ\n少しあやつを\nからかってやるか♪", 0, 4, 0, 1, 1, 1, 111701, 3640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…クリスマスは\n恋人たちの夜！？\nち、近頃の若いもんは\n破廉恥なのじゃ！", 0, 5, 0, 1, 1, 1, 111701, 3641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あやつがおらんと、\n宴も物足りぬな\n…馬鹿者が\n早く帰ってこい…", 0, 101, 0, 1, 4, 1, 111701, 3642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰も見ておらぬな…？\n…よし、あやつへの\nプレゼントを\n準備するとしようか！", 0, 102, 0, 1, 8, 1, 111701, 3643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの\nチキンにケーキ…\nべ、別に楽しみになど\nしておらぬぞ！", 0, 1, 0, 2, 1, 1, 111701, 3644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿では、わらわの\n頭をなでるのは\n難しかろう…べ、\n別に残念ではないわ！", 0, 2, 0, 2, 1, 1, 111701, 3645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリー\nクリスマスじゃ！\nさあ、わらわのために\n宴の準備をするのじゃ", 0, 3, 0, 2, 1, 1, 111701, 3646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そんなにこの衣装が\n気になるのか？\n…だったら、直に\n触ってみるがよい♪", 0, 4, 0, 2, 1, 1, 111701, 3647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもと逆に、お主を\n子ども扱いしてやるか\nほれ、膝枕をしてやる\nからそばに来い♪", 0, 101, 0, 2, 4, 1, 111701, 3648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…せ、聖夜の予定は\n空けておくのじゃぞ？\nなんでって…\nな、なんでもじゃ！", 0, 102, 0, 2, 8, 1, 111701, 3649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう朝か…聖夜の宴が\n楽しみで…ではなく！\n準備のせいで、\nあまり眠れんかったぞ", 0, 1, 1, 2, 1, 1, 111701, 3650);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ずっと雪が\n降っておれば、\n陽光が強いこの時間も\n怯えずにすむのにのう", 0, 2, 2, 2, 1, 1, 111701, 3651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時は来た…\nさあ眷属よ！\nわらわと共に、\n聖夜の宴を楽しもうぞ", 0, 3, 3, 2, 1, 1, 111701, 3652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い椅子ではないか\nここから聖夜の宴を\n眺めるのもよいかもな", 0, 2, 0, 3, 1, 1, 111701, 3654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわい…こほん\nなかなか良い\nデザインをしておるな", 0, 3, 0, 3, 1, 1, 111701, 3655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、良い香りじゃ\n聖夜の宴でも\nこれを使うとしよう", 0, 4, 0, 3, 1, 1, 111701, 3656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これが癒し…はっ！\nあやうく浄化される\nところであった…", 0, 5, 0, 3, 1, 1, 111701, 3657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニ、ニンニクは\n入っておらぬよな？\n…うむ、美味じゃ♪", 0, 7, 0, 3, 1, 1, 111701, 3659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聖夜は恋人たちの夜…\n…き、気になるわけ\nではないが、\n少し調べてみるか", 0, 8, 0, 3, 1, 1, 111701, 3660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほう…これは面白い\n魔法の使い方じゃな\nまるで本物の\n演劇のようじゃ", 0, 14, 0, 3, 1, 1, 111701, 3662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、この程度の\nかわいさに誘惑される\nわらわでは…\nふわもこなのじゃ～♪", 0, 15, 0, 3, 1, 1, 111701, 3663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせち料理も\n魔物尽くしだったり\nしないわよね！", 0, 1, 0, 1, 1, 1, 112001, 3664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣で何をお祈り\nしようかしら…\n定番でいいわよね？", 0, 2, 0, 1, 1, 1, 112001, 3665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初日の出って\n特別な感じがして\nいいわよね…", 0, 3, 0, 1, 1, 1, 112001, 3666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い中並んで飲む\n甘酒って不思議なほど\nおいしいわよね", 0, 4, 0, 1, 1, 1, 112001, 3667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("羽根つきで勝負…\nあいつにだったら\n勝てるかしら？", 0, 5, 0, 1, 1, 1, 112001, 3668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年賀状になんて書こう\n…いろいろと\n恥ずかしくなるのよね", 0, 101, 0, 1, 4, 1, 112001, 3669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年もあいつと\n居られること…\n結構うれしいわ", 0, 102, 0, 1, 8, 1, 112001, 3670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何じっと\n見てんのよ？\nお年玉はあげないわよ", 0, 1, 0, 2, 1, 1, 112001, 3671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせち料理一緒に\n食べる？\n結構おいしいわよ", 0, 2, 0, 2, 1, 1, 112001, 3672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("羽根つきで負けたら\n顔に墨塗られるのよ\n覚悟しなさい！", 0, 3, 0, 2, 1, 1, 112001, 3673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("門松飾るから\nちょっと手伝って\nくれる？", 0, 4, 0, 2, 1, 1, 112001, 3674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと一緒に\n初詣行くのも悪くない\n…かも", 0, 101, 0, 2, 4, 1, 112001, 3675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣で何をお祈り\nしたか？　うっさい！\n内緒よ！内緒！", 0, 102, 0, 2, 8, 1, 112001, 3676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう朝なの…\n正月くらいゆっくり\n寝ていたいわよね…", 0, 1, 1, 2, 1, 1, 112001, 3677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせちに飽きたら\n次は何を食べよう\nかしら…", 0, 2, 2, 2, 1, 1, 112001, 3678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝ましょ\nいい初夢が見られると\nいいわね", 0, 3, 3, 2, 1, 1, 112001, 3679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好でいるのも\nなかなか疲れるわね\n休憩～", 0, 2, 0, 3, 1, 1, 112001, 3681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…う～ん\n鏡餅も顔を描けば\nかわいくなるかしら？", 0, 3, 0, 3, 1, 1, 112001, 3682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂いね\n落ち着いて\n眠れそう…", 0, 4, 0, 3, 1, 1, 112001, 3683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでお餅焼いたら\n一段とおいしく\nなりそうね", 0, 5, 0, 3, 1, 1, 112001, 3684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月に食べるものは\nなんでもおいしく\n感じちゃうわね！", 0, 7, 0, 3, 1, 1, 112001, 3686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物を使わない\nおせちを\n調べておかなきゃ…", 0, 8, 0, 3, 1, 1, 112001, 3687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新年を気持ちよく\n過ごせるように\nお掃除がんばります！", 0, 1, 0, 1, 1, 1, 112101, 3689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("神殿に通っていたら\nいつの間にか足腰が\n鍛えられたような…", 0, 2, 0, 1, 1, 1, 112101, 3690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("神殿付近は屋台も\nあるので、良い香りが\n漂ってくるんですよ～", 0, 3, 0, 1, 1, 1, 112101, 3691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせちを作れるように\nなれば、子どもたちも\n喜んでくれるかな…？", 0, 4, 0, 1, 1, 1, 112101, 3692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コホォォォォォ…！\nふぅ、深呼吸すると\n落ち着きますね♪", 0, 5, 0, 1, 1, 1, 112101, 3693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お仕事以外の時も\nあなたと…い、いえ！\nなんでもないです！", 0, 101, 0, 1, 4, 1, 112101, 3694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと一緒だと\nなんだかポカポカ\nしてくるんです…", 0, 102, 0, 1, 8, 1, 112101, 3695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好をしていると\nなんだか神殿にいる\n気分になりますね", 0, 1, 0, 2, 1, 1, 112101, 3696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえば神殿で\n甘酒をもらったんです\nあなたも飲みますか？", 0, 2, 0, 2, 1, 1, 112101, 3697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、髪飾りが\nズレちゃってました！\nいけないいけない…", 0, 3, 0, 2, 1, 1, 112101, 3698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃわっ！？\nく、くすぐったり\nしないでください～", 0, 4, 0, 2, 1, 1, 112101, 3699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そ、そんなに\n見つめられると\nて、照れちゃいます…", 0, 101, 0, 2, 4, 1, 112101, 3700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、私が考えた\n運気上昇のおまじない\nかけてあげますね♪", 0, 102, 0, 2, 8, 1, 112101, 3701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n神殿のお手伝いに行く\n準備もしなきゃですね", 0, 1, 1, 2, 1, 1, 112101, 3702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼になりましたし\nご飯は私が作…\nえっ、ダメですか！？", 0, 2, 2, 2, 1, 1, 112101, 3703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日も早いですし\nそろそろ寝る支度を…\nふわぁ…", 0, 3, 3, 2, 1, 1, 112101, 3704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除も終わったので\n少し休憩を…ふわぁ…\n急に眠気が…", 0, 2, 0, 3, 1, 1, 112101, 3706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新年を気持ちよく\n過ごせるようこの子も\nきれいにしましょう♪", 0, 3, 0, 3, 1, 1, 112101, 3707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("神殿のお香のような\n香りだと落ち着いて\n過ごせそうですよね", 0, 4, 0, 3, 1, 1, 112101, 3708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかですね～…\n甘酒も飲んで体の\n芯から温めましょう", 0, 5, 0, 3, 1, 1, 112101, 3709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年こそ\n料理も上手に…\nもぐもぐもぐもぐ…", 0, 7, 0, 3, 1, 1, 112101, 3711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("失敗続きだと\n逆に運が良くなる…\nほ、本当ですかぁ…？", 0, 8, 0, 3, 1, 1, 112101, 3712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミにならもう\nどんな私を見られても\n大丈夫かな…♪", 0, 103, 0, 1, 12, 1, 103401, 3714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なになにどしたのぉ？\nお姉さんが撫でたげる\nこっちにきなさぁい♪", 0, 103, 0, 2, 12, 1, 103401, 3715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたくしの舞を\n主さまは喜んで\nくださるでしょうか…", 0, 1, 0, 1, 1, 1, 111901, 3716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年を越したあとに\n食べるおそばも\nおいしいです", 0, 2, 0, 1, 1, 1, 111901, 3717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘酒を飲むと\n心まで温まる\n気がいたします", 0, 3, 0, 1, 1, 1, 111901, 3718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのために\n真心を込めたおせちを\nご用意しなくては", 0, 4, 0, 1, 1, 1, 111901, 3719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おみくじを引くのは\nドキドキしつつも\n楽しいものです", 0, 5, 0, 1, 1, 1, 111901, 3720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまの温もりは\n心まで温めてくれる\nようです", 0, 101, 0, 1, 4, 1, 111901, 3721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うまくできなくとも\n心を込めて精いっぱい\n舞いましょう", 0, 102, 0, 1, 8, 1, 111901, 3722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、この晴れ着は\n似合っている\nでしょうか？", 0, 1, 0, 2, 1, 1, 111901, 3723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お餅はゆっくりと\n召し上がって\nくださいまし", 0, 2, 0, 2, 1, 1, 111901, 3724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのお顔の\n福笑いなら、完璧に\nできる気がいたします", 0, 3, 0, 2, 1, 1, 111901, 3725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまはどのような\n初夢をご覧になった\nのでしょう？", 0, 4, 0, 2, 1, 1, 111901, 3726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘酒の飲み過ぎは\nいけませんよ？\nめっ、でございます", 0, 101, 0, 2, 4, 1, 111901, 3727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("二人羽織とは\nあんなにも暖かい\nものなのですね…", 0, 102, 0, 2, 8, 1, 111901, 3728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n寒い季節の朝日は\nとても美しいですね", 0, 1, 1, 2, 1, 1, 111901, 3729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしくとも\n食べ過ぎは正月太りの\nもとでございます", 0, 2, 2, 2, 1, 1, 111901, 3730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい夢が見られるよう\n暖かくして\n眠るといたしましょう", 0, 3, 3, 2, 1, 1, 111901, 3731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか…\nこのまま\n寝てしまいそうです", 0, 2, 0, 3, 1, 1, 111901, 3733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと一緒に\nお正月遊びを\n楽しんでみたいです", 0, 3, 0, 3, 1, 1, 111901, 3734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("神殿の独特な香りを\nおうちに持ち込むのは\nどうでしょうか", 0, 4, 0, 3, 1, 1, 111901, 3735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪をひきませんよう\n暖かくいたしましょう", 0, 5, 0, 3, 1, 1, 111901, 3736);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ過ぎは\n正月太りの\nもとだというのに…", 0, 7, 0, 3, 1, 1, 111901, 3738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのために\n参拝の作法を\n予習しておきましょう", 0, 8, 0, 3, 1, 1, 111901, 3739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…この杖、変身前には\n無いパーツがあるけど\nこれはどこから…うん\n考えないようにしよう", 0, 1, 0, 1, 1, 1, 112201, 3741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フ、フリフリの\nかわいい衣装…はっ！\n素に戻ってはダメだ！", 0, 2, 0, 1, 1, 1, 112201, 3742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法探偵\nミスティ★カスミ！\n魔法の力で捜査開始！\n…練習終わりっと", 0, 3, 0, 1, 1, 1, 112201, 3743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪しい視線を感じる…\nまさか、近くに\n闇の力を持つ人が！？", 0, 4, 0, 1, 1, 1, 112201, 3744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時間もあるし、\n魔法少女の修行を…\nじゃ、じゃなくて！\n探偵の仕事をしよう！", 0, 5, 0, 1, 1, 1, 112201, 3745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くんとずっと\n一緒に居られるし、\n魔法少女も\n案外悪くないかも♪", 0, 101, 0, 1, 4, 1, 112201, 3746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の訓練のため\n助手くんの所に行こう\nかな…あ、あくまで\n訓練のためにね！", 0, 102, 0, 1, 8, 1, 112201, 3747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…髪型が急に\n変わって驚いた？\nき、気になるなら…\n少し触ってみるかい？", 0, 1, 0, 2, 1, 1, 112201, 3748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くんは魔法少女に\nなりたいのかい？\nその場合は魔法騎士…\nいや、魔法助手とか？", 0, 2, 0, 2, 1, 1, 112201, 3749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭に浮かぶ呪文…\n強制変身…助手くん\n魔法少女とは\n呪いか何かなのかな？", 0, 3, 0, 2, 1, 1, 112201, 3750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あまり触らないで\nくれ…魔法少女になる\nと感覚が鋭くなって、\n耳も敏感に…ひゃう！", 0, 4, 0, 2, 1, 1, 112201, 3751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("や、やっぱりこの\n格好は変かな…え、\nかわいい？　じゃあ…\nいや、でも、う～ん", 0, 101, 0, 2, 4, 1, 112201, 3752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…この変身は助手くん\nのせいでもあるんだよ\nだから…せ、責任を\n取ってもらうからね！", 0, 102, 0, 2, 8, 1, 112201, 3753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう助手くん\nさあ、そろそろ\n街のパトロールに\n行こうじゃないか！", 0, 1, 1, 2, 1, 1, 112201, 3754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお昼…助手くん、\nそろそろ本業に戻ろう\n…その顔は何かな？\n私の本業は探偵だぞ！", 0, 2, 2, 2, 1, 1, 112201, 3755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜だけど、私は\nもう少し仕事をするよ\n魔法少女の強い体は\nこんなときに便利だね", 0, 3, 3, 2, 1, 1, 112201, 3756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいい…\nこの癒しを、魔法と\n論理の二つの観点から\n解明したいね…", 0, 2, 0, 3, 1, 1, 112201, 3758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダ、ダメ！！\nここで感情のままに\n飛びついたら、私の\nイメージがぁ～！", 0, 3, 0, 3, 1, 1, 112201, 3759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心が安らぐ香りだね…\n…今なら、魔法少女も\nすんなりと受け入れ…\nてはダメだっ！", 0, 4, 0, 3, 1, 1, 112201, 3760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\n魔法少女だろうと\n休息は必要だし、少し\n休んでいこうかな", 0, 5, 0, 3, 1, 1, 112201, 3761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女も探偵も、\nやっぱり体が資本！\n食べられるときに\n食べておかないとね♪", 0, 7, 0, 3, 1, 1, 112201, 3763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…魔法少女\nセリイちゃんの本は\nどこにあるのかな？", 0, 8, 0, 3, 1, 1, 112201, 3764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女かぁ…\nせっかくだし思う存分\n体を動かしてみたいな", 0, 1, 0, 1, 1, 1, 112301, 3766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃん…\nこの格好を見て\n私って気づくかな？", 0, 2, 0, 1, 1, 1, 112301, 3767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…\n今日はなんだか\n調子がいいかも", 0, 3, 0, 1, 1, 1, 112301, 3768);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法は便利だけど\nあまり頼りすぎちゃ\nダメだよね", 0, 4, 0, 1, 1, 1, 112301, 3769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっき街で小さな子に\n声かけられちゃった\n照れるけどうれしいな", 0, 5, 0, 1, 1, 1, 112301, 3770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人がいると\nなんだかホッとする\n不思議…", 0, 101, 0, 1, 4, 1, 112301, 3771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女になっても\nあの人への気持ちは\nずっと同じ…", 0, 102, 0, 1, 8, 1, 112301, 3772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の私…ですか？\nはいとっても元気です\n…あなたのおかげかも", 0, 1, 0, 2, 1, 1, 112301, 3773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よかったら魔法の\n練習に付き合って\nくれませんか？", 0, 2, 0, 2, 1, 1, 112301, 3774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…\nこの格好どうですか？\n似合ってると…いいな", 0, 3, 0, 2, 1, 1, 112301, 3775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…な、なんですか？\nあまり見られると\n恥ずかしいです…", 0, 4, 0, 2, 1, 1, 112301, 3776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、あなたのそばに\nいられたら、それで…", 0, 101, 0, 2, 4, 1, 112301, 3777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("想い人と結ばれる\n魔法は…ひゃっ！？\n今の聞いてましたか？", 0, 102, 0, 2, 8, 1, 112301, 3778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日も街の平和の\nために頑張らなきゃ", 0, 1, 1, 2, 1, 1, 112301, 3779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すきましたね。\nあの…一緒にランチは\nいかがですか？", 0, 2, 2, 2, 1, 1, 112301, 3780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、もうこんな時間…\nふふ、まだこんなに\n体力が余ってるのに", 0, 3, 3, 2, 1, 1, 112301, 3781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいい…\nこの気持ち良さは\nどんな魔法も勝てない", 0, 2, 0, 3, 1, 1, 112301, 3783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何これ、かわいい…\nお姉ちゃんにも\n見せてあげたいな", 0, 3, 0, 3, 1, 1, 112301, 3784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、いい香り\n…これ、魔法で\n出せたりしないかな？", 0, 4, 0, 3, 1, 1, 112301, 3785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い\nえへへ…なんだか\nお姉ちゃんみたい", 0, 5, 0, 3, 1, 1, 112301, 3786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいなぁ、これ\n魔法少女になってから\n食欲旺盛かも…", 0, 7, 0, 3, 1, 1, 112301, 3788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…\n魔法少女になっても\n読書はやめられないな", 0, 8, 0, 3, 1, 1, 112301, 3789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みらくるまほりん\nくるりんぱ～♪\n王子はんのために\n花嫁修業や～♪", 0, 103, 0, 1, 12, 1, 101001, 3791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あのな王子はん\nできたらその…\nお姫さまだっこを\nお願いしてもええ…？", 0, 103, 0, 2, 12, 1, 101001, 3792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりわたしたちの\nギルドハウスの\n居心地は最高ですね☆", 0, 1, 0, 1, 1, 1, 180401, 3793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王宮じゃできないこと\nやっちゃいましょう♪\n例えば、えっと～…", 0, 2, 0, 1, 1, 1, 180401, 3794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、隠しておいた\nおやつがありました！\nまだ食べられますね☆", 0, 3, 0, 1, 1, 1, 180401, 3795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごはんはみんなで\n楽しく食べましょう！\nそれが一番の\n調味料です♪", 0, 4, 0, 1, 1, 1, 180401, 3796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりここが、\nわたしの帰る場所です\n…ただいま☆", 0, 5, 0, 1, 1, 1, 180401, 3797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか物足りません\nきっと、あの人が隣に\nいないからですね…", 0, 101, 0, 1, 4, 1, 180401, 3798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこを見ても、大切な\n思い出がたくさん\n詰まっていますね♪", 0, 102, 0, 1, 8, 1, 180401, 3799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無礼者～、なんて\n冗談です♪　どんどん\n触っちゃってください", 0, 1, 0, 2, 1, 1, 180401, 3800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷにぷにでしょう～？\nい～っぱい食べるのが\nぷにぷにの秘訣です！", 0, 2, 0, 2, 1, 1, 180401, 3801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("握手したいんですか？\nはい、にぎにぎ～！\nもう離しませんよ♪", 0, 3, 0, 2, 1, 1, 180401, 3802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしましたか？\n退屈してるんでしたら\nお散歩に行きましょう", 0, 4, 0, 2, 1, 1, 180401, 3803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごはん王子♪\nわたしは王女ですから\nこれでピッタリですね", 0, 101, 0, 2, 4, 1, 180401, 3804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大好きです～\n愛してます～\n…ほんと、ですよ♪", 0, 102, 0, 2, 8, 1, 180401, 3805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ごはんは大事です！\n山盛りごはんを食べて\n元気いっぱいですよ☆", 0, 1, 1, 2, 1, 1, 180401, 3806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹ぺこぺこになる\n時間ですね～！\nごはん特盛、一つ！", 0, 2, 2, 2, 1, 1, 180401, 3807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹いっぱい、今日は\nよく眠れそうですね♪\n明日もおいしい一日を", 0, 3, 3, 2, 1, 1, 180401, 3808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩休憩～♪\nお腹を休めて、次の\nごはんに挑みます…☆", 0, 2, 0, 3, 1, 1, 180401, 3810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいらしい\nぬいぐるみですね～\nキャルちゃんみたい☆", 0, 3, 0, 3, 1, 1, 180401, 3811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すんすん…この匂い\n食欲増進の効果が\nありそうですね…？", 0, 4, 0, 3, 1, 1, 180401, 3812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体温が上がってくると\n眠くなっちゃいます…\nほわぁ～", 0, 5, 0, 3, 1, 1, 180401, 3813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐもぐもぐもぐ\nむぐむぐむぐむぐむぐ\nはぐはぐはぐはぐはぐ", 0, 7, 0, 3, 1, 1, 180401, 3815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("教養を身に着けるには\n読書が一番です！\nえっと次のレシピは～", 0, 8, 0, 3, 1, 1, 180401, 3816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルらしくなる\nコツって、何か\nあるんでしょうか？", 0, 1, 0, 1, 1, 1, 112401, 3818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色んな人と話すのが\n好きなんです。つい\n長くなっちゃって…", 0, 2, 0, 1, 1, 1, 112401, 3819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルを目指すって\n決めてから、毎日が\nワクワクなんです♪", 0, 3, 0, 1, 1, 1, 112401, 3820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんとストレッチ\nしておかなくっちゃ\nよいしょ、よいしょ…", 0, 4, 0, 1, 1, 1, 112401, 3821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リンちゃんミオちゃん\n二人に負けないように\n私、頑張ります！", 0, 5, 0, 1, 1, 1, 112401, 3822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の笑顔は素敵だって\n誰かに褒められた…\nそんな気がするんです", 0, 101, 0, 1, 4, 1, 112401, 3823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちを支えてくれる\n誰かが、ずっと一緒に\nいてくれたような…", 0, 102, 0, 1, 8, 1, 112401, 3824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしましたか？\n何か困ってるのなら\nお手伝いしますよ！", 0, 1, 0, 2, 1, 1, 112401, 3825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなさん個性的で\n普通じゃない人ばかり\nいるような気が…", 0, 2, 0, 2, 1, 1, 112401, 3826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はポカポカした\nいい天気ですね～\nお散歩日和です！", 0, 3, 0, 2, 1, 1, 112401, 3827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今、ミルクティーを\n淹れてたんです♪\nあなたも飲みますか？", 0, 4, 0, 2, 1, 1, 112401, 3828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の得意なこと？\nうーんなんでしょう…\nあっ、肩たたきです！", 0, 101, 0, 2, 4, 1, 112401, 3829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生・ハム・メローン！\nあ、ライブの掛け声を\n練習してたんですよ♪", 0, 102, 0, 2, 8, 1, 112401, 3830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n今日も一日\n頑張りましょうね！", 0, 1, 1, 2, 1, 1, 112401, 3831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかりお昼を食べて\n午後からも張り切って\nいきましょうね♪", 0, 2, 2, 2, 1, 1, 112401, 3832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐっすり眠れるよう\n早めに用事を済ませて\nお休みしましょうね", 0, 3, 3, 2, 1, 1, 112401, 3833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと休んだら\nレッスンの続きも\n頑張ります！", 0, 2, 0, 3, 1, 1, 112401, 3835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ～\nふわふわもこもこで\nかわいいです～♪", 0, 3, 0, 3, 1, 1, 112401, 3836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リラックスできる\nいい香りですね～♪", 0, 4, 0, 3, 1, 1, 112401, 3837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、ポカポカです♪\n温かい飲み物も\nほしくなりますね", 0, 5, 0, 3, 1, 1, 112401, 3838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンしたら\nお腹が空いちゃって…\nぱくぱくもぐもぐ…", 0, 7, 0, 3, 1, 1, 112401, 3840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンに役立つ\n運動の情報とか\n載ってるでしょうか…", 0, 8, 0, 3, 1, 1, 112401, 3841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きらきらーん☆\nよし、次のステージは\nこれで行けるかも！", 0, 1, 0, 1, 1, 1, 112601, 3843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の元気でみんなも\n元気になってくれたら\nうれしいな～", 0, 2, 0, 1, 1, 1, 112601, 3844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとレッスンで\n疲れちゃったかも…\nでも頑張るぞっ！", 0, 3, 0, 1, 1, 1, 112601, 3845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("晩ごはん何にしよう？\nそーだ、しぶりんにも\n聞いてみよっと！", 0, 4, 0, 1, 1, 1, 112601, 3846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元気だから笑顔になる\nじゃなくて\n笑顔だから\n元気になるんだよね～", 0, 5, 0, 1, 1, 1, 112601, 3847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("声援を聞いてる時ね\nすごく懐かしいって\n思うことがあるんだ", 0, 101, 0, 1, 4, 1, 112601, 3848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私を応援してくれる\n一番大事な人が\n隣にいた気がする…", 0, 102, 0, 1, 8, 1, 112601, 3849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なになにー？\nミオちゃんに\n何か用かな～？", 0, 1, 0, 2, 1, 1, 112601, 3850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっ、やっほー！\n元気そうだね～、キミ\n私？\nもちろん元気～！", 0, 2, 0, 2, 1, 1, 112601, 3851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇねぇ、ちょっと\n遊びに行かない？\nたまには息抜きで！", 0, 3, 0, 2, 1, 1, 112601, 3852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、この魔物料理さ\nプリンって言い張れば\n食べてもらえそうかな", 0, 4, 0, 2, 1, 1, 112601, 3853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ\nいつもありがとねっ！\nパワーもらってるよ～", 0, 101, 0, 2, 4, 1, 112601, 3854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたどうした～\nミオちゃんの魅力に\nメロメロなのかい？", 0, 102, 0, 2, 8, 1, 112601, 3855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっはよ～！\n一日の始まりだし\nテンション上げてこ！", 0, 1, 1, 2, 1, 1, 112601, 3856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いた～…\nねぇねぇ、一緒に\nお昼食べようよ～", 0, 2, 2, 2, 1, 1, 112601, 3857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ～…\n眠くなってきちゃった\nそろそろ休もっかなぁ", 0, 3, 3, 2, 1, 1, 112601, 3858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、ふっかふか～！\nレッスンの疲れも\n吹っ飛んじゃうね☆", 0, 2, 0, 3, 1, 1, 112601, 3860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何これ…かわいーっ！\n早くしまむーに\n教えてあげなきゃ！", 0, 3, 0, 3, 1, 1, 112601, 3861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すぅ～…\nうんっ、これ私の\n好きな香りだな～♪", 0, 4, 0, 3, 1, 1, 112601, 3862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポッカポカだね～♪\n…あ～ん、ここから\n動きたくないーっ！", 0, 5, 0, 3, 1, 1, 112601, 3863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、おーいしー！\nこれはテンション\n上がっちゃうね♪", 0, 7, 0, 3, 1, 1, 112601, 3865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nふむふむふむ…！\n勉強になった、ブイ☆", 0, 8, 0, 3, 1, 1, 112601, 3866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんでドキドキが\n止まらないの…？\n騎士くんのせいだー！", 0, 103, 0, 1, 12, 1, 100101, 3868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドキドキしてるの\nあたしだけ、かな…\n騎士くんはどう…？", 0, 103, 0, 2, 12, 1, 100101, 3869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの前で\n好きって言えるように\n練習しないと…", 0, 103, 0, 1, 12, 1, 100201, 3870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン…大好き\n…き、騎士クン！？\nなんでここに！？", 0, 103, 0, 2, 12, 1, 100201, 3871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困ったな…\n彼が居ないだけで、\nここまで\n寂しいと思うなんて…", 0, 103, 0, 1, 12, 1, 100301, 3872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えっと…\n今日は訓練じゃなくて\nその…二人でゆっくり\n過ごしたいな…", 0, 103, 0, 2, 12, 1, 100301, 3873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルの心構え…\nどういう風に考えると\nしっくりくるのかな", 0, 1, 0, 1, 1, 1, 112501, 3874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か始めるのって\nドキドキするよね\nだから最近楽しいんだ", 0, 2, 0, 1, 1, 1, 112501, 3875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険者の時って毎日\nバタバタしてたけど…\n目標ができると違うね", 0, 3, 0, 1, 1, 1, 112501, 3876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少しお腹が空いた…\nチョコレート一粒だけ\n食べようかな", 0, 4, 0, 1, 1, 1, 112501, 3877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウヅキもミオも\n頑張ってるし\n私も負けられないね", 0, 5, 0, 1, 1, 1, 112501, 3878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンしてる時さ\n何か、誰かが足りない\nそう思うことがあるの", 0, 101, 0, 1, 4, 1, 112501, 3879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大事なのは笑顔…\n誰か、大切な人から\n言われた気がするんだ", 0, 102, 0, 1, 8, 1, 112501, 3880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの、何か用？\n手伝えることがあれば\nすぐに言ってね", 0, 1, 0, 2, 1, 1, 112501, 3881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("姿勢がいい？\n普段から鍛えてるし\n自然とそうなるのかも", 0, 2, 0, 2, 1, 1, 112501, 3882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっき散歩してたら\n犬を見かけたんだ\n人懐っこい子だったよ", 0, 3, 0, 2, 1, 1, 112501, 3883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今から冒険？\nなら私も一緒に行くよ\n前衛は任せておいて", 0, 4, 0, 2, 1, 1, 112501, 3884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今からレッスンに\n行くつもりだったんだ\n少し手伝ってくれる？", 0, 101, 0, 2, 4, 1, 112501, 3885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("蒼の剣を受けよ！\nえ、何してるのって？\nただの発声練習だけど", 0, 102, 0, 2, 8, 1, 112501, 3886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう、早いね\n今日は依頼もないし\nゆっくりしようかな", 0, 1, 1, 2, 1, 1, 112501, 3887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろお昼だね\nうーん、今日は\n何を食べよう…", 0, 2, 2, 2, 1, 1, 112501, 3888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\n明日も早いし\nそろそろ寝なくちゃ", 0, 3, 3, 2, 1, 1, 112501, 3889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンで疲れたし\nちょっとだけ\n休んでおこうかな", 0, 2, 0, 3, 1, 1, 112501, 3891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、かわいい\nふわふわしたものって\n撫でたくなるんだよね", 0, 3, 0, 3, 1, 1, 112501, 3892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん、いい香り…\nこういうものがあると\n落ち着くからいいよね", 0, 4, 0, 3, 1, 1, 112501, 3893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かい場所って\n居心地がいいから\nのんびりしちゃうよ", 0, 5, 0, 3, 1, 1, 112501, 3894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスン頑張ったら\nすぐお腹が空くし\n食べておかないと…！", 0, 7, 0, 3, 1, 1, 112501, 3896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルのことを\nもっと勉強して\n成長しなくちゃ", 0, 8, 0, 3, 1, 1, 112501, 3897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、知りたい…\nなんでもかんでも\nとにかく知りたい…", 0, 1, 0, 1, 1, 1, 111001, 3899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、眠い…\nいつでもどこでも\nとにかく眠い…", 0, 2, 0, 1, 1, 1, 111001, 3900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君、気を付けたまえ\nぼーっと歩いていると\nほわっ！　転んだ…", 0, 3, 0, 1, 1, 1, 111001, 3901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミツキ師にいただいた\n新作サプリ…丁度よい\n被験体はいないものか", 0, 4, 0, 1, 1, 1, 111001, 3902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サレンディア救護院に\nユニちゃん８歳として\n潜入済みだが何か？", 0, 5, 0, 1, 1, 1, 111001, 3903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君がユニちゃんズの\n同志であること、\nぼくは誇りに思うぞ", 0, 101, 0, 1, 4, 1, 111001, 3904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼくは青春がしたい\nおい、君\nぼくと青春しないか", 0, 102, 0, 1, 8, 1, 111001, 3905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、そうだな。\nぼくもそう思う。\n……えっ、何が？", 0, 1, 0, 2, 1, 1, 111001, 3906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("待て、話しかけるな。\n今の閃きをメモに…\n…ああっ、忘れた！", 0, 2, 0, 2, 1, 1, 111001, 3907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歩き方が綺麗？\n何を今更なこと\n言っとるんだ君は", 0, 3, 0, 2, 1, 1, 111001, 3908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼくの血液型？\n大らかのОだ。\n何か異論あるかね", 0, 4, 0, 2, 1, 1, 111001, 3909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君の声は精神に\n高揚をもたらすな…\n波形を分析したいぞ", 0, 101, 0, 2, 4, 1, 111001, 3910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妙だな…最近\n君に話しかけられると\n心拍に乱れを覚える", 0, 102, 0, 2, 8, 1, 111001, 3911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと、朝だな。\nそろそろ寝るか、\n朝更かしは体に悪い", 0, 1, 1, 2, 1, 1, 111001, 3912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、昼餉時か…\n今日のランチは\nサプリ定食にしよう", 0, 2, 2, 2, 1, 1, 111001, 3913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう夜だな、\nそろそろ起きるか。\n最高の一日にするぞ！", 0, 3, 3, 2, 1, 1, 111001, 3914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほわぁ～\n副交感神経が…\n優位に…ふふっひ", 0, 2, 0, 3, 1, 1, 111001, 3916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいすぎるな…\nセクシーユニには\nミスマッチか…", 0, 3, 0, 3, 1, 1, 111001, 3917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほぁあアあァぁー…\nいい香りー…\nあアァあ…イイ…", 0, 4, 0, 3, 1, 1, 111001, 3918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("炎はいいぞ\nそこには人類発展の\nドラマがある", 0, 5, 0, 3, 1, 1, 111001, 3919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フオオー！\n次から次へと固形食物\n原理気になるー！", 0, 7, 0, 3, 1, 1, 111001, 3921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良書は時間を忘れる\n…ふむ、今度\n布団を持ってこよう", 0, 8, 0, 3, 1, 1, 111001, 3922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きらーん☆\nハツネちゃんに\n不可能はないのだ☆", 0, 103, 0, 1, 12, 1, 101201, 3924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒だと\n寝ちゃうのが\nもったいないよ～", 0, 103, 0, 2, 12, 1, 101201, 3925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちぇるーん☆", 0, 1, 0, 2, 1, 1, 192101, 3933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちぇる～ん☆\n今日もチエルは\nかわいいですよね～？", 0, 1, 0, 1, 1, 1, 110901, 3951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこかに楽しいもの\n落ちてないかにゃー", 0, 2, 0, 1, 1, 1, 110901, 3952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チエルのオキニは\n甘々カフェラテ！\nシクヨロでぇ～す☆", 0, 3, 0, 1, 1, 1, 110901, 3953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩、ひまですよね？\nチエル遊んであげても\nいいですけど？", 0, 4, 0, 1, 1, 1, 110901, 3954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁー…しゅき…\nカルミナ尊い…\n一生すこれる…", 0, 5, 0, 1, 1, 1, 110901, 3955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩、ひまー\nちょっとは構えよーう\nデュクシ！デュクシ！", 0, 101, 0, 1, 4, 1, 110901, 3956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩なんか\nおごって～！\nてか…おごらなくても\nいいから遊んでよ…", 0, 102, 0, 1, 8, 1, 110901, 3957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、なんですか？\n告白だったら\n間に合ってますけど", 0, 1, 0, 2, 1, 1, 110901, 3958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと静かに！\n今ヤバかわポーズの\nイメトレ中なんです！", 0, 2, 0, 2, 1, 1, 110901, 3959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("足取りが軽やか？\nあー…ダンスとか\n習ってるからですかね", 0, 3, 0, 2, 1, 1, 110901, 3960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チエルの血液型？\n大型新人のОです\n何か問題でも？", 0, 4, 0, 2, 1, 1, 110901, 3961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩って何気に\nいい声してますよね\n言うことは変だけど", 0, 101, 0, 2, 4, 1, 110901, 3962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、なんですか？\nたまにだったら\n告白してもいいですよ", 0, 102, 0, 2, 8, 1, 110901, 3963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはちぇる～ん☆\nハイ、ご一緒に～？", 0, 1, 1, 2, 1, 1, 110901, 3964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のランチは\nどこで\n映えよっかにゃー", 0, 2, 2, 2, 1, 1, 110901, 3965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんばんちぇるるん☆\nハイ、ご一緒に～？", 0, 3, 3, 2, 1, 1, 110901, 3966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかチエルン\n略して、ふかルン♪", 0, 2, 0, 3, 1, 1, 110901, 3968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいこの子と\nかわいいチエル！\n映ぁ～え～る～！", 0, 3, 0, 3, 1, 1, 110901, 3969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい香り～！\n持って帰ろっと！\nすぅーっ…", 0, 4, 0, 3, 1, 1, 110901, 3970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マシュマロは\n焼かない方のが\nかわいくないです？", 0, 5, 0, 3, 1, 1, 110901, 3971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チエル食べても\n太らない体質\nなんでぇ～！", 0, 7, 0, 3, 1, 1, 110901, 3973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("読書は好きですよ\nシンプルに楽しいし\nギャップ萌えでしょ？", 0, 8, 0, 3, 1, 1, 110901, 3974);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなのあたしを\n見る目が違うね\nま、気にしないけどね", 0, 1, 0, 1, 1, 1, 112701, 3976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も疲れた～\nやる気ゼロだし\nもう寝ちゃおうかな", 0, 2, 0, 1, 1, 1, 112701, 3977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの代わりに誰か\n働いてくれないかね", 0, 3, 0, 1, 1, 1, 112701, 3978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("労働の後に食べる\nあんパン最高～", 0, 4, 0, 1, 1, 1, 112701, 3979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事の合間に\nちょっと一息いれよ\nあ～ドングリ美味し～", 0, 5, 0, 1, 1, 1, 112701, 3980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("報酬も入ったことだし\nあいつに何か\n買ってあげようかな", 0, 101, 0, 1, 4, 1, 112701, 3981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の休みはあいつと\n一日中だらだら\nしたいな～", 0, 102, 0, 1, 8, 1, 112701, 3982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしは褒められて\n伸びるタイプなんだ\nだから褒めて褒めて", 0, 1, 0, 2, 1, 1, 112701, 3983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、差し入れ？\n気が利くねぇ\nあんがと", 0, 2, 0, 2, 1, 1, 112701, 3984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい依頼？\n今日はもう無理～\n閉店で～す", 0, 3, 0, 2, 1, 1, 112701, 3985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サ、サボってないよ！\nちょっと休憩してた\nだけだから！", 0, 4, 0, 2, 1, 1, 112701, 3986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、一緒に\nサボろうよ？\n働き過ぎはよくないよ", 0, 101, 0, 2, 4, 1, 112701, 3987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが近くにいると\n仕事の疲れも\n和らぐんだよね～", 0, 102, 0, 2, 8, 1, 112701, 3988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…もう起きなきゃ\nつらい労働の\nはじまりだ～", 0, 1, 1, 2, 1, 1, 112701, 3989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ、お昼に\nあんパン食べ過ぎた…\n苦しい…眠い…", 0, 2, 2, 2, 1, 1, 112701, 3990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日は仕事ないし\nガッツリ夜ふかし\nしちゃうよ～", 0, 3, 3, 2, 1, 1, 112701, 3991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫みたいに\n丸くなっちゃうよ～\nあたしリスだけどね", 0, 2, 0, 3, 1, 1, 112701, 3993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか～\nあたしの尻尾と\n互角とはやるね～", 0, 3, 0, 3, 1, 1, 112701, 3994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんパンの香りの\nアロマとか\nあればいいのにな～", 0, 4, 0, 3, 1, 1, 112701, 3995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは危険な\nあたたかさだね～\n労働意欲が\nなくなるよ～", 0, 5, 0, 3, 1, 1, 112701, 3996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい働いたから\nいっぱい食べても\nカロリー０だよ", 0, 7, 0, 3, 1, 1, 112701, 3998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしだってたまには\n本くらい読むって\n全然似合わないけどね", 0, 8, 0, 3, 1, 1, 112701, 3999);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの作った\nオリジナルたい焼き…\nあいつ、\n喜んでくれるかにゃ？", 0, 103, 0, 1, 12, 1, 104601, 4001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、お帰りにゃー♪\nえへへ…キミに\nお帰りって言えるのが\nなんかうれしいにゃ♪", 0, 103, 0, 2, 12, 1, 104601, 4002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フロンティア\nスピリッツを\nお見せするべ！", 0, 1, 0, 1, 1, 1, 112801, 4003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この鎧を着ると\n気が引き締まる\n感じがするべ", 0, 2, 0, 1, 1, 1, 112801, 4004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("搾りたての牛乳飲んで\n今日も一日\nがんばるべ！", 0, 3, 0, 1, 1, 1, 112801, 4005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなに牧場の\n乳製品を\n味わってもらいてぇべ", 0, 4, 0, 1, 1, 1, 112801, 4006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここはいいとこだべ\nうちの動物たちも\n連れてきてやりてぇな", 0, 5, 0, 1, 1, 1, 112801, 4007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなオラより\n若ぇのに働いてて\n立派だべな", 0, 101, 0, 1, 4, 1, 112801, 4008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場もギルドの\nみんなもオラが\nまとめて面倒見るべ！", 0, 102, 0, 1, 8, 1, 112801, 4009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、今日も\n忙しくなるべよ\n気合入れてくべ！", 0, 1, 0, 2, 1, 1, 112801, 4010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、あんちゃん\n丁度いいとこに！\n一緒に街に\n行商しに行くべ！", 0, 2, 0, 2, 1, 1, 112801, 4011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場仕事で培った力が\n戦いでも役立つなら\n一石二鳥だべさ！", 0, 3, 0, 2, 1, 1, 112801, 4012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("疲れた時は牧場産の\nミルク菓子で\n糖分補給だべ", 0, 4, 0, 2, 1, 1, 112801, 4013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、牧場の\n新製品だべ\n一番最初に味見\nしてほしいべさ", 0, 101, 0, 2, 4, 1, 112801, 4014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("働きづめはよくねぇベ\n膝枕してやっから\nこっち来るべさ", 0, 102, 0, 2, 8, 1, 112801, 4015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁあ…\n酪農家の朝は\n早ぇんだべ…", 0, 1, 1, 2, 1, 1, 112801, 4016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごはんの時間だべ！\n腹が減っては酪農も\n戦いもできねえべ！", 0, 2, 2, 2, 1, 1, 112801, 4017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝るべ！\n健全なお笑いは\n健全な肉体に宿るべ！", 0, 3, 3, 2, 1, 1, 112801, 4018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧草みたいに\nふっかふかだべ～", 0, 2, 0, 3, 1, 1, 112801, 4020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子、目の感じが\nエリザベスに似てるべ", 0, 3, 0, 3, 1, 1, 112801, 4021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂いだべ～\n疲れた体に\nしみるべな～", 0, 4, 0, 3, 1, 1, 112801, 4022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったけぇな～\n牧場にも\n置いてみっかな～", 0, 5, 0, 3, 1, 1, 112801, 4023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うまいべ！\n生産者のこだわりを\n感じるべさ", 0, 7, 0, 3, 1, 1, 112801, 4025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("酪農も戦いも\nまずは知識だべ！", 0, 8, 0, 3, 1, 1, 112801, 4026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴょん、ぴょん♪\nこの服のおかげで、\n体が軽いなぁ…♪", 0, 1, 0, 1, 1, 1, 113001, 4028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今の内に部屋の\n掃除をしておこっと…\nみんな喜んで\nくれるといいなぁ", 0, 2, 0, 1, 1, 1, 113001, 4029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("耳と尻尾…この服、\n本当にウサギさん\nみたいだなぁ", 0, 3, 0, 1, 1, 1, 113001, 4030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか先輩の\n気配がするような…\n気のせいかな？", 0, 4, 0, 1, 1, 1, 113001, 4031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウサギさんの真似を\nしたら、存在感が薄い\nとか言われないかな？\nア、アユミだぴょん♪", 0, 5, 0, 1, 1, 1, 113001, 4032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…\nいつもとは違う先輩が\nたくさん見られて、\nうれしいな♪", 0, 101, 0, 1, 4, 1, 113001, 4033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本の中の世界で先輩と\n旅をするなんて…\n幸せすぎて、罰が\n当たりそうだよぉ…", 0, 102, 0, 1, 8, 1, 113001, 4034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じ～…はっ！？\nす、すみません！\n話しかけてもらえる\nなんて思ってなくて！", 0, 1, 0, 2, 1, 1, 113001, 4035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩がすぐそばに…\nし、幸せすぎて\n倒れそうですぅ！", 0, 2, 0, 2, 1, 1, 113001, 4036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、えっと…あの…！\nうう…いざ先輩と\n向き合うと\n緊張しちゃうよぉ…", 0, 3, 0, 2, 1, 1, 113001, 4037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はうっ！？\nしょ、正面から見る\n先輩は、私にとって\n神々しすぎますぅ…！", 0, 4, 0, 2, 1, 1, 113001, 4038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩…その…\nい、一緒にご飯でも\nどうでひゅか！\nうう…またかんだぁ…", 0, 101, 0, 2, 4, 1, 113001, 4039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩…\nハーブティーを\n入れたんですが、\n一緒にどうですか…？", 0, 102, 0, 2, 8, 1, 113001, 4040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩！\nおはようございます！\nえへへ、練習通りに\nバッチリ言えたぁ♪", 0, 1, 1, 2, 1, 1, 113001, 4041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、もうお昼ですね\n時計を持ってて\n良かったです", 0, 2, 2, 2, 1, 1, 113001, 4042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\nお休みする\n準備をしちゃいますね", 0, 3, 3, 2, 1, 1, 113001, 4043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ…ちょっとだけ\n先輩の匂いがする…\nえへへ、幸せだなぁ♪", 0, 2, 0, 3, 1, 1, 113001, 4045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…私もウサギさんの\nぬいぐるみとして、\n先輩のそばに…はっ！\n私ったら何を…！", 0, 3, 0, 3, 1, 1, 113001, 4046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、いい香り…\n先輩もこういうのが\n好きなのかな？", 0, 4, 0, 3, 1, 1, 113001, 4047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩が隣に\n居たら、もっと\n暖かいのになぁ…♪", 0, 5, 0, 3, 1, 1, 113001, 4048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい…でも、\n先輩と一緒に\n食べたら、もっと\nおいしいだろうな…", 0, 7, 0, 3, 1, 1, 113001, 4050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウサギさんって、穴を\n掘ったりするんだ…\n私も、隠れたいときに\n掘ってみようかな？", 0, 8, 0, 3, 1, 1, 113001, 4051);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネビアさまのように\n普段からパタパタと\n飛んでみるのも…", 0, 1, 0, 1, 1, 1, 180501, 4053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご立派になられた\n主さまと並べるように\nもっと精進しなくては", 0, 2, 0, 1, 1, 1, 180501, 4054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("月々の食費が\n増えてしまいました\n申し訳ございません…", 0, 3, 0, 1, 1, 1, 180501, 4055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワンワンのほうの\n主さまは、この姿に\n驚くでしょうか…？", 0, 4, 0, 1, 1, 1, 180501, 4056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまと離れていても\n主さまとの絆は\n胸に感じております…", 0, 5, 0, 1, 1, 1, 180501, 4057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスは\nみなさまの帰る場所…\nわたくしが守ります", 0, 101, 0, 1, 4, 1, 180501, 4058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんな未来が\n待ち受けようとも\n主さまと添い遂げます", 0, 102, 0, 1, 8, 1, 180501, 4059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おでかけですか？\nではわたくしも\nお供いたします", 0, 1, 0, 2, 1, 1, 180501, 4060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう二度と主さまと\n離れたくはありません\nいつ何時も…", 0, 2, 0, 2, 1, 1, 180501, 4061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにかお困りごと\nでございますか？\nわたくしに何なりと…", 0, 3, 0, 2, 1, 1, 180501, 4062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうぞゆっくりと\n心ゆくまでくつろいで\nくださいまし、主さま", 0, 4, 0, 2, 1, 1, 180501, 4063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この羽で主さまを\nどこまでも遠く…\n高くへと導きます", 0, 101, 0, 2, 4, 1, 180501, 4064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、主さま…♪\nおそばにいられるのが\nうれしくて、つい…", 0, 102, 0, 2, 8, 1, 180501, 4065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日も一日、主さまの\nサポートをいたします", 0, 1, 1, 2, 1, 1, 180501, 4066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も頑張っている\n主さまに、スタンプを\nもう一つ…ポン！", 0, 2, 2, 2, 1, 1, 180501, 4067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝付けないのでしたら\nわたくしが子守唄を\n歌ってさしあげます", 0, 3, 3, 2, 1, 1, 180501, 4068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか…\nまるで主さまのような\n柔らかさでございます", 0, 2, 0, 3, 1, 1, 180501, 4070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたも一緒に\n主さまと遊びますか？\n至福の時間ですよ♪", 0, 3, 0, 3, 1, 1, 180501, 4071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまの優しくて\nくすぐったい匂いが\nたまらなく恋しいです", 0, 4, 0, 3, 1, 1, 180501, 4072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまの心と\n繋がったときのような\n温もりを感じます", 0, 5, 0, 3, 1, 1, 180501, 4073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いけませんっ…！\n元の姿に戻ると、また\n食べてしまうのに…！", 0, 7, 0, 3, 1, 1, 180501, 4075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまに読み聞かせる\n絵本は…妖精が主役の\n物語にいたしましょう", 0, 8, 0, 3, 1, 1, 180501, 4076);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…彼のこと弟みたいに\n思ってきたのに…私、\nどうしたらいいの…？", 0, 103, 0, 1, 12, 1, 104801, 4078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よ、予定がなかったら\nでいいんだけど…\nその、ふ、二人で\n訓練とか…どうかな？", 0, 103, 0, 2, 12, 1, 104801, 4079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おめかしもしたし\nあとはお兄ちゃんを\n待つだけですね～♪", 0, 1, 0, 1, 1, 1, 112901, 4080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんの身の回り\nをお片付け～、これぞ\nデキる妹アピール！", 0, 2, 0, 1, 1, 1, 112901, 4081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、衣装がほつれてる\nこれくらいなら自分で\n繕えますね…！", 0, 3, 0, 1, 1, 1, 112901, 4082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好で歩いてると\n見慣れた景色も\n違うものに見えますね", 0, 4, 0, 1, 1, 1, 112901, 4083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("勉強もちゃんとします\n…でも、一人だと\n集中力がもちません～", 0, 5, 0, 1, 1, 1, 112901, 4084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんを大好きな\n妹が待ってますよ～\n…まだですかね～", 0, 101, 0, 1, 4, 1, 112901, 4085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんのために\n掃除洗濯をする私って\nお嫁さんみたい…\n…えへへ～", 0, 102, 0, 1, 8, 1, 112901, 4086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おに～いちゃん！\n縫い物、一緒に\nやりましょうよ！", 0, 1, 0, 2, 1, 1, 112901, 4087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい妹を\n愛でたくなりました？\n思う存分、どうぞ♪", 0, 2, 0, 2, 1, 1, 112901, 4088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、ビックリした～\nもう、お兄ちゃんてば\nイタズラっ子ですね～", 0, 3, 0, 2, 1, 1, 112901, 4089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にお買い物\n行きませんか？\n妹とデートですよっ♪", 0, 4, 0, 2, 1, 1, 112901, 4090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん…頭を\n撫でてくれませんか？\nえへへ、これが一番♪", 0, 101, 0, 2, 4, 1, 112901, 4091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん大好き♪\n何度でも言いますよ！\nお兄ちゃん大好きっ♪", 0, 102, 0, 2, 8, 1, 112901, 4092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ～お兄ちゃん！\n妹モーニングコールの\n時間ですよっ♪", 0, 1, 1, 2, 1, 1, 112901, 4093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ休憩ですね！\n甘いお菓子で\n元気回復しましょ～！", 0, 2, 2, 2, 1, 1, 112901, 4094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かし厳禁！\nでも、もう少しだけ\nお話ししたいなぁ～", 0, 3, 3, 2, 1, 1, 112901, 4095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっかふかですよ！\nお兄ちゃんと一緒に\n座りたいなぁ…♪", 0, 2, 0, 3, 1, 1, 112901, 4097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このぬいぐるみの\nかわいさ…う～ん\n負けられません…！", 0, 3, 0, 3, 1, 1, 112901, 4098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りにも気をつかって\nパーフェクトな妹に\nなっちゃいますから！", 0, 4, 0, 3, 1, 1, 112901, 4099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～ぬくぬくです～\nお兄ちゃんと一緒に\n温まりたいなぁ…♪", 0, 5, 0, 3, 1, 1, 112901, 4100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは止まりませんね\nもぐもぐ…いくらでも\n食べられちゃいます", 0, 7, 0, 3, 1, 1, 112901, 4102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、デザインの\n参考になりそう！\n私にも作れるかなぁ", 0, 8, 0, 3, 1, 1, 112901, 4103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈です…\nなにか楽しいことは\nないですか？", 0, 1, 0, 1, 1, 1, 106601, 4105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギャングの仕事は\n今日はお休みです\nのんびりするですよ", 0, 2, 0, 1, 1, 1, 106601, 4106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひうっ！　あたしの\n尻尾なんて食べても\nおいしくないですよ？", 0, 3, 0, 1, 1, 1, 106601, 4107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう…どうやら\n例の件はまだボスに\nバレてないですね…", 0, 4, 0, 1, 1, 1, 106601, 4108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("下克上…いい言葉です\nって、ボスに聞かれて\nないですよね…？", 0, 5, 0, 1, 1, 1, 106601, 4109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか絶対ビッグに\nなってやるです！\nあたしを信じるです！", 0, 101, 0, 1, 4, 1, 106601, 4110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしが覚醒したら\nきっと誰よりも\n強くなるはずです！", 0, 102, 0, 1, 8, 1, 106601, 4111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんですか？\n貢ぎ物なら\nいつでも歓迎ですよ！", 0, 1, 0, 2, 1, 1, 106601, 4112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしだって\nやる時はやるですよ！\nその時がこないだけ！", 0, 2, 0, 2, 1, 1, 106601, 4113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しりとり勝負ですか？\nいい度胸ですね、\nかかってくるです！", 0, 3, 0, 2, 1, 1, 106601, 4114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんは\nヒマそうですね…\nうらやましいです", 0, 4, 0, 2, 1, 1, 106601, 4115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かまってほしいです？\nまったく…いいですよ\nしょうがないですね", 0, 101, 0, 2, 4, 1, 106601, 4116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんのことは\nこのあたしが\n守ってやるですよ！", 0, 102, 0, 2, 8, 1, 106601, 4117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("デキるギャングの\n朝は早いのです…\nふぁあ…", 0, 1, 1, 2, 1, 1, 106601, 4118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹がすいたですね\nなにか食べにいくです\nお兄さんのおごりで！", 0, 2, 2, 2, 1, 1, 106601, 4119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁあ…むにゅう…\nまだ起きてるですよぉ", 0, 3, 3, 2, 1, 1, 106601, 4120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～…\nもうここから一歩も\n動きたくないです", 0, 2, 0, 3, 1, 1, 106601, 4122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなかいいモフりを\nしてやがるです…\n舎弟にしてやるですよ", 0, 3, 0, 3, 1, 1, 106601, 4123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんかおしゃれな\n匂いがするですね…", 0, 4, 0, 3, 1, 1, 106601, 4124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふーん！\nあたしのブレスの方が\n火力は上ですね！", 0, 5, 0, 3, 1, 1, 106601, 4125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしに貢ぎ物とは\nよく分かってるですね\n食べてやるですよ", 0, 7, 0, 3, 1, 1, 106601, 4127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふーむ…\nもっと楽しい本は\nないですかね？", 0, 8, 0, 3, 1, 1, 106601, 4128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に眠る秘宝…\n心躍る響きだ！\n早く見つけたい…！", 0, 1, 0, 1, 1, 1, 113201, 4130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう～、暑いぃ…\nかき氷を食べて\nすっきりしたいぃ…", 0, 2, 0, 1, 1, 1, 113201, 4131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アターック！\nいや、もっとこう…\nアタァーック！", 0, 3, 0, 1, 1, 1, 113201, 4132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スイカ割りで\n目を回さない\nコツはなんだろうか…", 0, 4, 0, 1, 1, 1, 113201, 4133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかく海に来たのだ\n泳ぎも上手に\nなりたいものだな", 0, 5, 0, 1, 1, 1, 113201, 4134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっふっふ…\n疼く…疼くぞ！\n日焼けの痕が…", 0, 101, 0, 1, 4, 1, 113201, 4135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルドと私は\n来世でも共にある…\nつまり我らはずっと…\nはわわ…！", 0, 102, 0, 1, 8, 1, 113201, 4136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルド、私と共に\n日光浴に行かないか？\n光の力を集めよう！", 0, 1, 0, 2, 1, 1, 113201, 4137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好だからできる\n必殺技を考えている\n何か案はないか？", 0, 2, 0, 2, 1, 1, 113201, 4138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルド～！\nスイカを貰ったから\n一緒に食べよう！", 0, 3, 0, 2, 1, 1, 113201, 4139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こう日差しが強いと\n日焼けしそうだな\n跡になってないか…？", 0, 4, 0, 2, 1, 1, 113201, 4140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("我らの夏の黙示録\nしっかりと記録\nしておかねばな", 0, 101, 0, 2, 4, 1, 113201, 4141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんと日焼けどめを\n塗ってもらうべき\nだったかな…？\nシ、シグルドに…！", 0, 102, 0, 2, 8, 1, 113201, 4142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝だぞシグルド！\nさぁ、日光を浴びて\n光の加護を得るのだ！", 0, 1, 1, 2, 1, 1, 113201, 4143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう昼食の時間か…\n私の魔力も減ったし\n早く補給しなければ", 0, 2, 2, 2, 1, 1, 113201, 4144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜でも我らの活動は\n終わることはない！\nさぁ準備を…ふわぁ…", 0, 3, 3, 2, 1, 1, 113201, 4145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で遊んでいると\n疲れてしまうからな\n少し休まるとしよう", 0, 2, 0, 3, 1, 1, 113201, 4147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ～、君の名前は\n何にしまちょうかね♪\n…はっ、見たのか！？", 0, 3, 0, 3, 1, 1, 113201, 4148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心地よい香りで\n我が精神も安らぐ…", 0, 4, 0, 3, 1, 1, 113201, 4149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("別に寒くなどないぞ！\n寒くないが、ちょっと\n暖まりたくなってな！", 0, 5, 0, 3, 1, 1, 113201, 4150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐ…食べ過ぎた分は\n魔力に変換されるのだ\n…たぶん", 0, 7, 0, 3, 1, 1, 113201, 4152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…なな、なんだ！？\nシグルドはこういう\n趣味なのか…！？", 0, 8, 0, 3, 1, 1, 113201, 4153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむ、この乗り心地…\nいざゆかん、\nシードラゴンよ！", 0, 10, 0, 3, 1, 1, 113201, 4155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("疾風の冥姫の名に\nふさわしき\n深海の玉座よ…\nふああ…柔らかい～", 0, 11, 0, 3, 1, 1, 113201, 4156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿でいると\nわたしもお姫様に\nなれた気がする…♪", 0, 1, 0, 1, 1, 1, 180201, 4157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いてきちゃった\nまずは買い出しに…\n…変身解かなくちゃ！", 0, 2, 0, 1, 1, 1, 180201, 4158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("胸のところが空いてて\nスースーするの\nまだ慣れないな…", 0, 3, 0, 1, 1, 1, 180201, 4159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("治癒魔法に使ってた\n魔力を攻撃魔法に…\n頭の中でも練習練習", 0, 4, 0, 1, 1, 1, 180201, 4160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何もできなかった\nわたしから、少しは\n変われたのかな…？", 0, 5, 0, 1, 1, 1, 180201, 4161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン…\n今どこにいるの…？\n…会いたいな", 0, 101, 0, 1, 4, 1, 180201, 4162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("離れてても分かるよ…\n温かい力で騎士クンに\n守られてるの", 0, 102, 0, 1, 8, 1, 180201, 4163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしが戦えてるのは\n騎士クンのおかげだよ\nいつもありがとう！", 0, 1, 0, 2, 1, 1, 180201, 4164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いてそう…？\n…内緒で作ったおやつ\n騎士クンも食べる？", 0, 2, 0, 2, 1, 1, 180201, 4165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃうっ！　え！？\nせ、背中はダメ～！\n言ってから触って～！", 0, 3, 0, 2, 1, 1, 180201, 4166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好、どうかな？\nえ？　似合ってる…？\n本当？　…うれしい！", 0, 4, 0, 2, 1, 1, 180201, 4167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい？　そうだね\nひらひらが…わたし？\nええっ、そ、そんな！", 0, 101, 0, 2, 4, 1, 180201, 4168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン、これからも\nずっと…わたしの\nそばにいてください", 0, 102, 0, 2, 8, 1, 180201, 4169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝からこんなに\n食べる日が来るなんて\n思ってなかったよ…", 0, 1, 1, 2, 1, 1, 180201, 4170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼を作らなくちゃ\n騎士クン、一緒に\nお料理してみる？", 0, 2, 2, 2, 1, 1, 180201, 4171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン、もう眠い？\n眠るまで、わたしが\nずっとそばにいるね", 0, 3, 3, 2, 1, 1, 180201, 4172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("攻撃参加するからこそ\n適度に体を休めるのは\n大切だよね！", 0, 2, 0, 3, 1, 1, 180201, 4174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい…騎士クンと\nシェフィちゃんにも\nプレゼントしたいな", 0, 3, 0, 3, 1, 1, 180201, 4175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～…\nあれ？　お腹が空いて\nきちゃった…！？", 0, 4, 0, 3, 1, 1, 180201, 4176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かい…\n騎士クンがくれる\n力みたい…", 0, 5, 0, 3, 1, 1, 180201, 4177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぱくっ、\nあむ、はむっ…\nううぅ～…やっぱり\n手が止まらないよぉ～", 0, 7, 0, 3, 1, 1, 180201, 4179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しく覚えたいな…\nみんなで食べられる\n大皿向けの料理♪", 0, 8, 0, 3, 1, 1, 180201, 4180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんの愛\nこのままじゃ\nあふれちゃうよ…♪", 0, 103, 0, 1, 12, 1, 104901, 4182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くん♪\n弟くんっ♪\nおっとうっとくんっ♪", 0, 103, 0, 2, 12, 1, 104901, 4183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐのもいいけど\n今日は砂浜で\nのんびりしようかね", 0, 1, 0, 1, 1, 1, 113101, 4184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さてと\nちょっくらひと泳ぎ\n行ってくるかね", 0, 2, 0, 1, 1, 1, 113101, 4185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっついねぇ…\nうちわがないと\nしんどいったらないよ", 0, 3, 0, 1, 1, 1, 113101, 4186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷たすぎる飲み物で\n体を冷やさないよう\n気をつけないと…", 0, 4, 0, 1, 1, 1, 113101, 4187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏はあっという間だし\n悔いがないように\n楽しまないとね", 0, 5, 0, 1, 1, 1, 113101, 4188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きっとこの夏は\nアタシにとって大事な\n想い出になるね…", 0, 101, 0, 1, 4, 1, 113101, 4189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…前に比べたら\nアタシたちの距離も\n近づいたみたいだね", 0, 102, 0, 1, 8, 1, 113101, 4190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし暇なら\n今日も笹舟釣り\n一緒にどうだい？", 0, 1, 0, 2, 1, 1, 113101, 4191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お前さん、釣りに\n興味が湧いたなら今度\n道具を見に行こうよ", 0, 2, 0, 2, 1, 1, 113101, 4192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今から砂浜に行くんだ\nお前さんも一緒に\n散歩するかい？", 0, 3, 0, 2, 1, 1, 113101, 4193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、日焼け跡？\nおや…本当だ\nすぐ焼けちまうねえ", 0, 4, 0, 2, 1, 1, 113101, 4194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっ！？\nちょっと！\n日焼け跡をいきなり\n触らないでおくれ！", 0, 101, 0, 2, 4, 1, 113101, 4195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お前さんは、その…\nアタシと一緒にいて\n楽しかったかい？", 0, 102, 0, 2, 8, 1, 113101, 4196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようさん\n今日も砂浜に行って\nゆっくりしようか", 0, 1, 1, 2, 1, 1, 113101, 4197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼か…\nそうだ、よかったら\n刺身定食、作ろうか？", 0, 2, 2, 2, 1, 1, 113101, 4198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の空を見てるとさ\nなつかしい気持ちに\nなるんだよね", 0, 3, 3, 2, 1, 1, 113101, 4199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適度に休憩して\n夏バテしないよう\n気をつけないとね", 0, 2, 0, 3, 1, 1, 113101, 4201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたたちも\n海を楽しみたいって\n思っているのかね", 0, 3, 0, 3, 1, 1, 113101, 4202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～…香りでも\nバカンスらしさを\n楽しめるもんだね", 0, 4, 0, 3, 1, 1, 113101, 4203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう格好だと\n少し冷えちまうんだよ", 0, 5, 0, 3, 1, 1, 113101, 4204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐもぐ…\n遊んだ分、お腹が\n空いちまってねぇ", 0, 7, 0, 3, 1, 1, 113101, 4206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ん、なんだいこの本\n催眠…うーん読めない\nナナカに聞いてみるか", 0, 8, 0, 3, 1, 1, 113101, 4207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へえ…\nなかなかいい\n乗り心地じゃないか", 0, 10, 0, 3, 1, 1, 113101, 4209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうそうハマグリって\n竿でも釣れるんだよ\n知ってたかい？", 0, 11, 0, 3, 1, 1, 113101, 4210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海を満喫しなきゃね\nちょっとひと泳ぎ\n行ってこようかな？", 0, 1, 0, 1, 1, 1, 113301, 4211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん…♪\nいつもと違った\n開放感～\nなんちゃって！", 0, 2, 0, 1, 1, 1, 113301, 4212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今のナナカちゃんは\nたぶん水属性！", 0, 3, 0, 1, 1, 1, 113301, 4213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着もバッチリ！\nサイカワサイツヨ\nナナカちゃ～ん☆", 0, 4, 0, 1, 1, 1, 113301, 4214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んっふっふ\nドキ！　水着だらけの\nギルドハウス！\nとかどうかな？", 0, 5, 0, 1, 1, 1, 113301, 4215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そんなに見られると\nちょ～っと\n恥ずかしいかも…\nなんてねなんてね！", 0, 101, 0, 1, 4, 1, 113301, 4216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとくらい\nドキッとしてくれても\nいいのにな～、もう…", 0, 102, 0, 1, 8, 1, 113301, 4217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着魔法少女の\n相方がほしいなぁ～…\nね、君やってみない？", 0, 1, 0, 2, 1, 1, 113301, 4218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもの格好と同じ？\nも～、わかってない！\nセクスィー度が違う！", 0, 2, 0, 2, 1, 1, 113301, 4219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかなどうかな？\nこのひらひらのとこが\nかわいーかなー\nとか思うんだけど！", 0, 3, 0, 2, 1, 1, 113301, 4220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくだから\nギャルゲーイベント\nごっことか\nやってみる？", 0, 4, 0, 2, 1, 1, 113301, 4221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナナカちゃんの\n好感度を上げたい？\nならおでかけだー！", 0, 101, 0, 2, 4, 1, 113301, 4222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おうちで水着って\nなんだかコスプレ\nみたいで楽しいかも♪", 0, 102, 0, 2, 8, 1, 113301, 4223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっはよーう！\n今日はバカンス日和！\n海へゴーですぞ～♪", 0, 1, 1, 2, 1, 1, 113301, 4224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯どうしよ～…\nあ、ナナカちゃんと\nどっか食べに行く？", 0, 2, 2, 2, 1, 1, 113301, 4225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は本を読むのが\n捗りまくりですな～！\n今日はなに読もっかな", 0, 3, 3, 2, 1, 1, 113301, 4226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のイベントもあるし\nちょっと休んで体力を\n回復しなきゃね～", 0, 2, 0, 3, 1, 1, 113301, 4228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうマスコット\n私にもいたらなぁ\nいっそ作っちゃう…？", 0, 3, 0, 3, 1, 1, 113301, 4229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着魔法少女に\n似合う香りってのも\n考えてみよっかな♪", 0, 4, 0, 3, 1, 1, 113301, 4230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜になると急に冷えて\n肌寒いんだよね～…", 0, 5, 0, 3, 1, 1, 113301, 4231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんまり食べると\nお腹が出て…でも…\nうう、止まらない～！", 0, 7, 0, 3, 1, 1, 113301, 4233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この催眠魔法の本\n誰にもばれないように\n保管しとかなきゃね…", 0, 8, 0, 3, 1, 1, 113301, 4234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゴーゴーゴーゴーゴー\nナナカちゃーん♪", 0, 10, 0, 3, 1, 1, 113301, 4236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナナカちゃんの\n誕生～\nなんちゃって", 0, 11, 0, 3, 1, 1, 113301, 4237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ファイトファイト☆\n一生懸命\n応援するね！", 0, 1, 0, 1, 1, 1, 113401, 4238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんながんばってる！\n私も応援でみんなを\n盛り上げなきゃ！", 0, 2, 0, 1, 1, 1, 113401, 4239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし元気のない人が\nいたら…応援で少し\nでも元気にしたいな！", 0, 3, 0, 1, 1, 1, 113401, 4240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("がんばれ～☆\nよし、発声練習OK！\n応援は、声も大事！", 0, 4, 0, 1, 1, 1, 113401, 4241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかく水着なんだし\n泳いだり潜ったりして\n遊びたいな～！", 0, 5, 0, 1, 1, 1, 113401, 4242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チアリーダーとして\nキミを精一杯\n応援したいな…！", 0, 101, 0, 1, 4, 1, 113401, 4243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミへの応援\nちゃんと\n届いてるかな…", 0, 102, 0, 1, 8, 1, 113401, 4244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…今ね、\nキミへの応援歌を\n考えてたのだ～♪", 0, 1, 0, 2, 1, 1, 113401, 4245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\n元気がないなら\n私が応援するよ☆", 0, 2, 0, 2, 1, 1, 113401, 4246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("がんばったあとは休憩\nしなきゃね！　私と\n一緒にお昼寝する？", 0, 3, 0, 2, 1, 1, 113401, 4247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリンとおそろいの\n水着で応援…\nしてみたいなぁ～", 0, 4, 0, 2, 1, 1, 113401, 4248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はなにして遊ぶ？\nキミがしたいことを\n教えてよ！", 0, 101, 0, 2, 4, 1, 113401, 4249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミを応援\nすることができて…\n私、すごく幸せ…", 0, 102, 0, 2, 8, 1, 113401, 4250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミって早起き\nなんだね！　私も\n見習わなきゃ！", 0, 1, 1, 2, 1, 1, 113401, 4251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとお疲れかな？\nそれじゃあ\n応援してあげるね♪", 0, 2, 2, 2, 1, 1, 113401, 4252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遅い時間まで\nがんばってえらいね！\nでも無理はダメだよ♪", 0, 3, 3, 2, 1, 1, 113401, 4253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとだけ休憩…\n…あう、座り心地が\n良すぎて…眠気が…", 0, 2, 0, 3, 1, 1, 113401, 4255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいるみんなを\n私の応援でもっと\n元気にするのだ～！", 0, 3, 0, 3, 1, 1, 113401, 4256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元気の出る香り～♪\nこれもうまく応援に\n活かせないかな～？", 0, 4, 0, 3, 1, 1, 113401, 4257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかあったまって\n元気をチャージ\nするのだ～☆", 0, 5, 0, 3, 1, 1, 113401, 4258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べて、\nみんなを応援する\nパワーをつけなきゃ！", 0, 7, 0, 3, 1, 1, 113401, 4260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなを元気にする\n方法は…どこかに\n書いてないかなぁ…？", 0, 8, 0, 3, 1, 1, 113401, 4261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、この子\n怪獣さんみたいで\nかわいいね～♪", 0, 10, 0, 3, 1, 1, 113401, 4263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着でこれに\n乗ってると海にいる\n気分になれるね！", 0, 11, 0, 3, 1, 1, 113401, 4264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごく忙しいけど\nとても充実した気分\nこれが青春なのかしら", 0, 1, 0, 1, 1, 1, 113501, 4265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森の静かな雰囲気も\n海の開放的な空気も\nどちらも素敵ね～", 0, 2, 0, 1, 1, 1, 113501, 4266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("汚れたお洗濯物は\nみんなが頑張った証\nなんだか愛おしいわ", 0, 3, 0, 1, 1, 1, 113501, 4267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなを見てると\n何だか私も\n走りたくなっちゃうわ", 0, 4, 0, 1, 1, 1, 113501, 4268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの水着だし\n泳ぐ練習でも\nしてみようかしら", 0, 5, 0, 1, 1, 1, 113501, 4269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな～ファイト～！\n応援するのも大事よね\n練習しておかなきゃ♪", 0, 101, 0, 1, 4, 1, 113501, 4270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先生に教えられること\nまだまだい～っぱいね\n次は何がいいかしら♪", 0, 102, 0, 1, 8, 1, 113501, 4271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も暑くなりそうね\nこまめな水分補給を\n忘れないでね", 0, 1, 0, 2, 1, 1, 113501, 4272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手伝ってくれるの？\nありがとう♪\n先生、頼りにしてるわ", 0, 2, 0, 2, 1, 1, 113501, 4273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩はこまめに\nとりましょうね\n無理は厳禁よ", 0, 3, 0, 2, 1, 1, 113501, 4274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の遊びって\nどんなのがあるの？\n先生に教えてね", 0, 4, 0, 2, 1, 1, 113501, 4275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着は初めてだけど\nどう？　変じゃない？\nふふ、ありがとう", 0, 101, 0, 2, 4, 1, 113501, 4276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと過ごした\nこの夏は、きっと…\n忘れられない思い出ね", 0, 102, 0, 2, 8, 1, 113501, 4277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう～\n朝練前にちゃんと\nごはん食べましょうね", 0, 1, 1, 2, 1, 1, 113501, 4278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お弁当作ってきたの\n栄養いっぱい摂って\n午後も頑張ろうね", 0, 2, 2, 2, 1, 1, 113501, 4279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお休みしなきゃね\n先生が子守唄を歌って\nあげましょうか？", 0, 3, 3, 2, 1, 1, 113501, 4280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、いい気持ちねぇ\n先生、少しだけ\n休憩しちゃおうかしら", 0, 2, 0, 3, 1, 1, 113501, 4282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらかわいい♪\nチームにもこういう\nマスコットが欲しいわ", 0, 3, 0, 3, 1, 1, 113501, 4283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、海の香り？\n波の音まで聞こえて\nきちゃいそうだわ", 0, 4, 0, 3, 1, 1, 113501, 4284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ\nこれなら濡れた水着を\n乾かすのも簡単ね♪", 0, 5, 0, 3, 1, 1, 113501, 4285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、美味しいわね♪\nでも、食べ過ぎは\n禁物よ", 0, 7, 0, 3, 1, 1, 113501, 4287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先生だって日々勉強よ\n新しいことを知るのは\nとても楽しいわ♪", 0, 8, 0, 3, 1, 1, 113501, 4288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらあら、楽しいわね\nみんなもきっと\nおおはしゃぎね", 0, 10, 0, 3, 1, 1, 113501, 4290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、これで\n夏らしい気分を\n満喫するわよ♪", 0, 11, 0, 3, 1, 1, 113501, 4291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンドイッチも\n作ったし、\nお兄ちゃんのお出迎え\n準備は完璧だね♪", 0, 103, 0, 1, 12, 1, 102301, 4292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、お兄ちゃんと\nぷうきちが居てくれる\nだけで、なんだか\nうれしくなっちゃう♪", 0, 103, 0, 2, 12, 1, 102301, 4293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し赤くなっているな\n日焼けなんてしたのは\nいつ以来だろう", 0, 1, 0, 1, 1, 1, 113601, 4294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好で\n過ごすのは\n少し勇気がいるな…", 0, 2, 0, 1, 1, 1, 113601, 4295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑いのは平気だが\n肌が外気に触れるの\nにはまだ慣れないな…", 0, 3, 0, 1, 1, 1, 113601, 4296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好でも\n堂々としていれば\n恥ずかしくはない…\nのかな？", 0, 4, 0, 1, 1, 1, 113601, 4297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと…鎧姿の時と\n重心が違うせいか\nちょっと不安定だな", 0, 5, 0, 1, 1, 1, 113601, 4298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この水着…\n私に似合って\nいるのだろうか…？\n少年には聞きづらいな", 0, 101, 0, 1, 4, 1, 113601, 4299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年との\n海のバカンス…\nまた行きたい\nものだな", 0, 102, 0, 1, 8, 1, 113601, 4300);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あまり見るのは\nよしてくれ…\n恥ずかしいじゃ\nないか…", 0, 1, 0, 2, 1, 1, 113601, 4301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしたのかい？\n私でよければ\n話し相手くらいには\nなろうじゃないか", 0, 2, 0, 2, 1, 1, 113601, 4302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっ！\nす、すまない\nちょっと過敏に\nなっているようだ", 0, 3, 0, 2, 1, 1, 113601, 4303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…っくしゅん！\nすまない\n薄着には慣れて\nないものでね", 0, 4, 0, 2, 1, 1, 113601, 4304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、少年になら\n見られても…\nい、いや！\nなんでもない！", 0, 101, 0, 2, 4, 1, 113601, 4305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私がこうして\nゆっくりできるのは\n少年がそばにいて\nくれるからだよ", 0, 102, 0, 2, 8, 1, 113601, 4306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間なら\nビーチにも人は\n少ないだろうね…\n遊びに行くかい？", 0, 1, 1, 2, 1, 1, 113601, 4307);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食のお誘いかい？\nいいよ、付き合おう", 0, 2, 2, 2, 1, 1, 113601, 4308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう夜か…\n一日が経つのは\nはやいものだね", 0, 3, 3, 2, 1, 1, 113601, 4309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは楽でいいな…\nいつもは鎧姿で\n家具を傷つけないか\n気を使っているからね", 0, 2, 0, 3, 1, 1, 113601, 4311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん…ふわふわの\n感触が\nよくわかるな…", 0, 3, 0, 3, 1, 1, 113601, 4312);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもは\n鎧に匂いが\n移ってしまうのが\n悩みなんだよ…", 0, 4, 0, 3, 1, 1, 113601, 4313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーむ…\n涼しいのに暖かい\nなんだか奇妙な気分だ", 0, 5, 0, 3, 1, 1, 113601, 4314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兜を気にせず\n食べられるのは\n楽でいいな…", 0, 7, 0, 3, 1, 1, 113601, 4316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…鎧がないと\nページがめくりやすい", 0, 8, 0, 3, 1, 1, 113601, 4317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身軽でいいな…\n鎧を着ていると\n騎乗訓練の時\n馬に申し訳がなくてね", 0, 10, 0, 3, 1, 1, 113601, 4319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貝をうまく使えば\n水中でも\n守りを固められそうだ", 0, 11, 0, 3, 1, 1, 113601, 4320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこをアジトと\nつなげようかな～…\nこのへんにしよっと♪", 0, 1, 0, 1, 1, 1, 106801, 4321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここってちょっと\n変わった建物だね\n妖精がいるでしょ？", 0, 2, 0, 1, 1, 1, 106801, 4322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色んな人を観察できて\n眼福眼福…♪", 0, 3, 0, 1, 1, 1, 106801, 4323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家具の配置変更なら\nアタシにおまかせあれ\n…家の形は変えない？", 0, 4, 0, 1, 1, 1, 106801, 4324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新メニューどうしよう\n思いついた人がいたら\nアタシに教えてね！", 0, 5, 0, 1, 1, 1, 106801, 4325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年、早く帰って\nこないかな…\nよし、迎えに行こう！", 0, 101, 0, 1, 4, 1, 106801, 4326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("結局またあちこち\n移動する日々だし…\n少年に会いたいな～", 0, 102, 0, 1, 8, 1, 106801, 4327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どしたの少年？\nお姉さんに何でも\n相談してみな～？", 0, 1, 0, 2, 1, 1, 106801, 4328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれをああして…\nおや少年！　ごめんね\nすぐに気づけなくて！", 0, 2, 0, 2, 1, 1, 106801, 4329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何？　クリスが\nアタシを探してる？\n…いないって言って！", 0, 3, 0, 2, 1, 1, 106801, 4330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よければリノちゃんと\nシズルちゃんにも\n顔を見せてあげて", 0, 4, 0, 2, 1, 1, 106801, 4331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年～！\nもうヘトヘトだよ～！\nお願い癒して～！", 0, 101, 0, 2, 4, 1, 106801, 4332);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…アタシが素直に\n助けてって言えるのは\n少年だけだよ", 0, 102, 0, 2, 8, 1, 106801, 4333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝だよ少年！\n爽やかな朝の\nクレープはいかが？", 0, 1, 1, 2, 1, 1, 106801, 4334);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いたな～\nお昼のクレープ\n少年は食べる？", 0, 2, 2, 2, 1, 1, 106801, 4335);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜までクレープは\nやめとけ？　ごめん\nそれだけは無理…！", 0, 3, 3, 2, 1, 1, 106801, 4336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシこんなに\nゆっくりしちゃって\nいいんだっけ～？", 0, 2, 0, 3, 1, 1, 106801, 4338);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…これ\nネネカが変身\nしてないよね？", 0, 3, 0, 3, 1, 1, 106801, 4339);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだ…\n解析完了\n今度生成しようっと♪", 0, 4, 0, 3, 1, 1, 106801, 4340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安心するな～…\nアジトに置けないから\n羨ましいよ", 0, 5, 0, 3, 1, 1, 106801, 4341);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ物を消化するって\n仕組み、どんなものか\n気になる…", 0, 7, 0, 3, 1, 1, 106801, 4343);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("速読できるけど\n本を読む時くらい\n文字にじっくり\n浸かりたいんだよね…", 0, 8, 0, 3, 1, 1, 106801, 4344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルとして\nみんなを元気に…！\nアカリ、頑張ります♪", 0, 1, 0, 1, 1, 1, 113701, 4346);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんと一緒に\nお兄ちゃんを…えへへ\nまだかな、お兄ちゃん", 0, 2, 0, 1, 1, 1, 113701, 4347);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルの音色を\n目指して、今日も\nサックスの練習です♪", 0, 3, 0, 1, 1, 1, 113701, 4348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんとの特訓も\n頑張らないと…\n厳しくしてくださいね", 0, 4, 0, 1, 1, 1, 113701, 4349);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいエンジェルの\n格好、お兄ちゃんなら\n喜んでくれますよね♪", 0, 5, 0, 1, 1, 1, 113701, 4350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルの力で\nお兄ちゃんのハートも\nイチコロですよ♪", 0, 101, 0, 1, 4, 1, 113701, 4351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリが一番\n元気にしたいのは\nお兄ちゃんですよ♪", 0, 102, 0, 1, 8, 1, 113701, 4352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん？\n触りたいなら…\nこことかどうですか♪", 0, 1, 0, 2, 1, 1, 113701, 4353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓の時間ですか？\nアカリ、楽しみに\nしてたんですよ♪", 0, 2, 0, 2, 1, 1, 113701, 4354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、お兄ちゃん！\nそろそろアカリと\n休憩…しませんか♪", 0, 3, 0, 2, 1, 1, 113701, 4355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この羽、触り心地\nいいですか？　あんっ\nくすぐったいですよぉ", 0, 4, 0, 2, 1, 1, 113701, 4356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんも元気に\nなりたいんですか？\nアカリにお任せです♪", 0, 101, 0, 2, 4, 1, 113701, 4357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やんっ♪\nお兄ちゃんったら\nダイタンですね♪", 0, 102, 0, 2, 8, 1, 113701, 4358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん、朝ですよ\nすっごく気持ちのいい\nお天気ですよ…♪", 0, 1, 1, 2, 1, 1, 113701, 4359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼寝しませんか\nお兄ちゃん？\nアカリの膝枕で…♪", 0, 2, 2, 2, 1, 1, 113701, 4360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜ですね、お兄ちゃん\nアカリ、なんだか胸が\nドキドキしちゃいます", 0, 3, 3, 2, 1, 1, 113701, 4361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フカフカですね…\n隣にお兄ちゃんが\nいてくれたらなぁ…♪", 0, 2, 0, 3, 1, 1, 113701, 4363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、アカリも\nこんな風にかわいく\nなりたいな～", 0, 3, 0, 3, 1, 1, 113701, 4364);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんが好きな\n匂いなのかな？\n参考にしますね！", 0, 4, 0, 3, 1, 1, 113701, 4365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体が火照ってきて\nなんだかアカリ…\nクラクラしちゃう…", 0, 5, 0, 3, 1, 1, 113701, 4366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむ、んぐ…あっ\nほっぺについちゃった\nベトベトですよぉ～", 0, 7, 0, 3, 1, 1, 113701, 4368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルって色んな\n物語に出てきますよね\nもっと調べなくちゃ！", 0, 8, 0, 3, 1, 1, 113701, 4369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの方の前では\n常に気高く\nありたいですわね", 0, 103, 0, 1, 12, 1, 103201, 4371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなに道に迷っても\nあなたさまの元には\n絶対に辿り着く\n自信がありますわ", 0, 103, 0, 2, 12, 1, 103201, 4372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと一緒に\nいるときが一番楽しい\n一時かもしれないわ", 0, 103, 0, 1, 12, 1, 102801, 4373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかあんたと一緒に\nサレンディア救護院を\n切り盛り…なんてね♪", 0, 103, 0, 2, 12, 1, 102801, 4374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も\nエンジェルとして、\nみんなの幸せの\nために頑張らないと", 0, 1, 0, 1, 1, 1, 113801, 4375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかく羽が\nついてるのに\n飛べないのが残念だわ", 0, 2, 0, 1, 1, 1, 113801, 4376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好、子供たちに\n妙にウケがいいわね\nま、悪くないけど", 0, 3, 0, 1, 1, 1, 113801, 4377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("や、やっぱりみんな\n注目してくるわね…\nエンジェルって珍しい\nからしかたないか", 0, 4, 0, 1, 1, 1, 113801, 4378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルになると\n人見知りがなおる！\n…わけないか", 0, 5, 0, 1, 1, 1, 113801, 4379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルの活動は\n大変だけど、自分が\n成長してるって\n実感がうれしいわね", 0, 101, 0, 1, 4, 1, 113801, 4380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし誰かの願いを\nかなえられるなら\n私はアイツの…\nって何考えてるのよ！", 0, 102, 0, 1, 8, 1, 113801, 4381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何ボサっとしてるの！\nさあ、街に出て\n人助けするわよ！", 0, 1, 0, 2, 1, 1, 113801, 4382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェリック\nアロー！\nなんてね…え、アンタ\nいつから見てたのよ！", 0, 2, 0, 2, 1, 1, 113801, 4383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コラ！\n羽は触らないで！\n壊れたらどうするのよ", 0, 3, 0, 2, 1, 1, 113801, 4384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルじゃなく\nても、アンタはいつも\n人助けしてるわよね\n…ちょっと尊敬するわ", 0, 4, 0, 2, 1, 1, 113801, 4385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服なら他の子より\n私を見てくれるかも…\nって、な、何\n見てるのよ！", 0, 101, 0, 2, 4, 1, 113801, 4386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、ねえ、もし私が\n困ってたら、一番に\n駆けつけて…やっぱり\n何でもないわ！", 0, 102, 0, 2, 8, 1, 113801, 4387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう…あ、あの、\nエンジェルとして\n町に行くんだけど…\n一緒に行かない？", 0, 1, 1, 2, 1, 1, 113801, 4388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ、いいことした\n後のランチは\nおいしいわね", 0, 2, 2, 2, 1, 1, 113801, 4389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\n夜更かししてないで\n早く寝なさいよね", 0, 3, 3, 2, 1, 1, 113801, 4390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい座り心地ね～\nまさに天にも昇る\n心地よさだわ～", 0, 2, 0, 3, 1, 1, 113801, 4392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、かわいい…\nあ、羽付けたら\nもっとかわいく\nなるんじゃないかな？", 0, 3, 0, 3, 1, 1, 113801, 4393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～落ち着くわ～\n回復アイテムみたいで\n癒やされちゃうわ～", 0, 4, 0, 3, 1, 1, 113801, 4394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、とと…\n危ない、羽が\nこげちゃうところ\nだったわ", 0, 5, 0, 3, 1, 1, 113801, 4395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人の役に立つのって\nすごく大変だから、\nこれでライフ回復よ！", 0, 7, 0, 3, 1, 1, 113801, 4397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エンジェルに関する\n本はあるかしら…あ！\nこれ探してた攻略本！", 0, 8, 0, 3, 1, 1, 113801, 4398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっふっふ\n吸血鬼らしく\n驚かせてあげましょう", 0, 1, 0, 1, 1, 1, 113901, 4400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("獲物はどこですか～！\nう～ん、もうちょっと\n迫力が欲しいですね", 0, 2, 0, 1, 1, 1, 113901, 4401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トリックオアトリート\n…返事がないので\nイタズラしておきます", 0, 3, 0, 1, 1, 1, 113901, 4402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンですし\nたまには騎士さんでも\n誘ってあげますかね", 0, 4, 0, 1, 1, 1, 113901, 4403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マントは動きに\nメリハリがついて\nいいですね", 0, 5, 0, 1, 1, 1, 113901, 4404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色んな仮装が見られて\nやっぱりハロウィンは\n最高ですね", 0, 101, 0, 1, 4, 1, 113901, 4405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼らしい行動って\n噛みついたり…いや\nそれは大胆過ぎです！", 0, 102, 0, 1, 8, 1, 113901, 4406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("呼びましたか？\n手短にお願いしますよ\n忙しいんですから！", 0, 1, 0, 2, 1, 1, 113901, 4407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え？　衣装に穴が？\nありがとうございます\n…よく見てるんですね", 0, 2, 0, 2, 1, 1, 113901, 4408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…吸血鬼の\n姿でも、眠い時は\n眠いんですよね…", 0, 3, 0, 2, 1, 1, 113901, 4409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンってライブ\nとは違った賑やかさが\nあってワクワクします", 0, 4, 0, 2, 1, 1, 113901, 4410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私を驚かそうとしても\n無駄ですよ！\nすぐ分かるんですから", 0, 101, 0, 2, 4, 1, 113901, 4411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さん、一緒に\nハロウィンを…いいえ\nなんでもないですっ！", 0, 102, 0, 2, 8, 1, 113901, 4412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事で寝不足だから\n太陽がまぶしいです…\n私、吸血鬼っぽいかも", 0, 1, 1, 2, 1, 1, 113901, 4413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯は真っ赤な…\nトマト尽くしのお弁当\nにしてみました", 0, 2, 2, 2, 1, 1, 113901, 4414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜はハロウィンが\n盛り上がる時間…\n行きますよ騎士さん！", 0, 3, 3, 2, 1, 1, 113901, 4415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このフィット感\nどうにか服作りにも\n活かせれば…！", 0, 2, 0, 3, 1, 1, 113901, 4417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よく出来てますね…！\nぬいぐるみの服を作る\nのも楽しそうですね！", 0, 3, 0, 3, 1, 1, 113901, 4418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい感じですね…\n服に合わせた香りって\nいうのも、いいかも…", 0, 4, 0, 3, 1, 1, 113901, 4419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、温まりますね…\nおっと、マントに火が\n点いちゃいそうです！", 0, 5, 0, 3, 1, 1, 113901, 4420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あぁ、美味しい～\n食べた分は、働いて\n燃焼しますからね！", 0, 7, 0, 3, 1, 1, 113901, 4422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("伝説の吸血鬼…\n夜を統べる者…\nほうほう…", 0, 8, 0, 3, 1, 1, 113901, 4423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりハロウィンと\nいえばお菓子です！\nさぁ配りましょうか！", 0, 12, 0, 3, 1, 1, 113901, 4425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好…\nカッコイイのに\n動きやすくて\n着心地も最高ッス！", 0, 1, 0, 1, 1, 1, 114101, 4427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キメポーズはこう…\nいやこっちのほうが…\nなやましいッス…！", 0, 2, 0, 1, 1, 1, 114101, 4428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トリックオア\nジャスティス！\nって言ったら何か\nもらえるッスかね？", 0, 3, 0, 1, 1, 1, 114101, 4429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい必殺技の\n特訓もしなくちゃ\nいけないッスね…\n忙しいッス！", 0, 4, 0, 1, 1, 1, 114101, 4430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分のこの姿\nトモね～ちゃんにも\nみせてあげるッス！", 0, 5, 0, 1, 1, 1, 114101, 4431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ホワイトタイガー\n参上ッス！\n今のポーズは\nキマったッス！", 0, 101, 0, 1, 4, 1, 114101, 4432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人と一緒だと\nほんとにヒーローに\nなれる気がするッス！", 0, 102, 0, 1, 8, 1, 114101, 4433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうッスか？\nこの色、自分に\n似合ってるッスかね？", 0, 1, 0, 2, 1, 1, 114101, 4434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒマだったら\n必殺技の特訓に\n付き合ってもらって\nいいッスか？", 0, 2, 0, 2, 1, 1, 114101, 4435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどいいところに\n来たッスね！\nこのキメポーズ\nどうッスか？", 0, 3, 0, 2, 1, 1, 114101, 4436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お！　この格好、\n気になるッスか？\nじっくり見ても\nいいッスよ♪", 0, 4, 0, 2, 1, 1, 114101, 4437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたも一緒に\n新しい技の練習\nどうッスか？", 0, 101, 0, 2, 4, 1, 114101, 4438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もあんたと一緒に\nランドソルの平和を\n守るッスよ！", 0, 102, 0, 2, 8, 1, 114101, 4439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ッス！\n一緒に早朝特訓\nやるッスよ！", 0, 1, 1, 2, 1, 1, 114101, 4440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼休憩ッス！\nヒーローにも\n休息は必要ッス！", 0, 2, 2, 2, 1, 1, 114101, 4441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("闇夜に映える\n白い衣装で\n平和を守るッスよ！", 0, 3, 3, 2, 1, 1, 114101, 4442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トラも狩りの時以外は\nごろごろしてるって\n本で読んだッスよー", 0, 2, 0, 3, 1, 1, 114101, 4444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もこもこッスね♪\nこのかわいらしさを\n守ってあげるのも\nヒーローの役目ッス！", 0, 3, 0, 3, 1, 1, 114101, 4445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂いッスね…\nリラックスして\n瞑想するッス！", 0, 4, 0, 3, 1, 1, 114101, 4446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("燃える炎は\nヒーローの心意気ッス\nいつまでも\n見てられるッスよ", 0, 5, 0, 3, 1, 1, 114101, 4447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nいっぱい食べて\n強いヒーローに\nなるッスよ！", 0, 7, 0, 3, 1, 1, 114101, 4449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんと勉強の本も\n読んでるッスよ…！\nヒーローには賢さも\n必要らしいッス！", 0, 8, 0, 3, 1, 1, 114101, 4450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わわっ、お菓子が\nいっぱいッス！\nみんなで\n食べるッスよ！", 0, 12, 0, 3, 1, 1, 114101, 4452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシがチューシンと\nなった今、天下統一は\n目の前デス！", 0, 103, 0, 1, 12, 1, 103001, 4454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうショーグンってば\nそれはセイシツに\nすることデ～ス…", 0, 103, 0, 2, 12, 1, 103001, 4455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女幽霊…うらめしや…\nうーん、これは\nちょっと違う気が\nするな…", 0, 1, 0, 1, 1, 1, 114001, 4456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何だか寒気がする…\nま、まさか\nこの部屋にも幽霊が？", 0, 2, 0, 1, 1, 1, 114001, 4457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンは楽しいね\n童心に帰ったような\n気分だよ", 0, 3, 0, 1, 1, 1, 114001, 4458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のハロウィンは\nユイとヒヨリを\n誘ってみようかな", 0, 4, 0, 1, 1, 1, 114001, 4459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンのお菓子は\nどれもかわいいね\n…一つくらいなら\nいいかな？", 0, 5, 0, 1, 1, 1, 114001, 4460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次は彼と\nどんなハロウィンを\n過ごそうかな…", 0, 101, 0, 1, 4, 1, 114001, 4461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな賑やかさも\nいいものだね\n彼といられるのなら\nなおさら…", 0, 102, 0, 1, 8, 1, 114001, 4462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…いたずらしようと\nしてない、キミ？\nふふ、お見通しだよ", 0, 1, 0, 2, 1, 1, 114001, 4463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、私にもお菓子を？\nありがとう…ふふ\nうれしいものだね\nハッピーハロウィン！", 0, 2, 0, 2, 1, 1, 114001, 4464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\n出かけるなら\n私も同行しようか", 0, 3, 0, 2, 1, 1, 114001, 4465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好、舞踏会にも\n出られそうだね\n一曲、踊ってみる？", 0, 4, 0, 2, 1, 1, 114001, 4466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やるからには本気で\nやらせてもらおう\nトリックオア\nトリート！", 0, 101, 0, 2, 4, 1, 114001, 4467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("他の子に目移りする\nのも分かるが、その…\nせっかくの特別な衣装\n見てほしいな", 0, 102, 0, 2, 8, 1, 114001, 4468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝起きの体を\n慣らしておこうか\nほら、剣を取って", 0, 1, 1, 2, 1, 1, 114001, 4469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子もいいけど\nちゃんと昼食も\nとるんだよ", 0, 2, 2, 2, 1, 1, 114001, 4470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、行こうか！\nハロウィンは\nこれからが本番だよ", 0, 3, 3, 2, 1, 1, 114001, 4471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンはまだ\nこれからだ\n一休みしようか", 0, 2, 0, 3, 1, 1, 114001, 4473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミたちも\n仮装に興味は\nあるかな？　…ふふ", 0, 3, 0, 3, 1, 1, 114001, 4474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだけど\n幽霊が集まったり\nしないだろうか…？", 0, 4, 0, 3, 1, 1, 114001, 4475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かい…一息ついたら\nハロウィンの\nパレードを\n見に行こうかな", 0, 5, 0, 3, 1, 1, 114001, 4476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンを本気で\n楽しむなら\n食事もしっかり\nとっておかないとね", 0, 7, 0, 3, 1, 1, 114001, 4478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンの\nホラー小説か…\nけ、結構\n怖いものだね…？", 0, 8, 0, 3, 1, 1, 114001, 4479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子がいっぱいだ…\nこういうのって\n見ているだけで心が\n躍ってしまうね", 0, 12, 0, 3, 1, 1, 114001, 4481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにかわいい\n武器で戦えるとは…\nすごいものだな\n魔法少女は", 0, 1, 0, 1, 1, 1, 114201, 4483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("決めポーズの訓練も\nしっかりやっておくか\n…誰も見ていないな？", 0, 2, 0, 1, 1, 1, 114201, 4484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう格好は\nユキあたりがすごく\n似合いそうだな", 0, 3, 0, 1, 1, 1, 114201, 4485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちにサインを\n求められてしまった…\nこれもまた私の使命！", 0, 4, 0, 1, 1, 1, 114201, 4486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好は目立つな…\nいや、提督とは人々の\n視線を集めるものだ！", 0, 5, 0, 1, 1, 1, 114201, 4487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと作戦会議を\nしておくか。あれで\nなかなか頼れるからな", 0, 101, 0, 1, 4, 1, 114201, 4488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつには私の勇姿を\nちゃんと見ていて\nほしいものだな", 0, 102, 0, 1, 8, 1, 114201, 4489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一仕事終えたことだし\n一緒に甘いものでも\n食べに行くか？", 0, 1, 0, 2, 1, 1, 114201, 4490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪しげな気配がするな\n貴公も警戒を\n怠るなよ！", 0, 2, 0, 2, 1, 1, 114201, 4491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリに魔法少女の\n本を借りたんだ\n一緒に読まないか？", 0, 3, 0, 2, 1, 1, 114201, 4492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("巡回の時間まで\nお茶にでもするか\n貴公も付き合うがいい", 0, 4, 0, 2, 1, 1, 114201, 4493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公がサポートして\nくれるのなら心強いな\n頼りにしているぞ", 0, 101, 0, 2, 4, 1, 114201, 4494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭を撫でるな～！\n…まったく、貴公だけ\nだぞ、こんな風に私を\n撫でてくるのは…", 0, 102, 0, 2, 8, 1, 114201, 4495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きろ貴公！\n魔法少女の朝は\n早いぞ！", 0, 1, 1, 2, 1, 1, 114201, 4496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほら、食後の\nデザートだ\nて、適度な糖分は\n体に必要なんだ！", 0, 2, 2, 2, 1, 1, 114201, 4497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…魔法少女も…\n眠気、には…い、いや\n寝てないぞ！？", 0, 3, 3, 2, 1, 1, 114201, 4498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("任務や訓練で\n疲れた体に\nこれは効くなぁ…", 0, 2, 0, 3, 1, 1, 114201, 4500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ、かわいいな\nモーラのやつを隣に\n並べようか", 0, 3, 0, 3, 1, 1, 114201, 4501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、身も心も\n安らぐ…\nまるで魔法だな…", 0, 4, 0, 3, 1, 1, 114201, 4502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この温かさ…\n愛と希望に\n通じるものがある…", 0, 5, 0, 3, 1, 1, 114201, 4503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事の大切さは\n魔法少女も軍人も\n変わりない\nしっかり食べるんだ！", 0, 7, 0, 3, 1, 1, 114201, 4505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の本を\n読んでるのだが\nわ、私もこんななのか", 0, 8, 0, 3, 1, 1, 114201, 4506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オラとあんちゃんは\nボケもツッコミも\nあうんの呼吸だべ♪", 0, 103, 0, 1, 12, 1, 103301, 4508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんと二人で\nネタ合わせ…初めての\n共同作業だべ♪", 0, 103, 0, 2, 12, 1, 103301, 4509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴっぷる！", 0, 1, 0, 1, 1, 1, 192501, 4510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴっぷるぴっぷる♪", 0, 2, 0, 1, 1, 1, 192501, 4511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴっ！", 0, 3, 0, 1, 1, 1, 192501, 4512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷっぷー", 0, 4, 0, 1, 1, 1, 192501, 4513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴぃ？", 0, 5, 0, 1, 1, 1, 192501, 4514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴっぷるんるん♪", 0, 1, 0, 2, 1, 1, 192501, 4515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷぅ！", 0, 2, 0, 2, 1, 1, 192501, 4516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴぴっ♪", 0, 3, 0, 2, 1, 1, 192501, 4517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷぅー…", 0, 4, 0, 2, 1, 1, 192501, 4518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゅ！", 0, 1, 1, 2, 1, 1, 192501, 4519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷはー", 0, 2, 2, 2, 1, 1, 192501, 4520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴぇー", 0, 3, 3, 2, 1, 1, 192501, 4521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女になったら\n髪型も変わるんだね\n色々試してみようかな", 0, 1, 0, 1, 1, 1, 114301, 4531);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…煌く剣技で、\n悪を断つ！\nうん、今日も\n完璧なポーズだね♪", 0, 2, 0, 1, 1, 1, 114301, 4532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミクマ流剣術で、\n魔法少女の技に使え\nそうなものは…よし、\n早速試してみよっと♪", 0, 3, 0, 1, 1, 1, 114301, 4533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女になったから\nには、サインの練習も\nしないと…\nよし、頑張るぞ！", 0, 4, 0, 1, 1, 1, 114301, 4534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の姿はすごく\nかわいいけど…この\n姿はジュンさんたちに\n見せられないなぁ…", 0, 5, 0, 1, 1, 1, 114301, 4535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人は魔法少女\nのこと好きなのかな？\n…好きだったら\nうれしいな♪", 0, 101, 0, 1, 4, 1, 114301, 4536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…やっぱり、\nあの人がいないと\n特訓に身が入らない…\n早く帰ってこないかな", 0, 102, 0, 1, 8, 1, 114301, 4537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし時間があるなら、\n私と街の見回りに\n行かない？", 0, 1, 0, 2, 1, 1, 114301, 4538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、いいところに！\n新しい魔法剣術を\n編み出したから、\n見てくれないかな？", 0, 2, 0, 2, 1, 1, 114301, 4539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の姿が気に\nなるのは分かるけど…\nず、ずっと見られる\nのは照れるからやめて", 0, 3, 0, 2, 1, 1, 114301, 4540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身ポーズ中の動き、\n少し変えた方が\nいいかな…\nあなたはどう思う？", 0, 4, 0, 2, 1, 1, 114301, 4541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よければ、\n魔法少女の特訓に\n付き合ってくれない？\nその…二人きりでさ…", 0, 101, 0, 2, 4, 1, 114301, 4542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私…あなただけの\n魔法少女になっても…\nふふっ、な～んてね♪", 0, 102, 0, 2, 8, 1, 114301, 4543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もいい朝だね\nさあ、一緒に\n街の見回りに行こうか", 0, 1, 1, 2, 1, 1, 114301, 4544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう昼か…なにか\n食べたいものある？\n簡単なのでいいなら、\n私が作ってあげるよ", 0, 2, 2, 2, 1, 1, 114301, 4545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ休もうか\n…なんなら、添い寝\nしてあげようか？\nふふっ、冗談だよ♪", 0, 3, 3, 2, 1, 1, 114301, 4546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…\n心身ともに安らぐね\nなんだか\n眠くなっちゃいそう", 0, 2, 0, 3, 1, 1, 114301, 4548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…これ、\n魔法で動かせたり\nしないかな？", 0, 3, 0, 3, 1, 1, 114301, 4549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだね\nなんだか頭が冴えて\nきたし、新しい技でも\n考えようかな", 0, 4, 0, 3, 1, 1, 114301, 4550);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいな…\nこの温もりは、\n魔法少女の魔法でも\n再現不可能だね…", 0, 5, 0, 3, 1, 1, 114301, 4551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、これは…\nおいしすぎて手が\n止まらないかも", 0, 7, 0, 3, 1, 1, 114301, 4553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本の\nキャラの動き、\n変身ポーズの\n参考にできるかも！", 0, 8, 0, 3, 1, 1, 114301, 4554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\nさあ、素敵な\nパーティーを始めると\nいたしましょう！", 0, 1, 0, 1, 1, 1, 114401, 4556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、\nいくつになっても、\nやはりクリスマスは、\nワクワクしますわね♪", 0, 2, 0, 1, 1, 1, 114401, 4557);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分で料理をしてみて\nシェフたちのすごさが\n改めて分かりましたわ", 0, 3, 0, 1, 1, 1, 114401, 4558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何事も自分で\n体験してみると\n新しい発見が\nあるものですわね♪", 0, 4, 0, 1, 1, 1, 114401, 4559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やはり、クリスマスは\n街が活発になり\nますわね…これは、\n絶好の商機ですわ♪", 0, 5, 0, 1, 1, 1, 114401, 4560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("他のクリスマス料理も\n作れるようになったら\nあのお方は食べて\nくださるかしら…？", 0, 101, 0, 1, 4, 1, 114401, 4561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのお方に贈る\nプレゼント…\nこれはかなりの\n難題ですわね…", 0, 102, 0, 1, 8, 1, 114401, 4562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\nよろしければ、一緒に\nクリスマスの準備を\nいたしませんか？", 0, 1, 0, 2, 1, 1, 114401, 4563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、クリスマスの\n飾りつけを手伝って\nいただけるのですか？\nありがとうございます", 0, 2, 0, 2, 1, 1, 114401, 4564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスに合わせて\nあつらえた自慢の衣装\nなのですが…その、\nいかがでしょうか？", 0, 3, 0, 2, 1, 1, 114401, 4565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幼い頃はサンタさんが\nいらっしゃるのを\n待ちわびたものです\n今は…内緒ですわ♪", 0, 4, 0, 2, 1, 1, 114401, 4566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("も、もしお時間が\nあるようでしたら、\nクリスマスの街を\n一緒に歩きませんか？", 0, 101, 0, 2, 4, 1, 114401, 4567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年のクリスマスも\nあのお方と一緒に\n迎えられたら…", 0, 102, 0, 2, 8, 1, 114401, 4568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時は金なり…\nせっかくの朝ですもの\n時間を有効活用\nいたしましょう！", 0, 1, 1, 2, 1, 1, 114401, 4569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼になりましたわね\nさあ、\nパーティーの準備を\n進めますわよ！", 0, 2, 2, 2, 1, 1, 114401, 4570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("静かな夜ですわね…\nもうちょっとだけ、\nあなたさまとお話を\nしていたい気分です", 0, 3, 3, 2, 1, 1, 114401, 4571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適度な休息は\n成功の秘訣ですわ！", 0, 2, 0, 3, 1, 1, 114401, 4573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このかわいらしさ…\nいつまでも見て\nいられそうですわ♪", 0, 3, 0, 3, 1, 1, 114401, 4574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人をもてなすには\nこうしたところにも\n気を配らないと\nいけませんわね", 0, 4, 0, 3, 1, 1, 114401, 4575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かい…\nこういう憩いの\nひと時こそ、大事に\nしたいものですわね", 0, 5, 0, 3, 1, 1, 114401, 4576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この奥深い味わい…\n何か隠し味など\n使われていまして？", 0, 7, 0, 3, 1, 1, 114401, 4578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマス料理の\nレシピも、\nこれだけあると\n迷ってしまいますわね", 0, 8, 0, 3, 1, 1, 114401, 4579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この絵本、とっても\n面白いつくりですわね\nうちの商品に\nしたいぐらいですわ", 0, 14, 0, 3, 1, 1, 114401, 4581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これだけ大きな\n着ぐるみ…\n職人の技術が\n光りますわね", 0, 15, 0, 3, 1, 1, 114401, 4582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスといえば\nパーティーよね！\nいっぱい飲むわよ～♪", 0, 1, 0, 1, 1, 1, 114601, 4583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私を麦しゅわだけの\n女と思ったら\n大間違いなんだから♪", 0, 2, 0, 1, 1, 1, 114601, 4584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスらしい\n飲み物も結構いいわね\n私も今度\n作ってみようかしら", 0, 3, 0, 1, 1, 1, 114601, 4585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かい部屋で飲む\n麦しゅわも\nまた格別なのよね…", 0, 4, 0, 1, 1, 1, 114601, 4586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はオフの日だし\n朝から飲んでも\n怒られないわよね？", 0, 5, 0, 1, 1, 1, 114601, 4587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの\nデートスポットで\n彼と一緒に…ってなに\n考えてるのユカリ！？", 0, 101, 0, 1, 4, 1, 114601, 4588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("背伸びしなくても\nありのままの自分を\n受け入れてくれるって\nすごく…幸せ…", 0, 102, 0, 1, 8, 1, 114601, 4589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大丈夫よ～\n飲んでない\n飲んでないひゃら～", 0, 1, 0, 2, 1, 1, 114601, 4590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスは\n特別だもの\n特別な一杯を\n飲まないとね♪", 0, 2, 0, 2, 1, 1, 114601, 4591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマース！\nほらほらぁ\n乾杯しましょ♪", 0, 3, 0, 2, 1, 1, 114601, 4592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉さんの\n頼れるところ\n見せてあげるわね", 0, 4, 0, 2, 1, 1, 114601, 4593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何かあったら\n頼ってくれても\nいいんだからね？", 0, 101, 0, 2, 4, 1, 114601, 4594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…これからも\nキミのこと…\n頼りにしちゃうからね", 0, 102, 0, 2, 8, 1, 114601, 4595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さわやかな朝ね\n…二日酔いがないと\n朝ってこんなに\n気持ちいいのね", 0, 1, 1, 2, 1, 1, 114601, 4596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼間から飲むのって\nまた格別よね…って\nガマン、ガマンよ…", 0, 2, 2, 2, 1, 1, 114601, 4597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間かあ…\nあとは寝るだけだし\nちょっとくらいは…", 0, 3, 3, 2, 1, 1, 114601, 4598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゴロゴロするのって\n最高ね～\nあとは麦しゅわが\nあればなぁ", 0, 2, 0, 3, 1, 1, 114601, 4600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私だって…\nかわいいものは\n好きでいいわよね？", 0, 3, 0, 3, 1, 1, 114601, 4601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んっ～…いい香りね\n日頃の疲れが\n取れる気がするわ", 0, 4, 0, 3, 1, 1, 114601, 4602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカする～\n…なんだかのどが\nかわいてきたわね", 0, 5, 0, 3, 1, 1, 114601, 4603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…労働の\n後のご飯はやっぱり\nおいしいわぁ…", 0, 7, 0, 3, 1, 1, 114601, 4605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスデート\n完全攻略マニュアル？\n…読んでおかなくちゃ", 0, 8, 0, 3, 1, 1, 114601, 4606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、絵が飛び出して\n見えるけど…\n酔っ払ってるせいじゃ\nないわよね…？", 0, 14, 0, 3, 1, 1, 114601, 4608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい手触りね～\nウチにもほしいけど\n麦しゅわをこぼしたら\n大変そうだわ…", 0, 15, 0, 3, 1, 1, 114601, 4609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイの視線\nずっと独り占め\nしてたいな～", 0, 103, 0, 1, 12, 1, 101601, 4610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイといるだけで\nうち、おに楽しいし！\nヒデサイもっしょ～？", 0, 103, 0, 2, 12, 1, 101601, 4611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\nふふ、口にするだけで\n何だか楽しくなるわね", 0, 1, 0, 1, 1, 1, 114501, 4612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもは子どもたちを\n見守る方だけど\n今ははしゃいでも\nいいわよね？", 0, 2, 0, 1, 1, 1, 114501, 4613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツリーや料理\nそしてプレゼント！\nいくつになっても\nやっぱり心躍るわね♪", 0, 3, 0, 1, 1, 1, 114501, 4614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("飾り付けも料理も\nいいセンスしてるわね\n救護院のパーティーの\n参考にさせてもらうわ", 0, 4, 0, 1, 1, 1, 114501, 4615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("焼きそばパンを\nクリスマスの定番に\nするにはどうすれば…", 0, 5, 0, 1, 1, 1, 114501, 4616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、あいつの\n好きそうな料理だわ\n取っといて食べさせて\nあげようかしら♪", 0, 101, 0, 1, 4, 1, 114501, 4617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつのプレゼント\nちょっとだけ奮発\nしたのよね…\n喜んでくれるかしら", 0, 102, 0, 1, 8, 1, 114501, 4618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このドレス\n似合ってるかしら？\n今だけは見とれても\n許してあげるわ♪", 0, 1, 0, 2, 1, 1, 114501, 4619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見て、このケーキ！\nおいしそうでしょ\nたまにはこんな贅沢も\nいいわよね♪", 0, 2, 0, 2, 1, 1, 114501, 4620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理も飲み物も\nおいしいわね！\nいっぱい食べて\n元を取らないと♪", 0, 3, 0, 2, 1, 1, 114501, 4621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちと一緒に\n雪遊び、楽しそうね\nあんたもどう？", 0, 4, 0, 2, 1, 1, 114501, 4622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの\nクリスマスなんだもの\nエスコート\nよろしくね♪", 0, 101, 0, 2, 4, 1, 114501, 4623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い？　そう…\nなら、もっとこっち\n来ていいわよ…？", 0, 102, 0, 2, 8, 1, 114501, 4624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほら、早く起きて？\nパーティー用の\n買い出しに\n付き合ってちょうだい", 0, 1, 1, 2, 1, 1, 114501, 4625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パーティーの料理の\n準備をしながらお昼も\n作っておいたわ\n我ながらいい手際ね", 0, 2, 2, 2, 1, 1, 114501, 4626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にぎやかなパーティー\nもいいけど、聖夜の\n余韻を感じるのも\n結構素敵ね", 0, 3, 3, 2, 1, 1, 114501, 4627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい座り心地だわ～\n腕のいい職人の仕事ね\nうちでも扱いたいわ", 0, 2, 0, 3, 1, 1, 114501, 4629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい！\n子どもたちに\nプレゼントしたら\n喜んでくれるかも", 0, 3, 0, 3, 1, 1, 114501, 4630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("華やかな香りね\nクリスマスに\nピッタリだわ", 0, 4, 0, 3, 1, 1, 114501, 4631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い日にはやっぱり\nこれよね…\nはぁ、極楽極楽♪", 0, 5, 0, 3, 1, 1, 114501, 4632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー、おいしいわ！\n焼きそばパン味の\nものも、作れない\nかしら？", 0, 7, 0, 3, 1, 1, 114501, 4634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはのんびり\n読書でも…なんだか\nラブロマンスばかりね\nクリスマスだから？", 0, 8, 0, 3, 1, 1, 114501, 4635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、面白いわね！\n子どもたちの\nプレゼントに\nピッタリだわ", 0, 14, 0, 3, 1, 1, 114501, 4637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんないい毛並み\n初めて見るわ…\n一体どこで手に\n入るのかしら？", 0, 15, 0, 3, 1, 1, 114501, 4638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシもみんなと\n一緒に正月を\n楽しんでいいのか？", 0, 1, 0, 1, 1, 1, 114701, 4639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年こそ、もう少し\n身長が伸びます\nように…", 0, 2, 0, 1, 1, 1, 114701, 4640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("げっ！　お年玉が\n全然残ってないぞ！？\nそんな、嘘だろ…？", 0, 3, 0, 1, 1, 1, 114701, 4641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大勢で過ごす\n正月か…初めてだけど\n悪くないもんだな", 0, 4, 0, 1, 1, 1, 114701, 4642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー…ここじゃ\n天楼覇断剣の\n出番はなさそうだな", 0, 5, 0, 1, 1, 1, 114701, 4643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツらと作る\n戦い以外の思い出も\nもっと増やしたいな", 0, 101, 0, 1, 4, 1, 114701, 4644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなに賑やかな\n正月は初めてだ\n…温かくて、いいな", 0, 102, 0, 1, 8, 1, 114701, 4645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("記憶がなくったって\n楽しい思い出は\n新しく作れるよな？", 0, 1, 0, 2, 1, 1, 114701, 4646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早くでかけるぞ！\nアタシはもっと\n正月を楽しみたい！", 0, 2, 0, 2, 1, 1, 114701, 4647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なあ、オマエはもう\nノウェムって名前\n覚えてくれたよな？", 0, 3, 0, 2, 1, 1, 114701, 4648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服、アタシに\n似合ってるのか？\n…そっか。\nありがとな！", 0, 4, 0, 2, 1, 1, 114701, 4649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエらと見た朝日は\nきっと忘れないぞ！\n思い出ができたな！", 0, 101, 0, 2, 4, 1, 114701, 4650);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかオクトーも\n一緒に、みんなで\n正月を過ごせたらな…", 0, 102, 0, 2, 8, 1, 114701, 4651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝から元気だな！\nアタシもいっちょ\n見習ってみるか！", 0, 1, 1, 2, 1, 1, 114701, 4652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯は何にする？\n正月はうまいものが\n多くて迷うよな！", 0, 2, 2, 2, 1, 1, 114701, 4653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい夜だな！\nアタシと一緒に\n夜更かしを楽しむか？", 0, 3, 3, 2, 1, 1, 114701, 4654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月らしく、たまには\nゆっくりするのも\nいいかもな…", 0, 2, 0, 3, 1, 1, 114701, 4656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ？\nオマエも初詣に\n行きたいのか？", 0, 3, 0, 3, 1, 1, 114701, 4657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すーはー…\n神殿のニオイがするな\nいい事ありそうだ！", 0, 4, 0, 3, 1, 1, 114701, 4658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コイツがあれば\nうまい魚が\n焼けそうだな…", 0, 5, 0, 3, 1, 1, 114701, 4659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ううー\n食べ過ぎて帯が\nきつくなってきたぞ…", 0, 7, 0, 3, 1, 1, 114701, 4661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おみくじって\n書いてあることが\nむずかしいんだよな…", 0, 8, 0, 3, 1, 1, 114701, 4662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困ってる人は\nいないみたいだし…\nちょっとここで、\n特訓しようかな♪", 0, 1, 0, 1, 1, 1, 180101, 4664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("空が飛べるんだから\nもっとたくさんの人を\n助けにいけちゃう！\n…ここじゃ飛べないや", 0, 2, 0, 1, 1, 1, 180101, 4665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("炎の翼\nかっこいいなー！\nこれ、もっと大きく\nできないのかな？", 0, 3, 0, 1, 1, 1, 180101, 4666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり変身すると\nお腹すくんだね…\n…今ならペコさんの\n食欲の理由が分かるよ", 0, 4, 0, 1, 1, 1, 180101, 4667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色なんかは違うけど…\nマントがあるから\n騎士くんとお揃いに\nなったみたい♪", 0, 5, 0, 1, 1, 1, 180101, 4668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…騎士くんがいないと\nなんか調子でない…\n早く会いたいよぉ…", 0, 101, 0, 1, 4, 1, 180101, 4669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿になると、\n騎士くんを近くに\n感じる…なんだろ\nドキドキしちゃう…", 0, 102, 0, 1, 8, 1, 180101, 4670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くん騎士くん！\n今大丈夫？\nトレーニングメニュー\n考えるの手伝って！", 0, 1, 0, 2, 1, 1, 180101, 4671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…うにゃっ！？\nこ、この姿になっても\n尻尾は触っちゃ\nダメー！", 0, 2, 0, 2, 1, 1, 180101, 4672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしかして、この服が\n気になってるの？\nだったら、もっと\n近くで見ていいよ♪", 0, 3, 0, 2, 1, 1, 180101, 4673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、騎士くん！\n困ってる人がいないか\n見回りに行くんだけど\nついてきて欲しいな！", 0, 4, 0, 2, 1, 1, 180101, 4674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("耳に触りたいの？\nだったら頭もなでて！\nそしたら、好きなだけ\n触っていいよ♪", 0, 101, 0, 2, 4, 1, 180101, 4675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あたし、強くなって\n騎士くんを守るよ！\nだから…これからも\n一緒にいていい？", 0, 102, 0, 2, 8, 1, 180101, 4676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっはよー！\nさあさあ騎士くん！\n今日も一緒に\nはりきっていこー♪", 0, 1, 1, 2, 1, 1, 180101, 4677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼、お昼～♪\n今日のご飯は何かな～\nあ、騎士くん！\n早くお昼食べ行こ！", 0, 2, 2, 2, 1, 1, 180101, 4678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もお疲れ様ー！\n騎士くん、あたしが\nマッサージしよっか？\n結構評判なんだよ！", 0, 3, 3, 2, 1, 1, 180101, 4679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うにゃぁ…\nこの気持ちよさ…\n溶けちゃいそう…\nにゃぁ…", 0, 2, 0, 3, 1, 1, 180101, 4681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい～\nこれ、なでなで\nしていいんだよね…？\nよしよし…♪", 0, 3, 0, 3, 1, 1, 180101, 4682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とってもいい香り！\n気分も落ち着くし、\n特訓の後なんかに\nいいかもー！", 0, 4, 0, 3, 1, 1, 180101, 4683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬくぬくだぁ…\nなんだか、\nふにゃふにゃに\nなっちゃうよぉ…", 0, 5, 0, 3, 1, 1, 180101, 4684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、おいひぃ…！\nこの姿になると\nお腹すくし、すっごく\n助かっちゃった！", 0, 7, 0, 3, 1, 1, 180101, 4686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本で勉強して、\nぶんぶりょーどーの\n超ウルトラヒヨリに\nなっちゃうぞー！", 0, 8, 0, 3, 1, 1, 180101, 4687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年もみんなで\nおいしいものを\nたくさん食べたいです", 0, 1, 0, 1, 1, 1, 111801, 4689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("挑戦は大切ですよね☆\nというわけで\nおせちに魔物を…", 0, 2, 0, 1, 1, 1, 111801, 4690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせちは縁起物です！\n食べれば食べるほど\n幸せになるはずです！", 0, 3, 0, 1, 1, 1, 111801, 4691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ物がたくさん\n入った福袋は\nないんでしょうか…？", 0, 4, 0, 1, 1, 1, 111801, 4692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣で何を\nお願いしましょう…\n五穀豊穣？", 0, 5, 0, 1, 1, 1, 111801, 4693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっとこうして\n年の始まりを\n過ごしたいですね", 0, 101, 0, 1, 4, 1, 111801, 4694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか二人きりで\n初日の出を\n見たいです", 0, 102, 0, 1, 8, 1, 111801, 4695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お餅おかわりです！\nいくらでも\n食べられますよ！", 0, 1, 0, 2, 1, 1, 111801, 4696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせちの食材を\n取りに行きませんか？\nいい運動です☆", 0, 2, 0, 2, 1, 1, 111801, 4697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("凧揚げって\n難しいですね～\n糸が絡まっちゃいます", 0, 3, 0, 2, 1, 1, 111801, 4698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一年の計は元旦にあり\n今年一年分の\n献立を作りましょう！", 0, 4, 0, 2, 1, 1, 111801, 4699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほらほら！\nもっと近くで着物を\n見ていいんですよ☆", 0, 101, 0, 2, 4, 1, 111801, 4700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたはどんな\n初夢を見ましたか？\nわたしは…内緒です☆", 0, 102, 0, 2, 8, 1, 111801, 4701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年明けの朝は\n心なしか\n気持ちいいですね☆", 0, 1, 1, 2, 1, 1, 111801, 4702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お雑煮のあとは\nおしるこで\nおやつタイムです！", 0, 2, 2, 2, 1, 1, 111801, 4703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかくして\n幸せな初夢を\n見ましょうね", 0, 3, 3, 2, 1, 1, 111801, 4704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～屋台巡りを\n満喫しました☆\n一休み一休み", 0, 2, 0, 3, 1, 1, 111801, 4706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("縁起のいい\nぬいぐるみを並べて\n福を呼びましょう！", 0, 3, 0, 3, 1, 1, 111801, 4707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おしるこのアロマって\nないんでしょうか？\nそれなら作るしか…", 0, 4, 0, 3, 1, 1, 111801, 4708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでお餅を\n焼いたらおいしく\nなりそうですね～♪", 0, 5, 0, 3, 1, 1, 111801, 4709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしすぎて\n食べる手が\n止まりません～", 0, 7, 0, 3, 1, 1, 111801, 4711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいおせち料理の\nヒントは…なるほど…\nふむふむ…", 0, 8, 0, 3, 1, 1, 111801, 4712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんとあんな\n特訓やこんな特訓が\nしたいなぁ、えへへ♪", 0, 103, 0, 1, 12, 1, 100601, 4714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんに褒めて\nもらうと、身体が\nじぃーんと\n熱くなっちゃいます♪", 0, 103, 0, 2, 12, 1, 100601, 4715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見目麗しい衣装に\n身を包むのも\n悪い気分では\nありませんね", 0, 1, 0, 1, 1, 1, 115001, 4716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("縁起物で\n験を担ぐというのも\nたまにはよいでしょう", 0, 2, 0, 1, 1, 1, 115001, 4717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("非効率なので\nあまり行いませんが\n私も手料理くらいは\n作れるのですよ", 0, 3, 0, 1, 1, 1, 115001, 4718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("研究のためなら\n時に遠路を超え\n実地へ赴くことも\n必要なのです", 0, 4, 0, 1, 1, 1, 115001, 4719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トゥンヌスの\n突然変異…\n大いに興味を\nそそられますね", 0, 5, 0, 1, 1, 1, 115001, 4720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("漁師の技法も\n再現できたことで\nまた一つ、仮説が\n実証できました", 0, 101, 0, 1, 4, 1, 115001, 4721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月くらいは\n私ものんびりしたい\n気持ちなのですよ\n意外ですか？", 0, 102, 0, 1, 8, 1, 115001, 4722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("模倣に頼らずとも\n衣装に合わせた\n所作程度は\nできて当然です", 0, 1, 0, 2, 1, 1, 115001, 4723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お年玉の使い道は\n思いつきましたか\nゆっくり考えても\nいいのですよ", 0, 2, 0, 2, 1, 1, 115001, 4724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トランプでも花札でも\n相手をしましょう\n手心が必要なら\nいつでも言いなさい", 0, 3, 0, 2, 1, 1, 115001, 4725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣でお祈りする\n内容ですか\n…ヒミツ、として\nおきましょう", 0, 4, 0, 2, 1, 1, 115001, 4726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちでオーマ中の\nトゥンヌスを\n釣り上げましょうか\n…冗談ですよ", 0, 101, 0, 2, 4, 1, 115001, 4727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見返りを求めない願い\nそれは祈りに通じるの\nかもしれませんね", 0, 102, 0, 2, 8, 1, 115001, 4728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…貴方がその眠たげな\n顔を洗ってくる間に、\n温かいお茶でも\n淹れておきましょう", 0, 1, 1, 2, 1, 1, 115001, 4729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、本格的に\n活動を再開します\n貴方も同行しなさい\n昼食は済みましたか？", 0, 2, 2, 2, 1, 1, 115001, 4730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私はもう少し\n作業を片付けてから\n寝ることにします\n早く眠りなさい", 0, 3, 3, 2, 1, 1, 115001, 4731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し休みます…\n時間が来たら\n起こすように", 0, 2, 0, 3, 1, 1, 115001, 4733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("贈り物を模倣して\n潜入…試してみる\n価値はありそうですね", 0, 3, 0, 3, 1, 1, 115001, 4734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("嗅覚から得られる\n情報量は侮れません\n動物の模倣において\n注意すべき点ですよ", 0, 4, 0, 3, 1, 1, 115001, 4735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("穏やかな炎による\nリラックス効果は\n本能によるものかも\nしれませんね", 0, 5, 0, 3, 1, 1, 115001, 4736);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いかなる強者でも\n兵站、補給は\n必要なものです", 0, 7, 0, 3, 1, 1, 115001, 4738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらゆる学問は\n完璧な模倣のための\n大きな礎となります", 0, 8, 0, 3, 1, 1, 115001, 4739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新たに得たこの力で\n仲間と目指す未来を\n切り拓いてみせます", 0, 1, 0, 1, 1, 1, 115501, 4741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは、みなさまと…\nわたくしの\n帰る場所でございます", 0, 2, 0, 1, 1, 1, 115501, 4742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまも精霊の召喚を\n試してみますか？", 0, 3, 0, 1, 1, 1, 115501, 4743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、おこづかいは\n足りていますか？\n遠慮は無用ですよ", 0, 4, 0, 1, 1, 1, 115501, 4744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この装束をまとうと\n自然と背筋が伸びる\n思いがいたします", 0, 5, 0, 1, 1, 1, 115501, 4745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("進化した精霊に\n負けぬよう\n修行に励みます", 0, 101, 0, 1, 4, 1, 115501, 4746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間たちといられる\nこの幸せが、末永く\n続きますように…", 0, 102, 0, 1, 8, 1, 115501, 4747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのお手手は\n大きくて温かいですね\nぎゅっぎゅっ…ふふ♪", 0, 1, 0, 2, 1, 1, 115501, 4748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、主さまにも\n里に伝わる昔話を\nお話しいたしましょう", 0, 2, 0, 2, 1, 1, 115501, 4749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("里で採れた果物を\n持って参りました\n召し上がってください", 0, 3, 0, 2, 1, 1, 115501, 4750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("里のお土産を\nここのみなさまに\nお配りいたしましょう", 0, 4, 0, 2, 1, 1, 115501, 4751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間と囲む食卓…この\n温もりは、みなさまの\n心の温かさなのですね", 0, 101, 0, 2, 4, 1, 115501, 4752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまに名前を\n呼んでいただくと\n心が温かくなります♪", 0, 102, 0, 2, 8, 1, 115501, 4753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…主さま\n寝癖がついて\nおりますよ？", 0, 1, 1, 2, 1, 1, 115501, 4754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の昼食は\n里の伝統料理です\nお口に合うでしょうか", 0, 2, 2, 2, 1, 1, 115501, 4755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまが眠れるよう\n安らぎの風を…\nおやすみなさいませ", 0, 3, 3, 2, 1, 1, 115501, 4756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この癒し…\n主さまにも味わって\nいただきたい…", 0, 2, 0, 3, 1, 1, 115501, 4758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この愛らしさ…\n精霊たちと似たものを\n感じます…♪", 0, 3, 0, 3, 1, 1, 115501, 4759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊よ…この安らぐ\n香りを、隅々まで\n届けてくださいまし", 0, 4, 0, 3, 1, 1, 115501, 4760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("瞑想するのに\nちょうどよい暖かさで\nございます", 0, 5, 0, 3, 1, 1, 115501, 4761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("進化した精霊を\n使役するためにも\nよく食べて体力を…！", 0, 7, 0, 3, 1, 1, 115501, 4763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風の精霊について\nもっと詳しく知って\nおかなければ…", 0, 8, 0, 3, 1, 1, 115501, 4764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("儀式の時を思い出して\n精霊に呼びかける…\n出ておいで～♪", 0, 1, 0, 1, 1, 1, 115601, 4766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃうっ！　もう…\n急に背中を触るなんて\nいたずら好きな精霊に\n育てた覚えはないのに", 0, 2, 0, 1, 1, 1, 115601, 4767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("儀式用の衣装…\nあんまり激しい動きは\nできないよね…でも\n戦う時は気にしない！", 0, 3, 0, 1, 1, 1, 115601, 4768);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ…精霊に\n騎士クンのそばで\n見守っていてって\n頼んでみようかな…", 0, 4, 0, 1, 1, 1, 115601, 4769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、こうやって、\n楽しく精霊とお話し\nしていられる、平穏な\n日々が続くといいな", 0, 5, 0, 1, 1, 1, 115601, 4770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("き、きき、騎士クン！\nわたしと、あの…！\nうう…練習ですら\n上手く誘えないよぉ…", 0, 101, 0, 1, 4, 1, 115601, 4771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、精霊が…\nふふ、応援ありがとう\nわたしの想い…いつか\n必ず伝えるね", 0, 102, 0, 1, 8, 1, 115601, 4772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しく覚えた料理\n作ってみたんだけど\n騎士クンも食べない？", 0, 1, 0, 2, 1, 1, 115601, 4773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン、\n疲れてない？\nわたしと精霊で\n治療するよ？", 0, 2, 0, 2, 1, 1, 115601, 4774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう、いたずらしない\n…騎士クン！？\nご、ごめんなさい！\n精霊だと思って！", 0, 3, 0, 2, 1, 1, 115601, 4775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン！\n時間が合ったら、\n精霊と一緒に\nお話しない？", 0, 4, 0, 2, 1, 1, 115601, 4776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…こういう服着るの\n初めてなんだけど…\nえっ、かわいい…？\nあ、ありがとう…！", 0, 101, 0, 2, 4, 1, 115601, 4777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困ったことがあったら\n相談してね。わたし、\n騎士クンのためなら…\n色々できるよ、色々！", 0, 102, 0, 2, 8, 1, 115601, 4778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう騎士クン！\n今からお外で\n瞑想するんだけど…\n騎士クンもどうかな？", 0, 1, 1, 2, 1, 1, 115601, 4779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼の時間だ\nご飯ならわたしが\n用意するから\nゆっくりしてて", 0, 2, 2, 2, 1, 1, 115601, 4780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\n騎士クン、はいどうぞ\n寝る前の温かいミルク\nぐっすり眠れるよ♪", 0, 3, 3, 2, 1, 1, 115601, 4781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…うん、落ち着く\n精霊との魔法で\nこんな風に誰かを\n安心させたいな", 0, 2, 0, 3, 1, 1, 115601, 4783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい…\n精霊も気に入ってる…\nそうだ、同じ物\n作ってあげようかな？", 0, 3, 0, 3, 1, 1, 115601, 4784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…これ、\nうちに置いたら、\nお母さん喜ぶかも！", 0, 4, 0, 3, 1, 1, 115601, 4785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nまるで誰かが\n抱きしめてくれた\nみたい…", 0, 5, 0, 3, 1, 1, 115601, 4786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自然の恵みに\n感謝して…\nいただきます♪", 0, 7, 0, 3, 1, 1, 115601, 4788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっと精霊について\n勉強して、みんなを\n守れるように\nなりたいな…", 0, 8, 0, 3, 1, 1, 115601, 4789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツといると胸が\nぎゅーっとなる…\nこれってもしかして…", 0, 103, 0, 1, 12, 1, 102201, 4791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタとならきっと\nどんなゲームでも…\nそ、その、たた、\n楽しいって思えるわ！", 0, 103, 0, 2, 12, 1, 102201, 4792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色んな人と話したら\n記憶探しの手がかりが\n見つかるかも…？", 0, 1, 0, 1, 1, 1, 106401, 4793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイスクリームでも\n作ろうかしら？\nバニラにミントに…", 0, 2, 0, 1, 1, 1, 106401, 4794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネビアに話しかけると\n逃げられるのよね…\nもう、襲わないのに…", 0, 3, 0, 1, 1, 1, 106401, 4795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「コッコロさん」、\n「コッコロさん」…\n…間違えないように…", 0, 4, 0, 1, 1, 1, 106401, 4796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近少し太ったかも？\nきっとおいしいもの、\n食べ過ぎね…", 0, 5, 0, 1, 1, 1, 106401, 4797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると、\nとても落ち着くわ…\n自分の家、だものね", 0, 101, 0, 1, 4, 1, 106401, 4798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなと一緒の時間、\nずっと記憶に残したい\n…そう思っているのよ", 0, 102, 0, 1, 8, 1, 106401, 4799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドラゴン族って、\nそんなに珍しいの？\nあまり実感ないけど…", 0, 1, 0, 2, 1, 1, 106401, 4800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理、練習してるのよ\n…味見してもらえる？\n期待はしないでね", 0, 2, 0, 2, 1, 1, 106401, 4801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭を叩いたら、\n記憶が戻ったり\nしないかしら…？\nやらなくていいわよ？", 0, 3, 0, 2, 1, 1, 106401, 4802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("赤ちゃんみたいだった\n時のことは、忘れて…\nお願いだから…", 0, 4, 0, 2, 1, 1, 106401, 4803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃんっ！？\nし、しっぽを掴むのは\nダメよ？", 0, 101, 0, 2, 4, 1, 106401, 4804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("記憶が戻っても…\n私は、あなたたちと\n一緒にいたいわ", 0, 102, 0, 2, 8, 1, 106401, 4805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう。\n寝ぐせついてるわよ？\n…ふふっ、これでよし", 0, 1, 1, 2, 1, 1, 106401, 4806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろお昼かしら？\nおいしいごはんを、\nみんなで一緒に…ね", 0, 2, 2, 2, 1, 1, 106401, 4807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間ね。\nそろそろ休みましょ？\n…ふわぁ…", 0, 3, 3, 2, 1, 1, 106401, 4808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか、ぎゅう～…\n…あっ、これはその…\nストレッチしててっ…", 0, 2, 0, 3, 1, 1, 106401, 4810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あまり、興味ないわ。\nけど…けど…\n…か、かわいい…", 0, 3, 0, 3, 1, 1, 106401, 4811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね。\nとっても落ち着くわ…\n…っくしゅっ", 0, 4, 0, 3, 1, 1, 106401, 4812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷やす方が得意だけど\nあったかいのも、\nキライじゃないのよ", 0, 5, 0, 3, 1, 1, 106401, 4813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("別に、食いしん坊\nじゃないのよ？\nでも、もう一口だけ…", 0, 7, 0, 3, 1, 1, 106401, 4815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん…なるほどね。\n勉強になるわ…", 0, 8, 0, 3, 1, 1, 106401, 4816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着の探偵か…\nちょっと恥ずかしい\n気がしてきたよ…", 0, 1, 0, 1, 1, 1, 115701, 4818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("依頼があれば\n海でも山でも\n赴くさ！", 0, 2, 0, 1, 1, 1, 115701, 4819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今のうちに\n助手くんの秘密を…\nわ…私はなにをっ！？", 0, 3, 0, 1, 1, 1, 115701, 4820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休暇も時には必要さ\n海でゆっくりと…\nむっ？　事件の気配！", 0, 4, 0, 1, 1, 1, 115701, 4821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("探偵の秘密道具…\n水着だと隠す\n場所がない…！", 0, 5, 0, 1, 1, 1, 115701, 4822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ助手くんが\n現れる時間かな？\nふふっ、楽しみだね", 0, 101, 0, 1, 4, 1, 115701, 4823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真実は私と助手くん\n二人だからこそ\n解き明かせるのさ", 0, 102, 0, 1, 8, 1, 115701, 4824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃああっ！？\nわ、私の不意を突く\nとは…やるね助手くん", 0, 1, 0, 2, 1, 1, 115701, 4825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、なにか気づいた\nことはあるかな？\n言ってごらん♪", 0, 2, 0, 2, 1, 1, 115701, 4826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この感触…分かった！\n助手くんだね！\nふふっ、やっぱり♪", 0, 3, 0, 2, 1, 1, 115701, 4827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着…どうかな？\n探偵らしさは\n残してるつもりだけど", 0, 4, 0, 2, 1, 1, 115701, 4828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　依頼かな？\n助手くんの頼みなら\nなんでもお安い御用さ", 0, 101, 0, 2, 4, 1, 115701, 4829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くん、私と海に\n行かないかな\n…事件じゃないよ？", 0, 102, 0, 2, 8, 1, 115701, 4830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("珈琲でも淹れて\n目を覚ますとしよう\n一緒に飲むかい？", 0, 1, 1, 2, 1, 1, 115701, 4831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食は済ませた？\nなにを食べたか\n当ててあげよう！", 0, 2, 2, 2, 1, 1, 115701, 4832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は謎が深まる時間…\n闇に覆い隠された真実\n必ず暴いてみせる！", 0, 3, 3, 2, 1, 1, 115701, 4833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、推理の時間だ\n…サボってないよ？\n考えてるんだからね？", 0, 2, 0, 3, 1, 1, 115701, 4835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはもしや、中に\n秘密のメッセージが？\n…かわいいだけだね", 0, 3, 0, 3, 1, 1, 115701, 4836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、なんだか\n頭がスッキリするね\n…閃いた！", 0, 4, 0, 3, 1, 1, 115701, 4837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカするね…\n助手くん\n君もおいでよ", 0, 5, 0, 3, 1, 1, 115701, 4838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむ、はむ…んぐっ\nた、食べてるところを\n見つめられると～…", 0, 7, 0, 3, 1, 1, 115701, 4840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("秘密の依頼とか\nこういう場所に\n隠したりするよね…♪", 0, 8, 0, 3, 1, 1, 115701, 4841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはいい乗り心地だ\n事件現場にこれで登場\n…は、やめておこう", 0, 10, 0, 3, 1, 1, 115701, 4843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不思議な感触だね…\nでも、いい発想が\n生まれてきそうだ…♪", 0, 11, 0, 3, 1, 1, 115701, 4844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはあたしが\n前へ進むために\nあいつがくれた\n大切な力…！", 0, 1, 0, 1, 1, 1, 180601, 4845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チェンジ・\nプリンセスフォーム！\n練習練習、っと", 0, 2, 0, 1, 1, 1, 180601, 4846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうあいつに助けて\nもらいっぱなしの\nあたしは…\n卒業しなきゃね", 0, 3, 0, 1, 1, 1, 180601, 4847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気ままに、お気楽に\nあいつと冒険する…\nそれって幸せよね", 0, 4, 0, 1, 1, 1, 180601, 4848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスフォーム…\nお姫様みたいね\nあたしがお姫様か…\nそっかぁ…ふふ♪", 0, 5, 0, 1, 1, 1, 180601, 4849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと繋がって\n生まれたこの絆は\nあたしの宝物だわ", 0, 101, 0, 1, 4, 1, 180601, 4850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの命の使い方…\n全て受け止めてくれた\nあいつにだったら…", 0, 102, 0, 1, 8, 1, 180601, 4851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ～ん♪\nプリンセスフォームの\n天才魔法使い\nキャル様に用かしら？", 0, 1, 0, 2, 1, 1, 180601, 4852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからは\nあたしの力で\nなんでもパパっと\n解決してあげるわね！", 0, 2, 0, 2, 1, 1, 180601, 4853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔力がみなぎってる…\nねえ、もしかして\n今のあたしって本気で\nすごいんじゃない？", 0, 3, 0, 2, 1, 1, 180601, 4854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身の反動で\nお腹が空いても\n魔物料理だけは\nいやだからね！？", 0, 4, 0, 2, 1, 1, 180601, 4855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、あんたになら\nあたしの心…\n全部預けていいかも", 0, 101, 0, 2, 4, 1, 180601, 4856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと一緒に\nいられたら、他には\n何も…って、あああ\nあんたいつの間に！？", 0, 102, 0, 2, 8, 1, 180601, 4857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きも悪くないわね\n読みかけの魔導書\n今のうちに\n読んじゃおうかしら", 0, 1, 1, 2, 1, 1, 180601, 4858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ～お腹すいたー\nあんたなんか\n作りなさいよ\n魔物料理以外でね！", 0, 2, 2, 2, 1, 1, 180601, 4859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁぁ…眠すぎて\n今なら変身しても\nお腹が減らない\n自信があるわ…", 0, 3, 3, 2, 1, 1, 180601, 4860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あー♪　最っ高！\n休んで魔力を高めて…\nあいつの役に\n立ってあげなきゃね", 0, 2, 0, 3, 1, 1, 180601, 4862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにこれかわいい…！\nコレクションにしたく\nなっちゃうじゃない", 0, 3, 0, 3, 1, 1, 180601, 4863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…すごく\nリラックスできるわ…\nあ、いい感じの魔法\n思いついちゃったかも", 0, 4, 0, 3, 1, 1, 180601, 4864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\n落ち着くわ…\nあいつの手の\nぬくもりみたいね", 0, 5, 0, 3, 1, 1, 180601, 4865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスフォーム…\nこ、こんなに\nお腹が減るのね\n甘く見てたわ…！", 0, 7, 0, 3, 1, 1, 180601, 4867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ま、魔物料理の本！？\n誰よこんな本\n買ったの！　って…\n一人しかいないか", 0, 8, 0, 3, 1, 1, 180601, 4868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("憧れの舞踏会…\n私、きちんと\n踊れるかしら", 0, 1, 0, 1, 1, 1, 115801, 4870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アン・ドゥ・トロワ\nアン・ドゥ・トロワ\n練習はばっちりね♪", 0, 2, 0, 1, 1, 1, 115801, 4871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにすてきな\nドレスを着られて\n本当に夢みたいだわ♪", 0, 3, 0, 1, 1, 1, 115801, 4872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法はいつか解ける…\nでも、その時間は心に\n残り続けるわ♪", 0, 4, 0, 1, 1, 1, 115801, 4873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガラスの靴は夢へ\n踏み出す魔法の道具…\n私、がんばっちゃう！", 0, 5, 0, 1, 1, 1, 115801, 4874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞踏会であなたと\n一緒に踊れたら\nいいのにな", 0, 101, 0, 1, 4, 1, 115801, 4875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞踏会に行く前に\n運命の王子様には\n出会ってるのよね", 0, 102, 0, 1, 8, 1, 115801, 4876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしら？\n私、きちんとドレス\n着られてる？", 0, 1, 0, 2, 1, 1, 115801, 4877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたも一緒に\n踊ってみる？\nしゃなりしゃなり♪", 0, 2, 0, 2, 1, 1, 115801, 4878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたにエスコート\nされてきれいなお城を\n歩いてみたいわ♪", 0, 3, 0, 2, 1, 1, 115801, 4879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どう？　レッスンの\n成果はきちんと\n出てるかしら？", 0, 4, 0, 2, 1, 1, 115801, 4880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたが隣にいれば\n私も立派なお姫様に\n見えるかしら♪", 0, 101, 0, 2, 4, 1, 115801, 4881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私にとって\n一番の魔法はあなたが\nくれる勇気よ♪", 0, 102, 0, 2, 8, 1, 115801, 4882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁ！　今日も一日\n立派な淑女を目指して\nいきましょう♪", 0, 1, 1, 2, 1, 1, 115801, 4883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはん代わりに\nメタモルアップルを\n食べておきましょう", 0, 2, 2, 2, 1, 1, 115801, 4884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ魔法が解ける\n時間…でも淑女の\n心得は忘れないわ♪", 0, 3, 3, 2, 1, 1, 115801, 4885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("淑女にも休息は\n必要よね…少しだけ\n休ませてもらおっと", 0, 2, 0, 3, 1, 1, 115801, 4887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいものに\n囲まれた部屋も\n女の子の夢よね…", 0, 3, 0, 3, 1, 1, 115801, 4888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すてきな香り…\nお花かしら？\n森で探してみようかな", 0, 4, 0, 3, 1, 1, 115801, 4889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かい…暖炉のそばで\nおとぎ話を聞くのも\nいいわよね♪", 0, 5, 0, 3, 1, 1, 115801, 4890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンのために\n栄養補給して\nおかないと！", 0, 7, 0, 3, 1, 1, 115801, 4892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("教養を身に着ける\nことも大切よね！\nなになに…", 0, 8, 0, 3, 1, 1, 115801, 4893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("や、やっぱスカートは\n落ち着かねえな…\nなんか、\nスースーするしよ…", 0, 1, 0, 1, 1, 1, 115901, 4895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくこんな格好\nしてるし、いつもとは\n違う剣術の訓練を\nしてみるかな", 0, 2, 0, 1, 1, 1, 115901, 4896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、他の連中が\n帰ってくる前に、\nなんか料理でも\n作っといてやるか", 0, 3, 0, 1, 1, 1, 115901, 4897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、こんな服着てる\nわけだし、紅茶とか\n楽しんじゃっても\n変じゃないよな！", 0, 4, 0, 1, 1, 1, 115901, 4898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし運動でも…\nあ、あぶねえ！\nスカートなの忘れてた\n…誰も見てねえよな？", 0, 5, 0, 1, 1, 1, 115901, 4899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("紅茶が切れてるな…\nよし、あいつと一緒に\n買い物にでも行くか♪", 0, 101, 0, 1, 4, 1, 115901, 4900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あいつがいねえと、\nつまんねえな…ったく\n飯用意してやるから、\n早く帰ってこいよな…", 0, 102, 0, 1, 8, 1, 115901, 4901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あんまり\nジロジロ見んなよ\n…結構、\n恥ずかしいんだからな", 0, 1, 0, 2, 1, 1, 115901, 4902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダンスの相手は\n無理だが、\n剣の訓練なら\nいつでも付き合うぜ！", 0, 2, 0, 2, 1, 1, 115901, 4903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服に\n触りたいのか？\nすごい作りだし、\n気持ちは分かるぜ", 0, 3, 0, 2, 1, 1, 115901, 4904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、いいところに！\nクッキーを焼く\nところだったんだが、\nおまえも食うか？", 0, 4, 0, 2, 1, 1, 115901, 4905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おまえにもこういう服\n似合うんじゃねえか？\n今度あたしが\n選んでやるよ♪", 0, 101, 0, 2, 4, 1, 115901, 4906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…おまえの前でなら、\nこういう格好を\nすんのも…\nな、なんでもねえよ！", 0, 102, 0, 2, 8, 1, 115901, 4907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の訓練を始めるか\n時間あるなら、\nおまえも付き合えよな", 0, 1, 1, 2, 1, 1, 115901, 4908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間か…\n昼飯作るけど、\nなんか\n食いたいものあるか？", 0, 2, 2, 2, 1, 1, 115901, 4909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠れないなら、\nホットミルク飲むか？\n体あったまって、\n眠くなると思うぜ", 0, 3, 3, 2, 1, 1, 115901, 4910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと休憩して…\nおっと、服にしわが\nできないように\nしねえとな", 0, 2, 0, 3, 1, 1, 115901, 4912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("だ、誰も\n見てねえよな？\n…よ～しよしよし、\nかわいいなおまえー♪", 0, 3, 0, 3, 1, 1, 115901, 4913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すげぇいい香りだな\nうちの居酒屋にも…\nいや、合わねえか", 0, 4, 0, 3, 1, 1, 115901, 4914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったけぇ…\nちょっとだけなら、\n寝ちまっても\nいいよな…？", 0, 5, 0, 3, 1, 1, 115901, 4915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これうめえな！\nたぶん材料は…よし！\nあたしも作ってみるか", 0, 7, 0, 3, 1, 1, 115901, 4917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本は…\n誰でも分かる作法…か\n最低限このぐらいは\n勉強しとくか…", 0, 8, 0, 3, 1, 1, 115901, 4918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミがおとなに\nなっても\nおにいちゃんとは\nずーっといっしょ♪", 0, 103, 0, 1, 12, 1, 102001, 4920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミとくべつなだっこ\nしてほしいな…うん！\nおひめさまだっこ～♪", 0, 103, 0, 2, 12, 1, 102001, 4921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はにいちゃんに\nどんなイタズラしよう\n早く会いたいな～", 0, 103, 0, 1, 12, 1, 100401, 4922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギの特別な\nイタズラ見てくれる？\nいいよねっ♪", 0, 103, 0, 2, 12, 1, 100401, 4923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人になったら、\nあの人と何しようかな\n…楽しみだなぁ", 0, 103, 0, 1, 12, 1, 103601, 4924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭を撫でないで\nください！　もう、\n少しだけ、ですからね", 0, 103, 0, 2, 12, 1, 103601, 4925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くるくる〜♪\nうちのドレス\nかわええなぁ", 0, 1, 0, 1, 1, 1, 116001, 4926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日差しは苦手やけど\nたまにはひなたの下で\nぽかぽかしたいわぁ", 0, 2, 0, 1, 1, 1, 116001, 4927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外はお花が咲いてる\n久しぶりにお花を\n活けたいなぁ", 0, 3, 0, 1, 1, 1, 116001, 4928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花をたくさん集めて\nギルドハウスに飾れば\n喜んでくれはるかな", 0, 4, 0, 1, 1, 1, 116001, 4929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい日は\n紅茶を飲みながら\nゆっくりしたいなぁ", 0, 5, 0, 1, 1, 1, 116001, 4930);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お稽古事を始めるなら\nうちに言ってな\nどんなことも教えたる", 0, 101, 0, 1, 4, 1, 116001, 4931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちにいろんな夢を\n見せてくれはって\nほんま、おおきにな♪", 0, 102, 0, 1, 8, 1, 116001, 4932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はん\n一緒におとぎの国へ\nお散歩にいきまひょ♪", 0, 1, 0, 2, 1, 1, 116001, 4933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんふんふ〜ん♪\n今な、王子はんに\n花冠を作ってるんよ", 0, 2, 0, 2, 1, 1, 116001, 4934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんは\nお菓子好きどす？\nうち、作りますわ", 0, 3, 0, 2, 1, 1, 116001, 4935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん。ドレスの柄は\nお花とお星さま\nどっちにしまひょか", 0, 4, 0, 2, 1, 1, 116001, 4936);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんとの\n思い出が増えるたび\nうちの宝物も増えます", 0, 101, 0, 2, 4, 1, 116001, 4937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんと一緒なら\nどんな場所でも\n夢の国になりますわ", 0, 102, 0, 2, 8, 1, 116001, 4938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夢の中におりたいけど\n王子はんに会いたくて\n起きてもうたわ♪", 0, 1, 1, 2, 1, 1, 116001, 4939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はん一緒に\nアフタヌーンティー\nいかがやろか？", 0, 2, 2, 2, 1, 1, 116001, 4940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の舞踏会…\n夢が広がるわぁ\nもちろんお相手は…♪", 0, 3, 3, 2, 1, 1, 116001, 4941);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわや〜\nなんや心地よぉて\n眠ってしまいそうや…", 0, 2, 0, 3, 1, 1, 116001, 4943);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かいらしいなぁ\n新しいお洋服でも\n作ってあげまひょか♪", 0, 3, 0, 3, 1, 1, 116001, 4944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花やろうか…\nリラックスできて\nええ香りやねぇ", 0, 4, 0, 3, 1, 1, 116001, 4945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう場所で\n絵本を読むと\n気分が出てええなぁ♪", 0, 5, 0, 3, 1, 1, 116001, 4946);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞踏会を楽しむなら\nたくさん食べて\nたくさん踊りまひょ", 0, 7, 0, 3, 1, 1, 116001, 4948);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うち、この本好きや\n王子さまと結ばれる\nお姫さまのお話なんよ", 0, 8, 0, 3, 1, 1, 116001, 4949);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、宿題めんどい…\nこれは楽しくない…\nこんな青春いらない…", 0, 1, 0, 1, 1, 1, 116301, 4951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("奨学金の道は遠いなぁ\nメルクリちゃんたちが\nお金くれればいいのに", 0, 2, 0, 1, 1, 1, 116301, 4952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アオイちゃん元気かな\nチエルに会いたくて\n泣いてるんだろうな…", 0, 3, 0, 1, 1, 1, 116301, 4953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし鏡でも見るか…\nうわ、顔良っ！\nえ誰この超絶美少女！", 0, 4, 0, 1, 1, 1, 116301, 4954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワンツーワンツー♪\nうーん…カルミナの\n振りコピ難しいにゃー", 0, 5, 0, 1, 1, 1, 116301, 4955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩も運動してます？\nチエルが一緒に走って\nあげてもいいですよ？", 0, 101, 0, 1, 4, 1, 116301, 4956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年のテレフェスも\n今から楽しみだなあ…\nまた一緒にお化け屋敷\n入ってくださいね", 0, 102, 0, 1, 8, 1, 116301, 4957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちぇる～ん☆\nフェス仕様でも\nかわいいちえるん！", 0, 1, 0, 2, 1, 1, 116301, 4958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いま話しかけないで！\n来年の聖学祭ライブの\nイメトレ中なんです！", 0, 2, 0, 2, 1, 1, 116301, 4959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クロエ先輩のウェア姿\nめっちゃカッコよ！\n思わずおへそ触ったら\nぶたれましたけど", 0, 3, 0, 2, 1, 1, 116301, 4960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユニ先輩の体操着姿…\nあれはあれで実に良き\n一生見てられますよね", 0, 4, 0, 2, 1, 1, 116301, 4961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩って体操着持って\nないんですか？　ハ？\nチエルのを貸せと…？\nえっ…変態かな？", 0, 101, 0, 2, 4, 1, 116301, 4962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テレフェスでは先輩も\n地味に頑張ってました\nね。まあ格好よかった\nんじゃないですか…", 0, 102, 0, 2, 8, 1, 116301, 4963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはちぇる～ん☆\nさあ今日も楽しいを\n探しに行きますよー！", 0, 1, 1, 2, 1, 1, 116301, 4964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩ビッグニュース！\n今からお昼ごはん\nおごらせてあげます！", 0, 2, 2, 2, 1, 1, 116301, 4965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんばんちぇるるん☆\nさあ朝まで楽しいを\n探しに行きますよー！", 0, 3, 3, 2, 1, 1, 116301, 4966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…ふかふか～…\n運動の後は…眠たく…\nなり…ま…", 0, 2, 0, 3, 1, 1, 116301, 4968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユニ先輩に似合いそ！\nいやクロエ先輩かな？\nチエルは当然すぎて…", 0, 3, 0, 3, 1, 1, 116301, 4969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やん、いい香り～！\nまるでチエルのために\n存在するみたい！", 0, 4, 0, 3, 1, 1, 116301, 4970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この火を使って\n聖火リレーしましょう\n先輩、一本抜いて！", 0, 5, 0, 3, 1, 1, 116301, 4971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あむあむ…ちゃんと\n食べないとユニ先輩\nみたいになっちゃう！", 0, 7, 0, 3, 1, 1, 116301, 4973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…ちゃんと\n読まないとクロエ先輩\nみたいになっちゃう！", 0, 8, 0, 3, 1, 1, 116301, 4974);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今なら書ける気がする\n私の本当の\n想いを込めた\nラブソングを！", 0, 103, 0, 1, 12, 1, 102901, 4976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("輝きを増した私を\nいっぱい見てね！\n…ちょ、ちょっと\n見つめすぎだよ！", 0, 103, 0, 2, 12, 1, 102901, 4977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テレフェスかぁー…\nあんまいい記憶ないな\nよし、忘れとこ", 0, 1, 0, 1, 1, 1, 116201, 4978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし鏡でも見るか…\nふふ～ん…いいじゃん\nあ？　何見てんだコラ", 0, 2, 0, 1, 1, 1, 116201, 4979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワンツー、ワンツー♪\nああクソ、難しいな…\nあ？　何見てんだコラ", 0, 3, 0, 1, 1, 1, 116201, 4980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アオイ元気してるかな\nまた絶叫したり白目\n剥いたりしてんのかな", 0, 4, 0, 1, 1, 1, 116201, 4981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミフユねえさんが\nバイトリーダーしてる\n工場…うちも行くか…", 0, 5, 0, 1, 1, 1, 116201, 4982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…今日の晩御飯\n何にすっかなァ…\nあんたも食べてく？", 0, 101, 0, 1, 4, 1, 116201, 4983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年のテレフェスは\nどーなンだかねえ？\nま、一緒にまた弟の\n相手してやってよ", 0, 102, 0, 1, 8, 1, 116201, 4984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体操着なんてフツーに\n着てもつまんないし？\nその辺センス出るよね", 0, 1, 0, 2, 1, 1, 116201, 4985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("奨学金の道、遠くね？\nアキノ先輩と仲良く\nなった方が早いかも…", 0, 2, 0, 2, 1, 1, 116201, 4986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんた体操着は持って\nないの。ハ？　うちの\n貸せって？　いいけど\n…いや、よくねえよ", 0, 3, 0, 2, 1, 1, 116201, 4987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃんっ！\nや、だからさ…急に\n話しかけんなっての", 0, 4, 0, 2, 1, 1, 116201, 4988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、なに？　この服？\nハ？　似合ってる？\n…え、聞こえなかった\nちょ、もっかい言って", 0, 101, 0, 2, 4, 1, 116201, 4989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたもテレフェスで\n一応は頑張ってたよね\nま格好よかったんじゃ\nないの。知んないけど", 0, 102, 0, 2, 8, 1, 116201, 4990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～あ…おはーす\n昨日も寝たの遅くて\nまだ目がショボだよ…", 0, 1, 1, 2, 1, 1, 116201, 4991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに。あんた昼御飯\nまだなの。じゃ、うち\n適当になんか作ろうか", 0, 2, 2, 2, 1, 1, 116201, 4992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜っていいよね。色々\n見えすぎない感じとか\n…この話したっけ？", 0, 3, 3, 2, 1, 1, 116201, 4993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、ヤバ…運動の後に\nこのフカついたのは…\n秒でスヤれる…すやぁ", 0, 2, 0, 3, 1, 1, 116201, 4995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へーこんなんチエルに\n似合いそうじゃん。\n…いやユニ先輩かな？", 0, 3, 0, 3, 1, 1, 116201, 4996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、なんか良さげな\n香りじゃん。これは\n何の…いや分かんね", 0, 4, 0, 3, 1, 1, 116201, 4997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("熱ッ！　この野郎なに\n爆ぜてンだコラァ！\n濡らすぞ木、てめえ！", 0, 5, 0, 3, 1, 1, 116201, 4998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何コレよく分かんない\nけど、今日モヤシしか\n食ってないから助かる", 0, 7, 0, 3, 1, 1, 116201, 5000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日、体操着だしね。\n読書には逆アドかな。\nうん帰ろ。いやあ残念", 0, 8, 0, 3, 1, 1, 116201, 5001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビッグボス・イノリ様\nふっふっふ…\nしびれる響きです！", 0, 1, 0, 1, 1, 1, 116501, 5003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかお兄さんを\nあたしの側近に\nしてやるですよ！", 0, 2, 0, 1, 1, 1, 116501, 5004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビッグボスになったら\nみんなからたくさん\nお菓子をもらうです！", 0, 3, 0, 1, 1, 1, 116501, 5005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふん！\nこの服はあたしにしか\n着こなせませんよ！", 0, 4, 0, 1, 1, 1, 116501, 5006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ばーんと立って\nどーんと腕を組む！\nこれがボスのポーズ！", 0, 5, 0, 1, 1, 1, 116501, 5007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イノリ様の側近に\n選ばれるなんて\n名誉なことですよ！", 0, 101, 0, 1, 4, 1, 116501, 5008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("未来の側近として\nあたしをしっかり\n甘やかすですよ！", 0, 102, 0, 1, 8, 1, 116501, 5009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしがお兄さんを\n立派なギャングに\nしてあげますからね！", 0, 1, 0, 2, 1, 1, 116501, 5010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("側近たるもの\nボスを甘やかなさいと\nだめですよ！", 0, 2, 0, 2, 1, 1, 116501, 5011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに見てやがるです…\nくぅ、分かりました！\nお菓子は半分こです！", 0, 3, 0, 2, 1, 1, 116501, 5012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんも\nあたしがボスなら\nうれしいですよね！", 0, 4, 0, 2, 1, 1, 116501, 5013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんが側近なら\nあたしも安心して\n夜眠れるですよ！", 0, 101, 0, 2, 4, 1, 116501, 5014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビッグボスになったら\nお兄さんにいい思い\nさせてあげますから！", 0, 102, 0, 2, 8, 1, 116501, 5015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボスたるもの\n早起きは鉄則ですよ！\nふぁあ…", 0, 1, 1, 2, 1, 1, 116501, 5016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹が空きました…\nご飯食べにいきますよ", 0, 2, 2, 2, 1, 1, 116501, 5017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボスたるものぉ〜…\n夜更かしぐらい当然…\nぐー…", 0, 3, 3, 2, 1, 1, 116501, 5018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("は〜これは人をだめに\nしやがるやつですね\nあたし専用です", 0, 2, 0, 3, 1, 1, 116501, 5020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはけしからん\nかわいらしさですね\nあたしにぴったりです", 0, 3, 0, 3, 1, 1, 116501, 5021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("高級な香りがするです\nボスになったら\n部屋に置いてやるです", 0, 4, 0, 3, 1, 1, 116501, 5022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいですねぇ\nちょっとこのまま\n一休憩です…", 0, 5, 0, 3, 1, 1, 116501, 5023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむ♪\nボスたるもの食べねば\n戦はできませんよ！", 0, 7, 0, 3, 1, 1, 116501, 5025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボスなら経済書ぐらい\n…う。難しくて\n読めねーです…", 0, 8, 0, 3, 1, 1, 116501, 5026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたはドジな私を\n受け入れてくれる…\nだから、頑張れます！", 0, 103, 0, 1, 12, 1, 102501, 5028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何でも仰ってください\nちょっぴり大胆な\nことでも…な～んて♪", 0, 103, 0, 2, 12, 1, 102501, 5029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーあー、よし\nのどの調子もいいし\nはりきってガイド\nしてくるか！", 0, 1, 0, 1, 1, 1, 116601, 5030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、そろそろ行くか\nガイドが\n遅刻したんじゃ\n話になんないからな", 0, 2, 0, 1, 1, 1, 116601, 5031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しれっとドラゴン族が\n旅行に来たり\nしてくれないかな", 0, 3, 0, 1, 1, 1, 116601, 5032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たぎるガイド先…\n火山、魔物の巣…\nダメだ、そんなとこ\nオレしか行けないや", 0, 4, 0, 1, 1, 1, 116601, 5033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この前行った絶景\nスポットよかったな\nキレイな景色を見る\nのもいいもんだぜ", 0, 5, 0, 1, 1, 1, 116601, 5034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、今日はカレと\n一緒か。なんだか\nやる気出てきたぜ！", 0, 101, 0, 1, 4, 1, 116601, 5035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カレにガイドして\nもらったら\nどこに行っても\n楽しいだろうな", 0, 102, 0, 1, 8, 1, 116601, 5036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よっしゃあ！\nどっちが上手く\nガイドできるか\n勝負しようぜ！", 0, 1, 0, 2, 1, 1, 116601, 5037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("飯でも食いがてら\nおススメの店の\n下調べでもしようぜ！", 0, 2, 0, 2, 1, 1, 116601, 5038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなかいいだろ？\nこの格好。キミも\n作ってもらったら\nどうだ？", 0, 3, 0, 2, 1, 1, 116601, 5039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普通は行けない\n場所とか行きたいよな\nキミならどんな\nとこがいい？", 0, 4, 0, 2, 1, 1, 116601, 5040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガイドの仕事は\nキミの方が得意そうだ\n参考にさせてもらうぜ\nよろしくな！", 0, 101, 0, 2, 4, 1, 116601, 5041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの探してきた店\n結構よさそうじゃん\nそうだ、今度二人で\n下見に行こうぜ！", 0, 102, 0, 2, 8, 1, 116601, 5042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい朝だな。絶好の\n仕事日和だぜ！\n今日もよろしくな！", 0, 1, 1, 2, 1, 1, 116601, 5043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よし、昼飯にしよう\nこの後も激務だし\n飯抜きじゃあ\nぶっ倒れちまうからな", 0, 2, 2, 2, 1, 1, 116601, 5044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お疲れさん！　さーて\n次はオレと遊んで\nくれよ。まだまだ\nいけるだろ？", 0, 3, 3, 2, 1, 1, 116601, 5045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガイドは一日\n歩きっぱなしだからな\nゆっくり休ませて\nもらうぜ", 0, 2, 0, 3, 1, 1, 116601, 5047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、どこで\n売ってるんだろ？\n土産の情報も\n仕入れとかなきゃな", 0, 3, 0, 3, 1, 1, 116601, 5048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アロマとかよく\n分かんねえけど\n土産にはいいかもな\n覚えておくぜ", 0, 4, 0, 3, 1, 1, 116601, 5049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体が温まると心も\n熱くなるんだよな\nいい仕事が\nできそうだぜ", 0, 5, 0, 3, 1, 1, 116601, 5050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ放題か\nこれはお客さんも\n喜んでくれそうだな！", 0, 7, 0, 3, 1, 1, 116601, 5052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へえ、こんなスポット\nあったんだ。やっぱ\nたまには勉強も\nしとくもんだな", 0, 8, 0, 3, 1, 1, 116601, 5053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイト先になじめる\nように笑顔の練習を！\nに、にへぇ〜…", 0, 1, 0, 1, 1, 1, 116701, 5055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("働いて働いて働いて\n…いつかその先に\nぼっちの出口が\n見えるのかも…！", 0, 2, 0, 1, 1, 1, 116701, 5056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイトのイメトレを\n始めます。ポーズを\n決めて…よし！\n角度を変えて…よし！", 0, 3, 0, 1, 1, 1, 116701, 5057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイト仲間に入る\nためには厳しい修業が\n必須と聞きました…！", 0, 4, 0, 1, 1, 1, 116701, 5058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんどん技術を磨いて\nバイト仲間として\n認めてもらうんです！\n目指せ職人技…！", 0, 5, 0, 1, 1, 1, 116701, 5059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人が応援して\nくれる…だから必ず\nバイト仲間の輪に\n入ってみせます…！", 0, 101, 0, 1, 4, 1, 116701, 5060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人がいてくれると\n勇気が湧いてきます…\nぼっち卒業を夢見ても\nいいんだ、って…♪", 0, 102, 0, 1, 8, 1, 116701, 5061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("緊張するけど\n思い切って声をかけて\nみます…バイト仲間に\n入るために…！", 0, 1, 0, 2, 1, 1, 116701, 5062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼっちの私が\nおもちゃ作りで\n人と共同作業…！\nか、感動です…！", 0, 2, 0, 2, 1, 1, 116701, 5063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("好きなおもちゃって\nありますか？　私は\nもちろんマイフレンド\nくんです！", 0, 3, 0, 2, 1, 1, 116701, 5064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が作ったおもちゃも\n誰かの友達に\nなってたら\nいいなぁ…♪", 0, 4, 0, 2, 1, 1, 116701, 5065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も明日もバイト\nですね！　バイト\n仲間ができる日が\n楽しみです…♪", 0, 101, 0, 2, 4, 1, 116701, 5066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("脱ぼっちを目指して\nこれからも一緒に\n頑張りましょう！\n目指せ、バイト仲間！", 0, 102, 0, 2, 8, 1, 116701, 5067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日も気合いを入れて\nおもちゃ作りします！", 0, 1, 1, 2, 1, 1, 116701, 5068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランチの時間です…♪\nもちろん工場の隅で\nぼっち飯です…！", 0, 2, 2, 2, 1, 1, 116701, 5069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…今日も\nお疲れさまでした\n明日も働きます～！", 0, 3, 3, 2, 1, 1, 116701, 5070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイトで頑張った日は\nふわふわの誘惑に\n勝てません…", 0, 2, 0, 3, 1, 1, 116701, 5072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうおもちゃの\nアイデアも\n素敵かも…♪", 0, 3, 0, 3, 1, 1, 116701, 5073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りがする\nおもちゃはどうかな…\n森の薬草を使って…", 0, 4, 0, 3, 1, 1, 116701, 5074);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽか…\n幸せなひとときですね", 0, 5, 0, 3, 1, 1, 116701, 5075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…たくさん\n食べて厳しいバイトを\n乗り切ります…！", 0, 7, 0, 3, 1, 1, 116701, 5077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…おもちゃの\n設計図を見るのも\n勉強になりますね！", 0, 8, 0, 3, 1, 1, 116701, 5078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん\n次はどんなたい焼きを\n作ろうかにゃぁ…", 0, 1, 0, 1, 1, 1, 116801, 5080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしが売る\nたい焼きには\n夢が詰まってるにゃ！", 0, 2, 0, 1, 1, 1, 116801, 5081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか絶対に\nたい焼き工場を\n建て直してみせるにゃ", 0, 3, 0, 1, 1, 1, 116801, 5082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにたい焼き以外の\nおやつも食べるにゃ\nたとえば煮干しとか！", 0, 4, 0, 1, 1, 1, 116801, 5083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪い商売人がいたら\nファントムキャッツに\n知らせるにゃ！", 0, 5, 0, 1, 1, 1, 116801, 5084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒にいると\nたい焼きのアイデアが\n次々出てくるにゃ♪", 0, 101, 0, 1, 4, 1, 116801, 5085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("出来ないことも\nキミと一緒にいれば\n出来る気がするにゃ♪", 0, 102, 0, 1, 8, 1, 116801, 5086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんにゃ～？\nお姉さんにかまって\nほしいのかにゃ♪", 0, 1, 0, 2, 1, 1, 116801, 5087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミ、いいところに！\nあたしとライバル店へ\n視察にいくにゃ！", 0, 2, 0, 2, 1, 1, 116801, 5088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…この匂い！\nたい焼き持ってるなら\nちょうだいにゃ♪", 0, 3, 0, 2, 1, 1, 116801, 5089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はどんなたい焼きを\n売ろうかにゃ～\nキミの案も欲しいにゃ", 0, 4, 0, 2, 1, 1, 116801, 5090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ファントムキャッツに\n相棒が必要にゃ\nたとえばキミとか…", 0, 101, 0, 2, 4, 1, 116801, 5091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("相棒！\n…ってキミのこと\n呼んでいいかにゃ？", 0, 102, 0, 2, 8, 1, 116801, 5092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きは三文の徳にゃ\n今日もたい焼き\n売れますよーににゃ！", 0, 1, 1, 2, 1, 1, 116801, 5093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いたにゃ…\n賄いのたい焼きを\nいただくにゃ！", 0, 2, 2, 2, 1, 1, 116801, 5094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫は夜が本番にゃ\nでもあたしは…\nふわぁ～眠いにゃ…", 0, 3, 3, 2, 1, 1, 116801, 5095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかにゃ～\nここで体を丸めて\n一眠りしたいにゃ", 0, 2, 0, 3, 1, 1, 116801, 5097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…！\n猫にも負けない\nかわいさだにゃ…！", 0, 3, 0, 3, 1, 1, 116801, 5098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りにゃ～\nゴロゴロのどが\n鳴りそうだにゃ～", 0, 4, 0, 3, 1, 1, 116801, 5099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃ～…\nこのまま働かずに\nまるまってたいにゃ…", 0, 5, 0, 3, 1, 1, 116801, 5100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("商売は戦いにゃ\nたくさん食べて\nたくさん働くにゃ！", 0, 7, 0, 3, 1, 1, 116801, 5102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ。たい焼きの\nアレンジレシピ集…\nためになるにゃ…", 0, 8, 0, 3, 1, 1, 116801, 5103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お芝居の前に\nお兄ちゃんの顔を\n見ると、とっても\n落ち着きますぅ…♪", 0, 103, 0, 1, 12, 1, 102101, 5105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんにもっと\n見てもらいたい…\nだから私…\n強くなりたいです…！", 0, 103, 0, 2, 12, 1, 102101, 5106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さらなる効率化で\nみんなといい仕事を\nしたいわね！", 0, 1, 0, 1, 1, 1, 116901, 5107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("他のバイトとの\nスケジュールを\n調整しないと…", 0, 2, 0, 1, 1, 1, 116901, 5108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時給がアップしたわ！\n働きが認められると\nやる気が出るわね", 0, 3, 0, 1, 1, 1, 116901, 5109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("効率的に動ければ\n業務を追加できる…\n燃えてきたわ！", 0, 4, 0, 1, 1, 1, 116901, 5110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("帳簿付けのコツ…\nユカリさんに教わって\nみようかしら", 0, 5, 0, 1, 1, 1, 116901, 5111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイトリーダーとして\nみんなをビシバシ\n鍛えていくわ！", 0, 101, 0, 1, 4, 1, 116901, 5112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦いでもバイトでも\nキミなら安心して\n背中を預けられるわね", 0, 102, 0, 1, 8, 1, 116901, 5113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\n仕事のことなら\nなんでも相談してね！", 0, 1, 0, 2, 1, 1, 116901, 5114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さすがは私の弟子ね\nこれなら安心して\n仕事を任せられるわ", 0, 2, 0, 2, 1, 1, 116901, 5115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなのお手本になる\n働きぶりを見せないと\nいけないわね！", 0, 3, 0, 2, 1, 1, 116901, 5116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミのこと…もっと\n頼りにしちゃっても\nいいのかしら…？", 0, 4, 0, 2, 1, 1, 116901, 5117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、キミも一人前の\nバイト戦士として\n立派に成長したわね！", 0, 101, 0, 2, 4, 1, 116901, 5118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいおもちゃの\n企画書を作ってみたの\nちょっと見てくれる？", 0, 102, 0, 2, 8, 1, 116901, 5119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は一番効率がいい\n時間帯よ！\nバリバリ働くわよ！", 0, 1, 1, 2, 1, 1, 116901, 5120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ、お昼に行きましょ\n今日の日替わり定食は\n何かしら…楽しみね♪", 0, 2, 2, 2, 1, 1, 116901, 5121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\nちゃんと寝て明日に\n備えなくちゃね", 0, 3, 3, 2, 1, 1, 116901, 5122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適度な労働と休息の\nサイクルが最大効率を\n生み出すのよ…ふぅ…", 0, 2, 0, 3, 1, 1, 116901, 5124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～なんて素敵な\n抱き心地なのかしら…\n最高効率の癒やしね♪", 0, 3, 0, 3, 1, 1, 116901, 5125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着く香りね…\nなんだか集中力が\nアップした気がするわ", 0, 4, 0, 3, 1, 1, 116901, 5126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…癒されるわね…\n仕事のオンオフの\n切り替えは重要よね", 0, 5, 0, 3, 1, 1, 116901, 5127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("働くためには\nエネルギーをちゃんと\n摂っておかないと", 0, 7, 0, 3, 1, 1, 116901, 5129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("効率を上げるため\n生産管理の勉強も\nしておきたいわね", 0, 8, 0, 3, 1, 1, 116901, 5130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身している間に\n色々と試しておこう\nまずは…", 0, 1, 0, 1, 1, 1, 180301, 5132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("飛べるというのは\n便利だな。料理が\n暖かいうちに\n持ち帰れる", 0, 2, 0, 1, 1, 1, 180301, 5133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスか…\n柄ではないけれど\n嫌な気はしないな", 0, 3, 0, 1, 1, 1, 180301, 5134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この力で\n何を成すべきなのか…\n剣に聞いてみよう", 0, 4, 0, 1, 1, 1, 180301, 5135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身したとて私は私\n一時的に強くなろうと\n元が弱くてはだめだ", 0, 5, 0, 1, 1, 1, 180301, 5136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身していない時でも\n彼がそばにいると\n力が湧いてくる…", 0, 101, 0, 1, 4, 1, 180301, 5137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の思い…\nいつか伝えてみせるよ\n…きっといつか！", 0, 102, 0, 1, 8, 1, 180301, 5138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何者かと戦うの？\nそれとも修行？\nどちらだとしても\n付き合うよ", 0, 1, 0, 2, 1, 1, 180301, 5139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身し続けたら\nどれだけ空腹に…\n私は試さないからね？", 0, 2, 0, 2, 1, 1, 180301, 5140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本物のプリンセスに\nなるのは御免だが\nナイトがいて\nくれるのは頼もしいよ", 0, 3, 0, 2, 1, 1, 180301, 5141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかこの力を\n誰かを救うために…\n戦い以外に使える時が\nくることを願うよ", 0, 4, 0, 2, 1, 1, 180301, 5142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミに感じてほしいな\n私に流れてくる\nキミからの力を…\nその…私の、思いも…", 0, 101, 0, 2, 4, 1, 180301, 5143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思いを告げる…\nそれがこんなにも\n難しいなんて…\nでも、いつか必ず…！", 0, 102, 0, 2, 8, 1, 180301, 5144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\nいい変身日和だ！\n…ふふっ、冗談だよ", 0, 1, 1, 2, 1, 1, 180301, 5145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもより多く\n昼食を用意しよう\n変身が解けたら大変だ", 0, 2, 2, 2, 1, 1, 180301, 5146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日お疲れ様\n私もそろそろ変身を\n解いて休むとするよ", 0, 3, 3, 2, 1, 1, 180301, 5147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変身してしまうと\n動かずにいても\n空腹になるのかな…？", 0, 2, 0, 3, 1, 1, 180301, 5149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私もキミたちくらい\n可愛げがある姿に\nなっているかな？", 0, 3, 0, 3, 1, 1, 180301, 5150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りに対する感覚も\nいつもより鋭く\nなっているみたいだ…", 0, 4, 0, 3, 1, 1, 180301, 5151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ありがたいな\n少し足元が\n冷えていたところだ", 0, 5, 0, 3, 1, 1, 180301, 5152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…！\n持ち運べるように\n改良できないかな？", 0, 7, 0, 3, 1, 1, 180301, 5154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("祖父に貰った\n技法書を読んで\n初心に帰ろう", 0, 8, 0, 3, 1, 1, 180301, 5155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最強の惚れ薬を作って\nあのおかたの心を\n私の思いのままに…", 0, 1, 0, 1, 1, 1, 117001, 5157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏といえば海にスイカ\n花火に水着…\nそして惚れ薬ですわ…", 0, 2, 0, 1, 1, 1, 117001, 5158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのおかたの心を\n手に入れるための\n準備を進めましょう\nこの夏こそ確実に…", 0, 3, 0, 1, 1, 1, 117001, 5159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのおかたに近づく\n虫どもを、どうやって\n片付けようかしら…\nまったく忌々しいこと", 0, 4, 0, 1, 1, 1, 117001, 5160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…クスクス\n薬の調合を考えるのは\n至福の時間ですわ…", 0, 5, 0, 1, 1, 1, 117001, 5161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのおかたの全てが\n早く私のものに\nなりますように…", 0, 101, 0, 1, 4, 1, 117001, 5162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かき氷も花火も海も…\nあなた様がいてこそ…\nそう、あなた様は\n私の全てなのですわ", 0, 102, 0, 1, 8, 1, 117001, 5163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("二人だけの夏を\n楽しみましょう…？\n…クスクス", 0, 1, 0, 2, 1, 1, 117001, 5164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、あなた様\n私に秘密でどこに\n行こうとして\nいますの…？", 0, 2, 0, 2, 1, 1, 117001, 5165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行きませんか？\nあなた様と一緒に\n過ごすには\n最高の場所ですから…", 0, 3, 0, 2, 1, 1, 117001, 5166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどいいところに\nいらっしゃいました\nできたての薬を…\nさぁどうぞ…クスクス", 0, 4, 0, 2, 1, 1, 117001, 5167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の海のきらめきも\nあなた様の存在が\nなければ色あせて\nしまいますわ…", 0, 101, 0, 2, 4, 1, 117001, 5168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私とあなた様は\n結ばれる運命に\nあるのです…\n逃がしませんわ…", 0, 102, 0, 2, 8, 1, 117001, 5169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きてすぐに会いに\n来てくださるなんて\nようやく私の伴侶たる\n自覚が…クスクス", 0, 1, 1, 2, 1, 1, 117001, 5170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お食事はまだですか？\n特製の薬草ランチを\n召し上がれ…クスクス", 0, 2, 2, 2, 1, 1, 117001, 5171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の夢を見られる薬を\n差し上げますわ…\nおやすみなさいませ\nあなた様…クスクス", 0, 3, 3, 2, 1, 1, 117001, 5172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい肌触りですわ…\n考え事にもぴったり\n眠くなるのが\n玉に瑕ですが…", 0, 2, 0, 3, 1, 1, 117001, 5174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういったものに\n揮発性の薬を仕込む\nのも一つの手ですわね", 0, 3, 0, 3, 1, 1, 117001, 5175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…開発中の\n薬に使えそうな気が\nしますわ…クスクス", 0, 4, 0, 3, 1, 1, 117001, 5176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのおかたの\nぬくもりを\n思い出しますわ…", 0, 5, 0, 3, 1, 1, 117001, 5177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しい…この味なら\n薬を混ぜても違和感は\nなさそうですわ…", 0, 7, 0, 3, 1, 1, 117001, 5179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この薬の調合法…\n今度試してみましょう\nもちろんあのおかたに\n飲んでいただいて…", 0, 8, 0, 3, 1, 1, 117001, 5180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("二人乗りができると\nいいですわね…", 0, 10, 0, 3, 1, 1, 117001, 5182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかですわ…\nあのおかたの分も\n欲しくなります…", 0, 11, 0, 3, 1, 1, 117001, 5183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はキミと\nいつまでも歌って\n踊りたい気分さ～♪", 0, 103, 0, 1, 12, 1, 101701, 5184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あは～♪\nキミの隣は、故郷より\n落ち着くかも～…♪", 0, 103, 0, 2, 12, 1, 101701, 5185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この水着…\n一番に弟くんに\n見せたいな♪", 0, 1, 0, 1, 1, 1, 117101, 5186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんをこっそり\n海に運んで…\nサプライズしちゃお♪", 0, 2, 0, 1, 1, 1, 117101, 5187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもと違う髪型に\nしてみたけど…\n気に入ってくれるかな", 0, 3, 0, 1, 1, 1, 117101, 5188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海は楽しみだけど\n日焼けしないように\n気を付けなきゃね", 0, 4, 0, 1, 1, 1, 117101, 5189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだかな、弟くん\n水着のお姉ちゃんが\nお出迎えだよっ♪", 0, 5, 0, 1, 1, 1, 117101, 5190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海が見えるおうちで\n弟くんと一緒に\n暮らしたいなぁ～", 0, 101, 0, 1, 4, 1, 117101, 5191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの水着…\nどんな感じかなぁ\n…あ、想像してたら\nドキドキして…えへへ", 0, 102, 0, 1, 8, 1, 117101, 5192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こーら、水着の\nお姉ちゃんは\nおさわり禁止♪\n…なんてね？", 0, 1, 0, 2, 1, 1, 117101, 5193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なぁに？\nふふっ、何回でも\n呼んでいいんだよ♪", 0, 2, 0, 2, 1, 1, 117101, 5194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で迷子に\nならないように\n手を繋ごうね♪", 0, 3, 0, 2, 1, 1, 117101, 5195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんが\n海の楽しみ方を\n教えてあげるねっ！", 0, 4, 0, 2, 1, 1, 117101, 5196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、弟くん\nどこ触ってるの？\nも～驚いちゃったぞ♪", 0, 101, 0, 2, 4, 1, 117101, 5197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん、海でも\nずっとキミを見てるよ\n…安心してね", 0, 102, 0, 2, 8, 1, 117101, 5198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ眠そうだね？\nほら、海が待ってるよ\n早く起きて起きて♪", 0, 1, 1, 2, 1, 1, 117101, 5199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大丈夫、疲れてない？\n海で遊び疲れた時は\n素直に休憩しようね", 0, 2, 2, 2, 1, 1, 117101, 5200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほら、早く寝ないと\n明日もお姉ちゃんと\n遊べないぞ♪", 0, 3, 3, 2, 1, 1, 117101, 5201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("だらけたお姉ちゃんは\n弟くんには\n見せられないな～", 0, 2, 0, 3, 1, 1, 117101, 5203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、かわいいね♪\n弟くんが持つと\nもっとかわいいよっ♪", 0, 3, 0, 3, 1, 1, 117101, 5204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだね…\n一味違うお姉ちゃんに\nなれそう…♪", 0, 4, 0, 3, 1, 1, 117101, 5205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い♪\nほら、弟くんも\nおいでよ♪", 0, 5, 0, 3, 1, 1, 117101, 5206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よく食べて、いつでも\n弟くんの呼び声に\n応える準備を…！", 0, 7, 0, 3, 1, 1, 117101, 5208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの水着の写真\nこの辺りに隠して\nおこうかな", 0, 8, 0, 3, 1, 1, 117101, 5209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子の背に乗って\nお姉ちゃんと弟くんの\n楽園へ…な～んて♪", 0, 10, 0, 3, 1, 1, 117101, 5211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海を感じる感触だね\n弟くんとの楽しい夏を\n思い出しちゃうな…♪", 0, 11, 0, 3, 1, 1, 117101, 5212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この夏、誰よりも\nキラキラしてみせる！\nだって私は\nアイドルだから！", 0, 1, 0, 1, 1, 1, 117201, 5213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日傘にアームカバー\n帽子にサングラス…\n紫外線対策は完璧！", 0, 2, 0, 1, 1, 1, 117201, 5214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっておきの\nサマーソングを\nみんなに届けるよ！", 0, 3, 0, 1, 1, 1, 117201, 5215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんにもしないのって\n苦手かも…\n彼、早く来ないかな？", 0, 4, 0, 1, 1, 1, 117201, 5216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラムネって\n夏って感じするよね\n後で彼と飲もっと♪", 0, 5, 0, 1, 1, 1, 117201, 5217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は恋の季節！\n燃えるような恋…\nいつかしたいな", 0, 101, 0, 1, 4, 1, 117201, 5218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年の夏の目標は\n…彼との思い出を\nいっぱい作ること！", 0, 102, 0, 1, 8, 1, 117201, 5219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の水着写真集\n見てくれたんだ！\nどう、かわいかった？", 0, 1, 0, 2, 1, 1, 117201, 5220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スイカ割りしたいの？\nいいね、楽しそう！\nみんなも誘おうよ♪", 0, 2, 0, 2, 1, 1, 117201, 5221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、見て見て！\n水着の映える\nポーズ考えたんだ！", 0, 3, 0, 2, 1, 1, 117201, 5222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ライブ中に\n花火を打ち上げたら\n絶対盛り上がるよね！", 0, 4, 0, 2, 1, 1, 117201, 5223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近、忙しいけど…\nキミの顔見たら\n疲れなんて\n消えちゃった！", 0, 101, 0, 2, 4, 1, 117201, 5224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この夏もいーっぱい\nドキドキさせるから！\n覚悟しててよね♪", 0, 102, 0, 2, 8, 1, 117201, 5225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外は朝から暑いね\nけど、負けないから！\nお仕事、頑張るぞー！", 0, 1, 1, 2, 1, 1, 117201, 5226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分へのご褒美に、\nアイス食べちゃお♪\nキミも一緒に食べよ！", 0, 2, 2, 2, 1, 1, 117201, 5227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の夜って\nワクワクするね♪\nホタル見に行こうよ！", 0, 3, 3, 2, 1, 1, 117201, 5228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…眠い…\n仕事とかの疲れ、\nたまってるのかな…？", 0, 2, 0, 3, 1, 1, 117201, 5230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私のぬいぐるみが\nグッズになったら…\n彼にかわいがって\nもらえるかな？", 0, 3, 0, 3, 1, 1, 117201, 5231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\n夏限定のやつでしょ？\nいいセンスしてるね♪", 0, 4, 0, 3, 1, 1, 117201, 5232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑～い！\nけど…汗かいて\n気持ちいいかも！", 0, 5, 0, 3, 1, 1, 117201, 5233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンの後のご飯は\n特別おいしい♪\n…もうひとつだけ\n食べちゃおっかな", 0, 7, 0, 3, 1, 1, 117201, 5235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、この前撮影した\n水着グラビアだ\nうんうん、いい感じ！", 0, 8, 0, 3, 1, 1, 117201, 5236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子、もふもふだね\n触るのクセになりそう\nもふもふもふもふ…", 0, 10, 0, 3, 1, 1, 117201, 5238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ、かわいい♪\n今度のグラビア撮影で\nこれ使ってもいい？", 0, 11, 0, 3, 1, 1, 117201, 5239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着っていいですよね\n海に浮かぶ一輪の花\nって感じがして！", 0, 1, 0, 1, 1, 1, 117401, 5240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分の水着を作るのも\n誰かの水着を作るのも\n楽しいですね♪", 0, 2, 0, 1, 1, 1, 117401, 5241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着の最終チェック！\n伸縮性や動きやすさは\n…いい感じですね！", 0, 3, 0, 1, 1, 1, 117401, 5242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("振り付けや衣装作りに\n歌や踊りの練習…\n…やることがいっぱい", 0, 4, 0, 1, 1, 1, 117401, 5243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…レイ様の水着…\n私に作らせて\nもらえないかなぁ～…", 0, 5, 0, 1, 1, 1, 117401, 5244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんのことは\n気に入らないですけど\n別に嫌いという\nわけじゃなくて…", 0, 101, 0, 1, 4, 1, 117401, 5245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さん暇そうですね\nに、荷物持ちとして\n誘ってみようかな…", 0, 102, 0, 1, 8, 1, 117401, 5246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんいいところに\nこの衣装\nどう思います？", 0, 1, 0, 2, 1, 1, 117401, 5247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何見てるんですか？\nもしかしてこの水着の\n良さが分かります！？", 0, 2, 0, 2, 1, 1, 117401, 5248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真夏でも涼しい…\nそれも水着の良さの\n一つですね", 0, 3, 0, 2, 1, 1, 117401, 5249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕立て屋も\nアイドルも\n諦めません！", 0, 4, 0, 2, 1, 1, 117401, 5250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏と言えば\nバカンスですけど…\n予定、あるんですか？", 0, 101, 0, 2, 4, 1, 117401, 5251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん…騎士さんを\n海へ誘うには…って\nなんでもないですよ！", 0, 102, 0, 2, 8, 1, 117401, 5252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふー…夏はやっぱり\n朝が一番過ごしやすい\nですね～！", 0, 1, 1, 2, 1, 1, 117401, 5253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑い時こそ海です！\n体力づくりのためにも\n泳ぎにいきますよ！", 0, 2, 2, 2, 1, 1, 117401, 5254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外で虫が鳴いてる…\n夏って感じがして\n風流ですねぇ…", 0, 3, 3, 2, 1, 1, 117401, 5255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し休憩です…\nこのまま寝ないよう\n気をつけないと…", 0, 2, 0, 3, 1, 1, 117401, 5257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…！\nこの感動を次の\nステージ衣装にも…！", 0, 3, 0, 3, 1, 1, 117401, 5258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りですね～\n波の音が聞こえて\nきそうです…", 0, 4, 0, 3, 1, 1, 117401, 5259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳いだ後は\n少し寒いので\nちょうどいいですね", 0, 5, 0, 3, 1, 1, 117401, 5260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテしないように\n栄養はしっかり\n取らないと！", 0, 7, 0, 3, 1, 1, 117401, 5262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のトレンドは…\nふむふむ、やっぱり\nこう来ましたか…", 0, 8, 0, 3, 1, 1, 117401, 5263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("デザインはもちろん\n触り心地も\n最高ですね♪", 0, 10, 0, 3, 1, 1, 117401, 5265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の撮影スポットに\n活用できそうですね\nさっそく衣装考えて…", 0, 11, 0, 3, 1, 1, 117401, 5266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…♪\n団長さんが初めての\n友達で本当に良かった", 0, 103, 0, 1, 12, 1, 104001, 5267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、団長さん！\n今日のＢＢ団の活動\nなんですけど…二人で\n大縄跳びしませんか！", 0, 103, 0, 2, 12, 1, 104001, 5268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装で\nライブするのは\n恥ずかしいな…", 0, 1, 0, 1, 1, 1, 117301, 5269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの夏だし\n肝試しに\n行ってみたいかも…", 0, 2, 0, 1, 1, 1, 117301, 5270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歌もダンスも\nより上を目指すために\n夏合宿をしよう…！", 0, 3, 0, 1, 1, 1, 117301, 5271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の暑さにも負けない\n熱いライブに\nしてみせる…！", 0, 4, 0, 1, 1, 1, 117301, 5272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新曲のアイデア\nまとめたいな…\n少し海辺を散歩しよう", 0, 5, 0, 1, 1, 1, 117301, 5273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かき氷、食べたいな\n…あの人は何味が\n好きなんだろう？", 0, 101, 0, 1, 4, 1, 117301, 5274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着、似合ってるって\n言ってもらえるかな…", 0, 102, 0, 1, 8, 1, 117301, 5275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サインして、ですか？\nいいですけど…\n少し照れますね…", 0, 1, 0, 2, 1, 1, 117301, 5276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し待ってください\n今、新曲の楽譜を\n書いているので…", 0, 2, 0, 2, 1, 1, 117301, 5277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんでしょう？\nもしかして…\nボイトレに興味が？", 0, 3, 0, 2, 1, 1, 117301, 5278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のライブでは\n夏らしい爽やかな歌を\nファンにお届けします", 0, 4, 0, 2, 1, 1, 117301, 5279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…水鉄砲で遊ぼう？\nふふ。楽しそうですね\nお手柔らかに…♪", 0, 101, 0, 2, 4, 1, 117301, 5280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの声を\n聴いていると、\n何だか落ち着きます…", 0, 102, 0, 2, 8, 1, 117301, 5281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も暑くなりそう…\nお互いしっかりと\n水分補給しましょうね", 0, 1, 1, 2, 1, 1, 117301, 5282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空きましたよね\n海の家で、\nなにか買ってきます", 0, 2, 2, 2, 1, 1, 117301, 5283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海で月明かりと\n波の音を楽しもうかと\n…一緒に行きますか？", 0, 3, 3, 2, 1, 1, 117301, 5284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンだけでなく\nリラックスすることも\n大事、ですよね", 0, 2, 0, 3, 1, 1, 117301, 5286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、かわいい\n精霊も負けないくらい\nかわいいですけどね", 0, 3, 0, 3, 1, 1, 117301, 5287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏らしい爽やかで\nいい匂い…あなたに\nピッタリな香りですね", 0, 4, 0, 3, 1, 1, 117301, 5288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に入った後は、\n体が冷えてしまいます\n一緒に温まりましょう", 0, 5, 0, 3, 1, 1, 117301, 5289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルとして、\n食べすぎには\n気をつけないと…", 0, 7, 0, 3, 1, 1, 117301, 5291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は恋の季節…\nガンガン攻めるべし…\nなるほど…", 0, 8, 0, 3, 1, 1, 117301, 5292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子に乗りながら\nライブをする…\nというのはどうですか", 0, 10, 0, 3, 1, 1, 117301, 5294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まるで人魚になった\n気分…なんて、ふふ", 0, 11, 0, 3, 1, 1, 117301, 5295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんとして\nシオリンにかっこいい\nとこ見せなくっちゃ☆", 0, 1, 0, 1, 1, 1, 118301, 5296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかシオリンと\n一緒に空を飛んで\n空中散歩してみたいな", 0, 2, 0, 1, 1, 1, 118301, 5297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すこし眠くなってきた\nかも…シオリンと\nお昼寝しようかな", 0, 3, 0, 1, 1, 1, 118301, 5298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お散歩してこよっと！\nシオリンとお出かけ\nするのにいい場所\n探さなくっちゃ！", 0, 4, 0, 1, 1, 1, 118301, 5299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリンに過保護って\n言われちゃった…♪\nそれでも心配しちゃう\nのが姉心…だよね？", 0, 5, 0, 1, 1, 1, 118301, 5300);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいい日差し！\nシオリンと彼と、\nお昼寝したら\n気持ちよさそ～♪", 0, 101, 0, 1, 4, 1, 118301, 5301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度天気がいい日には\nシオリンと彼を誘って\n一緒にお出かけ\nしたいな～♪", 0, 102, 0, 1, 8, 1, 118301, 5302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はご機嫌なんだ♪\nだって、シオリンの\n調子がいいんだもん☆", 0, 1, 0, 2, 1, 1, 118301, 5303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今からシオリンと\nピクニックに\n行くんだ♪　そうだ！\nキミも一緒にどう？", 0, 2, 0, 2, 1, 1, 118301, 5304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、びっくりした！\nシオリンから借りた本\n読むのに集中\nしてたから…", 0, 3, 0, 2, 1, 1, 118301, 5305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん？　どうしたの？\nあっ、もしかして\nこの服、気になる？", 0, 4, 0, 2, 1, 1, 118301, 5306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリンもキミも元気\nいっぱいだと、私も\n元気になっちゃうよ☆", 0, 101, 0, 2, 4, 1, 118301, 5307);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリンの前だけ\nじゃなくて、キミにも\nかっこいい私の姿を\n見てほしいな☆", 0, 102, 0, 2, 8, 1, 118301, 5308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！　えへへっ\n今日は早起きなんだ♪\nシオリンにかっこ悪い\nとこ見せたくないから", 0, 1, 1, 2, 1, 1, 118301, 5309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おなかすいたなぁ～…\nシオリンと一緒に\nおいしいもの食べに\n行こうかな！", 0, 2, 2, 2, 1, 1, 118301, 5310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間！？\nシオリンと一緒だと\n時間が早く\n過ぎていっちゃうね！", 0, 3, 3, 2, 1, 1, 118301, 5311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この快適な寝心地…！\nシオリンにもおすすめ\nしなきゃ…！", 0, 2, 0, 3, 1, 1, 118301, 5313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、かわいい！\nそれにさわり心地も\nいいし、抱き枕に\nちょうどいいかも！", 0, 3, 0, 3, 1, 1, 118301, 5314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいにおい…♪\nなんだかリラックス\nできて…すやぁ…", 0, 4, 0, 3, 1, 1, 118301, 5315);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽか～☆\nシオリンと一緒に\nぬくぬくしたら\n気持ちよさそう♪", 0, 5, 0, 3, 1, 1, 118301, 5316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲のいい人が一緒だと\nつい食が進んじゃうね\nえへへ…♪", 0, 7, 0, 3, 1, 1, 118301, 5318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…この本…\nシオリンが好きかも！\n今度おすすめしよっと", 0, 8, 0, 3, 1, 1, 118301, 5319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん、\n私のために無理は\nしてないかな…？", 0, 1, 0, 1, 1, 1, 118401, 5322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しく買った絵本…\nこういうのなら\nお姉ちゃんと楽しく\n読めるよね", 0, 2, 0, 1, 1, 1, 118401, 5323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃんを\nここに連れてきて\nみんなで遊べないかな", 0, 3, 0, 1, 1, 1, 118401, 5324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本屋さんに行こうかな\nみんなで読める\n面白い本が\nあるといいなぁ", 0, 4, 0, 1, 1, 1, 118401, 5325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには…読むだけ\nじゃなくて、自分で\nお話を書いて\nみようかな…？", 0, 5, 0, 1, 1, 1, 118401, 5326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時々…お姉ちゃんと\nあの人が似てるって\n思うことがあります…", 0, 101, 0, 1, 4, 1, 118401, 5327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんとあの人…\n優しくて頼もしい\n二人に囲まれて…\n私、幸せ者だなぁ…", 0, 102, 0, 1, 8, 1, 118401, 5328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかしましたか？\nもしかして…あなたも\n一緒にこの本を\n読みたい…とか？", 0, 1, 0, 2, 1, 1, 118401, 5329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("けほっ…けほっ…\nあっ、心配いりません\n飲み物を飲んで\nむせただけですから", 0, 2, 0, 2, 1, 1, 118401, 5330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好…\n似合ってますか…？\nえへへ、照れますね…", 0, 3, 0, 2, 1, 1, 118401, 5331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なぁに、お姉ちゃん？\n…あっ、すみません\n読書に集中していて…\n間違えちゃいました…", 0, 4, 0, 2, 1, 1, 118401, 5332);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん、時々無理\nしちゃうから…\nあなたも一緒だと\n安心できます", 0, 101, 0, 2, 4, 1, 118401, 5333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんとあなたと\n頼れる人に囲まれて\n私は幸せものですね", 0, 102, 0, 2, 8, 1, 118401, 5334);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか朝から\n調子がいい…今日は\nいい日になりそうです", 0, 1, 1, 2, 1, 1, 118401, 5335);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくだから、\nお姉ちゃんを誘って\nお外でランチも\nいいかも", 0, 2, 2, 2, 1, 1, 118401, 5336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんに心配\nかけないように…もう\nちょっと本を読んだら\n寝なくちゃね", 0, 3, 3, 2, 1, 1, 118401, 5337);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんわり柔らかくて\n気持ちいい手触り…\nお姉ちゃんが寝るのに\nちょうどよさそう", 0, 2, 0, 3, 1, 1, 118401, 5339);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、かわいい♪\n絵本の物語みたいに\nおしゃべりできない\nかな…？", 0, 3, 0, 3, 1, 1, 118401, 5340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な落ち着く香り♪\nなんだかお姉ちゃん\nみたい、ふふっ", 0, 4, 0, 3, 1, 1, 118401, 5341);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかくてほっと\nするなぁ\nここでゆっくり\n読書しようかな", 0, 5, 0, 3, 1, 1, 118401, 5342);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この味…\nお姉ちゃんが好きそう\n少しもらって、\n持って行こうかな…？", 0, 7, 0, 3, 1, 1, 118401, 5344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この本みたいな、\n心躍る大冒険も\nお姉ちゃんと一緒なら\nできちゃいそう", 0, 8, 0, 3, 1, 1, 118401, 5345);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい部屋ね\nここを私の分院に\nするのもいいかも\nしれないわね…♪", 0, 1, 0, 1, 1, 1, 117501, 5348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("珍しいカンポーが\n手に入ったから\n色々試してみたいわ\n色々と、ね♪", 0, 2, 0, 1, 1, 1, 117501, 5349);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服を着ると\n自分が医者だって\nより実感するわね\nまあ、闇医者だけどね", 0, 3, 0, 1, 1, 1, 117501, 5350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新薬開発のために\n薬草を採取して\nおこうかしら", 0, 4, 0, 1, 1, 1, 117501, 5351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつ急患が来ても\n対応できるように\nしておきましょうか", 0, 5, 0, 1, 1, 1, 117501, 5352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子の研究資料も\nだいぶ増えてきたわね\nちゃんとまとめて\nおかないと♪", 0, 101, 0, 1, 4, 1, 117501, 5353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子は大事な\n研究対象。だから\nいつまでも健康で\nいてもらわないとね♪", 0, 102, 0, 1, 8, 1, 117501, 5354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("薬に興味があるの？\nなら、今度ゆっくりと\n教えてあげるわね", 0, 1, 0, 2, 1, 1, 117501, 5355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し時間があいたから\n一緒に新薬の実験を\nしましょうか♪", 0, 2, 0, 2, 1, 1, 117501, 5356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\nまさか急患…！？\nあら、違うのね\nならよかったわ", 0, 3, 0, 2, 1, 1, 117501, 5357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("具合が悪い時はすぐに\n言うのよ。君には\nいつでも健康でいて\nほしいから", 0, 4, 0, 2, 1, 1, 117501, 5358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し仮眠したいわね\n肩…いいえ、膝を\n貸してもらえる？", 0, 101, 0, 2, 4, 1, 117501, 5359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには…君の隣なら\n闇医者も悪い研究者も\nお休みにするのも\n悪くないわね♪", 0, 102, 0, 2, 8, 1, 117501, 5360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには朝の陽ざしを\n浴びるのも…\n悪くないわね", 0, 1, 1, 2, 1, 1, 117501, 5361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("天気がいい日は\nいい薬草が採れるの\n君も集めるの、\n手伝ってくれる？", 0, 2, 2, 2, 1, 1, 117501, 5362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いけない、もうこんな\n時間なのね\n診察に没頭すると\n時間感覚がなくなるわ", 0, 3, 3, 2, 1, 1, 117501, 5363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう少し固い方が\n私好みだけど…\n悪くない寝心地ね", 0, 2, 0, 3, 1, 1, 117501, 5365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このぬいぐるみ…\n闇医者として\n興味深いわね…", 0, 3, 0, 3, 1, 1, 117501, 5366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着く香りね\n私も診察室で\n使ってみようかしら", 0, 4, 0, 3, 1, 1, 117501, 5367);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷えは病につながるわ\nしっかり温めて\n体をいたわりましょ", 0, 5, 0, 3, 1, 1, 117501, 5368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい♪\n研究のお供に\nもってこいの\n味だわ", 0, 7, 0, 3, 1, 1, 117501, 5370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("医学は日進月歩…\n闇医者とはいえ\n最新の論文には\n目を通しておかないと", 0, 8, 0, 3, 1, 1, 117501, 5371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("白衣の天使かあ\nまさにボクのための\n呼び方だね", 0, 1, 0, 1, 1, 1, 117601, 5400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美しさとは\n日々の努力が\n作るものなんだよ", 0, 2, 0, 1, 1, 1, 117601, 5401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大変だ…\nボクは美しく\nなりすぎたかも", 0, 3, 0, 1, 1, 1, 117601, 5402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクのかわいさで\n癒やされて\nみんな健康に\nなっちゃうね", 0, 4, 0, 1, 1, 1, 117601, 5403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんな服装をしても\nボクの美しさは\n変わらないね", 0, 5, 0, 1, 1, 1, 117601, 5404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからはボクも\n美の伝道師として\nがんばらないとね♪", 0, 101, 0, 1, 4, 1, 117601, 5405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクのかわいい笑顔を\n近くで見る以上の\n癒やしはないよね♪", 0, 102, 0, 1, 8, 1, 117601, 5406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どう？　看護師姿の\nボクもかわいいでしょ\nもっと近くで見る？", 0, 1, 0, 2, 1, 1, 117601, 5407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほら！　美しいボクの\n看護師姿を見たら\n元気でちゃうでしょ？", 0, 2, 0, 2, 1, 1, 117601, 5408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("白衣の天使のボクも\n最高に美しいね\n存分に癒されてよ♪", 0, 3, 0, 2, 1, 1, 117601, 5409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("具合が悪いの？\nならボクの美しい顔を\n処方してあげる♪", 0, 4, 0, 2, 1, 1, 117601, 5410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ今日もボクと\n一緒に美の追求に\n付き合ってもらうよ♪", 0, 101, 0, 2, 4, 1, 117601, 5411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい天使のボクが\nいつもそばにいるんだ\nキミって幸せ者だね♪", 0, 102, 0, 2, 8, 1, 117601, 5412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さすがボク\n目が覚めるような\n美しさでしょ？", 0, 1, 1, 2, 1, 1, 117601, 5413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美は食で作られる\n美容にいいものを\n食べようよ！", 0, 2, 2, 2, 1, 1, 117601, 5414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふああ…早く寝よ？\n夜更かしは美容の\n大敵だからね", 0, 3, 3, 2, 1, 1, 117601, 5415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう～…\nリラックスする\nボクも美しい", 0, 2, 0, 3, 1, 1, 117601, 5417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクが抱きしめると\n普段よりかわいく\n見えちゃうね♪", 0, 3, 0, 3, 1, 1, 117601, 5418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美しいボクは\n常にいい香りを\nしていなくちゃね", 0, 4, 0, 3, 1, 1, 117601, 5419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("光がボクを照らしてる\nんじゃなくて、ボクが\n光を輝かせてるのさ", 0, 5, 0, 3, 1, 1, 117601, 5420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バランスのいい食事が\n美しいボクを\n作るのさ", 0, 7, 0, 3, 1, 1, 117601, 5422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…なるほど\nこうすればより美しく\nなれるかもしれない", 0, 8, 0, 3, 1, 1, 117601, 5423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間のためなら\nきっと…どこまでも\n強くなれるよね", 0, 103, 0, 1, 12, 1, 105701, 5425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスフォーム？\n私と同じような力を\n持ってる人がいるの？\n会ってみたいな～！", 0, 103, 0, 2, 12, 1, 105701, 5426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここの空気は、\nどうもゆるすぎて…\n落ち着きませんわね", 0, 1, 0, 1, 1, 1, 118001, 5427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("陛下のお越しになる\n別宅としては、\n少し警備が\n甘すぎでは？", 0, 2, 0, 1, 1, 1, 118001, 5428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらあら？\nサッシにホコリが！\nちょっとネコ助！\n掃除は念入りに！", 0, 3, 0, 1, 1, 1, 118001, 5429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつまで入り浸って\nいるのかと、\n秘書に叱られて\nしまいましたわ…", 0, 4, 0, 1, 1, 1, 118001, 5430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もういっそ、\nここに間借りして\n仕事しようかしら…？", 0, 5, 0, 1, 1, 1, 118001, 5431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("邪魔している身ですし\n家事くらい\nお手伝いさせなさいな", 0, 101, 0, 1, 4, 1, 118001, 5432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本当は、意外と\n居心地が良いのかも…\n陛下の気持ち、\n少し分かりましたわ", 0, 102, 0, 1, 8, 1, 118001, 5433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっ…わたくしを\n叩いても、ホコリなど\nあまり出ませんわよ！", 0, 1, 0, 2, 1, 1, 118001, 5434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("陛下っ？\nなんだ…貴方でしたの\n用件は手短にお願いね", 0, 2, 0, 2, 1, 1, 118001, 5435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("別に、好き嫌いは\nありませんけれど…\n魔物料理って、意外と\n美味なものですわね", 0, 3, 0, 2, 1, 1, 118001, 5436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("言っておきますけれど\nわたくしは商売人です\n荒事は専門外ですわよ", 0, 4, 0, 2, 1, 1, 118001, 5437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスナイトの\n能力…なにか儲け話に\n使えませんかしらね", 0, 101, 0, 2, 4, 1, 118001, 5438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴方がたのことも、\n少しくらいは\n信用してないことも\nありませんでしてよ", 0, 102, 0, 2, 8, 1, 118001, 5439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\nさ、今日もバリバリ\n働きますわよ！", 0, 1, 1, 2, 1, 1, 118001, 5440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですわね\n栄養補給をしつつ\n働きますわよ！", 0, 2, 2, 2, 1, 1, 118001, 5441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("定時ですって？\n関係ありません！\nわたくし、まだまだ\n働きますわよ～っ！", 0, 3, 3, 2, 1, 1, 118001, 5442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うっ…いけませんわ\n日頃の疲れが…\nふわぁ…", 0, 2, 0, 3, 1, 1, 118001, 5444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もふもふ…ふふっ♪\n…なんですのっ、\nなにかおかしくて！？", 0, 3, 0, 3, 1, 1, 118001, 5445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りですわね\nわたくしの執務室にも\n置きたいくらいですわ", 0, 4, 0, 3, 1, 1, 118001, 5446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いけませんわ…\nこんなに暖かいと\n日頃の疲れが…ふわぁ", 0, 5, 0, 3, 1, 1, 118001, 5447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう一つ食べたら\n仕事に戻りますわよ？\nあと一つだけ…", 0, 7, 0, 3, 1, 1, 118001, 5449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("商人にとって\n知識は武器ですわ\n陛下のため、貴方も\nもっと勉強なさい？", 0, 8, 0, 3, 1, 1, 118001, 5450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("故郷のお菓子を\nいろいろ作ったんだ～\nみんなに\n配ってくるさ～♪", 0, 1, 0, 1, 1, 1, 117701, 5452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼ってどんな仮装が\n似合うかな～？\nシーサーとか？", 0, 2, 0, 1, 1, 1, 117701, 5453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャチャンプルー\n作ってみよっと！\nきっとおいしいさ～♪", 0, 3, 0, 1, 1, 1, 117701, 5454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("視線を感じるさ～\nもしかして幽霊？\nおしゃべりするさ～♪", 0, 4, 0, 1, 1, 1, 117701, 5455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっき作った\nサーターアンダギー、\n早く彼に\n食べてほしいさ～♪", 0, 5, 0, 1, 1, 1, 117701, 5456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼のために、\n特別なイタズラを\n考えとくさ～♪", 0, 101, 0, 1, 4, 1, 117701, 5457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか彼と、\n故郷のハロウィンを\n楽しみたいさ～♪", 0, 102, 0, 1, 8, 1, 117701, 5458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンは\n私たちが守るさ～♪\nさ、見回りに行こ！", 0, 1, 0, 2, 1, 1, 117701, 5459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この制服、\nハロウィンらしくて\n大好きさ～♪", 0, 2, 0, 2, 1, 1, 117701, 5460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イタズラする気ね～？\nどんなことされるのか\n楽しみさ～♪", 0, 3, 0, 2, 1, 1, 117701, 5461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャのランタン、\n一緒に作ろ！\n絶対楽しいよ～♪", 0, 4, 0, 2, 1, 1, 117701, 5462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子くれるの？\nあは～、ありがとー♪\nもぐもぐ…\n優しい味がするさ～♪", 0, 101, 0, 2, 4, 1, 117701, 5463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミと一緒に過ごす\nハロウィンは、\nドキドキとワクワクが\n止まらないさ～♪", 0, 102, 0, 2, 8, 1, 117701, 5464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンは\n朝から大忙しさ～！\nお菓子作り、\n手伝ってほしいさ～", 0, 1, 1, 2, 1, 1, 117701, 5465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お化け屋敷に行こ！\n一緒にいっぱい\nドキドキしようね～♪", 0, 2, 2, 2, 1, 1, 117701, 5466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここからが\nハロウィン本番さ～！\n幽霊たちと\nいっぱい遊ぶさ～♪", 0, 3, 3, 2, 1, 1, 117701, 5467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと休んだら、\nお菓子作りを\n再開するさ～♪", 0, 2, 0, 3, 1, 1, 117701, 5469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("でーじかわいいね～♪\nこの子に仮装させたら\nきっと似合うさ～♪", 0, 3, 0, 3, 1, 1, 117701, 5470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子みたいに\n甘い匂い…\nハロウィンらしい\nいい香りさ～♪", 0, 4, 0, 3, 1, 1, 117701, 5471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの秋って\n冷えるけど…\nこれがあれば\n体も心もぽかぽかさ～", 0, 5, 0, 3, 1, 1, 117701, 5472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("故郷のご飯も\nおいしいけど、\nこっちのご飯も\nでーじおいしいさ～♪", 0, 7, 0, 3, 1, 1, 117701, 5474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パンプキンパイの\nレシピは…なるほど～\n勉強になるさ～♪", 0, 8, 0, 3, 1, 1, 117701, 5475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("全部おいしそうで\nどれから食べるか\n迷っちゃうさ～♪", 0, 12, 0, 3, 1, 1, 117701, 5477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ムっ！　幽霊の気配を\n感じるデス！\nさあ姿を現すデス！", 0, 1, 0, 1, 1, 1, 117801, 5479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ムムム…\n妖魔の力を忍法に\n使えないでショウか…", 0, 2, 0, 1, 1, 1, 117801, 5480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪しい妖魔を\n成敗するデス！\nハロウィンの平和は\nワタシが守りマスよ！", 0, 3, 0, 1, 1, 1, 117801, 5481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシの祭囃子が\n聞こえマスかー？\nさあ集まるデース！\n陽気に踊りまショウ！", 0, 4, 0, 1, 1, 1, 117801, 5482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お祭りは\n楽しんだ者勝ちデス！\n踊らにゃ\nソンソンデス！", 0, 5, 0, 1, 1, 1, 117801, 5483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊になる前に\n天下統一を\n果たしたいデスね", 0, 101, 0, 1, 4, 1, 117801, 5484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの世に行っても\nショーグンは\nワタシの大事な\nショーグンデス！", 0, 102, 0, 1, 8, 1, 117801, 5485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグン！\n悪霊退治に\n出かけるデース！", 0, 1, 0, 2, 1, 1, 117801, 5486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妖魔を家来に\nしてみるのは\nどうデス？", 0, 2, 0, 2, 1, 1, 117801, 5487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マントを使って\nウツセミの術の精度を\n高めるデス！", 0, 3, 0, 2, 1, 1, 117801, 5488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンにちなんだ\n新しい忍法…\nすなわち妖忍法の\n開発を急ぐデス！", 0, 4, 0, 2, 1, 1, 117801, 5489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの世でも\nショーグンに\nお仕えしマスよー！", 0, 101, 0, 2, 4, 1, 117801, 5490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグンもワタシと\nハロウィンパレードを\n踊り明かしまセンか？", 0, 102, 0, 2, 8, 1, 117801, 5491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございマス！\n天下統一に向けて\n急いで準備するデス！", 0, 1, 1, 2, 1, 1, 117801, 5492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹減ってまセンか？\nハロウィンスイーツで\n休憩するデ〜ス", 0, 2, 2, 2, 1, 1, 117801, 5493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしすると幽霊が\nでるかもしれまセン…\nヒュ〜ドロロロ〜…", 0, 3, 3, 2, 1, 1, 117801, 5494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もふもふなところが\nわたあめちゃんに\n似ていマス。わんっ！", 0, 2, 0, 3, 1, 1, 117801, 5496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみや人形には\n魂が宿るという\n言い伝えがありマス…\nマカフシギデ〜ス", 0, 3, 0, 3, 1, 1, 117801, 5497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウ〜ム…\nなんとも怪しい\n香りがしマスね！", 0, 4, 0, 3, 1, 1, 117801, 5498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パレードの熱気に\n負けないくらい\n熱いデス！", 0, 5, 0, 3, 1, 1, 117801, 5499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ついつい食べすぎて\nしまうのは\n妖魔のせいデスか！？", 0, 7, 0, 3, 1, 1, 117801, 5501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トーゴク妖怪の\n図鑑デス！　個性的な\n妖怪ばかりデスね！", 0, 8, 0, 3, 1, 1, 117801, 5502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンの甘味を\n集めまシタよ！\nショーグンへの\n貢ぎ物デス！", 0, 12, 0, 3, 1, 1, 117801, 5504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と二人で\n買い物に…って…\nこれってデートに\nなっちゃうのかな！？", 0, 103, 0, 1, 12, 1, 101301, 5531);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とうっ！　どうどう？\n今の決めポーズ！\nかっこいいよね♪", 0, 103, 0, 2, 12, 1, 101301, 5532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイとおそろの\nハロウィンコスとか\nしてみたいな～", 0, 1, 0, 1, 1, 1, 117901, 5533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャ料理かぁ…\n作ったらヒデサイ\n食べてくれるかな～", 0, 2, 0, 1, 1, 1, 117901, 5534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンスイーツ…\nどれもおいしすぎて\n激ヤバなんですけど！", 0, 3, 0, 1, 1, 1, 117901, 5535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("霊界ってどんなとこ\nなんだろ～\nわりと近所だったり？", 0, 4, 0, 1, 1, 1, 117901, 5536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("服をハロウィンっぽく\nアレンジするのも\nたのしーよね♪", 0, 5, 0, 1, 1, 1, 117901, 5537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイと一緒に\nハロウィンパーティー\n…えへへ、楽しみ～", 0, 101, 0, 1, 4, 1, 117901, 5538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイといると\nドキドキする…\nなんでだろ～？", 0, 102, 0, 1, 8, 1, 117901, 5539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねねね、うちらも\nハロウィンパレード\n見に行こー？", 0, 1, 0, 2, 1, 1, 117901, 5540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンセイバーズ\nしゅつどーう！\nヒデサイも行こ～♪", 0, 2, 0, 2, 1, 1, 117901, 5541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マントのロゴ\nかっこいいっしょ～？\nカボきちってゆーんだ", 0, 3, 0, 2, 1, 1, 117901, 5542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トリックオア\nトリート！\nねえねえヒデサイ\nお菓子ちょうだい♪", 0, 4, 0, 2, 1, 1, 117901, 5543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイも\nメイクしてみる？\nハロウィンぽいやつ♪", 0, 101, 0, 2, 4, 1, 117901, 5544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイのこと\nうちがいつでも\nあっためたげるね！\n…あ！　手、手の話！", 0, 102, 0, 2, 8, 1, 117901, 5545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンのイベント\n朝からでも\nやってるかな～？", 0, 1, 1, 2, 1, 1, 117901, 5546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャでおやつ\n作ってみたんだ～\nヒデサイ食べてみて！", 0, 2, 2, 2, 1, 1, 117901, 5547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンの夜って\nやっぱテンション\n上がるよね～♪", 0, 3, 3, 2, 1, 1, 117901, 5548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("超ふかふかしてる～\nちょっと休憩させて\nもらっちゃお", 0, 2, 0, 3, 1, 1, 117901, 5550);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…\nもにカワすぎて\nつらいんですけど～！", 0, 3, 0, 3, 1, 1, 117901, 5551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィン限定の\nフレグランスじゃん！\nいい匂いする～♪", 0, 4, 0, 3, 1, 1, 117901, 5552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やばばば…\nあったかくて\n眠くなっちゃう～", 0, 5, 0, 3, 1, 1, 117901, 5553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ食べて\nもうひとがんばり\nしよーっと！", 0, 7, 0, 3, 1, 1, 117901, 5555);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンっぽい\nファッションとか\n載ってないかなぁ？", 0, 8, 0, 3, 1, 1, 117901, 5556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子いっぱいだ～！\nあとでヒデサイにも\n持ってってあげよ～", 0, 12, 0, 3, 1, 1, 117901, 5558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除が終わったら\n次は書類を片付けて…\nその次は…", 0, 1, 0, 1, 1, 1, 118501, 5560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆さんが冒険している\n間の留守は私に\nお任せください♪", 0, 2, 0, 1, 1, 1, 118501, 5561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美食殿の皆さんが\n持ってきてくれる\nお土産が楽しみです♪", 0, 3, 0, 1, 1, 1, 118501, 5562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネビアさんとは\nときどき一緒にお茶\nする仲なんです", 0, 4, 0, 1, 1, 1, 118501, 5563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスの乱れは\nギルドの乱れ\n整理整頓が大切です", 0, 5, 0, 1, 1, 1, 118501, 5564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵なギルドハウスの\n管理人ができて\nとっても幸せです♪", 0, 101, 0, 1, 4, 1, 118501, 5565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆さんをほんの少し\n特別扱いしちゃう\n私がいます", 0, 102, 0, 1, 8, 1, 118501, 5566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何かわからないことが\nあるときは私に\n聞いてくださいね", 0, 1, 0, 2, 1, 1, 118501, 5567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("書類を書いていると\n落ち着きます…\n一緒にどうですか？", 0, 2, 0, 2, 1, 1, 118501, 5568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたのまわりは\nいつも賑やかで\n楽しいですね♪", 0, 3, 0, 2, 1, 1, 118501, 5569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ！　お頼みしたい\nことがあって\n探してたんです♪", 0, 4, 0, 2, 1, 1, 118501, 5570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギブアンドテイクは\n大切です。たまには\nお礼させてください♪", 0, 101, 0, 2, 4, 1, 118501, 5571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("陰に日向にあなたを\n支えていきます♪\n期待していてください", 0, 102, 0, 2, 8, 1, 118501, 5572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\n管理人として\nがんばります♪", 0, 1, 1, 2, 1, 1, 118501, 5573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹がすきました…\nそろそろお昼に\nしませんか？", 0, 2, 2, 2, 1, 1, 118501, 5574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間…\n皆さんといると一日が\nあっという間です", 0, 3, 3, 2, 1, 1, 118501, 5575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良質なお仕事は\n良質な休憩から\nです♪", 0, 2, 0, 3, 1, 1, 118501, 5577);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいものに\n囲まれてお仕事できる\nのは幸せですね♪", 0, 3, 0, 3, 1, 1, 118501, 5578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お仕事に集中できる\nアロマを設置するのも\nよさそうですね♪", 0, 4, 0, 3, 1, 1, 118501, 5579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカ温まりながら\n書類仕事をするのも\nいいものですね…", 0, 5, 0, 3, 1, 1, 118501, 5580);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("栄養補給しないと\n頭が回りませんからね\nきちんと食べましょう", 0, 7, 0, 3, 1, 1, 118501, 5582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新条例はこのように\n活用されている、と…\nふむふむ…", 0, 8, 0, 3, 1, 1, 118501, 5583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("会合用の資料と\n連載のネーム…\nどっちを片付けよう？", 0, 1, 0, 1, 1, 1, 106701, 5585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イノリちゃん、また\nお金くすねてる…\n帰ってきたら\nお尻ペンペンだ♪", 0, 2, 0, 1, 1, 1, 106701, 5586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カヤちゃんの装備\n傷むの早いなぁ〜\nメンテしてあげないと", 0, 3, 0, 1, 1, 1, 106701, 5587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、ラーゴのご飯\n買いに行かないと\n今日は何がいいかな？", 0, 4, 0, 1, 1, 1, 106701, 5588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここの人たちは見てて\n飽きない人ばっかり♪\n漫画の参考にしよ〜", 0, 5, 0, 1, 1, 1, 106701, 5589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また一緒に買い物にも\n行きたいし、冒険も\nしたいな〜…♪", 0, 101, 0, 1, 4, 1, 106701, 5590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…君は見てるだけで\n満足なの？ ちゃんと\n触って欲しいな…♪", 0, 102, 0, 1, 8, 1, 106701, 5591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の目が見たいの？\nいいけど…魅了されて\n魂が壊れちゃうよ…？\n…冗談で〜す☆", 0, 1, 0, 2, 1, 1, 106701, 5592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラーゴがね、君に\n遊んで欲しいって☆\n仲良くしてあげてね", 0, 2, 0, 2, 1, 1, 106701, 5593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アシスタントの仕事\n気に入ってくれたなら\nまたお願いしていい？", 0, 3, 0, 2, 1, 1, 106701, 5594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が覚醒できるか？\n見せてあげたいけど…\nすごいことになるから\nまた今度で♪", 0, 4, 0, 2, 1, 1, 106701, 5595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽しいトラブルが\nあったら、とりあえず\n声はかけて欲しいな♪", 0, 101, 0, 2, 4, 1, 106701, 5596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マッサージお願い♪\n変なところは…\n少しだけなら☆", 0, 102, 0, 2, 8, 1, 106701, 5597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう〜♪\n今日も一日、一緒に\nがんばっていこうね", 0, 1, 1, 2, 1, 1, 106701, 5598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いちゃった…\n一緒にお昼行かない？\nいいお店があるんだ〜", 0, 2, 2, 2, 1, 1, 106701, 5599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君、眠れないの？\n誰かに見られてる？\n…きっと気のせいだよ", 0, 3, 3, 2, 1, 1, 106701, 5600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと休憩〜…\nこのまま原稿すれば\n疲れなくなるのかな？", 0, 2, 0, 3, 1, 1, 106701, 5602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい〜♪\nラーゴのお友達に\nなってくれる？", 0, 3, 0, 3, 1, 1, 106701, 5603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り〜♪\nこの目でどう見えるか\n伝えられたらいいのに", 0, 4, 0, 3, 1, 1, 106701, 5604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほどほどなのが\nちょうどいい時も\nあるよね…♪", 0, 5, 0, 3, 1, 1, 106701, 5605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この味付け…\nあっちでも再現\nできるかな？", 0, 7, 0, 3, 1, 1, 106701, 5607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、面白い♪\nイノリちゃんの買う\n漫画にハズレなし☆", 0, 8, 0, 3, 1, 1, 106701, 5608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私…23歳だもん\n魔法少女だなんて\n名乗れないわ…", 0, 1, 0, 1, 1, 1, 119001, 5610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あん、どぅ、とろわ〜\nみんなイイ子に\nな〜る♪", 0, 2, 0, 1, 1, 1, 119001, 5611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ！　イケナイ子の\n気配がするわ！\n風紀の乱れは\n先生が許しませんっ！", 0, 3, 0, 1, 1, 1, 119001, 5612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで闇の力が\n発動したら大変だわ！\nやだっ…そう思ったら\n緊張して…ダメぇ〜！", 0, 4, 0, 1, 1, 1, 119001, 5613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オイタした子はみんな\nどうしてうれしそうに\n私の愛のムチを\n欲しがるのかしら…？", 0, 5, 0, 1, 1, 1, 119001, 5614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子に次は何を\n教えてあげようかしら\n愛？　希望？\nそれとも…♪", 0, 101, 0, 1, 4, 1, 119001, 5615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子のことを\n考えると、愛と希望で\n胸がいっぱいになるの", 0, 102, 0, 1, 8, 1, 119001, 5616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先生なのに闇の力を\n持ってるのは秘密よ？\n他の子には\n知られたくないから…", 0, 1, 0, 2, 1, 1, 119001, 5617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("秘密の授業の内容？\nそれは…あんなことや\nこんなことよ♪\nそれから、それから…", 0, 2, 0, 2, 1, 1, 119001, 5618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しーっ！　私の正体が\nルーセント学院の\n先生だって、ここでは\n秘密にしててね？", 0, 3, 0, 2, 1, 1, 119001, 5619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら？　補習して\nほしいの？　いいわよ\n君のお願いなら\nなんでも聞いちゃう♪", 0, 4, 0, 2, 1, 1, 119001, 5620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イイ子にはごほうびを\nあげなくちゃ！\n君はなにが欲しい？\n遠慮しちゃダメよ？", 0, 101, 0, 2, 4, 1, 119001, 5621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君との秘密が\nまた一つ\n増えちゃったね♪", 0, 102, 0, 2, 8, 1, 119001, 5622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\n元気に過ごしましょう\n先生が指導してあげる", 0, 1, 1, 2, 1, 1, 119001, 5623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜まで頑張れるように\nお昼ご飯はしっかり\n食べましょう〜！", 0, 2, 2, 2, 1, 1, 119001, 5624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしはダメよ？\nイケナイ子が\nすることです！", 0, 3, 3, 2, 1, 1, 119001, 5625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("闇の力に振り回されて\nもうヘトヘトよ〜\n心も体も\n癒されたいわ〜", 0, 2, 0, 3, 1, 1, 119001, 5627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『秘密の学び舎』に\nこっそり連れて\n行っちゃおうかしら♪", 0, 3, 0, 3, 1, 1, 119001, 5628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イケナイ甘い香り…\nなんだか胸の奥が\n熱くなってきたわ…♪", 0, 4, 0, 3, 1, 1, 119001, 5629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やんっ♪\n燃え上がる愛みたい♪\n火照ってきちゃった♪", 0, 5, 0, 3, 1, 1, 119001, 5630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生徒の見本に\nなれるように\n好き嫌いはしないの", 0, 7, 0, 3, 1, 1, 119001, 5632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『学び舎に咲く禁断の\n愛』？　気になるわ…\nううん、ダメよっ！\nでも…ちょっとだけ…", 0, 8, 0, 3, 1, 1, 119001, 5633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次に会う時は、\nまたあそこに一緒に…\nえへへ…！", 0, 103, 0, 1, 12, 1, 106301, 5635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("横顔見てるの、\nバレてないよね…？\n…ちらっ", 0, 103, 0, 2, 12, 1, 106301, 5636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("背が少し伸びたか！？\nあ、あいつのところへ\n報告に行かねばっ！", 0, 103, 0, 1, 12, 1, 105301, 5637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私も貴公の隣に\n立っていられるよう\n日々精進していくぞ！", 0, 103, 0, 2, 12, 1, 105301, 5638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ～\nドＭミストが\nあふれてしまいます～", 0, 1, 0, 1, 1, 1, 119101, 5639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女として\nクウカ頑張ります～！\n愛と希望の妄想を…！", 0, 2, 0, 1, 1, 1, 119101, 5640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("決めポーズの練習より\nやられポーズの練習を\nしておきます…♪", 0, 3, 0, 1, 1, 1, 119101, 5641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("快感を溜めに溜めて\n放つドＭビームは\n最高ですよ～", 0, 4, 0, 1, 1, 1, 119101, 5642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はっ！\nこれは闇の気配！\n…クウカ自身でした", 0, 5, 0, 1, 1, 1, 119101, 5643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさん…ぐふふ…\nクウカを縛りあげ…\nじゅるりぃ～♪", 0, 101, 0, 1, 4, 1, 119101, 5644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんに攻められる\nことで、クウカは進化\nしてゆくのです～！", 0, 102, 0, 1, 8, 1, 119101, 5645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぅっ！\nもっと激しく…！\n情熱的に～～～！", 0, 1, 0, 2, 1, 1, 119101, 5646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカの変身シーンを\nじっくり眺めたい！？\nは、恥ずかしいです～", 0, 2, 0, 2, 1, 1, 119101, 5647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「本当に魔法少女か\n確かめてやるよ…！」\nドＳさんはそう言って\nクウカを…ぐふふ…♪", 0, 3, 0, 2, 1, 1, 119101, 5648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛と希望の力が\nクウカの中に…\nこの胸の高鳴りが…？", 0, 4, 0, 2, 1, 1, 119101, 5649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃあんっ！\nそこです～っ！\nもっと、もっと～♪", 0, 101, 0, 2, 4, 1, 119101, 5650);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカをこんなに\n悦ばせるのは\nドＳさんだけです…♪", 0, 102, 0, 2, 8, 1, 119101, 5651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明るい時間に出歩くと\n目立ちますね\n魔法少女の衣装…", 0, 1, 1, 2, 1, 1, 119101, 5652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼の見回りです～♪\nああ～うっかりドＭを\n増やしてしまいました", 0, 2, 2, 2, 1, 1, 119101, 5653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜！　それはクウカが\n活性化する時間です！\n闇の活動開始です～♪", 0, 3, 3, 2, 1, 1, 119101, 5654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気の緩んだクウカを\nドＳさんの鋭い牙が\n狙っています～♪", 0, 2, 0, 3, 1, 1, 119101, 5656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女のマスコット\nにいいかもしれません\nもっと鎖とか飾りを…", 0, 3, 0, 3, 1, 1, 119101, 5657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魅惑的な香りです～\nドＭミストの香りに\n似て…いや違いますね", 0, 4, 0, 3, 1, 1, 119101, 5658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火照る体…紅潮した\nクウカの肢体を熱く\n見つめるドＳさん…", 0, 5, 0, 3, 1, 1, 119101, 5659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食欲を満たした次は\n何を満たせば\nいいですかねぇ～♪", 0, 7, 0, 3, 1, 1, 119101, 5661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女がひどい目に\n遭う物語は…\nなさそうですね…", 0, 8, 0, 3, 1, 1, 119101, 5662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ケーキも悪くないけど\nプリンが一番なの\nでもせっかくだから\n両方もらってやるの！", 0, 1, 0, 1, 1, 1, 119901, 5664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスって聞くと\nなんだかあったかい\n気分になるの～", 0, 2, 0, 1, 1, 1, 119901, 5665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("煙突がなくても\nミヤコはどこからでも\nおうちに入れるの♪", 0, 3, 0, 1, 1, 1, 119901, 5666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イブもプリン！\nクリスマスもプリン！\nプレゼントもプリン！", 0, 4, 0, 1, 1, 1, 119901, 5667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスツリーの\n高いところの\n飾りつけは、ミヤコに\nまかせろなの～！", 0, 5, 0, 1, 1, 1, 119901, 5668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツのプレゼント\n楽しみなの～\nきっと最っ高に特別な\nプリンなの～♪", 0, 101, 0, 1, 4, 1, 119901, 5669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミヤコがサンタなら\nアイツはトナカイなの\nつまりお似合いって\nことなの～♪", 0, 102, 0, 1, 8, 1, 119901, 5670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミヤコ、プレゼントを\n配りにいくの～♪\nオマエも手伝えなの！", 0, 1, 0, 2, 1, 1, 119901, 5671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエにも飾りつけ\nしてやるの！\n頭にプリンを乗せると\nかわいいの♪", 0, 2, 0, 2, 1, 1, 119901, 5672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊のミヤコが\nいるなら、サンタも\nいて当たり前なの～！", 0, 3, 0, 2, 1, 1, 119901, 5673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("靴下にプリンを\n入れたらつぶれるの\nだからプリンは直接\nミヤコによこすの～！", 0, 4, 0, 2, 1, 1, 119901, 5674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はプリンだけじゃ\n満足してやらないの！\nミヤコをたくさん\n甘やかせなの！", 0, 101, 0, 2, 4, 1, 119901, 5675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミヤコのプリン\nオマエになら一個…\nうう～、一口だけ\nあげてもいいの！", 0, 102, 0, 2, 8, 1, 119901, 5676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンタの朝は早いの～\nミヤコも早起きして\nプレゼント準備したの\nとってもえらいの♪", 0, 1, 1, 2, 1, 1, 119901, 5677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は一日中\nみんなと遊ぶの～！\nオマエも来いなの！", 0, 2, 2, 2, 1, 1, 119901, 5678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなが寝たら\nチャンスなの～\nこっそりプレゼント\n配りにいくの♪", 0, 3, 3, 2, 1, 1, 119901, 5679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むふー、気持ちいいの\nこういうプレゼントも\nいいかもしれないの", 0, 2, 0, 3, 1, 1, 119901, 5681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ気に入ったの～\nプリンとアイツの\n次くらいなの♪", 0, 3, 0, 3, 1, 1, 119901, 5682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいにおいなの～\nうっかり成仏\nしちゃいそうなの…", 0, 4, 0, 3, 1, 1, 119901, 5683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここに飾っといた\n雪だるま\nなくなっちゃったの\nきっと成仏したの～", 0, 5, 0, 3, 1, 1, 119901, 5684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはオマエがくれる\nプリンとは\n別腹なの～", 0, 7, 0, 3, 1, 1, 119901, 5686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンケーキ…\nこれならミヤコにも\n作れそうなの！\nさっそく作るの！", 0, 8, 0, 3, 1, 1, 119901, 5687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("びっくりしたの～！\n幽霊のミヤコを\n驚かすなんて…\nなかなかやるの！", 0, 14, 0, 3, 1, 1, 119901, 5689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コイツの中…\nあったかいの～♪\n昼寝にぴったりなの～", 0, 15, 0, 3, 1, 1, 119901, 5690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリークリスマス！\n聖夜に笑顔を\nお届けするべ♪", 0, 1, 0, 1, 1, 1, 119201, 5691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマス前は\n乳製品がよく売れて\nありがてぇけんど…\n目が回る忙しさだ～", 0, 2, 0, 1, 1, 1, 119201, 5692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場で売る\nクリスマスリースを\n作っておかねぇと…", 0, 3, 0, 1, 1, 1, 119201, 5693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの動物たちにも\nクリスマスプレゼント\n用意しなきゃなぁ", 0, 4, 0, 1, 1, 1, 119201, 5694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスに向けた\n限定商品とか\n作ってみるべか？", 0, 5, 0, 1, 1, 1, 119201, 5695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんへの\nプレゼント選び…\nここでボケるか…？\nやめておくべか…？", 0, 101, 0, 1, 4, 1, 119201, 5696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オラ、あんちゃんから\n本当にたくさんの物を\nもらってんなぁ…", 0, 102, 0, 1, 8, 1, 119201, 5697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("雪遊びがしたいべか？\nへへっ、あんちゃん\nには負けねぇど！", 0, 1, 0, 2, 1, 1, 119201, 5698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ディナーと一緒に\n聖夜のお笑いライブを\nすんのはどうだべか？\nツッコミは任せたべ！", 0, 2, 0, 2, 1, 1, 119201, 5699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒くなってくると\n鍋が食べたくなるべや\nあんちゃんはどうだ？", 0, 3, 0, 2, 1, 1, 119201, 5700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんは\nサンタさんのこと\n信じてるだか？", 0, 4, 0, 2, 1, 1, 119201, 5701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どでかいクリスマス\nケーキをこさえるべ\nあんちゃんも作るの\n手伝ってくんろ♪", 0, 101, 0, 2, 4, 1, 119201, 5702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんが\nオラの旦那だったら…\nって、あんちゃん！\n今の聞いてただか！？", 0, 102, 0, 2, 8, 1, 119201, 5703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場の朝は早いど！\nさぁてと、まずは\n雪かきしに行くべや", 0, 1, 1, 2, 1, 1, 119201, 5704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんちゃんも一緒に\nお昼食べてくか？\n採れたての冬野菜は\nうんまいど～♪", 0, 2, 2, 2, 1, 1, 119201, 5705);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よい子は早く寝ねぇと\nサンタさんが\n来てくれねぇべよ？", 0, 3, 3, 2, 1, 1, 119201, 5706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのリンリンが\n好きそうだな…\nプレゼント候補に\n入れておくべ！", 0, 2, 0, 3, 1, 1, 119201, 5708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もふもふしてて\nなまらめんこくて…\nあぁ…癒されるべや…", 0, 3, 0, 3, 1, 1, 119201, 5709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い…\n気持ちが和むべや\n夢心地になっちまうな", 0, 4, 0, 3, 1, 1, 119201, 5710);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったけぇところは\n落ち着くなぁ…\nつい眠くなっちまう", 0, 5, 0, 3, 1, 1, 119201, 5711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、この味は…！\n…うーん、もっと\nリアクション芸も\n練習しねぇとな", 0, 7, 0, 3, 1, 1, 119201, 5713);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオシオって\nどんな本読んでんだ？\n…難しい字が\nぎっしりだべや…", 0, 8, 0, 3, 1, 1, 119201, 5714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この仕掛け…\nオラのコントに\n活かせるかも\nしんねぇな", 0, 14, 0, 3, 1, 1, 119201, 5716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この着ぐるみで\nリマリマのモノマネを\n練習してみるべか…？", 0, 15, 0, 3, 1, 1, 119201, 5717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっとキレイになって\nアイツにぎゃふんと\n言わせてやるんだから", 0, 103, 0, 1, 12, 1, 105001, 5718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシのこと\nどう思う？\nかわいいって…そこは\nキレイって言ってよね", 0, 103, 0, 2, 12, 1, 105001, 5719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハートマークの刺繍…\nは、やりすぎですかね\nいやちょっとくらい\nアピールしてみても…", 0, 1, 0, 1, 1, 1, 119301, 5720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("雪降らないかな～\nそしたらお兄ちゃんと\n雪だるま作ったり\nできるのに～", 0, 2, 0, 1, 1, 1, 119301, 5721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントを入れる\n靴下…いくつ編んでも\n足りません～！", 0, 3, 0, 1, 1, 1, 119301, 5722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんとの\nクリスマスデートは\n早い者勝ちですからね\n負けませんよ～！", 0, 4, 0, 1, 1, 1, 119301, 5723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスだし…\n受験勉強は今日だけ\nお休みです♪", 0, 5, 0, 1, 1, 1, 119301, 5724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんと\nおそろいのコーデで\nクリスマスデート…\nしたいなぁ～！", 0, 101, 0, 1, 4, 1, 119301, 5725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんに\nプレゼントする編み物\nこれで３着目～と♪\nあれ、作りすぎ？", 0, 102, 0, 1, 8, 1, 119301, 5726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、もっと近くで\n見たくありませんか？\n私のとっておきの\nクリスマスコーデ♪", 0, 1, 0, 2, 1, 1, 119301, 5727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんが風邪を\n引いたら一大事です！\n私の編み物で暖かく\nしてあげます♪", 0, 2, 0, 2, 1, 1, 119301, 5728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん、ほっぺに\nケーキのクリームが\nついちゃってますよ♪\n私がとってあげます！", 0, 3, 0, 2, 1, 1, 119301, 5729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん！\nケーキ、あーんって\nしてあげます！\nほら、あーん♪", 0, 4, 0, 2, 1, 1, 119301, 5730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスは大切な\n人と過ごすものっ！\nお兄ちゃん…妹の予定\n空いてますよっ！", 0, 101, 0, 2, 4, 1, 119301, 5731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスはずっと、\nお兄ちゃんと一緒に\nいたい…って言ったら\n欲張り…すぎですか？", 0, 102, 0, 2, 8, 1, 119301, 5732);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きは３本お得！\n…クリスマスなら\n追加で10本ぐらい\nもらえちゃうかも！？", 0, 1, 1, 2, 1, 1, 119301, 5733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はケーキ？\nそれとも七面鳥？\nごちそういっぱいで\n迷っちゃいますね～♪", 0, 2, 2, 2, 1, 1, 119301, 5734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんと\nクリスマスに夜更かし\n…えへへ、ちょっぴり\nドキドキしちゃう♪", 0, 3, 3, 2, 1, 1, 119301, 5735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("編み物をするには\n絶好のくつろぎ空間\nですね～♪", 0, 2, 0, 3, 1, 1, 119301, 5737);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんというかわいさ…\nクリスマス\nプレゼントに\nもってこいですね！", 0, 3, 0, 3, 1, 1, 119301, 5738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがお兄ちゃんの\nお部屋の香り…？\nんん～！　ずっと\nかいでいたいです～♪", 0, 4, 0, 3, 1, 1, 119301, 5739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ、あったか～い…\n冬場はこういうのが\nありがたいですね～♪", 0, 5, 0, 3, 1, 1, 119301, 5740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごちそうだぁ～♪\nほら、お兄ちゃんも\n食べて食べてっ！", 0, 7, 0, 3, 1, 1, 119301, 5742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスデートの\n必勝法…こ、これは\n読むしかないです！", 0, 8, 0, 3, 1, 1, 119301, 5743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、すごいです～！\nこれを飾っておけば\nクリスマスが一層\n賑やかになりますね♪", 0, 14, 0, 3, 1, 1, 119301, 5745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぷらーいずっ！\nリマちゃんじゃなくて\nリノちゃんでした～！", 0, 15, 0, 3, 1, 1, 119301, 5746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミにもミソギにも\nあの人にも頼りに\nしてもらえるように\nしっかりしなきゃ！", 0, 1, 0, 1, 1, 1, 120601, 5747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミはにんじんを\n食べられてすごいな…\n私も見習わなきゃ\nがんばろう…！", 0, 2, 0, 1, 1, 1, 120601, 5748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギから怖い話\n聞いちゃった…\nうぅ…誰か一緒に\nいてくれないかな", 0, 3, 0, 1, 1, 1, 120601, 5749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("立派な大人に\nなれるように\nいっぱい勉強\nしておかなくっちゃ！", 0, 4, 0, 1, 1, 1, 120601, 5750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか…あの人の\nあやしい視線を\n感じるような…？", 0, 5, 0, 1, 1, 1, 120601, 5751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人に勉強を\n教えられるように\nしっかり予習を\nしておこうっと…！", 0, 101, 0, 1, 4, 1, 120601, 5752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はあの人と\n一緒に冒険できる…\nなんだかワクワク\nしてきちゃった…！", 0, 102, 0, 1, 8, 1, 120601, 5753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、いいとこに来て\nくれましたね！\nあなたに頼みたい\nことがあるんです！", 0, 1, 0, 2, 1, 1, 120601, 5754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃあっ！？\nへ、変なところを\n触らないでください！", 0, 2, 0, 2, 1, 1, 120601, 5755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうですかこの格好？\nかわいい、ですか…？\nそ、そうですか…\nありがとうございます", 0, 3, 0, 2, 1, 1, 120601, 5756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃあっ…！\nすみません、勉強に\n集中してたので\n驚いちゃいました", 0, 4, 0, 2, 1, 1, 120601, 5757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に勉強して立派な\n大人になりましょうね\n私がそばで見張ってて\nあげます", 0, 101, 0, 2, 4, 1, 120601, 5758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ立派ではないかも\nですけど、私よりも\n大人なあなたのことは\n頼りにしてますからね", 0, 102, 0, 2, 8, 1, 120601, 5759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("立派な大人は\n朝の時間の使い方が\n上手だと聞きました\nあなたはどうですか？", 0, 1, 1, 2, 1, 1, 120601, 5760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミとミソギと\nあなたと…大事な人と\n一緒のお昼ごはんは\nやさしい味がしますね", 0, 2, 2, 2, 1, 1, 120601, 5761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ…怖い話を\n思い出しちゃいました\n寝るまで一緒に\nいてくれますか…？", 0, 3, 3, 2, 1, 1, 120601, 5762);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごい座り心地…！\nとっても勉強が\nはかどりそう…！", 0, 2, 0, 3, 1, 1, 120601, 5764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子…なんだか\nミミに似てるような\n気がする…ふふっ♪", 0, 3, 0, 3, 1, 1, 120601, 5765);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…♪\n勉強で疲れた\n頭がリフレッシュ\nできそうです", 0, 4, 0, 3, 1, 1, 120601, 5766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかだ…♪\nミミとミソギと\nあの人と一緒に\nいるときみたい", 0, 5, 0, 3, 1, 1, 120601, 5767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べたら\n早く大人になれたり\nしないかな…？", 0, 7, 0, 3, 1, 1, 120601, 5769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あう…\n知らない単語が…\nちゃんと調べて\n覚えなくっちゃ…！", 0, 8, 0, 3, 1, 1, 120601, 5770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うさぎさんが\nぴょ～んぴょん♪\nみんなえがおで\nるんたった～♪", 0, 1, 0, 1, 1, 1, 120401, 5773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キョウカちゃんも\nいつかにんじんさんを\n好きになってくれたら\nうれしいな～♪", 0, 2, 0, 1, 1, 1, 120401, 5774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のミソギちゃんの\nイタズラ、びっくり\nしちゃったけど\nおもしろかったな～♪", 0, 3, 0, 1, 1, 1, 120401, 5775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このおうち、いつも\nいろんな人がいて\nドキドキぴょんぴょん\nって楽しいな～♪", 0, 4, 0, 1, 1, 1, 120401, 5776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいお天気～♪\nお外でみんなと\nいっぱい遊びたいな♪", 0, 5, 0, 1, 1, 1, 120401, 5777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギちゃんも\nキョウカちゃんも\nおにいちゃんがいると\nずっと笑顔だね～♪", 0, 101, 0, 1, 4, 1, 120401, 5778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんにはやく\nあいたいな～♪\nまだかな、まだかな♪", 0, 102, 0, 1, 8, 1, 120401, 5779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ♪\nおにいちゃんに\nなでなでされると\nぽかぽかするね♪", 0, 1, 0, 2, 1, 1, 120401, 5780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聞いて、おにいちゃん\nさっきね、かわいい\nちょうちょさんに\n会ったんだよ～♪", 0, 2, 0, 2, 1, 1, 120401, 5781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわっ…！\nおにいちゃんの顔を\nお絵かきしてたから\nびっくりしちゃった♪", 0, 3, 0, 2, 1, 1, 120401, 5782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんも\n遊びたいの？\nそれじゃあ二人も\n呼んで遊ぼう♪", 0, 4, 0, 2, 1, 1, 120401, 5783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんも\nみんなも、優しい人\nばっかりで\nミミ幸せ～♪", 0, 101, 0, 2, 4, 1, 120401, 5784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃん♪\n高い高いしてほしいな\nすっごくぴょんぴょん\nできて、好きなんだ♪", 0, 102, 0, 2, 8, 1, 120401, 5785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう～♪\nおにいちゃん、今日は\nおひさまみたいに\nきらきら元気だね～♪", 0, 1, 1, 2, 1, 1, 120401, 5786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おひるごはんだね～♪\nにんじんさんを\nいっぱい食べて\n元気いっぱい♪", 0, 2, 2, 2, 1, 1, 120401, 5787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…\n眠くなってきちゃった\nおにいちゃん、\n一緒に寝よう～？", 0, 3, 3, 2, 1, 1, 120401, 5788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ、気持ちいい♪\nずっとこうやって\n座ってたくなるね～♪", 0, 2, 0, 3, 1, 1, 120401, 5790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、かわいい～\nぎゅ～っ、ぎゅ～っ♪\nこれで仲よしだね\nえへへ♪", 0, 3, 0, 3, 1, 1, 120401, 5791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいいにおい～♪\nぴょんぴょんしたく\nなってきちゃった♪", 0, 4, 0, 3, 1, 1, 120401, 5792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかぽかぽか♪\nおにいちゃんも\nきてくれたら、もっと\nあったかくなりそう♪", 0, 5, 0, 3, 1, 1, 120401, 5793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…ごっくん♪\nおっきくなりたいから\nいっぱい食べるよ～♪", 0, 7, 0, 3, 1, 1, 120401, 5795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、おもしろ～い\nこの絵本ね、\nキョウカちゃんから\n教えてもらったんだ♪", 0, 8, 0, 3, 1, 1, 120401, 5796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋…探索の\nしがいがありそう！\nついでにイタズラも\nしかけちゃお♪", 0, 1, 0, 1, 1, 1, 120501, 5799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミってああ見えて\n実は大胆で度胸も\nあるよね…ちょっと\nかっこいいな…！", 0, 2, 0, 1, 1, 1, 120501, 5800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怖い話を聞いた時の\nキョウカって\n面白いんだよね～♪", 0, 3, 0, 1, 1, 1, 120501, 5801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんが\n慣れちゃわないように\nまた新しいイタズラを\n考えなきゃ！", 0, 4, 0, 1, 1, 1, 120501, 5802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イタズラもいいけど\nミミとキョウカと\nにいちゃんと、普通に\n遊ぶのも楽しいなぁ♪", 0, 5, 0, 1, 1, 1, 120501, 5803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミにキョウカ、\nそれににいちゃん！\nみんなそろえば愉快な\n冒険が始まりそう！", 0, 101, 0, 1, 4, 1, 120501, 5804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はどんなイタズラを\nしたら、にいちゃんは\n喜んでくれるかな？", 0, 102, 0, 1, 8, 1, 120501, 5805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今ミソギに触ったね？\nヤバいよにいちゃん…\n逃げないとトラップが\n発動しちゃうよ…！", 0, 1, 0, 2, 1, 1, 120501, 5806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わわっ！？　びっくり\nしたあ…！　新しい\nトラップを作ってて\n気づかなかったよ～", 0, 2, 0, 2, 1, 1, 120501, 5807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お？　にいちゃん、\nイタズラする側にも\n興味があるの？", 0, 3, 0, 2, 1, 1, 120501, 5808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんなにか用？\nあ、もしかして…\nミソギと遊びたく\nなっちゃった？", 0, 4, 0, 2, 1, 1, 120501, 5809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ベストタイミングだよ\nにいちゃん！\n今からみんなで探検に\n行くところなんだ！", 0, 101, 0, 2, 4, 1, 120501, 5810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんってさ\nホントに優しいよね\nなにしても怒らないし\n…ありがとね♪", 0, 102, 0, 2, 8, 1, 120501, 5811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんおはよー！\n景気づけに本日\n一発目のイタズラ、\nやっちゃうよ～♪", 0, 1, 1, 2, 1, 1, 120501, 5812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんはロシアン\nサンドイッチだよ！\nさあ、にいちゃん！\n好きなの選んでよ！", 0, 2, 2, 2, 1, 1, 120501, 5813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜ってなんだか\nワクワクしてなかなか\n眠れないんだよね\nにいちゃんはどう？", 0, 3, 3, 2, 1, 1, 120501, 5814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この座り心地のよさ…\nなにかのトラップに\nうまく使えないかな？", 0, 2, 0, 3, 1, 1, 120501, 5816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのに細工して\nミミやキョウカを\n驚かせると、いい反応\nするんだよね♪", 0, 3, 0, 3, 1, 1, 120501, 5817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("においをうまく使った\nイタズラって…\nなにかないかな？", 0, 4, 0, 3, 1, 1, 120501, 5818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったまりながら\n新しいイタズラを\n考えると、いい案が\n出て来たりするんだ♪", 0, 5, 0, 3, 1, 1, 120501, 5819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしくてついつい\n食べ過ぎちゃうなぁ…\nはっ…！？　これって\nまさかトラップ…！？", 0, 7, 0, 3, 1, 1, 120501, 5821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このキョウカから\n借りた冒険物語\nすっごく\nおもしろいんだよね！", 0, 8, 0, 3, 1, 1, 120501, 5822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("晴れ着を着ると\nなんだか心が躍るね\n足取りも軽く\nなるってもんさ", 0, 1, 0, 1, 1, 1, 120801, 5825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月の食べ物ってのは\n美味いもんだね\nいくらでも\n食べれちまうよ", 0, 2, 0, 1, 1, 1, 120801, 5826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段は好き勝手してる\nアタシらも\n正月くらいは\n大人しくするさ", 0, 3, 0, 1, 1, 1, 120801, 5827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年越しそばに雑煮\nこの季節は\n温かいものが\n体に沁みるね", 0, 4, 0, 1, 1, 1, 120801, 5828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月だからって\nのんびりしすぎたね\nちょっと釣りにでも\n行こうかね", 0, 5, 0, 1, 1, 1, 120801, 5829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい正月だね\nいつかあの子と\n一杯やりたいもんだよ", 0, 101, 0, 1, 4, 1, 120801, 5830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大事な人と過ごす\n正月ってのがこんなに\n楽しいもんだとはね", 0, 102, 0, 1, 8, 1, 120801, 5831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋があったかくて\n顔が火照っちまったよ\nちょいと外に涼みに\n行かないか？", 0, 1, 0, 2, 1, 1, 120801, 5832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("餅ってのは\n何をつけてもうまいね\nお前さんは\nどの味が好きだい？", 0, 2, 0, 2, 1, 1, 120801, 5833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お祝いの鯛が\n足りないって？\nそれじゃあアタシが\n釣ってきてやるよ", 0, 3, 0, 2, 1, 1, 120801, 5834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせちが美味いのは\n分かるけど\n食べ過ぎには\n気を付けるんだよ", 0, 4, 0, 2, 1, 1, 120801, 5835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お前さんのおかげで\nいい正月を\n迎えられたよ\nありがとさん！", 0, 101, 0, 2, 4, 1, 120801, 5836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("慣れない晴れ着も\nお前さんに見て\nもらえたなら\n着たかいがあったね", 0, 102, 0, 2, 8, 1, 120801, 5837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようさん\n寒いのは分かるけど\nいい加減布団から\n出て顔洗ってきな", 0, 1, 1, 2, 1, 1, 120801, 5838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の昼飯は雑煮だ\nアタシの郷土の味\nしっかり味わって\nおくれよ", 0, 2, 2, 2, 1, 1, 120801, 5839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おや、お前さんも\n夜ふかしかい？\n退屈してたところさ\n付き合っておくれよ", 0, 3, 3, 2, 1, 1, 120801, 5840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("晴れ着だと座り方にも\n気を遣うね\nしわになったら大変さ", 0, 2, 0, 3, 1, 1, 120801, 5842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくだし\nこの子にも晴れ着を\n着せてあげたいね", 0, 3, 0, 3, 1, 1, 120801, 5843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは冬の花の香り…\n風情があって\nいいじゃないか", 0, 4, 0, 3, 1, 1, 120801, 5844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいねぇ…\nこんな寒い日には\nまさに天国だよ", 0, 5, 0, 3, 1, 1, 120801, 5845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつも食べてる\nものでも正月に\n食べると\n新鮮な気がするね", 0, 7, 0, 3, 1, 1, 120801, 5847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの正月休みだ\nたまにはゆっくりと\n本でも読もうかね", 0, 8, 0, 3, 1, 1, 120801, 5848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新年のあいさつ…\n私も街のみんなに\nしてみようかしら…", 0, 1, 0, 1, 1, 1, 120701, 5850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月はゆっくり過ごす\nのよね…ゆっくりって\n何したらいいのかしら", 0, 2, 0, 1, 1, 1, 120701, 5851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好も\n慣れてくれば\n動きやすいわ", 0, 3, 0, 1, 1, 1, 120701, 5852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、今年の抱負…\nやりたいことが\nたくさんあるのよね", 0, 4, 0, 1, 1, 1, 120701, 5853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせち料理\nネビアの分も\n用意しなくちゃね", 0, 5, 0, 1, 1, 1, 120701, 5854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ\n正月っていいわね\nみんな楽しそうだもの", 0, 101, 0, 1, 4, 1, 120701, 5855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新年の思い出…\nこれからもっと作るわ\nそれが私の抱負よ", 0, 102, 0, 1, 8, 1, 120701, 5856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は家で過ごすの？\nあなたと一緒なら\nきっと楽しいわね", 0, 1, 0, 2, 1, 1, 120701, 5857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どう？　この格好？\nコッコロさんは\n褒めてくれたけど…", 0, 2, 0, 2, 1, 1, 120701, 5858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうど良かったわ\nあなたも大掃除\n手伝ってくれる？", 0, 3, 0, 2, 1, 1, 120701, 5859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これから料理するけど\nお雑煮と焼き餅\nどっちが好きかしら？", 0, 4, 0, 2, 1, 1, 120701, 5860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『今の私』にとって\n初めての正月だもの\nあなたと楽しまないと", 0, 101, 0, 2, 4, 1, 120701, 5861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("去年よりも今年…\nもっと成長するからね\n…お兄ちゃん♪", 0, 102, 0, 2, 8, 1, 120701, 5862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう\nせっかくの正月だもの\n朝から楽しまないとね", 0, 1, 1, 2, 1, 1, 120701, 5863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ…\n良かったら正月の遊び\n教えてくれるかしら？", 0, 2, 2, 2, 1, 1, 120701, 5864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ～…今日が\n終わっちゃうのが…\nもったいないわね…", 0, 3, 3, 2, 1, 1, 120701, 5865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…お参り後だから\n心地よすぎて眠って\nしまいそうだわ…", 0, 2, 0, 3, 1, 1, 120701, 5867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ\nかわいいものって\n癒されるわね…", 0, 3, 0, 3, 1, 1, 120701, 5868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ん\nこれが梅の香り？\n…いい匂いね", 0, 4, 0, 3, 1, 1, 120701, 5869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャルじゃないけど…\nこのまま丸く\nなりたいところね…", 0, 5, 0, 3, 1, 1, 120701, 5870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむっ…♪\nせっかくの正月だもの\n堪能しなくちゃね♪", 0, 7, 0, 3, 1, 1, 120701, 5872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ふんふん\n帯の結び方って\nこんなにあるのね…", 0, 8, 0, 3, 1, 1, 120701, 5873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今の私が作れる\n最高の一曲…\nあの人に届くといいな", 0, 103, 0, 1, 12, 1, 104201, 5875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、歌を…\n聞いてくれませんか？\nあなたに贈る\n特別な歌を", 0, 103, 0, 2, 12, 1, 104201, 5876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひい、ふう…\nむむ、みなに配る\nお年玉のポチ袋が\n残りわずかなのじゃ…", 0, 1, 0, 1, 1, 1, 120901, 5877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宴の準備はわらわに\n任せておくのじゃ！\n支配者の手腕、\n見せつけてくれる！", 0, 2, 0, 1, 1, 1, 120901, 5878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新年の願掛けなら\nわらわにすればよい\n支配者に頼むほうが\n確実じゃろう？", 0, 3, 0, 1, 1, 1, 120901, 5879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなからもらった\nこの年賀状とやら…\nわらわも\n書いてみようかの♪", 0, 4, 0, 1, 1, 1, 120901, 5880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月飾りにもいろいろ\n種類があるんじゃの～\nどれも華々しくて\nわらわ好みじゃ♪", 0, 5, 0, 1, 1, 1, 120901, 5881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あやつへのお年玉は\nちと多めにしておくか\n…日ごろの感謝も\n込めてのう", 0, 101, 0, 1, 4, 1, 120901, 5882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あやつのことを想うと\nそれだけで行く年\n来る年が楽しみになる\nふふ、愉快なやつじゃ", 0, 102, 0, 1, 8, 1, 120901, 5883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなに晴れ着を\n褒められて、とても\nよい気分なのじゃ♪\n次はお主の番じゃぞ？", 0, 1, 0, 2, 1, 1, 120901, 5884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お主へのお年玉は\nいちばん最後じゃ！\n残り物には福が宿る\nそうじゃからのう", 0, 2, 0, 2, 1, 1, 120901, 5885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この季節は手が\nかじかむのう…ほれ、\nお主！　わらわの手を\nあたためるのじゃ！", 0, 3, 0, 2, 1, 1, 120901, 5886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お主のために雑煮を\n手作りしてみたのじゃ\n食べていくがよい♪", 0, 4, 0, 2, 1, 1, 120901, 5887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属のお主に\n正月休みはまだ早い！\nずっとわらわのそばに\n控えておくのじゃ♪", 0, 101, 0, 2, 4, 1, 120901, 5888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、これほど楽しい\n正月は初めてじゃ…\nお主と過ごす時間は\nいつだって特別じゃな", 0, 102, 0, 2, 8, 1, 120901, 5889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きしてわらわを\n待っておったのか？\nさすがはわらわの眷属\n殊勝な心がけじゃな♪", 0, 1, 1, 2, 1, 1, 120901, 5890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事どきじゃな\n正月の宴会料理が\nわらわたちを\n待っておるぞ♪", 0, 2, 2, 2, 1, 1, 120901, 5891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も更けてきたのう\n冬の夜は長い…\n心ゆくまでお主と\n過ごせるわけじゃな♪", 0, 3, 3, 2, 1, 1, 120901, 5892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実に心地がよい♪\nこのまま寝正月も\n悪くないかも\nしれぬのう", 0, 2, 0, 3, 1, 1, 120901, 5894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛いやつじゃのう\nわらわのそばに置いて\nやってもよいぞ♪", 0, 3, 0, 3, 1, 1, 120901, 5895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("品のある香りじゃのう\n寝室に置いておけば\nなにかご利益に\nあずかれそうじゃな", 0, 4, 0, 3, 1, 1, 120901, 5896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心地よい…\nわらわはしばらく\nここから動かぬぞ\nお主も付き合うがよい", 0, 5, 0, 3, 1, 1, 120901, 5897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舌鼓が鳴るのう♪\n正月の宴には\n持ってこいの品じゃ！", 0, 7, 0, 3, 1, 1, 120901, 5899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほう、新春にはそんな\n習わしが…正月を\n制するには、まだまだ\n勉強が必要じゃのう", 0, 8, 0, 3, 1, 1, 120901, 5900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("久しぶりの我が家って\n感じです！　やっぱり\nここが一番ですね〜！", 0, 1, 0, 1, 1, 1, 121001, 5902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ食べましょう！\nみんなで囲める食卓を\n心から味わいますよ☆", 0, 2, 0, 1, 1, 1, 121001, 5903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルに\n帰ってきた途端に\nお腹が空きました〜！", 0, 3, 0, 1, 1, 1, 121001, 5904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ただいま☆\n幸せ特盛りの\nわたしの日常！", 0, 4, 0, 1, 1, 1, 121001, 5905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ようやくランドソルに\n帰ってきたことですし\nやっぱり魔物料理を\nいただきましょう☆", 0, 5, 0, 1, 1, 1, 121001, 5906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人との絆を\n守るために\nもっともっと食べて\n強くならなくちゃ☆", 0, 101, 0, 1, 4, 1, 121001, 5907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもありがとうって\nあの人を思いっきり\n抱きしめたいです☆", 0, 102, 0, 1, 8, 1, 121001, 5908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの想いは\nこの身をかけて\n全力で受け止めます！", 0, 1, 0, 2, 1, 1, 121001, 5909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おかえりなさい☆\nここにいるみんなも\nあなたの帰りをずっと\n待っていましたよ！", 0, 2, 0, 2, 1, 1, 121001, 5910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスで\n冒険の疲れを\n癒しましょう〜！", 0, 3, 0, 2, 1, 1, 121001, 5911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの想いが\n全力全開を超える\n力をくれました！", 0, 4, 0, 2, 1, 1, 121001, 5912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日常が続く幸せを\nあなたと一緒に\nかみしめたいです☆", 0, 101, 0, 2, 4, 1, 121001, 5913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぎゅ〜っ！\nわたしたちは\nどんなことがあっても\nずっと一緒ですよ？", 0, 102, 0, 2, 8, 1, 121001, 5914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\nあなたと過ごせる\n幸せを、今日も\n味わいますよ〜！", 0, 1, 1, 2, 1, 1, 121001, 5915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご飯の時間ですよー！\nあなたも一緒に\n食べましょうね！", 0, 2, 2, 2, 1, 1, 121001, 5916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日もあなたが隣に\nいてくれることを\n心から願ってますよ\nおやすみなさい☆", 0, 3, 3, 2, 1, 1, 121001, 5917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふい〜…\n安心できる場所で\nくつろげるって\n幸せですね〜…", 0, 2, 0, 3, 1, 1, 121001, 5919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じゅるり…\n食べたくなっちゃう\nくらい、かわいい☆", 0, 3, 0, 3, 1, 1, 121001, 5920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…おおー！\nステーキの香り！\nやばいですね☆", 0, 4, 0, 3, 1, 1, 121001, 5921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体がぽかぽかしてきて\nわたしの食欲も\n燃えてきましたよー！", 0, 5, 0, 3, 1, 1, 121001, 5922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしの食欲に\nついてこられますか？\nまだまだ食べますよ！", 0, 7, 0, 3, 1, 1, 121001, 5924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがキャルちゃんの\n言っていた、キスで\n目覚める王子様の\nおとぎ話ですか〜☆", 0, 8, 0, 3, 1, 1, 121001, 5925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分で自分を\n分析するのも、これは\nこれで面白い…♪", 0, 1, 0, 1, 1, 1, 121201, 5927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強過ぎる力の扱いには\n注意しないと…\n七冠がいい例だね", 0, 2, 0, 1, 1, 1, 121201, 5928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年の交友関係は\n計り知れないな…\nアタシも含むのか！", 0, 3, 0, 1, 1, 1, 121201, 5929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("原理を徹底解明して\n再発を防ぐぞー！\n…誰か手伝って～！", 0, 4, 0, 1, 1, 1, 121201, 5930);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは祝福にも\n呪いにもなる…\n忘れずにいよう", 0, 5, 0, 1, 1, 1, 121201, 5931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年が\n目を覚ましてくれて\n本当によかった…", 0, 101, 0, 1, 4, 1, 121201, 5932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼以外を選んでいたら\n今回の事態は\n乗り切れなかったな…\nさすがだよ、少年", 0, 102, 0, 1, 8, 1, 121201, 5933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年！　調子はどう？\nクレープ食べられる？\nっていうか食べて？", 0, 1, 0, 2, 1, 1, 121201, 5934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元気そうで何よりだ\nまた店を手伝いに\nきてよ。二人もキミに\n会いたがってたしさ", 0, 2, 0, 2, 1, 1, 121201, 5935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの診察もあるし\n今はなるべくそばに\nいるよ。迷惑じゃ\nなければだけど", 0, 3, 0, 2, 1, 1, 121201, 5936);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり少年は\nあちこちで人を\n助けてる時が\n一番輝いてるよ", 0, 4, 0, 2, 1, 1, 121201, 5937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシは大したこと\nしてないけど\nみんなのことは\n褒めてあげてね", 0, 101, 0, 2, 4, 1, 121201, 5938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなを笑顔に\nできるのは\nやっぱり少年だね", 0, 102, 0, 2, 8, 1, 121201, 5939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やあ少年\n朝寝坊はしてない？\nそれじゃ、よい１日を", 0, 1, 1, 2, 1, 1, 121201, 5940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おや、少年！\nまかないのクレープ\n作ったけど、食べる？", 0, 2, 2, 2, 1, 1, 121201, 5941);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…もう夜か…\n研究してたら\nあっという間だね…\nおやすみ、少年", 0, 3, 3, 2, 1, 1, 121201, 5942);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体がなまってたのか\n前線に出ると疲れる…\nまさか…年のせい！？", 0, 2, 0, 3, 1, 1, 121201, 5944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミたちも今の\nアタシと同じ感じに\nアレンジしてあげよう", 0, 3, 0, 3, 1, 1, 121201, 5945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰が置いたんだろう？\nいい香りだねぇ…\nうん、気に入った♪", 0, 4, 0, 3, 1, 1, 121201, 5946);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何も考えてない時間も\n実は思考にとって\n大事なんだよね～…", 0, 5, 0, 3, 1, 1, 121201, 5947);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食の大切さは\nいつの食事からも\n感じられるね♪", 0, 7, 0, 3, 1, 1, 121201, 5949);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…面白い！\n今度全巻\n借りにこようっと", 0, 8, 0, 3, 1, 1, 121201, 5950);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聖学祭か…\n良い記憶はないな\nよし忘れよう", 0, 1, 0, 1, 1, 1, 116401, 5952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("健全なる精神は\n健全なる肉体に宿る…\nはっ、知ったことかよ", 0, 2, 0, 1, 1, 1, 116401, 5953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし鏡でも見るか…\nえへへ、ユニだよ♪\nよし子供料金いけるな", 0, 3, 0, 1, 1, 1, 116401, 5954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アオイ君は元気に\nしているだろうか…\n彼女は人一倍ぼくに\n懐いていたからな…", 0, 4, 0, 1, 1, 1, 116401, 5955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろシズル君は\n姉という幻想から\n目覚めただろうか…", 0, 5, 0, 1, 1, 1, 116401, 5956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼくは来年も聖学祭に\n行くさ…卒業しても\n君らとは永遠だ", 0, 101, 0, 1, 4, 1, 116401, 5957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近同志の登校率が\n減少傾向だな…\nまあ仕方ないのだが…\nないのだが…", 0, 102, 0, 1, 8, 1, 116401, 5958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほわあああ！\nおい急に話しかけるな\n学びがこぼれる", 0, 1, 0, 2, 1, 1, 116401, 5959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この体操着、周囲から\n大層評判が良いのだよ\nたいそうだけにな\nどやっ！", 0, 2, 0, 2, 1, 1, 116401, 5960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何を着ていようと\nぼくはぼくさ\n外見など所詮は\n魂の識別符に過ぎん", 0, 3, 0, 2, 1, 1, 116401, 5961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("救護院のアヤネ君が\n最近ぼくの自称年齢に\n疑念を持ち始めてな…\nあの熊…殺るか…", 0, 4, 0, 2, 1, 1, 116401, 5962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん？　なんだね？\nなに、用は無い？\n用も無いのに呼ぶとは\nもしや…これが友達！", 0, 101, 0, 2, 4, 1, 116401, 5963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服が似合ってる？\nな、なんだね突然…\nやめたまえよでゅふふ", 0, 102, 0, 2, 8, 1, 116401, 5964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～あ…\n朝も更けてきたな…\nそろそろ寝るか…", 0, 1, 1, 2, 1, 1, 116401, 5965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～あ…もう昼だ…\n人間の起きている\n時間ではないな…\n早く寝なくては…", 0, 2, 2, 2, 1, 1, 116401, 5966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、よく寝た！\n気持ちのいい夜だな\n今日も一日がんばるぞ", 0, 3, 3, 2, 1, 1, 116401, 5967);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほわぁ～…\nもしやこれは都で噂の\n人を駄目にするやつ…", 0, 2, 0, 3, 1, 1, 116401, 5969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、愛くるしいな\nだが似合い過ぎる…\nぼくが持つと我ながら\n子供にしか見えん", 0, 3, 0, 3, 1, 1, 116401, 5970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アロマか、興味深いな\nミツキ印ポーションも\n気化させて鼻腔から\n吸入してみるか…", 0, 4, 0, 3, 1, 1, 116401, 5971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んふ、んふふ…\n火ってイイよね…\nずっと見てられるね…", 0, 5, 0, 3, 1, 1, 116401, 5972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("や、やめろ…\nとめどなく固形食物を\n生産するのはやめろ…", 0, 7, 0, 3, 1, 1, 116401, 5974);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この可愛げのない筆致\nやはり作者は理系か！\nぐああ目が理系になる", 0, 8, 0, 3, 1, 1, 116401, 5975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あいつのためなら\n無理くらいいくらでも\nしてやるわよ", 0, 1, 0, 1, 1, 1, 121101, 5977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿、\n魔力の制御ムズ過ぎ…\nま、あたしは優秀だし\nどうとでもなるけど！", 0, 2, 0, 1, 1, 1, 121101, 5978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつのこと、\n全部受け入れるって\n決めたから！", 0, 3, 0, 1, 1, 1, 121101, 5979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今なら誰だろうと\n負ける気がしないわ\nドラゴンでもなんでも\nかかってこいっての！", 0, 4, 0, 1, 1, 1, 121101, 5980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("散々助けられた分、\n今度はあたしが\nあいつのこと助けるわ", 0, 5, 0, 1, 1, 1, 121101, 5981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつとの\nこれまでの冒険は\nどれも、あたしの\n大切な思い出…", 0, 101, 0, 1, 4, 1, 121101, 5982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしまたあいつが\n寝たままになったら\nなんだってするわ\nキ…キスでも…", 0, 102, 0, 1, 8, 1, 121101, 5983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに、お腹空いたの？\nなら、おいしいご飯を\n食べに行きましょ♪", 0, 1, 0, 2, 1, 1, 121101, 5984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱ、\nあんたのアホ面見ると\n安心するわ♪", 0, 2, 0, 2, 1, 1, 121101, 5985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("【美食殿】はあんたと\nぺコリーヌがいなきゃ\n始まんないっての", 0, 3, 0, 2, 1, 1, 121101, 5986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃあっ！？\n急に声かけないで！？\n魔力が暴発しても\n知らないわよ！", 0, 4, 0, 2, 1, 1, 121101, 5987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あんたとこうして\nぼーっと過ごす時間、\nまあ…嫌いじゃないわ", 0, 101, 0, 2, 4, 1, 121101, 5988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたが信じて\n見守っててくれれば…\nあたし、\nなんだってできるわ", 0, 102, 0, 2, 8, 1, 121101, 5989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ\n早く顔洗いなさいよ、\nこのねぼすけ♪", 0, 1, 1, 2, 1, 1, 121101, 5990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のお昼は\nどこで食べる？\nあんたが\n決めていいわよ", 0, 2, 2, 2, 1, 1, 121101, 5991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしあんたがまた\n夢に囚われても\nあたしが助けるわ\n安心して寝なさいよ", 0, 3, 3, 2, 1, 1, 121101, 5992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいい～…♪\nあいつもたまには\nこうして休ませなきゃ", 0, 2, 0, 3, 1, 1, 121101, 5994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一目惚れしたかも…！\nこの子、\n部屋に飾りたいわー♪", 0, 3, 0, 3, 1, 1, 121101, 5995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へぇ、あいつって\nこういう匂いが\n好きなのかしら…？", 0, 4, 0, 3, 1, 1, 121101, 5996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かくて最高…♪\n丸くなっちゃいそう…\nうにゃあ…♪", 0, 5, 0, 3, 1, 1, 121101, 5997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イケるわね、これ！\nやっぱり食べるって\n大事よねー♪", 0, 7, 0, 3, 1, 1, 121101, 5999);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ファーストキスは\nどんな味、ね…\nふ、ふ～ん…？\nなるほど…", 0, 8, 0, 3, 1, 1, 121101, 6000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お友だち…\nできるかしら…？\nこんなわたしでも…", 0, 1, 0, 1, 1, 1, 118101, 6002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あまり、きょろきょろ\nしちゃダメよね…\n変な子だと、\n思われてしまうわ…", 0, 2, 0, 1, 1, 1, 118101, 6003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("広い場所、\n落ち着かない…\nはぅ…どこにいれば…", 0, 3, 0, 1, 1, 1, 118101, 6004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("～♪", 0, 4, 0, 1, 1, 1, 118101, 6005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("【レイジ・レギオン】\n…またいつか、\nみんなと…", 0, 5, 0, 1, 1, 1, 118101, 6006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…一度でいいから、\nわたしもママって…\nあっ、その…\n…な、なんでもないわ", 0, 101, 0, 1, 4, 1, 118101, 6007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが、今のわたしに\nとっての帰る場所…\n…そう思っても、\nいいのかしら…？", 0, 102, 0, 1, 8, 1, 118101, 6008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええと…\nお腹、空いてる？\nおねむじゃない？", 0, 1, 0, 2, 1, 1, 118101, 6009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると\n邪魔かしら…？\nならもっと隅っこに…", 0, 2, 0, 2, 1, 1, 118101, 6010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お喋り…？\nわたしでいいの…？\nうれしい…", 0, 3, 0, 2, 1, 1, 118101, 6011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの好きな歌…\n教えて…？\n練習、するから…", 0, 4, 0, 2, 1, 1, 118101, 6012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは賑やかだけど…\nうるさいとは感じない\nむしろ、心地いい…", 0, 101, 0, 2, 4, 1, 118101, 6013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安心、して…\nわたしの歌で、\nあなたを守るから…", 0, 102, 0, 2, 8, 1, 118101, 6014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとだけ…\n朝は、苦手…\n…ふぁ…", 0, 1, 1, 2, 1, 1, 118101, 6015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は、食べた？\n良かったら、一緒に…\n少し…焦げてるけど…", 0, 2, 2, 2, 1, 1, 118101, 6016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠れないのかしら…\nじゃ、じゃあ…\n子守歌…聴く？", 0, 3, 3, 2, 1, 1, 118101, 6017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな特等席…\n恐縮、です…", 0, 2, 0, 3, 1, 1, 118101, 6019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("い、今のうちに、\nこの子でお世話の\n練習を…", 0, 3, 0, 3, 1, 1, 118101, 6020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\n…つらい気持ちも\n癒してくれる", 0, 4, 0, 3, 1, 1, 118101, 6021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nいつまでも、\nこうしていられそう…", 0, 5, 0, 3, 1, 1, 118101, 6022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしく出来てる…\nすごいわ…\n見習わなくっちゃ…", 0, 7, 0, 3, 1, 1, 118101, 6024);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『赤ちゃんとママの\nスキンシップ入門』…\n…べ、勉強になるわ…", 0, 8, 0, 3, 1, 1, 118101, 6025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きれいなお部屋…！\n立派な舞台の\nセットみたい…♪", 0, 1, 0, 1, 1, 1, 121301, 6027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お芝居では私が先輩\nなんだから、しっかり\n私がミサキちゃんを\nエスコートしなきゃ", 0, 2, 0, 1, 1, 1, 121301, 6028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("～～♪\n歌うお芝居も多いから\nもっと上手く\nなりたいな…！", 0, 3, 0, 1, 1, 1, 121301, 6029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいる人たちと\n仲良くなりたいな…\nそしたらきっと演技の\n幅も広げられるよね", 0, 4, 0, 1, 1, 1, 121301, 6030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("機会があったら\nアヤネちゃんとも\nお芝居してみたいな♪", 0, 5, 0, 1, 1, 1, 121301, 6031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんに褒めて\nもらえるように\nお芝居の練習\nいっぱいしなきゃ…♪", 0, 101, 0, 1, 4, 1, 121301, 6032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あう…お兄ちゃんを\n意識したら、台詞が\n飛んじゃったよぅ…！", 0, 102, 0, 1, 8, 1, 121301, 6033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、お兄ちゃん…♪\nお芝居の練習を\n見てくれませんか…？", 0, 1, 0, 2, 1, 1, 121301, 6034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いまの発声練習\nどうでしたか？\nひゃん…！？\n頭は撫でないでぇ～", 0, 2, 0, 2, 1, 1, 121301, 6035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミサキちゃんも\nお芝居、とっても\n上達してるんですよ\n私も負けられません♪", 0, 3, 0, 2, 1, 1, 121301, 6036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また物語を聞かせて\nほしい、ですか…？\n私なんかでよければ\nもちろんよろこんで♪", 0, 4, 0, 2, 1, 1, 121301, 6037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいお話を\n考えてみました\n聞いてくれますか…？\nよかった…♪", 0, 101, 0, 2, 4, 1, 121301, 6038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか…舞台上じゃ\nなくても、照れずに\nお兄ちゃんに気持ちを\n伝えてみせますね…♪", 0, 102, 0, 2, 8, 1, 121301, 6039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\nマヒルさんにもらった\nミルク、一緒に\n飲みませんか？", 0, 1, 1, 2, 1, 1, 121301, 6040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場のみなさんに\nドングリパンを\nいただきました～\nおひとつどうぞ♪", 0, 2, 2, 2, 1, 1, 121301, 6041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝る前にまたココアを\n飲みながら、お話を\n聞いてもらえますか？\nえへへ、うれしいな♪", 0, 3, 3, 2, 1, 1, 121301, 6042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お芝居の練習の\nあとは、ここで\nお兄ちゃんと\nゆっくりしたいな♪", 0, 2, 0, 3, 1, 1, 121301, 6044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も演技の\n練習に付き合ってね♪", 0, 3, 0, 3, 1, 1, 121301, 6045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な香り…\nこのイメージも\nお芝居に\n活かせないかな…？", 0, 4, 0, 3, 1, 1, 121301, 6046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私もお芝居で\nみんなの心を\nぽかぽか温められる\nようになりたいな…♪", 0, 5, 0, 3, 1, 1, 121301, 6047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞台に立つんだから\n食べ過ぎないように\n気をつけないと。\nでも…おいしいなぁ♪", 0, 7, 0, 3, 1, 1, 121301, 6049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお話、面白い…\n脚本を書く\n参考にもなりそう…♪", 0, 8, 0, 3, 1, 1, 121301, 6050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…♪\n二人で見た夕日…\nキレイでしたね…", 0, 103, 0, 1, 12, 1, 107501, 6052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これから泳ぎの\n練習ですか？\n付き合いますよ♪", 0, 103, 0, 2, 12, 1, 107501, 6053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまを導くことで\nわたくしも未知なる\n領域へと辿り着けます", 0, 103, 0, 1, 12, 1, 107601, 6054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまとなら\n海よりも深く\n空よりも高い場所へも\n目指せそうです", 0, 103, 0, 2, 12, 1, 107601, 6055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと二人で\n夏の遠い海に…って\nあたしってば\nなに考えてるのよ！", 0, 103, 0, 1, 12, 1, 107801, 6056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしが楽しく\n過ごせるのはあんたが\nいてくれたからよ\nか、感謝してるわ", 0, 103, 0, 2, 12, 1, 107801, 6057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…アタシってば\nこんなにかわいくって\nキレイなんて罪よね～", 0, 1, 0, 1, 1, 1, 121401, 6058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞台の衣装を\nクリーニング\nしとかなくちゃ…", 0, 2, 0, 1, 1, 1, 121401, 6059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("舞台映えするメイク…\nスズナなら\n知ってるかしら？", 0, 3, 0, 1, 1, 1, 121401, 6060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("物産展の会計係と\n山盛りの算数の宿題…\nどっちが簡単かしら…", 0, 4, 0, 1, 1, 1, 121401, 6061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牧場と温泉の仕事に\nお芝居の練習に…\nちょ、ちょっと休憩～", 0, 5, 0, 1, 1, 1, 121401, 6062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お客さんの視線も\nうれしいけど…\nあいつも見てて\nくれてるかしら？", 0, 101, 0, 1, 4, 1, 121401, 6063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっともっと\nセクシーになって\nあいつをビックリ\nさせてやるわ♪", 0, 102, 0, 1, 8, 1, 121401, 6064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタも休憩？\nしっかり働くために\n休むのも大事よね", 0, 1, 0, 2, 1, 1, 121401, 6065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふん♪　アタシも\n料理ができるように\nなったんだから！\n簡単なのだけだけど…", 0, 2, 0, 2, 1, 1, 121401, 6066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温泉ってお肌に\nいいのよね？\nもっとキレイに\nなったらどうしよう〜", 0, 3, 0, 2, 1, 1, 121401, 6067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("物産展の荷物は\nこれでよし…っと\nそれじゃアンタも\n運ぶの手伝ってよね♪", 0, 4, 0, 2, 1, 1, 121401, 6068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもと違うアタシに\n見とれちゃった？\n仕方ないわね～♪", 0, 101, 0, 2, 4, 1, 121401, 6069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花見って風流で\n大人って感じ♪\n…でもお団子も\n忘れないでよね！", 0, 102, 0, 2, 8, 1, 121401, 6070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなに朝ごはんを\n作ってみたら\n喜んでくれるかしら？", 0, 1, 1, 2, 1, 1, 121401, 6071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お客さんがいっぱい\n来る時間帯ね！\n元気出していくわ！", 0, 2, 2, 2, 1, 1, 121401, 6072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝ないと…\n睡眠不足はお肌の\n大敵なんだから", 0, 3, 3, 2, 1, 1, 121401, 6073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかしてて\n気持ちいい～♪\n疲れが癒されるぅ…", 0, 2, 0, 3, 1, 1, 121401, 6075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子もアタシと\nおそろいの衣装に\nしてあげようかしら♪", 0, 3, 0, 3, 1, 1, 121401, 6076);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な衣装で\nいい香りを\n身にまとう…ふふ、\n大人のたしなみよね♪", 0, 4, 0, 3, 1, 1, 121401, 6077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～い♪\nここでお昼寝したら\n気持ちよさそう…", 0, 5, 0, 3, 1, 1, 121401, 6078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お仕事がんばると\nいつもよりお腹\n空いちゃう～！", 0, 7, 0, 3, 1, 1, 121401, 6080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最新のトレンド\n載ってないかしら？\n物産展の売り物に\n取り入れなくちゃ！", 0, 8, 0, 3, 1, 1, 121401, 6081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪盗のこと…\nお父さんお母さんに\nもし知られたら\nなんて説明しよう…", 0, 1, 0, 1, 1, 1, 121501, 6083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たとえ怪盗でも、人の\n家にお邪魔するときは\n身だしなみをしっかり\nしないと…", 0, 2, 0, 1, 1, 1, 121501, 6084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鍵開けって難しい…\nうーん、もっと\n練習しておかなくちゃ", 0, 3, 0, 1, 1, 1, 121501, 6085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("姿が見えない\n怪盗の噂…？\nわ、私のことじゃ\nありませんように…！", 0, 4, 0, 1, 1, 1, 121501, 6086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("予告状って…\n切手はどこに貼れば\nいいんだろう…？", 0, 5, 0, 1, 1, 1, 121501, 6087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪盗活動にも\n慣れてきたけど…\nやっぱり先輩が\nいないと心細いなぁ…", 0, 101, 0, 1, 4, 1, 121501, 6088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、先輩の心も\nいつか盗めるかな…？\n…わわわ、私ってば\nなに言ってるんだろ…", 0, 102, 0, 1, 8, 1, 121501, 6089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪盗が大活躍って\n新聞で読んだ…？\nだっ、誰のこと\nでしょうね…あはは", 0, 1, 0, 2, 1, 1, 121501, 6090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("尾行に潜入…\n存在感がないのって\n意外と役立つことも\nあるんですね", 0, 2, 0, 2, 1, 1, 121501, 6091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せせせ、先輩っ！\n帽子をぎゅーって\nかぶったら、抜けなく\nなっちゃいました…！", 0, 3, 0, 2, 1, 1, 121501, 6092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬ、盗み聞きなんて\nしてませんよ？\nみんなが私に気づかず\n話し始めるだけで…", 0, 4, 0, 2, 1, 1, 121501, 6093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("秘密道具が見たい？\nそ、それは内緒です！\n秘密道具ですから…\nで、でも先輩になら…", 0, 101, 0, 2, 4, 1, 121501, 6094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ\n見つかっちゃいました\n先輩はいつも私を\n見つけてくれますね…", 0, 102, 0, 2, 8, 1, 121501, 6095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございまふ…\n秘密道具のお手入れで\n夜更かししちゃって…\nちょっと眠たいです～", 0, 1, 1, 2, 1, 1, 121501, 6096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪盗が昼に活動する…\n案外そのほうが\n意外性が\nあるのかも…？", 0, 2, 2, 2, 1, 1, 121501, 6097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外が暗くなりましたね\n…そろそろ怪盗の活動\n始めましょうか？", 0, 3, 3, 2, 1, 1, 121501, 6098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでくつろぐと\n疲れが取れます～\n…今日も怪盗\nがんばろっと", 0, 2, 0, 3, 1, 1, 121501, 6100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、かわいい…！\n心を盗まれるって\nこういうことかな…？", 0, 3, 0, 3, 1, 1, 121501, 6101);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な香り…でも\n服に香りがついたら\n隠れてるときに\n見つかっちゃうかな…", 0, 4, 0, 3, 1, 1, 121501, 6102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかで\nいい気持ち…\n夜道を歩く前に\n温まっておこうっと…", 0, 5, 0, 3, 1, 1, 121501, 6103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怪盗活動に備えて\n今のうちにしっかり\n食べておかなきゃ…！", 0, 7, 0, 3, 1, 1, 121501, 6105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女の子は秘密が\n多いほうが魅力的…？\nそ、そうなんだ…", 0, 8, 0, 3, 1, 1, 121501, 6106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんはいつも\nクウカの妄想の中に…\nぐふふ、じゅるり～♪", 0, 103, 0, 1, 12, 1, 104501, 6108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やさしい触り方も\n嫌いじゃありません…\nは…恥ずかしいですが", 0, 103, 0, 2, 12, 1, 104501, 6109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この大怪盗さまに\n盗めないものなんて\nないです！　たぶん！", 0, 1, 0, 1, 1, 1, 121601, 6110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしにふさわしい\nビッグなお宝は\nどこにあるですかね～", 0, 2, 0, 1, 1, 1, 121601, 6111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろーりそろーり…\n気配を消せばお菓子も\n食べ放題…にやり", 0, 3, 0, 1, 1, 1, 121601, 6112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またサボってたのが\nバレたです…\nボスの地獄耳～！", 0, 4, 0, 1, 1, 1, 121601, 6113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギャングで大怪盗…！\nこの肩書の多さ！\nまさに有能の証です！", 0, 5, 0, 1, 1, 1, 121601, 6114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんだったら…\nお宝を山分けして\nあげてもいいですよ", 0, 101, 0, 1, 4, 1, 121601, 6115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんはアレですよ\n大怪盗イノリさまの\n相棒みたいなものです", 0, 102, 0, 1, 8, 1, 121601, 6116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何事も用心深さが\n大切ですよ。ビ…\nビビりじゃないです！", 0, 1, 0, 2, 1, 1, 121601, 6117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬ、盗み聞き？\nしてないですよっ？\nぴゅーぴゅーぴゅー", 0, 2, 0, 2, 1, 1, 121601, 6118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("情報が欲しければ\nお菓子と交換ですよ\nさぁ、交換交換っ♪", 0, 3, 0, 2, 1, 1, 121601, 6119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しーっ！\n今、尾行中なんです\n話はあとで…", 0, 4, 0, 2, 1, 1, 121601, 6120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんと話してると\n時間が速いような…？\nこの時間泥棒！", 0, 101, 0, 2, 4, 1, 121601, 6121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどよかった！\nいい話があるんです\n一口乗りませんか？", 0, 102, 0, 2, 8, 1, 121601, 6122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おてんとうさまが\n出てやがるですね…\n悪事がやりにくいです", 0, 1, 1, 2, 1, 1, 121601, 6123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間ですか\nご飯にお昼寝…\nいやー忙しいです♪", 0, 2, 2, 2, 1, 1, 121601, 6124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっふっふ！　夜こそ\n大怪盗の時間です！\n……ふぁあ", 0, 3, 3, 2, 1, 1, 121601, 6125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…\n警備の目がないと\n気楽でいいですねぇ", 0, 2, 0, 3, 1, 1, 121601, 6127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くう…！\nこのかわいさは\n盗めないです…♪", 0, 3, 0, 3, 1, 1, 121601, 6128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("犯行現場に残ったのは\n香水の匂いだけ…\nふふ、おしゃれ大怪盗", 0, 4, 0, 3, 1, 1, 121601, 6129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("意外とこういう場所に\n隠し扉があったり…\nしないです？", 0, 5, 0, 3, 1, 1, 121601, 6130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nこの美味しさ…\nとんでもない罠ですね", 0, 7, 0, 3, 1, 1, 121601, 6132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむむ…ちっとも\n分からないです…\nほとんど暗号ですよ", 0, 8, 0, 3, 1, 1, 121601, 6133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、サレンさんは\nどこに行かれた\nのかしら？", 0, 1, 0, 1, 1, 1, 121701, 6135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんふんふーん♪\nなんだか華やいだ\n気分ですわ♪", 0, 2, 0, 1, 1, 1, 121701, 6136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて…次の事業は\nどうしましょう\n何か面白いことは…", 0, 3, 0, 1, 1, 1, 121701, 6137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おーっほっほっほ！\nあら…楽しくて、つい\n笑ってしまいましたわ", 0, 4, 0, 1, 1, 1, 121701, 6138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("センスがあって\nいいお部屋ですわね\n私も見習いたいですわ", 0, 5, 0, 1, 1, 1, 121701, 6139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サレンさんとあのお方\n仲がいいですわね\nも、もちろん仲がいい\nのはよいことですわ！", 0, 101, 0, 1, 4, 1, 121701, 6140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなときでも\n正々堂々！\nそれが私の\n誇りですわ！", 0, 102, 0, 1, 8, 1, 121701, 6141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、ごきげんよう\n私、絶好調でしてよ", 0, 1, 0, 2, 1, 1, 121701, 6142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうかされましたか？\n何かお困りごと\nでしたら\n是非力になりますわよ", 0, 2, 0, 2, 1, 1, 121701, 6143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはこうして\nゆっくりと\nお話しするのも\nいいものですわね", 0, 3, 0, 2, 1, 1, 121701, 6144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の事業に関して\n考え事をしてましたの\nよければ相談に乗って\nくださるかしら？", 0, 4, 0, 2, 1, 1, 121701, 6145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よろしければ\nお話しませんこと？\nサレンさんのお話を\n聞かせてほしいですわ", 0, 101, 0, 2, 4, 1, 121701, 6146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…\n先ほどサレンさんと\nあなたさまのお話を\nしていたところですわ", 0, 102, 0, 2, 8, 1, 121701, 6147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ！\n今日も一日\n全力で参りますわ！", 0, 1, 1, 2, 1, 1, 121701, 6148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はどうしましょう\nサレンさんをお誘い\nしてみようかしら", 0, 2, 2, 2, 1, 1, 121701, 6149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう少しだけ…\n明日の準備をして\nおかないと…", 0, 3, 3, 2, 1, 1, 121701, 6150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～…いいですわね\nはっ、私としたことが\nはしたないですわね", 0, 2, 0, 3, 1, 1, 121701, 6152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいらしいですわ\nいくつになっても\nぎゅっと\nしたくなりますわね", 0, 3, 0, 3, 1, 1, 121701, 6153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着きますわね\nサレンさんはどんな\n香りが好きなのかしら", 0, 4, 0, 3, 1, 1, 121701, 6154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、燃え盛る\n情熱の炎…\nいいですわね", 0, 5, 0, 3, 1, 1, 121701, 6155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このおいしさで\n元手がゼロ…\nすばらしい\n商品ですわ！", 0, 7, 0, 3, 1, 1, 121701, 6157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…ふむふむ\n新しい事業のヒントに\nなりそうですわ", 0, 8, 0, 3, 1, 1, 121701, 6158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、と…\n今日は何をしなくちゃ\nいけないんだっけ？", 0, 1, 0, 1, 1, 1, 121801, 6161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やることは山積み\nだけど、手を動かす\nのは嫌いじゃないわ♪", 0, 2, 0, 1, 1, 1, 121801, 6162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら？　アキノさんの\n声が聞こえたような\n気がしたんだけど…", 0, 3, 0, 1, 1, 1, 121801, 6163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アキノさんといると\nついこっちまで笑顔に\nなっちゃうのよね", 0, 4, 0, 1, 1, 1, 121801, 6164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弱音なんか\nはいてられないわ\nアキノさんに\n笑われちゃうもの", 0, 5, 0, 1, 1, 1, 121801, 6165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気が付けばアキノさん\nのペースだけど…\n不思議と嫌では\nないのよね", 0, 101, 0, 1, 4, 1, 121801, 6166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしを好敵手って\n言ってくれる\nアキノさんのためにも\nしっかりしなくちゃ", 0, 102, 0, 1, 8, 1, 121801, 6167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\nアキノさんなら\nさっきそこに\nいなかった？", 0, 1, 0, 2, 1, 1, 121801, 6168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしなら大丈夫\n救護院だって\nみんなが助けて\nくれるからね", 0, 2, 0, 2, 1, 1, 121801, 6169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっきアキノさんが\nあんたを探してたわよ\nなにかしたの？", 0, 3, 0, 2, 1, 1, 121801, 6170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こう見えてヒマじゃ\nないんだけど…\n少しくらいなら\n付き合ってあげるわ", 0, 4, 0, 2, 1, 1, 121801, 6171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、あんたと\nアキノさんって…\nううん、やっぱり\nなんでもないわ…", 0, 101, 0, 2, 4, 1, 121801, 6172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アキノさんも誘って\nお茶でもしない？\n話したいことが\nたくさんあるの♪", 0, 102, 0, 2, 8, 1, 121801, 6173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きは三文の得よ\nいい一日を迎えるため\n目を覚まさなきゃ", 0, 1, 1, 2, 1, 1, 121801, 6174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のお昼は…\nアキノさんと同席する\n予定だったわね\nあんたもどう？", 0, 2, 2, 2, 1, 1, 121801, 6175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ…っと、だめね\nたるんだところを\nアキノさんに\n見せるわけには", 0, 3, 3, 2, 1, 1, 121801, 6176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～…\n落ち着くわね\nこのまま\n寝ちゃいそう…", 0, 2, 0, 3, 1, 1, 121801, 6178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("救護院の皆も\nぬいぐるみが\n大好きなのよ", 0, 3, 0, 3, 1, 1, 121801, 6179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね…\nこれはアキノさんの\n趣味かしら？", 0, 4, 0, 3, 1, 1, 121801, 6180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなに激しく\n燃えているのに\nあったかくて落ち着く\nまるでアキノさんね", 0, 5, 0, 3, 1, 1, 121801, 6181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんどん出てくる…\nこれ、救護院にも\nほしいわね…", 0, 7, 0, 3, 1, 1, 121801, 6183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\n前にアキノさんが\n言ってたのは\nこのことかしら？", 0, 8, 0, 3, 1, 1, 121801, 6184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装、私には\nちょっとかわい過ぎて\n恥ずかしいな…", 0, 1, 0, 1, 1, 1, 122001, 6187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一部の人からは\n海賊より海賊らしいと\n評判の父です", 0, 2, 0, 1, 1, 1, 122001, 6188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("潮風で錆びないよう\n武器の手入れを\nしておきましょうか", 0, 3, 0, 1, 1, 1, 122001, 6189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宝探しのお手伝いなら\n力になれると思います\n父のやる気次第ですが", 0, 4, 0, 1, 1, 1, 122001, 6190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("除霊は気を遣います\n一歩間違えると父まで\n成仏させてしまうので", 0, 5, 0, 1, 1, 1, 122001, 6191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人と見た\n海の景色を…ずっと\n忘れずにいたいな", 0, 101, 0, 1, 4, 1, 122001, 6192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊になっても\n一目会えるなら…\n私はきっとあの人に…", 0, 102, 0, 1, 8, 1, 122001, 6193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボートを漕ぐの、少し\n上手になったんですよ\n今度お見せしますね", 0, 1, 0, 2, 1, 1, 122001, 6194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("航海に向けた\n買い出しが必要ですね\n予定は空いていますか", 0, 2, 0, 2, 1, 1, 122001, 6195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("呪われた財宝の\n解呪依頼が多くて…\nふぅ…えっと次は…", 0, 3, 0, 2, 1, 1, 122001, 6196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の航海では\n父が明かり代わりに\nなってくれるんです", 0, 4, 0, 2, 1, 1, 122001, 6197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("船の上では食材が\n限られるので料理の\nいい練習になります", 0, 101, 0, 2, 4, 1, 122001, 6198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この先もずっと\nあなたと一緒に\nたくさんの思い出を\n作っていきたいです", 0, 102, 0, 2, 8, 1, 122001, 6199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人の寝顔…\nもう少しだけ\n眺めていたいな…", 0, 1, 1, 2, 1, 1, 122001, 6200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("船の上では\n規則正しい生活が\n重要ですから", 0, 2, 2, 2, 1, 1, 122001, 6201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海は幽霊が\n見分けやすいんです\n青白く光るので", 0, 3, 3, 2, 1, 1, 122001, 6202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に揺られるような\n心地よさですね\n気が休まります…", 0, 2, 0, 3, 1, 1, 122001, 6204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたも一緒に\n海を見に行きますか？\n…なんて。ふふっ", 0, 3, 0, 3, 1, 1, 122001, 6205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("爽やかな香りですね…\n一面の青い海が\n目に浮かぶようです", 0, 4, 0, 3, 1, 1, 122001, 6206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かい…\n潮風で冷えた体に\n沁みますね", 0, 5, 0, 3, 1, 1, 122001, 6207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、おいしい…\n日持ちするなら船旅に\n持っていこうかな…", 0, 7, 0, 3, 1, 1, 122001, 6209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンナさんに教えて\nもらった小説は…\nあ、これですね", 0, 8, 0, 3, 1, 1, 122001, 6210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにもしないを\nしてるんだよ\nあ～いそがしいそがし", 0, 103, 0, 1, 12, 1, 102601, 6212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～あんたといると\nどこまでも気持ちよく\nダラダラできるね～", 0, 103, 0, 2, 12, 1, 102601, 6213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暗黒騎士にして、\n伝説の海賊でもある\n私に不可能はないっ！", 0, 1, 0, 1, 1, 1, 121901, 6214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海賊団の船員、\n随時募集中です…と\nこれで新たな盟友が\n増えるはずだ…！", 0, 2, 0, 1, 1, 1, 121901, 6215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("肩に乗せるペットが\nほしいな。今のうちに\nペット用品を買いに\n行かなくては…！", 0, 3, 0, 1, 1, 1, 121901, 6216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("財宝の地図はどこで\n売っているのだろう…\n古本屋？　古物商？", 0, 4, 0, 1, 1, 1, 121901, 6217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この海賊衣装に\n身を包んでいると\n前世の新たな記憶が\nよみがえってくるな！", 0, 5, 0, 1, 1, 1, 121901, 6218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いずれはシグルドと\n海原への冒険に\n繰り出したいな…\nきっと楽しいぞ！", 0, 101, 0, 1, 4, 1, 121901, 6219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("待ちわびたぞ盟友よ！\n私と貴様あっての\n海賊団…だからその…\n今日はそばにいてくれ", 0, 102, 0, 1, 8, 1, 121901, 6220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルド！　港町で\nお魚のおすそ分けを\nもらったんだ！\n一緒に食べよう！", 0, 1, 0, 2, 1, 1, 121901, 6221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シグルドもこのコート\n羽織ってみないか？\nふふっ、きっとすごく\n似合うと思うぞ！", 0, 2, 0, 2, 1, 1, 121901, 6222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海賊船の新たな\n秘密兵器を作ったぞ！\nシグルド、これから\n見に来ないか！？", 0, 3, 0, 2, 1, 1, 121901, 6223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私は伝説の海賊だから\n泳ぐのだって得意だ！\nふ、深いところは\n少し怖いが…", 0, 4, 0, 2, 1, 1, 121901, 6224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、いつ無人島に\n漂着してもいいように\n非常食は準備済みだ\nシグルドの分もある！", 0, 101, 0, 2, 4, 1, 121901, 6225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冥風戦記の新章が\n完成したぞ…！\nシグルド、まずは\n貴様に読んでほしい！", 0, 102, 0, 2, 8, 1, 121901, 6226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっ、天気明朗\n絶好の航海日和だ！\n早速海に繰り出そう！", 0, 1, 1, 2, 1, 1, 121901, 6227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食用に魚を\n釣っておいたぞ！\nふふ、いかにも\n海賊っぽいだろう？", 0, 2, 2, 2, 1, 1, 121901, 6228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海は真っ黒で\n少しだけ怖いな…\nシグルド、私の\nそばを離れるなよ…！", 0, 3, 3, 2, 1, 1, 121901, 6229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大海賊がくつろぐのに\n相応しい逸品だ…！\nえっと…これ、どこの\nお店で買えますか？", 0, 2, 0, 3, 1, 1, 121901, 6231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わわ、かわいい…！\n船室のベッドに\n置いておきたいな…\n連れてってはダメか？", 0, 3, 0, 3, 1, 1, 121901, 6232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おぉ、この香りは…！\n集中力が上がりそうだ\n海賊船の船長室に\nぜひ置きたいな！", 0, 4, 0, 3, 1, 1, 121901, 6233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これが船乗りの\n伝承に聞く、海原を\nさまよう神秘の火か！\n…暖まるな！", 0, 5, 0, 3, 1, 1, 121901, 6234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹が減っては\n海賊はできぬ！\n…小説も書けぬ！", 0, 7, 0, 3, 1, 1, 121901, 6236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女海賊と騎士はその後\n恋に落ち…？　恋愛\nモノではないかっ！？\nき、興味深くはあるが", 0, 8, 0, 3, 1, 1, 121901, 6237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもの山籠もりが\nブームになるなんて…\n人生、なにが起きるか\n分からないなぁ", 0, 1, 0, 1, 1, 1, 122101, 6239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャンプ道具…\nいえ、キャンプギア！\nカッコいい響き…♪", 0, 2, 0, 1, 1, 1, 122101, 6240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッツ、ＢＢキャン！\nこのフレーズ\n流行るかも…？", 0, 3, 0, 1, 1, 1, 122101, 6241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャンプ仲間…\n募集してみようかな？\n友達も兼任で…", 0, 4, 0, 1, 1, 1, 122101, 6242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユカリさんと\nジュンさん…元気かな\nまた一緒に\nキャンプしたいなぁ…", 0, 5, 0, 1, 1, 1, 122101, 6243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の取材が載った本…\n【フォレスティエ】に\n送らなくちゃ…♪", 0, 101, 0, 1, 4, 1, 122101, 6244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし、あの人が\n落ち込むことが\nあったら…その時は\n私が力になりたいな", 0, 102, 0, 1, 8, 1, 122101, 6245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ブッシュクラフトは\nマイフレンドくんの\nカスタムにも\n活かせる技術です！", 0, 1, 0, 2, 1, 1, 122101, 6246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("会話に花が咲く…\nって言いますよね\n私の場合、会話相手が\nお花そのものですけど", 0, 2, 0, 2, 1, 1, 122101, 6247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服、実は…\n昔ミサト先生に\nこしらえてもらった\n物なんです！", 0, 3, 0, 2, 1, 1, 122101, 6248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昔はやまびこで会話の\n練習をしてたんです\nほとんどオウム返しで\n気まずかったなぁ～", 0, 4, 0, 2, 1, 1, 122101, 6249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうもマイスターです\n…あ、すみません\nみなさんの期待に\n応えようと練習中で…", 0, 101, 0, 2, 4, 1, 122101, 6250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たとえぼっちを\n卒業しても…\n私は一生ＢＢ団です！", 0, 102, 0, 2, 8, 1, 122101, 6251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小鳥さんのさえずりで\n目が覚める…\n心地いいものですね", 0, 1, 1, 2, 1, 1, 122101, 6252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャンプといえば\nおいしいご飯です！\n腕を振るいますよ！", 0, 2, 2, 2, 1, 1, 122101, 6253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すっかり夜ですね…\nおやすみの前に\n星でも見ませんか？", 0, 3, 3, 2, 1, 1, 122101, 6254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("都会でくつろぎ…\n自然の中でくつろぐ…\nくつろぎ無限ループ…", 0, 2, 0, 3, 1, 1, 122101, 6256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり観察すれば\nブッシュクラフトで\n再現できるかも…？", 0, 3, 0, 3, 1, 1, 122101, 6257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～…やっぱり\n木の香りを嗅ぐと\n肩の力が抜けますねぇ", 0, 4, 0, 3, 1, 1, 122101, 6258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ…あったまります\nなんだか心に\nゆとりがでますね…", 0, 5, 0, 3, 1, 1, 122101, 6259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このおいしさ…！\n今度はキャンプに\n持っていこうかな…", 0, 7, 0, 3, 1, 1, 122101, 6261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nいろんな知識があると\nキャンプはもっと\n楽しくなりますよね", 0, 8, 0, 3, 1, 1, 122101, 6262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋がキャンプ用品で\n埋まっていく…\nキャンプ…なんて\n恐ろしい趣味なの…？", 0, 1, 0, 1, 1, 1, 122201, 6264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事でも\nアウトドアでも\n頼れるお姉さんに\nなれたらいいなぁ…", 0, 2, 0, 1, 1, 1, 122201, 6265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服、かわいい上に\n本当に快適ね～♪\nおしゃれにキャンプを\n楽しめて最高だわ！", 0, 3, 0, 1, 1, 1, 122201, 6266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん〜次はどんな\nキャンプ飯を\n作ろうかしら？\n彼の好物は、っと…", 0, 4, 0, 1, 1, 1, 122201, 6267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早く週末が\n来ないかしら…\n仕事を忘れてパーっと\nキャンプ飲みを…！", 0, 5, 0, 1, 1, 1, 122201, 6268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいキャンプ飯の\nレシピを覚えたわ！\n彼も喜んで\nくれるはず…よね♪", 0, 101, 0, 1, 4, 1, 122201, 6269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼の分の食器も\nこっそり買い揃えちゃ\nおうかな…そ、それは\nさすがにまだ早いか…", 0, 102, 0, 1, 8, 1, 122201, 6270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、財団主催で\n大規模なキャンプを\nやってみるのも\nいいかもしれないわね", 0, 1, 0, 2, 1, 1, 122201, 6271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ソロキャンプも\n悪くはないけど\n私はやっぱりキミと…\nな、なんでもない！", 0, 2, 0, 2, 1, 1, 122201, 6272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャンプのことなら\n私に聞いて。なんでも\n教えてあげるから！\n…調べた上でね！", 0, 3, 0, 2, 1, 1, 122201, 6273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャンプ場で飲む\n最高の一杯は\n他じゃ味わえないわ！\nさあ、乾杯っ！", 0, 4, 0, 2, 1, 1, 122201, 6274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん、決めた！　次は\n禁しゅわキャンプ！\nだってキミとゆっくり\n話したいんだもん♪", 0, 101, 0, 2, 4, 1, 122201, 6275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミのおかげで\n本当の最高の一杯が\n味わえたわ…\nありがとう♪", 0, 102, 0, 2, 8, 1, 122201, 6276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー、気持ちいい！\nキャンプが趣味に\nなってから、寝覚めが\nよくなったわ♪", 0, 1, 1, 2, 1, 1, 122201, 6277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は私がごちそう\nするわ。キャンプ飯で\n鍛えた料理の腕前を\n披露しちゃうわよ～！", 0, 2, 2, 2, 1, 1, 122201, 6278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝ましょ？\n明日も朝日を眺める\nためにね。もちろん\nコーヒー付きで♪", 0, 3, 3, 2, 1, 1, 122201, 6279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くつろぐのに\n持ってこいね～\nテントの中に置いても\nよさそうだわ！", 0, 2, 0, 3, 1, 1, 122201, 6281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、かわいいわね～\n…今度キャンプ場に\n連れていこうかしら？", 0, 3, 0, 3, 1, 1, 122201, 6282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん、いい匂い…♪\nキャンプ場を思い出す\n自然の香りだわ〜", 0, 4, 0, 3, 1, 1, 122201, 6283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、温まるぅ～\n冬のキャンプで\n使ってみたいわね", 0, 5, 0, 3, 1, 1, 122201, 6284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい～♪\nキャンプ飲みの\nおつまみに\nぴったりね！", 0, 7, 0, 3, 1, 1, 122201, 6286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へえ…こんなキャンプ\n飯もあるんだ？\n彼、好きだったり\nするかな…", 0, 8, 0, 3, 1, 1, 122201, 6287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一生ついててやるの\n幽霊の一生は\nなっが～～～いの！", 0, 103, 0, 1, 12, 1, 100701, 6289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("む～…あんまり触ると\nすり抜けてやるの！\nウソなの。むふふ♪", 0, 103, 0, 2, 12, 1, 100701, 6290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー…\n今日はベスちゃんと\nなにして遊ぼーかなー", 0, 1, 0, 1, 1, 1, 122301, 6291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴァンピィちゃんも\nけんぞくの友だちと\n仲良くなりたいな♪", 0, 2, 0, 1, 1, 1, 122301, 6292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("けんぞくのお部屋は\nヴァンピィちゃんが\n守ってあげなくちゃ！", 0, 3, 0, 1, 1, 1, 122301, 6293);
