INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいねー…\nヴァンピィちゃん\nずっとここにいるー…", 0, 5, 0, 3, 1, 1, 122301, 6311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむ…\nんー！\nおいしー♪", 0, 7, 0, 3, 1, 1, 122301, 6313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴァンピィちゃん\nこの本\n好きなんだよねー♪", 0, 8, 0, 3, 1, 1, 122301, 6314);
