INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くん！\n海に行くなら\n準備運動\n忘れずにね！", 0, 1, 0, 2, 1, 1, 122401, 6350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐ練習がしたいの？\nいいよ！　水着だから\nなにかあったらすぐに\n助けてあげるね！", 0, 2, 0, 2, 1, 1, 122401, 6351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くんの水着姿も\nかっこよかったよ！\nまた遊びに行こ！\n約束ね！", 0, 3, 0, 2, 1, 1, 122401, 6352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このグローブの向日葵\nかわいいでしょ？\nユイちゃんが\n選んでくれたんだ♪", 0, 4, 0, 2, 1, 1, 122401, 6353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実はこの水着\nいつも着てる\n服とおなじなんだ…\nって、冗談だよ？", 0, 101, 0, 2, 4, 1, 122401, 6354);
