INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏のお日様に\n負けないよう\n今日も元気いっぱい\nがんばるぞー！", 0, 1, 1, 2, 1, 1, 122401, 6356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹減ってきちゃった\n騎士くんはお腹\n空いてない？\n…聞こえちゃった♪", 0, 2, 2, 2, 1, 1, 122401, 6357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\n楽しかったー！\n明日もまた\n楽しもうね！", 0, 3, 3, 2, 1, 1, 122401, 6358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…\nふわふわなのが\nいつもより\nよくわかるよー…", 0, 2, 0, 3, 1, 1, 122401, 6360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ！　水着なら\n濡れてもいいし\n今度洗ってあげるね♪", 0, 3, 0, 3, 1, 1, 122401, 6361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー…いい匂い♪\nなんだか\n身体がぽかぽか\nしてきちゃった！", 0, 4, 0, 3, 1, 1, 122401, 6362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着だから、えっと…\n暖か涼しい…！\n不思議な感じー", 0, 5, 0, 3, 1, 1, 122401, 6363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思いっきり身体を\n動かした後だから\nいくらでも\n食べちゃえるよー！", 0, 7, 0, 3, 1, 1, 122401, 6365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nなるほどー\n水着の種類って\nそんなにあるんだぁ…", 0, 8, 0, 3, 1, 1, 122401, 6366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("乗り心地バッチリだね\nしゅっぱつしんこー！\nなんちゃって♪", 0, 10, 0, 3, 1, 1, 122401, 6368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、ぽよんぽよん！\nトランポリンみたいで\nた～のし～！", 0, 11, 0, 3, 1, 1, 122401, 6369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼のことを考えてると\n幸せで胸が温かくなる\n…私ったら、もう", 0, 103, 0, 1, 12, 1, 101501, 6370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふふふ\nくすぐったいわ～♪\nもう、イタズラっ子ね\n次は先生の番よ～♪", 0, 103, 0, 2, 12, 1, 101501, 6371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの汗\n拭いてあげたいな…\n余計なお世話かな…？", 0, 1, 0, 1, 1, 1, 122601, 6372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテ気味かも…\nそうだ、今夜は\nかば焼きにしよう♪", 0, 2, 0, 1, 1, 1, 122601, 6373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("青い空、白い雲\n眩しい日差し…！\n夏って好きだな…", 0, 3, 0, 1, 1, 1, 122601, 6374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒリヒリする…？\n日に焼けちゃったかな\nふー…ふー…", 0, 4, 0, 1, 1, 1, 122601, 6375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花火大会があるんだ…\n夜、浜辺…2人きり…\nむ、無理だよ〜！", 0, 5, 0, 1, 1, 1, 122601, 6376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着って不思議…\n引っ込み思案が少し\nおさまる…気がする", 0, 101, 0, 1, 4, 1, 122601, 6377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンとまた\n海に行きたいな…\nまた、一緒に…", 0, 102, 0, 1, 8, 1, 122601, 6378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダ、ダイエット！？\nしてないよ！？\n元々これ位だよ…？", 0, 1, 0, 2, 1, 1, 122601, 6379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スイカ割りのコツ？\nわたしは、騎士クンに\n教わりたいな…", 0, 2, 0, 2, 1, 1, 122601, 6380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン。うちわで\n扇いであげるね\nどこに置いたかな…", 0, 3, 0, 2, 1, 1, 122601, 6381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ…暑いね…\n騎士クン、温度計は\n見ない方がいいよ～", 0, 4, 0, 2, 1, 1, 122601, 6382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じ、じっと見ないで…\nええっと…ちょっと！\nちょっとならいいよ…", 0, 101, 0, 2, 4, 1, 122601, 6383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、肝試し？\nう〜ん、うう〜ん…\n…騎士クンとなら！", 0, 102, 0, 2, 8, 1, 122601, 6384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう騎士クン\n見て、あっちの空\nもう入道雲が出てる", 0, 1, 1, 2, 1, 1, 122601, 6385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夕立、来るかなぁ…\nもし雷が鳴ったら\nそばにいてくれる…？", 0, 2, 2, 2, 1, 1, 122601, 6386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しー。…ほら、虫の声\n…わ、わたしの心臓の\n音は気にしないで…！", 0, 3, 3, 2, 1, 1, 122601, 6387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、水着でゴロゴロ\nするのってなんだか…\nいけないことみたい", 0, 2, 0, 3, 1, 1, 122601, 6389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい～♪\n日光浴させて\nあげたいな♪", 0, 3, 0, 3, 1, 1, 122601, 6390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほんのり潮の香りが…\n香ばしくて塩辛くて…\nあ…おなか鳴っちゃう", 0, 4, 0, 3, 1, 1, 122601, 6391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着、乾かせるかも…\nそうだ、みんなの分も\n持ってこよう！", 0, 5, 0, 3, 1, 1, 122601, 6392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテなんてしてたら\nみんなの足を\n引っ張っちゃうよね\nいただきます！", 0, 7, 0, 3, 1, 1, 122601, 6394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの、どうして\n海はしょっぱいの？\nって質問の答えは…\n分かんないよぉ～", 0, 8, 0, 3, 1, 1, 122601, 6395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("顔は怒ってるのに\nなんだかかわいい…\n誰かに似てる…？", 0, 10, 0, 3, 1, 1, 122601, 6397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを枕に、ビーチで\n騎士クンと…なんて…\nなんて…なんて…！", 0, 11, 0, 3, 1, 1, 122601, 6398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休み、\n毎日たのしいな～♪\nつぎはなにしよう？", 0, 1, 0, 1, 1, 1, 122901, 6399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自由研究、\nなににしよっかな～？\nプチグリフォンさんの\nかんさつにっきとか？", 0, 2, 0, 1, 1, 1, 122901, 6400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みって、\n給食ないから…\nそれはちょっぴり\nさみしいかも…？", 0, 3, 0, 1, 1, 1, 122901, 6401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("砂浜をはだしで歩くの\nきもちいいよね♪\nくすぐったいけど\nミミ、好きなんだ～♪", 0, 4, 0, 1, 1, 1, 122901, 6402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きれいな貝がら\n見つけちゃった♪\nミミのたからもの！", 0, 5, 0, 1, 1, 1, 122901, 6403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミ、浴衣を\n買ってもらったんだ♪\n今度、おにいちゃんに\n見せてあげたいな！", 0, 101, 0, 1, 4, 1, 122901, 6404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミ、おにいちゃんと\nいっぱい夏休みの\n思い出つくりたいな♪", 0, 102, 0, 1, 8, 1, 122901, 6405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、おにいちゃん…\n夏休みの宿題、\nわかんないとこ\nおしえてくれる…？", 0, 1, 0, 2, 1, 1, 122901, 6406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おかあさんにね、\n麦茶つくるの上手って\nほめられたんだ～♪\n飲んでみて♪", 0, 2, 0, 2, 1, 1, 122901, 6407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みの宿題で\nポスターかくんだ～♪\nおにいちゃんを\nかいてもいい？", 0, 3, 0, 2, 1, 1, 122901, 6408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("線香花火やりたいな♪\nミミ、長持ちさせるの\n上手なんだよ♪", 0, 4, 0, 2, 1, 1, 122901, 6409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにいちゃんの\n好きな本ってなあに？\nその本で読書感想文\n書こうかな♪", 0, 101, 0, 2, 4, 1, 122901, 6410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海であそんだ後ね、\nおにいちゃんに\n髪を拭いてもらうの\nすきなんだ～♪", 0, 102, 0, 2, 8, 1, 122901, 6411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みって、\nワクワクして\n早起きしちゃうよね♪", 0, 1, 1, 2, 1, 1, 122901, 6412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ♪　お昼は、\n流しそうめんなんだ？\nミミ、流してみたい♪", 0, 2, 2, 2, 1, 1, 122901, 6413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こわい話聞いて、\nねむれないの…\nねえ、おにいちゃん、\nいっしょに寝ていい？", 0, 3, 3, 2, 1, 1, 122901, 6414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっぴりやすんだら\nまた、いっしょに\n海であそぼうね♪", 0, 2, 0, 3, 1, 1, 122901, 6416);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すっごくかわいいね♪\nこの子のこと、\n絵日記にかこうっと♪", 0, 3, 0, 3, 1, 1, 122901, 6417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…\nスイカのにおいだね♪\nこのにおいだいすき！", 0, 4, 0, 3, 1, 1, 122901, 6418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("およいだあとは、\nちゃんと体を\nあっためなくちゃね！", 0, 5, 0, 3, 1, 1, 122901, 6419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みのご飯って\nなんだかとくべつ\nおいしい気がするね♪", 0, 7, 0, 3, 1, 1, 122901, 6421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の星座って\nすっごくきれいだね♪\nいつかみんなと\nいっしょに見たいな♪", 0, 8, 0, 3, 1, 1, 122901, 6422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ♪　この子、\nとってもかわいいね！\nおともだちに\nなりたいな♪", 0, 10, 0, 3, 1, 1, 122901, 6424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミ、人魚姫に\nなったみたい！\nおにいちゃん、\nとなりにすわって♪", 0, 11, 0, 3, 1, 1, 122901, 6425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿になると\nバカンス気分を\n味わえちゃうね！", 0, 1, 0, 1, 1, 1, 122801, 6426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行くの待ちきれ\nなくて、もう水着に\n着替えちゃった！", 0, 2, 0, 1, 1, 1, 122801, 6427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行ったら\nずぶぬれ系のイタズラ\nたくさんしかけよう！", 0, 3, 0, 1, 1, 1, 122801, 6428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の中で泳ぎの練習\nしよう！　にいちゃん\nも水着に着替えて！", 0, 4, 0, 1, 1, 1, 122801, 6429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お日さまとお揃いの\n水着なんだ～♪\n似合ってるかなぁ？", 0, 5, 0, 1, 1, 1, 122801, 6430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海といえば冒険！\n海底に眠る財宝を\n見つけちゃおう！", 0, 101, 0, 1, 4, 1, 122801, 6431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんと一緒だと\n部屋にいても海気分♪\nスイカわりしよっか！", 0, 102, 0, 1, 8, 1, 122801, 6432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃん！\n早く海に行く準備\nしなよ～！", 0, 1, 0, 2, 1, 1, 122801, 6433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねーにいちゃん\n何秒息止められるか\n勝負しよーよ！", 0, 2, 0, 2, 1, 1, 122801, 6434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんはアイスと\nかき氷どっちが好き？\nミソギは…どっちも！", 0, 3, 0, 2, 1, 1, 122801, 6435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日焼け止めクリーム\nキョウカに\nもらったんだ～", 0, 4, 0, 2, 1, 1, 122801, 6436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水中メガネがあれば\n水鉄砲くらっても\n平気だね！", 0, 101, 0, 2, 4, 1, 122801, 6437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着なら、毎日夏休み\n気分！　にいちゃんも\n着てみなよ～！", 0, 102, 0, 2, 8, 1, 122801, 6438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんおはよー！\n早く顔洗って、\nいっぱい遊んじゃお！", 0, 1, 1, 2, 1, 1, 122801, 6439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にいちゃんデザートは\nイチゴのかき氷だよ！\n…激辛ってバレた？", 0, 2, 2, 2, 1, 1, 122801, 6440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は楽しかった～！\n明日もイタズラ日和に\nなるといいな！", 0, 3, 3, 2, 1, 1, 122801, 6441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落とし穴の下に\nやわらかいの置けば\nケガしないよね！", 0, 2, 0, 3, 1, 1, 122801, 6443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいね～！\nこの子も海に\n連れてっちゃおうよ！", 0, 3, 0, 3, 1, 1, 122801, 6444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このにおいを利用して\nイタズラするには…\nにいちゃんどう思う？", 0, 4, 0, 3, 1, 1, 122801, 6445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着を着て暖炉で\nあったまるのって、\n変でおもしろいね～！", 0, 5, 0, 3, 1, 1, 122801, 6446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海辺で食べる\nお昼ごはんって最高♪\nってことで海行こう！", 0, 7, 0, 3, 1, 1, 122801, 6448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか海を越えて、\n地図にも載ってない\n場所を見つけたいな！", 0, 8, 0, 3, 1, 1, 122801, 6449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この口から水が出たら\nみんな驚くよね！\nぷぷ…細工しちゃお！", 0, 10, 0, 3, 1, 1, 122801, 6451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変な音がするイタズラ\nを仕込んどいて…\n誰か座らないかな～♪", 0, 11, 0, 3, 1, 1, 122801, 6452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様と私の愛を\n周りに見せつけて\n差し上げましょう♪", 0, 103, 0, 1, 12, 1, 102701, 6453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("呼びましたか？\n呼びましたね？\nでは愛を語りましょう\nそうしましょう", 0, 103, 0, 2, 12, 1, 102701, 6454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で歩き回るのは\n恥ずかしいな…\n誰も見てないよね？", 0, 1, 0, 1, 1, 1, 122701, 6455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏はやっぱり\nかき氷ですよね\n何色がいいかなぁ…♪", 0, 2, 0, 1, 1, 1, 122701, 6456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人、泳げないって\n聞きました！\n私が教えてあげないと", 0, 3, 0, 1, 1, 1, 122701, 6457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みの宿題は\n計画的に進めましょう\n当たり前のことです！", 0, 4, 0, 1, 1, 1, 122701, 6458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("防犯魔石、どこに\n着けておこうかなぁ\n…ここにしようかな", 0, 5, 0, 1, 1, 1, 122701, 6459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の楽しみ方は\n予習済みです！\nあとは実践ですね♪", 0, 101, 0, 1, 4, 1, 122701, 6460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着…きっとあの人に\n見られちゃいますよね\n…褒めてくれるかな…", 0, 102, 0, 1, 8, 1, 122701, 6461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("触りたいんですか？\n…いいですよ\n帽子くらいなら", 0, 1, 0, 2, 1, 1, 122701, 6462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は体調管理に\n気をつけましょう\n私が管理してあげます", 0, 2, 0, 2, 1, 1, 122701, 6463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行くのが楽しみで\nたまらないんですか？\n私はそこまで…嘘です", 0, 3, 0, 2, 1, 1, 122701, 6464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもより薄着だから\nなんだか恥ずかしい…\nみ、見ないでください", 0, 4, 0, 2, 1, 1, 122701, 6465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へんたいふしんしゃ～\nえっ？　ああ、これは\n海に叫ぶ練習です", 0, 101, 0, 2, 4, 1, 122701, 6466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと一緒に\n海に行くなんて…\nなんだか大人…えへへ", 0, 102, 0, 2, 8, 1, 122701, 6467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\nさぁ、海に行って\n私と運動しましょう", 0, 1, 1, 2, 1, 1, 122701, 6468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっつ～い…\nはっ！？　ダメですよ\nシャキッとしないと！", 0, 2, 2, 2, 1, 1, 122701, 6469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日も海で\n遊ぶために、しっかり\nお休みしましょうね", 0, 3, 3, 2, 1, 1, 122701, 6470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏を楽しむときは\n休憩も大事ですよね\n計画的に、計画的に！", 0, 2, 0, 3, 1, 1, 122701, 6472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいなぁ～\n海のお土産屋さんに\n売ってるかなぁ？", 0, 3, 0, 3, 1, 1, 122701, 6473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人な香りがします\n私も違いが分かる\n素敵な女性になります", 0, 4, 0, 3, 1, 1, 122701, 6474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("濡れた体を\n乾かしましょう\nタオル、タオル…", 0, 5, 0, 3, 1, 1, 122701, 6475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳いだ後は\n栄養補給…だけど\n…おなか膨らんじゃう", 0, 7, 0, 3, 1, 1, 122701, 6477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遊ぶだけじゃなくて\nお勉強もしてますよ\nあなたもどうですか？", 0, 8, 0, 3, 1, 1, 122701, 6478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミが喜びそう…♪\nわ、私ははしゃいだり\nしませんけど…っ！", 0, 10, 0, 3, 1, 1, 122701, 6480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギがいたずらに\n使いそう…しっかりと\n試しておかないと！", 0, 11, 0, 3, 1, 1, 122701, 6481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしがまさか\nここにいるなんて…\n自分でも不思議だわ", 0, 1, 0, 1, 1, 1, 123001, 6482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昔みたいにあちこち\n飛び回れないのって\nちょっと不便かも", 0, 2, 0, 1, 1, 1, 123001, 6483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうして誰かと一緒に\n暮らせるのもあいつや\nみんなのおかげね", 0, 3, 0, 1, 1, 1, 123001, 6484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで厄介になるなら\nあたしも家事とか\n手伝わないと…", 0, 4, 0, 1, 1, 1, 123001, 6485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…だめ！　誰かの\n世話をせずには\nいられないわ！", 0, 5, 0, 1, 1, 1, 123001, 6486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつたちが\n帰ってくるところだし\n綺麗にしないと…", 0, 101, 0, 1, 4, 1, 123001, 6487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくあたしが\nいるっていうのに\n少しは構いなさいよ…", 0, 102, 0, 1, 8, 1, 123001, 6488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい店とか\n知らないの？\n食べに行きましょ", 0, 1, 0, 2, 1, 1, 123001, 6489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんた暇でしょ？\nあたしのやること\n手伝いなさい", 0, 2, 0, 2, 1, 1, 123001, 6490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コッコロたんと\n遊んでくるから\n留守番よろしく♪", 0, 3, 0, 2, 1, 1, 123001, 6491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらおかえり…って\nボロボロじゃない！\nまた人助けしてたの？", 0, 4, 0, 2, 1, 1, 123001, 6492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりあたしは\nあんたのそばが\n一番落ち着くみたい", 0, 101, 0, 2, 4, 1, 123001, 6493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこまでだって\nあんたと一緒に\nいてやるんだから", 0, 102, 0, 2, 8, 1, 123001, 6494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…おはよう\n…大きくなったせいか\n朝は特に体が重いわ", 0, 1, 1, 2, 1, 1, 123001, 6495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯が食べたい？\nしょうがないわね…\nなんか作って\nあげるから", 0, 2, 2, 2, 1, 1, 123001, 6496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたまだ成長期だし\nさっさと寝なさい\n大きくなれないわよ？", 0, 3, 3, 2, 1, 1, 123001, 6497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはあたしも\nゆっくりしないと\nもたないのよ…", 0, 2, 0, 3, 1, 1, 123001, 6499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいじゃな～い♪\nコッコロたんに\nプレゼントしたいわ", 0, 3, 0, 3, 1, 1, 123001, 6500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね\n塔にもこういうの\n置いておこうかしら", 0, 4, 0, 3, 1, 1, 123001, 6501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("炎か…前は\n羽が焼けそうで\n怖かったっけ", 0, 5, 0, 3, 1, 1, 123001, 6502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あむ…妖精に\n体重増減の設定って\nあったっけ…？", 0, 7, 0, 3, 1, 1, 123001, 6504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("記憶のデータと違って\n物語はいいわね\n結末が読めなくて", 0, 8, 0, 3, 1, 1, 123001, 6505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険のお土産\nみんなにおすそわけ\nせなあきまへんな", 0, 1, 0, 1, 1, 1, 123101, 6507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おとぎ話よりも\n不思議なことが\nあるもんやねぇ", 0, 2, 0, 1, 1, 1, 123101, 6508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険しに出かけるなら\n動きやすい服装に\nせななぁ", 0, 3, 0, 1, 1, 1, 123101, 6509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("地図に水筒に…\n他に忘れもんは\nあらへんやろか？", 0, 4, 0, 1, 1, 1, 123101, 6510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これまでの冒険のこと\nノートに書いて\nまとめてますんよ", 0, 5, 0, 1, 1, 1, 123101, 6511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんとの冒険は\nどれもマホマホ王国の\n大事な歴史や♪", 0, 101, 0, 1, 4, 1, 123101, 6512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこへ冒険するときも\nうちと王子はんは\n一緒どす♪", 0, 102, 0, 1, 8, 1, 123101, 6513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法で火ぃつける\n練習してますんよ～\nよう爆発しますけど…", 0, 1, 0, 2, 1, 1, 123101, 6514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちと王子はんで\n冒険道具をお揃いに\nするんもええなぁ♪", 0, 2, 0, 2, 1, 1, 123101, 6515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("テント張りも随分\n上達したんよ\n王子はんのおかげやね", 0, 3, 0, 2, 1, 1, 123101, 6516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランスロットたちの\n新しい冒険衣装\n思いついたんよ♪", 0, 4, 0, 2, 1, 1, 123101, 6517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("迷子になっても\n王子はんと一緒なら\nきっと大丈夫やね♪", 0, 101, 0, 2, 4, 1, 123101, 6518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんのこと、\nきっちり守れるように\nなってみせますえ", 0, 102, 0, 2, 8, 1, 123101, 6519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お寝坊さんは\n布団めくって\n起こしにいきますえ～", 0, 1, 1, 2, 1, 1, 123101, 6520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("支度が終わったら\n今日の冒険に\n出かけまひょか", 0, 2, 2, 2, 1, 1, 123101, 6521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうちょっと\nおしゃべりしたいん？\nあと少しだけやで♪", 0, 3, 3, 2, 1, 1, 123101, 6522);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険で疲れた体に\nこの癒しぱわーは\nあきまへん…すや…", 0, 2, 0, 3, 1, 1, 123101, 6524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、あんさんも\nうちと一緒に\n冒険します？", 0, 3, 0, 3, 1, 1, 123101, 6525);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("虫除けのアロマは\n冒険の必需品どす\n忘れんようにせんと", 0, 4, 0, 3, 1, 1, 123101, 6526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちも魔法使わんでも\n火ぃ起こせるよう\n練習せんとあかんなぁ", 0, 5, 0, 3, 1, 1, 123101, 6527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この料理…\n冒険するときに\n作ってみまひょか", 0, 7, 0, 3, 1, 1, 123101, 6529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんとの\n愛と冒険のおとぎ話…\nはぁ…素敵やわぁ♪", 0, 8, 0, 3, 1, 1, 123101, 6530);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人との\n最良の未来のために\n占いも霊能力ももっと\n精進しなきゃ", 0, 103, 0, 1, 12, 1, 103101, 6532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたともっと深く\nつながりたいです\n絆も、そして魂までも", 0, 103, 0, 2, 12, 1, 103101, 6533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絆の契約…\nあやつが望むのなら\n考えぬでもないがのう", 0, 103, 0, 1, 12, 1, 104401, 6534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんじゃ？\nわらわの姿に\n見惚れたかの？", 0, 103, 0, 2, 12, 1, 104401, 6535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅の荷物って多いな…\nねぇぷうきち～\nすこしは持ってよぉ～", 0, 1, 0, 1, 1, 1, 123201, 6536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("傘はなくてもいっか\nぷうきちがいるし♪\n『おいなんだと…？』", 0, 2, 0, 1, 1, 1, 123201, 6537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅先で人見知りなんか\nしてちゃだめだよね…\nまずはあいさつだ…！", 0, 3, 0, 1, 1, 1, 123201, 6538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おみやげはやっぱり\nご当地ぬいぐるみ\nだよね♪　ワクワク…", 0, 4, 0, 1, 1, 1, 123201, 6539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知らない場所かぁ…\nうぅ…考えただけで\nすでにホームシック…", 0, 5, 0, 1, 1, 1, 123201, 6540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("野宿するってことは…\nお兄ちゃんのマントで\n寝るチャンスかも…！", 0, 101, 0, 1, 4, 1, 123201, 6541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなに危険な冒険も\nお兄ちゃんと一緒なら\n大丈夫！　…だよね？", 0, 102, 0, 1, 8, 1, 123201, 6542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぷうきちのアイマスク\nも腹巻も持ってくの！\n旅の必需品なの～！", 0, 1, 0, 2, 1, 1, 123201, 6543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ全部背負うのって\nけっこうむずかしいの\n順番まちがえると大変", 0, 2, 0, 2, 1, 1, 123201, 6544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ～\nなでなでして？　帽子\nの上からでもいいよ♪", 0, 3, 0, 2, 1, 1, 123201, 6545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『悪いが絆創膏の部分\nはアンタッチャブルだ\n綿が飛び出ちまう』", 0, 4, 0, 2, 1, 1, 123201, 6546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんと一緒に\nもっともっといろんな\n景色が見たいな！", 0, 101, 0, 2, 4, 1, 123201, 6547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅って、終わる時は\nきっとさびしいよね…\nお兄ちゃん、帰り道は\n手をつないでもいい？", 0, 102, 0, 2, 8, 1, 123201, 6548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("出発が楽しみすぎて\n寝られなかった…\n『旅行のお約束だな』", 0, 1, 1, 2, 1, 1, 123201, 6549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ　いいお天気！\n旅の間もずーっと\nぴーかんだといいな♪", 0, 2, 2, 2, 1, 1, 123201, 6550);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知らない場所で寝るの\n怖いな…寝る時だけ\n帰ってこようかな…", 0, 3, 3, 2, 1, 1, 123201, 6551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅先にはクッションも\nソファもないよね…\n『俺でいいだろ』", 0, 2, 0, 3, 1, 1, 123201, 6553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみのみんな\n旅の無事を\n祈ってて…！", 0, 3, 0, 3, 1, 1, 123201, 6554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅先の香りも\n思い出に持って\n帰れたらいいのにな～", 0, 4, 0, 3, 1, 1, 123201, 6555);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅行用に携帯用暖炉\nがあるといいかも…！\n『まだ荷物増やす？』", 0, 5, 0, 3, 1, 1, 123201, 6556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『もう出発だぜ？』\nえーまってまって！\n腹ごしらえがまだ…", 0, 7, 0, 3, 1, 1, 123201, 6558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界ってこんなに広い\nんだ…！　はやく自分\nの目で見てみたいな～", 0, 8, 0, 3, 1, 1, 123201, 6559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はちゃめちゃヒマ～\nなーんか楽し～コト\nないかなー", 0, 1, 0, 1, 1, 1, 123301, 6561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ、いートコだねー\nこんどカリザきゅんも\nつれてこよー", 0, 2, 0, 1, 1, 1, 123301, 6562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわゆいショタが\n見た～い♪\n触りた～～～い♪", 0, 3, 0, 1, 1, 1, 123301, 6563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんか服きっついなー\nちょい太ったかー？\nん～\nま・気のせーっしょ♪", 0, 4, 0, 1, 1, 1, 123301, 6564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ～やべ\nおねえちゃんに\nメッセすんの忘れたー\nまいっかー", 0, 5, 0, 1, 1, 1, 123301, 6565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パンケーキ食いてー\n騎士きゅん\n誘ってみよーっと♪", 0, 101, 0, 1, 4, 1, 123301, 6566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きょーも～\n好きぴに囲まれて～\nシ・ア・ワ・セ♪", 0, 102, 0, 1, 8, 1, 123301, 6567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシと遊ばな～い？\nってなんか\nナンパみスゴー\nウケる～", 0, 1, 0, 2, 1, 1, 123301, 6568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んー？\n今はだるいからパース\nあとでねー", 0, 2, 0, 2, 1, 1, 123301, 6569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カリザきゅん\n見なかった～？\nおねえちゃんから\n逃げるとかオシオキー", 0, 3, 0, 2, 1, 1, 123301, 6570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネイルしたいけど\n無理なんよねー\n爪の間にめっちゃ\nスライム入っからさー", 0, 4, 0, 2, 1, 1, 123301, 6571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おねえちゃんに\nかまってほし～の？\nかわゆ～い♪", 0, 101, 0, 2, 4, 1, 123301, 6572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な～に騎士きゅん♪\nここでイチャイチャ～\nし・ちゃ・う～？", 0, 102, 0, 2, 8, 1, 123301, 6573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねんむ～\nけど外から\nショタの声したんで～\nつい起きちった～", 0, 1, 1, 2, 1, 1, 123301, 6574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランチの後はやっぱ\nデザートっしょー\nベツバラってヤツ～♪", 0, 2, 2, 2, 1, 1, 123301, 6575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな時間まで\n起きてるコは～\n食べちゃうぞ～♪", 0, 3, 3, 2, 1, 1, 123301, 6576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーラクー\nいっしょーここで\nキューケーできるわー", 0, 2, 0, 3, 1, 1, 123301, 6578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なにこれ～\nかわいいじゃ～ん\nショタの次くらいに～", 0, 3, 0, 3, 1, 1, 123301, 6579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いーニオイする～\nなんのニオイとかー\nよくわかんないけどー", 0, 4, 0, 3, 1, 1, 123301, 6580);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったか～♪\n溶けてスライム\n戻りそ～", 0, 5, 0, 3, 1, 1, 123301, 6581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ン・ン・ン～♪\nお・い・し～♪\nも～っと食べるぅ～♪", 0, 7, 0, 3, 1, 1, 123301, 6583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ～なんかムズー\n読めなー\nウケるー", 0, 8, 0, 3, 1, 1, 123301, 6584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんパンって\nお菓子に入るのかな？\nハロウィンで\nもらえたりしない？", 0, 1, 0, 1, 1, 1, 123501, 6586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子をくれなきゃ\nぐうたらするぞ～！\nハロウィン以外でも！", 0, 2, 0, 1, 1, 1, 123501, 6587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お化けになったら\n仕事しないで\nゴロゴロし放題\nなのかな？", 0, 3, 0, 1, 1, 1, 123501, 6588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと…この仮装\n袖がすごく長いからさ\n引っ掛けないように\n気を付けないとね～", 0, 4, 0, 1, 1, 1, 123501, 6589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イタズラするのも\n体力がいるよね～\n楽にできそうなの\n何かないかな？", 0, 5, 0, 1, 1, 1, 123501, 6590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつって\n仮装とかするのかな？\n似合いそうなのは\nどんなお化けだろ？", 0, 101, 0, 1, 4, 1, 123501, 6591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっとハロウィンなら\nあいつと遊び放題\nなんだけどな～", 0, 102, 0, 1, 8, 1, 123501, 6592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今の街はハロウィン\n一色だからね～\n人混みが大変だよ", 0, 1, 0, 2, 1, 1, 123501, 6593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この仮装、どうかな？\n気に入ったなら\n来年もしてあげるよ～", 0, 2, 0, 2, 1, 1, 123501, 6594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実はこの長い袖\nドングリとかを\nため込めるんだよね…", 0, 3, 0, 2, 1, 1, 123501, 6595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャランタンが\nあるんなら\nドングリランタンも\nあっていいよね～♪", 0, 4, 0, 2, 1, 1, 123501, 6596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンでも\nやる気があれば\nぐうたらできる…\nうん、いいこと言った", 0, 101, 0, 2, 4, 1, 123501, 6597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にお菓子食べよ？\n寝転びながら堪能する\nハロウィンスイーツは\n最高だからね～", 0, 102, 0, 2, 8, 1, 123501, 6598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お化けは寝る時間…\n今のあたしはお化け…\nだから、おやすみ～…", 0, 1, 1, 2, 1, 1, 123501, 6599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼か～…\n食後のデザートは\nハロウィンのお菓子で\n決まりだね～♪", 0, 2, 2, 2, 1, 1, 123501, 6600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～、寝よ…\nお化けは夜に\n出るものだけど\nあたしはリスだからね", 0, 3, 3, 2, 1, 1, 123501, 6601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンを楽しむ\nためにも、ぐっすり\n寝とかないとね～", 0, 2, 0, 3, 1, 1, 123501, 6603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…袖から手が\n出せないから\nこのまま撫でよう\nよしよし", 0, 3, 0, 3, 1, 1, 123501, 6604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リラックスできる\n素敵な香りだね～\n成仏しそうだよ～", 0, 4, 0, 3, 1, 1, 123501, 6605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいね～\nここで寝てもいい？\n…着替えないとダメか", 0, 5, 0, 3, 1, 1, 123501, 6606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nお化けもリスも\nお腹は空くんだよ", 0, 7, 0, 3, 1, 1, 123501, 6608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キョンシーって\nどんなお化けなのか\n本で調べようかな？", 0, 8, 0, 3, 1, 1, 123501, 6609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("より取り見取りだね～\nとりあえず、これと\nこのお菓子はキープで", 0, 12, 0, 3, 1, 1, 123501, 6611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よし、衣装もばっちり\nハロウィンパレードへ\n出かけよう♪", 0, 1, 0, 1, 1, 1, 123601, 6613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仮装してても\n剣は手放せないね\nほとんど体の一部だよ", 0, 2, 0, 1, 1, 1, 123601, 6614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見回りに誘うふりして\n二人でパレードに\n参加しちゃおうかな♪", 0, 3, 0, 1, 1, 1, 123601, 6615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あれ？　手錠の鍵\n落としちゃった…？\nやば、出かける前に\n見つけないと…！", 0, 4, 0, 1, 1, 1, 123601, 6616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お家でコスプレも\nこれはこれで楽しいな\n決めポーズの練習\nたくさんしておこう！", 0, 5, 0, 1, 1, 1, 123601, 6617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("他にも、お姫様に\nメイドさんに学生服…\nやりたいコスプレが\n多すぎるよ～", 0, 101, 0, 1, 4, 1, 123601, 6618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("漫画もゲームも好き！\n仮装するのも大好き！\n…好きを言葉にすると\nもっと好きになる♪", 0, 102, 0, 1, 8, 1, 123601, 6619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっと目が合ってるね\n見つめてくれるのは\nいいんだけど、今日は\n衣装を見てほしいな♪", 0, 1, 0, 2, 1, 1, 123601, 6620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トリックオアトリート\nお菓子をくれなきゃ\n逮捕しちゃうぞ♪", 0, 2, 0, 2, 1, 1, 123601, 6621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたにだけはこの姿\nいつでも見せてあげる\nふふ、なんちゃって♪", 0, 3, 0, 2, 1, 1, 123601, 6622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\nイタズラするなら\n隙を突かなきゃ\nこんなふうに、ね♪", 0, 4, 0, 2, 1, 1, 123601, 6623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コスプレしてても\n剣の稽古は休まないよ\nちょっと相手になって\nくれるかな？", 0, 101, 0, 2, 4, 1, 123601, 6624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっ、びっくりした\n急に触らないでよ～\nハロウィンだからって\nイタズラしないでね？", 0, 102, 0, 2, 8, 1, 123601, 6625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n今日も朝から\nパトロールに行こう！", 0, 1, 1, 2, 1, 1, 123601, 6626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カボチャのケーキを\n用意してるよ！\nデザートを食べて\n午後も頑張ろう！", 0, 2, 2, 2, 1, 1, 123601, 6627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暗くなってきたね\nカボチャのランタンに\n火を灯そうよ♪", 0, 3, 3, 2, 1, 1, 123601, 6628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか気持ちいい～\nあっでも衣装がシワに\nなっちゃうかも…？\n…でも気持ちいい～", 0, 2, 0, 3, 1, 1, 123601, 6630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…かわいい\nこの子もパレードに\n連れて行きたいな", 0, 3, 0, 3, 1, 1, 123601, 6631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～癒される♪\nハロウィンの見回りが\n終わった後は、\nまったりくつろごう", 0, 4, 0, 3, 1, 1, 123601, 6632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで二人寄り添って\nカボチャスープ飲もう\n…なんて想像したら\nポカポカしてきた…", 0, 5, 0, 3, 1, 1, 123601, 6633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パレードに参加すると\n体力を使うから、\nいっぱい食べておこう", 0, 7, 0, 3, 1, 1, 123601, 6635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この絵本のお姫様\nかわいいね\nこの仮装もいいな♪", 0, 8, 0, 3, 1, 1, 123601, 6636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、おいしそう！\n見回りに行く前に\n少しつまんじゃおう♪", 0, 12, 0, 3, 1, 1, 123601, 6638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日こそは、あの人に\n気持ちを打ち明けて…\nそのあとは…うう\nど、どうしよう？", 0, 103, 0, 1, 12, 1, 103701, 6640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が剣なら、あなたは\nさしずめ私の鞘…\nふふ、私の帰る\n場所ってことだよ♪", 0, 103, 0, 2, 12, 1, 103701, 6641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり\nコスプレしてると\nテンションあがる～♪", 0, 1, 0, 1, 1, 1, 123701, 6642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャラコスにも\n興味あるけど…\nマジカル、ラブリー\nどっちにしよっかな～", 0, 2, 0, 1, 1, 1, 123701, 6643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャラコスといえば\nミスティーシャイニー\nもいいんだよねえ…\nうはー！　悩むー！", 0, 3, 0, 1, 1, 1, 123701, 6644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスで\n宅コスしてる人\n実は結構\nいるんじゃないかな～", 0, 4, 0, 1, 1, 1, 123701, 6645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コスプレだけど普段着\nって言いはれそう…\nって、ダメダメ！\nオタクは節度が大事！", 0, 5, 0, 1, 1, 1, 123701, 6646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フェスで買ってきた\n薄い本～♪\nギルドハウスに持って\nきちゃおっかな～", 0, 101, 0, 1, 4, 1, 123701, 6647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ようこそ\nコスプレ沼へ～\nなんちゃって♪", 0, 102, 0, 1, 8, 1, 123701, 6648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうどう？\nナナカちゃんの\nハロウィンコスプレ\n似合ってる？", 0, 1, 0, 2, 1, 1, 123701, 6649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィン魔法少女\n参上カボ～！\n…やっぱ今の語尾\nナシで！", 0, 2, 0, 2, 1, 1, 123701, 6650);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハロウィンといえば\nトリックオア～…\nコスプレ！\nなんちゃって", 0, 3, 0, 2, 1, 1, 123701, 6651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランフェスの\n戦利品～♪\nねえねえ\n見たい？　見たい？", 0, 4, 0, 2, 1, 1, 123701, 6652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私にしてほしい\nコスプレがあったら\n教えて♪　君のために\nや～ってやるぜぇ！", 0, 101, 0, 2, 4, 1, 123701, 6653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にコスプレしたい\nならナナカちゃんは\nいつでも大歓迎だよ♪", 0, 102, 0, 2, 8, 1, 123701, 6654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁあ…ねむ\nって、ありゃりゃ　\n昨日コスプレしたまま\n寝ちゃってたかあ…", 0, 1, 1, 2, 1, 1, 123701, 6655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のお昼は\nなんにしよ？\nカボチャ料理に\nしよっかな～", 0, 2, 2, 2, 1, 1, 123701, 6656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間かあ\nそういえばオタクって\n夜行性の人が多い\n気がするぜぇ…", 0, 3, 3, 2, 1, 1, 123701, 6657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふっふっふ\nこのパニエは\n座るときはちゃんと\nふにゃってなるのさ！", 0, 2, 0, 3, 1, 1, 123701, 6659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いや～\nかわいいものをみると\n癒されますな～", 0, 3, 0, 3, 1, 1, 123701, 6660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい薄い本の匂いの\nアロマとか…ダメ？\n私はあの匂い、なんか\n好きなんだよね～", 0, 4, 0, 3, 1, 1, 123701, 6661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖か～い…\nけど近づきすぎて\n衣装が燃えないように\n気を付けなきゃ", 0, 5, 0, 3, 1, 1, 123701, 6662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コス衣装のために\n体型維持は必須だけど\nついつい\n食べちゃうんだよね～", 0, 7, 0, 3, 1, 1, 123701, 6664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっ、次はこの本に\nのってるキャラのコス\nしてみよっかな？", 0, 8, 0, 3, 1, 1, 123701, 6665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おおっ！\nお菓子がいっぱい！\nベルルちゃんチョコ\n入ってないかな～？", 0, 12, 0, 3, 1, 1, 123701, 6667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むっ…\nこの耳の手触り…\n驚嘆に値する…！", 0, 1, 0, 1, 1, 1, 123801, 6669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("獲物を狩りまくる…\nそんなウサギがいても\nいいだろう？", 0, 2, 0, 1, 1, 1, 123801, 6670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワナなど怖くないぞ？\nむしろ積極的に\n踏んでいく性分だ", 0, 3, 0, 1, 1, 1, 123801, 6671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一匹狼ならぬ\n一匹ウサギか\nどっちでもかまわん♪", 0, 4, 0, 1, 1, 1, 123801, 6672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人間とて本を正せば獣\n本能に従えばよいのだ\n遠慮は無用さ☆", 0, 5, 0, 1, 1, 1, 123801, 6673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("脱兎のごとく…\n逃げるものか\n坊やを追い回すのさ♪", 0, 101, 0, 1, 4, 1, 123801, 6674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("獣の道は険しいが…\n坊やめ、音を上げずに\nちゃんとついてきたな\n褒めてやるとしよう♪", 0, 102, 0, 1, 8, 1, 123801, 6675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニンジンはいらん\n好物は好敵手だ\nさぁどんどんおくれ♪", 0, 1, 0, 2, 1, 1, 123801, 6676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("尻尾に触りたいだと？\nワタシの乱数聖域を\n崩せたらな…☆", 0, 2, 0, 2, 1, 1, 123801, 6677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭で考えるな\n体に率直になれ\n己を野放しにするのさ", 0, 3, 0, 2, 1, 1, 123801, 6678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうさモコフワさ♪\nなで心地は最高だが\n意外にどう猛だぞ…？", 0, 4, 0, 2, 1, 1, 123801, 6679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシにピョンピョン\n跳ねてほしいのか？\nあとでじっくり、な♪", 0, 101, 0, 2, 4, 1, 123801, 6680);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシと番になるか？\nオマエさえよければ\nいつでもかまわんぞ☆", 0, 102, 0, 2, 8, 1, 123801, 6681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("太陽と共に目覚め\n活動する\nそれが獣の生き方さ☆", 0, 1, 1, 2, 1, 1, 123801, 6682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼寝をすればいい\nワタシが周囲を\n警戒していてやる", 0, 2, 2, 2, 1, 1, 123801, 6683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暗くなれば眠るだけさ\nそうすれば余計な\nストレスなどたまらん", 0, 3, 3, 2, 1, 1, 123801, 6684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむっ！？\n尻尾がつっかえて\nうまく座れんな…", 0, 2, 0, 3, 1, 1, 123801, 6686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛らしさでワタシに\n張り合おうというのか\n５億年後に出直せ☆", 0, 3, 0, 3, 1, 1, 123801, 6687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("野生の芳香か…\n本能が呼び覚まされる\nいいセンスだ♪", 0, 4, 0, 3, 1, 1, 123801, 6688);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒さも野生のうちだ\n…とはいえ\n温まっていくか♪", 0, 5, 0, 3, 1, 1, 123801, 6689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪くはないが物足りん\nこう見えて肉食なのだ\n肉はないのか肉は☆", 0, 7, 0, 3, 1, 1, 123801, 6691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウサギ族は地獄耳？\nワタシとの共通点だな", 0, 8, 0, 3, 1, 1, 123801, 6692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが私の家…\nそれはこれからも\nずっと変わらないわ…", 0, 103, 0, 1, 12, 1, 106401, 6694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええと、その…今から\nデート…じゃなくって\n散歩でもどうかしら？\n…ふ、二人きりで…", 0, 103, 0, 2, 12, 1, 106401, 6695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスに\nヒーロー参上！\nみんな仲良くッスよ！", 0, 1, 0, 1, 1, 1, 123901, 6696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理もできて\n鎧も作れる！\nお母さんはすごいッス", 0, 2, 0, 1, 1, 1, 123901, 6697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ううう…\nまたマントをドアに\n挟んじゃったッス…", 0, 3, 0, 1, 1, 1, 123901, 6698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっと鎧を着ていれば\nジュンさんに近づける\nかも？　燃えるッス！", 0, 4, 0, 1, 1, 1, 123901, 6699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サインの練習…\nもっとしておいた\nほうがいいッスかね～", 0, 5, 0, 1, 1, 1, 123901, 6700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("半人前でも\n胸を張るッス！\nそのうち似合う日が\nくるッスから！", 0, 101, 0, 1, 4, 1, 123901, 6701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("種族の違いも\n強い魂があれば\n超えられるッス！\n信じてるッスよ！", 0, 102, 0, 1, 8, 1, 123901, 6702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困ったときは\n自分を呼ぶッス！\nあと楽しいときにも\n呼んでほしいッス！", 0, 1, 0, 2, 1, 1, 123901, 6703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓でも行くッスか？\n望むところッス！\n目指せ、一人前！", 0, 2, 0, 2, 1, 1, 123901, 6704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいショーの台本を\n読みこんでるッス！\nところで…この言葉の\n意味、分かるッスか？", 0, 3, 0, 2, 1, 1, 123901, 6705);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒミツがなくなると\nなんか恥ずかしいッス\nあんたはどうッスか？", 0, 4, 0, 2, 1, 1, 123901, 6706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローは遅れて\nやってくる…\nあんたもそうッスね♪", 0, 101, 0, 2, 4, 1, 123901, 6707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰よりも早く\nあんたに見せたいッス\n一人前になった自分！", 0, 102, 0, 2, 8, 1, 123901, 6708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、今日も\nよく眠れたッス～！\n絶好調、間違いなし！", 0, 1, 1, 2, 1, 1, 123901, 6709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おお、もうお昼ッスか\nどうりでお腹が空くと\n思ったッス～えへへ", 0, 2, 2, 2, 1, 1, 123901, 6710);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パトロールのあとは\n歯みがきに宿題に…\n大忙しッスね、夜！", 0, 3, 3, 2, 1, 1, 123901, 6711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにリラックス\nできるなんて…\n平和な証拠ッスね～", 0, 2, 0, 3, 1, 1, 123901, 6713);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("か、かわいい…♪\nさあ、自分と握手…\nううん、抱っこッス♪", 0, 3, 0, 3, 1, 1, 123901, 6714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("優しい匂いッスね…♪\nこれくらいみんなを\n包み込めるように\nなりたいッス～", 0, 4, 0, 3, 1, 1, 123901, 6715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひっくちゅ！　うー…\nちょっと冷えるッスね\nぬくぬくするッス～♪", 0, 5, 0, 3, 1, 1, 123901, 6716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓した分、\nいっぱい食べるッス！\nでっかくなるッス！", 0, 7, 0, 3, 1, 1, 123901, 6718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか自分の\nヒミツ図鑑が出たり\nして…いやいやいや", 0, 8, 0, 3, 1, 1, 123901, 6719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("牢獄よりは\nマシな環境ね\n我慢してあげるわ", 0, 1, 0, 1, 1, 1, 106901, 6721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈ね…\nキャルでもいじって\n暇をつぶそうかしら", 0, 2, 0, 1, 1, 1, 106901, 6722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいる連中\n私を天気予報士と\n勘違いしてない？", 0, 3, 0, 1, 1, 1, 106901, 6723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("音波情報が多いわね…\nここ、もう少し静かに\nならないの…？", 0, 4, 0, 1, 1, 1, 106901, 6724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("共同生活なんて\n久しぶりだわ\n…懐かしいわね", 0, 5, 0, 1, 1, 1, 106901, 6725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子たちのギルド\n経営が雑すぎるわ…！\n教育が必要みたいね", 0, 101, 0, 1, 4, 1, 106901, 6726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とどめを刺される\n準備はできているのに\nまだなのかしら…？", 0, 102, 0, 1, 8, 1, 106901, 6727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私と戦う気になった？\nあら、まだなのね…\nその時を待ってるわよ", 0, 1, 0, 2, 1, 1, 106901, 6728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私というリソースは\n有効活用しなさい\n子守なんてごめんだわ", 0, 2, 0, 2, 1, 1, 106901, 6729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしてそんなに\n頭がいいか？\n生まれつきよ", 0, 3, 0, 2, 1, 1, 106901, 6730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("視力は権能に\n影響しないわよ\n当たり前じゃない", 0, 4, 0, 2, 1, 1, 106901, 6731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたまで天気を\n教えろですって…？\nぶっ殺すわよ？", 0, 101, 0, 2, 4, 1, 106901, 6732);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇なら付き合いなさい\n好きなゲームでいいわ\nどうせ私が勝つもの", 0, 102, 0, 2, 8, 1, 106901, 6733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人生朝露…\n悔いのない一日を\n過ごしなさい", 0, 1, 1, 2, 1, 1, 106901, 6734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午睡はいいわよ…\nふわぁ…眠りは思考に\n必要不可欠なの…", 0, 2, 2, 2, 1, 1, 106901, 6735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夙興夜寝なんて\nやめておきなさい\n休息は大切よ", 0, 3, 3, 2, 1, 1, 106901, 6736);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私を満足させるなんて\n大したものね…晶に\n大量生産させるわ", 0, 2, 0, 3, 1, 1, 106901, 6738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャルの代わりに\nズタズタにする物が\n欲しかったの…♪", 0, 3, 0, 3, 1, 1, 106901, 6739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りじゃない\n見たことのない調合ね\n誰が用意したの？", 0, 4, 0, 3, 1, 1, 106901, 6740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パワーが足りないわね\nもっとよ、もっと私を\n寛がせなさい", 0, 5, 0, 3, 1, 1, 106901, 6741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("栄養価はともかく\n味のバランスは\n悪くないわね", 0, 7, 0, 3, 1, 1, 106901, 6743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つまらない本は\n私が書き直すわ\nこれはどうかしら？", 0, 8, 0, 3, 1, 1, 106901, 6744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年はアカリと\nお姉ちゃんでサンタが\n二人…つまり幸せも\n二倍ですね♪", 0, 1, 0, 1, 1, 1, 124001, 6746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスに向けての\nサックス練習…\nお兄ちゃんと一緒に\n猛特訓です！", 0, 2, 0, 1, 1, 1, 124001, 6747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスツリーの\n飾りつけ、完璧です♪\nお兄ちゃんお姉ちゃん\n喜んでくれるかな？", 0, 3, 0, 1, 1, 1, 124001, 6748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、お外が真っ白！\n生クリームが\nいーっぱいの\nケーキみたいです♪", 0, 4, 0, 1, 1, 1, 124001, 6749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("煙突から入ると\nお洋服が汚れちゃう…\n玄関からじゃ\nダメなのかなぁ？", 0, 5, 0, 1, 1, 1, 124001, 6750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんが来たら\nサンタのお洋服\nいっぱい褒めて\nもらおっと♪", 0, 101, 0, 1, 4, 1, 124001, 6751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聖夜をお兄ちゃんと\n過ごせたら…\nアカリもちょっぴり\n大人になれるかも♪", 0, 102, 0, 1, 8, 1, 124001, 6752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今のアカリは\nサンタさんですから♪\nなんでもお願いして\nくださいね？", 0, 1, 0, 2, 1, 1, 124001, 6753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お外は寒いですから\nアカリとくっついて\nお出かけしましょ♪", 0, 2, 0, 2, 1, 1, 124001, 6754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんは\nアカリのトナカイさん\nですから、ずーっと\nそばにいてください♪", 0, 3, 0, 2, 1, 1, 124001, 6755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん、助けて！\nアカリのカラダで\nラッピング練習したら\n絡まっちゃいました…", 0, 4, 0, 2, 1, 1, 124001, 6756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼント、いっぱい\n準備できました♪\nお兄ちゃんの分は…\nまだヒミツでーす♪", 0, 101, 0, 2, 4, 1, 124001, 6757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリ、プレゼントは\n大人っぽいのがいいな\n早くお兄ちゃんに\n追いつきたいから♪", 0, 102, 0, 2, 8, 1, 124001, 6758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\nふふ、アカリサンタは\nいい子のお手本なので\n早寝早起きなんです♪", 0, 1, 1, 2, 1, 1, 124001, 6759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ、もうお昼？\nクリスマスナンバーの\n練習してたら\nもうこんな時間…", 0, 2, 2, 2, 1, 1, 124001, 6760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冬の夜空は星が\nキレイですね～\nお兄ちゃん、一緒に\n見に行きませんか？", 0, 3, 3, 2, 1, 1, 124001, 6761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、快適すぎて\nとろけちゃいそう…\nこういうプレゼントも\nいいかもです…", 0, 2, 0, 3, 1, 1, 124001, 6763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やん、かわいいです♪\nえへへ、お兄ちゃんは\nどんなプレゼントが\n欲しいですか～？", 0, 3, 0, 3, 1, 1, 124001, 6764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わわ、大人な香り…\nロマンチックな\nクリスマスが\n過ごせそうです♪", 0, 4, 0, 3, 1, 1, 124001, 6765);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これでカラダを温めて\nアカリの温もり…\nお兄ちゃんに\nおすそ分けしよっと♪", 0, 5, 0, 3, 1, 1, 124001, 6766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹がパンパンです…\nでもこれで\nちょっとサンタさんに\n近づけたかも…？", 0, 7, 0, 3, 1, 1, 124001, 6768);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスイブの\n恋人との過ごし方…？\nはわわ、アカリには\nまだ早いかもです…！", 0, 8, 0, 3, 1, 1, 124001, 6769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、すごいすごい！\n不思議な絵本ですね♪\nこの本でお兄ちゃんに\nイタズラしちゃお♪", 0, 14, 0, 3, 1, 1, 124001, 6771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アカリ、ホカホカに\nなっちゃいました～♪\n…ぎゅってしても\nいいですよ？", 0, 15, 0, 3, 1, 1, 124001, 6772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またエンジェルになる\nかもとは思ってたけど\n…サンタさん要素の\n追加は想定外だったわ", 0, 1, 0, 1, 1, 1, 124101, 6773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラフィたちがいない\nときは私がなんとか\nしないとね\n一応…エンジェルだし", 0, 2, 0, 1, 1, 1, 124101, 6774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の飾りつけとか\nするのも…あり？\nふふ、浮かれすぎかな", 0, 3, 0, 1, 1, 1, 124101, 6775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パーティーだったら\nみんなで大人数向けの\nボードゲームもできる\nかも…やったっ", 0, 4, 0, 1, 1, 1, 124101, 6776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服のモコモコ…\n気づいたら触っちゃう\n…やるわね、ラフィ", 0, 5, 0, 1, 1, 1, 124101, 6777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツと一緒にいると\n人見知りとは違う\n緊張があるのよね…\nって今の聞いてたっ？", 0, 101, 0, 1, 4, 1, 124101, 6778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみ…\nいじめてないわよね？\n…大事にしてるって？\nそれはそれで…あうぅ", 0, 102, 0, 1, 8, 1, 124101, 6779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい子と悪い子って\nどう見分けるのかしら\n…まさか素直さとか？\nだったら困る！", 0, 1, 0, 2, 1, 1, 124101, 6780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントといえば\nやっぱりゲーム！\n年末商戦サイコー♪", 0, 2, 0, 2, 1, 1, 124101, 6781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンタさんはお仕事を\n見られちゃ\nいけないのよね？\n…天職？", 0, 3, 0, 2, 1, 1, 124101, 6782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服は汚れ対策も\nバッチリなのよね\n煙突に入れるように\n…いや私はNGよ！？", 0, 4, 0, 2, 1, 1, 124101, 6783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタのお願い…\n今なら一つくらい\n聞いてあげるわよ？\nほら、サンタ衣装だし", 0, 101, 0, 2, 4, 1, 124101, 6784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちって\nなぜかぬいぐるみと\n縁があるわよね\n…ふふ", 0, 102, 0, 2, 8, 1, 124101, 6785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、おはよっ\n…ふぅ、寝ぐせを\n直すのが間に合って\nよかったぁ", 0, 1, 1, 2, 1, 1, 124101, 6786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え…一緒にごはん？\nそ、そう…うん。OK\nまあ、せっかくだし？", 0, 2, 2, 2, 1, 1, 124101, 6787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間のゲームって\n妙に楽しいのよね\n…ということで、\nちょっと遊ばない？", 0, 3, 3, 2, 1, 1, 124101, 6788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ～ダメになるぅ…\nもうここでずっと\nゲームしてた～い", 0, 2, 0, 3, 1, 1, 124101, 6790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントのために\n研究は必要よね、うん\n…はぁ、かわいい～♪", 0, 3, 0, 3, 1, 1, 124101, 6791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("集中力を高める香りも\nあるのよね…\n勝負をするときには\n持ち歩こうかしら", 0, 4, 0, 3, 1, 1, 124101, 6792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだかまったり\nしちゃうわね…\n時間が溶けるわ…", 0, 5, 0, 3, 1, 1, 124101, 6793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹いっぱい\n食べられるのも\n幸せなことよね", 0, 7, 0, 3, 1, 1, 124101, 6795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちっちゃいときは\nアカリと一緒に絵本を\n読んだなぁ…懐かしい", 0, 8, 0, 3, 1, 1, 124101, 6796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("飛び出す絵本…\nこれでゲームブックを\n作ったらおもしろく\nなる気がするわ…", 0, 14, 0, 3, 1, 1, 124101, 6798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったまる…\nモフモフ…ふわふわ…\nちょっと休憩しても…\nいいよね…？", 0, 15, 0, 3, 1, 1, 124101, 6799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、どうしたの？\nもしかして、私と\n新しい実験を\n始めたくなった？", 0, 103, 0, 1, 12, 1, 105101, 6800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("調子が悪いときは\n診療所に来て\n君は特別に、じっくり\n診察してあげるわ♪", 0, 103, 0, 2, 12, 1, 105101, 6801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特別じゃなくても\nまったり過ごす\nクリスマスも\nいいものだね", 0, 1, 0, 1, 1, 1, 124201, 6802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニットの帽子に\nマフラーに耳当て…\n素顔用の防寒対策を\n整えなければ", 0, 2, 0, 1, 1, 1, 124201, 6803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("靴下が\n見当たらなかったから\n枕元にはかわりに\n鎧を置いておこう", 0, 3, 0, 1, 1, 1, 124201, 6804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聖女なんて言われる程\n素晴らしくはないけど\n心は聖くいたいものだ\n日々精進だね", 0, 4, 0, 1, 1, 1, 124201, 6805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兜がないから\nイルミネーションが\nいつもよりまぶしく\n感じるよ", 0, 5, 0, 1, 1, 1, 124201, 6806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆の幸福を\n祈願して\nクリスマスリースを\n飾ろうか", 0, 101, 0, 1, 4, 1, 124201, 6807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私にはかわいすぎる\n衣装だが…開き直って\nクリスマス気分を\n楽しんでしまおう", 0, 102, 0, 1, 8, 1, 124201, 6808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツリーの飾りつけ\n手伝ってくれるかい？\nセンスは少年に\nお任せするよ", 0, 1, 0, 2, 1, 1, 124201, 6809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パーティーは\n用意してる時も楽しい\nねえ少年、この気持ち\n分かってくれるかい？", 0, 2, 0, 2, 1, 1, 124201, 6810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんでトナカイの鼻は\n赤いのかって？\n無灯ソリ運転は違反で\n取り締まられるからだ", 0, 3, 0, 2, 1, 1, 124201, 6811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トモちゃんや\nマツリちゃんは\nいい子だから、きっと\nサンタさんに会えるね", 0, 4, 0, 2, 1, 1, 124201, 6812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒイラギの髪飾り\n実は気にいってるんだ\n少年にも\n褒めてもらいたいな", 0, 101, 0, 2, 4, 1, 124201, 6813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ少年…そろそろ\n見慣れてほしい\nそんなにまじまじ\n見つめられると照れる", 0, 102, 0, 2, 8, 1, 124201, 6814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝日に照らされて\n街がキラキラ白銀に\n輝いてるよ", 0, 1, 1, 2, 1, 1, 124201, 6815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯を食べて\nちょっと散歩しようか\n祝祭に沸く街は\nとてもきれいだよ", 0, 2, 2, 2, 1, 1, 124201, 6816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱりクリスマスは\n夜が本番って感じだね\nキャンドルを灯して\n厳かに過ごそうか", 0, 3, 3, 2, 1, 1, 124201, 6817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鎧姿では無縁だったが\nふかふかしていて\n気持ちいいな…\nふかふか…ふかふか…", 0, 2, 0, 3, 1, 1, 124201, 6819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、かわいいね\n抱きしめると\nあの雪の日に産まれた\n赤ちゃんを思い出す", 0, 3, 0, 3, 1, 1, 124201, 6820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兜を脱いだおかげで\nこの香りに出会えた\n…クリスマスの魔法も\n悪くないかもね", 0, 4, 0, 3, 1, 1, 124201, 6821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("指先から体の芯まで\n暖まるね\nこれなら雪の日でも\n安心だよ", 0, 5, 0, 3, 1, 1, 124201, 6822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐ、もぐ…\nあまり食べるところ\n見ないでほしい", 0, 7, 0, 3, 1, 1, 124201, 6824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵なレストランの\n特集記事が載ってる\n聖夜に予約が取れたら\n最高に幸せだろうね", 0, 8, 0, 3, 1, 1, 124201, 6825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ！\n…………いや\n驚いてなどいない", 0, 14, 0, 3, 1, 1, 124201, 6827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…頬に直接\nふかふかを感じられる\n温かくて気持ちいいよ", 0, 15, 0, 3, 1, 1, 124201, 6828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ピアノに読書…\nグレアと一緒に\nなにをしようかな～♪", 0, 1, 0, 1, 1, 1, 124301, 6829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元の世界へ戻った時\n授業に遅れないよう\nグレアと勉強しとこう", 0, 2, 0, 1, 1, 1, 124301, 6830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("街に魔物料理屋さんが\nあるんだ！　グレアと\n食べに行ってみよう♪", 0, 3, 0, 1, 1, 1, 124301, 6831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかく新しい魔法を\n覚えたし、グレアにも\n見てもらいたいな！", 0, 4, 0, 1, 1, 1, 124301, 6832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グレアも誘って\nランドソルをもっと\n探索したい！", 0, 5, 0, 1, 1, 1, 124301, 6833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちも\nあの人を見習って\nバイトとかしよう！", 0, 101, 0, 1, 4, 1, 124301, 6834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかあの人を\n私たちの学院に\n招待したいな！", 0, 102, 0, 1, 8, 1, 124301, 6835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのね！\nこれからグレアと\n魔法愛好会に\n行くんだ！", 0, 1, 0, 2, 1, 1, 124301, 6836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからなにするの？\n私たちもついて行って\nいいかな！？", 0, 2, 0, 2, 1, 1, 124301, 6837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グレアと一緒に\nあなたも魔法の練習\nしてみない？", 0, 3, 0, 2, 1, 1, 124301, 6838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グレアとよく話すの\nマナリアの制服\nあなたに着せたいって", 0, 4, 0, 2, 1, 1, 124301, 6839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グレアのそばって\n温かいんだ～！\nぬくぬくだよ～♪", 0, 101, 0, 2, 4, 1, 124301, 6840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたは\nグレアと私の友達！\nこれからもずっと！", 0, 102, 0, 2, 8, 1, 124301, 6841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n今朝はグレアと一緒に\n外を散歩してきたよ！", 0, 1, 1, 2, 1, 1, 124301, 6842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹空いたな…\nよし、グレアと一緒に\n魔物料理を作ろう！", 0, 2, 2, 2, 1, 1, 124301, 6843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間だね\n明日のために\nそろそろ寝ようかな！", 0, 3, 3, 2, 1, 1, 124301, 6844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～この感触…\nグレアの尻尾みたいで\n安らぐ～", 0, 2, 0, 3, 1, 1, 124301, 6846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみって\nいいよね…私もよく\nグレアに抱き付くんだ", 0, 3, 0, 3, 1, 1, 124301, 6847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～…\nグレアもこういうの\n好きなんだよ！", 0, 4, 0, 3, 1, 1, 124301, 6848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいね～…\nグレアにくっついてる\n時を思い出すよ～…", 0, 5, 0, 3, 1, 1, 124301, 6849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界にしかない\nおいしいものが\nたくさんあるよね！", 0, 7, 0, 3, 1, 1, 124301, 6851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界を繋ぐ魔法の\nヒント…本に書いて\nないかなぁ…", 0, 8, 0, 3, 1, 1, 124301, 6852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ピアノに読書…\n今日のアンは\nなにをするのかな…", 0, 1, 0, 1, 1, 1, 124401, 6855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私はアンほど\n勉強はできないから\nちゃんと自習しないと", 0, 2, 0, 1, 1, 1, 124401, 6856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一度始めたら\nとことん追求するのが\nアンなんだよね…", 0, 3, 0, 1, 1, 1, 124401, 6857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…夢中になってる\nアンを眺めてるだけで\n一日があっという間…", 0, 4, 0, 1, 1, 1, 124401, 6858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルは広いね…\nアンと一緒にいろんな\n場所へ行ってみたい", 0, 5, 0, 1, 1, 1, 124401, 6859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンやあの人の笑顔を\n見てると、すごく\n安心するんだ…", 0, 101, 0, 1, 4, 1, 124401, 6860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしあの人が私たちの\n学院に編入したら…\nふふ、楽しそうだね", 0, 102, 0, 1, 8, 1, 124401, 6861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンもあなたも\nすごいな…\nみんなとすぐに\n仲良くなっちゃうから", 0, 1, 0, 2, 1, 1, 124401, 6862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたはこれから\nなにをするの？\nその…アンと一緒に\nついていってもいい？", 0, 2, 0, 2, 1, 1, 124401, 6863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンから魔法の練習に\n誘われた？　実は私も\n…一緒にどうかな？", 0, 3, 0, 2, 1, 1, 124401, 6864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたがマナリアに\n編入したら\n楽しいのになって\nアンとよく話すんだ…", 0, 4, 0, 2, 1, 1, 124401, 6865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界にも\nアンのように\n私を受け入れてくれる\n人たちがいるんだね…", 0, 101, 0, 2, 4, 1, 124401, 6866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元の世界へ帰る日が\n来たとしても私たちは\n「さよなら」より\n「またね」がいいよね", 0, 102, 0, 2, 8, 1, 124401, 6867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう。さっき\nランドソルの朝日を\nアンと見てきたんだ", 0, 1, 1, 2, 1, 1, 124401, 6868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちは\nこれからなんだけど\nあなたはお昼ごはん\n何を食べたの？", 0, 2, 2, 2, 1, 1, 124401, 6869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ\nアンが眠る時間だ…\nあなたもおやすみ", 0, 3, 3, 2, 1, 1, 124401, 6870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ、疲れが取れる…\nこの尻尾…\nちょっと重いんだよね", 0, 2, 0, 3, 1, 1, 124401, 6872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ…\nアンに見せたら\n喜ぶだろうな…", 0, 3, 0, 3, 1, 1, 124401, 6873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\nアンの感想も\n聞いてみたいな", 0, 4, 0, 3, 1, 1, 124401, 6874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nアンがここにいたら\n本を読みながら\n寝ちゃうんだろうな", 0, 5, 0, 3, 1, 1, 124401, 6875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいからたくさん\n食べれちゃうけど\nまた尻尾…\n大きくなっちゃうかな", 0, 7, 0, 3, 1, 1, 124401, 6877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンがおススメ\nしてくれた本は\nこれかな…？", 0, 8, 0, 3, 1, 1, 124401, 6878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("凶、凶、凶…大凶？\nなによこのおみくじ\n自宅用だからって\n排出率が適当すぎよ…", 0, 1, 0, 1, 1, 1, 124701, 6881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年こそ最高の新薬が\nもはや偶然に近い\n最小限の手間で\n作れますように", 0, 2, 0, 1, 1, 1, 124701, 6882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("喉に詰まる前に\n溶けてなくなるお餅…\n最優先の研究課題だわ", 0, 3, 0, 1, 1, 1, 124701, 6883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よし、完成♪\nミツキ特製…\n「新解釈おせち料理」\n医学的根拠が満載よ", 0, 4, 0, 1, 1, 1, 124701, 6884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お年玉を彼に…\nあげるべき…？\n色んな意味で微妙ね…", 0, 5, 0, 1, 1, 1, 124701, 6885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、今年もまた一年\n彼のバイタルを\n記録できるのね♪", 0, 101, 0, 1, 4, 1, 124701, 6886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年こそ\n私の薬で彼を魔改造…\nううん、大人の男に！", 0, 102, 0, 1, 8, 1, 124701, 6887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コマ回しのコマを\n見てたら目が回った？\nそう…手当は不要よ…", 0, 1, 0, 2, 1, 1, 124701, 6888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の顔で\n福笑いを作った？\nあら…隻眼まで\n再現度が高いわね♪", 0, 2, 0, 2, 1, 1, 124701, 6889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("門松よし、しめ縄よし\nこんなギルドでもね\n一応縁起を担ぐのよ", 0, 3, 0, 2, 1, 1, 124701, 6890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本気の薬草を煮込んだ\n本気の七草粥よ\n色は気にしちゃダメ", 0, 4, 0, 2, 1, 1, 124701, 6891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君が今年も健康で\nつつがなく…実験台を\n務められますように", 0, 101, 0, 2, 4, 1, 124701, 6892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いくつ新年を迎えても\n俗世の垢にまみれない\nそんな君こそが…\n私には最高のお薬よ", 0, 102, 0, 2, 8, 1, 124701, 6893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月なんだから\nいつまでも寝てないで\nさぁ、実験開始よ♪", 0, 1, 1, 2, 1, 1, 124701, 6894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カルタも双六もしたし\nあとは実験くらいしか\nやることがないわね", 0, 2, 2, 2, 1, 1, 124701, 6895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日頃からたいがい\n意味深な夢を見るけど\n初夢はまた別かしら…", 0, 3, 3, 2, 1, 1, 124701, 6896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さすがにこの格好で\n寝正月を敢行するのは\nためらわれるわね", 0, 2, 0, 3, 1, 1, 124701, 6898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("や、闇医者たる者\nこんな愛くるしい物に\n心奪われるわけには…", 0, 3, 0, 3, 1, 1, 124701, 6899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お雑煮のいい香り…\n食欲が増進されるわ\nアロマも立派なお薬ね", 0, 4, 0, 3, 1, 1, 124701, 6900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("胸元は閉じないわよ？\nでも時々ここで\nこっそり暖まるの…", 0, 5, 0, 3, 1, 1, 124701, 6901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無から有が生まれてる\n新年早々物理の法則を\n無視してくるのね…", 0, 7, 0, 3, 1, 1, 124701, 6903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どれもこれも読んだわ\n新しい婚活本の\n入荷はまだかしら…", 0, 8, 0, 3, 1, 1, 124701, 6904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼が一生懸命\n書いてくれた年賀状\n気持ちがこもっていて\nすごくうれしいわ♪", 0, 1, 0, 1, 1, 1, 124601, 6906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり丁寧に\n大掃除したから\nとってもいい気持ちで\n新年を迎えられたわ♪", 0, 2, 0, 1, 1, 1, 124601, 6907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼の着物姿\nきっと凛々しいわよね\n想像しただけで\n笑顔になるわ～♪", 0, 3, 0, 1, 1, 1, 124601, 6908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お雑煮は地域によって\n違いがあるけれど\n愛情が隠し味なのは\nどこも一緒よね♪", 0, 4, 0, 1, 1, 1, 124601, 6909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と凧揚げして\n遊びたいけど\n森では引っかかって\nできないかしら…？", 0, 5, 0, 1, 1, 1, 124601, 6910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年も彼が素直に\n成長できるように\nたくさんいい子いい子\nしてあげましょう…♪", 0, 101, 0, 1, 4, 1, 124601, 6911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵馬に彼と\n書いた通り\n今年もみんなが笑って\n過ごせますように", 0, 102, 0, 1, 8, 1, 124601, 6912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先生と初詣に\n行きましょう〜♪\n迷子にならないように\n手を繋いで、ね？", 0, 1, 0, 2, 1, 1, 124601, 6913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初売りセールいいわね\nでも気を付けないと\nあれこれ欲しくなって\n買い過ぎちゃうかも…", 0, 2, 0, 2, 1, 1, 124601, 6914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪をひかないように\n温かくするんですよ～\nえ？　先生、温めて？\nふふ、甘えん坊さんね", 0, 3, 0, 2, 1, 1, 124601, 6915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたのために\nちょっと豪華なおせち\n用意したのよ\nお口に合うかしら？", 0, 4, 0, 2, 1, 1, 124601, 6916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたも着物着たい？\nふふ、貫禄出ちゃって\n先生ドキドキ\nしちゃうかも…♪", 0, 101, 0, 2, 4, 1, 124601, 6917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの成長は\nとってもうれしいけど\n今年もまだ、あなたの\n先生でいたいな…♪", 0, 102, 0, 2, 8, 1, 124601, 6918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら、起きたの？\nお雑煮できてるから\nちゃんとお顔\n洗ってらっしゃいね", 0, 1, 1, 2, 1, 1, 124601, 6919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯を\nしっかり食べて\nみんなでかるた大会\nしましょう〜♪", 0, 2, 2, 2, 1, 1, 124601, 6920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("は～い、良い子は\nもう寝る時間ですよ\n素敵な初夢が\n見られますように♪", 0, 3, 3, 2, 1, 1, 124601, 6921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このフカフカちゃんも\n天日干ししたいけど…\nその前にちょっと\n休憩しちゃおうかしら", 0, 2, 0, 3, 1, 1, 124601, 6923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ、かわいい～\nアオイちゃんや\nハツネちゃんも\nきっと気に入るわね♪", 0, 3, 0, 3, 1, 1, 124601, 6924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月は空気も\n透き通ってるから\nいつも以上に\n素敵な香りに感じるわ", 0, 4, 0, 3, 1, 1, 124601, 6925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火のぬくもりに\n抱かれていると\n不思議と眠気が…\nふああ…", 0, 5, 0, 3, 1, 1, 124601, 6926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛情のこもった料理は\nおいしいだけじゃなく\n心も満たされちゃう♪", 0, 7, 0, 3, 1, 1, 124601, 6928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月のお作法も\nたくさんあるのね～\n先生も日々勉強だわ～", 0, 8, 0, 3, 1, 1, 124601, 6929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少年への感謝をどんな\n形で伝えるべきか…\n言葉よりも物の方が\n良いのだろうか？", 0, 103, 0, 1, 12, 1, 104701, 6931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("話し相手になって\nもらってもいいかな？\n少年と一緒にいると\nとても楽しいんだ", 0, 103, 0, 2, 12, 1, 104701, 6932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月だからって\nギャングのボスは\n油断できないよ～？", 0, 1, 0, 1, 1, 1, 124501, 6933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イノリちゃんがお年玉\n欲しいんだって♪\n悪い子だったし\n10ルピでいいかな☆", 0, 2, 0, 1, 1, 1, 124501, 6934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月だからお雑煮を\n作ったんだけど\nカヤちゃんには\n大好評だったよ♪", 0, 3, 0, 1, 1, 1, 124501, 6935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラーゴがお餅を\n食べたがってるけど…\nこの子にあげるのは\nちょっと心配かな～？", 0, 4, 0, 1, 1, 1, 124501, 6936);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月は晴れ着の子が\nやっぱり多いよね～\n今度、私の漫画でも\n出してみようかな？", 0, 5, 0, 1, 1, 1, 124501, 6937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君と二人っきりで\n神殿に初詣…\n行ってみたいな～♪", 0, 101, 0, 1, 4, 1, 124501, 6938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君とお正月を\n過ごしていると\n面倒なことも\n全部忘れられそう…", 0, 102, 0, 1, 8, 1, 124501, 6939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この着物、どう思う？\n似合ってたら\nうれしいけどな～♪", 0, 1, 0, 2, 1, 1, 124501, 6940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("袖を引っ張ったり\nしないでね？\n着崩れしちゃうから♪", 0, 2, 0, 2, 1, 1, 124501, 6941);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月ならではの\n漫画ネタってある？\n参考にしたいんだよね", 0, 3, 0, 2, 1, 1, 124501, 6942);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昔は凧あげとか\n駒回しとかしてたけど\n大人になるとそういう\n機会も減るよね…", 0, 4, 0, 2, 1, 1, 124501, 6943);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君にもお年玉を\nあげようか？\n好きな額を言ってね☆", 0, 101, 0, 2, 4, 1, 124501, 6944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年も、再来年も…\nこうしてみんなで\n新年がお祝いできると\n素敵だね～♪", 0, 102, 0, 2, 8, 1, 124501, 6945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ～♪\n朝ごはんは\n焼いたお餅とか\nどうかな？", 0, 1, 1, 2, 1, 1, 124501, 6946);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼だね～\nおせちを用意したから\nみんなで食べよっか", 0, 2, 2, 2, 1, 1, 124501, 6947);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間だね～\n一日中着物だったから\n肩が凝っちゃったよ", 0, 3, 3, 2, 1, 1, 124501, 6948);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このまま寝たら\nしわになるかな？\n着替えた方がいい？", 0, 2, 0, 3, 1, 1, 124501, 6950);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのって\nラーゴのおもちゃに\nちょうどいいかも♪", 0, 3, 0, 3, 1, 1, 124501, 6951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだけど\n着物に移らないように\n気をつけないとね", 0, 4, 0, 3, 1, 1, 124501, 6952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどいい\n火加減だね♪\nぽかぽかするよ～♪", 0, 5, 0, 3, 1, 1, 124501, 6953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物の時は\nほどほどにしないと…\n欲張ったら、お腹が\n苦しくなるからね～", 0, 7, 0, 3, 1, 1, 124501, 6955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふーん\nイノリちゃんは最近\nこんな漫画を\n読んでるんだ～♪", 0, 8, 0, 3, 1, 1, 124501, 6956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("楽園の気配は…ナシ！\nみんな前を向いてるね\nそうこなくっちゃ！", 0, 1, 0, 1, 1, 1, 124801, 6958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンの成果も\nこの格好くらい\n目に見えたら\n分かりやすいのになぁ", 0, 2, 0, 1, 1, 1, 124801, 6959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の曲はワイルドで\n悪い感じもいいなぁ…\nカヤとムイミちゃん\nみたいなイメージで！", 0, 3, 0, 1, 1, 1, 124801, 6960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私…服、着てるよね？\nうんうん、着てる！\nあんまり体が軽いと\n急に焦る瞬間あるな～", 0, 4, 0, 1, 1, 1, 124801, 6961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近ファンの年齢層が\n幅広くなってきたかも\nこれって私…国民的\nアイドルに近づいた？", 0, 5, 0, 1, 1, 1, 124801, 6962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パティスリーとコラボ\nしたらどんな感じかな\n…ノゾミンマカロン♪\nとか？　…いけるかも", 0, 101, 0, 1, 4, 1, 124801, 6963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と一緒にいると…\nうれしくって苦しいな\nでも両方諦められない\n…アイドルらしいや", 0, 102, 0, 1, 8, 1, 124801, 6964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好、チカと\nツムギも似合うと\n思うんだけどな～\nキミもそう思うよね？", 0, 1, 0, 2, 1, 1, 124801, 6965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("街を歩いてたらね？\nライブとか写真集の\n告知イベントだって\n思われちゃった！", 0, 2, 0, 2, 1, 1, 124801, 6966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が持ってた剣に\n結んであったリボン…\n何か気づいてくれた？\nヒントは…色だよ♪", 0, 3, 0, 2, 1, 1, 124801, 6967);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの気配ってすごく\n分かりやすいんだよ\n近くにいたらすぐに\nピンとくるんだ♪", 0, 4, 0, 2, 1, 1, 124801, 6968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、それ…はじめて\nキミにあげた音響盤！\nね、一緒に聴こうよ", 0, 101, 0, 2, 4, 1, 124801, 6969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼうっとしてたら\nイタズラしちゃうよ♪\nもっともっと私のこと\n見てないとダーメ！", 0, 102, 0, 2, 8, 1, 124801, 6970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は今日のはじまり！\n昨日よりももっと\nいい一日にしようね♪", 0, 1, 1, 2, 1, 1, 124801, 6971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レッスンがんばったし\nまだお昼だし…\nランチ大盛りにしても\nセーフだよね！", 0, 2, 2, 2, 1, 1, 124801, 6972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝る前に明日の予定を\n確認しておかないと！\nえっと、集合場所は…", 0, 3, 3, 2, 1, 1, 124801, 6973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一休みのつもりが\nなが～い休憩になるの\nあるあるだよね～", 0, 2, 0, 3, 1, 1, 124801, 6975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ノゾミンの熱烈ハグ♪\n…ここだけ聞いたら\nスクープになっちゃう\nかも？　なーんて！", 0, 3, 0, 3, 1, 1, 124801, 6976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りってなんだか\n記憶に残るよねー\n…こういうの私だけ？\nみんなも同じだよね？", 0, 4, 0, 3, 1, 1, 124801, 6977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだかライブの\n熱気を思い出して\nきちゃった…！\nレッスンしよっと！", 0, 5, 0, 3, 1, 1, 124801, 6978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹が減ってたら\nいいパフォーマンスは\nできないもんね！\n…んー、おいし～♪", 0, 7, 0, 3, 1, 1, 124801, 6980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい歌詞を書くには\nしっくりくる言葉を\n知っておかないと！", 0, 8, 0, 3, 1, 1, 124801, 6981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うだうだ悩んでる\nヤツがいたら\nオレのとこ連れてこい\n背中押してやるからさ", 0, 1, 0, 1, 1, 1, 124901, 6983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近どことなく\nファミリーの連中が\n浮き足立ってんだよな\n…なんでだ？", 0, 2, 0, 1, 1, 1, 124901, 6984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イノリのヤツ\nやたらと脇腹\nつついてきやがって…\nくすぐったいっての", 0, 3, 0, 1, 1, 1, 124901, 6985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身軽になったのは\nいいが…くそっ\nどこもかしこも\nスースーする…", 0, 4, 0, 1, 1, 1, 124901, 6986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思い出に浸るのも\n悪くはないが\nやっぱ人間\n未来に生きないとな！", 0, 5, 0, 1, 1, 1, 124901, 6987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またムイミやノゾミと\nツルむのもいいな\nそこにカレもいたら\nなおいいぜ", 0, 101, 0, 1, 4, 1, 124901, 6988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("未来のことを考えると\nなぜかいつもカレが\n頭に浮かんじまう…\nええい、やめだやめ！", 0, 102, 0, 1, 8, 1, 124901, 6989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっくらオレと\n腕相撲しねえか？\nこの新しい力\n試させてくれ！", 0, 1, 0, 2, 1, 1, 124901, 6990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なあ、悪いが上着\n貸してくれないか？\nこのカッコ、割と\n肌寒いんだよ…", 0, 2, 0, 2, 1, 1, 124901, 6991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっ、生まれ変わった\n喧嘩屋にご用命か？\nいいぜ、キミの\n依頼なら二つ返事だ！", 0, 3, 0, 2, 1, 1, 124901, 6992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんか悩みごとが\nあるなら、なんでも\n話してくれよな\nオレとキミの仲だろ？", 0, 4, 0, 2, 1, 1, 124901, 6993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このカッコが\nきれいだって？\nや、やめろよ…\n照れくさいだろ…", 0, 101, 0, 2, 4, 1, 124901, 6994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミがいると、なにを\nするにも退屈しないぜ\nだから今日も\n付き合ってくれよな！", 0, 102, 0, 2, 8, 1, 124901, 6995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！　新しい\n未来がやってきたぜ！\n一秒だって時間は\n無駄にするなよ？", 0, 1, 1, 2, 1, 1, 124901, 6996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ昼飯に\nしないか？\n穴場のうまい店に\n案内してやるからさ", 0, 2, 2, 2, 1, 1, 124901, 6997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしは\n未来の前借りだ\n体壊さないように\nほどほどにしとけよ？", 0, 3, 3, 2, 1, 1, 124901, 6998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、いいなこれ\nファミリーの\nアジトにも\n置いときたいぜ", 0, 2, 0, 3, 1, 1, 124901, 7000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("べ、別にかわいいもん\nなんて、そんなに\n好きじゃないし…\n嫌いでもないけどさ", 0, 3, 0, 3, 1, 1, 124901, 7001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("嗅いだことない\n香りだな\nなかなか気に入った！", 0, 4, 0, 3, 1, 1, 124901, 7002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("薄着で暖を取るのって\n最高にぜいたくだよな\nへへっ、堪能させて\nもらうとするか", 0, 5, 0, 3, 1, 1, 124901, 7003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こいつはいいや\nこのカッコだと\n消耗が激しくて\nやたら腹が減るからな", 0, 7, 0, 3, 1, 1, 124901, 7005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘辛コーデ…\nへぇ、そんなのが\nあるのか…\nわ、悪くねえかもな", 0, 8, 0, 3, 1, 1, 124901, 7006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…\nもっともっと長い時間\n先輩と過ごせたらなぁ", 0, 103, 0, 1, 12, 1, 105501, 7008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ…♪\n先輩が、すぐそばに\nいてくれるなんて…\n幸せだなぁ…♪", 0, 103, 0, 2, 12, 1, 105501, 7009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はーっはっは！\n強くてカッコいい\n大悪党、ここに参上！", 0, 1, 0, 1, 1, 1, 125001, 7010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなおしゃれで\nカッコいいけど\n今のアタシも\n負けてないぞ！", 0, 2, 0, 1, 1, 1, 125001, 7011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギャングのアジトも\nよかったけど\nここも賑やかで\n悪くないな！", 0, 3, 0, 1, 1, 1, 125001, 7012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪党にも休息は必要だ\nここならゆっくり\n休めそうだ！\n邪魔するぞ！", 0, 4, 0, 1, 1, 1, 125001, 7013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい人がいるな…\nアタシの悪党っぷりを\n広めるチャンスだ！", 0, 5, 0, 1, 1, 1, 125001, 7014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいれば\nいい思い出がたくさん\n作れそうだな！", 0, 101, 0, 1, 4, 1, 125001, 7015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかアタシも\nオクトーと一緒に\nこんなアジトを手に\n入れてやるからな！", 0, 102, 0, 1, 8, 1, 125001, 7016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　アタシの格好が\n気になるのか？\nならもっと近くで\n見てもいいぞ！", 0, 1, 0, 2, 1, 1, 125001, 7017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おい、暇だから\nアタシと遊べ！\nカヤとノゾミも呼んで\n大騒ぎするぞ！", 0, 2, 0, 2, 1, 1, 125001, 7018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエ、前より強く\nなってないか！？\nくっそー！　アタシも\n負けてらんないぞー！", 0, 3, 0, 2, 1, 1, 125001, 7019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は特別にアタシの\n思い出話を聞かせて\nやる！　さーて、どの\n悪事から話そうか…", 0, 4, 0, 2, 1, 1, 125001, 7020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエとの付き合いも\n結構長くなったよな？\nこれからも\nよろしく頼むぞ！", 0, 101, 0, 2, 4, 1, 125001, 7021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエまでいなく\nなったらアタシが困る\n勝手にどっか\n行くんじゃないぞ！", 0, 102, 0, 2, 8, 1, 125001, 7022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きろ、起きろー！\n大悪党の朝は早いんだ\nさっさと\n顔洗ってこい！", 0, 1, 1, 2, 1, 1, 125001, 7023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯どうしようか…\nそうだ！　オマエの\nおススメに連れてけ！\nいい店期待してるぞ！", 0, 2, 2, 2, 1, 1, 125001, 7024);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日を思い切り\n楽しむためにも\n早く寝とけよ！\nまた明日な！", 0, 3, 3, 2, 1, 1, 125001, 7025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうやって座ると…\nおお！　すっごく悪党\nっぽいぞ！", 0, 2, 0, 3, 1, 1, 125001, 7027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オマエ、仲間に\nなりたそうな目を\nしてるな！", 0, 3, 0, 3, 1, 1, 125001, 7028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うん、いい匂いだ！\n何の匂いかは全然\n分かんないけどな！", 0, 4, 0, 3, 1, 1, 125001, 7029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("炎ってなんだか\nカッコいいよな！\n見てるだけで心が\n燃えてくるぞ！", 0, 5, 0, 3, 1, 1, 125001, 7030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べれば\nちょっとは\n背が伸びるかな…？", 0, 7, 0, 3, 1, 1, 125001, 7032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐぬぅ…たまには\n本でもと思ったけど\nやっぱりアタシは\nバトル担当だな！", 0, 8, 0, 3, 1, 1, 125001, 7033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お邪魔しまーす★\nなーんてもう\nすっかりくつろいで\nますけどー♪", 0, 1, 0, 1, 1, 1, 118201, 7035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんの\nギルドハウス…★\nなんだかドキドキ\nしちゃいます♪", 0, 2, 0, 1, 1, 1, 118201, 7036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぺんぽこりんの\n置き場所はー…\nま、このへんで★", 0, 3, 0, 1, 1, 1, 118201, 7037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、これは\n壊しがいがありそ…\nウソウソ、冗談です★", 0, 4, 0, 1, 1, 1, 118201, 7038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オトモダチでも\n作ってみますかー\nくすっ★", 0, 5, 0, 1, 1, 1, 118201, 7039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈ですねー\n騎士さん、構って\nくれないかなー", 0, 101, 0, 1, 4, 1, 118201, 7040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっともっと早く\n騎士さんに逢えてたら\n…なんて、わたし\nらしくないですね", 0, 102, 0, 1, 8, 1, 118201, 7041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたし一人にするの\n不安だったりします？\nちゃーんとイイコに\nしてますってー★", 0, 1, 0, 2, 1, 1, 118201, 7042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お出かけします？\nそれともおうちで\nまったりしますー？", 0, 2, 0, 2, 1, 1, 118201, 7043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女の子をすぐ家に\nあげちゃうなんて…\nふふ、やっぱり隅に\n置けないですねー★", 0, 3, 0, 2, 1, 1, 118201, 7044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さん騎士さーん★\nウザ絡みしても\nいいですかー？\n騎士さんってばー★", 0, 4, 0, 2, 1, 1, 118201, 7045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にゴロゴロ\nしませんかー？\nコイビトっぽくて\n楽しそうですし♪", 0, 101, 0, 2, 4, 1, 118201, 7046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ★\nこーやってあなたに\n優しくされると…\nときめいちゃいます♪", 0, 102, 0, 2, 8, 1, 118201, 7047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます★\nあれれー？\nまだおねむですかー？", 0, 1, 1, 2, 1, 1, 118201, 7048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さん、お昼は\nもう食べましたー？\nわたし、ラーメンが\n食べたいでーす★", 0, 2, 2, 2, 1, 1, 118201, 7049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、夜更かししてちゃ\nダメですよー？\nほらほら、お布団に\nごーごー★", 0, 3, 3, 2, 1, 1, 118201, 7050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかのふわふわー\nついついまーったり\nしちゃいます★", 0, 2, 0, 3, 1, 1, 118201, 7052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かっわいー★\n名前はー、んー…\nぱんぱかぷんで★", 0, 3, 0, 3, 1, 1, 118201, 7053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん★\nうーん…\nたぶん素敵な香り♪", 0, 4, 0, 3, 1, 1, 118201, 7054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかーい★\n心も体も\nぽっかぽかですねー★", 0, 5, 0, 3, 1, 1, 118201, 7055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ★\nんー、おいしくって\n止まらないですねー★", 0, 7, 0, 3, 1, 1, 118201, 7057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へー★\nほほー★\nふんふーん★", 0, 8, 0, 3, 1, 1, 118201, 7058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ～て時間もあるし\nラテアートの練習でも\nするかにゃ～♪", 0, 1, 0, 1, 1, 1, 125101, 7060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カフェの猫たちも\n元気に働いてくれて\nお客さんからの評判も\n上々にゃ～♪", 0, 2, 0, 1, 1, 1, 125101, 7061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カフェのカウンターに\nファントムキャッツの\n目安箱を置こうかにゃ", 0, 3, 0, 1, 1, 1, 125101, 7062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんこもコーヒーも\n原料は豆にゃ～\nそりゃ相性いいに\n決まってるにゃ♪", 0, 4, 0, 1, 1, 1, 125101, 7063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつの為に\nタマキ特製ブレンドを\n開発したいにゃ♪", 0, 5, 0, 1, 1, 1, 125101, 7064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつと働いてると\nなぜかあっという間に\n閉店時間が\n来ちゃうのにゃ～", 0, 101, 0, 1, 4, 1, 125101, 7065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつといると\n新しいアイデアが\n溢れるほど\n出てきちゃうのにゃ♪", 0, 102, 0, 1, 8, 1, 125101, 7066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミがコーヒーを\n淹れてくれたのにゃ？\nにゃはは、常温で\n猫舌にも優しいにゃ♪", 0, 1, 0, 2, 1, 1, 125101, 7067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理が上手くなったら\nカフェご飯メニューも\n充実させたいにゃ～", 0, 2, 0, 2, 1, 1, 125101, 7068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お店の経営は大変\nだけど、キミとなら\n乗り越えられるって\n確信してるにゃ！", 0, 3, 0, 2, 1, 1, 125101, 7069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　この制服\n似合ってるにゃ？\nにゃはは！　褒めても\n１ルピも出ないにゃ♪", 0, 4, 0, 2, 1, 1, 125101, 7070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしが好きなのは\n猫に好かれる人にゃ♪\n…ん、キミ猫に懐かれ\nまくってるにゃ…", 0, 101, 0, 2, 4, 1, 125101, 7071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミの制服姿\nけっこーイケてるにゃ\nあたしがお客さんなら\n通いつめちゃうにゃ♪", 0, 102, 0, 2, 8, 1, 125101, 7072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は一杯の\nコーヒーから始まる…\nにゃふふん♪\nシャレた朝だにゃ～♪", 0, 1, 1, 2, 1, 1, 125101, 7073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はたい焼きと\nコーヒーのセットで\nまったり休憩\nしようにゃ～♪", 0, 2, 2, 2, 1, 1, 125101, 7074);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コーヒー淹れたにゃ\n星空を見ながら\n二人で飲もうにゃ…♪", 0, 3, 3, 2, 1, 1, 125101, 7075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃ～ん…ゴロゴロ\nコーヒーと同じくらい\n癒されるにゃ～…♪", 0, 2, 0, 3, 1, 1, 125101, 7077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こいつかわいいにゃ～\nうちの猫たちとも\nいい勝負なのにゃ！", 0, 3, 0, 3, 1, 1, 125101, 7078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～いい香りだにゃ～\nコーヒーもそうだけど\n香りの癒し効果は\n抜群にゃ～♪", 0, 4, 0, 3, 1, 1, 125101, 7079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫に暖かいものは\nまるまれと言ってる\nようなもんにゃ…♪\nまるまる…", 0, 5, 0, 3, 1, 1, 125101, 7080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃは～うまいにゃ♪\nカフェの新メニューに\n採用しちゃおう\nかにゃ～♪", 0, 7, 0, 3, 1, 1, 125101, 7082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃるほど…\n調べれば調べるほど\nコーヒーは\n奥が深いのにゃ…", 0, 8, 0, 3, 1, 1, 125101, 7083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシの手料理は\n坊やの口に合うらしい\n胃袋は討ち取ったぞ♪", 0, 103, 0, 1, 12, 1, 107101, 7085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("胸に再度触れると\n誓約は無効になるのか\n…だと？　鋭い質問だ\n安心しろ。ならん☆", 0, 103, 0, 2, 12, 1, 107101, 7086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ようやくこの服にも\n慣れてきたかな？\nふふっ、たまには\nこういう服も悪くない", 0, 1, 0, 1, 1, 1, 125201, 7087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も店は好調だが、\n私は軍人だからな\n当初の目的も\n忘れないようにしよう", 0, 2, 0, 1, 1, 1, 125201, 7088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫が近くに来ると\nついつい見てしまうな\n仕事が終わったら\n遊んでやるかな♪", 0, 3, 0, 1, 1, 1, 125201, 7089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コーヒーの淹れ方が\nうまくなってきたな♪\nどうせならお菓子も\n研究してみるか！", 0, 4, 0, 1, 1, 1, 125201, 7090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("利益を考えると\n価格をあげるべきか？\n…いや、利益よりも\n皆の笑顔の方が大事だ", 0, 5, 0, 1, 1, 1, 125201, 7091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またあいつを\n呼んでしまったな…\n今度、コーヒーでも\n淹れて労ってやるか♪", 0, 101, 0, 1, 4, 1, 125201, 7092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次に入荷するお菓子は\nあいつの意見を聞くか\nどんな味が好きか\n気になるしな", 0, 102, 0, 1, 8, 1, 125201, 7093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに、コーヒーを\n淹れてほしい？\nふふっ♪\n仕方のない奴だな！", 0, 1, 0, 2, 1, 1, 125201, 7094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…そうだ。\nコーヒーと乾パンは\n合うのではないか？\n今度試してみよう！", 0, 2, 0, 2, 1, 1, 125201, 7095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コーヒーもいいが、\nココアも悪くないぞ♪\n貴公も一緒にどうだ？", 0, 3, 0, 2, 1, 1, 125201, 7096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女に比べれば\n大人しい服だろう？\nだが、カフェには\nこの服でバッチリだ！", 0, 4, 0, 2, 1, 1, 125201, 7097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公はコーヒーを\n飲めるのかっ？それは\nうらやましいな…", 0, 101, 0, 2, 4, 1, 125201, 7098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公の働きぶりには\n目を見張るものがある\nその姿は、その…\n結構かっこいいぞっ！", 0, 102, 0, 2, 8, 1, 125201, 7099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さぁ、今日も一日、\n頑張るぞっ！\n気合いを入れて\n開店準備だっ！", 0, 1, 1, 2, 1, 1, 125201, 7100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼は稼ぎ時だからな！\n荒波を乗り切るため\n貴公も一緒に\n頑張ってくれるか？", 0, 2, 2, 2, 1, 1, 125201, 7101);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふあぁ…もう夜か\n今日は頑張ったからな\nはやめに休むとしよう", 0, 3, 3, 2, 1, 1, 125201, 7102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はふぅ～…\nたまにはこうして\nゆったりするのも\n悪くないな…", 0, 2, 0, 3, 1, 1, 125201, 7104);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("猫もかわいいが、\nこいつもなかなか…\n見ていると、\n撫でたくなるな♪", 0, 3, 0, 3, 1, 1, 125201, 7105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは良い香りだな\nふむ、コーヒーも\nより香り高いものが\n作れるよう試すか！", 0, 4, 0, 3, 1, 1, 125201, 7106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ～…\n体を温めなければ、\nすぐに動けないからな", 0, 5, 0, 3, 1, 1, 125201, 7107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これもうまいが、\n私はお菓子も…\nいや、食べすぎは\n体に良くないな", 0, 7, 0, 3, 1, 1, 125201, 7109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…書物は参考になるな\n次はこのやり方を\n試してみるかな", 0, 8, 0, 3, 1, 1, 125201, 7110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛と希望の魔法少女！\n弟くんの平和は\nお姉ちゃんが守るよ♪", 0, 1, 0, 1, 1, 1, 120001, 7112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の戦い方を\n見せてあげる！\nお姉ちゃんチョップ♪", 0, 2, 0, 1, 1, 1, 120001, 7113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("闇の力が高まってる…\n早く弟くんを\nギュ～ってしないと！", 0, 3, 0, 1, 1, 1, 120001, 7114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミニ弟くんを\n部屋中に呼び出して\n弟くんハウスに～♪", 0, 4, 0, 1, 1, 1, 120001, 7115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("決めポーズの練習でも\nしよっかな…\nはい、ポーズ♪", 0, 5, 0, 1, 1, 1, 120001, 7116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の力で\n弟くんのそばに\n瞬間移動したいなぁ", 0, 101, 0, 1, 4, 1, 120001, 7117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("禁じられた必殺技\nその名も──\n闇のお姉ちゃん頭突き", 0, 102, 0, 1, 8, 1, 120001, 7118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女な\nお姉ちゃんに\n興味津々だねっ？\n全部教えてあげるね♪", 0, 1, 0, 2, 1, 1, 120001, 7119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("闇のお姉ちゃんとして\n世界を弟くんのものに\n…な～んて冗談冗談♪", 0, 2, 0, 2, 1, 1, 120001, 7120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんって魔法少女に\nなりたがってたよね？\n…うん。応援するね！", 0, 3, 0, 2, 1, 1, 120001, 7121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サインが欲しいの？\nふふっ、任せて！\n愛する弟くんへ、と♪", 0, 4, 0, 2, 1, 1, 120001, 7122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんふふ～ん♪\n魔法少女お姉ちゃんの\nテーマソング完成っ♪", 0, 101, 0, 2, 4, 1, 120001, 7123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、弟くんからの\n愛と希望を感じるよ…\n更に変身しちゃうぞ♪", 0, 102, 0, 2, 8, 1, 120001, 7124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの朝を魔法で\n守りに来たよ！\n希望の朝だねっ♪", 0, 1, 1, 2, 1, 1, 120001, 7125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんのお昼を魔法で\n守りに来たよ！\n愛のお弁当をどうぞ♪", 0, 2, 2, 2, 1, 1, 120001, 7126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの夜を魔法で\n守りに来たよ！\nここからは闇の時間♪", 0, 3, 3, 2, 1, 1, 120001, 7127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法少女の一休み♪\n愛と希望と…闇の力が\n回復していくね～♪", 0, 2, 0, 3, 1, 1, 120001, 7129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいかわいい♪\nお姉ちゃんの魔法で\n増やしちゃうぞ…♪", 0, 3, 0, 3, 1, 1, 120001, 7130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\n弟くんと同じ…\nくんくん、くんくん…", 0, 4, 0, 3, 1, 1, 120001, 7131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体を温めておいて…\nこの熱を、ぜ～んぶ\n弟くんに伝えるよ…！", 0, 5, 0, 3, 1, 1, 120001, 7132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミニ弟くんを呼ぶには\nいっぱい食べないと…\n魔法ってお腹減るから", 0, 7, 0, 3, 1, 1, 120001, 7134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの平和を守る…\nそのためには\nチェックチェック…♪", 0, 8, 0, 3, 1, 1, 120001, 7135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服も、最初は\n慣れなかったのですが\n今ではすっかり\n体に馴染んでおります", 0, 1, 0, 1, 1, 1, 125301, 7137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自然を守るためにも\nお勉強は欠かせません\n日々精進でございます", 0, 2, 0, 1, 1, 1, 125301, 7138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("採取した薬草を\n調合しておきましょう\nいつ必要になるか\n分かりませんからね", 0, 3, 0, 1, 1, 1, 125301, 7139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("合宿は過酷でしたが\nおかげでちょっと\n力持ちになったような\n気がいたします…♪", 0, 4, 0, 1, 1, 1, 125301, 7140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんわんのほうの\n主さまに、ごはんを\nあげる時間ですね…", 0, 5, 0, 1, 1, 1, 125301, 7141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっともっと訓練や\nお勉強を重ねて\n主さまのお役に\n立たなくては…", 0, 101, 0, 1, 4, 1, 125301, 7142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おや、そろそろ\nわんわんのほうの\n主さまをお散歩に\n連れていく時間です", 0, 102, 0, 1, 8, 1, 125301, 7143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さま、よろしければ\nお散歩に行きませんか\n今日の森は穏やかで\n過ごしやすいかと", 0, 1, 0, 2, 1, 1, 125301, 7144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんわんのほうの\n主さまも、今では\n【美食殿】の大切な\n仲間でございます", 0, 2, 0, 2, 1, 1, 125301, 7145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森には危険が\nいっぱいでございます\nケガをなさらないよう\nお気をつけください", 0, 3, 0, 2, 1, 1, 125301, 7146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし森や動物のことで\n気になることがあれば\n気軽にお尋ねください", 0, 4, 0, 2, 1, 1, 125301, 7147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森へ行く前には\n必ず装備の点検を\nお願いいたします\n約束ですよ、主さま？", 0, 101, 0, 2, 4, 1, 125301, 7148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森の中で主さまたちと\nゆったり過ごす時間は\nわたくしにとって\n大切なひとときです", 0, 102, 0, 2, 8, 1, 125301, 7149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n朝ごはんをしっかり\n食べて、お勤めに\n備えましょう", 0, 1, 1, 2, 1, 1, 125301, 7150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんわんのほうの\n主さまにおやつを\nあげる時間です\nどうぞ、召し上がれ", 0, 2, 2, 2, 1, 1, 125301, 7151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どれだけ野営に\n慣れたとしても\nベッドで眠れるなら\nそうしたいところです", 0, 3, 3, 2, 1, 1, 125301, 7152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらなのですが\nわんわんのほうの\n主さまもお気に入りの\nようです", 0, 2, 0, 3, 1, 1, 125301, 7154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんわんのほうの\n主さまにも、こうした\n玩具を与えるべき\nでしょうか…？", 0, 3, 0, 3, 1, 1, 125301, 7155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心地よい香りです\n次は、自然由来の\n香料も試しましょう", 0, 4, 0, 3, 1, 1, 125301, 7156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖をとるのは\n野営の時などに\nとても大事なことで\nございますね", 0, 5, 0, 3, 1, 1, 125301, 7157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べられる時に食べて\nおくのも、大自然では\n重要でございます", 0, 7, 0, 3, 1, 1, 125301, 7159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("より知識を蓄え\n自然の力を活用できる\nようにいたしましょう", 0, 8, 0, 3, 1, 1, 125301, 7160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今回の「冥風戦記」も\nなかなかよく書けたぞ\nふふっ、シグルドも\n喜んでくれるかな？", 0, 103, 0, 1, 12, 1, 100901, 7162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴様のためならば\n我が真なる魔力\nいつでも\n解き放とうぞ！", 0, 103, 0, 2, 12, 1, 100901, 7163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃんに\nブラッシングを\nしてあげようかな", 0, 1, 0, 1, 1, 1, 125401, 7164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ…\nこれがレンジャーの\n制服ですか", 0, 2, 0, 1, 1, 1, 125401, 7165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ\nパトロールの\n時間だ…", 0, 3, 0, 1, 1, 1, 125401, 7166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物について\nもっと知りたいな\n本を探しに行こう", 0, 4, 0, 1, 1, 1, 125401, 7167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レンジャーになって\n体調を崩す日が\n減った気がします…", 0, 5, 0, 1, 1, 1, 125401, 7168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本だけじゃわからない\n世界のことを、\nもっと知りたいです…", 0, 101, 0, 1, 4, 1, 125401, 7169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな私にも\nできることはある…\nそう信じています", 0, 102, 0, 1, 8, 1, 125401, 7170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…良かったら\n一緒に見回りへ\n行きませんか？", 0, 1, 0, 2, 1, 1, 125401, 7171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またあなたと一緒に\nレンジャーの仕事が\nできたらうれしいです", 0, 2, 0, 2, 1, 1, 125401, 7172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("けほっこほっ\n…だ、大丈夫です\nたまに出るだけなので", 0, 3, 0, 2, 1, 1, 125401, 7173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃん\nあなたにも\n懐いてきましたね", 0, 4, 0, 2, 1, 1, 125401, 7174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃんと\n散歩に出かけようかな\n…あの人も誘って", 0, 101, 0, 2, 4, 1, 125401, 7175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと肩を並べて\nレンジャーの仕事が\nできてうれしいです…", 0, 102, 0, 2, 8, 1, 125401, 7176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\nレンジャー・シオリ\n元気に出勤します", 0, 1, 1, 2, 1, 1, 125401, 7177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃんにも\nお昼ごはんを\n用意しなくちゃ", 0, 2, 2, 2, 1, 1, 125401, 7178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日は仕事だから\n早起きしなくちゃ\nおやすみなさい", 0, 3, 3, 2, 1, 1, 125401, 7179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…仕事で\n走り回ったので\n少し休憩します", 0, 2, 0, 3, 1, 1, 125401, 7181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事が終わった後に\nこうして触れていると\n癒されますね…", 0, 3, 0, 3, 1, 1, 125401, 7182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("森の香りがします…\n今日はよく\n眠れそうです…", 0, 4, 0, 3, 1, 1, 125401, 7183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ニャットちゃんと\n同じぐらい\n暖かいです…", 0, 5, 0, 3, 1, 1, 125401, 7184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レンジャーの仕事を\nしていると\nお腹が空きます", 0, 7, 0, 3, 1, 1, 125401, 7186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなに忙しくても\n読書だけは\nやめられませんね", 0, 8, 0, 3, 1, 1, 125401, 7187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様のお留守の間\nわたくしが、兄様の\n御家を守ります！", 0, 1, 0, 1, 1, 1, 125801, 7189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("に、に、兄様の御家…\n招待いただいた以上は\n失礼のないよう\n振る舞わなくては…！", 0, 2, 0, 1, 1, 1, 125801, 7190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…兄様の素敵な\nお人柄が、家中から\nにじみ出ています…♪", 0, 3, 0, 1, 1, 1, 125801, 7191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("靴を脱がずに\n御家に上がるのに\n慣れていなくて…あ！\n飛べばいいのでは…！", 0, 4, 0, 1, 1, 1, 125801, 7192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここに花を生けたら\n華やぎそうですね\n兄様はお花…\n好きでしょうか…？", 0, 5, 0, 1, 1, 1, 125801, 7193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっとここにいたい…\nなどと言ったら\n兄様を困らせて\nしまいますよね…", 0, 101, 0, 1, 4, 1, 125801, 7194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お料理などを作って\n兄様を出迎えられたら\nいいのに…料理の腕も\n磨かなくては…！", 0, 102, 0, 1, 8, 1, 125801, 7195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このような姿で\n失礼しております…！\nネ、ネズミがいたので\nつい本気を…！", 0, 1, 0, 2, 1, 1, 125801, 7196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おかえりなさいませ\nお忙しい御身をどうぞ\n癒してくださいね", 0, 2, 0, 2, 1, 1, 125801, 7197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様の話し相手…！？\nど、どうしましょう…\nわたくしには面白い\n話なんて…はうぅ…！", 0, 3, 0, 2, 1, 1, 125801, 7198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なぜか、動物などに\n好かれる体質で…\n迷い猫捜しのバイトの\nお役に立てますか？", 0, 4, 0, 2, 1, 1, 125801, 7199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("に、兄様の家に来たら\n『添い寝』をするのが\n礼儀とリアさんが…\n本当…でしょうか？", 0, 101, 0, 2, 4, 1, 125801, 7200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたくしはここに\nいて…よいのですね？\n『仲間』として…", 0, 102, 0, 2, 8, 1, 125801, 7201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は得意なんです\nもし兄様が苦手なら\nわたくしが起こして\n差し上げますよ", 0, 1, 1, 2, 1, 1, 125801, 7202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様…昼餉を作って\nみたのですが、失敗\nしてしまいました…", 0, 2, 2, 2, 1, 1, 125801, 7203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふあぁ…\nはっ！　お…\nお恥ずかしい所を…！", 0, 3, 3, 2, 1, 1, 125801, 7204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、これは…！\n人様の御家なのに\nつい…駄目になって…\nしまいますぅ…！", 0, 2, 0, 3, 1, 1, 125801, 7206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("と、飛びかかっては\nこない…ですよね…？", 0, 3, 0, 3, 1, 1, 125801, 7207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すぅ…はぁ…\nこのかぐわしさ\n心が洗われます…", 0, 4, 0, 3, 1, 1, 125801, 7208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんて暖かい…\n兄様の優しくお広い\n御心のようです…♪", 0, 5, 0, 3, 1, 1, 125801, 7209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなに食べていたら\nはしたない…\nでしょうか？", 0, 7, 0, 3, 1, 1, 125801, 7211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様の本棚はまるで\n知識の宝庫ですね\n己の世間知らずぶりを\n実感してしまいます", 0, 8, 0, 3, 1, 1, 125801, 7212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の冒険に向けて\n騎空士弁当を作ろっと\nまずはおにぎりから！", 0, 1, 0, 1, 1, 1, 125501, 7214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の修行しなくちゃ\nもっともっと頼れる\n団長になりたいから！", 0, 2, 0, 1, 1, 1, 125501, 7215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビカラちゃんを\n遊びに誘いたいけど…\nどういう場所が\n好きなんだろう？", 0, 3, 0, 1, 1, 1, 125501, 7216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事を真面目に\nしっかりこなすことが\n騎空艇への\n一番の近道だよね", 0, 4, 0, 1, 1, 1, 125501, 7217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいる人の中で\n騎空団に興味ある人\nいたりしないかな…？", 0, 5, 0, 1, 1, 1, 125501, 7218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これまでも想い出は\nいっぱいできたけど…\nこれからもたくさん\n想い出を作りたいな！", 0, 101, 0, 1, 4, 1, 125501, 7219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間がいるから\n騎空士は限界だって\n超えられるんだね", 0, 102, 0, 1, 8, 1, 125501, 7220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装\n魔法使いらしいでしょ\n服に着られないよう\n頑張らなくちゃね！", 0, 1, 0, 2, 1, 1, 125501, 7221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとなら\nどんな相手だって\n怖くなんてないよ！", 0, 2, 0, 2, 1, 1, 125501, 7222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カリンさんから\n新しい依頼が来たよ！\n一緒に頑張ろ！", 0, 3, 0, 2, 1, 1, 125501, 7223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("操舵士になるのは\nずいぶん難しそう…\nいつか頼れる仲間が\n見つかるといいな", 0, 4, 0, 2, 1, 1, 125501, 7224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手合わせしたいの？\nいいよ、たまには\n団長らしいところ\n見せてあげるね！", 0, 101, 0, 2, 4, 1, 125501, 7225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ二人きりだけど…\nこの騎空団は\n私の宝物だよ！", 0, 102, 0, 2, 8, 1, 125501, 7226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう～…\n昨日は遅くまで\n魔法の研究してて…\nふわぁ…眠いなぁ…", 0, 1, 1, 2, 1, 1, 125501, 7227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さてと、お昼休み！\n紅茶淹れてくるから\n一緒に飲もうよ！", 0, 2, 2, 2, 1, 1, 125501, 7228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遅くまでお疲れさま！\n無理しない程度に\nお互い頑張ろう！", 0, 3, 3, 2, 1, 1, 125501, 7229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の研究は\n一旦、休憩！\n頭を休めなくちゃ", 0, 2, 0, 3, 1, 1, 125501, 7231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法みたいに\nかわいい！\n騎空団に入る？\nなんてね！", 0, 3, 0, 3, 1, 1, 125501, 7232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂い…\nそれになんだか\n集中力が増したかも", 0, 4, 0, 3, 1, 1, 125501, 7233);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体だけじゃなくて\n心までポカポカする…\nなんだか魔法みたい", 0, 5, 0, 3, 1, 1, 125501, 7234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いろいろ考え事したら\nお腹が空いちゃった！\nいただきまーす！", 0, 7, 0, 3, 1, 1, 125501, 7236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『摂理の彼方へ\n至るには…』\n…この魔導書\n勉強になるなあ", 0, 8, 0, 3, 1, 1, 125501, 7237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらの服を着ると\n冒険に出かけたく\nなっちゃいますね", 0, 1, 0, 1, 1, 1, 125701, 7239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険者の心得その一\n準備はできる限り\nしっかりとこなすべし\nなんてどうでしょう？", 0, 2, 0, 1, 1, 1, 125701, 7240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("調合に必要な素材は\nあれとこれとそれと…\n時間があるとついつい\n考えちゃいますね", 0, 3, 0, 1, 1, 1, 125701, 7241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくですから\nより良い素材を\n自分で集めたいですね", 0, 4, 0, 1, 1, 1, 125701, 7242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このポーションが\nみなさんの役に立つと\nうれしいですね", 0, 5, 0, 1, 1, 1, 125701, 7243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険者の心得その二\n危なくなった時は\nまず逃げるべし！\n大事なことですね", 0, 101, 0, 1, 4, 1, 125701, 7244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人の冒険は\nいつも楽しそうで\n元気がもらえます", 0, 102, 0, 1, 8, 1, 125701, 7245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぜひおすすめしたい\n依頼があるんです\nこちらをどうぞ♪", 0, 1, 0, 2, 1, 1, 125701, 7246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほしいお薬があれば\n錬金術で作って\nさしあげますよ", 0, 2, 0, 2, 1, 1, 125701, 7247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("依頼で気になる\nところがあれば\n何でもご確認ください", 0, 3, 0, 2, 1, 1, 125701, 7248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスに\n錬金術の実験設備を…\nえ？　だめですか？", 0, 4, 0, 2, 1, 1, 125701, 7249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポーションをどうぞ\n大丈夫、効果は\n確認済みですので♪", 0, 101, 0, 2, 4, 1, 125701, 7250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はどんな冒険に\n行かれるんですか？\nいつでもお供しますよ", 0, 102, 0, 2, 8, 1, 125701, 7251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もいい一日に\nなりそうですね\n冒険日和といった\nところでしょうか", 0, 1, 1, 2, 1, 1, 125701, 7252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい時間ですし\nランチにしませんか？\n次の冒険の\n作戦会議も兼ねて♪", 0, 2, 2, 2, 1, 1, 125701, 7253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も遅いですし\n明日の冒険のため\n今日は早く寝ましょう", 0, 3, 3, 2, 1, 1, 125701, 7254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふう…やはり冒険は\n事務仕事と違いますね\n少し休憩を…", 0, 2, 0, 3, 1, 1, 125701, 7256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険は緊張の連続です\nかわいい物で\n心を癒しましょう", 0, 3, 0, 3, 1, 1, 125701, 7257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、この香りは…\n素晴らしいバランスで\n調合されていますね", 0, 4, 0, 3, 1, 1, 125701, 7258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この火力…\n錬金術の調合に\n使えそうですね", 0, 5, 0, 3, 1, 1, 125701, 7259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険の際は食べられる\n時に食べておく！\n…とペコリーヌさんも\nおっしゃってましたね", 0, 7, 0, 3, 1, 1, 125701, 7261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…なるほど\nこんな調合も\nあるのですね…\n奥が深いです", 0, 8, 0, 3, 1, 1, 125701, 7262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイツどこ行った…？\n戦うならアタシも\n連れてけよなー！", 0, 103, 0, 1, 12, 1, 106101, 7264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も悪いヤツ退治…\nの前に腹ごしらえだ！\nなんか食べに行くぞ！", 0, 103, 0, 2, 12, 1, 106101, 7265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなー！\nギルドハウスで\nぼくと握手！", 0, 1, 0, 1, 1, 1, 125601, 7266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("種族も年齢も違うけど\nみんな楽しそうだね！\nやっぱりここはぼくの\nゆ～とぴあさ！", 0, 2, 0, 1, 1, 1, 125601, 7267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハハッ！　まるで\nパーティー会場だね！\nこれは楽しませがいが\nあるってものだよ！", 0, 3, 0, 1, 1, 1, 125601, 7268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やぁみんな！\nご利益満点のネズ耳は\nいかがかな？\nひとつ３ルピだよ！", 0, 4, 0, 1, 1, 1, 125601, 7269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいれば\n遊び相手に困らないね\nかしこみかしこみ～！", 0, 5, 0, 1, 1, 1, 125601, 7270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこか遊びに\n行こうかな♪\nそうだ、あの人にも\n声をかけてみよう！", 0, 101, 0, 1, 4, 1, 125601, 7271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人といると\nぼくまで楽しくなって\nくるんだよね！\n毎日パレード気分さ！", 0, 102, 0, 1, 8, 1, 125601, 7272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネズ耳の在庫が\n切れたんだ！\n作るのを\n手伝ってくれるかい？", 0, 1, 0, 2, 1, 1, 125601, 7273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん？　握手かい？\nいいとも！\nいつでも何度でも\nしてあげるよ！", 0, 2, 0, 2, 1, 1, 125601, 7274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装に興味が\nあるのかい？\nきみ、なかなか\n見る目があるね！", 0, 3, 0, 2, 1, 1, 125601, 7275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しばらくここに厄介に\nなるつもりなんだ\nあとで街を案内\nしてくれるかい？", 0, 4, 0, 2, 1, 1, 125601, 7276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっておきのチーズ\nきみと半分こだ！\nみんなには内緒だよ？", 0, 101, 0, 2, 4, 1, 125601, 7277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きみはいてほしい時に\nいつもそばに\nいてくれるね\n本当にかしこみだよ！", 0, 102, 0, 2, 8, 1, 125601, 7278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やぁ、おはよう！\n気持ちのいい朝だね\n今日も楽しくネズ耳\n売りにはげもうか！", 0, 1, 1, 2, 1, 1, 125601, 7279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼だね！\nおいしいチーズを\n持ってきたから\nぼくと半分こだ！", 0, 2, 2, 2, 1, 1, 125601, 7280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\n楽しかったね！\nいい夢が見られること\n間違いなしさ！", 0, 3, 3, 2, 1, 1, 125601, 7281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼくにも休息は\n必要さ！\nリラックス〜\nリラックス〜♪", 0, 2, 0, 3, 1, 1, 125601, 7283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼくのぬいぐるみも\n作って売ろうかな…\n修繕費も一気に\n集まるかもね！", 0, 3, 0, 3, 1, 1, 125601, 7284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだね！\nトーゴクのお香に\nよく似てるよ", 0, 4, 0, 3, 1, 1, 125601, 7285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…温まるねぇ…\nそうだ、この火で\nチーズでも炙って\nみようかな", 0, 5, 0, 3, 1, 1, 125601, 7286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、この味…\nトーゴクを思い出すよ\nどれ、もう一つ\nいただこうか！", 0, 7, 0, 3, 1, 1, 125601, 7288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはランドソルの\nガイド本だね！\nありがたく参考に\nさせてもらうよ！", 0, 8, 0, 3, 1, 1, 125601, 7289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか、わらわが\nこのような装束を\n纏う日がくるとはな…\n感慨深いものじゃ", 0, 1, 0, 1, 1, 1, 126201, 7291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わらわの美貌で\nこのギルドハウスも\nより華やかに\nなったようじゃな", 0, 2, 0, 1, 1, 1, 126201, 7292);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つまらぬ戦いで\n晴れ着を汚しとうない\n今日は一日\nゆっくりするかの", 0, 3, 0, 1, 1, 1, 126201, 7293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はわらわが食事の\n準備をして、あやつの\n帰りを待ってやろう\n献立は何がよいかの…", 0, 4, 0, 1, 1, 1, 126201, 7294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユキといったか…\n掴みどころのない\nやつじゃが、根性は\n認めてやるかの", 0, 5, 0, 1, 1, 1, 126201, 7295);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうして、仲間と\nのんびり過ごす時間も\n悪くないのう♪", 0, 101, 0, 1, 4, 1, 126201, 7296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あやつを誘って\n月を見に行こうかの\n夜が楽しみじゃ♪", 0, 102, 0, 1, 8, 1, 126201, 7297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いかなる衣装で\nあろうとも、わらわは\n完璧に着こなして\nしまうのじゃ♪", 0, 1, 0, 2, 1, 1, 126201, 7298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんじゃ？\nわらわの姿に\n見惚れておったとな？\nす、素直でよいのじゃ", 0, 2, 0, 2, 1, 1, 126201, 7299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼であるわらわに\n相応しい装束じゃろう\nあとは真っ赤な血を\n添えたいのう…", 0, 3, 0, 2, 1, 1, 126201, 7300);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お主、疲れておるな？\nわらわが癒してやろう\nほれ、近う寄るのじゃ", 0, 4, 0, 2, 1, 1, 126201, 7301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お主がおるだけで\nギルドハウスが\n賑やかになるのう\nある種の才能じゃな♪", 0, 101, 0, 2, 4, 1, 126201, 7302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属よ、風呂にするか\nご飯にするか\nそれとも、わらわに…\nいや、忘れるのじゃ", 0, 102, 0, 2, 8, 1, 126201, 7303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝一番、わらわに\n会いたかったとな…\n眷属よ\n褒めてつかわすぞ♪", 0, 1, 1, 2, 1, 1, 126201, 7304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眷属よ、わらわが\n食事を用意したぞ\n忌々しい太陽に負けず\n頑張るのじゃ", 0, 2, 2, 2, 1, 1, 126201, 7305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠るには惜しい夜じゃ\n眷属よ、もうしばらく\nわらわの傍に\nおるがよい", 0, 3, 3, 2, 1, 1, 126201, 7306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかじゃの♪\n今度あやつにも\n座らせてやろう", 0, 2, 0, 3, 1, 1, 126201, 7308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛いやつじゃ\n少しばかり、わらわが\n遊んでやろうかの", 0, 3, 0, 3, 1, 1, 126201, 7309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気品ある香りじゃのう\nわらわの古城にも\n一つ欲しいところじゃ", 0, 4, 0, 3, 1, 1, 126201, 7310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よいぬくもりじゃ…\n忌々しい太陽とは\n大違いじゃの", 0, 5, 0, 3, 1, 1, 126201, 7311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("味付けの参考に\nあと、もう一つだけ…\n止まらんのじゃ…", 0, 7, 0, 3, 1, 1, 126201, 7313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼の弱点について\n記されておるのか…\nふむ、眠気が\nさめてしもうたぞ", 0, 8, 0, 3, 1, 1, 126201, 7314);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このままボクが美しく\nなり続けても、彼なら\nきっと隣にいてくれる\nはずだよね！", 0, 103, 0, 1, 12, 1, 100801, 7316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もっとそばに来なよ\nボクの隣は\nキミのための\n特等席なんだから", 0, 103, 0, 2, 12, 1, 100801, 7317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドレスの影響かな…\n前より黒や赤が\n好きになったかも", 0, 1, 0, 1, 1, 1, 126301, 7318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクがいるだけで\nここがぐんっと\n華やかになったね♪", 0, 2, 0, 1, 1, 1, 126301, 7319);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクを描いた絵画\n今度持ってきて\n飾ってあげようかな", 0, 3, 0, 1, 1, 1, 126301, 7320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクはボクに\n魅了されっぱなしさ♪\nまさに魔性の存在だよ", 0, 4, 0, 1, 1, 1, 126301, 7321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美のアドバイスを\n聞きたい人いるかい？\nボクがもっともっと\n輝かせてあげるよ♪", 0, 5, 0, 1, 1, 1, 126301, 7322);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人、今度はボクを\nどう褒めるだろう？\nもし語彙が尽きても\n許してあげよっと♪", 0, 101, 0, 1, 4, 1, 126301, 7323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人に似合うコーデ\n考えてあげよっと\n案外、なんでも\n着こなしそうだよね♪", 0, 102, 0, 1, 8, 1, 126301, 7324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼になるなんて\nやっぱりゴメンだね！\n永遠の美よりも\n大事なことがあるのさ", 0, 1, 0, 2, 1, 1, 126301, 7325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お肌にいいものは\n大体好きだよ\nトマトジュースとかね", 0, 2, 0, 2, 1, 1, 126301, 7326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("銀のアクセサリーが\nボクは大好きでね\nいつでもプレゼント\n待ってるよ♪", 0, 3, 0, 2, 1, 1, 126301, 7327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イリヤみたいにお城に\n住んでみたいんだ♪\n美を統べる者に\n相応しいでしょ？", 0, 4, 0, 2, 1, 1, 126301, 7328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今のボクがカップを\n触ると壊しちゃうんだ\nだからほら、キミが\nボクに紅茶を飲ませて", 0, 101, 0, 2, 4, 1, 126301, 7329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミも美を磨けば\nもっと輝けるはずさ！\nボクがメイクとか\nしてあげようか？", 0, 102, 0, 2, 8, 1, 126301, 7330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んん、まだ眠い…\n美のためにも、\nもうひと眠りするよ…", 0, 1, 1, 2, 1, 1, 126301, 7331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクにぴったりな\n日傘を買ったんだ♪\n散歩にでも行こうよ！", 0, 2, 2, 2, 1, 1, 126301, 7332);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜こそボクの時間！\nさぁ、あまねく人々へ\nボクの美を広めよう！", 0, 3, 3, 2, 1, 1, 126301, 7333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リラックスは大事だよ\n心の余裕こそが\n美の秘訣だからね♪", 0, 2, 0, 3, 1, 1, 126301, 7335);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミもボクの\n美の虜にしてあげる♪\nうれしいでしょ？", 0, 3, 0, 3, 1, 1, 126301, 7336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人々を魅了するほどの\n魔性の香り…\nボクにふさわしいね♪", 0, 4, 0, 3, 1, 1, 126301, 7337);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷えは美の大敵さ\nボクのように\n美しくなりたいなら\n体を温めるべきだよ", 0, 5, 0, 3, 1, 1, 126301, 7338);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事をするボクの\nなまめかしさ…♪\n吸血鬼すらも\nドキッとするだろうね", 0, 7, 0, 3, 1, 1, 126301, 7340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("吸血鬼って\n美しい存在だよね…\nボクほどではないけど", 0, 8, 0, 3, 1, 1, 126301, 7341);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここがナイトさんの\nお家なんですねーっ！\n雰囲気そっくりっ！", 0, 1, 0, 1, 1, 1, 126401, 7343);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドアも壁もお菓子じゃ\nないんですよねっ？\n不思議ですねーっ♪", 0, 2, 0, 1, 1, 1, 126401, 7344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("失礼のないように\n気をつけないとっ！\nライラエルさまとも\n約束してますからっ！", 0, 3, 0, 1, 1, 1, 126401, 7345);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("向こうに帰るころには\nお土産話がいっぱい\nできてるといいな～♪", 0, 4, 0, 1, 1, 1, 126401, 7346);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦闘用のアームの他に\n観光用のアームも\nあったらいいのにな～", 0, 5, 0, 1, 1, 1, 126401, 7347);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナイトさんの充填と\nライラエルさまの充填\nどっちも違って\nどっちも大好きです♪", 0, 101, 0, 1, 4, 1, 126401, 7348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ナイトさんが\nマスターになって\nくれたら…えへへっ\nなんでもないですっ！", 0, 102, 0, 1, 8, 1, 126401, 7349);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お手伝いだったら\n任せてくださいっ！\nお家の移転とか\nしちゃいますかっ？", 0, 1, 0, 2, 1, 1, 126401, 7350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちに来るときは\nポポおじいさんが\nしっかりメンテして\nくれるんですよっ♪", 0, 2, 0, 2, 1, 1, 126401, 7351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お家の中にいるのも\nいいですけど、お外も\n気になります～っ！\nお出かけしましょう♪", 0, 3, 0, 2, 1, 1, 126401, 7352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴォルガーノさんに\nそっくりの子猫さんを\n見かけたんですっ！\nご親戚ですかねっ？", 0, 4, 0, 2, 1, 1, 126401, 7353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここだけの話ですよ？\n…実はケーブルって\n触られると、ちょっと\nくすぐったいんですっ", 0, 101, 0, 2, 4, 1, 126401, 7354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお家の持ち主は\nナイトさんですよね？\nそれじゃここでは\nご主人さまですねっ", 0, 102, 0, 2, 8, 1, 126401, 7355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございますっ\n今日もフルパワーで\nがんばりましょうっ♪", 0, 1, 1, 2, 1, 1, 126401, 7356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼の時間ですねっ！\nランチの充填、\nお願いしまーすっ♪", 0, 2, 2, 2, 1, 1, 126401, 7357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ眠らなくて\n大丈夫ですかっ？\n夜ふかしさんなら\nお付き合いしますよ♪", 0, 3, 3, 2, 1, 1, 126401, 7358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エネルギーの消費を\n抑えるのも大切\nですよね～っ", 0, 2, 0, 3, 1, 1, 126401, 7360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしが触っても\n平気なんて…！\nかわいくて頑丈っ！\n好きですっ！", 0, 3, 0, 3, 1, 1, 126401, 7361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("センサーによると…\nこの香りはいい香りに\n該当するみたいですっ\nなるほどーっ！", 0, 4, 0, 3, 1, 1, 126401, 7362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいのって\nいいですよねっ！\nみなさんうれしそう\nですしっ♪", 0, 5, 0, 3, 1, 1, 126401, 7363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがこっちの世界の\nごはんなんですねっ\nおいしい気がします！", 0, 7, 0, 3, 1, 1, 126401, 7365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そーっとそーっと…\n本を破かないように…\n書いてある内容より\n難しいです～っ！", 0, 8, 0, 3, 1, 1, 126401, 7366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウィスタリア家の\nプライベートビーチも\nご案内しますわね♪", 0, 1, 0, 1, 1, 1, 126701, 7368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界を巡る\nリゾートクルーズも\nご用意できますわよ", 0, 2, 0, 1, 1, 1, 126701, 7369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("避暑地に専用の\n別荘がありますの\n今度ご招待しますわね", 0, 3, 0, 1, 1, 1, 126701, 7370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日焼けは乙女の\n天敵ですわね\n備えはしっかりと…", 0, 4, 0, 1, 1, 1, 126701, 7371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("線香花火だけでは\n物足りませんわね\nもっとドカーンと…", 0, 5, 0, 1, 1, 1, 126701, 7372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルド活動も全力で！\nバカンスも全力で！\nそれが私ですわ！", 0, 101, 0, 1, 4, 1, 126701, 7373);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私のセンスで選んだ\n特注の水着ですもの\n似合って当然ですわ♪", 0, 102, 0, 1, 8, 1, 126701, 7374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご希望ならすぐにでも\n夏の飛空艇遊覧ツアー\nへご招待しますわ♪", 0, 1, 0, 2, 1, 1, 126701, 7375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の賑やかな\n雰囲気は好きですが…\n暑さには参りますわね", 0, 2, 0, 2, 1, 1, 126701, 7376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日の光を浴びるほどに\n輝きを増す夏の私！\n今日も絶好調ですわ♪", 0, 3, 0, 2, 1, 1, 126701, 7377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏祭りに協力するなら\n資金と人材、どちらも\n用意しないとですわね", 0, 4, 0, 2, 1, 1, 126701, 7378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたさま…その…\nそうも見つめられると\n照れてしまいます…", 0, 101, 0, 2, 4, 1, 126701, 7379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("タマキさんの働く\n海の家も訪れて\nみたいですわね♪", 0, 102, 0, 2, 8, 1, 126701, 7380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("港の市場が\n賑わう頃ですわね！\n私たちも参りますわよ", 0, 1, 1, 2, 1, 1, 126701, 7381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷たい飲み物でも\nご一緒にいかが？\nうちのシェフに用意\nさせてありますの", 0, 2, 2, 2, 1, 1, 126701, 7382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだもう少し…\nこの夏の夜を\nあなたさまと…", 0, 3, 3, 2, 1, 1, 126701, 7383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたさまも\n良ければこちらへ\nいらっしゃいな♪", 0, 2, 0, 3, 1, 1, 126701, 7385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏に合わせた装いに\n替えてみるのも\n楽しそうですわね♪", 0, 3, 0, 3, 1, 1, 126701, 7386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この夏めいた爽やかな\n香り…期間限定で\n売り出したいですわ", 0, 4, 0, 3, 1, 1, 126701, 7387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("く…我慢です…\nこの暑さに耐えてこそ\n美しさにも磨きが…", 0, 5, 0, 3, 1, 1, 126701, 7388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑い季節に働く\nみなさまへ差し入れも\n必要ですわね", 0, 7, 0, 3, 1, 1, 126701, 7390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏のトレンドを\n押さえておくのも\n大事ですわね", 0, 8, 0, 3, 1, 1, 126701, 7391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("上手くいけば\nヒット商品になる\nポテンシャルを\n感じますわね…！", 0, 10, 0, 3, 1, 1, 126701, 7393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この極上の肌触り…\n言い値で買いますわ\n一体おいくらですの？", 0, 11, 0, 3, 1, 1, 126701, 7394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくのバカンス…\n自由に羽を\n伸ばすとしましょう", 0, 1, 0, 1, 1, 1, 126601, 7395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たとえどのような\n秘密を持とうとも\n私には筒抜けですよ", 0, 2, 0, 1, 1, 1, 126601, 7396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子供だましの怪談に\n関心はありませんが…\n霊には興味があります\n観察対象として、ね", 0, 3, 0, 1, 1, 1, 126601, 7397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼の絵日記…\nあとでゆっくりと\n読ませてもらいます", 0, 4, 0, 1, 1, 1, 126601, 7398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("セミの鳴き声に入道雲\nそしてクリームソーダ\nこれでこそ夏ですね", 0, 5, 0, 1, 1, 1, 126601, 7399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏休みの宿題でも\n作るとしましょうか\n彼の限界を少し超えた\n負荷を与えるには…", 0, 101, 0, 1, 4, 1, 126601, 7400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と過ごす夏を\n特別なものにしたい…\nそれが私の望みです", 0, 102, 0, 1, 8, 1, 126601, 7401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏だからといって\n浮かれすぎないように\n節度を持って\n楽しみなさい？", 0, 1, 0, 2, 1, 1, 126601, 7402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ見えてもマサキは\n私のプリンセスナイト\nあまり侮られては\n困りますよ？", 0, 2, 0, 2, 1, 1, 126601, 7403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の秘密ですか？\nまんじゅうが怖い…\nというのはどうです？", 0, 3, 0, 2, 1, 1, 126601, 7404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは誰かの秘密を\n盗み聞くのに\n最適な場所ですね\n…ジョークですよ", 0, 4, 0, 2, 1, 1, 126601, 7405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に風鈴の音を\nのんびり楽しもう…？\n…別に構いませんよ\n貴方とならば", 0, 101, 0, 2, 4, 1, 126601, 7406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴方に約束しましょう\n決して忘れられない\n夏にしてあげますよ", 0, 102, 0, 2, 8, 1, 126601, 7407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("早起きとは感心ですね\nでは一緒に\n体操でもしましょうか", 0, 1, 1, 2, 1, 1, 126601, 7408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食は流しそうめん？\n非効率的ですね\n…食べないとは\n一言も言っていません", 0, 2, 2, 2, 1, 1, 126601, 7409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…貴方が望むならば\nいくらでも怖い話を\nしてあげますが…\nいかがですか？", 0, 3, 3, 2, 1, 1, 126601, 7410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("七冠にも休息は\n必要なのです\nしばらくここで\n休ませてもらいますよ", 0, 2, 0, 3, 1, 1, 126601, 7412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか気に入った…\nというのは\n誰にも秘密です", 0, 3, 0, 3, 1, 1, 126601, 7413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("薫風を思わせる\nこのさわやかな香り…\n悪くないセンスですね", 0, 4, 0, 3, 1, 1, 126601, 7414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏だからこそ\n冷え対策は\n重要なのです\n…とはいえ暑いですね", 0, 5, 0, 3, 1, 1, 126601, 7415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私がどのような味が\n好きなのかは…\n当然秘密です", 0, 7, 0, 3, 1, 1, 126601, 7417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏を舞台にした\n小説は数多くあります\n彼が好きそうな本を\n何冊か見繕いましょう", 0, 8, 0, 3, 1, 1, 126601, 7418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見た目も手触りも\n完璧に覚えました\nいつでも模倣できます", 0, 10, 0, 3, 1, 1, 126601, 7420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…夏らしい\nクッションですね\nナイトプールに\n映えそうです", 0, 11, 0, 3, 1, 1, 126601, 7421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レイ様も格好良いけど\n騎士さんもなかなか…\nって、今の聞こえて\nませんよねっ？", 0, 103, 0, 1, 12, 1, 105401, 7422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんはシンプルな\n服が似合いそうです！\n今度、一緒に\n見に行きましょう♪", 0, 103, 0, 2, 12, 1, 105401, 7423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最初はどうかな～って\n思ったけど…\n水着姿でも案外\n問題ないのよね…", 0, 1, 0, 1, 1, 1, 126801, 7424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で飲みすぎると\nお腹が冷える、って\n言うけど…麦しゅわ\nなら問題ないわね！", 0, 2, 0, 1, 1, 1, 126801, 7425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑ければ暑いほど\nその後の麦しゅわは\nおいしくなるのよ…", 0, 3, 0, 1, 1, 1, 126801, 7426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかりと仕事を\nこなしてから、\nしっかりと麦しゅわ！\nやっぱりこれね！", 0, 4, 0, 1, 1, 1, 126801, 7427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、デザインも\n着心地も最高ね\n奮発して用意して\n正解だったわ♪", 0, 5, 0, 1, 1, 1, 126801, 7428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("伝説の麦しゅわ、\n飲めるものなら\nまた飲みたいわね…", 0, 101, 0, 1, 4, 1, 126801, 7429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("二つ名に恥じない\n聖騎士として\n私…飲むわ！", 0, 102, 0, 1, 8, 1, 126801, 7430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好なら水に\n濡れても大丈夫！\nなんだけど、さすがに\n書類は濡らせないわね", 0, 1, 0, 2, 1, 1, 126801, 7431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうやってじっと\n見られると…ちょっと\n恥ずかしいわ…", 0, 2, 0, 2, 1, 1, 126801, 7432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もいい天気ね\nふふっ、あとで\nビーチに遊びに\n行きましょ♪", 0, 3, 0, 2, 1, 1, 126801, 7433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着姿も慣れると\n案外快適ね\nそうだ、キミも\n水着になっちゃう？", 0, 4, 0, 2, 1, 1, 126801, 7434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("例え水着姿であろうと\n聖騎士としての誇りは\n忘れてないわ！", 0, 101, 0, 2, 4, 1, 126801, 7435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミとだったら\n麦しゅわなしでも\n最高の夏のバカンスに\nなると思うわ♪", 0, 102, 0, 2, 8, 1, 126801, 7436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仕事終わりの\n麦しゅわのために\n今日も一日\n頑張るわよ♪", 0, 1, 1, 2, 1, 1, 126801, 7437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のお昼は\nどうしようかしら…\nさ、さすがに昼からは\n自重してるわよ？", 0, 2, 2, 2, 1, 1, 126801, 7438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ、一日の疲れを\n洗い流すために…\n軽～く飲むわよ！", 0, 3, 3, 2, 1, 1, 126801, 7439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうやって\n直に触れると\n肌触りの良さが\nよく分かるわ♪", 0, 2, 0, 3, 1, 1, 126801, 7441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もかわいいわね～\nどう？　今度\nお姉さんの一人飲みに\n付き合わない？", 0, 3, 0, 3, 1, 1, 126801, 7442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りね～…はっ！\n麦しゅわの匂いの\nアロマポットなんて\nあったらよくない？", 0, 4, 0, 3, 1, 1, 126801, 7443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな格好で火に\n当たってると焙られる\nスルメの気分が\nちょっと分かるわ…", 0, 5, 0, 3, 1, 1, 126801, 7444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…うん、\n結構おつまみにも\nむいてそうね～♪", 0, 7, 0, 3, 1, 1, 126801, 7446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("試験に使った参考書、\nたまには読み返して\nおかないとね", 0, 8, 0, 3, 1, 1, 126801, 7447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ♪\nいい手触りね～", 0, 10, 0, 3, 1, 1, 126801, 7449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…はふう～…\nゴロゴロするのって\n最高ね～", 0, 11, 0, 3, 1, 1, 126801, 7450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん…やっぱり\nこの水着…\n大胆、なんじゃ…？", 0, 1, 0, 1, 1, 1, 126901, 7451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海でもお世話って、\nできるのかしら…？\n浮き輪代わりになる、\nとか…？", 0, 2, 0, 1, 1, 1, 126901, 7452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("～♪\nふふ…海に行く\n準備も、楽しい…かも", 0, 3, 0, 1, 1, 1, 126901, 7453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あうぅ…水着で\n歩いてると…お尻…\nすぐ食い込んじゃう…", 0, 4, 0, 1, 1, 1, 126901, 7454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海では、はしゃいだ\nほうがいいのよね…\nわ、わー、い…♪\n…こうかしら？", 0, 5, 0, 1, 1, 1, 126901, 7455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとなら…\n楽しい夏の思い出、\n作れる…気がするの…", 0, 101, 0, 1, 4, 1, 126901, 7456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また来年も…\n再来年も…\nあなたと海へ\n行けますように…", 0, 102, 0, 1, 8, 1, 126901, 7457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着の着方を\n練習してるの…\n後ろ、変じゃない…？", 0, 1, 0, 2, 1, 1, 126901, 7458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行く支度…\n進んでるかしら…？\nお手伝い、する…？", 0, 2, 0, 2, 1, 1, 126901, 7459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひ、日除けの準備は\n万全よ…\nずっと太陽の下に\nいたら…溶けちゃう…", 0, 3, 0, 2, 1, 1, 126901, 7460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぐ練習…\nこ、ここでするのは\n…さすがに変？", 0, 4, 0, 2, 1, 1, 126901, 7461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人混みに入るのは\nまだ不安で…\nでも、あなたといれば\nきっと…大丈夫…", 0, 101, 0, 2, 4, 1, 126901, 7462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたのおかげで\n海の楽しいところを\nたくさん知ったわ…\nありがとう…♪", 0, 102, 0, 2, 8, 1, 126901, 7463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お出かけの日の朝は\n早い、のよね…？\nだから、ずっと\n起きていたわ…", 0, 1, 1, 2, 1, 1, 126901, 7464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今頃ビーチの日差しは\n強いんでしょうね…\nそ、想像しただけで…\nめまいが…", 0, 2, 2, 2, 1, 1, 126901, 7465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビーチの夜といえば\n花火って、聞いたわ…\nバン、って言わない\n花火…ある…？", 0, 3, 3, 2, 1, 1, 126901, 7466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素肌にふわふわが…\n気持ちいい…♪", 0, 2, 0, 3, 1, 1, 126901, 7468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ…\n一緒に海…行く？", 0, 3, 0, 3, 1, 1, 126901, 7469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…♪\n気分まで…\n晴れやかになるわ…", 0, 4, 0, 3, 1, 1, 126901, 7470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑いような…\n寒いような…\n不思議な気持ちに\nなるわ…ね？", 0, 5, 0, 3, 1, 1, 126901, 7471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳いだ後には\nいっぱい食べたほうが\n体によさそう、ね…", 0, 7, 0, 3, 1, 1, 126901, 7473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビーチの日陰で\n読書するのも…\n気持ちよさそう…♪", 0, 8, 0, 3, 1, 1, 126901, 7474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで合ってる…？\n遊び方わからなくて…", 0, 10, 0, 3, 1, 1, 126901, 7476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわ…♪\n海の底にいるみたい…", 0, 11, 0, 3, 1, 1, 126901, 7477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("恥ずかしい格好で\n室内を歩くこの快感\nクセになりそうです…", 0, 1, 0, 1, 1, 1, 127001, 7478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この水着…\nどうしてかポーズを\n決めたくなりますね…", 0, 2, 0, 1, 1, 1, 127001, 7479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海にはどんな生き物が\nいるのでしょう～\n胸が高鳴ります～♪", 0, 3, 0, 1, 1, 1, 127001, 7480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は暑いですね…\nクウカの体が熱いのも\n夏のせい…ぐふふ…♪", 0, 4, 0, 1, 1, 1, 127001, 7481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんと無人島に\n取り残されて…という\n妄想はかなりイイです", 0, 5, 0, 1, 1, 1, 127001, 7482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんの\n欲望に満ちた眼差し…\nクウカ、受け止めます", 0, 101, 0, 1, 4, 1, 127001, 7483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行くのが\n楽しみです…\nドＳさんと…ぐふふ♪", 0, 102, 0, 1, 8, 1, 127001, 7484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「もっと過激な水着を\n見せてみろよ」なんて\nいけませんドＳさん…", 0, 1, 0, 2, 1, 1, 127001, 7485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着のままで\n踊ればいいのですね…\nドＳさんの望みなら！", 0, 2, 0, 2, 1, 1, 127001, 7486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさんの熱い視線を\n感じます…じゅるり…\nもっと見てください…", 0, 3, 0, 2, 1, 1, 127001, 7487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな格好のクウカを\n放っておくなんて…\nさすがですドＳさん！", 0, 4, 0, 2, 1, 1, 127001, 7488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で水着といえば\n何かが起きる予感…！\nドＳさんの新たな攻め\n期待していますね…！", 0, 101, 0, 2, 4, 1, 127001, 7489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("恥ずかしいですけど\n頑張っちゃいました\nドＳさん…こういう\n水着、好きですか？", 0, 102, 0, 2, 8, 1, 127001, 7490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな朝からクウカを\n水着に着替えさせて…\n本当にドＳさんは\n欲望に正直ですね！", 0, 1, 1, 2, 1, 1, 127001, 7491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな昼間から\nドＳさんがヌルヌルの\n液体をクウカに～！\nえっ…日焼け止め？", 0, 2, 2, 2, 1, 1, 127001, 7492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドＳさん…これから\nクウカと夜の海を\n見に行きませんか？\nきっと綺麗ですよ…♪", 0, 3, 3, 2, 1, 1, 127001, 7493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここなら妄想に\n集中できます～♪\nじゅるり～♪", 0, 2, 0, 3, 1, 1, 127001, 7495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうもかわいいと\n妄想に登場させるのも\n気が引けます…", 0, 3, 0, 3, 1, 1, 127001, 7496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカを昂らせる\nこの香り…！\nは！　ドＳさんの罠！", 0, 4, 0, 3, 1, 1, 127001, 7497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体を熱くさせて\n水着を脱がそうと！？\nテクニカルです…！", 0, 5, 0, 3, 1, 1, 127001, 7498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クウカの口の中に\nたくさん…♪\n止まりません…！", 0, 7, 0, 3, 1, 1, 127001, 7500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("読書は心が穏やかに\nなりますね…！\nぐふふ…穏やかに…", 0, 8, 0, 3, 1, 1, 127001, 7501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい乗り心地です…♪\nあっ…普通に楽しんで\nしまいました…", 0, 10, 0, 3, 1, 1, 127001, 7503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…\n妄想に役立ちそうな\n感触です…！", 0, 11, 0, 3, 1, 1, 127001, 7504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("成長した自分に\nあわせて、もっと\nかっこいいポーズを\n研究するッス！", 0, 103, 0, 1, 12, 1, 100501, 7505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからも一緒に\n最高のヒーローを\n目指していくッスよ♪", 0, 103, 0, 2, 12, 1, 100501, 7506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さん、娘の\n水着姿がそんなに\nうれしいの？", 0, 1, 0, 1, 1, 1, 127101, 7507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怖い話を子どもたちに\n聞かせたら泣かれて\nしまいました…\n加減が難しいです…", 0, 2, 0, 1, 1, 1, 127101, 7508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行くと父が\n水着の女性ばかり\n追いかけて困ります…", 0, 3, 0, 1, 1, 1, 127101, 7509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("拾った貝殻で\n新しい占いでも\nはじめてみようかな", 0, 4, 0, 1, 1, 1, 127101, 7510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貝殻を耳に当てると\n波の音が…あっ\nこれはダメです\nよくない声がします", 0, 5, 0, 1, 1, 1, 127101, 7511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この飲み物、スーッと\n体に沁み込んでくる…\nあの人にも\n教えてあげたいです", 0, 101, 0, 1, 4, 1, 127101, 7512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強い日差しも騒がしい\n海も苦手なのに\nあの人となら不思議と\n楽しく思えるんです", 0, 102, 0, 1, 8, 1, 127101, 7513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏限定、水と氷を\n使った特別な占いは\nいかがですか？", 0, 1, 0, 2, 1, 1, 127101, 7514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑い日々にはやはり\n怪談ですね\n厳選フルコースで\nお聞かせします", 0, 2, 0, 2, 1, 1, 127101, 7515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒気がする？　それは\n霊ではなくかき氷の\n食べ過ぎですよ", 0, 3, 0, 2, 1, 1, 127101, 7516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の占い、あなたの\nラッキーパーソンは…\n白い水着の女性です", 0, 4, 0, 2, 1, 1, 127101, 7517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、よければ\n日焼け止めを塗って\nもらえませんか？\n背中は届かなくて…", 0, 101, 0, 2, 4, 1, 127101, 7518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に行きませんか？\n二人きりで静かな\n砂浜を散歩したいです", 0, 102, 0, 2, 8, 1, 127101, 7519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("潮騒だけが響く朝の海\n心が落ち着きます\nこれから一緒に散歩に\n行ってみませんか？", 0, 1, 1, 2, 1, 1, 127101, 7520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不思議です。どうして\n普通のご飯でも、海で\n食べると特別おいしく\n感じるのでしょう…", 0, 2, 2, 2, 1, 1, 127101, 7521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の海に行きませんか\n今なら夜光虫が\n見られるかも\nしれませんよ", 0, 3, 3, 2, 1, 1, 127101, 7522);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は知らぬ間に体力を\n消耗しています\n適度に休息して\nいきましょう", 0, 2, 0, 3, 1, 1, 127101, 7524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このぬいぐるみ…\n大丈夫です\n何も憑いては\nいませんよ", 0, 3, 0, 3, 1, 1, 127101, 7525);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほのかにお線香\nみたいな香り…\nなんだか\n落ち着きます", 0, 4, 0, 3, 1, 1, 127101, 7526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人魂、鬼火\nセントエルモの火…\n炎を見ていると色々と\n連想してしまいます", 0, 5, 0, 3, 1, 1, 127101, 7527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹を壊さぬよう\n食い合わせには\nご注意ください", 0, 7, 0, 3, 1, 1, 127101, 7529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはいい\n怪談集ですね…\nつい読みふけって\nしまいます", 0, 8, 0, 3, 1, 1, 127101, 7530);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、こういうのに\n乗るとなんだか\n子どもに戻った\nみたいですね", 0, 10, 0, 3, 1, 1, 127101, 7532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、これは…\nちょっとメルヘン\n過ぎて恥ずかしい\nですね…", 0, 11, 0, 3, 1, 1, 127101, 7533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本当に素敵なお家…♪\n騎士たちの人柄を\n感じられるようで…\n不思議と落ち着きます", 0, 1, 0, 1, 1, 1, 126501, 7534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("調度品をつい間食…\nという習慣がこちらの\n世界にはないのですね\n…気をつけないと", 0, 2, 0, 1, 1, 1, 126501, 7535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手土産のお菓子は\nどちらに置けば\nよいでしょうか？", 0, 3, 0, 1, 1, 1, 126501, 7536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まるでおとぎ話の中に\n入ってしまったかの\nよう…別世界とは\nよく言ったものです", 0, 4, 0, 1, 1, 1, 126501, 7537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お忍び…ふふっ♪\nときめく響きです\nなんだかお茶目で…\n密やかな印象が", 0, 5, 0, 1, 1, 1, 126501, 7538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわ…\nああ、ついあくびが…\n居心地がよすぎるのも\n困り物ですね…ふふ♪", 0, 101, 0, 1, 4, 1, 126501, 7539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士には不思議な力が\nあるだけでなく\n何者かの加護が\nあるようですね…", 0, 102, 0, 1, 8, 1, 126501, 7540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この『王家の装備』は\n少し気難しいのです\nわたし以外が触れると\nその…ビリビリっと", 0, 1, 0, 2, 1, 1, 126501, 7541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちに新しい\n遊びを教わりました♪\nにーらめっこしましょ\nあっぷっ…ぷ～っ！", 0, 2, 0, 2, 1, 1, 126501, 7542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実は憧れていたのです\n友人の家を訪ねると\nいう経験に…ふふっ", 0, 3, 0, 2, 1, 1, 126501, 7543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぎるどはうす…\nぎるど活動の拠点だと\n管理協会？　の方に\nうかがいました", 0, 4, 0, 2, 1, 1, 126501, 7544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたは運命を\n信じますか？\nわたしは…信じます\nよい運命だけですが♪", 0, 101, 0, 2, 4, 1, 126501, 7545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしわたしが本当に\n天使だったとしたら…\nどうされますか？\n…ふふ、冗談です♪", 0, 102, 0, 2, 8, 1, 126501, 7546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パンケーキの香りで\n目覚める朝は\nとても良いものですよ\nぜひともお試しを♪", 0, 1, 1, 2, 1, 1, 126501, 7547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひと休みの時間ですね\n食事にお昼寝…\nすべきことを行って\n英気を養いましょう", 0, 2, 2, 2, 1, 1, 126501, 7548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ休まれては？\n眠れないようであれば\n寝物語か子守歌でも\nふふ、遠慮は無用です", 0, 3, 3, 2, 1, 1, 126501, 7549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すう………はっ！\n眠ってはいませんよ？\nいくら居心地が良い\nからといって…ふわぁ", 0, 2, 0, 3, 1, 1, 126501, 7551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、あいらしい…♪\nぜひわたしの寝室に\n招待させてください", 0, 3, 0, 3, 1, 1, 126501, 7552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんて、かぐわしい…\nオーブンからただよう\n焼き菓子の香りとは\nまた異なる魅力が…", 0, 4, 0, 3, 1, 1, 126501, 7553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなで暖をとりながら\n互いに語り笑い合う\n…心休まる時間ですね", 0, 5, 0, 3, 1, 1, 126501, 7554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食は心と体に\nゆとりを生みます\n…辛い食べ物の場合？\nそれは、その…", 0, 7, 0, 3, 1, 1, 126501, 7556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらの世界の知識を\n蓄えておかなければ\nテーブルマナーに\nついてのページは…", 0, 8, 0, 3, 1, 1, 126501, 7557);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい色の蛍光ペン\n買ったのよね\nこれで勉強が\n楽しくなるわ～♪", 0, 1, 0, 1, 1, 1, 127201, 7559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学食のランチ、結構\nおいしいのよね～\n今度ペコリーヌに\n教えてやろうかしら？", 0, 2, 0, 1, 1, 1, 127201, 7560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふふ…扉に黒板消し\n仕掛けてるの…あいつ\n引っかかるかしら？", 0, 3, 0, 1, 1, 1, 127201, 7561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部活するなら運動部も\n悪くないかもね～\n夕日に向かって\n突っ走ってやるわ！", 0, 4, 0, 1, 1, 1, 127201, 7562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日窮屈な制服着て\n学生も大変ね～\n…ま、かわいいけど", 0, 5, 0, 1, 1, 1, 127201, 7563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつに貸したノート\n変な落書きとか\nしてなかったよね…？\n…その、相合傘とか…", 0, 101, 0, 1, 4, 1, 127201, 7564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日の家庭科で\n作ったクッキー…\nあいつにどうやって\n渡そうかな…？", 0, 102, 0, 1, 8, 1, 127201, 7565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宿題教えてって？\nしょうがないわね～\nじゃあ一緒に\nやりましょ", 0, 1, 0, 2, 1, 1, 127201, 7566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、明日あたしたち\n日直当番よね？\nめんどい仕事は\nあんたに任せるわ～", 0, 2, 0, 2, 1, 1, 127201, 7567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寮生活は楽しいけど\n就寝時間が早すぎよね\nいきなり消灯されると\nビックリするわ", 0, 3, 0, 2, 1, 1, 127201, 7568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("校則で禁止だけど、\nにけつでほうき通学\nとか青春っぽくない？", 0, 4, 0, 2, 1, 1, 127201, 7569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("制服って好きな人とも\n自然にお揃いになれて\nいいわよね…って別に\nあんたとって訳じゃ…", 0, 101, 0, 2, 4, 1, 127201, 7570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたネクタイ\n曲がってるわよ～？\nほら直したげるから\nこっち向いて？", 0, 102, 0, 2, 8, 1, 127201, 7571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ～！\n今日も元気に登校よ！\n忘れ物ないようにね！", 0, 1, 1, 2, 1, 1, 127201, 7572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午前の授業疲れたわ～\nしっかりお昼を食べて\n午後も頑張るわよ！", 0, 2, 2, 2, 1, 1, 127201, 7573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…学校の怪談\n思い出しちゃった…\n…別に怖くないけど！", 0, 3, 3, 2, 1, 1, 127201, 7574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか～\n…気持ち良すぎて\n制服のまま\n寝ちゃいそうね…", 0, 2, 0, 3, 1, 1, 127201, 7576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいくて癒されるわ\n寮に持ち込んでも\n大丈夫かしら…？", 0, 3, 0, 3, 1, 1, 127201, 7577);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("集中力の高まる香りで\n勉強の効率爆上がりね\n次のテストで\nいい点取るわよ～！", 0, 4, 0, 3, 1, 1, 127201, 7578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう、ちょっと冷えて\n来たわね…\nスカートの下に\nジャージ穿こうかしら", 0, 5, 0, 3, 1, 1, 127201, 7579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐっ…もぐっ…\n食べとかないと教室で\nお腹なっちゃうわ～", 0, 7, 0, 3, 1, 1, 127201, 7581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("図書室で借りた本\n明日返却日なのよね…\n今日中に読むわよ！", 0, 8, 0, 3, 1, 1, 127201, 7582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつに背中を\n預けるのもいい気分だ\nいつかは、全部…", 0, 103, 0, 1, 12, 1, 104301, 7584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("な、なんだよ？\nじっと見るんじゃねぇ\n尻尾が揺れちまうだろ", 0, 103, 0, 2, 12, 1, 104301, 7585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の練習！\nむむむ～…\nそれっ…！", 0, 1, 0, 1, 1, 1, 127301, 7586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そだ！　これ着て\nルー学行こっかな？　\n制服自慢しちゃお♪", 0, 2, 0, 1, 1, 1, 127301, 7587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("赤点回避の魔法とか\nあったら最高じゃね？\n誰かうちに教えて～", 0, 3, 0, 1, 1, 1, 127301, 7588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("制服が一番映える\n場所ってどこだろ？\n教室？　遊園地？", 0, 4, 0, 1, 1, 1, 127301, 7589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ベンキョーつらたん…\n今度キャルっちに\n助けてもらお", 0, 5, 0, 1, 1, 1, 127301, 7590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部活か…\nヒデサイと一緒に\nやったら楽し～かも♪", 0, 101, 0, 1, 4, 1, 127301, 7591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("男子の制服\nもにカワだった…\n今度ヒデサイに\n借りよっかな？", 0, 102, 0, 1, 8, 1, 127301, 7592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょすー、うちの\nさいきょー魔法で\nテンアゲしてあげる～", 0, 1, 0, 2, 1, 1, 127301, 7593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("九九って呪文ぽくね？\nほら、例えばヒチシ…\nヒチシ、なんだっけ？", 0, 2, 0, 2, 1, 1, 127301, 7594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイセンセー\nうちにベンキョー\n教えて！", 0, 3, 0, 2, 1, 1, 127301, 7595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学割マジ助かるー\nヒデサイ、一緒に\nどんどん使ってこー♪", 0, 4, 0, 2, 1, 1, 127301, 7596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度ヒデサイに\nお弁当作ったげる\n屋上で一緒に食べよ♪", 0, 101, 0, 2, 4, 1, 127301, 7597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒデサイのバイブス\n上がる言葉教えてよ\nつらたんな時、うちが\nいっぱい言ったげるよ", 0, 102, 0, 2, 8, 1, 127301, 7598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょすちょす～\n今日も朝から\nバイブス十分♪", 0, 1, 1, 2, 1, 1, 127301, 7599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼どうしよっかな\nたまにはガッツリ\nいっちゃう系？", 0, 2, 2, 2, 1, 1, 127301, 7600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やべ、宿題まだ\nできてないし…\nヒデサイ助けて～", 0, 3, 3, 2, 1, 1, 127301, 7601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("充電ちう～\n…ガッコーのイスも\nこれにして～", 0, 2, 0, 3, 1, 1, 127301, 7603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいし、\n癒されるし、キュン死\nしちゃうじゃん…！", 0, 3, 0, 3, 1, 1, 127301, 7604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リフレッシュの\n魔法発見！\nいい香り～♪", 0, 4, 0, 3, 1, 1, 127301, 7605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽかサイコー♪\n今日はもーずーっと\nここにいたいかも～", 0, 5, 0, 3, 1, 1, 127301, 7606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("超おいし～♪\n学食にあったら\n毎日リピする～", 0, 7, 0, 3, 1, 1, 127301, 7608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nねむみパない…\n続きはまた今度～", 0, 8, 0, 3, 1, 1, 127301, 7609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度は子どもたちも\nサラサリアに連れて\n行ってあげたいわ", 0, 1, 0, 1, 1, 1, 127501, 7611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちから\nお姫さまみたいって\n言われちゃった♪", 0, 2, 0, 1, 1, 1, 127501, 7612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この剣…火を点けたり\nするのに便利なのよ\nコントロールも効くし", 0, 3, 0, 1, 1, 1, 127501, 7613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのサラサリアの\nカラっとした暑さが\nちょっと恋しいわ…", 0, 4, 0, 1, 1, 1, 127501, 7614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("買ってきたお土産、\nお世話になってる\nみんなに配りましょ♪", 0, 5, 0, 1, 1, 1, 127501, 7615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと一緒なら\nどこの国でだって\n暮らしていけそうね♪", 0, 101, 0, 1, 4, 1, 127501, 7616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今の事業を大きくして\nあんたと世界中の国を\n飛び回ったり…なんて\nすてきじゃない？", 0, 102, 0, 1, 8, 1, 127501, 7617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアで食べた\n料理が恋しい…？\nもう…また今度\n作ってあげるわよ", 0, 1, 0, 2, 1, 1, 127501, 7618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度旅行するなら\nどこに行こうかしら？\n希望があれば教えてね", 0, 2, 0, 2, 1, 1, 127501, 7619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアの香辛料、\nランドソルでも\n人気が出そうよね\nいいビジネスの予感！", 0, 3, 0, 2, 1, 1, 127501, 7620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そんなにじっと\n見られるとさすがに\n恥ずかしいってば…", 0, 4, 0, 2, 1, 1, 127501, 7621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お嫁さんは憧れるけど\nお婿さんになって\nもらうのもありよね…\nあんたはどう思う？", 0, 101, 0, 2, 4, 1, 127501, 7622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっぱり、あんたには\nいつもあたしの隣に\n居てほしいな…", 0, 102, 0, 2, 8, 1, 127501, 7623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("陽射しが強くなる前に\n雑多な用事は\n片付けちゃいましょ", 0, 1, 1, 2, 1, 1, 127501, 7624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアで食べた\n料理を再現してみたの\n味見してくれる？", 0, 2, 2, 2, 1, 1, 127501, 7625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑さに負けないように\n睡眠はちゃんと\n取っておかないと", 0, 3, 3, 2, 1, 1, 127501, 7626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちでもあっちでも\n忙しいのは変わらない\nわね…ちょっと休憩～", 0, 2, 0, 3, 1, 1, 127501, 7628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアで見た\nぬいぐるみも\nかわいかったわね", 0, 3, 0, 3, 1, 1, 127501, 7629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お香って地域ごとの\n特色が出るわよね\nこの香りは…\nちょっと神秘的？", 0, 4, 0, 3, 1, 1, 127501, 7630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("砂漠地方も夜は冷える\nのよね。温かいものが\nあると安心するわ…♪", 0, 5, 0, 3, 1, 1, 127501, 7631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ慣れた味って\nどうしてほっと\nするのかしら…", 0, 7, 0, 3, 1, 1, 127501, 7633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今後の取引相手に\nなるかもしれないし\n向こうの文化も\n勉強しておかないと…", 0, 8, 0, 3, 1, 1, 127501, 7634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("犯人はこの中にいる！\n探偵として一度は\n言ってみたいセリフさ", 0, 103, 0, 1, 12, 1, 101401, 7636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くんの情報を\n仕入れておかないと…\n理想の私を、ずっと\n見ていてほしいからね", 0, 103, 0, 2, 12, 1, 101401, 7637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("久々の長旅で\n里心がついちまったね\nしばらくランドソルで\nのんびりしようか", 0, 1, 0, 1, 1, 1, 127601, 7638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまには違う服装\n違う得物を使うのも\n悪くないね", 0, 2, 0, 1, 1, 1, 127601, 7639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアにいた時は\n砂まみれで大丈夫かと\n思ってたけど、今じゃ\n懐かしく感じるよ", 0, 3, 0, 1, 1, 1, 127601, 7640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の絨毯、あれは\n楽だし速いし便利\nだったねえ…土産に\n一枚欲しかったな", 0, 4, 0, 1, 1, 1, 127601, 7641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("砂上での戦いは\nなかなかいい鍛錬に\nなったね…今度は\n修行しに行くとしよう", 0, 5, 0, 1, 1, 1, 127601, 7642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアの人たちも\n気のいい連中だったが\n元気にやってるかねえ", 0, 101, 0, 1, 4, 1, 127601, 7643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅の恥はかき捨てって\nいうけど、悪い旅じゃ\nなかったね。次は\nアイツとどこに行こう", 0, 102, 0, 1, 8, 1, 127601, 7644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好を冷やかしに\n来たのかい？\n生憎、もうすっかり\n慣れちまったよ", 0, 1, 0, 2, 1, 1, 127601, 7645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドの連中に\n土産をわたしに\n行くところなんだ\n付き合っておくれよ", 0, 2, 0, 2, 1, 1, 127601, 7646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("久々に水場で\n釣りがしたいねえ…\nもちろんお前さんも\nくるんだろう？", 0, 3, 0, 2, 1, 1, 127601, 7647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと\nサラサリアの連中から\n便りが来てるよ\nさ、一緒に読もうか", 0, 4, 0, 2, 1, 1, 127601, 7648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近サラサリアの踊り\nを練習してるんだ\nあとで振付けを\n見ておくれよ", 0, 101, 0, 2, 4, 1, 127601, 7649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだいお前さん？\n…なんだか若奥さん\nっぽいって？　まあ、\nそりゃあ、ねえ…", 0, 102, 0, 2, 8, 1, 127601, 7650);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい時間だね\n日が昇りきる前に\nやることをすませ\nとかないと", 0, 1, 1, 2, 1, 1, 127601, 7651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼はどうしようかね\nサラサリア風の\n食事でもつくろうか", 0, 2, 2, 2, 1, 1, 127601, 7652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、早めに寝ようか\n砂漠の夜は冷えるから\n…っと、まだ旅行中の\n気分でいたよ", 0, 3, 3, 2, 1, 1, 127601, 7653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("良い座り心地だ\nサラサリア宮殿の\n応接間を\n思い出すねえ…", 0, 2, 0, 3, 1, 1, 127601, 7655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランプの魔神に\nあげたら喜ぶかねえ？\n次に会う時までに\n見繕ってみようか", 0, 3, 0, 3, 1, 1, 127601, 7656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\nサラサリア土産の\n香木かい？", 0, 4, 0, 3, 1, 1, 127601, 7657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旅先での焚火を\n思い出すよ\nなんだかほっとするね", 0, 5, 0, 3, 1, 1, 127601, 7658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、慣れてる味も\nいいけど、むこうの\n味付けが懐かしく\nなっちまうね", 0, 7, 0, 3, 1, 1, 127601, 7660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\n千夜一夜物語か\nおもしろいもんだねえ", 0, 8, 0, 3, 1, 1, 127601, 7661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("立派なギルドハウス♪\n帰る場所が素敵だと\n冒険に出るのも\n楽しくなりそうです♪", 0, 1, 0, 1, 1, 1, 126001, 7663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除でも…と\n思いましたけど、\nさすがお兄さんのお家\nきれいにしてますね♪", 0, 2, 0, 1, 1, 1, 126001, 7664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしたちもいつか\n立派なギルドハウスが\n持てる冒険者に\nなりたいです…♪", 0, 3, 0, 1, 1, 1, 126001, 7665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたし冒険者ですけど\n家を守ってお兄さんの\n帰りを待つのも\n悪くない…かも？", 0, 4, 0, 1, 1, 1, 126001, 7666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子焼こうかな…♪\nちょっと多めに作って\nお兄さんにも\n食べてもらおうっと♪", 0, 5, 0, 1, 1, 1, 126001, 7667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお家、とっても\n大好きになりました♪\nだからその…もう少し\nいてもいいですか…？", 0, 101, 0, 1, 4, 1, 126001, 7668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんに\n感謝の手紙を書いて\n枕元に隠して\nおこうかな…♪", 0, 102, 0, 1, 8, 1, 126001, 7669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…お兄さん\nお暇なんですか？\nじゃあ一緒に冒険へ\n出かけましょう♪", 0, 1, 0, 2, 1, 1, 126001, 7670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんは苦手な食材\nとかありますか？\nあの、もしよければ\n今から手料理を…♪", 0, 2, 0, 2, 1, 1, 126001, 7671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まったり過ごす\nお家時間もいいですね\n冒険者には羽休めも\n大事ですから♪", 0, 3, 0, 2, 1, 1, 126001, 7672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつでもお兄さんを\n守れるように\nこの姿でいることに\n慣れておきますね…！", 0, 4, 0, 2, 1, 1, 126001, 7673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さん眠そうです…\nちょっとお昼寝\nしちゃいましょうか♪\nはい、膝枕…♪", 0, 101, 0, 2, 4, 1, 126001, 7674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さん怪我を…！？\nわたしが治療を…\nふー…ふー…", 0, 102, 0, 2, 8, 1, 126001, 7675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\n朝、元気に挨拶すれば\n幸せな一日が過ごせる\nそうですよ♪", 0, 1, 1, 2, 1, 1, 126001, 7676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんの時間です\n…手がふさがってる？\nわかりました、じゃあ\nあ～んしますね♪", 0, 2, 2, 2, 1, 1, 126001, 7677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…眠くなって\nきちゃいました…\nお兄さん…お泊りして\nいいですか…？", 0, 3, 3, 2, 1, 1, 126001, 7678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふにゃ～～…♪\nこんな姿、他の人には\n見せられません…♪\nもふもふ～～…♪", 0, 2, 0, 3, 1, 1, 126001, 7680);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんこういうの\n好きなのかな～…\nふふっ、わたしも♪\nぎゅ～～～っ♪", 0, 3, 0, 3, 1, 1, 126001, 7681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アロマの癒し効果…\n上手くアレンジして\nみなさんの治療に\n活かせないかな～？", 0, 4, 0, 3, 1, 1, 126001, 7682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("は～気持ちいい～♪\n身体が暖まると\n心もぽかぽかです♪", 0, 5, 0, 3, 1, 1, 126001, 7683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ、おいしい♪\nプレシアちゃんなら\n無限にぱくぱく～って\nしちゃいそうです…♪", 0, 7, 0, 3, 1, 1, 126001, 7685);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本はわたしを\n知らない世界に\n連れていってくれる…\nまるでお兄さんです♪", 0, 8, 0, 3, 1, 1, 126001, 7686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("話題の新刊…\nあの人も読んでるかな\n今度会う時、感想\n聞いてみたいな…♪", 0, 103, 0, 1, 12, 1, 103801, 7688);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うにゃっ…あ、熱を\n測ってくれたんですか\nありがとうございます\nバッチリ元気ですよ♪", 0, 103, 0, 2, 12, 1, 103801, 7689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄の、けはい…\nん、みつけた\nぎゅ", 0, 1, 0, 1, 1, 1, 126101, 7690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きょろきょろ\nここも\nぱとろる、するよ", 0, 2, 0, 1, 1, 1, 126101, 7691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おうち\nにぎやか\nさみしく、ない", 0, 3, 0, 1, 1, 1, 126101, 7692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きょだい、おにぎり\nきょだい、肉まん\nきょだい…お兄？", 0, 4, 0, 1, 1, 1, 126101, 7693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はっぴーちゃん\nどこ？\nお兄、たべた？", 0, 5, 0, 1, 1, 1, 126101, 7694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…この、へや\nお兄の、におい\nすんでる\nすめる？", 0, 101, 0, 1, 4, 1, 126101, 7695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おそうじ、にがて\nでも\nれんしゅう\nきゅっきゅ", 0, 102, 0, 1, 8, 1, 126101, 7696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みみ、さわり、たい？\nんー…だめ…\nむずむず\nなので", 0, 1, 0, 2, 1, 1, 126101, 7697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くろぷれしあ\nかっこいい？\nん…あざます", 0, 2, 0, 2, 1, 1, 126101, 7698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄の、おうち\nきょうみ、ましまし\nたんけん\nするね", 0, 3, 0, 2, 1, 1, 126101, 7699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なでなで、される…と\nねむ…く…\nぶぅ…ぶぅ…ぶぅ…", 0, 4, 0, 2, 1, 1, 126101, 7700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かみ、りぼん\nおてつだい\nよろ\nです", 0, 101, 0, 2, 4, 1, 126101, 7701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ\nすむ\nね？\nまいにち、いっしょ", 0, 102, 0, 2, 8, 1, 126101, 7702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐっもにん\nあさごはん\nあさごはん", 0, 1, 1, 2, 1, 1, 126101, 7703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄\nおつかれ？\nれっつ、まいぺーす", 0, 2, 2, 2, 1, 1, 126101, 7704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひとりで、ねれる\nでも\nひとりじゃ、なくても\nねれる、よ…？", 0, 3, 3, 2, 1, 1, 126101, 7705);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか\nパパの、おなか\nみたい", 0, 2, 0, 3, 1, 1, 126101, 7707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんにちは\nぷれしあ、です\nおともだち、なろ？", 0, 3, 0, 3, 1, 1, 126101, 7708);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい、におい\nでも、お兄\nもっと、いい、におい", 0, 4, 0, 3, 1, 1, 126101, 7709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とりま\nお肉、やこ", 0, 5, 0, 3, 1, 1, 126101, 7710);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nむげん肉まん、も\nきぼう", 0, 7, 0, 3, 1, 1, 126101, 7712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぜんぶ、よんだ\nもっと、ぶあついほん\nでも、いーよ？", 0, 8, 0, 3, 1, 1, 126101, 7713);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幸せなクリスマスを\n過ごすため\nギルドハウスを\nきれいにしなくちゃ♪", 0, 1, 0, 1, 1, 1, 127901, 7715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ♪\n彼へのプレゼント…\n枕元にそっと\nおいておきましょう☆", 0, 2, 0, 1, 1, 1, 127901, 7716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスといえば\n七面鳥の丸焼き…☆\nよだれを拭いて\nいざ準備です♪", 0, 3, 0, 1, 1, 1, 127901, 7717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼に用意した\nプレゼント…\n大きすぎて\nくつ下に入りません…", 0, 4, 0, 1, 1, 1, 127901, 7718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントは\n貰う方も、贈る方も\nどちらも幸せを\n感じますね…☆", 0, 5, 0, 1, 1, 1, 127901, 7719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜景が見える\nレストランであの人と\nクリスマスデート…\n憧れちゃいますね☆", 0, 101, 0, 1, 4, 1, 127901, 7720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレゼントはわたし…\n恥ずかしいですけど\nこの贈り物、彼に\n喜んでほしいです…☆", 0, 102, 0, 1, 8, 1, 127901, 7721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オーナメントを\nたくさん用意したので\n二人でツリーに\n飾りつけましょう☆", 0, 1, 0, 2, 1, 1, 127901, 7722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはは、お腹\n空いちゃいました？\nパーティーまで\n我慢してください♪", 0, 2, 0, 2, 1, 1, 127901, 7723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジングルベ～ル♪\nあなたも一緒に\nクリスマスソング\n歌っちゃいましょう♪", 0, 3, 0, 2, 1, 1, 127901, 7724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サプライズプレゼント\nの用意をして…って\nあなた！？　い、今の\n聞いてませんよね…？", 0, 4, 0, 2, 1, 1, 127901, 7725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの夜は\nパーティーしましょう\nできれば…その…\n二人っきりで…☆", 0, 101, 0, 2, 4, 1, 127901, 7726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと過ごした\n最高のクリスマス…\nずっとずっと心の奥に\nしまっておきますね", 0, 102, 0, 2, 8, 1, 127901, 7727);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n皆の願いが叶うような\n素敵な一日に\nしましょうね☆", 0, 1, 1, 2, 1, 1, 127901, 7728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですね！\nディナーの買い出しが\n済んだら、少しお昼寝\nしちゃいましょうか☆", 0, 2, 2, 2, 1, 1, 127901, 7729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ就寝の\n時間ですね～\n枕元にくつ下の準備を\nお忘れなく～☆", 0, 3, 3, 2, 1, 1, 127901, 7730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふ～気持ちいい…☆\nお家でまったり過ごす\nクリスマスも\nいいですよね…♪", 0, 2, 0, 3, 1, 1, 127901, 7732);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいですね～♪\nサンタさんからの\n贈り物でしょうか～？", 0, 3, 0, 3, 1, 1, 127901, 7733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すう～…はあ～…\nすごく素敵な香り…\n炊き立てのご飯と\nいい勝負です…♪", 0, 4, 0, 3, 1, 1, 127901, 7734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かいですけど…\nあの日の山小屋を\n思い出して\n恥ずかしいですね…☆", 0, 5, 0, 3, 1, 1, 127901, 7735);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むしゃむしゃもぐもぐ\n止まりませんよ\nクリスマスですから\nむしゃむしゃもぐもぐ", 0, 7, 0, 3, 1, 1, 127901, 7737);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("物語に出てくる\nサンタさんみたいに\nわたしも幸せを\n運びたいです…☆", 0, 8, 0, 3, 1, 1, 127901, 7738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ！\nこ…これは素敵な\nサプライズプレゼント\nですね…☆", 0, 14, 0, 3, 1, 1, 127901, 7740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これを着ればわたしも\n立派なサンタさんに\nなれますかね…？", 0, 15, 0, 3, 1, 1, 127901, 7741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが今のあたしの\n居場所ってやつです\nふふっ、なかなか\n悪くねー気分ですよ", 0, 103, 0, 1, 12, 1, 106601, 7742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからはボス代行\nとしてブイブイ\nいわせてやるです\nついてくるですよ！", 0, 103, 0, 2, 12, 1, 106601, 7743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("陛下～♪\n貴女のクレジッタが\nおめかしして\nはせ参じましたわ～♪", 0, 1, 0, 1, 1, 1, 128001, 7744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パーティーとは景気の\n良さを見せつける場…\n倹約などは\nもっての外でしてよ！", 0, 2, 0, 1, 1, 1, 128001, 7745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この天井の高さなら\n搬入できそうですわね\n陛下用の特注ケーキ♪", 0, 3, 0, 1, 1, 1, 128001, 7746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ぶぇっくしゅ！\nふう…少し背中を\n開けすぎたかしら…？", 0, 4, 0, 1, 1, 1, 128001, 7747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは秘書の目も\n届きませんから\nチクりメモの心配も\nありませんのよね～♪", 0, 5, 0, 1, 1, 1, 128001, 7748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いくらでも二度見して\nよろしくてよ？\n本当にわたくしだと\n心から納得できるまで", 0, 101, 0, 1, 4, 1, 128001, 7749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("袖の下以外の贈り物も\nなかなかどうして…\n悪くないものですのね", 0, 102, 0, 1, 8, 1, 128001, 7750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こう見えてダンスの\nたしなみはありますの\nお相手してあげても\nよろしくってよ", 0, 1, 0, 2, 1, 1, 128001, 7751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ドレスはもちろん\n特注品ですわ♪\nもしや貸衣装だと\n思いまして？", 0, 2, 0, 2, 1, 1, 128001, 7752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バッグの中身？\n仕事に必要なものと…\n心を潤わせるための\n宝石がいくつか♪", 0, 3, 0, 2, 1, 1, 128001, 7753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やる気というものは\n仕事に必要な条件です\nいわばドレスコードの\nようなものですわね", 0, 4, 0, 2, 1, 1, 128001, 7754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("全ての仕事は自分の\n血となり肉となり\nお金にもなるもの\nなのです。経験談です", 0, 101, 0, 2, 4, 1, 128001, 7755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年の教訓を活かして\n来年は更に素晴らしい\nクリスマスにして\n差し上げますわ！", 0, 102, 0, 2, 8, 1, 128001, 7756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日という稼ぎ時の\nはじまりですわよ！", 0, 1, 1, 2, 1, 1, 128001, 7757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安くて早くておいしい\nそれがランチに必須の\n栄養素ですわ！", 0, 2, 2, 2, 1, 1, 128001, 7758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宵越しの仕事は\n安眠の敵！\n熟睡したいのであれば\n今が勝負時ですわよ！", 0, 3, 3, 2, 1, 1, 128001, 7759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはこうして\n休息を取ることも…\n…はっ！？\nドレスにシワが～っ！", 0, 2, 0, 3, 1, 1, 128001, 7761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…わたくしの勘が\n言っていますわ\nこの愛らしさ！\n爆売れ確・定！", 0, 3, 0, 3, 1, 1, 128001, 7762);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りですわね…\nお金の匂いには\n敵いませんけれども♪", 0, 4, 0, 3, 1, 1, 128001, 7763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("……ハッ！？\n完全にボーッとして\nしまいましたわ…！\nぬくもり…恐ろしい！", 0, 5, 0, 3, 1, 1, 128001, 7764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("考えませんわ…\n考えませんわよ！\nカロリーのことはっ！", 0, 7, 0, 3, 1, 1, 128001, 7766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビジネス本以外の本を\n読むのも、たまには\n悪くありませんわね…", 0, 8, 0, 3, 1, 1, 128001, 7767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よくできていますわね\nこの絵本！\n子ども向けだと甘く\n見ていましたわ…！", 0, 14, 0, 3, 1, 1, 128001, 7769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この視界の狭さ…\n思い出しますわね\nティッシュ配りの\nアルバイト時代を…", 0, 15, 0, 3, 1, 1, 128001, 7770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふふ…こっそり\nスイーツを食べる\nリノちゃん見～っけ♪", 0, 1, 0, 1, 1, 1, 128101, 7771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんの抜き打ち\nお部屋チェック～♪\n…ケーキの食べこぼし\nこれはリノちゃんだね", 0, 2, 0, 1, 1, 1, 128101, 7772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装は目立つから\nどこにいても弟くんに\n気付いてもらえるね！", 0, 3, 0, 1, 1, 1, 128101, 7773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くん、協力して！\nリノちゃんにお勉強\nしなさいって圧を\nかけるんだよっ…♪", 0, 4, 0, 1, 1, 1, 128101, 7774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絆の力を感じるよ\nこれならもっと万全な\n弟くんのお世話が\nできそうだねっ！", 0, 5, 0, 1, 1, 1, 128101, 7775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんもたまには\nリノちゃんみたいに\n甘えてみようかな…", 0, 101, 0, 1, 4, 1, 128101, 7776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんとリノちゃん\nどっちも大切な\n私のきょうだいだよ", 0, 102, 0, 1, 8, 1, 128101, 7777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("分かってるよ♪\nお姉ちゃんの膝枕を\nご所望だねっ？　え？\n違う？　違わないよ？", 0, 1, 0, 2, 1, 1, 128101, 7778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リノちゃんがね\nお姉ちゃんチョップを\n防ぐ妹白刃取りを\n訓練してるんだよね", 0, 2, 0, 2, 1, 1, 128101, 7779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん頭突きは\n封印しないとね…\nだって、今使うと\n頭飾りで威力が…ね", 0, 3, 0, 2, 1, 1, 128101, 7780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ♪\n目をつぶってても\n弟くんは見えてるよ\n…そこでしょ？", 0, 4, 0, 2, 1, 1, 128101, 7781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんも\nリノちゃんみたいに\nかわいさいっぱいに\n振舞っちゃうぞ♪", 0, 101, 0, 2, 4, 1, 128101, 7782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんっ♪\nいつもお姉ちゃんの\n声が届く範囲にいてね\n…絶対だよ", 0, 102, 0, 2, 8, 1, 128101, 7783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう、弟くん！\nリノちゃんが起こして\nくれたんだね♪\n…先を越されちゃった", 0, 1, 1, 2, 1, 1, 128101, 7784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんランチの\n時間だぞ♪\nさ、食べさせてあげる\nお口を開けて…♪", 0, 2, 2, 2, 1, 1, 128101, 7785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみの時間だよ\n…弟くんは真ん中ね\n左右には私たち姉妹が\nいるから安心だよ♪", 0, 3, 3, 2, 1, 1, 128101, 7786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんは全力で\nリラックスしてても\n弟くんの声一つで\nすぐにでも動けるよ♪", 0, 2, 0, 3, 1, 1, 128101, 7788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リノちゃんこういうの\n好きそうだよね\n今度プレゼントして\nみようかな？", 0, 3, 0, 3, 1, 1, 128101, 7789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂いがするね～\nあれ？\nリノちゃんのケーキの\n甘い匂いも混ざってる", 0, 4, 0, 3, 1, 1, 128101, 7790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんの\n弟くんへの愛も\n熱く燃えあがるね…！", 0, 5, 0, 3, 1, 1, 128101, 7791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさん食べて\n栄養を補給して\nお姉ちゃん力に\n全て変換するよっ！", 0, 7, 0, 3, 1, 1, 128101, 7793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ことわざ辞典…\nリノちゃんにこれを\n読ませようかな", 0, 8, 0, 3, 1, 1, 128101, 7794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろ～り、そろり…\nお姉ちゃんが居ぬ間に\nスイーツを～…♪", 0, 1, 0, 1, 1, 1, 128201, 7797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか\nお姉ちゃんに似合う服\n作ってみたいですね", 0, 2, 0, 1, 1, 1, 128201, 7798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいたっ！？\nひらひらしたとこ\n踏んづけちゃいました", 0, 3, 0, 1, 1, 1, 128201, 7799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんと\nお兄ちゃんの二人から\n勉強しろって圧力が～", 0, 4, 0, 1, 1, 1, 128201, 7800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の中にも秘めた力が\n眠っているはず…\nそう、妹パワーが", 0, 5, 0, 1, 1, 1, 128201, 7801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私もお兄ちゃんを\n甘やかしてみたいです\n…お姉ちゃんみたいに", 0, 101, 0, 1, 4, 1, 128201, 7802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんの部屋を\nこっそり拝見～♪\nはっ！？　これは\nお姉ちゃんの視線…！", 0, 102, 0, 1, 8, 1, 128201, 7803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん頭突きは\n大地を揺らす威力です\n私とお兄ちゃんは\n挨拶感覚で喰らいます", 0, 1, 0, 2, 1, 1, 128201, 7804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんチョップは\n雲を裂く切れ味です\n早く妹白刃取りを\n完成させないと…", 0, 2, 0, 2, 1, 1, 128201, 7805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんみたいに\n大人っぽく着こなす\nには一体どうしたら…", 0, 3, 0, 2, 1, 1, 128201, 7806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弓のデザインも\nかわいいんですよっ♪\n常に持ち歩きたいです\nけど…危ないですよね", 0, 4, 0, 2, 1, 1, 128201, 7807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きれいな服を着てると\nお姫さま気分に\nなれますね…あとは\n王子さまがいれば…♪", 0, 101, 0, 2, 4, 1, 128201, 7808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんっ！\n私は褒められて伸びる\nタイプなのでもっと\nナデナデしてください", 0, 102, 0, 2, 8, 1, 128201, 7809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妹モーニングコール♪\nお姉ちゃんより先に\n起こしに来れました！", 0, 1, 1, 2, 1, 1, 128201, 7810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああっ、お姉ちゃん！\nお兄ちゃんにアーン\nするなんてずるいです\n私もしたいですっ！", 0, 2, 2, 2, 1, 1, 128201, 7811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみの時間ですね\nえへへ、きょうだいで\n並んで寝るのって\n楽しいですよね！", 0, 3, 3, 2, 1, 1, 128201, 7812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スイーツを食べた後は\nお腹を休めましょう～\n平気平気…ちゃぁんと\n運動もしますからぁ…", 0, 2, 0, 3, 1, 1, 128201, 7814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんも\nこういうかわいいもの\n好きなんですかね", 0, 3, 0, 3, 1, 1, 128201, 7815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…\nなんの匂いでしょうか\n新しいスイーツ？", 0, 4, 0, 3, 1, 1, 128201, 7816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きょうだい３人\n肩を寄せて暖まるとか\nよくないですかっ？", 0, 5, 0, 3, 1, 1, 128201, 7817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつも元気な妹で\nいるためには\nよく食べるのが大事！", 0, 7, 0, 3, 1, 1, 128201, 7819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんか姉に関する本が\nちらほらと混ざって…\nこれお姉ちゃんの\n仕業ですね！？", 0, 8, 0, 3, 1, 1, 128201, 7820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんふんふ～ん\nお正月で世間は\n浮かれてるですねえ\nま、いいですけど♪", 0, 1, 0, 1, 1, 1, 128301, 7823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("は～、お正月は\nだらだらできて\n最高ですね\n…いつも通りですけど", 0, 2, 0, 1, 1, 1, 128301, 7824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ビッグな幹部は\nビッグなお年玉が\nもらえるはずです\n楽しみですね", 0, 3, 0, 1, 1, 1, 128301, 7825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度ドラちゃんに\nお年玉を持っていって\nやりたいですね", 0, 4, 0, 1, 1, 1, 128301, 7826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえばアユアユと\n約束してたですよ…\nそろそろ出かける\nですかね", 0, 5, 0, 1, 1, 1, 128301, 7827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お年玉がもらえたら\n何に使うか…\n今のうちに\n考えとくです", 0, 101, 0, 1, 4, 1, 128301, 7828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年神の報酬の駄菓子が\nたまってきたですね…\nガキどもにでも\n配っちまうですよ", 0, 102, 0, 1, 8, 1, 128301, 7829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしのレアな\n晴れ着姿、今のうちに\nしっかり目に焼き付け\nとくがいいですよ", 0, 1, 0, 2, 1, 1, 128301, 7830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんは今日も\nヒマそうですねぇ…\nしょうがないから\nかまってやるですよ", 0, 2, 0, 2, 1, 1, 128301, 7831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえばカヤぴぃ\n見なかったですか？\n喧嘩屋初売りセール\nとか言ってたですけど", 0, 3, 0, 2, 1, 1, 128301, 7832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月ならではの\n大きなシノギ…\nなにかないですかね？", 0, 4, 0, 2, 1, 1, 128301, 7833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいとこに来たですよ\nさっき走ったら帯が\n曲がっちゃったです\n直すの手伝うです！", 0, 101, 0, 2, 4, 1, 128301, 7834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年神の仕事ですか？\nこれからいくとこです\nお兄さんも一緒に\n来やがるですよ！", 0, 102, 0, 2, 8, 1, 128301, 7835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁあ…\nどうしたですか？\nお正月に早起きなんて\n無粋ってヤツですよ…", 0, 1, 1, 2, 1, 1, 128301, 7836);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小腹が減ったですね\n一緒におせちでも\nつつきにいくですよ！", 0, 2, 2, 2, 1, 1, 128301, 7837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜はあたしの時間\nと言いたいとこですが\n初夢のために早く\n寝とくですかね…", 0, 3, 3, 2, 1, 1, 128301, 7838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月は食っちゃ寝\nするのが仕事…\nって聞いたこと\nあるですよ", 0, 2, 0, 3, 1, 1, 128301, 7840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ、晴れ着の\nあたしの次くらいには\nかわいいですね", 0, 3, 0, 3, 1, 1, 128301, 7841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんかいい匂い…？\nよく知らんですけど\n晴れ着からも同じ\n匂いがしてるですね…", 0, 4, 0, 3, 1, 1, 128301, 7842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふ～あったまるです…\nお正月の唯一の弱点は\n寒いことですからね…", 0, 5, 0, 3, 1, 1, 128301, 7843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…正月太り？\nあたしには関係ない\n言葉ですね", 0, 7, 0, 3, 1, 1, 128301, 7845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったあった…\nトーゴクには\nドラゴンの神宮も\nあるんですね", 0, 8, 0, 3, 1, 1, 128301, 7846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月のトラブルも\nハツネちゃんが\nめでたく解決\nしてみせるのだ～！", 0, 1, 0, 1, 1, 1, 128401, 7848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、新年会に\nサプライズ大作戦を\nしかけちゃおう！", 0, 2, 0, 1, 1, 1, 128401, 7849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イノリちゃんも\nカスミンも振袖姿が\nかわいかったな～", 0, 3, 0, 1, 1, 1, 128401, 7850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリンに\nお年玉あげたいし\n彼にバイトを紹介\nしてもらおうかな？", 0, 4, 0, 1, 1, 1, 128401, 7851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度はどんな凧を\n飛ばそうかな？\nみんなが驚くような\n凧がいいよね～", 0, 5, 0, 1, 1, 1, 128401, 7852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひらめいた！\n彼への年賀状は\nきらーんっ☆って\n感じにしよう！", 0, 101, 0, 1, 4, 1, 128401, 7853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("来年も彼の隣で\n初日の出が\n見られるといいな～", 0, 102, 0, 1, 8, 1, 128401, 7854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はキミが\nギルドハウスに来る\n予知夢を見たんだよ～\nふふ、正夢になったね", 0, 1, 0, 2, 1, 1, 128401, 7855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この振袖どうかな？\nすっごくかわいいよね\nえへへ、ありがとう～", 0, 2, 0, 2, 1, 1, 128401, 7856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハツネちゃんおみくじ\n開始！　きらーんっ☆\nキミは大吉なのだ～\nどう元気出たかな？", 0, 3, 0, 2, 1, 1, 128401, 7857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度エルフの森にある\n薬草を使って七草粥を\n作ろうと思うんだ～\nぜひ食べてほしいな♪", 0, 4, 0, 2, 1, 1, 128401, 7858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月っぽい遊びを\n色々と用意したのだ～\nたまにはギルドハウス\nでゆっくり過ごそうよ", 0, 101, 0, 2, 4, 1, 128401, 7859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしかして眠たいの？\n…じゃあ、また膝枕\nしてあげてもいいよ？", 0, 102, 0, 2, 8, 1, 128401, 7860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい寝たから\n元気いっぱいだよ～\n今日もがんばろう！", 0, 1, 1, 2, 1, 1, 128401, 7861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼だね～\nおせちがあるから\nキミも食べるでしょ？", 0, 2, 2, 2, 1, 1, 128401, 7862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝る時間だね\n今日はどんな夢を\n見られるかな～", 0, 3, 3, 2, 1, 1, 128401, 7863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい座り心地～\n寝正月で過ごすのも\n最高なのだ～", 0, 2, 0, 3, 1, 1, 128401, 7865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいな～\n癒されてぐっすり\n眠れそうだよ～", 0, 3, 0, 3, 1, 1, 128401, 7866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～\nリラックスすると\n眠たくなっちゃうよ…", 0, 4, 0, 3, 1, 1, 128401, 7867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカいい気持ち～\n初日の出の温もりを\n思い出しちゃうな～♪", 0, 5, 0, 3, 1, 1, 128401, 7868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ、おいし～\nでもいっぱい食べたら\n眠くなっちゃった…", 0, 7, 0, 3, 1, 1, 128401, 7870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ\nお正月料理も\n色々あるんだね～\n今度作ってみようかな", 0, 8, 0, 3, 1, 1, 128401, 7871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近カレを見てたら\n何故かおいしそうに\n思えてくるんだよな…", 0, 103, 0, 1, 12, 1, 106501, 7873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手握っててくれるか？\nじゃないとオレ…\n力が抑えきれない…", 0, 103, 0, 2, 12, 1, 106501, 7874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つかの間の平和を享受\nしながらぬくぬくと\n読書に耽る…\nふふ、最高だね", 0, 1, 0, 1, 1, 1, 128501, 7875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月飾りなんて\n置いたらはしゃいでる\nように見えるかな…？", 0, 2, 0, 1, 1, 1, 128501, 7876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ま、まずい…\n一人遊びしすぎて\nお正月遊びをほぼ\n極めつつある…", 0, 3, 0, 1, 1, 1, 128501, 7877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミステリーは\n時と場所を選ばない\nつまり…新年でも\n探偵は休まないよ！", 0, 4, 0, 1, 1, 1, 128501, 7878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お世話になった人に\n年賀状でも書こうかな\n助手くん、喜んで\nくれるかな…えへへっ", 0, 5, 0, 1, 1, 1, 128501, 7879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絵馬に願い事を書こう\n助手くんと一緒に\nいられますように…♪\n…は、恥ずかしいな", 0, 101, 0, 1, 4, 1, 128501, 7880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くんはもっと\n派手な着物のほうが\n好みだったかな…？\nき、気になる…", 0, 102, 0, 1, 8, 1, 128501, 7881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やあ。助手くんも\nお正月休みを\n持て余してるのかい？\nふふ、似た者同士だね", 0, 1, 0, 2, 1, 1, 128501, 7882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くん助手くん！\n凧あげしにいこう！\n…そ、捜査の一環で", 0, 2, 0, 2, 1, 1, 128501, 7883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物は転びそうで\n怖いんだよなあ…\nお、押さないでね？\nフリじゃないよ！？", 0, 3, 0, 2, 1, 1, 128501, 7884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひ、人目を憚る\n本を読むなら\nみんなが帰省中の今！\nはっ！　助手くん！？", 0, 4, 0, 2, 1, 1, 128501, 7885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね、ねえ…助手くん…\n一緒に初詣いかない？\nあ、いや！　深い\n意味はないんだけど！", 0, 101, 0, 2, 4, 1, 128501, 7886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはは…助手くんと\n一緒だと家でごろごろ\nしてるだけでも\n楽しいや…♪", 0, 102, 0, 2, 8, 1, 128501, 7887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～…\nお正月休みのおかげで\n昼夜逆転中だよ…", 0, 1, 1, 2, 1, 1, 128501, 7888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月も依頼が\nひっきりなしだね\nさあ、街へ出よう！\nもちろん君も一緒にね", 0, 2, 2, 2, 1, 1, 128501, 7889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("も、もっと\n近くにきてもいいよ？\n冬の夜は…寒いからね", 0, 3, 3, 2, 1, 1, 128501, 7890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ううぅ～…！\nこのままじゃ\n寝正月だぁ…！", 0, 2, 0, 3, 1, 1, 128501, 7892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなが帰省中でも\nこれがあれば\n寂しくない…かな", 0, 3, 0, 3, 1, 1, 128501, 7893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…♪\nお正月休みの\nリフレッシュに\nちょうどいいや♪", 0, 4, 0, 3, 1, 1, 128501, 7894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…あったまるな\n冬は寒いから\n助かるよ…", 0, 5, 0, 3, 1, 1, 128501, 7895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、おいしい♪\n読書のお供に\nちょうどいい", 0, 7, 0, 3, 1, 1, 128501, 7897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時間に余裕があると\n読書が進むよ\nいざ、本棚読破だ♪", 0, 8, 0, 3, 1, 1, 128501, 7898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この新しい力…\nさらに使いこなせる\nようになるには…", 0, 1, 0, 1, 1, 1, 128801, 7900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私に眠る属性の力…\n風の力以外には\nどんな力があるのかな", 0, 2, 0, 1, 1, 1, 128801, 7901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今の私なら\nどこまでいけるのか…\nやれるだけ\nやってみよう", 0, 3, 0, 1, 1, 1, 128801, 7902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風の力の制御…\n段々とコツが\n掴めてきたな", 0, 4, 0, 1, 1, 1, 128801, 7903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風の力か…\n応用の幅は広そうだ\n何ができそうか\n色々試してみよう", 0, 5, 0, 1, 1, 1, 128801, 7904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度、私とキミで\n料理対決でもする？\n簡単には負けないよ", 0, 101, 0, 1, 4, 1, 128801, 7905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この胸に溢れる\n温かな気持ちは…\nきっと彼への…", 0, 102, 0, 1, 8, 1, 128801, 7906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一段と剣技が\n冴えてきたような…\nいや…油断禁物だ", 0, 1, 0, 2, 1, 1, 128801, 7907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かっこいいって？\nありがとう…そんなに\n真っすぐ褒められると\n照れてしまうな…", 0, 2, 0, 2, 1, 1, 128801, 7908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どれほど厚い壁が\n立ち塞がろうと\n打ち破ってみせる", 0, 3, 0, 2, 1, 1, 128801, 7909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手が空いてるなら\n剣の稽古に少し\n付き合ってくれるかな", 0, 4, 0, 2, 1, 1, 128801, 7910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("試練を乗り越えて…\n私の中にあるものが\nはっきりと分かったよ", 0, 101, 0, 2, 4, 1, 128801, 7911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キミから流れてくる\n力の温かさ…これが\n私たちの絆なんだ", 0, 102, 0, 2, 8, 1, 128801, 7912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝だよ、そろそろ\n起きる時間だ\nそれとも私に起こして\nほしいのかな？", 0, 1, 1, 2, 1, 1, 128801, 7913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食は私が作るよ\nリクエストはある？\nできる範囲で応えるよ", 0, 2, 2, 2, 1, 1, 128801, 7914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみ。また明日も\n一緒に冒険しよう\n約束だよ？", 0, 3, 3, 2, 1, 1, 128801, 7915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休める時は休む…\n戦い続けるには\n必要なことだからね", 0, 2, 0, 3, 1, 1, 128801, 7917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心の安らぎの大切さ…\nそれを知れたのは\nキミたちのおかげだね", 0, 3, 0, 3, 1, 1, 128801, 7918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちが落ち着くな…\nこの香り、風の力で\n纏えたりしないかな", 0, 4, 0, 3, 1, 1, 128801, 7919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖まった空気の流れ…\n以前より風の変化に\n気づくようになったな", 0, 5, 0, 3, 1, 1, 128801, 7920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この味付け…\n今度試してみようか\n味見は任せたからね", 0, 7, 0, 3, 1, 1, 128801, 7922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心技体、すべてを\n鍛えるには座学も\n必要だからね", 0, 8, 0, 3, 1, 1, 128801, 7923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("瞑想するのに\nいいところはあるかな\n集中できて…お昼寝は\n我慢できるところ", 0, 1, 0, 1, 1, 1, 128901, 7925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにはあったかい\n空気が流れてるなぁ…\nみんなが受け入れて\nくれるおかげだね", 0, 2, 0, 1, 1, 1, 128901, 7926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まるで心の中に\n光が満ちてるみたい…\nこの気持ち、みんなに\nおすそ分けしたいな♪", 0, 3, 0, 1, 1, 1, 128901, 7927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装は属性の力を\n反映しやすいんだよね\nキラキラしてるのも\n納得だよ", 0, 4, 0, 1, 1, 1, 128901, 7928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エルフの里のみなさん\n元気かなぁ…\nまた会いに行きたいな", 0, 5, 0, 1, 1, 1, 128901, 7929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ変身できてる…\nわたしと騎士クンの\n修行の成果\n出てるなぁ…ふふっ♪", 0, 101, 0, 1, 4, 1, 128901, 7930);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服を脱いだら\nどうなるのかな…\nた、試す勇気は\nないけど…", 0, 102, 0, 1, 8, 1, 128901, 7931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…あ、騎士クン\nちょうど瞑想してたの\n一緒に…する？", 0, 1, 0, 2, 1, 1, 128901, 7932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不思議だけど\nいつの間にか\n出たり消えたりするの\n…背中の輪っか！", 0, 2, 0, 2, 1, 1, 128901, 7933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服って肌触りが\nとってもいいんだよ\nさ、触ってみる？\nスベスベだよ？", 0, 3, 0, 2, 1, 1, 128901, 7934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アストラルの力…\nすごく持続できてるね\n修行の成果が出てるよ", 0, 4, 0, 2, 1, 1, 128901, 7935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この力があれば\n暗いところで\n落とし物をしても\n見つけやすいかも…？", 0, 101, 0, 2, 4, 1, 128901, 7936);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険の準備なら\nできてるよ\nいつでも声をかけてね\n…楽しみにしてる！", 0, 102, 0, 2, 8, 1, 128901, 7937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう騎士クン\n一緒にお散歩とか…\nどうかな？", 0, 1, 1, 2, 1, 1, 128901, 7938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯のあとの\n瞑想って難しいんだよ\n眠くなっちゃって…", 0, 2, 2, 2, 1, 1, 128901, 7939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜ふかしさんは\nほどほどにね？\n一日頑張った自分を\n休ませてあげないと", 0, 3, 3, 2, 1, 1, 128901, 7940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("のんびりしてたら\nケーキが食べたく\nなっちゃうなぁ…\nでも太る…よね…？", 0, 2, 0, 3, 1, 1, 128901, 7942);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、かわいい…！\n見てるだけで\nにやけちゃう…♪", 0, 3, 0, 3, 1, 1, 128901, 7943);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…花の香りかな\n知ってる花かも…？\n当ててみようっ", 0, 4, 0, 3, 1, 1, 128901, 7944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいと\nどうしてこんなに\n落ち着くんだろう…", 0, 5, 0, 3, 1, 1, 128901, 7945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ過ぎたらお腹が\n目立っちゃうかもって\n分かってるのに…！\n止められないよ～っ！", 0, 7, 0, 3, 1, 1, 128901, 7947);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、恋の精霊とか\nいたりするのかな…？\nはっ！　ダメダメっ！\n実力で頑張らないと", 0, 8, 0, 3, 1, 1, 128901, 7948);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お部屋の中でも\n修行、修行っ♪\nでも燃やさないように\n注意しなきゃだね", 0, 1, 0, 1, 1, 1, 128701, 7950);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん…この衣装\n厚着か薄着か\nどっちなんだろう…？", 0, 2, 0, 1, 1, 1, 128701, 7951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもの肉球がない分\nお片付けしやすいな♪\n騎士くんのお部屋\nピカピカにしとこー！", 0, 3, 0, 1, 1, 1, 128701, 7952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お休みは騎士くんと\nＢＢＱに行きたいなー\nあたしと一緒なら\n火の心配はいらないよ", 0, 4, 0, 1, 1, 1, 128701, 7953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿ならもっと\n人を助けられる…！\nえへへっ！\n燃えてきたーーっ！", 0, 5, 0, 1, 1, 1, 128701, 7954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くんが帰ったら\nアイラみたいな笑顔で\nお疲れさまさまって\nお出迎えしよっと…♪", 0, 101, 0, 1, 4, 1, 128701, 7955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿の時、いつも\n胸が熱く燃えてるのは\nずっと騎士くんのこと\n考えてるからかな…？", 0, 102, 0, 1, 8, 1, 128701, 7956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くん騎士くん！\nあたしに触れると\nやけどしちゃうよ…？\nなんちゃってー♪", 0, 1, 0, 2, 1, 1, 128701, 7957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっ、騎士くん\n修行に行きたいの？\nえへへっ、いいねー♪\n二人で燃えちゃおー！", 0, 2, 0, 2, 1, 1, 128701, 7958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ騎士くん\nじゃんけんしよっか？\nグローブ外してるから\nチョキも出せるよっ♪", 0, 3, 0, 2, 1, 1, 128701, 7959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿でいられる時間\nすごく増えてきた…！\nえへへ！　あたしたち\n修行の成果出てるね！", 0, 4, 0, 2, 1, 1, 128701, 7960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じっと見つめないでよ\n顔が真っ赤に…やば！\nほんとに顔から\n火噴いちゃいそう…！", 0, 101, 0, 2, 4, 1, 128701, 7961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火には強くなれても\n騎士くんに触られた\nほっぺはずーっと\n熱くてたまんないや…", 0, 102, 0, 2, 8, 1, 128701, 7962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよー騎士くん！\n今日も一日\n燃え滾っていくよー！\nファイヤーッ！！", 0, 1, 1, 2, 1, 1, 128701, 7963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くんお昼だよ！\nちゃんとご飯食べて\n午後からの修行も\n乗り切ろうねー！", 0, 2, 2, 2, 1, 1, 128701, 7964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もお疲れさま！\nそうだ、寝る前に\nキャンプファイヤー\n囲んじゃおっか♪", 0, 3, 3, 2, 1, 1, 128701, 7965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼふーんっ！\nえへへ、気持ちいい…\n修行の前に\nちょっと休憩ー♪", 0, 2, 0, 3, 1, 1, 128701, 7967);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいな～♪\nなでなでなでなでなで\nなでなでなでなでっ！\nあははっ、摩擦熱！", 0, 3, 0, 3, 1, 1, 128701, 7968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～いい香り♪\n少し熱したほうが\n香りが広がるね…って\n蒸発しちゃった！！！", 0, 4, 0, 3, 1, 1, 128701, 7969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外でも自分の火で\nあったまれるけど\nお部屋でぬくぬく\nするのが一番だよね♪", 0, 5, 0, 3, 1, 1, 128701, 7970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐっ！\nお腹が減っては\n人助けはできずっ！\nもぐもぐもぐっ！", 0, 7, 0, 3, 1, 1, 128701, 7972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nなるほどなるほど…\n…これが上手な\nＢＢＱのやり方か…", 0, 8, 0, 3, 1, 1, 128701, 7973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…壁も扉も柱も\n全て記録で見たまま\n本当に…来ているのね", 0, 1, 0, 1, 1, 1, 129001, 7975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…騒がしい場所\n騎士クンが受け入れて\nくれるのをいいことに", 0, 2, 0, 1, 1, 1, 129001, 7976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが…騎士クンの\n守りたかった場所\n騎士クンの思い出が\n詰まった場所…ね", 0, 3, 0, 1, 1, 1, 129001, 7977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("視線を感じる…\nこちらの様子を\n探るような…心の動き\n取るに足らないけれど", 0, 4, 0, 1, 1, 1, 129001, 7978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…そこかしこで…\n言葉にもしたくない\n相手が過ごしていた\n記録を思い出す…", 0, 5, 0, 1, 1, 1, 129001, 7979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人は多いけれど…\n雪深い山中よりは\n過ごしやすい…か", 0, 101, 0, 1, 4, 1, 129001, 7980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自覚したことは\nあまりなかったけれど\nひどく…諦めの悪い女\nなのかもしれない", 0, 102, 0, 1, 8, 1, 129001, 7981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お招きありがとう\nそれで…何をして\nいればいい…かな？", 0, 1, 0, 2, 1, 1, 129001, 7982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは…明るいね\nわたしの城と比べると\nなんだか眩しいくらい", 0, 2, 0, 2, 1, 1, 129001, 7983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仮面はもう必要ないよ\nだって…わたしの顔を\n騎士クンに見て\nもらえなくなるから", 0, 3, 0, 2, 1, 1, 129001, 7984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンさえよければ\nわたしの城に専用の\n部屋を用意するよ\n…いつでも", 0, 4, 0, 2, 1, 1, 129001, 7985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…騎士クンのマント\nまた貸してほしいな\nきれいに使うから\n…だめ？", 0, 101, 0, 2, 4, 1, 129001, 7986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか二人の願いが\n重なり合えるって…\n信じているね\n…いつまでだって…", 0, 102, 0, 2, 8, 1, 129001, 7987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう、騎士クン\n…昨日は夢の中で\nお話ししすぎちゃって\nごめんね。ふふっ", 0, 1, 1, 2, 1, 1, 129001, 7988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹は…空いてない？\n食べ物はないけれど\n空腹を忘れる魔法なら\nかけてあげられるよ", 0, 2, 2, 2, 1, 1, 129001, 7989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン…\nまだ、眠らないの？\n…そう。それなら…\nわたしも起きているね", 0, 3, 3, 2, 1, 1, 129001, 7990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("肩の力を抜くには…\nまだ時間がかかりそう\nきっと…騎士クンと\n二人きりなら別なのに", 0, 2, 0, 3, 1, 1, 129001, 7992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぺんぽこりん…\nそう、確かあれも\nこんな感じだった…", 0, 3, 0, 3, 1, 1, 129001, 7993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花の香りは…好き\nつかの間\n心を穏やかに\nしてくれるから", 0, 4, 0, 3, 1, 1, 129001, 7994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい…けれど\n騎士クンの優しさに\n比べれば、まだまだ", 0, 5, 0, 3, 1, 1, 129001, 7995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おい、しい…？\nこの感覚が、それ？\nなぜか…納得できる", 0, 7, 0, 3, 1, 1, 129001, 7997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("情報を入手するには\nわざわざ本を開く\n必要があるだなんて…\nプレイヤーは面倒ね", 0, 8, 0, 3, 1, 1, 129001, 7998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メルクリゾートか…\n良い記憶はないな\nよし忘れよう", 0, 1, 0, 1, 1, 1, 129301, 8000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知性の戦士ユニ！\nその恐るべき筋力！\nふおお！　うにゃー！", 0, 2, 0, 1, 1, 1, 129301, 8001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽーん！\n石用の水着ください！\nセクシーロゼッタが、\n渚の視線を独占です！", 0, 3, 0, 1, 1, 1, 129301, 8002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学院から奨学金を\n勝ち取るより某財団を\nだまくらかした方が\n早い気がしてきたな…", 0, 4, 0, 1, 1, 1, 129301, 8003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんつぅ、わんつぅ…\nんぎゃあ足攣ったー！\nおのれカルミナとやら\n絶対に許さん！", 0, 5, 0, 1, 1, 1, 129301, 8004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ところで…なぜぼくは\nプールでもないのに\n水着のままなんだ…\nおのれ世界め！", 0, 101, 0, 1, 4, 1, 129301, 8005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼と二人で撮った動画\nうう、凝視に耐えん…\nなんだこのムズ痒さは", 0, 102, 0, 1, 8, 1, 129301, 8006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なに？　水着姿で\n寒くないのかだと？\n普段からもっと薄着の\n娘が沢山いるだろう", 0, 1, 0, 2, 1, 1, 129301, 8007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シノブ君にメリゾの\n招待状を送ったのだが\n御尊父の暴走を\n心配していたな…", 0, 2, 0, 2, 1, 1, 129301, 8008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミミ君らにメリゾの\n招待状を送ったのだよ\n迎える準備をせねば…\nおしゃぶり持ってる？", 0, 3, 0, 2, 1, 1, 129301, 8009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本質の賢者…？\nいや元気にしているが\nなぜ君がぼくの身内を\n知っているんだ…？", 0, 4, 0, 2, 1, 1, 129301, 8010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着が似合ってる？\nな、なんだね突然…\nやめたまえよふひひ…", 0, 101, 0, 2, 4, 1, 129301, 8011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度は夏にメリゾへ\n行きたいものだ\nむろん君も一緒だぞ", 0, 102, 0, 2, 8, 1, 129301, 8012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぐああっ、朝陽が…！\n朝陽が昇っている…！\n夜行性ユニ死んじゃう", 0, 1, 1, 2, 1, 1, 129301, 8013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…もう昼か…\nそろそろ寝ないとな\n規則正しい生活を\nしないと不健康だ…", 0, 2, 2, 2, 1, 1, 129301, 8014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃっはー、夜だー！\nオレたちの時間だぜ！\nふおおブチ上がり～！", 0, 3, 3, 2, 1, 1, 129301, 8015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…ぼくにここで\n寝ろということか？\n一向に構わんが…", 0, 2, 0, 3, 1, 1, 129301, 8017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃっきゃっ！\nこれかわい～！\n…よし、今日も\n子供の擬態完璧だな", 0, 3, 0, 3, 1, 1, 129301, 8018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、良い香りだ\nだがそれだけか…\nとくに精神高揚効果は\nないのか…ちぇー", 0, 4, 0, 3, 1, 1, 129301, 8019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火を見ていると…\n魔導罐を思いだすな…\nかに座、元気かな…", 0, 5, 0, 3, 1, 1, 129301, 8020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええい、\n固形食物はいらん！　\nポーションを出せ！", 0, 7, 0, 3, 1, 1, 129301, 8022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やはり書は文系に限る\nなんと心地よい筆致…\nぐああ突然理系文が！\nひぃ目が理系になる！", 0, 8, 0, 3, 1, 1, 129301, 8023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほああ～！\n知性の海上騎士ユニ！\nこれは新たな可能性！", 0, 10, 0, 3, 1, 1, 129301, 8025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは…なんだ？\n何が面白いんだ？\n難しいな…", 0, 11, 0, 3, 1, 1, 129301, 8026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大切な人と過ごす\n正月の思い出、か…\n昔の私だったら\n考えられなかったな", 0, 103, 0, 1, 12, 1, 108901, 8027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("叶えたい願いなら\nたくさんあるよ\nそれでも一番を選ぶ\nなら、やはりキミと…", 0, 103, 0, 2, 12, 1, 108901, 8028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("神殿にあった\n恋愛おみくじ…\n引いてみようかな…", 0, 103, 0, 1, 12, 1, 108801, 8029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン。来年も\nまた一緒におみくじ\n結ぼうね。約束だよ", 0, 103, 0, 2, 12, 1, 108801, 8030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度は騎士くんと\n一緒にうつった写真、\nおばあちゃんに\n送ろうっと♪", 0, 103, 0, 1, 12, 1, 108701, 8031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、騎士くん！\n今年も…ううん\nこれからも、よろしく\nおねがいします♪", 0, 103, 0, 2, 12, 1, 108701, 8032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("旧校舎の地下牢…\n真冬のサマー計画…\n等身大のＰＲ…\nうッ、頭が…！", 0, 1, 0, 1, 1, 1, 129401, 8033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし鏡でも見るか。\nお、いい腹筋育って…\nあ？　何見てんだコラ", 0, 2, 0, 1, 1, 1, 129401, 8034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("オレは金色の疾風！\nんん…なんか違うな。\n我が名は金色の…\nあ？　何見てんだコラ", 0, 3, 0, 1, 1, 1, 129401, 8035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("モニカとユニ先輩って\n口調と身長似てるけど\n子供扱いに対する\n反応は真逆だよね…", 0, 4, 0, 1, 1, 1, 129401, 8036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シオリン元気かな…\n昔くちゃくちゃに\n撫でくり回して\n嫌がられたっけなァ…", 0, 5, 0, 1, 1, 1, 129401, 8037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("べつにいんだけどさ…\nあんたの知り合いって\n普段から水着みたいな\nカッコの女多くない？", 0, 101, 0, 1, 4, 1, 129401, 8038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そだ、弟らがあんたに\n会いたがってたンだ。\n暇だったらいつでも\nウチ来てやってよ", 0, 102, 0, 1, 8, 1, 129401, 8039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特別講座は色々あった\nけど…メリゾ自体は\nまあ悪くなかったよね", 0, 1, 0, 2, 1, 1, 129401, 8040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着と合わせる小物に\nセンス出るよね、\nって話をミィコ先輩が\nしててマジわかりみ", 0, 2, 0, 2, 1, 1, 129401, 8041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着のミフユねえさん\nやっぱ仕上がってたね\nあれが竜殺しの体か…\nバリかっけーな…", 0, 3, 0, 2, 1, 1, 129401, 8042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はにょんっ！？\nや、だからさ…\n後ろから声かけんな、\nつってンじゃん…", 0, 4, 0, 2, 1, 1, 129401, 8043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリゾの特別講座が\n上手くいったのも\n敏腕カメラマンがいた\nお陰だよ。ありがとね", 0, 101, 0, 2, 4, 1, 129401, 8044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ？　この水着が？\n似合っ…え、なんて？\nごめ、聞こえんくて。\nもっかい言ってみて", 0, 102, 0, 2, 8, 1, 129401, 8045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう朝とかマジないわ\n昨日二人に付き合って\nオールでカラオケだよ", 0, 1, 1, 2, 1, 1, 129401, 8046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ授業行かなきゃ…\n真っ昼間から勉強とか\nマジつらたん過ぎ…", 0, 2, 2, 2, 1, 1, 129401, 8047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日これから夜勤で…\nいやバイトちゃーくて\nボランティアの話よ？\n校則違反よくない", 0, 3, 3, 2, 1, 1, 129401, 8048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うわ、ふっかふか…\nオニほど安らぐわ…\nやば、ユニってくる…", 0, 2, 0, 3, 1, 1, 129401, 8050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちも妹いりゃ\nこーゆーのもなァ…\nま自分用でもいいか", 0, 3, 0, 3, 1, 1, 129401, 8051);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふーん…\nいいじゃんこの香り\n抜群に嗅げるわ", 0, 4, 0, 3, 1, 1, 129401, 8052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちン家のルーツの森\n大火災でなくなった\nらしンだよね…\n生まれる前の話だけど", 0, 5, 0, 3, 1, 1, 129401, 8053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何コレありがてぇー\n食料ほくほく過ぎて草\n米ガチで尊いわァ…", 0, 7, 0, 3, 1, 1, 129401, 8055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいけど、なんでうち\n水着で本読んでンだよ\nどーゆープレイだよ", 0, 8, 0, 3, 1, 1, 129401, 8056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("金色の海上騎士クロエ\n推して参る！　覇ァ！\nあ？　何見てんだコラ", 0, 10, 0, 3, 1, 1, 129401, 8058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何コレ、貝の椅子？\nどーやって遊ぶんだ…\nいや座って終わりか…\nまァそりゃそーか…", 0, 11, 0, 3, 1, 1, 129401, 8059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さてと…\n明日の訓練メニュー\n考えねえとな", 0, 1, 0, 1, 1, 1, 129801, 8060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また新入りの女子に\n弁当もらっちまった…\nありがたく食うけどよ", 0, 2, 0, 1, 1, 1, 129801, 8061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("種族なんて関係なく\nみんなが力を合わせて\nランドソルを守る…\nいい時代になったよな", 0, 3, 0, 1, 1, 1, 129801, 8062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰にだって長所はある\n新入りのいいところを\n見つけてやるのも\n教官の仕事だ", 0, 4, 0, 1, 1, 1, 129801, 8063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("厳し過ぎても\n甘過ぎてもダメ…\n教官ってのは難しいぜ", 0, 5, 0, 1, 1, 1, 129801, 8064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦いが苦手な新入りを\nどうフォローするか…\n後であいつと\n相談してみるか", 0, 101, 0, 1, 4, 1, 129801, 8065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつは優し過ぎて\n戦いに向いてねえ\n…そういう甘さ\n嫌いじゃねえけどな", 0, 102, 0, 1, 8, 1, 129801, 8066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強くなる近道はねえ\n地道な鍛錬あるのみだ\nさ、訓練始めるぞ！", 0, 1, 0, 2, 1, 1, 129801, 8067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新入りにも\nいつも言ってるが…\n装備の手入れは\n念入りにしろよな？", 0, 2, 0, 2, 1, 1, 129801, 8068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("座学も受けてえのか？\nいい心がけだな！\nなんでも教えてやるよ\n…魔法以外ならな", 0, 3, 0, 2, 1, 1, 129801, 8069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新入りたちがよく\n恋バナしててな…\nお、おまえは…誰か\n気になるやついるか？", 0, 4, 0, 2, 1, 1, 129801, 8070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なあ、ストレッチ\n手伝ってくれねえか？\n訓練前にしっかり\n筋肉ほぐさねえと…", 0, 101, 0, 2, 4, 1, 129801, 8071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずいぶん頑張って\n鍛えたよな、おまえ\nよし！　ご褒美に\nお菓子作ってやるよ♪", 0, 102, 0, 2, 8, 1, 129801, 8072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("訓練日和だな！\nさぁて…まずは\n走り込みといくか！", 0, 1, 1, 2, 1, 1, 129801, 8073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯はしっかり食えよ\nでなきゃ、\nこの後もたねえぜ？", 0, 2, 2, 2, 1, 1, 129801, 8074);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっくに消灯時間だ\nさっさと寝な？\n明日も早いんだからよ", 0, 3, 3, 2, 1, 1, 129801, 8075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休むのも訓練のうちだ\n今はのんびり\nさせてもらうぜ", 0, 2, 0, 3, 1, 1, 129801, 8077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい面構えだ\n気に入ったぜ！\nあたしの班に入るか？\n…なんてな♪", 0, 3, 0, 3, 1, 1, 129801, 8078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…いやされる匂いだな\n新入りたちにも\nすすめてみるか…", 0, 4, 0, 3, 1, 1, 129801, 8079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったけえからって\n寝ないようにしねえと\n教官としての\n威厳に関わるからな…", 0, 5, 0, 3, 1, 1, 129801, 8080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事も訓練の一環だ\nとはいえ食い過ぎには\n気をつけねえと…", 0, 7, 0, 3, 1, 1, 129801, 8082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トーゴクの剣術…か\nなにか訓練に\n活かせるかもしれねえ", 0, 8, 0, 3, 1, 1, 129801, 8083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのおかたに近付く\n不埒な輩には、特別な\n訓練で地獄を見て\nいただきましょう", 0, 1, 0, 1, 1, 1, 129901, 8085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これだけ広ければ\n多少派手に\n動き回っても\n問題なさそうですね", 0, 2, 0, 1, 1, 1, 129901, 8086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…今誰か私を\n「鬼」教官と\n呼びませんでしたか？", 0, 3, 0, 1, 1, 1, 129901, 8087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しく開発したこの薬\n誰か試してくれる人は\nいませんか？", 0, 4, 0, 1, 1, 1, 129901, 8088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("厳しくすれば投げ出し\n優しくすればサボる\n人というのはどこまで\n度し難いのでしょう", 0, 5, 0, 1, 1, 1, 129901, 8089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はじめましょう\nあのおかたの心を\n射貫くための\nシミュレーションを", 0, 101, 0, 1, 4, 1, 129901, 8090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらゆる苦難と\n忌々しい女から守る\nためにも、私自身も\n鍛えておかねば", 0, 102, 0, 1, 8, 1, 129901, 8091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様、そんなに\n見つめられると…え？\nエリコはカッコいい？\nええ、当然ですとも", 0, 1, 0, 2, 1, 1, 129901, 8092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不調があればすぐ\n報告してください\n体のケアも教官の\n大事な役目ですので", 0, 2, 0, 2, 1, 1, 129901, 8093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい訓練器具の\n使い心地はどう…え？\n重すぎる？　これでも\n軽くしたのですが…", 0, 3, 0, 2, 1, 1, 129901, 8094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("運動後には特製の\n栄養ドリンクをどうぞ\nクスクス、何も\n入れたりしてませんわ", 0, 4, 0, 2, 1, 1, 129901, 8095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よくがんばりました\nあなた様。あぁ…\nお疲れになったお顔も\n素敵ですわ", 0, 101, 0, 2, 4, 1, 129901, 8096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた様、二人だけの\n遠征訓練へ\nまいりましょう。\n既に準備万端ですわ", 0, 102, 0, 2, 8, 1, 129901, 8097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ眠いですか？\nならばストレッチで\n体を痛めつ…ではなく\nほぐしていきましょう", 0, 1, 1, 2, 1, 1, 129901, 8098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はお弁当をご用意\nいたしました。量も\nスタミナも増し増し\n残さず食べてください", 0, 2, 2, 2, 1, 1, 129901, 8099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よい睡眠こそ健やかな\n体に不可欠。ですので\n私が寝ずの番をさせて\nいただきますわ", 0, 3, 3, 2, 1, 1, 129901, 8100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩用に使おうと思い\nましたが、心地よくて\n立てなくなって\nしまいますわ…", 0, 2, 0, 3, 1, 1, 129901, 8102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("中に重しを詰めれば\n愛でながら運動が\n可能ですわ", 0, 3, 0, 3, 1, 1, 129901, 8103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りでリラックスさせ\n同時に暗示を\nかけてみましょうか", 0, 4, 0, 3, 1, 1, 129901, 8104);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…くっ、眠気を誘う\nこの暖かさ…\n油断も隙もありません", 0, 5, 0, 3, 1, 1, 129901, 8105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主食はこちらで十分\nまかなえますわね\nそれでは私はおかずを\n作りましょう", 0, 7, 0, 3, 1, 1, 129901, 8107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、実用書の類も\n揃っているのですね\nとても助かりますわ", 0, 8, 0, 3, 1, 1, 129901, 8108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("……（そわそわ）", 0, 1, 0, 1, 1, 1, 129601, 8110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここに寄らずの花陣…\n作ったらダメですよね", 0, 2, 0, 1, 1, 1, 129601, 8111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の隅が\n落ち着きます\nそれか、陽の当たる所", 0, 3, 0, 1, 1, 1, 129601, 8112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身を隠せる場所が\nあると…\n助かるんですけど", 0, 4, 0, 1, 1, 1, 129601, 8113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("複雑な造りの家ですね\n触って壊れたり─\nしませんか？", 0, 5, 0, 1, 1, 1, 129601, 8114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("出入りするひと\nみんな、笑顔…\n…変わった家ですね", 0, 101, 0, 1, 4, 1, 129601, 8115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この家なら安全─\nかもしれません\n魔物が出ないので", 0, 102, 0, 1, 8, 1, 129601, 8116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これも、視察の一環\n遊びに来たわけじゃ\nないです", 0, 1, 0, 2, 1, 1, 129601, 8117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("長話─苦手です\n疲れるので…\nふぅ…", 0, 2, 0, 2, 1, 1, 129601, 8118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで友達を作れと\nネアさんが…\nそう、言われても…", 0, 3, 0, 2, 1, 1, 129601, 8119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世話をするのは\n得意です\n…花の、ですよ？", 0, 4, 0, 2, 1, 1, 129601, 8120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("媛へのお土産を\n探してるんですけど…\n…貴方のおすすめ、\n聞いておきます", 0, 101, 0, 2, 4, 1, 129601, 8121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("平和でのんきで…\n貴方らしい家です\n一応、褒めてます", 0, 102, 0, 2, 8, 1, 129601, 8122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花に、お水─？\n…いりません", 0, 1, 1, 2, 1, 1, 129601, 8123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日が高いうちは\nむやみに外へ出ません\n面倒事、多いので…", 0, 2, 2, 2, 1, 1, 129601, 8124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜番。私がします\nあまり眠らない\n性質なので…", 0, 3, 3, 2, 1, 1, 129601, 8125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここなら根を張れる\nかもしれません\n…張りませんけど", 0, 2, 0, 3, 1, 1, 129601, 8127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにやわな体じゃ\n身を守れませんよ─\n…あ。生き物じゃ\nないんですね", 0, 3, 0, 3, 1, 1, 129601, 8128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花みたいに─\nいい匂い、です", 0, 4, 0, 3, 1, 1, 129601, 8129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火を見てると、\nジオ・ゲヘナを\n思い出します…ふぅ", 0, 5, 0, 3, 1, 1, 129601, 8130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事も立派な戦支度\n媛が言ってました", 0, 7, 0, 3, 1, 1, 129601, 8132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知識も武器の一つだと\n媛が…でも、\nこれでどうやって…？", 0, 8, 0, 3, 1, 1, 129601, 8133);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("天気もいいしお花畑に\nピクニックでも\n行こうかな♪", 0, 1, 0, 1, 1, 1, 130701, 8135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、どこからか\nお花の匂いが…\nいい香りですね", 0, 2, 0, 1, 1, 1, 130701, 8136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しいシャベルとか\nじょうろもほしいなぁ\nお小遣いしっかり\nためないとね", 0, 3, 0, 1, 1, 1, 130701, 8137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花飾りたいけど\n花瓶はどこかな…\nあとであの人に\n聞いてみよっと", 0, 4, 0, 1, 1, 1, 130701, 8138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花の観察日記\n書かなきゃ\n日々勉強は\n欠かせませんよ", 0, 5, 0, 1, 1, 1, 130701, 8139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("衣装にお花を足して\nみたけど、あの人\n気付いてくれるかな？", 0, 101, 0, 1, 4, 1, 130701, 8140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この花冠、上手に\n作れたかも…\n日頃のお礼にあの人に\nあげようかな…", 0, 102, 0, 1, 8, 1, 130701, 8141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたは何のお花が\n好きですか？　ほら、\n一応知っておいたら\n役に立つかもですし", 0, 1, 0, 2, 1, 1, 130701, 8142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そのお花、乱暴に\n扱っちゃダメですよ\n花粉が服について\nとれなくなりますから", 0, 2, 0, 2, 1, 1, 130701, 8143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("土いじりしたから\n服が汚れてますよ\nはたいてあげますから\nじっとしててください", 0, 3, 0, 2, 1, 1, 130701, 8144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そんなにすぐに芽は\n出ませんよ\nまあ、楽しみなのは\n私も同じですけど…", 0, 4, 0, 2, 1, 1, 130701, 8145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装、そんなに\n気になります？　なら\nこうしてお花を\n着ければおそろいです", 0, 101, 0, 2, 4, 1, 130701, 8146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花の種を私に？\nありがとうございます\nせっかくなので一緒に\nお世話しませんか？", 0, 102, 0, 2, 8, 1, 130701, 8147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花にお水をあげるの\n手伝ってもらえます？\nお水は朝にあげるのが\nいいんですよ", 0, 1, 1, 2, 1, 1, 130701, 8148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっておきのお花見\nスポットに\nご案内しますよ\nお弁当も忘れずに！", 0, 2, 2, 2, 1, 1, 130701, 8149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間\n早く寝ましょう\n草木も眠るなんとか\nって言いますからね", 0, 3, 3, 2, 1, 1, 130701, 8150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花のお手入れって\nけっこう疲れますね…\nここでちょっと一息\nしちゃおっと", 0, 2, 0, 3, 1, 1, 130701, 8152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("耳にお花を着ければ…\nえへへ、すっごく\nかわいくなったね！", 0, 3, 0, 3, 1, 1, 130701, 8153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これはラベンダー\nこっちはミモザ\nフローラル系の香り\nっていいですねぇ", 0, 4, 0, 3, 1, 1, 130701, 8154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポカポカしますね～\nまるで春の陽気\nみたいです～", 0, 5, 0, 3, 1, 1, 130701, 8155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花を一輪さすだけで\nご飯の時間がとても\n華やかになりますね", 0, 7, 0, 3, 1, 1, 130701, 8157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お花の本が\nいっぱいある！\n今日はこれで\nお勉強です！", 0, 8, 0, 3, 1, 1, 130701, 8158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふんふ～ん♪\n華やかな服を着ると\n心がウキウキします♪", 0, 1, 0, 1, 1, 1, 130801, 8160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花祭りで出会った\nみなさん…\nお元気でしょうか？\nまたお会いしたいです", 0, 2, 0, 1, 1, 1, 130801, 8161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はっ！　そうでした\nこの服の時は\nメイドのお仕事は\nお休みでした…", 0, 3, 0, 1, 1, 1, 130801, 8162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服は替えが\nありませんから\n大きなドジには\n気を付けないと…", 0, 4, 0, 1, 1, 1, 130801, 8163);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("目立ったほつれもなし\n…うん、いい感じに\n補修できました♪", 0, 5, 0, 1, 1, 1, 130801, 8164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メイド姿でなくても\n心はいつでも\nお嬢さまの\nメイドです♪", 0, 101, 0, 1, 4, 1, 130801, 8165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服を着ると心が\n浮き立つのはあのかた\nと一緒にいる気持ちに\nなるからでしょうか？", 0, 102, 0, 1, 8, 1, 130801, 8166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はい、今日は一日\nこの服で過ごそうと\n思います\n変じゃないですよね？", 0, 1, 0, 2, 1, 1, 130801, 8167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花祭りのおかげで\n少しだけお花に\n詳しくなった…\nような気がします！", 0, 2, 0, 2, 1, 1, 130801, 8168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花祭り、今度は\nお嬢さまと救護院の\nみんなと一緒に\n行ってみたいですね", 0, 3, 0, 2, 1, 1, 130801, 8169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度キョウカちゃんと\n花祭りの服でお花を\n見にお出かけ\nするんです", 0, 4, 0, 2, 1, 1, 130801, 8170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メイド服を全部洗濯\nしちゃうなんて…\nドジっちゃいましたぁ", 0, 101, 0, 2, 4, 1, 130801, 8171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花祭りの服は私たちの\n思い出の服ですから…\nこれからも\n大切にします♪", 0, 102, 0, 2, 8, 1, 130801, 8172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はう、そうでした\nお花にお水を\nあげる時間です！", 0, 1, 1, 2, 1, 1, 130801, 8173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯は\nバスケットを持って\nお花畑に食べ\nに行きませんか？", 0, 2, 2, 2, 1, 1, 130801, 8174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁあ…繕い物を\nしていたらこんな時間\nになってしまいました\n早く寝ないと…", 0, 3, 3, 2, 1, 1, 130801, 8175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわしてて\nきもちいいです～\nどんな生地を\nつかってるんだろ～？", 0, 2, 0, 3, 1, 1, 130801, 8177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいですね～\nぬいぐるみさんにも\n服をつくって\nあげたいです♪", 0, 3, 0, 3, 1, 1, 130801, 8178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りです～\nあれ？　もしかして\n私の服についてる花と\n同じ香りが…？", 0, 4, 0, 3, 1, 1, 130801, 8179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かいですけど\nあまり近づいちゃうと\n頭の花飾りが乾燥\nしちゃいそうですね…", 0, 5, 0, 3, 1, 1, 130801, 8180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\nいい花を咲かせるには\nしっかりとした栄養が\n必要だそうです！", 0, 7, 0, 3, 1, 1, 130801, 8182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なるほどなるほど…\nお花のお手入れは\n奥が深いですね…", 0, 8, 0, 3, 1, 1, 130801, 8183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マホマホ王国にも\nサーカス団設立や\n夢と希望を届けますえ", 0, 1, 0, 1, 1, 1, 131001, 8185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの晴れ舞台や\nかっこいいポーズも\nできるようにしたいわ", 0, 2, 0, 1, 1, 1, 131001, 8186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむむむ～っ。うーん\nクルルはんみたいに\n胸から宝石を出すんは\n難しいみたいやわ", 0, 3, 0, 1, 1, 1, 131001, 8187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あむっ…んん～♪\nやっぱり練習のあとは\n甘いものに限るわぁ", 0, 4, 0, 1, 1, 1, 131001, 8188);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アーサーたちの衣装も\n今のうちに考えんと…\n生地、足りるやろか", 0, 5, 0, 1, 1, 1, 131001, 8189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はんとなら\nどんなアイデアも\n見つけられます♪", 0, 101, 0, 1, 4, 1, 131001, 8190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの晴れ姿が\n王子はんの目に一等\n輝いて見えますように", 0, 102, 0, 1, 8, 1, 131001, 8191);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キリっとしたうちも\nかっこいい？\nもう、上手やなぁ", 0, 1, 0, 2, 1, 1, 131001, 8192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい演目考えたんよ\nなぁ王子はん、意見\n聞かせてもらえます？", 0, 2, 0, 2, 1, 1, 131001, 8193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聞いてや王子はん\n動物さんたちとさらに\n息が合うてきたんよ\nみんな頑張り屋さんや", 0, 3, 0, 2, 1, 1, 131001, 8194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("演技の感想なら\n大歓迎どすえ♪\nたんと聞かせてや～", 0, 4, 0, 2, 1, 1, 131001, 8195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子はん、本番当日は\n最前席で見たってな\nそしたらうち、もっと\n頑張れますさかい♪", 0, 101, 0, 2, 4, 1, 131001, 8196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この技をあなたに\n捧げます…なんて♪\n驚いたやろ？\nどっきり作戦成功や♪", 0, 102, 0, 2, 8, 1, 131001, 8197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵なショーのためや\n今日も焦らず一歩ずつ\n成長していきまひょ\nな、王子はん♪", 0, 1, 1, 2, 1, 1, 131001, 8198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お弁当、王子はんも\n一緒にいかがどす？\nみんなで食べて団結や", 0, 2, 2, 2, 1, 1, 131001, 8199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜のサーカスも\n幻想的でとっても\n魅力的なんよ\n一緒にいきまひょか♪", 0, 3, 3, 2, 1, 1, 131001, 8200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("練習が終わったあとは\nの～んびりして\n体力を回復せな…", 0, 2, 0, 3, 1, 1, 131001, 8202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子たちとなら\n空中ブランコや\n玉乗りもええなぁ", 0, 3, 0, 3, 1, 1, 131001, 8203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りやなぁ\n本番前の緊張も\n和らげてくれそうやわ", 0, 4, 0, 3, 1, 1, 131001, 8204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このあったかい感じ…\nスポットライトの熱を\n思い出すわぁ", 0, 5, 0, 3, 1, 1, 131001, 8205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんと食べへんと\nいい演技はできまへん\n団長はんも言うてたわ", 0, 7, 0, 3, 1, 1, 131001, 8207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("動物さんたちのことも\nもっと勉強せな\n大事な仲間やさかい", 0, 8, 0, 3, 1, 1, 131001, 8208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("器用じゃないが、\n情には厚いよ\nこういう女を「一途」\nってそう言うんだろ？", 0, 103, 0, 1, 12, 1, 105601, 8210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("斬れないものはないと\n思ってきたさ。だけど\n…この気持ちだけは\n斬れないね、絶対に", 0, 103, 0, 2, 12, 1, 105601, 8211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んしょ、んしょっ…！\n日頃の感謝を込めて\nヒーローさんのお家を\nきれいにしますです♪", 0, 1, 0, 1, 1, 1, 130901, 8212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\n新アトラクションは\nこのギルドハウスを\nモチーフに…", 0, 2, 0, 1, 1, 1, 130901, 8213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごそごそ、こそこそ…\nヒーローさんに内緒で\nどこかにお礼の宝石を\n隠しておきましょう…", 0, 3, 0, 1, 1, 1, 130901, 8214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パークの運営が\n落ち着いたら\nわたしもギルド活動？\nしてみたいですます♪", 0, 4, 0, 1, 1, 1, 130901, 8215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなすてきな\nおうちに住めたら…\nいえ！　うさぎ小屋で\n十分です～っ", 0, 5, 0, 1, 1, 1, 130901, 8216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさんのおうち\nだって意識したら\nアトラクションよりも\nドキドキしてきます…", 0, 101, 0, 1, 4, 1, 130901, 8217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさんのことを\n考えると顔が赤く…\nこれってもしかして\nひょっとして…？", 0, 102, 0, 1, 8, 1, 130901, 8218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、ヒーローさん！\n話しかけてくれた記念\nということで、宝石\n受け取ってください♪", 0, 1, 0, 2, 1, 1, 130901, 8219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元気がない時は\n語尾にぴょんですっ！\nさあヒーローさんも\nやってみるぴょん♪", 0, 2, 0, 2, 1, 1, 130901, 8220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさんへのご恩\nおばあちゃんうさぎに\nなるまでに、お返し\nできるでしょうか…？", 0, 3, 0, 2, 1, 1, 130901, 8221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさん！\n二人で一緒に\nパレードの練習\nしませんか～♪", 0, 4, 0, 2, 1, 1, 130901, 8222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはは♪\nヒーローさんは\n人を笑顔にする力が\nありますです♪", 0, 101, 0, 2, 4, 1, 130901, 8223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさんに\n一日一恩返しですっ！\n返し終わるまで\nやめませんですます♪", 0, 102, 0, 2, 8, 1, 130901, 8224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます♪\nんしょ、んしょっ…！\n気持ちよく起きられた\n記念に宝石どうぞ♪", 0, 1, 1, 2, 1, 1, 130901, 8225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼にフードコートで\nかばばん君バーガー\n買ってきましたよ！\n一緒に食べますです♪", 0, 2, 2, 2, 1, 1, 130901, 8226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日\nお疲れさまですっ♪\nマッサージしますから\n寝そべってください♪", 0, 3, 3, 2, 1, 1, 130901, 8227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はふぅ～…♪\nお仕事の疲れも\nぴょんぴょ～んって\n飛んでっちゃいます♪", 0, 2, 0, 3, 1, 1, 130901, 8229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁっ、とっても\nかわいいですますっ！\nギルドハウスの\nマスコットですね♪", 0, 3, 0, 3, 1, 1, 130901, 8230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒーローさんの好きな\n香り…これを宝石に\nつければ、受け取って\nもらえるでしょうか？", 0, 4, 0, 3, 1, 1, 130901, 8231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ、気持ちいい♪\nヒーローさんの\n好きな温度に\n調整しときますです♪", 0, 5, 0, 3, 1, 1, 130901, 8232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("支配人は体が資本っ！\nたくさん食べ…すぎて\n動けなくなっちゃい\nましたぁ～…！", 0, 7, 0, 3, 1, 1, 130901, 8234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パークの\nガイドブックとか\nあったらいいですね♪", 0, 8, 0, 3, 1, 1, 130901, 8235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外あつすぎ溶けるわ～\nやっぱ部屋ん中で\n水着がラクだねー", 0, 1, 0, 1, 1, 1, 131101, 8237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ン～\nカリザきゅんどこー？\nもしかして逃げた？", 0, 2, 0, 1, 1, 1, 131101, 8238);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソラちゃんと\nリリちゃん誘って\nそろそろイイコト\nしよっかなー？", 0, 3, 0, 1, 1, 1, 131101, 8239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おねえちゃんに\n頼まれたシゴトは\nまた今度にすっかー\n夏休みだしー♪", 0, 4, 0, 1, 1, 1, 131101, 8240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士きゅんの\nプリンセスフォームも\n見てみたいんだよなー\nンフ♡", 0, 5, 0, 1, 1, 1, 131101, 8241);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スライムを\nこーしてあーしたら\n騎士きゅんの泳ぐ\n練習に使えるっぽ？", 0, 101, 0, 1, 4, 1, 131101, 8242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おかえり～♡\nって水着で迎えたら\n騎士きゅん喜んで\nくれるかなー？", 0, 102, 0, 1, 8, 1, 131101, 8243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士きゅん\nこのサングラス\nかけてみる？\nぜってー似合うよー", 0, 1, 0, 2, 1, 1, 131101, 8244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日焼け痛かったら\nいつでも言ってねー\nスライムでひんやり\nしてあげるよ～♪", 0, 2, 0, 2, 1, 1, 131101, 8245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今から外で\n焼いてこっかなー\n騎士きゅんもどー？", 0, 3, 0, 2, 1, 1, 131101, 8246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スライムマッサージ\nしてあげよっかー\nほーれ、もみもみ～♡", 0, 4, 0, 2, 1, 1, 131101, 8247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士きゅんが選んだ\n水着も着てみたーい\nネアおねえちゃんに\nどんなの着てほしい？", 0, 101, 0, 2, 4, 1, 131101, 8248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士きゅ～ん\n尻相撲しよっかー♪\nおねえちゃんに\n勝てたらご褒美だぞ～", 0, 102, 0, 2, 8, 1, 131101, 8249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑すぎてムダに\n早起きしちった～\n二度寝すっか～\n…ふぁあ…", 0, 1, 1, 2, 1, 1, 131101, 8250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテしても\nスイカとかかき氷なら\n全然ウェルカム\nなんだよなー", 0, 2, 2, 2, 1, 1, 131101, 8251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はこのまま\n水着で寝るかー\n夢ん中で泳ごー", 0, 3, 3, 2, 1, 1, 131101, 8252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いったんキューケイ…\nンー…よし\n充電カンリョ～♪", 0, 2, 0, 3, 1, 1, 131101, 8254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仲間になりたそうに\nこっち見てんねー\nきゃわいいしおっけ～", 0, 3, 0, 3, 1, 1, 131101, 8255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ン～いいニオーイ\nお日様あたった\n騎士きゅんの\n次くらいかな～", 0, 4, 0, 3, 1, 1, 131101, 8256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カラダ冷えてきたから\nたすかるーおかげで\nまだまだ水着イケるわ", 0, 5, 0, 3, 1, 1, 131101, 8257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うめ～\nとまんねぇ～\n夏バテどこいった～？", 0, 7, 0, 3, 1, 1, 131101, 8259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nこれは意外と\nぬるっと読めるっぽー", 0, 8, 0, 3, 1, 1, 131101, 8260);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ンフフ～\n海の戦士ってカンジ？\nアリよりのアリだね～", 0, 10, 0, 3, 1, 1, 131101, 8262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あーやべ\n一瞬で寝そー\nヤバだわ～", 0, 11, 0, 3, 1, 1, 131101, 8263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("服や紙が易々と\n燃えぬとは\nランドソルとはまこと\n住み易き国で候", 0, 1, 0, 1, 1, 1, 129701, 8264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どの世界にあっても\n民は活力に溢れ\n街は賑わうもの…\n善哉、善哉", 0, 2, 0, 1, 1, 1, 129701, 8265);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べ歩きに世界征服…\nギルドとはかくも\n自由気儘な徒党に\nありんすなぁ", 0, 3, 0, 1, 1, 1, 129701, 8266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("連絡は…今日もなし\n我が妹子は相変わらず\n放埓なことよ喃", 0, 4, 0, 1, 1, 1, 129701, 8267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("モネは相変わらず\n警戒しきりなれど…\nそのようなところも\n愛らしくあり申す", 0, 5, 0, 1, 1, 1, 129701, 8268);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんと長閑な世にや\nありけむ…この平和は\n騎士殿たちの努力の\n賜物にありんす喃", 0, 101, 0, 1, 4, 1, 129701, 8269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『王家の装備』は\n使わぬのかと？\n…フフ。すでに\n用いており申す", 0, 102, 0, 1, 8, 1, 129701, 8270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今ばかりは媛という\n立場は置いて\nこの地の者らと\n歓談したく候", 0, 1, 0, 2, 1, 1, 129701, 8271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強さの秘密？　…フフ\n女子の秘密を暴くのは\n野暮にござんす\nご寛恕いただきたく候", 0, 2, 0, 2, 1, 1, 129701, 8272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("此方の家屋、\n見目以上に\n堅牢であり申す\n何ぞ仕掛けがありや？", 0, 3, 0, 2, 1, 1, 129701, 8273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心地よい時間とは\n疾く過ぎ去りゆくもの\n此処で過ごすと改めて\n実感できる喃", 0, 4, 0, 2, 1, 1, 129701, 8274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("視線が気になる？\nこれはすみませぬ\nなにぶん、お前さまは\n見ていて飽きませぬ故", 0, 101, 0, 2, 4, 1, 129701, 8275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お前さまの前では\n誰もが心を開く…\nなんとまぁ罪作りな\n色男にありんすな？", 0, 102, 0, 2, 8, 1, 129701, 8276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よく眠れましたかの？\n寝る子は良く育つ、と\n古くより申します由", 0, 1, 1, 2, 1, 1, 129701, 8277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美食殿の作法に倣い\n皆で共に昼餉を頂くと\n致しんしょう", 0, 2, 2, 2, 1, 1, 129701, 8278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("逢魔ヶ時は望まぬ客も\n参るもの…お前さまも\n気をつけなんし", 0, 3, 3, 2, 1, 1, 129701, 8279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっちの蛇に\n勝るとも劣らぬ\n座り心地で候", 0, 2, 0, 3, 1, 1, 129701, 8281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魂、万物に宿る\nとの云いあらば\n情愛を注いでやるのが\nよかろうの", 0, 3, 0, 3, 1, 1, 129701, 8282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いと香しき哉…\n騎士殿は香の道にも\n詳しくあられるか", 0, 4, 0, 3, 1, 1, 129701, 8283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・ゲヘナの\n灼熱と比ぶれば\nそよ風と変わり\nござんせん", 0, 5, 0, 3, 1, 1, 129701, 8284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味なる哉…この味\nぺコリーヌ姫が好むも\n道理にありんす", 0, 7, 0, 3, 1, 1, 129701, 8286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トーゴクに、オーマ…\n書で見るだけでも\n心惹かれる土地よの", 0, 8, 0, 3, 1, 1, 129701, 8287);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑い日には\n冷たいものですよねー\nかき氷とか食べて\nすっきりしたいです★", 0, 1, 0, 1, 1, 1, 131201, 8289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海への行き来は\nテレポーテーションに\nお任せです★", 0, 2, 0, 1, 1, 1, 131201, 8290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("トロピカルジュースが\n飲みたいでーす♪\n海の家で見たんですよ\nカップル用ジュース★", 0, 3, 0, 1, 1, 1, 131201, 8291);
