INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("う～ん、まったり～\nこれぞ新ジャンル\nおうちバカンス★", 0, 2, 0, 3, 1, 1, 131201, 8306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よーしよーし★\nわたしとイイコト\n一緒にしましょうねー", 0, 3, 0, 3, 1, 1, 131201, 8307);
