INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、兄様…？\nスイカの種を飛ばす\n遊びもあるというのは\n…本当なのでしょうか", 0, 2, 0, 2, 1, 1, 131601, 8324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強くなるための修行は\nまだ始まったばかり\nまずは己の目指すべき\n道を見定めなくては", 0, 3, 0, 2, 1, 1, 131601, 8325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("同じ薄着であっても\n黒い天使の姿より…\n気が楽です", 0, 4, 0, 2, 1, 1, 131601, 8326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はい、ただいまー！\n…あっ！\n海の家でのお手伝いの\nくせが、つい…", 0, 101, 0, 2, 4, 1, 131601, 8327);
