INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("剣術とスイカ割りが\n上達する指南書…\n見つかりませんね…", 0, 8, 0, 3, 1, 1, 131601, 8339);
