INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえばあたしって\n羽があるけど\n泳げるのかしら…", 0, 4, 0, 1, 1, 1, 131701, 8346);
