INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もしかして暇なの？\nだったら記憶でも\n見せましょうか？\n凄く恥ずかしいやつ♪", 0, 3, 0, 2, 1, 1, 131701, 8352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏ってこんなに\n暑いのね…\n海にばかり行く\n気持ちが分かったわ", 0, 4, 0, 2, 1, 1, 131701, 8353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたの水着って\n新しいの買わないの？\nなんならあたしが\n選んであげるわよ♪", 0, 101, 0, 2, 4, 1, 131701, 8354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気軽に触れ合える\n距離にいる…\nあたしにとって\nとても大事なことよ", 0, 102, 0, 2, 8, 1, 131701, 8355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あらおはよう\n夏の朝は暑いわね\nシャワーでも浴びて\nさっぱりしなさい", 0, 1, 1, 2, 1, 1, 131701, 8356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は何を食べるの？\nガイド妖精として\n提案しましょうか？", 0, 2, 2, 2, 1, 1, 131701, 8357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしは厳禁よ\n無理やり眠らせて\nあげましょうか？", 0, 3, 3, 2, 1, 1, 131701, 8358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アメスさまだって\nゴロゴロするときは\nあるのよ～", 0, 2, 0, 3, 1, 1, 131701, 8360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…ふふっ♪\n何よ、あたしが\nかわいいものを\n愛でちゃだめなの？", 0, 3, 0, 3, 1, 1, 131701, 8361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういういい香り…\n塔の中じゃなかなか\n楽しめないのよね", 0, 4, 0, 3, 1, 1, 131701, 8362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着を着てるのに\n温まるのって\n矛盾してない？\n気にしすぎかしら", 0, 5, 0, 3, 1, 1, 131701, 8363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたと行動するなら\n沢山食べられるように\nならなきゃね…！", 0, 7, 0, 3, 1, 1, 131701, 8365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("文字を読むのと\nデータを読むのは\nまったく違うわ", 0, 8, 0, 3, 1, 1, 131701, 8366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へぇ、面白いじゃない\nこういう経験、昔じゃ\nできなかったわ", 0, 10, 0, 3, 1, 1, 131701, 8368);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("面白いクッションね\nところであんた…\nあたしで遊んでない？\n気のせいならいいけど", 0, 11, 0, 3, 1, 1, 131701, 8369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また新しい悪戯\n思いついちゃった♪\n誰に仕掛けようかしら", 0, 1, 0, 1, 1, 1, 118601, 8370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ～あ、退屈…\nフィオでもからかって\nこようかしら♪", 0, 2, 0, 1, 1, 1, 118601, 8371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ミソギの悪戯って\nレベル高いのよね…\n負けてらんないわ！", 0, 3, 0, 1, 1, 1, 118601, 8372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家事ニガテなのよね～\nコッコロたちには\n感謝しないとね", 0, 4, 0, 1, 1, 1, 118601, 8373);
