INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつに仕掛ける\n次の悪戯は～…♪\nこれ…ううん…\nやっぱこっちかしら？", 0, 101, 0, 1, 4, 1, 118601, 8375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("結局ギルドハウスが\n一番落ち着くわね\n…私たちの家だもの", 0, 102, 0, 1, 8, 1, 118601, 8376);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪戯のコツでも\n教えてあげよっか？\n…え～興味ないの？", 0, 1, 0, 2, 1, 1, 118601, 8377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからもずーっと\n退屈しない毎日に\nしてあげる♪\n私の悪戯でね♪", 0, 2, 0, 2, 1, 1, 118601, 8378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうど退屈してたの\nたーっぷりと\n構ってもらうわよ♪", 0, 3, 0, 2, 1, 1, 118601, 8379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("案内が必要なら\n頼ってくれていいわよ\n一応は私だって\nガイド妖精だし！", 0, 4, 0, 2, 1, 1, 118601, 8380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冒険のガイドなら\n私に任せなさい♪\nある意味忘れられない\n旅にしてあげる♪", 0, 101, 0, 2, 4, 1, 118601, 8381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妖精がいる家は\n栄えるのよ♪　だから\nずっといてあげる\nあんたのそばにね♪", 0, 102, 0, 2, 8, 1, 118601, 8382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃははっ！\n寝ぐせついてるわよ？\nこのままにしましょ！\nだって面白いし！", 0, 1, 1, 2, 1, 1, 118601, 8383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自由に外へ行けるって\nすっごく幸せなことよ\nさ、散歩行きましょ♪", 0, 2, 2, 2, 1, 1, 118601, 8384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安心していいわ\n寝てるあんたに\n悪戯しないから\n…あんたにはね♪", 0, 3, 3, 2, 1, 1, 118601, 8385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪くはないけど…\nあいつの頭の方が\n座り心地いいかも", 0, 2, 0, 3, 1, 1, 118601, 8387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子を使った\n悪戯は…\n…止めとこっと\nこんなにかわいいし♪", 0, 3, 0, 3, 1, 1, 118601, 8388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスに\nピッタリな匂いね♪\n一言で言えば…\nカオスって感じ？", 0, 4, 0, 3, 1, 1, 118601, 8389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんていうか…\n心があたたかいわ\n…変な感じ！", 0, 5, 0, 3, 1, 1, 118601, 8390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガイド妖精にも\n食事の機能があって\nよかったのかも\nしれないわね…もぐ…", 0, 7, 0, 3, 1, 1, 118601, 8392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じれったい物語ね…\nこんなの霧を使えば\n一瞬で終わるのに！", 0, 8, 0, 3, 1, 1, 118601, 8393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わる～い子は\nトゥンヌス漁船に\n乗ってもらおうかな～", 0, 1, 0, 1, 1, 1, 131801, 8395);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たまにはファミリーの\nみんなにもお休みを\nあげないとね～☆", 0, 2, 0, 1, 1, 1, 131801, 8396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海辺に素敵な\nバーがあるんだ～\n彼が大人になったら\n一緒に行きたいな♪", 0, 3, 0, 1, 1, 1, 131801, 8397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の風を肌で\n感じるの好きかも～\nラーゴはどう？", 0, 4, 0, 1, 1, 1, 131801, 8398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海岸線を\nのんびり散歩もいいね\n砂や貝殻に紛れた\nお宝探しの旅だよ～☆", 0, 5, 0, 1, 1, 1, 131801, 8399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなで集まって\nビーチパーティーでも\n開いちゃおっかな～♪", 0, 101, 0, 1, 4, 1, 131801, 8400);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さて、この水着…\n彼は気に入って\nくれてるかな～？", 0, 102, 0, 1, 8, 1, 131801, 8401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("心ゆくまで夏を\n楽しんじゃお～☆\nほら君も♪", 0, 1, 0, 2, 1, 1, 131801, 8402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着似合ってるって？\nふふ♪　うれしいこと\n言ってくれるね～☆", 0, 2, 0, 2, 1, 1, 131801, 8403);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("熱中症には\n気を付けないと\nだめだよ～？", 0, 3, 0, 2, 1, 1, 131801, 8404);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の家ならうちの\nファミリーでやってる\nとこにしよっか☆\n豪遊しちゃお～♪", 0, 4, 0, 2, 1, 1, 131801, 8405);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君と一緒なら\nどんな夏になるのか\n楽しみだね～♪", 0, 101, 0, 2, 4, 1, 131801, 8406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君といると子供心を\nくすぐられちゃうな～\n大人だって思いっきり\n遊んでいいんだよね♪", 0, 102, 0, 2, 8, 1, 131801, 8407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ、今日は何をして\n過ごそっかな～…\nねえ、君は何したい？", 0, 1, 1, 2, 1, 1, 131801, 8408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ♪\n波音が心地良い\n時間だね～☆", 0, 2, 2, 2, 1, 1, 131801, 8409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今夜は星空の下で\n乾杯しよっか～☆\n飲み物取ってくるね♪", 0, 3, 3, 2, 1, 1, 131801, 8410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ涼しい～♪\nちょっと一休み\nしていこっか☆", 0, 2, 0, 3, 1, 1, 131801, 8412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのも良いけど\nやっぱりラーゴの方が\nかわいいかな～♪", 0, 3, 0, 3, 1, 1, 131801, 8413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("爽やかな香りだね～\nこういう感覚も絵で\n表現してみたいな～", 0, 4, 0, 3, 1, 1, 131801, 8414);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("続きを描く前に\n原稿を乾かさないとね\nインクがにじむと\n直すの大変なんだよ～", 0, 5, 0, 3, 1, 1, 131801, 8415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は水着だし…\n食べるのは控えめに\nしておこっかな", 0, 7, 0, 3, 1, 1, 131801, 8417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("話題の作品は\nチェックしないとね～\nあっ、この作家さん\n新刊出すんだ～", 0, 8, 0, 3, 1, 1, 131801, 8418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの出店の客引きに\nこういう乗り物系を\n使うのもアリかな～☆", 0, 10, 0, 3, 1, 1, 131801, 8420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ、背景用の\n参考資料に\n一つ欲しいかも♪", 0, 11, 0, 3, 1, 1, 131801, 8421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここに帰るのも\n久しぶり…あれから\n変わったところは\nあるかしら？", 0, 1, 0, 1, 1, 1, 181201, 8422);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バイトも復帰しなきゃ\nうちのギルドにとって\n食費は重要だもの…！", 0, 2, 0, 1, 1, 1, 181201, 8423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コッコロマ…っ\n…うぅ…\nこの癖は\n直らないのね…", 0, 3, 0, 1, 1, 1, 181201, 8424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界はまだまだ\n知らないことだらけね\n『裏世界』とか…", 0, 4, 0, 1, 1, 1, 181201, 8425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("必ずみんなを\n助け出してみせるわ\n…もちろん、兄さんも", 0, 5, 0, 1, 1, 1, 181201, 8426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またみんなと\n暮らせるなんて…\n夢じゃ、ないのよね", 0, 101, 0, 1, 4, 1, 181201, 8427);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさんの人が\n私に優しくしてくれる\n…だからこそ、私も\n頼れる人になりたいわ", 0, 102, 0, 1, 8, 1, 181201, 8428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はランドソルの\n街の外にも行きたいわ\nあの…よかったらまた\n一緒に回ってくれる？", 0, 1, 0, 2, 1, 1, 181201, 8429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("独りぼっちで眠るのは\nやっぱり寂しかったわ\n…みんなで雑魚寝？\nそんなの…絶対やるわ", 0, 2, 0, 2, 1, 1, 181201, 8430);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネビアってば大泣きで\n私を出迎えてくれたの\n…すごく嬉しかったわ", 0, 3, 0, 2, 1, 1, 181201, 8431);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この翼、陽に当たると\n本当に綺麗よね…\n自分のだけれど、つい\nずっと見ちゃうもの", 0, 4, 0, 2, 1, 1, 181201, 8432);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにーたんっ♪\n…呼びたくなっただけ\n本当にそれだけよっ？", 0, 101, 0, 2, 4, 1, 181201, 8433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしたの？\n…ふふっ、安心して\nこれからもずっと\n私はここにいるわ", 0, 102, 0, 2, 8, 1, 181201, 8434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな起きだす時間ね\n街が活気づいてく感じ\n嫌いじゃないわ", 0, 1, 1, 2, 1, 1, 181201, 8435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("【美食殿】のお昼は\nいつも美味しいから\nまた太っちゃいそうね", 0, 2, 2, 2, 1, 1, 181201, 8436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみなさい\n明日も、その先も\n一緒に冒険しましょう", 0, 3, 3, 2, 1, 1, 181201, 8437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩も大事…よね\nじゃあ遠慮なく…\nふぅ～…♪", 0, 2, 0, 3, 1, 1, 181201, 8439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…ふわふわ…♪\nこのかわいさには\nもう抗えないわ…", 0, 3, 0, 3, 1, 1, 181201, 8440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着く香り…\nこの匂いを嗅いでると\n帰ってきたなって\n思うわね", 0, 4, 0, 3, 1, 1, 181201, 8441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなで野宿した時も\n焚火の明かりを見て\nすごく安心したのよね", 0, 5, 0, 3, 1, 1, 181201, 8442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ペコリーヌさんには\n負けるけど…\n美味しくって手が\n止まらないわ…！", 0, 7, 0, 3, 1, 1, 181201, 8444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスフォーム…\n一体どういう仕組みで\n発動するのか、文献に\n書いてないかしら…", 0, 8, 0, 3, 1, 1, 181201, 8445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すごーく暑いけど、\nこの暑さをどうやって\n乗り越えるかって\n考えるのも楽しいかも", 0, 1, 0, 1, 1, 1, 131901, 8447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("氷で彫刻を作るの？\nそれは楽しそうだけど\nすぐに溶けちゃわ\nないかしら？", 0, 2, 0, 1, 1, 1, 131901, 8448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お日様の下で遊ぶのも\n部屋の中で涼むのも\nどっちも夏ならではの\n楽しみ方なのね", 0, 3, 0, 1, 1, 1, 131901, 8449);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生き物の観察日記、\n私も書いてみたいな\nパックのお昼寝日記\nなんてどうかしら？", 0, 4, 0, 1, 1, 1, 131901, 8450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さまぁばけぇしょんは\n計画を立てるもの\nなんだって\n私も挑戦してみるわね", 0, 5, 0, 1, 1, 1, 131901, 8451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界のことを\nもっと知って\nアーラム村のみんなに\nお話ししてあげるの", 0, 101, 0, 1, 4, 1, 131901, 8452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつルグニカに帰るか\nわからないからこそ\n毎日頑張らなきゃね", 0, 102, 0, 1, 8, 1, 131901, 8453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はどこに行くの？\n私は、えーと…\nかき氷が食べたいわ！", 0, 1, 0, 2, 1, 1, 131901, 8454);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにも精霊が\n住んでたりするの？\n…精霊じゃなくて\nがいど妖精？", 0, 2, 0, 2, 1, 1, 131901, 8455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パックったら、\n近所の子にいっぱい\nなでなでされてたわ\nすごーく人気者ね！", 0, 3, 0, 2, 1, 1, 131901, 8456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実は…線香花火の\n特訓をしてたの！\n次は負けないんだから", 0, 4, 0, 2, 1, 1, 131901, 8457);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日、みんなの\n似顔絵も絵日記に\n描いてみたんだけど…\n笑っちゃダメよ？", 0, 101, 0, 2, 4, 1, 131901, 8458);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何気ない時間だって\n後で思い返せば\nずっと忘れない\n素敵な思い出になるの", 0, 102, 0, 2, 8, 1, 131901, 8459);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちよく起きて、\nいい一日を過ごしたい\nそんなときには\nラジーオタイソーね！", 0, 1, 1, 2, 1, 1, 131901, 8460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんの時間ね\n暑さに負けないように\nしっかり食べましょう", 0, 2, 2, 2, 1, 1, 131901, 8461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外は涼しいみたいだし\n夜の散歩に行ってみる\nのはどうかしら？", 0, 3, 3, 2, 1, 1, 131901, 8462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遊び疲れたら\nここでひとやすみ…\nふわぁ…\n眠くなっちゃった…", 0, 2, 0, 3, 1, 1, 131901, 8464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("細かいところまで\nすごーく丁寧に\n作られてる…", 0, 3, 0, 3, 1, 1, 131901, 8465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ、なんだか\nすーっとする香りね\nちょっぴり涼しく\nなったみたい", 0, 4, 0, 3, 1, 1, 131901, 8466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海で遊ぶと\n体が冷えるから\nあったかいのも\nすごーく嬉しい…", 0, 5, 0, 3, 1, 1, 131901, 8467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これも美味しい…！\nペコリーヌが\nどんどん食べちゃう\n気持ちが分かるかも", 0, 7, 0, 3, 1, 1, 131901, 8469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお話も面白い…！\nあっという間に時間が\n過ぎちゃったわ…\n…ね、寝てません！", 0, 8, 0, 3, 1, 1, 131901, 8470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子と一緒に海に\nいったら楽しそうね！\nどこに行けば\n会えるのかしら？", 0, 10, 0, 3, 1, 1, 131901, 8472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふかね！\nこうしてると波の音が\n聞こえてきそう…", 0, 11, 0, 3, 1, 1, 131901, 8473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こちらでは水着姿で\n過ごすのも\n珍しくないようですね", 0, 1, 0, 1, 1, 1, 132101, 8474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メイド服ではなく\n姉様と色違いの水着…\nレムは嬉しいです", 0, 2, 0, 1, 1, 1, 132101, 8475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し室温が高いかも\nしれませんね…\nいくつか氷を配置して\nおきましょうか", 0, 3, 0, 1, 1, 1, 132101, 8476);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("清涼感があるとはいえ\n鉄球をビーチバレーの\nボールに代用するのは\n危ないでしょうか…", 0, 4, 0, 1, 1, 1, 132101, 8477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅー…ふぅー…\nようやく浮輪が\n膨らみました\n姉様にお渡ししないと", 0, 5, 0, 1, 1, 1, 132101, 8478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海のことをもっと\n教えていただけますか\n…スバルくんと海の\n話をしたいんです", 0, 101, 0, 1, 4, 1, 132101, 8479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もし海に行く機会が\nあればレムにも…\nお声がけくださいね\nぜひ、お願いします", 0, 102, 0, 1, 8, 1, 132101, 8480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何を着ていても\nメイドはメイド\n掃除も料理も\nなんでもござれです", 0, 1, 0, 2, 1, 1, 132101, 8481);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スバルくんとあなたは\n兄弟のように\n仲がいいですね\n姉様とレムと一緒です", 0, 2, 0, 2, 1, 1, 132101, 8482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿で子どもたちと\n遊ぶのは…さすがに\nはばかられますね\nやはり着替えてきます", 0, 3, 0, 2, 1, 1, 132101, 8483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナンパ…というものが\n海にはあるそうです\nスバルくんがとても\n警戒していました", 0, 4, 0, 2, 1, 1, 132101, 8484);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魚釣りでしたら\nレムもご一緒します\n氷漬けの魚の備蓄を\n補充したかったので", 0, 101, 0, 2, 4, 1, 132101, 8485);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちと砂遊びの\n約束をしているんです\nあなたもご一緒に\nいかがですか？", 0, 102, 0, 2, 8, 1, 132101, 8486);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラジーオタイソーは\nもうされましたか？\n体がほぐれますよ", 0, 1, 1, 2, 1, 1, 132101, 8487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですね。では\n姉様に焼きそばを…\nもちろん皆様の分も\n用意してありますよ", 0, 2, 2, 2, 1, 1, 132101, 8488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("熱帯夜であっても\nお休みの際はお腹を\n冷やさないように\n気をつけてくださいね", 0, 3, 3, 2, 1, 1, 132101, 8489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とても気持ちよさそう\nです…！\nさっそく姉様に\nお教えしないと", 0, 2, 0, 3, 1, 1, 132101, 8491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("季節に合わせた\n着せ替えができれば\n子どもたちも\n楽しめそうです", 0, 3, 0, 3, 1, 1, 132101, 8492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…この香りは\n疲れを癒やしてくれ\nますね。エミリア様に\nお持ちします", 0, 4, 0, 3, 1, 1, 132101, 8493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身も心もほぐれます\n思っていたよりも\n体が冷えていたみたい\nですね…ふう…", 0, 5, 0, 3, 1, 1, 132101, 8494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…んうっ！？\nこのすっぱさは…\n梅干し、ですか…\nくせになりますね…！", 0, 7, 0, 3, 1, 1, 132101, 8496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に関する詩文なども\nあるのでしょうか…\n気になります", 0, 8, 0, 3, 1, 1, 132101, 8497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("地竜とは違った\n乗り心地です…\n本物にも乗ってみたい\nものですね", 0, 10, 0, 3, 1, 1, 132101, 8499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この大きさで\n本物の貝であれば…\nどんな料理にするか\n想像が膨らみます", 0, 11, 0, 3, 1, 1, 132101, 8500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがこの世界の\n居住環境か…\n面白い構造だね", 0, 1, 0, 1, 1, 1, 132001, 8501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇を持て余していてね\n誰か話し相手に\nなってくれないかな", 0, 2, 0, 1, 1, 1, 132001, 8502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("目新しいものが\nたくさんあるね\n胸が躍るよ", 0, 3, 0, 1, 1, 1, 132001, 8503);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頑丈そうな建物だ\nここなら彼女たちが\n暴れても大丈夫かな？", 0, 4, 0, 1, 1, 1, 132001, 8504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("力が制限されていて\n良かった面もある\n君も吐かずにすんだし", 0, 5, 0, 1, 1, 1, 132001, 8505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪さなんてするわけ\nないじゃないか\n傷つくなぁ", 0, 101, 0, 1, 4, 1, 132001, 8506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段と違う格好で\n歩き回るのも\n悪くない経験だ", 0, 102, 0, 1, 8, 1, 132001, 8507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクに聞きたいことが\nあるなら遠慮なく\n質問するといい", 0, 1, 0, 2, 1, 1, 132001, 8508);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気軽に魔女に\n話しかけるなんて\n君は物好きだね", 0, 2, 0, 2, 1, 1, 132001, 8509);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界においては\nボクは異物だからね\n大人しくしているさ", 0, 3, 0, 2, 1, 1, 132001, 8510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクの反応を\n見たいのかい？\n君の好奇心には\n恐れ入るよ", 0, 4, 0, 2, 1, 1, 132001, 8511);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクの手を借りたい？\nもちろん構わないさ\n対価はいただくけどね", 0, 101, 0, 2, 4, 1, 132001, 8512);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボクと海を見たい？\nふふ、魅力的な\nお誘いだね", 0, 102, 0, 2, 8, 1, 132001, 8513);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お目覚めかな？\nさて、君の見た夢を\n教えてくれないかな？", 0, 1, 1, 2, 1, 1, 132001, 8514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食後のお茶を\n一緒にどうだろうか？\nさあ、席に座ってよ", 0, 2, 2, 2, 1, 1, 132001, 8515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おや、お休みかな？\n魔女の前で無防備だね\n…無論、何もしないさ", 0, 3, 3, 2, 1, 1, 132001, 8516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう椅子は\n茶会には向かないね\nつい気が緩んでしまう", 0, 2, 0, 3, 1, 1, 132001, 8518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうものを好きな\n女の子がいいのかな？\n君の嗜好を知りたいな", 0, 3, 0, 3, 1, 1, 132001, 8519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだ\nこれにはどんな\n効能があるんだろう？", 0, 4, 0, 3, 1, 1, 132001, 8520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火の点け方に\nボクのいた世界との\n違いはないのかな？", 0, 5, 0, 3, 1, 1, 132001, 8521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これもまた未知の味だ\n存分に味わわせて\nもらうとしよう", 0, 7, 0, 3, 1, 1, 132001, 8523);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素晴らしいね\nここには叡智が\n詰まっている", 0, 8, 0, 3, 1, 1, 132001, 8524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物を模倣した\nぬいぐるみか…\n実物を見たくなるね", 0, 10, 0, 3, 1, 1, 132001, 8526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい気持ちだ…ボクと\nしたことが、何も考え\nられなくなりそうだ", 0, 11, 0, 3, 1, 1, 132001, 8527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("願わずにいられません\nどうかこちらの\n世界には…悲劇が\n生まれませんようにと", 0, 103, 0, 1, 12, 1, 109701, 8528);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食事のご希望があれば\nなんなりと。お腹が\nいっぱいになるまで\n沢山ご用意しますね", 0, 103, 0, 2, 12, 1, 109701, 8529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの男、これからも\n観察が必要ね\nラムの目の届く範囲に\n置く必要があるわ", 0, 103, 0, 1, 12, 1, 109801, 8530);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素直なところは\nあの男の美点ね\n癪だけど、偶然にも\nラムと同じだわ", 0, 103, 0, 2, 12, 1, 109801, 8531);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("迷惑かけちゃったけど\n雪遊びは楽しかったわ\nまたやりたい…なんて\n言ったら怒られるかも", 0, 103, 0, 1, 12, 1, 109901, 8532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("数えきれないくらいの\n思い出を、みんなで\n作りましょう！", 0, 103, 0, 2, 12, 1, 109901, 8533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わわっ、今すごく\nいい香りがしたけど…\n誰の香水かな\n教えてほしいな…♪", 0, 1, 0, 1, 1, 1, 132201, 8534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("錬金術用の釜、\n置くならどこかな？\n自分専用の錬金釜、\n憧れちゃうよね♪", 0, 2, 0, 1, 1, 1, 132201, 8535);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い…誰か\n唐揚げ食べたみたい\nうぅ…お腹空いて\nきちゃうよ", 0, 3, 0, 1, 1, 1, 132201, 8536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次の新曲のタイトルは\n『恋の錬金術』！\nうーん、ちょっと\nベタ過ぎるかな…", 0, 4, 0, 1, 1, 1, 132201, 8537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、錬金の素材\n切らしてたんだ…\n彼を誘って採集に\n行ってこようかな", 0, 5, 0, 1, 1, 1, 132201, 8538);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("瞬時に着替えができる\n薬とかできないかな？\n舞台で衣装チェンジ！\nなーんて、楽しそう♪", 0, 101, 0, 1, 4, 1, 132201, 8539);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("彼が遊びに来た後は\n部屋の空気がほんのり\n彼の匂いなんだ…\nなんだか幸せだな♪", 0, 102, 0, 1, 8, 1, 132201, 8540);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もバイト？\nそれならこれ飲んで\n私のお手製ポーション\nがんばってきてね！", 0, 1, 0, 2, 1, 1, 132201, 8541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しくできたカレー屋\n行ってみない？\n時々スパイスの香りが\n流れてくるんだよ", 0, 2, 0, 2, 1, 1, 132201, 8542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私のフィギュア\nそっくりでしょ！\nルイちゃんが作って\nくれたんだ", 0, 3, 0, 2, 1, 1, 132201, 8543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ、シャンプー\n変えた？　私と同じの\nだよ！　どうしよう\nドキドキしちゃう…", 0, 4, 0, 2, 1, 1, 132201, 8544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いらっしゃいませ♪\n何を作りますか？\nなーんてね。錬金堂で\nまた一日店長したいな", 0, 101, 0, 2, 4, 1, 132201, 8545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クンクン…彼の\nハンカチ…いい匂い♪\n私だけの秘密のお守り\nにしてるんだ", 0, 102, 0, 2, 8, 1, 132201, 8546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえねえ、天気も\nいいし一緒に錬金の\n素材集めに行こうよ！", 0, 1, 1, 2, 1, 1, 132201, 8547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯、用意したよ\nあはは、さすがに\nランチは錬成しないよ\n私の手作りだよ♪", 0, 2, 2, 2, 1, 1, 132201, 8548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日お疲れさま\nこれ飲んでゆっくり\n休んで。薬じゃないよ\nホットミルクだよ？", 0, 3, 3, 2, 1, 1, 132201, 8549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日、遅くまで\n錬金術の勉強してた\nから眠くって…\nちょっと一休みっと", 0, 2, 0, 3, 1, 1, 132201, 8551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子にちょっとだけ\n香水かけて、と…\nんー！　だっこした時\nすっごくいい匂い♪", 0, 3, 0, 3, 1, 1, 132201, 8552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("花みたいな、\nお菓子みたいな\nいい香り。気持ちが\n穏やかになるね♪", 0, 4, 0, 3, 1, 1, 132201, 8553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外でもこの暖かさを\n感じられる道具、\n作れたりしないかな？", 0, 5, 0, 3, 1, 1, 132201, 8554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素材集めに行くと\nお腹が空くんだよね\nイロハちゃんも\nこの味好きそう", 0, 7, 0, 3, 1, 1, 132201, 8556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("錬金術にはたくさんの\n知識が必要だからね\nさあ、今日も調合書を\n読まなくちゃ", 0, 8, 0, 3, 1, 1, 132201, 8557);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが騎士さんたちの\n住んでる場所…！\n粗相がないように\n気をつけなきゃ", 0, 1, 0, 1, 1, 1, 127701, 8559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・テオゴニアの\nみんな、私がいない間\nちゃんとお仕事\nしてればいいけど…", 0, 2, 0, 1, 1, 1, 127701, 8560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コッコロさんも\n従者として長いって\n聞いたような…\nあの年ですごい…！", 0, 3, 0, 1, 1, 1, 127701, 8561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分がもてなされる\n側になるのって\nやっぱりちょっと\n落ち着かないかも…", 0, 4, 0, 1, 1, 1, 127701, 8562);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のお休みの日は\n何しよう…？\nあっ、最近できたお店\nヴルムと行こうかな？", 0, 5, 0, 1, 1, 1, 127701, 8563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お買い物したら\nかわいいからって\nたくさんおまけして\nもらっちゃった…♪", 0, 101, 0, 1, 4, 1, 127701, 8564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると、つい\nぼんやりしちゃう…\nこれも騎士さんの力…\nなのかな", 0, 102, 0, 1, 8, 1, 127701, 8565);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お手伝いできることは\nありませんか？\nお世話でもなんでも\n任せてくださいっ", 0, 1, 0, 2, 1, 1, 127701, 8566);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルに初めて\n来たときは驚きました\n砂糖の山と思ったら…\nあんなに寒いなんて！", 0, 2, 0, 2, 1, 1, 127701, 8567);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、ヴルムを\n見ませんでしたか？\nもう…あの子ってば\nまた仕事をサボって…", 0, 3, 0, 2, 1, 1, 127701, 8568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家具や家が壊れても\n食べられないなんて\nなんだかもったいない\nですね", 0, 4, 0, 2, 1, 1, 127701, 8569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("とっておきの紅茶を\n手に入れたんです\n一杯いかがですか？\nその、日頃のお礼です", 0, 101, 0, 2, 4, 1, 127701, 8570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頑張ってて偉いって…\nほ、褒めてもなんにも\n出ませんからね！？\n…えへへ♪", 0, 102, 0, 2, 8, 1, 127701, 8571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\nモーニングティーは\nいかがですか？\n私、準備しますねっ", 0, 1, 1, 2, 1, 1, 127701, 8572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ライラエルさまも\nお昼寝はお好きです\nけど…だからって\n寝すぎはダメですよ！", 0, 2, 2, 2, 1, 1, 127701, 8573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみなさい\nくれぐれも寝不足には\n気をつけてくださいね", 0, 3, 3, 2, 1, 1, 127701, 8574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかりしないと…\nメイドの私が\n気を抜くなんて…\nそんな…ふぅ…", 0, 2, 0, 3, 1, 1, 127701, 8576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わぁ、かわいい…♪\nってダメダメ！\nメイドなんだから\n落ち着かないと…！", 0, 3, 0, 3, 1, 1, 127701, 8577);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂い…♪\nこの香り、\nライラエルさまも\n好きそうです！", 0, 4, 0, 3, 1, 1, 127701, 8578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの環境に\n触れると、この光の\nありがたみが\n身に沁みますね…", 0, 5, 0, 3, 1, 1, 127701, 8579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘くない食べ物が\n一般的なのも\n慣れてきました\nあむ…おいひぃ…♪", 0, 7, 0, 3, 1, 1, 127701, 8581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの文字、\n私たちのところと\nちょっと違いますね…\n覚えられるかなぁ", 0, 8, 0, 3, 1, 1, 127701, 8582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘い匂いがしない…\nジオ・テオゴニアとは\n別の世界なんですね", 0, 1, 0, 1, 1, 1, 127801, 8584);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("掃除めんど…\nん…このくらいで\nまー十分でしょ", 0, 2, 0, 1, 1, 1, 127801, 8585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ食事の\n用意もしなきゃ…\nあーやる事多い…", 0, 3, 0, 1, 1, 1, 127801, 8586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("秘密の隠れ場所、\nまた姉さんにバレた…\n次のを探さないと", 0, 4, 0, 1, 1, 1, 127801, 8587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知らない間に仕事が\n終わったり…しないか\nしてくれたらいいのに", 0, 5, 0, 1, 1, 1, 127801, 8588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きちんともてなすには\n騎士さんの好みも\n覚えてかないと…", 0, 101, 0, 1, 4, 1, 127801, 8589);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご主人サマに\nご奉仕します～♪\n…キャラじゃないか\nやめやめ、恥ずかし…", 0, 102, 0, 1, 8, 1, 127801, 8590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("居心地いいっすね…\n今日からここに\n住んでもいいですか", 0, 1, 0, 2, 1, 1, 127801, 8591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、ちょっと姉さん\n怒らせちゃったんで\n匿ってくれません？", 0, 2, 0, 2, 1, 1, 127801, 8592);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("羽と尻尾が格好いい？\n意外と邪魔ですよ\n仰向けで寝にくいし", 0, 3, 0, 2, 1, 1, 127801, 8593);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワークライフバランス\nっていい言葉ですね\nぜひライフ多めで", 0, 4, 0, 2, 1, 1, 127801, 8594);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんって\n働き者ですね\nそのままあたしの\n仕事も…いえなんでも", 0, 101, 0, 2, 4, 1, 127801, 8595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("熱心に見てても\n尻尾は触らせて\nあげませんってば\n角？　角なら…まぁ", 0, 102, 0, 2, 8, 1, 127801, 8596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝ても寝ても\n寝足りない…ふぁ…\nあー…眠たい…", 0, 1, 1, 2, 1, 1, 127801, 8597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アフタヌーンティーの\n準備は得意ですよ\nつまみ食いとか\n…つまみ食いとか", 0, 2, 2, 2, 1, 1, 127801, 8598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よく休んでください\n布団は干しといたんで\n…姉さんが", 0, 3, 3, 2, 1, 1, 127801, 8599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふー…\nこのままずーっと\nここに居たい…", 0, 2, 0, 3, 1, 1, 127801, 8601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたも一緒に\nサボっちゃうか～\n…なんて", 0, 3, 0, 3, 1, 1, 127801, 8602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着く匂い…\n騎士さんの好み\nなんですかね", 0, 4, 0, 3, 1, 1, 127801, 8603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうとこの\n掃除って面倒だし…\n今度でいっか", 0, 5, 0, 3, 1, 1, 127801, 8604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ご飯の前に\nこんな食べたら\n姉さんきっと怒るな…", 0, 7, 0, 3, 1, 1, 127801, 8606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食に関する本が\nやけに多い…\nお国柄ですかね", 0, 8, 0, 3, 1, 1, 127801, 8607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すんすん…\nお兄さんの匂いが\nぷんぷんする～♡\nザコくっさぁ♡", 0, 1, 0, 1, 1, 1, 130201, 8609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぴこーん！\nいひひっ、新作メカの\n面白いアイデア、\n思いついちった～♡", 0, 2, 0, 1, 1, 1, 130201, 8610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メカもいじりたいし\n服もアクセもほしー…\nあ～、おこづかい\n足んないよ～！", 0, 3, 0, 1, 1, 1, 130201, 8611);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お勉強でもしよっかな\nザコお兄さんには\n絶対わかんない\nよーなやつ♡", 0, 4, 0, 1, 1, 1, 130201, 8612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんの部屋って\nどこどこぉ？\nメカの実験室に\n使えそうだよね～♡", 0, 5, 0, 1, 1, 1, 130201, 8613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のデートコースは\nどんなのかなー？\n…いや、むしろ次は\nぼくが決めちゃうっ？", 0, 101, 0, 1, 4, 1, 130201, 8614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強奪計画は念入りに♡\nお兄さんのハートも\n全力でザコザコにする\n計画、立てないとね♡", 0, 102, 0, 1, 8, 1, 130201, 8615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねー、ヒマヒマヒマ～\nかまってかまってー♡\nどっか連れてけー♡", 0, 1, 0, 2, 1, 1, 130201, 8616);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はこっちで\nご飯食べたいなー♡\n…帰っても５日連続の\nバカナ姉カレーだし…", 0, 2, 0, 2, 1, 1, 130201, 8617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("依頼行くならぼくも\n連れてってよー♡\nお兄さんのザコっぷり\n見ててあげる～♡", 0, 3, 0, 2, 1, 1, 130201, 8618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんはぼくより\nオトナだもんね～♡\nじゃあオモテナシ、\n期待してるから～♡", 0, 4, 0, 2, 1, 1, 130201, 8619);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヤマ姉になんかお土産\n持って帰ろうかなー？\nザコお兄さん、選ぶの\n付きあって～♡", 0, 101, 0, 2, 4, 1, 130201, 8620);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遊びにいくときは\nザコお兄さんも\n誘ってあげるよ♡\nどうせヒマでしょ～？", 0, 102, 0, 2, 8, 1, 130201, 8621);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁ～、ねむぅ～…\n夜更かしぶん寝るから\nあとで起こして～♡\nあ、変なこと禁止～♡", 0, 1, 1, 2, 1, 1, 130201, 8622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おなかすいたぁ～\nなんか食べ行こ♡\n甘いのおごって～♡", 0, 2, 2, 2, 1, 1, 130201, 8623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えー、もう寝る時間？\nじゃあ…添い寝して\nあげよっか？\nなーんて、ウッソー♡", 0, 3, 3, 2, 1, 1, 130201, 8624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おお～ふわっふわ～♪\nバンディシャーク号の\n座席に使いたーい！", 0, 2, 0, 3, 1, 1, 130201, 8626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カワイイ～♡\n改造したらもっと\nカワイくなるかな～？", 0, 3, 0, 3, 1, 1, 130201, 8627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…いい匂い♡\nザコお兄さんって\nこーゆー香りが\n好きなのかなぁ～", 0, 4, 0, 3, 1, 1, 130201, 8628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はー、あったかーい♡\nバンディシャーク号\nにも欲しいかもー♪", 0, 5, 0, 3, 1, 1, 130201, 8629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べれるときに\n食べるのが大事って\nヤマ姉言ってたしね～", 0, 7, 0, 3, 1, 1, 130201, 8631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、この本読んだよ♡\n参考文献リストが\nしっかりしてて\n勉強になったなー♪", 0, 8, 0, 3, 1, 1, 130201, 8632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋は多少ゴチャつい\nてる方が落ち着くのさ\nバンディシャーク号\nみたいにね♪", 0, 1, 0, 1, 1, 1, 130001, 8634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("呆けてるのもいいが\nちいと物足りないねぇ\n麦しゅわもブドウ朱も\n無いなんてさ", 0, 2, 0, 1, 1, 1, 130001, 8635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この家セキュリティが\nなってないねぇ…\n盗賊目線でちょっくら\n指南でもしてやるか", 0, 3, 0, 1, 1, 1, 130001, 8636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不思議だねぇ\nここで飲むと、酔いが\n回るのが早い気が\nするよ…ヒック", 0, 4, 0, 1, 1, 1, 130001, 8637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…\nクルマが壊れた時は\nアジト代わりに\n使えそうだ♪", 0, 5, 0, 1, 1, 1, 130001, 8638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カカッ、いい部屋だ！\n妹を迎える準備は\nできてるみたいだねぇ", 0, 101, 0, 1, 4, 1, 130001, 8639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…っと、油断したら\n落ち着いちまうね\nボーヤの甘っちょろい\n雰囲気のせいだよ", 0, 102, 0, 1, 8, 1, 130001, 8640);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さすがにこの家から\n盗みはしないさ\nいずれは妹たちの\n共有財産になるからね", 0, 1, 0, 2, 1, 1, 130001, 8641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ボーヤ、暇なら\n博打でもやるかい？\nアタシが負けたら\n掃除でもしてやるよ", 0, 2, 0, 2, 1, 1, 130001, 8642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("立派な家じゃないか！\n一国一城の主とは\nちょっとボーヤのこと\n見くびってたかもねぇ", 0, 3, 0, 2, 1, 1, 130001, 8643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいい義弟のためだ\nアタシが盗ってきた\nお宝をくれてやるよ\n好きな場所に飾りな！", 0, 4, 0, 2, 1, 1, 130001, 8644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妹と結ばれる前に\n他の女との関係は\n清算しとくように\nわかったね、ボーヤ？", 0, 101, 0, 2, 4, 1, 130001, 8645);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、ヤシオーリかい？\nフフン、義弟からの\nお酌とあっちゃあ\n断れないねぇ♪", 0, 102, 0, 2, 8, 1, 130001, 8646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…清々しい朝だが\n頭がいてぇ…\nちっと昨日は\n飲みすぎたか…？", 0, 1, 1, 2, 1, 1, 130001, 8647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほらこれ、ワカナに\n作らせた弁当だ\nこれで昼からも\nバリバリやりな！", 0, 2, 2, 2, 1, 1, 130001, 8648);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだまだ夜はこれから\n…と言いたいとこだが\n早寝して立派に育ちな\nそれが妹たちの為だよ", 0, 3, 3, 2, 1, 1, 130001, 8649);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("中々いい座り心地だが\n盗賊が腑抜ける訳には\nいかないね…が…\nもう少しだけ座るか…", 0, 2, 0, 3, 1, 1, 130001, 8651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのの中に\n実はレアなブツが\n隠されてるとか\nありがちだねぇ", 0, 3, 0, 3, 1, 1, 130001, 8652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふうん、ボーヤは\nこういう匂いが\n好きなのかい？\n妹たちに教えてやろう", 0, 4, 0, 3, 1, 1, 130001, 8653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体を温めんにゃ\n酵露をカッとやるのが\n一番だが、これも存外\n悪くないねぇ…♪", 0, 5, 0, 3, 1, 1, 130001, 8654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ガツガツ…\nん、悪くねェ味だ\nこれにヤシオーリでも\nありゃ文句はないね", 0, 7, 0, 3, 1, 1, 130001, 8656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本にも載ってない\nレアもんのお宝か…\nフッ、想像しただけで\n血沸き肉躍るねぇ…！", 0, 8, 0, 3, 1, 1, 130001, 8657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の買い物は\nいつものお野菜と…\nあっ、確か特売が\nあったはず…！", 0, 1, 0, 1, 1, 1, 130101, 8659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除、お掃除…♪\nきゅっきゅっ…\nよいしょ、っと…", 0, 2, 0, 1, 1, 1, 130101, 8660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("洗濯ものも\nたまらないうちに\nやっちゃわないと…", 0, 3, 0, 1, 1, 1, 130101, 8661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夕飯のメニュー…\n何にしよう？\n期限の早い食材は…", 0, 4, 0, 1, 1, 1, 130101, 8662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("色々お菓子も\n作ってみたいけど…\n予算…足りるかなぁ…", 0, 5, 0, 1, 1, 1, 130101, 8663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さん…どんな\n料理が好きなんだろ？\n前に作ったコロッケは\n評判よかったけど…", 0, 101, 0, 1, 4, 1, 130101, 8664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんと\nおしゃべりすると、\n胸があたたかくなる…\nなんでだろ…？", 0, 102, 0, 1, 8, 1, 130101, 8665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、騎士さん\nどうかしましたか？\n御用ならいつでも…♪", 0, 1, 0, 2, 1, 1, 130101, 8666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("削っても削っても\n家計簿は赤字…\n騎士さ～ん…\n助けてください～！", 0, 2, 0, 2, 1, 1, 130101, 8667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手が空いてたら\n日用品の買い出し、\n手伝ってもらっても\nいいですか…？", 0, 3, 0, 2, 1, 1, 130101, 8668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっと一息つけそう…\nあっ、わたし\nお茶を淹れてきますね", 0, 4, 0, 2, 1, 1, 130101, 8669);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困りごとがあったら\n言ってくださいね\nわたし…騎士さんの\n力になりたいです", 0, 101, 0, 2, 4, 1, 130101, 8670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助けてもらった分は\n必ず返しますから…\nそれまでわたしのこと\n見ててくださいね…♪", 0, 102, 0, 2, 8, 1, 130101, 8671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("忘れ物はないですか？\n今日のお仕事も\n頑張りましょうね…！", 0, 1, 1, 2, 1, 1, 130101, 8672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯できてますよ\n大したものじゃなくて\n恐縮ですけど…", 0, 2, 2, 2, 1, 1, 130101, 8673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしはだめですよ\nわたしも家事を\n終わらせたら寝ないと", 0, 3, 3, 2, 1, 1, 130101, 8674);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これ…割れ物防止の\nクッションに\n使えるかも…？", 0, 2, 0, 3, 1, 1, 130101, 8676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうのいいなぁ…\nけど…フブキちゃんに\n絶対改造されちゃう…", 0, 3, 0, 3, 1, 1, 130101, 8677);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂い…でも\n切れかけてるかも？\nえっと補充するには…", 0, 4, 0, 3, 1, 1, 130101, 8678);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nちょっとだけなら\n休んでも…いいよね", 0, 5, 0, 3, 1, 1, 130101, 8679);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがあったら\nもうお料理を\n作らなくて済むかも？", 0, 7, 0, 3, 1, 1, 130101, 8681);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい節約レシピは…\nあ、この草って\n食べられるんだ…", 0, 8, 0, 3, 1, 1, 130101, 8682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛溢れるランドソルの\nクリスマス…ですか\nいけませんね、つい\n胸が躍ってしまいます", 0, 1, 0, 1, 1, 1, 132801, 8684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ツリーの飾りと\nわたしの髪…\nくるくるしていて\n似ているかも…くすっ", 0, 2, 0, 1, 1, 1, 132801, 8685);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿で傲慢な\nわたしになったら…\nいつもより怖がらせて\nしまうでしょうね…", 0, 3, 0, 1, 1, 1, 132801, 8686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪魔として、人を\nドキドキさせなくては\nい、イオから教わった\n…投げキスの練習を…", 0, 4, 0, 1, 1, 1, 132801, 8687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・テオゴニアの\nお菓子は、ツリーの\n飾りに向いていそう\nですね…ふふっ", 0, 5, 0, 1, 1, 1, 132801, 8688);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士のギルドハウス…\nクリスマスの時期も\n暖かいのですね…", 0, 101, 0, 1, 4, 1, 132801, 8689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("城の皆と過ごす宴も\n楽しいですが…\n騎士と二人の宴も\n幸せです…", 0, 102, 0, 1, 8, 1, 132801, 8690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士、あなたの\nもてなしに感謝します\nクリスマスの何たるか\n教えてくださいね", 0, 1, 0, 2, 1, 1, 132801, 8691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この黒い羽は\nどう手入れすれば？\nイオなら知っている\nでしょうか…", 0, 2, 0, 2, 1, 1, 132801, 8692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("城の皆も連れてきたい\nほど、クリスマスは\n楽しい行事ですね\nお土産も迷います", 0, 3, 0, 2, 1, 1, 132801, 8693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの晩餐に\n招待されたのですが…\nその…辛いものは\nありませんよね…？", 0, 4, 0, 2, 1, 1, 132801, 8694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスと言わず…\nいつでも星に祈って\nいますよ？　騎士達に\n幸せがあるように、と", 0, 101, 0, 2, 4, 1, 132801, 8695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪魔として騎士を\nドキドキさせる…？\nそ、そのようなこと\nわたしには…うぅ…", 0, 102, 0, 2, 8, 1, 132801, 8696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝は寒いですね…\n雪…積もっている\nでしょうか？", 0, 1, 1, 2, 1, 1, 132801, 8697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふあぁ…いけません\n公務の滞在先で\nお昼寝など…", 0, 2, 2, 2, 1, 1, 132801, 8698);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜は悪魔として\n夢を見せましょう\n騎士はどんな夢が\n見たいですか？", 0, 3, 3, 2, 1, 1, 132801, 8699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…落ち着きます…\n家でゆっくりと過ごす\nクリスマスも\n良いものですね", 0, 2, 0, 3, 1, 1, 132801, 8701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リンドのプレゼントに\nぬいぐるみは…？\n…子ども扱いすると\n落ち込むでしょうか…", 0, 3, 0, 3, 1, 1, 132801, 8702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かいお部屋に\nこの香りを漂わせたら\nふふっ…素敵な時間を\n過ごせそうです", 0, 4, 0, 3, 1, 1, 132801, 8703);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがあれば、\n寒い冬も安心ですね\n暖かくて…このまま\n眠ってしまいそうです", 0, 5, 0, 3, 1, 1, 132801, 8704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪魔の力を使ったら\nお腹が空いてきて\nしまって…\n恥ずかしいです…", 0, 7, 0, 3, 1, 1, 132801, 8706);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスには多くの\n伝承があるのですね…\n天使の伝承まで\nありましたし…", 0, 8, 0, 3, 1, 1, 132801, 8707);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まぁ…！\nよくできていますね\nサプライズプレゼント\n…でしょうか。ふふ♪", 0, 14, 0, 3, 1, 1, 132803, 8709);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ど、どうでしょう…？\n親善交流の催しに\nなりそうでしょうか…", 0, 15, 0, 3, 1, 1, 132804, 8710);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスって\nあったかぁ～い♪\n心がぽかぽかするの！", 0, 1, 0, 1, 1, 1, 132901, 8711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの悪魔の\nお仕事はないわね！\nだってここのみんな\nいい子なんですもの♪", 0, 2, 0, 1, 1, 1, 132901, 8712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなちゃんと\n寝られてるかしら？\n夜更かしせずに、\nいい夢見てね♪", 0, 3, 0, 1, 1, 1, 132901, 8713);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎回、来年が\n楽しみになるような\n素敵なクリスマスを\n過ごしたいわね♪", 0, 4, 0, 1, 1, 1, 132901, 8714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("訳ありケーキを見ると\n刑務作業を思い出すわ\n…あれも貴重な体験\nだったのかしら…？", 0, 5, 0, 1, 1, 1, 132901, 8715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ロマンチックな\nクリスマスに備えて\n今のうちに少女漫画で\n予習しておかないと！", 0, 101, 0, 1, 4, 1, 132901, 8716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほっぺにチューなら\nもう一回しても…\nや、やっぱり無理！\n恥ずかしいわ～！", 0, 102, 0, 1, 8, 1, 132901, 8717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またみんなで\nセッションしたいわね\nカラーベルの練習した\n成果を見せたいの♪", 0, 1, 0, 2, 1, 1, 132901, 8718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("君はサンタさんに\nどんなプレゼントを\n頼んでいたのかしら？\n気になるわ～！", 0, 2, 0, 2, 1, 1, 132901, 8719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛が壊れても、\n何度でも治してあげる\n私たちの間に、\n愛の尽きる日はないわ", 0, 3, 0, 2, 1, 1, 132901, 8720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冬休みって短いようで\n長く感じちゃうわよね\n学校のみんなと\n早く会いたいな～♪", 0, 4, 0, 2, 1, 1, 132901, 8721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛をテーマにした\n冬休みの作文の宿題、\n君の分を読むのが\n今から楽しみね♪", 0, 101, 0, 2, 4, 1, 132901, 8722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よかったらまた\n私をハニーって呼んで\nほしいの。ダーリン♪", 0, 102, 0, 2, 8, 1, 132901, 8723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！\n冬の朝は冷えるから\n風邪を引かないように\n対策しましょうね", 0, 1, 1, 2, 1, 1, 132901, 8724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯は一緒に\n食べに行きましょう！\nクリスマス限定の\nランチコースよ♪", 0, 2, 2, 2, 1, 1, 132901, 8725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえねえ、キャンドル\nイルミネーションを\n見に行きましょうよ！\nロマンチックよ～♪", 0, 3, 3, 2, 1, 1, 132901, 8726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かいクリスマスを\n過ごすのに必須よね♪\nふふ、柔らかぁい！", 0, 2, 0, 3, 1, 1, 132901, 8728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どの子もかわいい～♪\nクリスマスツリーの\n下で、一緒にお祝い\nしてもらいたいな♪", 0, 3, 0, 3, 1, 1, 132901, 8729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか胸の奥が\n温かくなる匂いね～\nリラックスしちゃう♪", 0, 4, 0, 3, 1, 1, 132901, 8730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかぁい♪\nあ、でも夜になったら\nサンタさんが入れる\nように、火を消すのよ", 0, 5, 0, 3, 1, 1, 132901, 8731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い冬だからこそ\nしっかり食べて\n備えておかなきゃ！", 0, 7, 0, 3, 1, 1, 132901, 8733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『聖夜の６時間』…？\n気になる小説だけど…\n勝手に読んじゃ悪い\nわよね…ガマンよ…！", 0, 8, 0, 3, 1, 1, 132901, 8734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きゃっ…！\nこんな不思議な本が\nあったのね～\nちょっと面白いかも♪", 0, 14, 0, 3, 1, 1, 132901, 8736);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もふもふ、ふわふわで\nあったかくて\n気持ちいい～…♪", 0, 15, 0, 3, 1, 1, 132901, 8737);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冬といえばサマー！\n…って言うけど夏は\n何をＰＲするんだろ\nメルクリゾート…", 0, 1, 0, 1, 1, 1, 129501, 8738);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("奨学金の道は遠いな…\nあまりに遠すぎて\n最近忘れてたまである", 0, 2, 0, 1, 1, 1, 129501, 8739);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暇だし鏡でも見よっと\nはー、今日も顔が良…\nげ、若干むくんでる？\nはー、今日終わった", 0, 3, 0, 1, 1, 1, 129501, 8740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着…お姉ちゃんと\n貸し借りするんだけど\nこれって少数派姉妹？", 0, 4, 0, 1, 1, 1, 129501, 8741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゅむ、ツムギちゃん\n今日も可愛いねデュフ\n…なんで推し語りの声\nキモくなるんだろ私…", 0, 5, 0, 1, 1, 1, 129501, 8742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ…なんで私\n水着のまま部屋の中\nうろついてるんだっけ\n…こわ！　てか寒っ！", 0, 101, 0, 1, 4, 1, 129501, 8743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩よく友達と海に\n行くって言ってたけど\n…え、誰とだろ？\nまあ誰でもいいけどさ", 0, 102, 0, 1, 8, 1, 129501, 8744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("始まる…\nチエルの夏が始まる…\nあ冬でしたっけ？\nまどっちでもいいです", 0, 1, 0, 2, 1, 1, 129501, 8745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こないだトミヱ先輩\n壁に喧嘩売ってました\n相変わらず元気ですね", 0, 2, 0, 2, 1, 1, 129501, 8746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユニ先輩にお芝居の\n出来を聞かれたんで\n可愛いって答えました\n嘘は言ってません", 0, 3, 0, 2, 1, 1, 129501, 8747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クロエ先輩の腹筋\nかっちょいーですよね\nさりげ触りたいけど\nあいつ隙ないんですよ", 0, 4, 0, 2, 1, 1, 129501, 8748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩もうカメラ係は\nやらないんです？\nチエルはやってますよ\n最高の被写体を常に", 0, 101, 0, 2, 4, 1, 129501, 8749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メリゾでカップル割の\n企画あるらしいんです\nちなみに先輩は…\nあ、いえ、何でも…", 0, 102, 0, 2, 8, 1, 129501, 8750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ごはんは抜いても\n朝ちぇるだけは\n抜いちゃ駄目ですよ", 0, 1, 1, 2, 1, 1, 129501, 8751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼なに食べるか\n悩んでます？\nおごってくれるなら\nいい店教えますけど", 0, 2, 2, 2, 1, 1, 129501, 8752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間帯になると\nユニ先輩がごそごそ\n蠢きだすんですよね…", 0, 3, 3, 2, 1, 1, 129501, 8753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界の美少女が…\nこんな格好で\nくつろいでたら…\nまずい…事案になる", 0, 2, 0, 3, 1, 1, 129501, 8755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え、この子って\nウォータープルーフ？\nメリゾにも連れて\nいけちゃうカンジ？", 0, 3, 0, 3, 1, 1, 129501, 8756);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～、いい香り…\nそういえばメリゾの\nスタッフルームも\n『贅』な匂いしてた…", 0, 4, 0, 3, 1, 1, 129501, 8757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("薄着で暖まるとか…\n冷静になっちゃ\n駄目なやつですよね\nこれ…", 0, 5, 0, 3, 1, 1, 129501, 8758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おにぎり１個は\nちぇるに換算すると…\n２５ちぇるくらい？", 0, 7, 0, 3, 1, 1, 129501, 8760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれー？　この辞書\nまだちぇるの項目\n載ってないんだ？", 0, 8, 0, 3, 1, 1, 129501, 8761);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何これ…地味に楽しい\nあとたぶん\nクロエ先輩が好きそう", 0, 10, 0, 3, 1, 1, 129501, 8763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは良きですねー\n自宅でメリゾ気分とか\nユニ先輩もにっこり", 0, 11, 0, 3, 1, 1, 129501, 8764);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここが騎士氏の\nお住まいですか\nふむ…地縛霊は\nいなさそうですね", 0, 1, 0, 1, 1, 1, 133001, 8765);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは土足厳禁では\nないみたいですね\nま、私には関係ないか\n足、透っけ透けなので", 0, 2, 0, 1, 1, 1, 133001, 8766);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの裏路地\nあそこは最高ですね\n暗くてじめじめしてて\n癒されるー", 0, 3, 0, 1, 1, 1, 133001, 8767);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("っ！\n今ラップ音が…？\nまさか幽霊？\nやだ、怖い", 0, 4, 0, 1, 1, 1, 133001, 8768);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("獣人族にエルフ族…\nなるほど騎士氏が\n幽霊程度では驚かない\n訳です…ちぇ", 0, 5, 0, 1, 1, 1, 133001, 8769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の深夜\n騎士氏が起きるまで\n枕元でずーっと\n立っててみようかな", 0, 101, 0, 1, 4, 1, 133001, 8770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士氏の驚く顔を\n見ると胸が高鳴る…\n変ですね、心臓なんて\n動いてないのに", 0, 102, 0, 1, 8, 1, 133001, 8771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("安心して下さい\n勝手にすり抜けて\n騎士氏の部屋は\n覗きませんよ…多分", 0, 1, 0, 2, 1, 1, 133001, 8772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんですか騎士氏\n怖い話でも聞きます？\nじゃあいきますね…\n今貴方の前に幽霊がっ", 0, 2, 0, 2, 1, 1, 133001, 8773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この家…幽霊が\n寄ってくる間取りに\nなってますね\nまあ、嘘ですけど", 0, 3, 0, 2, 1, 1, 133001, 8774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理はしませんよ\n指きったら痛いので\nえ…透ければいい？\n……天才ですか？", 0, 4, 0, 2, 1, 1, 133001, 8775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お散歩ですか？\n深夜なら付き合います\nあ、やっぱり断ります\n幽霊出たら怖いので", 0, 101, 0, 2, 4, 1, 133001, 8776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士氏の部屋のセンス\n好きですよ…もっと\nじめじめしていれば\nなおよし、ですが", 0, 102, 0, 2, 8, 1, 133001, 8777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("レイスになってから\nあまり言わなくなった\n挨拶第一位はこちら…\nおはようございます", 0, 1, 1, 2, 1, 1, 133001, 8778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士氏。午後からも\n頑張って下さいね\n私は日陰で休みます\nでは、おつです", 0, 2, 2, 2, 1, 1, 133001, 8779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜も更けてきましたね\nここからがレイスの\n本領発揮…では早速\nう　ら　め　し　や～", 0, 3, 3, 2, 1, 1, 133001, 8780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("中々座り心地が\nよろしいですね\nブロッケンに跨る方が\n安心はしますが", 0, 2, 0, 3, 1, 1, 133001, 8782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知ってますよ\nどうせ貴方も\n夜中になったら\n動き回るんでしょ？", 0, 3, 0, 3, 1, 1, 133001, 8783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すう…はあ…\nすごく落ち着く香り\n…落ち着き過ぎて\n成仏しそうでした", 0, 4, 0, 3, 1, 1, 133001, 8784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温度は感じませんが\nなぜかほっこり\n温かい気持ちです\nなんででしょうね？", 0, 5, 0, 3, 1, 1, 133001, 8785);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…\n食べ物は基本好きです\n消化の方法は…\n企業秘密で", 0, 7, 0, 3, 1, 1, 133001, 8787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("苦手なんですよね\nホラー小説\nだって幽霊とか\n怖いじゃないですか", 0, 8, 0, 3, 1, 1, 133001, 8788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この得も言われぬ\n高揚感…やはり\n正月はいいものだな！", 0, 1, 0, 1, 1, 1, 133201, 8790);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("む、いかんな\n気付くと黒豆と\n栗きんとんばかり\n食べてしまう…", 0, 2, 0, 1, 1, 1, 133201, 8791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドの連中にも\nお年玉を渡してみるか\n少しは士気が上がる\nかもしれないな！", 0, 3, 0, 1, 1, 1, 133201, 8792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月くらいはのんびり\n羽を伸ばすとしよう\n適切な休暇も軍人の\n大事な責務だからな", 0, 4, 0, 1, 1, 1, 133201, 8793);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月で浮かれすぎた\n者も多いはずだ\n念のため街を見回りに\n行くとしよう", 0, 5, 0, 1, 1, 1, 133201, 8794);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("む、このおせち料理は\n絶品だな！\nあいつの分も\nとっておいてやろう", 0, 101, 0, 1, 4, 1, 133201, 8795);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年の抱負は…\nそうだな、あいつと\nさらに高みを目指す\nこれでいこう", 0, 102, 0, 1, 8, 1, 133201, 8796);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えっ、お年玉！\n…い、いや、私は\n子どもではないからな\nえ、遠慮させてもらう", 0, 1, 0, 2, 1, 1, 133201, 8797);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("凧あげすごろく\nこま回し、たとえ遊び\nでも手は抜かんぞ\nさあ、勝負だ！", 0, 2, 0, 2, 1, 1, 133201, 8798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そのきな粉餅も\nうまそうだな…\n私のあんこと交換\nしないか？", 0, 3, 0, 2, 1, 1, 133201, 8799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公、正月料理を\n食べ過ぎてないか？\nじ、実は私も少々、な", 0, 4, 0, 2, 1, 1, 133201, 8800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公、お参りに行くぞ\n何？　外が寒いだと？\n仕方ない、手ぐらいは\nつないでやろう", 0, 101, 0, 2, 4, 1, 133201, 8801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴公と新たな年を\n迎えられてうれしいぞ\n今年も一つ\nよろしくたのむ！", 0, 102, 0, 2, 8, 1, 133201, 8802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きろ貴公。早朝なら\n参拝客も少ないはず\n今のうちにお参りを\n済ませよう", 0, 1, 1, 2, 1, 1, 133201, 8803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食に餅を焼いたぞ\nのどに詰まらせない\nようにゆっくり噛んで\n食べるんだ", 0, 2, 2, 2, 1, 1, 133201, 8804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜ふかしはあまり\n褒められたものでは\nないが…正月くらいは\n目をつむろう", 0, 3, 3, 2, 1, 1, 133201, 8805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これに座って飲む\n甘酒は格別だな", 0, 2, 0, 3, 1, 1, 133201, 8807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの正月だし\nこいつにも着物を\n着せてやりたいな", 0, 3, 0, 3, 1, 1, 133201, 8808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは梅の香り…？\nふふ、なかなか\n風流ではないか", 0, 4, 0, 3, 1, 1, 133201, 8809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冬の寒さが堪えるな…\nここでしっかりと\n暖をとるとしよう", 0, 5, 0, 3, 1, 1, 133201, 8810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月はのんびり\nしたいからな、勝手に\n食事が出てくるのは\n本当に助かる", 0, 7, 0, 3, 1, 1, 133201, 8812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、これが世界の\n新年のお祝いか\nなかなか興味深いな", 0, 8, 0, 3, 1, 1, 133201, 8813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一年の計は元旦にあり\n計画を立てて、\n有意義な一年を\n過ごしましょ", 0, 1, 0, 1, 1, 1, 133501, 8815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("年末年始はどうしても\n出費が増えちゃうし\nしばらくはきっちり\n節約しなきゃ…！", 0, 2, 0, 1, 1, 1, 133501, 8816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("タタミにフトン、\nトーゴク文化の内装…\nランドソルでももっと\n流行らないかしら", 0, 3, 0, 1, 1, 1, 133501, 8817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子どもたちが凧を\n手作りして遊んでたの\n偉いわよね、みんな…", 0, 4, 0, 1, 1, 1, 133501, 8818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お年玉をあげる側に\nなって、分かる苦労…\n大人になるって\nこういうことかしら", 0, 5, 0, 1, 1, 1, 133501, 8819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一応実家にも\n顔を出さないと…\nよかったらだけど、\nあんたも来る？", 0, 101, 0, 1, 4, 1, 133501, 8820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("毎日一緒にいて、\nささやかな幸せを\n同じように感じて…\nそれだけで十分ね", 0, 102, 0, 1, 8, 1, 133501, 8821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物姿、もっと\nじっくり見たいの？\nさすがに照れるわよ、\nもう…", 0, 1, 0, 2, 1, 1, 133501, 8822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("整理整頓、できてる？\nもし散らかってるなら\nお正月休みのうちに\n片づけちゃいましょ", 0, 2, 0, 2, 1, 1, 133501, 8823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年もみんなが無事に\n過ごせますように…\nほら、一緒に\nお祈りしましょ", 0, 3, 0, 2, 1, 1, 133501, 8824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんな、あんたと\n遊ぶのが楽しみだって\n子どもに好かれる\nタイプなのよね", 0, 4, 0, 2, 1, 1, 133501, 8825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたの運勢は大吉！\nラッキーパーソンは\n金髪の幼なじみよ\n…なんてねっ", 0, 101, 0, 2, 4, 1, 133501, 8826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初夢は実現するのよね\nそれじゃ、あたしは\nあんたと…んんっ\nなんでもないわ", 0, 102, 0, 2, 8, 1, 133501, 8827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外が寒いと、その分\n目も冴えるわよね\nこのまま朝の散歩に\n行こうかしら", 0, 1, 1, 2, 1, 1, 133501, 8828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月休みでも、\n食べてばっかじゃダメ\nしっかり動いて\n体を引き締めましょ", 0, 2, 2, 2, 1, 1, 133501, 8829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちゃんとあったかく\nして寝るのよ\nお正月から\n風邪ひかないようにね", 0, 3, 3, 2, 1, 1, 133501, 8830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物、しわに\nなっちゃいそう…\nでもそれ以上に、\n心地よくって…はぁ", 0, 2, 0, 3, 1, 1, 133501, 8832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("門松みたいに\nこの子も飾ってみる？\n運勢がよくなるかも♪", 0, 3, 0, 3, 1, 1, 133501, 8833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い、もしかして\nトーゴクのお香？\nワビサビを感じるわ", 0, 4, 0, 3, 1, 1, 133501, 8834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ、あったかい…\n冷えた体に\n染み渡ってくるわ…", 0, 5, 0, 3, 1, 1, 133501, 8835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("んっ、おいしい！\nおせちばっかじゃ\nやっぱり飽きちゃう\nものね…", 0, 7, 0, 3, 1, 1, 133501, 8837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("験担ぎとか縁起物とか\n調べてみると\nいろいろあって\n面白いのよね～", 0, 8, 0, 3, 1, 1, 133501, 8838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふーん、いい家ね\nアタシの巣に\nしちゃおうかしら？", 0, 1, 0, 1, 1, 1, 133601, 8840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃん…\n早く会いたいなぁ…", 0, 2, 0, 1, 1, 1, 133601, 8841);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("メドゥシアナも\n気に入るかしら？\n今度連れてこよっと！", 0, 3, 0, 1, 1, 1, 133601, 8842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お邪魔してるだけ\nなのも悪いわよね…\nお返しはしないとね\n…ネズミ退治とか？", 0, 4, 0, 1, 1, 1, 133601, 8843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何か平和よね\nランドソルって…\nアタシ的にはもう少し\n荒っぽくてもいいわ", 0, 5, 0, 1, 1, 1, 133601, 8844);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルも\n楽しい街よね…\n案内してくれる\nアイツのおかげ？", 0, 101, 0, 1, 4, 1, 133601, 8845);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシ、アイツに\n頼りすぎてるかも…？\nで、でも！　断らない\nアイツも問題だわ！", 0, 102, 0, 1, 8, 1, 133601, 8846);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、つまんなーい！\nもっとアタシを\n楽しませなさいよねー", 0, 1, 0, 2, 1, 1, 133601, 8847);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この家悪くないけど…\nもっとムシムシ\nジメジメにできない？", 0, 2, 0, 2, 1, 1, 133601, 8848);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何よ？\n用もないのに声掛けた\n…とか言ったら\n容赦しないわよ？", 0, 3, 0, 2, 1, 1, 133601, 8849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し部屋が寂しいわね\nそうだ、アンタを\n石にして家具に…\n冗談よ、ふふんっ♪", 0, 4, 0, 2, 1, 1, 133601, 8850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ、もう少し\n話していかない？\nアンタの話なら…\n特別に聞いてあげるわ", 0, 101, 0, 2, 4, 1, 133601, 8851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("い、いつも\nあ、あ、ありが…\nうぅ、何でもないー！", 0, 102, 0, 2, 8, 1, 133601, 8852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やっと起きたわね？\n寝ぼすけなんだから！\n尻尾でひっぱたいて\n起こそうかと思ったわ", 0, 1, 1, 2, 1, 1, 133601, 8853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人捜しは日の高い\nうちに限るわ！\nさぁ、メドゥシアナ！\n全速力で出発進行よ!", 0, 2, 2, 2, 1, 1, 133601, 8854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アタシ…\n子どもじゃないもん…\n眠くなんか…\nないんだからぁ…", 0, 3, 3, 2, 1, 1, 133601, 8855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわであったかい\nつい、とぐろを\n巻きたくなるわね…", 0, 2, 0, 3, 1, 1, 133601, 8857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アンタ、こんな\nヤワな体じゃ駄目よ\nウロコくらい\n生やしたらどうなの？", 0, 3, 0, 3, 1, 1, 133601, 8858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…\n…ふん\n悪くないじゃない\n…くんくんくんくん…", 0, 4, 0, 3, 1, 1, 133601, 8859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかいの大好き！\nジオ・ゲヘナでも\nよく日向ぼっこ\nしたもんだわ…ふわぁ", 0, 5, 0, 3, 1, 1, 133601, 8860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんを捜すなら\n…もぐ\n体力つけないとね\n…もぐもぐ", 0, 7, 0, 3, 1, 1, 133601, 8862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何よ？　たまには\n勉強くらいするわよ\nお姉ちゃんに\n笑われちゃうもの", 0, 8, 0, 3, 1, 1, 133601, 8863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この装いと力…\n今の世界との\n整合性を上手いこと\n合わせておかないとだ", 0, 1, 0, 1, 1, 1, 133701, 8865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好…開発してた\n当時のまんまだ\nサイズもそのまま♪\n体型維持も完璧っ！", 0, 2, 0, 1, 1, 1, 133701, 8866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あとで装備の手入れも\nやっとかないと\n…剣なら研ぐだけで\n終わるんだけどなぁ", 0, 3, 0, 1, 1, 1, 133701, 8867);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("自分の原点を\n振り返ってみるのも\nたまには必要だね", 0, 4, 0, 1, 1, 1, 133701, 8868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("完璧じゃなくても\n今できる全力を尽くす\nその事に意味がある…\nそうだよね、少年", 0, 5, 0, 1, 1, 1, 133701, 8869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("始まりのあの日、\nそして向かうべき道…\nいつも忘れずにいよう", 0, 101, 0, 1, 4, 1, 133701, 8870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰かを救うために\n許容される犠牲なんて\nあっちゃいけない…\n全部、助けてやる", 0, 102, 0, 1, 8, 1, 133701, 8871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっと少年、\n何か御用かな？\nキミに関わる事なら\n最優先で対応するよ", 0, 1, 0, 2, 1, 1, 133701, 8872);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("困った事があれば\n頼ってもらって\n構わないからね！\nむしろもっと頼って！", 0, 2, 0, 2, 1, 1, 133701, 8873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そうだ、時間あるなら\n武器のメンテを\n手伝ってくれないかな\n数が多くてさ～", 0, 3, 0, 2, 1, 1, 133701, 8874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遠距離戦の心得、\n少年にもレクチャー\nしてあげよっか？", 0, 4, 0, 2, 1, 1, 133701, 8875);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無茶しないで、って\n言ってもするだろうし\nせめてアタシの手が\n届く範囲で頼むよ", 0, 101, 0, 2, 4, 1, 133701, 8876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("虚実入り混じる\nこの世界でキミが…\n進むべきルートを\n照らしてくれたんだ", 0, 102, 0, 2, 8, 1, 133701, 8877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グッモーニン！\n朝だよ少年、今日も\n張り切っていこう！", 0, 1, 1, 2, 1, 1, 133701, 8878);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クレープの代わりに\nガレットを焼いたんだ\nこの味で少年を\n唸らせてみせよう！", 0, 2, 2, 2, 1, 1, 133701, 8879);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうこんな時間だ\n遅くならないうちに\n作業を切り上げようか\n少年も早く寝なよ？", 0, 3, 3, 2, 1, 1, 133701, 8880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あえて緊張を解くのも\n戦いには必要だし…\nそうそう…大事大事…", 0, 2, 0, 3, 1, 1, 133701, 8882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛着を抱かせる事を\n意図したデザインだね\n心理的効果の観点から\n分析してみようか…", 0, 3, 0, 3, 1, 1, 133701, 8883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りは記憶と密接に\n結びつく事がある…\n懐かしい匂いだね…", 0, 4, 0, 3, 1, 1, 133701, 8884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("癒されるな…\n何がこの感情変化を\n引き起こすんだろう？", 0, 5, 0, 3, 1, 1, 133701, 8885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食の偉大さを感じるな\n戦闘糧食ってやっぱり\n味気ないしなぁ…", 0, 7, 0, 3, 1, 1, 133701, 8887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実用ばかりじゃなく\n詩や物語ってのも\n人には必要だよね", 0, 8, 0, 3, 1, 1, 133701, 8888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この場所の開発版も\n探せばあるかもな\nさて、どんなデザイン\nだったのやら…", 0, 1, 0, 1, 1, 1, 133901, 8890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今まで数々の波乱に\n身を投じたが…やはり\n波乱にはこの姿が一番\n似合いだよ☆", 0, 2, 0, 1, 1, 1, 133901, 8891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むっ…この角に羽と\n尻尾は家具とぶつかり\nやすいな。兎の時は\n気にならなかったが…", 0, 3, 0, 1, 1, 1, 133901, 8892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつもより闘争を\n求める気分になるな\n初心に帰るとは\nこのことか…？", 0, 4, 0, 1, 1, 1, 133901, 8893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("未調整上等☆\nそれを上手く使い\nこなしてこその\nワタシだろう？", 0, 5, 0, 1, 1, 1, 133901, 8894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("坊やとできそうな\n愉しいことは…\nふむ、多すぎて迷うな", 0, 101, 0, 1, 4, 1, 133901, 8895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時折、坊やの居心地の\nよさに絆されそうに\nなってしまうな\nワタシらしくもない…", 0, 102, 0, 1, 8, 1, 133901, 8896);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうだ、おろした\n髪型も艶やかだろう？\nそんじょそこらの\n賞賛では満足せんぞ☆", 0, 1, 0, 2, 1, 1, 133901, 8897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外に出るぞ！\n共に退屈を殺しに\n行こうじゃないか☆", 0, 2, 0, 2, 1, 1, 133901, 8898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("角と翼も触りたい？\nワタシの虚数魔境に\n挑むというなら\n止めはせんよ☆", 0, 3, 0, 2, 1, 1, 133901, 8899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだ、困りごとか？\nクリスティーナさんが\n何でも聞いてやろう☆\n解決するかは別だがな", 0, 4, 0, 2, 1, 1, 133901, 8900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("力が欲しいか？\nならば呼ぶがいい！\nワタシの名を☆", 0, 101, 0, 2, 4, 1, 133901, 8901);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪魔との契約は絶対\nなのだそうだが…\nどうだ、坊や\n一つ契ってみるか？", 0, 102, 0, 2, 8, 1, 133901, 8902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ眠い？　甘えるな\n寝首を掻かれたく\nなければ飛び起きて\nこい…☆", 0, 1, 1, 2, 1, 1, 133901, 8903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食の準備を\nしてやろう。\n毒見はいらんぞ？\n安心するといい！", 0, 2, 2, 2, 1, 1, 133901, 8904);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("坊やは寝る時間だ\n寝ないのならば…\n大人の時間に\n付き合ってもらうか☆", 0, 3, 3, 2, 1, 1, 133901, 8905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("角と翼、尻尾の\nコンディションまで\n完璧だな☆", 0, 1, 0, 3, 1, 1, 133901, 8906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなかのフワモコ\n具合だが…ううむ…\n翼と尻尾が邪魔だな", 0, 2, 0, 3, 1, 1, 133901, 8907);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーむ、角と尻尾を\n追加して…さらに槍を\n持たせた方が見栄えが\nよさそうだ", 0, 3, 0, 3, 1, 1, 133901, 8908);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだな\n血と砂塵の臭いで\n上書きするまでの\n間に合わせに最適だ☆", 0, 4, 0, 3, 1, 1, 133901, 8909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生温いな\nもっと焦がれるほどの\n熱量が欲しいところだ", 0, 5, 0, 3, 1, 1, 133901, 8910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段はないものが\n生えているのだから、\n運動でしっかり感覚を\n掴んでおかなければな", 0, 6, 0, 3, 1, 1, 133901, 8911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腹が減っては戦は…\nと言うからな\nしっかり食べて\nおくとしようか☆", 0, 7, 0, 3, 1, 1, 133901, 8912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『家庭を築くための\n絶対条件』…？\nふむ…興味がある\nタイトルだ", 0, 8, 0, 3, 1, 1, 133901, 8913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("奇妙な感覚です\nまるであの頃の自分に\n変装しているかのよう", 0, 1, 0, 1, 1, 1, 133801, 8915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("グレゴール？\nおっと、そうでした\n今は昔の姿になって\n離れていましたね", 0, 2, 0, 1, 1, 1, 133801, 8916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このアバターでいると\n妙に子どもたちからの\n視線を感じますね…", 0, 3, 0, 1, 1, 1, 133801, 8917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リソースの割り振りが\n変わっただけなのに\n随分と身体が軽く\n感じますね", 0, 4, 0, 1, 1, 1, 133801, 8918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段グレゴールに\n任せている分身の管理\n自分でやるには\nいささか煩雑ですね…", 0, 5, 0, 1, 1, 1, 133801, 8919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("長老に頼まれて描いた\n妖精の絵…いったい\n何に使ったのでしょう", 0, 101, 0, 1, 4, 1, 133801, 8920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私自身をモデルにした\n完全なるNPCたち\nそれが私の分身です", 0, 102, 0, 1, 8, 1, 133801, 8921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このアバターが\n気になるのですか？\n貴方はつくづく\n妖精に縁がありますね", 0, 1, 0, 2, 1, 1, 133801, 8922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどよかった\nグレゴールを見かけ\nませんでしたか？", 0, 2, 0, 2, 1, 1, 133801, 8923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの翅は飾りでは\nありません。ただ…\nグレゴールに乗って\n飛ぶ方が楽なだけです", 0, 3, 0, 2, 1, 1, 133801, 8924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妖精とは本来神話に\nおけるトリックスター\n運命をかき回すことが\n存在意義なのです", 0, 4, 0, 2, 1, 1, 133801, 8925);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変貌大妃の権能との\n相性を考えなければ\nこの姿こそが私たちの\n最強の姿です", 0, 101, 0, 2, 4, 1, 133801, 8926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変化とは一種の喪失\nだからこそ得られる物\nがある…貴方のそれも\n大切にするのですよ", 0, 102, 0, 2, 8, 1, 133801, 8927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マサキからの定時連絡\nが来ませんね…心配は\n不要ですが、様子を\n見に行きましょうか", 0, 1, 1, 2, 1, 1, 133801, 8928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食の時間ですね\nグレゴールのために\nカロリーの高い物を\n食べに行きましょう", 0, 2, 2, 2, 1, 1, 133801, 8929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜更かしはダメですよ\n悪いスパイが暗躍して\nいる時間帯ですからね", 0, 3, 3, 2, 1, 1, 133801, 8930);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、座り心地は中々\nですが…私にはやはり\n玉座の方があいますね", 0, 2, 0, 3, 1, 1, 133801, 8932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、いいでしょう\n我が配下に加えます\n存分に働きなさい", 0, 3, 0, 3, 1, 1, 133801, 8933);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時折晶からしていた\nあの甘い匂いは何の\nアロマだったのか…", 0, 4, 0, 3, 1, 1, 133801, 8934);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("燃え盛る炎もこうして\n暖炉の中なら安全です\nクリスもあの衝動を\n管理さえできれば…", 0, 5, 0, 3, 1, 1, 133801, 8935);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そういえば真那が\n獄中で手持無沙汰に\nひたすらおにぎりを\n食べていましたね…", 0, 7, 0, 3, 1, 1, 133801, 8937);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは、妖精学の本…\n長老の蔵書から借りて\n読みふけったものです", 0, 8, 0, 3, 1, 1, 133801, 8938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんな詩を\n作ろうかしら…？\n…大体、暗く\nなっちゃうけど…", 0, 1, 0, 1, 1, 1, 134301, 8940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("唱喚術の練習…\nここでやったら\n迷惑よね…", 0, 2, 0, 1, 1, 1, 134301, 8941);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("チカちゃんとの\nデュエット…\n足をひっぱってない…\nかしら…？", 0, 3, 0, 1, 1, 1, 134301, 8942);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("唱喚士の修行…\n滝に打たれるとか…\n崖を登るとか…\nなくて、よかった…", 0, 4, 0, 1, 1, 1, 134301, 8943);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊さん、肉じゃが\n食べる、かしら…？\n魔力だけだと…\n飽きちゃいそうだし…", 0, 5, 0, 1, 1, 1, 134301, 8944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊さんのお世話に\n慣れたぶん…\nあのひとのお世話も\n上手にできる…はず？", 0, 101, 0, 1, 4, 1, 134301, 8945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これからも、歌うわ…\nこの声が、彼の力に\nなる、限り──", 0, 102, 0, 1, 8, 1, 134301, 8946);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服…踊り子さんに\n間違われちゃって…\nあ…お、お触りしちゃ\nだめよ…？", 0, 1, 0, 2, 1, 1, 134301, 8947);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたはどんな\n精霊が…好き…？\n唱喚…してみたいわ…", 0, 2, 0, 2, 1, 1, 134301, 8948);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんまり白い服って…\n着ないの…その…\nこ、ころんだりして…\n汚すから…", 0, 3, 0, 2, 1, 1, 134301, 8949);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じ、実はね…\nこの体の模様…筆で\n書いてもらうたび…\nくすぐったい…の…", 0, 4, 0, 2, 1, 1, 134301, 8950);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊さん…あなたと\n遊びたいみたい…\nや、やっぱり…\nパパ…だから…？", 0, 101, 0, 2, 4, 1, 134301, 8951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたを歌にしたら…\n…ふふっ、だめね\n一曲じゃ…あなたを\n表現できない、わ…", 0, 102, 0, 2, 8, 1, 134301, 8952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝の修行は…\nうとうと…し…ちゃ…\n……（かくん）\n……あぅっ？", 0, 1, 1, 2, 1, 1, 134301, 8953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せ、精霊さんと…\nかくれんぼ中なの…\nうぅ…見つからない…\n日が暮れちゃいそう…", 0, 2, 2, 2, 1, 1, 134301, 8954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊さん、寝たから…\nふふっ…ここからは\nパパとふたりの時間…\n…ね？", 0, 3, 3, 2, 1, 1, 134301, 8955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…修行と育児は…\nちょっとだけ…\n休憩…ふぁ…", 0, 2, 0, 3, 1, 1, 134301, 8957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたとも契約…\n…できる、かしら？\nふふっ…", 0, 3, 0, 3, 1, 1, 134301, 8958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りに包まれたら\n精神統一も\nはかどりそう…♪", 0, 4, 0, 3, 1, 1, 134301, 8959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい場所…\nここで作詞したら…\n穏やかな詩が\n書ける、かも…", 0, 5, 0, 3, 1, 1, 134301, 8960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊さんのお世話を\nしていると…\nお腹、空いちゃって…", 0, 7, 0, 3, 1, 1, 134301, 8962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ…♪\n色んな楽譜…\n集めるの、楽しい…♪", 0, 8, 0, 3, 1, 1, 134301, 8963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("けんぞくまだかな？\nはやく会いたいなー\nヴァンピィちゃん\nずっと待ってるからね", 0, 103, 0, 1, 12, 1, 122301, 8965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("けんぞくのこと\nずっとずっと守るよ！\nだからいつまでも\n一緒にいてね", 0, 103, 0, 2, 12, 1, 122301, 8966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の歌や想いを\n誰かに託せる…\nこれほどうれしい\nことはありません", 0, 1, 0, 1, 1, 1, 134401, 8967);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コッコロさんの\n包容力はすごいです\nあんなふうに私も\n人を包み込めたら…", 0, 2, 0, 1, 1, 1, 134401, 8968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近のボイトレは\nランファさんと一緒に\nやるんです。お互いに\n切磋琢磨しますよ！", 0, 3, 0, 1, 1, 1, 134401, 8969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先輩として相応しい\n立ち振る舞いを\n心がけたいですね\nしっかりしなきゃ…！", 0, 4, 0, 1, 1, 1, 134401, 8970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランファさんが\n踊ったら映えるかも…\nアイドルにも興味を\n持ってもらえないかな", 0, 5, 0, 1, 1, 1, 134401, 8971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("支え導くために\n寄り添って考える…\nあの人からたくさん\n教わったことでしたね", 0, 101, 0, 1, 4, 1, 134401, 8972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつだってあなたに\n恥じることのない\n姿をお見せしたいです", 0, 102, 0, 1, 8, 1, 134401, 8973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの手は温かくて\n触れていると\n落ち着きますね…♪", 0, 1, 0, 2, 1, 1, 134401, 8974);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("里のみんなから修行の\n差し入れを頂きました\nよろしければ、一緒に\n食べましょう♪", 0, 2, 0, 2, 1, 1, 134401, 8975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ノゾミにもお土産を\n用意したいですね\n里のお土産選び、\n付き合ってください♪", 0, 3, 0, 2, 1, 1, 134401, 8976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("精霊たちも、あなたが\n大好きみたいです♪\n優しさが伝わって\nいるんでしょうね", 0, 4, 0, 2, 1, 1, 134401, 8977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓が終わったら、\n二人でどこかに\n出かけましょうか♪", 0, 101, 0, 2, 4, 1, 134401, 8978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃ…す、すみません\n肌の模様を\nなぞられると、\nくすぐったくて…", 0, 102, 0, 2, 8, 1, 134401, 8979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n精霊たちと一緒に、\n今日も頑張ります\n応援してくださいね♪", 0, 1, 1, 2, 1, 1, 134401, 8980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼の時間です\n今日も精いっぱい\n修行を頑張りましょう", 0, 2, 2, 2, 1, 1, 134401, 8981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうすっかり夜ですね\n眠るまで子守唄を\n歌ってあげますよ？\nふふ♪", 0, 3, 3, 2, 1, 1, 134401, 8982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無理せず休憩するのも\n大切ですよね\nふかふか～…ふふっ♪", 0, 2, 0, 3, 1, 1, 134401, 8983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はこの子に\n歌の特訓を聞いて\nもらいましょう♪", 0, 3, 0, 3, 1, 1, 134401, 8984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な香り…\nふふ、精霊たちも\n気に入ったみたいです", 0, 4, 0, 3, 1, 1, 134401, 8985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nこの衣装、やっぱり\n少し冷えやすいものね", 0, 5, 0, 3, 1, 1, 134401, 8986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓の後のご飯は\n美味しいですね♪\nこれでまた頑張れます", 0, 7, 0, 3, 1, 1, 134401, 8987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("唱喚士についての\n書籍はないみたい\nいつか私がここに\n楽譜を入れたいな", 0, 8, 0, 3, 1, 1, 134401, 8988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギルドハウスの平和も\n任せてください\n何が来たって\n守ってみせますよ！", 0, 1, 0, 1, 1, 1, 134601, 8992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスも\nいつの間にか出撃台に\n改造されてたり\nするんでしょうか…？", 0, 2, 0, 1, 1, 1, 134601, 8993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦いを経験してこそ\n実感できますね\n平和はいいもの、\n友達は素晴らしいもの", 0, 3, 0, 1, 1, 1, 134601, 8994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はランドソルで\n巨大ロボットが\nブームになったり？\n…さすがにないか", 0, 4, 0, 1, 1, 1, 134601, 8995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("改めて見るとこの服…\nか、体の線とか\n結構目立ってるかも…", 0, 5, 0, 1, 1, 1, 134601, 8996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("団長さんって\n知らない人とも\n話せる系ですよね\nコツはいったい…", 0, 101, 0, 1, 4, 1, 134601, 8997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ＢＢ団、世界を救う！\nまだ信じられないけど\n本当にあった出来事\nなんですよね…！", 0, 102, 0, 1, 8, 1, 134601, 8998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パイロットも\n視力が大事なんです\n弓使いの経験が\n生きました！", 0, 1, 0, 2, 1, 1, 134601, 8999);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ギガンティック\nマイフレンドくん、\n出撃！\nあ、ただの妄想です", 0, 2, 0, 2, 1, 1, 134601, 9000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コクピットから\n降りたあとに残る\nふわふわ感…ちょっと\n癖になりませんか？", 0, 3, 0, 2, 1, 1, 134601, 9001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひえっ、敵襲！？\nあっすみません、\nちょっと\n寝ぼけてたかも…", 0, 4, 0, 2, 1, 1, 134601, 9002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("共に戦場を駆け抜け\nＢＢ団の絆もより強く\nこれからも結束を\n強めましょうね！", 0, 101, 0, 2, 4, 1, 134601, 9003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("同じコクピットに\n乗ったのに比べれば、\nスキンシップくらい…\nや、やっぱ緊張します", 0, 102, 0, 2, 8, 1, 134601, 9004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n今日もがんばりますっ\n…クローチェさんを\n見習ってみました…", 0, 1, 1, 2, 1, 1, 134601, 9005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯の時間ですね\nがんばって他の人\n誘ってみようかな…", 0, 2, 2, 2, 1, 1, 134601, 9006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜の見張りは\n任せてください\n一人きりの夜も\n慣れてますから！", 0, 3, 3, 2, 1, 1, 134601, 9007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休めるときに\n休んでおかなくちゃ\nいつ何が起こるか\n分かりませんからね", 0, 2, 0, 3, 1, 1, 134601, 9009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("師匠もこういうの\n好きだったのかな…\nなんだかしんみり\nしちゃいます", 0, 3, 0, 3, 1, 1, 134601, 9010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("香りでリラックス…\n余裕のない時でも\nこういう安らぎは\n大切ですよね", 0, 4, 0, 3, 1, 1, 134601, 9011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかい…\nこれはきっと友情と\n同じぬくもり…", 0, 5, 0, 3, 1, 1, 134601, 9012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新鮮なご飯、感動…！\n師匠たちの世界だと\nご飯は保存食ばかり\nでしたからね…", 0, 7, 0, 3, 1, 1, 134601, 9014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("操縦マニュアル、\nしっかり読んで\n性能を引き出さなきゃ", 0, 8, 0, 3, 1, 1, 134601, 9015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("屋内で飛べなくても\nここなら平気ですっ\n助けてくれる人が\nたくさんいますからっ", 0, 1, 0, 1, 1, 1, 134501, 9017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新ボディになってから\n人や物が前より身近に\n感じられて、わたし、\n幸せですっ♪", 0, 2, 0, 1, 1, 1, 134501, 9018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("配達以外にも何か\nお仕事したいですっ！\nハグで遊覧飛行とか、\n喜んでもらえますか？", 0, 3, 0, 1, 1, 1, 134501, 9019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむむ～…\n文字を書くのって\n難しいですね～っ\n練習しなくちゃっ！", 0, 4, 0, 1, 1, 1, 134501, 9020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("簡易点検、よしっ！\nポポおじいさんに\n点検の仕方を教わって\n今日も絶好調ですっ", 0, 5, 0, 1, 1, 1, 134501, 9021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("明日は北の空、\n明後日は南の空っ♪\nえへへっ、見せたい\n景色がいっぱいですっ", 0, 101, 0, 1, 4, 1, 134501, 9022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ついナイトさんを\n探しちゃいます…\nわたし、寂しんぼさん\nだったんでしょうかっ", 0, 102, 0, 1, 8, 1, 134501, 9023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなところでも\nひとっ飛びっ♪\nわたしに任せて\nくださいねっ！", 0, 1, 0, 2, 1, 1, 134501, 9024);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ知らない機能が\nエアリアルには\n隠されてるかもっ…\nワクワクしますねっ！", 0, 2, 0, 2, 1, 1, 134501, 9025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃんっ！　…あはは\nエアリアルになっても\nケーブルに触られると\nくすぐったいですねっ", 0, 3, 0, 2, 1, 1, 134501, 9026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴォルガーノさんに\nそっくりの子猫さんに\n最近触れたんですっ！\nかわいかったな～っ♪", 0, 4, 0, 2, 1, 1, 134501, 9027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハグしてくれるん\nですかっ？\nえへへっ、ぎゅーっ♪", 0, 101, 0, 2, 4, 1, 134501, 9028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナイトさんと一緒に\nいるだけで、胸が\nぽかぽか～って\nあったかいですっ♪", 0, 102, 0, 2, 8, 1, 134501, 9029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございますっ\n目覚まし飛行は\nいかがでしょうかっ？", 0, 1, 1, 2, 1, 1, 134501, 9030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですよっ！\nいっぱい補給して\nまたフルパワーで\nがんばりましょうっ♪", 0, 2, 2, 2, 1, 1, 134501, 9031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠れない夜はわたしに\n任せてくださいっ！\n充填さえあればずっと\n一緒にいられますよっ", 0, 3, 3, 2, 1, 1, 134501, 9032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歩きづらいので\nこういう休憩ポイント\nって助かります～っ", 0, 2, 0, 3, 1, 1, 134501, 9034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スラスターを付けたら\nこの子たちも空を\n自由に飛べたり\nするんでしょうかっ？", 0, 3, 0, 3, 1, 1, 134501, 9035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、これに似た\n香りを近くのお店で\n検知したことが\nありますっ♪", 0, 4, 0, 3, 1, 1, 134501, 9036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("高熱源反応を検知っ\nわたしのスラスターも\n熱量の高さなら\nかなりものですよっ♪", 0, 5, 0, 3, 1, 1, 134501, 9037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐもぐ…っ\n食べたぶんはあとで\n真空パックにして\nお返ししますねっ", 0, 7, 0, 3, 1, 1, 134501, 9039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本を読むのって\n楽しいですねっ♪\n前はびりびりーって\nしちゃってたのでっ", 0, 8, 0, 3, 1, 1, 134501, 9040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなかの住処ですね\nこの私の別邸にして\nあげてもいいですよ♪", 0, 1, 0, 1, 1, 1, 134701, 9042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…いつになったら\nすべての神力が\n戻るのでしょう？", 0, 2, 0, 1, 1, 1, 134701, 9043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここも悪くないですが\n昔私が作った庭園は、\nもっと良い場所でした\n焼けちゃいましたが…", 0, 3, 0, 1, 1, 1, 134701, 9044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うう…\nおなかが空きました…\nお米が食べたいです…", 0, 4, 0, 1, 1, 1, 134701, 9045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここは平和ですねえ…\nジオ・ゲヘナも\nこのくらい穏やかなら\n住みやすいのですが", 0, 5, 0, 1, 1, 1, 134701, 9046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんのおかげで\n神力が戻ってきました\n良い働きですよ♪", 0, 101, 0, 1, 4, 1, 134701, 9047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんのいる場所が\n今の私がいるべき場所\nなのかもしれませんね", 0, 102, 0, 1, 8, 1, 134701, 9048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("頭がたかーい！\n…ですよっ！", 0, 1, 0, 2, 1, 1, 134701, 9049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほーちゃんと呼ぶ権利\n安売りはしませんよ？\n特別ですから！", 0, 2, 0, 2, 1, 1, 134701, 9050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私とおしゃべりを？\nまあ、いいでしょう♪\n何を話しましょうか？\nこの羽の秘密とか？", 0, 3, 0, 2, 1, 1, 134701, 9051);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小鳥扱いは\nやめなさーい！\nこれでも神様ですよ？", 0, 4, 0, 2, 1, 1, 134701, 9052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("き、気安く触るのは…\n…い、いえ、\n騎士さんなら…まぁ…", 0, 101, 0, 2, 4, 1, 134701, 9053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絢爛豪華な絆！\nこの私と結べるなんて\n光栄でしょう？", 0, 102, 0, 2, 8, 1, 134701, 9054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁぁ～\nおはようごじゃいます\n…んむむ", 0, 1, 1, 2, 1, 1, 134701, 9055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯は何を…\nえっ？　私？\nそそんな゛あ゛！", 0, 2, 2, 2, 1, 1, 134701, 9056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの…騎士さん？\n添い寝する権利とか…\nほしくないですか？", 0, 3, 3, 2, 1, 1, 134701, 9057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～ふかふか…\n…へ？\n鳥の巣にいるみたい？", 0, 2, 0, 3, 1, 1, 134701, 9059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…\nそばに置いてあげても\nいいでしょう", 0, 3, 0, 3, 1, 1, 134701, 9060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほわぁ～\nいいかおり～", 0, 4, 0, 3, 1, 1, 134701, 9061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい…\nなんだか元気が\nでてきますねっ", 0, 5, 0, 3, 1, 1, 134701, 9062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさん食べて力を\n取り戻さなくてはっ\n…んがぐぐっ", 0, 7, 0, 3, 1, 1, 134701, 9064);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\n人の子にしては\nよく書けていますね♪", 0, 8, 0, 3, 1, 1, 134701, 9065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵なお家ですね\n温かみがあって\nどこか騎士様に\n似ております。ふふ", 0, 1, 0, 1, 1, 1, 133101, 9067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("賑やかな街ですね\nこれほど活気豊かだと\nつい外に出てみたく\nなってしまいます", 0, 2, 0, 1, 1, 1, 133101, 9068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("別世界の存在は知って\nおりましたが、いざ\n目の当たりにすると\n驚きの連続ですわ", 0, 3, 0, 1, 1, 1, 133101, 9069);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この街は様々な種族が\nなにはばかることなく\n混在しているのですね\n…我々も、いつかは…", 0, 4, 0, 1, 1, 1, 133101, 9070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルにも香水の\nお店があるのですね\nどんな香りが揃って\nいるのでしょうか…♪", 0, 5, 0, 1, 1, 1, 133101, 9071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日、素敵な花園を\n見つけたのです\n今日のお茶会は\nそちらでしましょうか", 0, 101, 0, 1, 4, 1, 133101, 9072);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気を抜いてはいけない\nとわかっていても、\nここだとつい安心して\nしまいます…ふう…", 0, 102, 0, 1, 8, 1, 133101, 9073);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ごきげんよう\n街で見つけた茶葉を\n試しているんです\n騎士様も一杯どうぞ♪", 0, 1, 0, 2, 1, 1, 133101, 9074);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("親切な方ばかりですね\n素敵なお友だちが\nできそうな予感で、\nワクワクしてます…♪", 0, 2, 0, 2, 1, 1, 133101, 9075);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("黄泉の食卓の皆様用に\nお土産を用意しないと\n騎士様のお知恵も\n頼りにしておりますわ", 0, 3, 0, 2, 1, 1, 133101, 9076);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・ニヴルヘルと\n比べると、この世界は\n本当に明るいですね\n少し眩しいくらいです", 0, 4, 0, 2, 1, 1, 133101, 9077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あまり、血の巡りが\n良くなくて…\n騎士様の手は\nとても温かいですね", 0, 101, 0, 2, 4, 1, 133101, 9078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度はわたくしに\nジオ・ニヴルヘルを\n案内させてくださいね\n観光案内のお返しです", 0, 102, 0, 2, 8, 1, 133101, 9079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n朝の眩しい太陽には\nなかなか慣れません…", 0, 1, 1, 2, 1, 1, 133101, 9080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士様、お茶は\nいかがでしょうか？\n一度一休みして、\n英気を養いましょう", 0, 2, 2, 2, 1, 1, 133101, 9081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眠れないのでしょうか\nまぶたが重くなるまで\nわたくしをお話し\n相手になさって下さい", 0, 3, 3, 2, 1, 1, 133101, 9082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思わず気が抜けそうに\nなってしまいます…\nふふ、ふわふわ…♪", 0, 2, 0, 3, 1, 1, 133101, 9084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、かわいらしい\nグレイスもきっと\n気に入りそうな\nデザインですわ", 0, 3, 0, 3, 1, 1, 133101, 9085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まあ、いい香り…\n心安らぐようですわ\n素敵なセンスを\nお持ちなのですね♪", 0, 4, 0, 3, 1, 1, 133101, 9086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("燃え移りや乾燥がある\nから近づかないほうが\nいいとわかりつつも…\nああ、温かい…♪", 0, 5, 0, 3, 1, 1, 133101, 9087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食が細いというよりは\n消化があまりうまく\nできなくて…本当は\nまだ頂きたいのですが", 0, 7, 0, 3, 1, 1, 133101, 9089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『薔薇の下の契り』？\nまあ、男性同士で…！\nそんな…こ、これ以上\nここで読むわけには！", 0, 8, 0, 3, 1, 1, 133101, 9090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダーリンが帰ってくる\n前に部屋の掃除しよ♪\n…ふふ、これってもう\n新婚生活だよね…♪", 0, 1, 0, 1, 1, 1, 132301, 9092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家具のセンスまで\n私と同じだなんて\n運命って怖いわ…♪", 0, 2, 0, 1, 1, 1, 132301, 9093);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人はベッドの下に\n何か隠してるのかな…\nな、なんて全っ然\n気にならないし…っ！", 0, 3, 0, 1, 1, 1, 132301, 9094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うっかりして\n角引っかけないように\nしないとね…", 0, 4, 0, 1, 1, 1, 132301, 9095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("錬金術を使わなくても\nあなたの心を鷲掴む\n私は恋も錬金術も\n失敗しないんだから！", 0, 5, 0, 1, 1, 1, 132301, 9096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人って破廉恥なの\n興味あるのかしら…？\n基本破廉恥禁止だけど\nあの人だけは…許す…", 0, 101, 0, 1, 4, 1, 132301, 9097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手狭になれば錬金術で\n新しい部屋作るから\nいつ家族が増えても\n安心だよね…♪", 0, 102, 0, 1, 8, 1, 132301, 9098);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("錬金術でカレーライス\n作っちゃおっかな♪\n具材を釜でグツグツ…\nま、料理とも言うわね", 0, 1, 0, 2, 1, 1, 132301, 9099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("錬金術に興味がある？\nじゃあさっそく私が\n手取り足取り教えるわ\nって…やだ破廉恥っ！", 0, 2, 0, 2, 1, 1, 132301, 9100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハちゃんとの\n虫捕りは命懸けよ！\n一万匹捕れるまで\n帰れないんだから…", 0, 3, 0, 2, 1, 1, 132301, 9101);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ソノさんって\n体は小さいけど\nとっても頼れる私の\nお姉さん的存在なの♪", 0, 4, 0, 2, 1, 1, 132301, 9102);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ…部屋中に広がる\nダーリンの香り…♪\n…ってノゾミみたいに\nなっちゃってる！？", 0, 101, 0, 2, 4, 1, 132301, 9103);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鹿の獣人族の特徴は\nこのエッチな角…\n違っ！　叡智よ叡智！\n噛んだだけだからっ！", 0, 102, 0, 2, 8, 1, 132301, 9104);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、おはよう！\n寝る前に飲んだ\n目覚めすっきり秘薬の\n効果はバッチリかな？", 0, 1, 1, 2, 1, 1, 132301, 9105);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午後からも頑張る\nあなたのために\n愛妻弁当作ったの♪\n一緒に食べよ？", 0, 2, 2, 2, 1, 1, 132301, 9106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も一日お疲れさま\n眠れないなら隣で…\nじゃなかった早寝して\n明日も頑張ろうね！", 0, 3, 3, 2, 1, 1, 132301, 9107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい錬成をするには\n適度な休憩も必要よね\n…気持ち良くてたまに\n寝落ちしちゃうけど…", 0, 2, 0, 3, 1, 1, 132301, 9109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいぬいぐるみ\n錬成じゃなくて\n手編みで作ったら\n驚いてくれるかも♪", 0, 3, 0, 3, 1, 1, 132301, 9110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くん、くん…\nん～いい匂い♪\nノゾミの香水と\nいい勝負だわ", 0, 4, 0, 3, 1, 1, 132301, 9111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ああ、暖かい\nでもソノさんの作った\nミートパイの方が\nもっと温かいわ…♪", 0, 5, 0, 3, 1, 1, 132301, 9112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…私も\n食べても減らない秘薬\n錬成して他の食べ物も\n作れないかな？", 0, 7, 0, 3, 1, 1, 132301, 9114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…\nこのレシピ面白いわね\n今度錬成してみよっと", 0, 8, 0, 3, 1, 1, 132301, 9115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おー、体が軽い\n腰痛も胃もたれも\nないし、最高かよ", 0, 1, 0, 1, 1, 1, 132501, 9117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっつも力入れてたら\nいざって時困るし\nやっぱ省エネだな", 0, 2, 0, 1, 1, 1, 132501, 9118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やば…なんか急に\nブドウ朱飲みたい…\nルイちゃんに頼むか？\nいや、でもなあ…", 0, 3, 0, 1, 1, 1, 132501, 9119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ、あの材料の在庫\nまだあったっけ…\nルイちゃんに確認しよ", 0, 4, 0, 1, 1, 1, 132501, 9120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハのやつ変な\nイタズラしてない\nといいけど…", 0, 5, 0, 1, 1, 1, 132501, 9121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のシフトは～…\nお、彼と一緒じゃん\nふふっ…", 0, 101, 0, 1, 4, 1, 132501, 9122);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハのやつ\n不用意に私の体で\n彼に抱きつくなって\nこっちが恥ずかしい…", 0, 102, 0, 1, 8, 1, 132501, 9123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も元気だねえ\n若いってうらやま…\nっていや、今は私の\n方が若いじゃん", 0, 1, 0, 2, 1, 1, 132501, 9124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～？　どしたん\nヒマならうちの店で\nバイトしてく？", 0, 2, 0, 2, 1, 1, 132501, 9125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハ見なかった？\n今日は手伝うって約束\nしてたのにさあ…", 0, 3, 0, 2, 1, 1, 132501, 9126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ルイちゃん特製\nエナドリ（子ども用）\nこれ飲んで今日も\nお仕事頑張るかー", 0, 4, 0, 2, 1, 1, 132501, 9127);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元の体なら\n君と目線、合うのにね\n…ってドラマかよ\nごめん、今の忘れて", 0, 101, 0, 2, 4, 1, 132501, 9128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんかヒマそうじゃん\n用事ないなら\nお姉さんがコーヒー\n淹れたげよっか", 0, 102, 0, 2, 8, 1, 132501, 9129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわあ…おはよ\n今日もお仕事\nがんばりますかー", 0, 1, 1, 2, 1, 1, 132501, 9130);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょうどいいや\n一緒にお昼どうよ\nお姉さんが\n奢ってあげよう", 0, 2, 2, 2, 1, 1, 132501, 9131);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぁぁ…ふぅ\nここからは大人の時間\nなんだけどさぁ\n眠くてかなわん…", 0, 3, 3, 2, 1, 1, 132501, 9132);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おお～なんか前より\nでっかく感じるわ～\nてそりゃそうか", 0, 2, 0, 3, 1, 1, 132501, 9134);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そいえば、イロハって\nあんまこういうの\n欲しがらなかったな～\nクワガタばっかで", 0, 3, 0, 3, 1, 1, 132501, 9135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ…いい匂いだね\nさすがルイちゃん特製\n錬金アロマ\n次の目玉商品だな", 0, 4, 0, 3, 1, 1, 132501, 9136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ユカリっち焚火の前で\nキメる麦しゅわに\nハマってるらしいけど\n興味あるわぁ…", 0, 5, 0, 3, 1, 1, 132501, 9137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うわこれ…\n無限にいけちゃうわ\n子どもの胃袋\n恐るべし…", 0, 7, 0, 3, 1, 1, 132501, 9139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ、こんな需要が…\n次の新商品として\nルイちゃんに試作\n頼んでみるか～", 0, 8, 0, 3, 1, 1, 132501, 9140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("服はその人の個性です\n仕立て屋は\nその手伝いをする\nプロなんです♪", 0, 1, 0, 1, 1, 1, 134801, 9142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("糸を紡いで紡いで\n巻き巻き～♪", 0, 2, 0, 1, 1, 1, 134801, 9143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…あの人の衣装\nなかなか斬新ですね\n後でどうなってるのか\n見せてもらおう♪", 0, 3, 0, 1, 1, 1, 134801, 9144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("動きやすさと\nファッション性\n両立させてみせますよ", 0, 4, 0, 1, 1, 1, 134801, 9145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度のコレクション\n新作にワイルドな\nルームウェアは\nどうかな…？", 0, 5, 0, 1, 1, 1, 134801, 9146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんもたまには\n衣装の感想とか言って\nくれてもいいのにな～", 0, 101, 0, 1, 4, 1, 134801, 9147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ノゾミさんとチカさん\nにも、おそろいの服を\nプレゼントしてみよう\n二人とも似合いそう♪", 0, 102, 0, 1, 8, 1, 134801, 9148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・ゲヘナでまた\n素材収集したいんです\n手伝ってくれますか？", 0, 1, 0, 2, 1, 1, 134801, 9149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えっ？　薄着すぎ？\nおしゃれのためなら\nこのくらいへっちゃら\nですよ…っくしゅん！", 0, 2, 0, 2, 1, 1, 134801, 9150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("穴が開いてる？\nこれはそーいう\nデザインですー！", 0, 3, 0, 2, 1, 1, 134801, 9151);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっとどこ\n触ってるんですかー！\n…あ、糸くず\n取ってくれたんですね", 0, 4, 0, 2, 1, 1, 134801, 9152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんに\n新しい生地の服を…\nいや、シャレじゃ\nないですよ？", 0, 101, 0, 2, 4, 1, 134801, 9153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な着こなしには\n健康な体も大切！\n騎士さんに見られても\n恥ずかしくないように", 0, 102, 0, 2, 8, 1, 134801, 9154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\nさあ、着替えて！\n私が見繕ってあげます", 0, 1, 1, 2, 1, 1, 134801, 9155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は激辛料理です\nジオ・ゲヘナで\nハマッちゃって…\n一緒にどうですか？", 0, 2, 2, 2, 1, 1, 134801, 9156);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("睡眠不足は美容の大敵\nていうかシンプルに…\nね、眠い…", 0, 3, 3, 2, 1, 1, 134801, 9157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くつろげますね～\nでももうちょっと\n生地の手触りが…\nって、職業病？", 0, 2, 0, 3, 1, 1, 134801, 9159);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいものって\n心を癒してくれますね\n服もそうありたいです", 0, 3, 0, 3, 1, 1, 134801, 9160);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～♪\nこの匂いにはどんな服\nが合うかなあ…？", 0, 4, 0, 3, 1, 1, 134801, 9161);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この服露出が多いから\n温かいとほっとする～\nずっとこうして\nいたいかも…", 0, 5, 0, 3, 1, 1, 134801, 9162);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いくらでも\n食べられちゃうから、\n自分でストップ\nかけないと…", 0, 7, 0, 3, 1, 1, 134801, 9164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しっかり勉強して\nジオ・ゲヘナに\nお洒落を伝えたいです", 0, 8, 0, 3, 1, 1, 134801, 9165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたくしは高貴なる\nマンティコア！\nサソリでもコウモリ\nでもありませんわよ♪", 0, 1, 0, 1, 1, 1, 134901, 9167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか居心地がいい\nお部屋ですわね～\n…さてどうやって\nあたくしのものに…", 0, 2, 0, 1, 1, 1, 134901, 9168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("高貴なるお審美眼で\nあの家具の価値を\n測ってやりますわ\n…ギリ合格ですわ！", 0, 3, 0, 1, 1, 1, 134901, 9169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("高貴なる笑い声は\n一日にしてならず\nお子様の頃から練習を\n重ねてきたのですわ！", 0, 4, 0, 1, 1, 1, 134901, 9170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お美しいあたくし様と\n同じ空間にいられる…\nどうぞその喜びを\n噛みしめなさいな♪", 0, 5, 0, 1, 1, 1, 134901, 9171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アナタがお土下座して\n頼むなら、あたくしも\nもう少しここに残って\n構いませんわよ♪", 0, 101, 0, 1, 4, 1, 134901, 9172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("馬ボーンをあたくしに\n振り向かせるには\nどうしたら…って、\nこの言い方は語弊が！", 0, 102, 0, 1, 8, 1, 134901, 9173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("少し寒いですわね…\n…この服装のせい？\nこっちだって好きで\n着てねぇですわよ！", 0, 1, 0, 2, 1, 1, 134901, 9174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのラミアが来たら\nあたくし様はお用事で\nお留守って言って\n追い返すんですのよ！", 0, 2, 0, 2, 1, 1, 134901, 9175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界にも\n闘技場がありますの？\nそこもお頂点を極めて\nしまおうかしら～♪", 0, 3, 0, 2, 1, 1, 134901, 9176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("馬ボーンって\n人畜無害そうなお面の\nわりに、時々やること\nえげつねぇですわね…", 0, 4, 0, 2, 1, 1, 134901, 9177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ馬ボーン…\nアナタあの魔札、\nまだ持ってまして？\nとっとと捨てなさい！", 0, 101, 0, 2, 4, 1, 134901, 9178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("絶対にあたくし様の\nお尻尾に触るんじゃ\nねぇですわよ…？\nいえ、振りではなく！", 0, 102, 0, 2, 8, 1, 134901, 9179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…\n打倒ネフィのお作戦を\n夜通し考え過ぎて、\n寝不足ですわぁ…", 0, 1, 1, 2, 1, 1, 134901, 9180);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお昼ですの？\nあたくし様に相応しい\n優雅なおランチと\n参りますわよ～♪", 0, 2, 2, 2, 1, 1, 134901, 9181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら馬ボーンったら\nまだ起きてますの？\n…ぐぬぬ、夜の間に\n仕掛ける作戦が…", 0, 3, 3, 2, 1, 1, 134901, 9182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このおフカフカ感…♪\n剣闘士宿舎の\nゴワゴワなお寝床とは\n大違いですわね！", 0, 2, 0, 3, 1, 1, 134901, 9184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんですの、この\n弱っちそうなお顔は…\nおかわいそうですし、\nお僕にしてあげますわ", 0, 3, 0, 3, 1, 1, 134901, 9185);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("馬ボーンはこういう\n匂いが好みですの？\nふーん…ほーう…\nなるほどですわ…♪", 0, 4, 0, 3, 1, 1, 134901, 9186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あぁ～～…\nそうそう、これくらい\n暑い方が快適ですわ…", 0, 5, 0, 3, 1, 1, 134901, 9187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ、もぐっ…\nまぁそこそこ？\n悪くないお味では\nありますわねっ", 0, 7, 0, 3, 1, 1, 134901, 9189);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんな本よりも、\n華麗なるカノン様の\n活躍録でも置いた方が\n世のためになりますわ", 0, 8, 0, 3, 1, 1, 134901, 9190);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さっきねー、外で猫と\n木登り競争したんだよ\nなかなか手ごわい\n相手だった！", 0, 1, 0, 1, 1, 1, 132401, 9192);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べて\n大きくなるんだ～\nあっでもこれ\nソノちゃんの体か", 0, 2, 0, 1, 1, 1, 132401, 9193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強いおねーさんの\n気配を感じる…\nどこから？\n…そこら中から！", 0, 3, 0, 1, 1, 1, 132401, 9194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("虫捕り網の手入れは\nいつもバッチリ！\nいつ何が出るか\nわからないもんね", 0, 4, 0, 1, 1, 1, 132401, 9195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うちの中で走り回ると\nソノちゃんに\n怒られちゃうけど…\nここならいける？", 0, 5, 0, 1, 1, 1, 132401, 9196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おじちゃんも\nお部屋にいろいろ\n隠してるのかな？\nルイちゃんみたいに", 0, 101, 0, 1, 4, 1, 132401, 9197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界一になったら\nおじちゃんにも\nいっぱい褒めて\nほしいな…約束っ♪", 0, 102, 0, 1, 8, 1, 132401, 9198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("高いとこのものが\n取りたいときは\nイロハに言ってね\nイロハ得意だから！", 0, 1, 0, 2, 1, 1, 132401, 9199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうも、イロハです\n剣士たるもの、\nあいさつは大事って\n教わったんだ♪", 0, 2, 0, 2, 1, 1, 132401, 9200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハと勝負だね！\n受けて立つよ～！\n…あれ、違った？", 0, 3, 0, 2, 1, 1, 132401, 9201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ！　ルイちゃんに\n素材集め頼まれてたの\n忘れてた…！　やばい\nおじちゃん手伝って！", 0, 4, 0, 2, 1, 1, 132401, 9202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実はイロハって\n褒めたら伸びる\nタイプなんだ\nだからよろしくね♪", 0, 101, 0, 2, 4, 1, 132401, 9203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このお部屋、すごく\n居心地がいいんだ～\nやっぱりおじちゃんが\nいるからかな？", 0, 102, 0, 2, 8, 1, 132401, 9204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日仕掛けた罠で\n虫捕れてるかな？\nあとで一緒に\n見に行こうね♪", 0, 1, 1, 2, 1, 1, 132401, 9205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もうお昼だよね？\nイロハのお腹が\n空いてきたから\n間違いないよ！", 0, 2, 2, 2, 1, 1, 132401, 9206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ～…\nあ、あくびじゃないよ\nイロハ大人なんだから\n眠くなんか…ふわぁ…", 0, 3, 3, 2, 1, 1, 132401, 9207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわしたものって\nつい飛び込みたく\nなっちゃうよね\n…うずうずっ", 0, 2, 0, 3, 1, 1, 132401, 9209);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいのもいいけど\nカッコよさも欲しいな\nそーだ、角とかもっと\nいっぱい付けてみる？", 0, 3, 0, 3, 1, 1, 132401, 9210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おー、いい匂い♪\nこれもしかして\nルイちゃんの新作？\n爆売れ間違いなしだよ", 0, 4, 0, 3, 1, 1, 132401, 9211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬくぬくぽかぽか、\n気持ちいいー…\nでもちょっと\n暑くなってきたな", 0, 5, 0, 3, 1, 1, 132401, 9212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐもぐ…\nこれはいい食材を\n使っておりますなぁ\nうん、三ツ星！", 0, 7, 0, 3, 1, 1, 132401, 9214);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむなるほど…\nこっ、これは…！\n…ごめん、適当に\n言ってみた", 0, 8, 0, 3, 1, 1, 132401, 9215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また海に行く時に\n備えて…次の計画を\n練る必要がある…", 0, 1, 0, 1, 1, 1, 135001, 9217);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騒がしいのも…\n以前ほど気にならない\n慣れてしまった…？", 0, 2, 0, 1, 1, 1, 135001, 9218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("眩暈がする暑さも\n騎士クンと同じ気温を\n感じられるなら…いい", 0, 3, 0, 1, 1, 1, 135001, 9219);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンに\n好意を抱く者は\nみんな有罪\n…わたしは例外", 0, 4, 0, 1, 1, 1, 135001, 9220);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("体も心も…外の世界に\n馴染んできた気がする\n少しずつ、だけど…", 0, 5, 0, 1, 1, 1, 135001, 9221);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの手…\n大きかった…\n…また、つなぎたいな", 0, 101, 0, 1, 4, 1, 135001, 9222);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏が終わっても…\nその先の季節も\n…その次の夏も\n騎士クンと一緒に…", 0, 102, 0, 1, 8, 1, 135001, 9223);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンといるとね\n渇いてた心が…\n潤される、気がするの", 0, 1, 0, 2, 1, 1, 135001, 9224);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンは…\nしたいこと、ある？\n夏にだけ…できること\n一緒に、しようね", 0, 2, 0, 2, 1, 1, 135001, 9225);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("仮想領域の夢でも\n現実の海でも…\n騎士クンと一緒なら\nそこが本物の夏、だね", 0, 3, 0, 2, 1, 1, 135001, 9226);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("肝試しがしたい…？\n…うまく驚けるかな\n練習しなくちゃ…", 0, 4, 0, 2, 1, 1, 135001, 9227);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンとなら\nどんな夏でも…\nきっと楽しい…♪", 0, 101, 0, 2, 4, 1, 135001, 9228);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着…どうかしら…？\n…よかった\nシミュレーションの\n成果ね。ふふ", 0, 102, 0, 2, 8, 1, 135001, 9229);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン…眠たそう\nもうちょっと…寝る？\n後で起こしてあげるね", 0, 1, 1, 2, 1, 1, 135001, 9230);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お出かけするなら\n水筒を用意するね…\n夏の水分補給は大事…", 0, 2, 2, 2, 1, 1, 135001, 9231);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また…夜の海を\n見に行きたいな\n騎士クンと一緒に\n連れていってくれる？", 0, 3, 3, 2, 1, 1, 135001, 9232);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンを待つには\nちょうどいい…\n…落ち着く…", 0, 2, 0, 3, 1, 1, 135001, 9234);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういう物を\n城に置いた方が\nかわいいって思って\nもらえる…かな…？", 0, 3, 0, 3, 1, 1, 135001, 9235);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏に合わせた香りね…\n涼やかな風が胸を\n吹き抜けるような…", 0, 4, 0, 3, 1, 1, 135001, 9236);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("火は落ち着く…\n身体感覚を味わえる\n作り物の…この体でも", 0, 5, 0, 3, 1, 1, 135001, 9237);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『食』…騎士クンと\n話す共通の話題には\n悪くなさそう…", 0, 7, 0, 3, 1, 1, 135001, 9239);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『好きな人と楽しめる\n夏デート特集』…？\n……ふむ…", 0, 8, 0, 3, 1, 1, 135001, 9240);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしの趣味では\nないけれど…\n騎士クンが望むなら\n城に置いても…？", 0, 10, 0, 3, 1, 1, 135001, 9242);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("む…悪くない\nこれなら\n騎士クンと一緒に…？", 0, 11, 0, 3, 1, 1, 135001, 9243);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日中水着でいるって\n浮かれているみたいね\n夏は短いから、沢山\n楽しまなくちゃね", 0, 1, 0, 1, 1, 1, 135101, 9244);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと暑いし\n氷の上を滑って\n涼もうかしら", 0, 2, 0, 1, 1, 1, 135101, 9245);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ運送ギルドの\nアルバイトの時間だわ\n準備しなきゃ", 0, 3, 0, 1, 1, 1, 135101, 9246);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エリスさん、水着が\nすごく似合ってた…\nどこで買ったのかしら", 0, 4, 0, 1, 1, 1, 135101, 9247);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("未練が残らないように\nこの夏休みでやりたい\nことはやらなくちゃ", 0, 5, 0, 1, 1, 1, 135101, 9248);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かき氷を作ったら\n彼も食べるかしら？\nアイスクリームの\nほうがいいかな…", 0, 101, 0, 1, 4, 1, 135101, 9249);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着を着ていれば\nどこにいても\nリゾート気分だわ♪", 0, 102, 0, 1, 8, 1, 135101, 9250);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏はおいしいものが\nたくさんあるし\n【美食殿】の活動も\n忙しくなりそうね♪", 0, 1, 0, 2, 1, 1, 135101, 9251);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ、私の尻尾…\nそんなに気になる？\nつついたらダメよ\nいいわね…？", 0, 2, 0, 2, 1, 1, 135101, 9252);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏は日が長いし\nまだまだたくさん\n遊べそうね♪", 0, 3, 0, 2, 1, 1, 135101, 9253);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は一緒に海に\n行かない？\nあなたも水着\n持ってきてるでしょ", 0, 4, 0, 2, 1, 1, 135101, 9254);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ日焼け止めを\n塗り直さなきゃ…あの\nお願いしてもいい…？", 0, 101, 0, 2, 4, 1, 135101, 9255);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私たちで最高の\n夏休みにしましょう\nね、おにーたん♪", 0, 102, 0, 2, 8, 1, 135101, 9256);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の朝は早いわね\nもうセミも鳴いてるし\nあなたも早起きだわ…\n見習わなくちゃ", 0, 1, 1, 2, 1, 1, 135101, 9257);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日中は暑いだろうし\nゆっくりしましょう\nお昼寝タイムはどう？", 0, 2, 2, 2, 1, 1, 135101, 9258);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この時間のアイス\nクリームは格別よね♪\n何味にしようかしら", 0, 3, 3, 2, 1, 1, 135101, 9259);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暑い夏はしっかり\n休むことが大切\nふぅ…いい気持ち♪", 0, 2, 0, 3, 1, 1, 135101, 9261);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわの毛並み\n暑くないのかしら\nかわいいだけじゃなく\n忍耐強くもあるのね", 0, 3, 0, 3, 1, 1, 135101, 9262);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("爽やかでいい匂い…♪\nジトジトしがちの夏に\nピッタリなアロマね", 0, 4, 0, 3, 1, 1, 135101, 9263);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっと水着でいると\n流石に冷えるわね\nうん、いい心地だわ", 0, 5, 0, 3, 1, 1, 135101, 9264);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむっはむっ…\nしっかり食べて\n夏バテ対策しないと", 0, 7, 0, 3, 1, 1, 135101, 9266);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむふむ…面白いわね\n今度プレシアちゃんと\n一緒に読もうかしら", 0, 8, 0, 3, 1, 1, 135101, 9267);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私のフロートと少し\n似ている気がする\nサイズ的にはこっちが\nお兄さんかしら…ふふ", 0, 10, 0, 3, 1, 1, 135101, 9269);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、きれい♪\nまるで\n海のステージね！", 0, 11, 0, 3, 1, 1, 135101, 9270);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じゅんび、おっけー\nうみでも\nおふろでも\nおんせんでも", 0, 1, 0, 1, 1, 1, 135201, 9271);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひまわり。すき\nおっきくて\nたね、うまし", 0, 2, 0, 1, 1, 1, 135201, 9272);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハッピーちゃん\nいい、におい\nひやけ？\nやきぶた？", 0, 3, 0, 1, 1, 1, 135201, 9273);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じーわ、じーわ…\nせみの、なきごえ\nきいてる、だけで\nあつい。かも…", 0, 4, 0, 1, 1, 1, 135201, 9274);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイス、かきごおり…\nあつい、なつ\nだから\nひえひえ、ひっす", 0, 5, 0, 1, 1, 1, 135201, 9275);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おっきくなるまほー\nきわめたい\nお兄を\nだっこ。するよ", 0, 101, 0, 1, 4, 1, 135201, 9276);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("「あなた」\n…ちょっと、ちがう？\nシェフィたち\nみたいに、ならない…", 0, 102, 0, 1, 8, 1, 135201, 9277);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じゃりじゃり\nべたべた\n…シャワー\nいって、きます", 0, 1, 0, 2, 1, 1, 135201, 9278);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("（すんすん）\nお兄。ほんのり\nうみの、におい\nおいしそう", 0, 2, 0, 2, 1, 1, 135201, 9279);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄。みて\nべろ、まっさお\nぶるーはわい\nカラー", 0, 3, 0, 2, 1, 1, 135201, 9280);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あつくても\nあついもの\nおいしい\n…バーベキュー…", 0, 4, 0, 2, 1, 1, 135201, 9281);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ついんて\nバランス、むずかし\nお兄\nリボン、よろ", 0, 101, 0, 2, 4, 1, 135201, 9282);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みずぎ\nにあってる。って\nお兄。いった\nもっと。みて？", 0, 102, 0, 2, 8, 1, 135201, 9283);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ\nあさごはん\nやきざかな", 0, 1, 1, 2, 1, 1, 135201, 9284);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おひる\nおひるね\nいっしょに、しよ？", 0, 2, 2, 2, 1, 1, 135201, 9285);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おそと\nまっくら\nはなび\nしよ？", 0, 3, 3, 2, 1, 1, 135201, 9286);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…\nあそびすぎ\nおつかれ\nねむねむ", 0, 2, 0, 3, 1, 1, 135201, 9288);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よしよし\nおるすばん\nおねがい。ね", 0, 3, 0, 3, 1, 1, 135201, 9289);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("（くんくん）\nれもんの、におい\nじゅる", 0, 4, 0, 3, 1, 1, 135201, 9290);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さかな、くしやき\nすたんばい、おっけー\nいつでも、やける。よ", 0, 5, 0, 3, 1, 1, 135201, 9291);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい、あそびたい\nいっぱい、つよくなる\nいっぱい、たべる", 0, 7, 0, 3, 1, 1, 135201, 9293);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おさかなの、ほん\nおもしろかった\nでも\nおなかが…", 0, 8, 0, 3, 1, 1, 135201, 9294);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("れっつ、ごー\nすいへーせん\nせかい\nいっしゅー", 0, 10, 0, 3, 1, 1, 135201, 9296);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("きぶんは、かいばしら\nバターやき\nおすすめ", 0, 11, 0, 3, 1, 1, 135201, 9297);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("成長して着れなく\nなっちゃう前に\nこの水着でできること\n全部しちゃいたいな♪", 0, 1, 0, 1, 1, 1, 135301, 9298);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お家で水着だと\n開放的な気分かも♪\nふふ、お兄さんにも\n教えてあげなきゃ♪", 0, 2, 0, 1, 1, 1, 135301, 9299);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎの練習しちゃお♪\nすいすい、すいすいー\n…ちょっと、\n子供っぽかったかも…", 0, 3, 0, 1, 1, 1, 135301, 9300);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("インドア派だけど\n夏の屋外は好き…や…\nお兄さんと一緒なら\nどこでも…", 0, 4, 0, 1, 1, 1, 135301, 9301);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏だからってちょっと\n羽目外しすぎかな…\nわたし…やっぱり\n真面目じゃない…かも", 0, 5, 0, 1, 1, 1, 135301, 9302);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしの水着姿…\n少しは大人っぽいって\n思ってくれたかな…？", 0, 101, 0, 1, 4, 1, 135301, 9303);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家の中は涼しいのに\nお兄さんのこと\n考えると暑くなって…\n夏バテしちゃいそう…", 0, 102, 0, 1, 8, 1, 135301, 9304);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さんと一緒なら\n夏休みの日記\n書くことが多すぎて\nページが足りません♪", 0, 1, 0, 2, 1, 1, 135301, 9305);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かき氷食べましょ♪\n…ふふ、お兄さん\n舌の色すごいですよ♪\nわたしも…べ～っ♪", 0, 2, 0, 2, 1, 1, 135301, 9306);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は海に行きます？\nそれともお家で\nのんびりですか？\nわたしはどっちでも♪", 0, 3, 0, 2, 1, 1, 135301, 9307);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏バテしないように\nスタミナ料理のレシピ\nお勉強しました♪", 0, 4, 0, 2, 1, 1, 135301, 9308);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏が終わっちゃっても\nこの水着を着てたら\n夏の思い出、忘れずに\nいてくれますか…？", 0, 101, 0, 2, 4, 1, 135301, 9309);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…この日焼け跡\nお兄さんと\nわたしだけの\n秘密…ですよ？", 0, 102, 0, 2, 8, 1, 135301, 9310);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n朝の体操１、２、３♪\nしゃきっと目覚めて\nいい一日にしましょ♪", 0, 1, 1, 2, 1, 1, 135301, 9311);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼休憩ですね♪\n午後からも頑張れる様\nお兄さんのこと\n癒しますね…♪", 0, 2, 2, 2, 1, 1, 135301, 9312);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝る時間…\nお兄さんが眠るまで\n一緒にいますね…\n…ふあぁ…", 0, 3, 3, 2, 1, 1, 135301, 9313);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちいいけど、汗…\n染みちゃわないように\n気をつけないと…", 0, 2, 0, 3, 1, 1, 135301, 9315);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぎゅう～♪\nなんて、ちょっと\nあざといかな…♪", 0, 3, 0, 3, 1, 1, 135301, 9316);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏にぴったりの\nフルーティーな香り♪\nお兄さん、好きかな？", 0, 4, 0, 3, 1, 1, 135301, 9317);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で暖まるのって\nなんだか贅沢な気分♪\nこたつでアイス的な♪", 0, 5, 0, 3, 1, 1, 135301, 9318);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹ぽっこりに\nならないよう\n気をつけないと…\nでも止まらない…", 0, 7, 0, 3, 1, 1, 135301, 9320);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弾ける水着でビーチの\n視線を独り占め…かぁ\nわたしはお兄さんの\n視線だけで…なんて♪", 0, 8, 0, 3, 1, 1, 135301, 9321);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これで夏の大冒険に\nしゅっぱ～つ！\n…なんちゃって♪", 0, 10, 0, 3, 1, 1, 135301, 9323);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだか女神さま\nみたい…？\nふふ、わたしには\n似合わないかもです♪", 0, 11, 0, 3, 1, 1, 135301, 9324);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真っ白い日差し─\nジオ・ゲヘナには\nなかったものですね\n─悪くはないです", 0, 1, 0, 1, 1, 1, 135401, 9325);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しばらくここで\n休んでます\n人の多い街中よりは\n落ち着くので─", 0, 2, 0, 1, 1, 1, 135401, 9326);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにも─\nあるんでしょうか\n海で使う遊び道具…", 0, 3, 0, 1, 1, 1, 135401, 9327);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見張りは─\nここならあまり\n必要なさそう…", 0, 4, 0, 1, 1, 1, 135401, 9328);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏のバカンス─\n媛が楽しんでるなら\n私は十分です", 0, 5, 0, 1, 1, 1, 135401, 9329);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("知らない相手は、\n苦手だけど─\n…少しだけ、\n話してみても…", 0, 101, 0, 1, 4, 1, 135401, 9330);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここにいると\n安心する、ような…\n土壌が─良い…？", 0, 102, 0, 1, 8, 1, 135401, 9331);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏の正装、水着─\n着方、間違えて\nないですよね…？", 0, 1, 0, 2, 1, 1, 135401, 9332);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("相変わらず、\nおしゃべりが\n好きなんですね\n私は─普通です", 0, 2, 0, 2, 1, 1, 135401, 9333);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("─喉が渇きました\n…いえ、花にお水が\n欲しいわけじゃなくて", 0, 3, 0, 2, 1, 1, 135401, 9334);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("─いつもより\n花がつやつやしてる？\n…あ、褒めて\nくれたんですか", 0, 4, 0, 2, 1, 1, 135401, 9335);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この部屋─\n貴方が飾りつけを？\nわかります、何となく", 0, 101, 0, 2, 4, 1, 135401, 9336);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すぐ傍にいると、\n暑くなりませんか？\n─私は別に\nかまいませんが", 0, 102, 0, 2, 8, 1, 135401, 9337);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝から元気ですね─\nおかげですっかり\n目が覚めました", 0, 1, 1, 2, 1, 1, 135401, 9338);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外─暑そうです\n出かけるなら\n気を付けてください\n倒れたりしないよう…", 0, 2, 2, 2, 1, 1, 135401, 9339);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("─貴方も\n夜更かしですか？\n…少しだけなら\n付き合いますよ", 0, 3, 3, 2, 1, 1, 135401, 9340);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴方もここで\n休みたいですか？\n─ダメです\n今は私が使うので", 0, 2, 0, 3, 1, 1, 135401, 9342);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ゆるい顔つきですね\nジャングルでは\n生き残れそうに\nないです─", 0, 3, 0, 3, 1, 1, 135401, 9343);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("─ん…\nこれ、海の香り？\n─いい匂い…", 0, 4, 0, 3, 1, 1, 135401, 9344);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…暑さには\n慣れてますよ\n寒いのよりは、ずっと", 0, 5, 0, 3, 1, 1, 135401, 9345);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("栄養は、大事です\n味は─あまり\n気にしたこと、\nありませんでした", 0, 7, 0, 3, 1, 1, 135401, 9347);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("適当に本を読んでいる\nだけです─\n…別に、遊びについて\n調べたりしてません", 0, 8, 0, 3, 1, 1, 135401, 9348);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物を模した\n人形─ですね\n戦闘訓練用に？", 0, 10, 0, 3, 1, 1, 135401, 9350);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貝のクッションですか\n─噛みついてきたり\nしないですよね", 0, 11, 0, 3, 1, 1, 135401, 9351);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シントーメッキャク\n火もまた涼し…\nむむむ…やっぱり夏は\n暑いデース！", 0, 1, 0, 1, 1, 1, 137101, 9352);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海にも新しい忍法の\nヒントがあるはずデス\nショーグンと海底散歩\nも楽しそうデス", 0, 2, 0, 1, 1, 1, 137101, 9353);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("釣りの心得は\nメイキョーシスイ…\n忍者の修行に\nうってつけデス♪", 0, 3, 0, 1, 1, 1, 137101, 9354);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("天下統一の後のことも\n考えねばなりまセン\n今度はテンジョー統一\nデスかね…？", 0, 4, 0, 1, 1, 1, 137101, 9355);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("デケデケデン♪\nテルテル坊主完成デス\n晴れてないとお外で\n遊べまセンからね！", 0, 5, 0, 1, 1, 1, 137101, 9356);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のオモテナシも\nショーグンをワクワク\nさせマス♪　今から\n用意しておかねばデス", 0, 101, 0, 1, 4, 1, 137101, 9357);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新しい忍法の開発に\n休みはないのデス！\nショーグンの天下統一\nを思えばなんのその！", 0, 102, 0, 1, 8, 1, 137101, 9358);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海の前に準備運動デス\nまずは手を後ろに、\n素早く忍者走り！\nシュバババッ", 0, 1, 0, 2, 1, 1, 137101, 9359);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夏にお祭りは\n欠かせないデスよね♪\n地域のイベント情報は\n見逃しまセン！", 0, 2, 0, 2, 1, 1, 137101, 9360);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグン、団扇で\nあおいであげマス！\n忍法・扇風の術ー！\nうりゃりゃりゃー！", 0, 3, 0, 2, 1, 1, 137101, 9361);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ワタシが必要な時は\n風鈴を鳴らすデス！\n風よりも早く\n駆けつけマスよ！", 0, 4, 0, 2, 1, 1, 137101, 9362);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じっと見つめられると\n顔が熱くなってきて…\nはっ、ショーグンの\n新しい忍法デスか！？", 0, 101, 0, 2, 4, 1, 137101, 9363);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグン、日焼けは\nノン、デスよ！\nワタシがクリームぬり\nぬりしてあげマース！", 0, 102, 0, 2, 8, 1, 137101, 9364);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようデス！\n朝ごはんはワタシに\nお任せデス。\n毎日みそ汁作るデス！", 0, 1, 1, 2, 1, 1, 137101, 9365);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日差しに注意デスよ\nネッチューショーに\n日焼け、どっちも\n大変デスからね！", 0, 2, 2, 2, 1, 1, 137101, 9366);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグン、\n外で花火しまショウ！\nぱちぱちキレイで\n楽しいデスよ！", 0, 3, 3, 2, 1, 1, 137101, 9367);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("遊びに備えて\n今は休む時…\nガシンショータンデス", 0, 2, 0, 3, 1, 1, 137101, 9369);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子たちにも\n手伝ってもらって\n新しい忍法を開発\nしてみまショウ♪", 0, 3, 0, 3, 1, 1, 137101, 9370);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むむっ、ここまで\n潮の香りが漂って\nきた気がしマス！", 0, 4, 0, 3, 1, 1, 137101, 9371);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("海に入った後は\n体を温めねば\nやはりサウナも\n必要デスね！", 0, 5, 0, 3, 1, 1, 137101, 9372);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いっぱい食べて\nいっぱい遊ぶデス！\n夏バテなんかに\n負けてられまセン！", 0, 7, 0, 3, 1, 1, 137101, 9374);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『BUSHIDO』の\n最新刊が待ち遠しい\nデス…マイゾーキン\n特集、読みたいデス", 0, 8, 0, 3, 1, 1, 137101, 9375);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ショーグンとこの子に\n乗って、天下統一まで\nシュババババッ！\nなんてどうでショウ", 0, 10, 0, 3, 1, 1, 137101, 9377);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽよんぽよ～ん♪\nショーグンと一緒に\n遊んでみたいデス♪", 0, 11, 0, 3, 1, 1, 137101, 9378);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度はシナツちゃんの\n世界へ行ってみたいな\nエリスちゃんも誘って\n大人女子旅とか最高♪", 0, 1, 0, 1, 1, 1, 135501, 9379);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっはっはー！\nよし、今日も絶好調！\nま、いつも笑ってたら\n不調なんてないけど♪", 0, 2, 0, 1, 1, 1, 135501, 9380);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～あっちの世界と\nほとんど一緒だね！\n違ってるところ探しに\n出かけてみよっかな？", 0, 3, 0, 1, 1, 1, 135501, 9381);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ううーん、のんびり\nするのもいいけど\nどこか行ってみたいな\n人助けとか、ね", 0, 4, 0, 1, 1, 1, 135501, 9382);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、そーだ\n向こうへ帰る前に\nこっちのお土産とか\n買っとかなくちゃ", 0, 5, 0, 1, 1, 1, 135501, 9383);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふ～ん、騎士くんって\nこういうのが好みか～\n後でヒヨリちゃんに\n教えてあげよ♪", 0, 101, 0, 1, 4, 1, 135501, 9384);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次はあたしが恩を返す\n番だね。騎士くんに\n助けが必要になったら\n絶対駆けつけるよ！", 0, 102, 0, 1, 8, 1, 135501, 9385);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ騎士くん！\n困ってることない？\nお姉さんがなんでも\n力になっちゃうよ！", 0, 1, 0, 2, 1, 1, 135501, 9386);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また闘技場に行こうよ\nちょっと運動不足でさ\nバーンと暴れたい気分\nなんだよね♪", 0, 2, 0, 2, 1, 1, 135501, 9387);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつか大人になったら\n一緒に飲もうよ！\nあははっ、騎士くん\n指切りげんまん♪", 0, 3, 0, 2, 1, 1, 135501, 9388);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に作った麦しゅわ\nカップ、最高だね♪\n騎士くんの分もどうぞ\nちゃんとジュースだよ", 0, 4, 0, 2, 1, 1, 135501, 9389);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ…ぶっちゃけ\nヒヨリちゃんのこと\nどう思ってるのかな？\nお姉さんに聞かせなよ", 0, 101, 0, 2, 4, 1, 135501, 9390);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くん、うっかり\n飲みすぎたあの日の\nコトは誰にも内緒で\nお願いね。約束だよ！", 0, 102, 0, 2, 8, 1, 135501, 9391);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはは、騎士くん\n新しい朝だよー！\n今日はどんな一日か\nワクワクするね～♪", 0, 1, 1, 2, 1, 1, 135501, 9392);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("午後からも笑顔で\n元気に乗り切ろうね！\n外に行くもよし、\n部屋で麦しゅわもよし", 0, 2, 2, 2, 1, 1, 135501, 9393);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここからは大人の時間\n騎士くんにはまだ少し\n早いかな～？\nだから、おやすみ♪", 0, 3, 3, 2, 1, 1, 135501, 9394);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("麦しゅわ飲み過ぎた\n夜はここにダーイブ\n…なんて大人に\nなっちゃダメだよ～？", 0, 2, 0, 3, 1, 1, 135501, 9396);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたしの世界の子たち\nこういうの好きかな？\nお土産に探してみよう\n気に入るかも♪", 0, 3, 0, 3, 1, 1, 135501, 9397);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～いいね♪\nあとでお気に入りの\nフレーバーも\n試してみよっかな？", 0, 4, 0, 3, 1, 1, 135501, 9398);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほうほう…熱い！\nサラサリアは\nいつも暖かいから\nこういうの新鮮！", 0, 5, 0, 3, 1, 1, 135501, 9399);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～おいしい！\nけどやっぱご飯は\nみんなで一緒に\n食べたいな～", 0, 7, 0, 3, 1, 1, 135501, 9401);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("文字ばっかの本は\nちょーっと苦手かも…\n必要なら読むけどさ？", 0, 8, 0, 3, 1, 1, 135501, 9402);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆思い思いに過ごして\nいるのに、不思議と\n落ち着く。いつまでも\nここにいられたら…", 0, 1, 0, 1, 1, 1, 135601, 9406);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("皆に挨拶をせねば\n…いや、今は、まだ\nタイミングが悪い…\nまた今度にしよう…", 0, 2, 0, 1, 1, 1, 135601, 9407);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の服装…この場で\n浮いてないだろうか\nまずい、心配に\nなってきた…！", 0, 3, 0, 1, 1, 1, 135601, 9408);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイラたちとの旅行も\n楽しかったな…\nまた３人で温泉に\nいきたいものだ", 0, 4, 0, 1, 1, 1, 135601, 9409);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここで剣の稽古は\nさすがによろしくない\n代わりに今日は瞑想を\nすることにしよう", 0, 5, 0, 1, 1, 1, 135601, 9410);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("人とのつながりは\n大切にしなければ\n今日こそは誰かに\n話しかけるぞ…！", 0, 101, 0, 1, 4, 1, 135601, 9411);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("できることが増えて、\n迷うばかりの毎日…\nそれが楽しく尊いと\n今実感している…", 0, 102, 0, 1, 8, 1, 135601, 9412);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええと…奇遇だな\nこんなところで\n会うなんて。いや違う\n…その、こんにちは…", 0, 1, 0, 2, 1, 1, 135601, 9413);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟子たちへの土産も\n探しておかないとな\nよければキミからも\nアドバイスを頼む…", 0, 3, 0, 2, 1, 1, 135601, 9415);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("剣の稽古をしたい？\nふっ…いいとも\nキミとならいくらでも\n準備をしてすぐ戻る", 0, 4, 0, 2, 1, 1, 135601, 9416);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よければまた、\n街を案内してくれ\n名所旧跡もだがキミと\n歩くのは楽しいんだ", 0, 101, 0, 2, 4, 1, 135601, 9417);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("感謝の心を\n忘れたことはないよ\nキミたちの優しさに\n救われた一人として…", 0, 102, 0, 2, 8, 1, 135601, 9418);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うむ、いい顔だな\n良い一日は、\n良い目覚めから始まる\n心掛けておくといい", 0, 1, 1, 2, 1, 1, 135601, 9419);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう昼時か\n誰かを誘って食事に…\n…いや無理だ、\nハードルが高い…！", 0, 2, 2, 2, 1, 1, 135601, 9420);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜はいい…\n誰とも話さず\n一人きりでいても、\n不自然ではないからな", 0, 3, 3, 2, 1, 1, 135601, 9421);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…いかんな、これは\n気を抜くとこのまま\n離れられなくなる…", 0, 2, 0, 3, 1, 1, 135601, 9423);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("シナツだ、よろしく\n……ふぅ\n人形相手の練習なら\n緊張しないのだがな…", 0, 3, 0, 3, 1, 1, 135601, 9424);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…集中力が\n高まりそうな香りだな\n稽古にも役立つだろう\n皆にも教えてやろうか", 0, 4, 0, 3, 1, 1, 135601, 9425);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("凍える人に寄り添い\n温もりを与える…\n私もそんな存在に\nなりたいものだ", 0, 5, 0, 3, 1, 1, 135601, 9426);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食の楽しみ…\nあまり意識して\nいなかったが、\nやはりいいものだな", 0, 7, 0, 3, 1, 1, 135601, 9428);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…っと、いかん\n読みふけっていたら\nいくらでも時間を\n過ごせてしまうぞ…", 0, 8, 0, 3, 1, 1, 135601, 9429);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また空を飛びたいな～\nふわふわ～ってなる\nあの感じが気持ちいい\nんだよね～♪", 0, 1, 0, 1, 1, 1, 135701, 9433);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("またサラサリアに\n行きたいなー\n…串焼きの味が\n忘れられなくって♪", 0, 2, 0, 1, 1, 1, 135701, 9434);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悩んでる人がいたら\n背中を押してあげたい\nあたしがそれで、勇気\nづけられたみたいに", 0, 3, 0, 1, 1, 1, 135701, 9435);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気持ちを言葉にするの\n大事って分かってても\nいざとなると緊張して\n上手くできないなぁ…", 0, 4, 0, 1, 1, 1, 135701, 9436);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっちの世界でも\nギルドハウスは\nあるのかな…？\n今度探してみよっと♪", 0, 5, 0, 1, 1, 1, 135701, 9437);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイラに会って少し\n成長できたかも…！\n素敵な女の人目指して\nもっと頑張るぞーっ♪", 0, 101, 0, 1, 4, 1, 135701, 9438);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっちのあたしは\n騎士くんに選ばれた…\nよし、あたしも\n頑張らなくっちゃ…！", 0, 102, 0, 1, 8, 1, 135701, 9439);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋の模様替えする？\nサラサリア風の家具も\nあったら素敵だよね！", 0, 1, 0, 2, 1, 1, 135701, 9440);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんだかお疲れ気味？\nそうだっ、サラサリア\nで教わったマッサージ\nをしてあげるっ♪", 0, 2, 0, 2, 1, 1, 135701, 9441);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士くんっ！\n今からあたしとデート\nしませんかっ！", 0, 3, 0, 2, 1, 1, 135701, 9442);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今ちょうど、踊りの\n練習してたとこなの\n騎士くんも\n一緒にどう？", 0, 4, 0, 2, 1, 1, 135701, 9443);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("き、騎士くん！\nこの前の続き…\n手、繋いでいい…？", 0, 101, 0, 2, 4, 1, 135701, 9444);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへへ、騎士くんが\nあたしの背中を押して\nくれると、勇気も\n100万倍だよっ♪", 0, 102, 0, 2, 8, 1, 135701, 9445);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ、騎士くん！\n今日もいい朝だよ！\nサラサリアみたいに\n太陽が輝いてるもん！", 0, 1, 1, 2, 1, 1, 135701, 9446);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フレフレ、騎士くん！\n午後もファイトー！\nあたしは日陰でお昼寝\nタイム…なんてねっ♪", 0, 2, 2, 2, 1, 1, 135701, 9447);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜に騎士くんといると\n空飛ぶ絨毯から見た\nサラサリアの夜景を\n思い出しちゃうな♪", 0, 3, 3, 2, 1, 1, 135701, 9448);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休憩きゅうけ～い♪\n強い人と戦った後は\nしっかりと体を\n休ませないとね", 0, 2, 0, 3, 1, 1, 135701, 9450);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("にゃ～、\nかわいいにゃ～♪\nアンブラを\n思い出しちゃうよ♪", 0, 3, 0, 3, 1, 1, 135701, 9451);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わっ…すごくいい\n匂い～サラサリアの\n砂漠の匂いにちょっと\n似てるかも", 0, 4, 0, 3, 1, 1, 135701, 9452);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サラサリアの太陽\nみたいに暖かい♪\n日向ぼっこしてる\nみたいでしあわせ…", 0, 5, 0, 3, 1, 1, 135701, 9453);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～おいしいっ！\nアイラもきっと\n好きな味だね…！\n今度食べてもらおっ！", 0, 7, 0, 3, 1, 1, 135701, 9455);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これは恋愛指南本…！\nふむ…意中の男性と\nキスするには…って\nこれはまだ早いよ～！", 0, 8, 0, 3, 1, 1, 135701, 9456);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あてがここにいたら、\nみんな寒い思いを\nしちまうかな…\nご、ごめんな", 0, 1, 0, 1, 1, 1, 135801, 9460);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あて、みんなより\n体でっけぇし…\nもうちょっと隅っこ\n行っとこうかな", 0, 2, 0, 1, 1, 1, 135801, 9461);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さ、騒がしいとこは\n苦手だども…\nここはそんなに\n気になんね…", 0, 3, 0, 1, 1, 1, 135801, 9462);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いろいろ勉強してぇな\nイナカもんだから、\nみんなに迷惑とか\nかけねぇように…", 0, 4, 0, 1, 1, 1, 135801, 9463);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("家具とか、飾りとか、\n壊しちまったら大変…\nき、気ぃつけねぇとっ", 0, 5, 0, 1, 1, 1, 135801, 9464);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あての三味線、\n聴きたいの…？\nこ、心の準備が\nできてからで、い…？", 0, 101, 0, 1, 4, 1, 135801, 9465);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("っ、ぁぶね…\nあてったらまた、\n騎士さのこと見て、\n溶けそうになってた…", 0, 102, 0, 1, 8, 1, 135801, 9466);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、おめさ、その…\nおやつさん、いらね？\nかき氷とかなら、\nあて、作れるよ…？", 0, 1, 0, 2, 1, 1, 135801, 9467);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、あてに…何か用？\n…声、聴きたかった？\nな、なら…えっと…\nおしゃべり…する？", 0, 2, 0, 2, 1, 1, 135801, 9468);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちさ来てから…\n向こうの世界の\n何年分も、おしゃべり\nしたかもしんね…", 0, 3, 0, 2, 1, 1, 135801, 9469);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界には、\n氷滑りって遊びが\nあるって…？\nあてにもできっかな…", 0, 4, 0, 2, 1, 1, 135801, 9470);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん…あては元気だよ\n悩みがあっても、\nおめさの声もらうと\n吹っ飛んじまうし…", 0, 101, 0, 2, 4, 1, 135801, 9471);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さが近くに\nいてくれる…\n今は、それだけで\nいいんだ…うん…", 0, 102, 0, 2, 8, 1, 135801, 9472);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お、おはよ…\nおめさのおかげで、\n昨夜もよく眠れたよ…", 0, 1, 1, 2, 1, 1, 135801, 9473);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…あっ、もう昼飯の\n時間かぁ…\n考えごとしてたら\nあっという間だよ", 0, 2, 2, 2, 1, 1, 135801, 9474);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("景色は似てるけど…\nこの世界の夜は、\nざわざわ音がして\n賑やかだな…", 0, 3, 3, 2, 1, 1, 135801, 9475);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんま縮こまってると\n体硬くなっちまうし…\nたまにはのんびり…", 0, 2, 0, 3, 1, 1, 135801, 9477);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ、めんこいな…\nそだ、仁太坊たちも\n並んでたら\nもっとめんこいかも…", 0, 3, 0, 3, 1, 1, 135801, 9478);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この匂い…なんか、\nは、はいから…？\nあて、イナカもん\nだから…", 0, 4, 0, 3, 1, 1, 135801, 9479);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、暑くて溶けそう…\nだども、我慢できたら\n修行になる…かも…？", 0, 5, 0, 3, 1, 1, 135801, 9480);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん…♪　うめぇ…\nこんなうめぇもん\n毎日食べられるの、\n幸せだなぁ…", 0, 7, 0, 3, 1, 1, 135801, 9482);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界にも…\n雪女が出る物語、\nあるみてぇだな…\nか、悲しい話だども…", 0, 8, 0, 3, 1, 1, 135801, 9483);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなか上等な\n家じゃねェか\nちっとばかし\n軒を借りるぜ", 0, 1, 0, 1, 1, 1, 135901, 9487);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("俺の棒っきれの\n置き場所は…\nま、玄関にでも\n立てかけときゃいいか", 0, 2, 0, 1, 1, 1, 135901, 9488);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界は\n眩しくって敵わねェぜ\n目がチカチカしやがる", 0, 3, 0, 1, 1, 1, 135901, 9489);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("建物の様式が同じでも\n世界と住人が違えば\n印象も変わるモンだな", 0, 4, 0, 1, 1, 1, 135901, 9490);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("街の連中は\n戦いなんて知らねェ\nのんきなツラしてんな\n…いいトコじゃねェか", 0, 5, 0, 1, 1, 1, 135901, 9491);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士公のヤツ、\nまたぞろ厄介事に\n巻き込まれや\nしてねェだろうな…", 0, 101, 0, 1, 4, 1, 135901, 9492);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわぁ…\nこうも居心地がいいと\n眠くなっちまうぜ", 0, 102, 0, 1, 8, 1, 135901, 9493);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("俺ばっかり\n見てんじゃねェよ\n赤鬼になっちまわぁ", 0, 1, 0, 2, 1, 1, 135901, 9494);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("注いでくれんのか？\nあんがとよ\nんじゃ俺からも\nお返しだぜ", 0, 2, 0, 2, 1, 1, 135901, 9495);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おう、暇してるなら\n鍛錬に付き合えよ\nじっとしてっと\n体がなまって仕方ねェ", 0, 3, 0, 2, 1, 1, 135901, 9496);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("退屈してきたな…\n散歩にでも行くか？\n騎士公なら退屈しねェ\n場所知ってるだろ", 0, 4, 0, 2, 1, 1, 135901, 9497);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("女との関係は\nきちっとしとけよ\n俺だって助けらんねぇ\nもんはあるからな", 0, 101, 0, 2, 4, 1, 135901, 9498);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("角に触りたいだぁ？\n…まあ、騎士公の\n頼みなら…\nあんま手荒にすんなよ", 0, 102, 0, 2, 8, 1, 135901, 9499);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きろ\n朝の鍛錬の時間だぜ\nほれ、さっさと\n身支度しちまいな", 0, 1, 1, 2, 1, 1, 135901, 9500);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼飯ィ？\n俺の分はいらねぇよ\n気ィつかわねぇで\nくんな", 0, 2, 2, 2, 1, 1, 135901, 9501);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まだ起きてんのか？\nさっさと寝ねェと\nこうやって鬼が来るぜ", 0, 3, 3, 2, 1, 1, 135901, 9502);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("悪くない座り心地だな\n気ィ抜くと、ダメに\nされちまいそうだぜ", 0, 2, 0, 3, 1, 1, 135901, 9504);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…今こいつ動いたか？\nグレ公あたりが\n悪さしてんじゃ\nねェだろうな", 0, 3, 0, 3, 1, 1, 135901, 9505);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士公はこういう\n香りが好みか？\nお姫とユキノに\n教えてやるとすっか", 0, 4, 0, 3, 1, 1, 135901, 9506);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("地獄の釜よりかは\nちとぬるいが…\nなかなか\nいい火力してやがるぜ", 0, 5, 0, 3, 1, 1, 135901, 9507);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの世界の本にも\n鬼が出てくるのか", 0, 8, 0, 3, 1, 1, 135901, 9510);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("フランシュシュ１号、\nサクラです！　サガの\n心を、歌でみんなに\n届けにきました！", 0, 1, 0, 1, 1, 1, 136101, 9514);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルはドキドキ\nいっぱいの街やけん！\nサガとどっちが\n暮らしやすかろうねっ", 0, 2, 0, 1, 1, 1, 136101, 9515);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ソロ活動がんばって、\n憧れの子にもも～っと\n近づくと！　成長した\n私、早く見せたか～！", 0, 3, 0, 1, 1, 1, 136101, 9516);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋におるとは、伝説\nのメンバーばかり…！\n私もこのランドソルで\n伝説ば刻むとよ！", 0, 4, 0, 1, 1, 1, 136101, 9517);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あそこの修繕が気に\nなると…。…あのっ！\nあ、ついあの子を\n呼びそうに…えへへっ", 0, 5, 0, 1, 1, 1, 136101, 9518);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドルのレッスン、\n気になると？　まず、\n脚をぐい～っと広げて\n…あわわ、戻らん！？", 0, 101, 0, 1, 4, 1, 136101, 9519);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんのコネが\nあれば、いつか堂々と\nゾンビアイドルで\n売り出せるかもっ…！", 0, 102, 0, 1, 8, 1, 136101, 9520);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようござい\nまーす！　挨拶は基本\nやけん、元気よくっ！\nさ、一緒にやろう！", 0, 1, 0, 2, 1, 1, 136101, 9521);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身だしなみチェック、\nよしっ。今日もいい\n天気っ♪　さあ、\nいってきまーーす！！", 0, 2, 0, 2, 1, 1, 136101, 9522);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんまり引っ張ると、\nう、腕が～…！　あ、\n気にせんで。伸びても\nすぐ元に戻るけんっ♪", 0, 3, 0, 2, 1, 1, 136101, 9523);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、持っとらんって\n思ってきたけど、それ\nが何ね！　友達ば、\nいっぱい持っとるけん", 0, 4, 0, 2, 1, 1, 136101, 9524);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("嚙めば噛むほど味が\n出る…騎士さんは\nサガのアタリメ\nみたいな人やねっ♪", 0, 101, 0, 2, 4, 1, 136101, 9525);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんにだけ教え\nますね。私の秘密…\n私の死因を。え？\nもう分かる気もする？", 0, 102, 0, 2, 8, 1, 136101, 9526);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぼ～っとしとかれんね\n「ぶっ殺すぞ」って\n気合入れてくれる子が\n両方の街におるけんっ", 0, 1, 1, 2, 1, 1, 136101, 9527);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのすごか食べっぷり\nよう思い出すとよ\n元気かな…変なもん\n食べてないかな…", 0, 2, 2, 2, 1, 1, 136101, 9528);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜、出歩くと、怖～い\nアンデッドに襲われる\nかもしれんよ！\n気をつけんと…！", 0, 3, 3, 2, 1, 1, 136101, 9529);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("リラックス！　もっと\nがんばってリラックス\nせんといかんね！\nむむむ～っ！", 0, 2, 0, 3, 1, 1, 136101, 9531);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("が～ばや～らしか～♪\nあの子のお土産に\nしたいけど、同じの\n売っとらんかな…？", 0, 3, 0, 3, 1, 1, 136101, 9532);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、いい香りっ♪\nいつもこやん素敵な\n香りのする人が、私の\n友達におってね…", 0, 4, 0, 3, 1, 1, 136101, 9533);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("え～と…熱いとその…\n傷んじゃいそうで、\nちょっと心配やけん…\nそ…その…私の体が", 0, 5, 0, 3, 1, 1, 136101, 9534);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わあ、美味しか～っ！\nランドソルのグルメも\nなかなか手強いっ…！\nサガも負けられんね～", 0, 7, 0, 3, 1, 1, 136101, 9536);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイドル雑誌はあると\nですかね？　フラン\nシュシュのランキング\nは…しょぼぼぼーん…", 0, 8, 0, 3, 1, 1, 136101, 9537);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("名探偵から聖職者へ、\n華麗なる変装だ！\nいや、心の中まで\n敬虔に…変貌、かな♪", 0, 1, 0, 1, 1, 1, 137401, 9541);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真実の鏡で、誰の謎も\n解いてみせるよ。\n恋の謎は…私が解いて\nほしいくらいだ…", 0, 2, 0, 1, 1, 1, 137401, 9542);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("歩き方も…厳かに…\n気品と高潔さが\n感じられるように\n練習しなくてはね", 0, 3, 0, 1, 1, 1, 137401, 9543);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の行いはきっと、\nどこかで見られている\nかつてお別れをした\n大切なあの子にも…ね", 0, 4, 0, 1, 1, 1, 137401, 9544);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("異議あり！　…う～ん\nもっと威厳をもって…\n異議あり！　はっ、\n聞いていたのかいっ！", 0, 5, 0, 1, 1, 1, 137401, 9545);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("静かに心を見つめれば\n大切なものが分かる\n助手くんとの時間の\nかけがえなさも、ね", 0, 101, 0, 1, 4, 1, 137401, 9546);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私も、想い合う二人の\n神聖な誓約の儀と\nいうものに憧れるよ\nつまり結婚式、にね…", 0, 102, 0, 1, 8, 1, 137401, 9547);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("珈琲を一杯お願い\nするよ、助手くん\nこれがないと私の\n推理が冴えなくてね", 0, 1, 0, 2, 1, 1, 137401, 9548);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("懺悔があるなら聞き\n届けよう。…え～っ！\n棚にある私のチョコを\n食べてしまったって！", 0, 2, 0, 2, 1, 1, 137401, 9549);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("助手くん、今日の\n依頼は何件かな\nもし誰も来ないなら\n一緒にお出かけしよう", 0, 3, 0, 2, 1, 1, 137401, 9550);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さあ、出かけようか\n君と私で巡礼の旅だ\n鞄の中身はただ一つ\n真実を愛する心、さ！", 0, 4, 0, 2, 1, 1, 137401, 9551);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に祈ってくれる\nかい？　ありがとう\n一人では真実が重荷に\nなるときもあってね", 0, 101, 0, 2, 4, 1, 137401, 9552);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("何でも話してほしい\n分かち合いたいんだ\n喜びも悲しみも、君が\n背負う、なにもかも", 0, 102, 0, 2, 8, 1, 137401, 9553);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう！　聖職者は\n早起きなのさ♪\nふわぁ…はっ、今の\nあくびは見てないね？", 0, 1, 1, 2, 1, 1, 137401, 9554);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日のお昼は…\n一緒に台所で\n作らないかい？\n新婚さんみたいに♪", 0, 2, 2, 2, 1, 1, 137401, 9555);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜のお祈りをしよう\n凶悪な事件なんて、\nもう起きないように", 0, 3, 3, 2, 1, 1, 137401, 9556);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ…ふかふか～…\n堕落してしまいそう…\nなんとも罪なアイテム\nだねえ、これは…", 0, 2, 0, 3, 1, 1, 137401, 9558);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいな…♪\n探偵事務所の机に\n置いたら場を和ませて\nくれそうだね", 0, 3, 0, 3, 1, 1, 137401, 9559);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ…心が落ち着く\nけして、その、小説の\n謎解きにイライラして\nいたわけではないよ？", 0, 4, 0, 3, 1, 1, 137401, 9560);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…暖かいね。こんな\n暖かさをあまねく\n世に届けるのが、\n今の私の役目だよ", 0, 5, 0, 3, 1, 1, 137401, 9561);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こんなにおいしい\nなんて、きっと重大な\n秘密が隠されているに\n違いないよね！", 0, 7, 0, 3, 1, 1, 137401, 9563);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時には推理小説でなく\n教えを説く本もいいね\nちょっとだけ…眠く\nなっちゃうけど…", 0, 8, 0, 3, 1, 1, 137401, 9564);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すんすん…\nなんか甘い匂いが\nするよーな？\nどこかなどこかな～", 0, 1, 0, 1, 1, 1, 136201, 9568);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お部屋の中、\nいっぱい歩いたよ～\nよーし、今日の訓練\nお～しまいっ♪", 0, 2, 0, 1, 1, 1, 136201, 9569);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どうしてドーナツには\n穴が開いてるんだろ？\nカスミちゃーん、\nおしえてーっ？", 0, 3, 0, 1, 1, 1, 136201, 9570);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いち、に、さん、し、\nごー、ろく…ナーナ！\nえへへへへ～♪", 0, 4, 0, 1, 1, 1, 136201, 9571);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("訓練しなきゃだけど…\nおやつとかゲームとか\nいろいろありすぎて…\nで、でもぉ～っ！", 0, 5, 0, 1, 1, 1, 136201, 9572);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここ、騎士ちゃんの\nお部屋って感じする！\nだってすっごく\n安心するもん", 0, 101, 0, 1, 4, 1, 136201, 9573);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お耳を澄ませたら～…\n騎士ちゃんの声、\nどこからだって\n聞こえちゃうんだ♪", 0, 102, 0, 1, 8, 1, 136201, 9574);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はい、ナーナだよっ\n騎士ちゃんに\nあいさつしてもらうと\n元気が出てくるねっ", 0, 1, 0, 2, 1, 1, 136201, 9575);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナーナの頭の角、\n気になっちゃった？\nさわってもいいよ～", 0, 2, 0, 2, 1, 1, 136201, 9576);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ナーナ、ずーっと\nだめだめだったけど…\nいつまでもそれじゃ\nだめだってわかったよ", 0, 3, 0, 2, 1, 1, 136201, 9577);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("るんるる～、らら～♪\nあっ、一緒に歌う？\nせーの、らんらら～♪", 0, 4, 0, 2, 1, 1, 136201, 9578);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねぇ騎士ちゃんっ\n今日も一緒に\nおでかけしようよ！\nどこへ行こっかな～♪", 0, 101, 0, 2, 4, 1, 136201, 9579);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルのごはん、\nどれもおいしいけど…\n一番はやっぱり\n騎士ちゃんのごはん！", 0, 102, 0, 2, 8, 1, 136201, 9580);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ～っ！\nおっきな声で\nあいさつすると\n気持ちいいよね♪", 0, 1, 1, 2, 1, 1, 136201, 9581);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんの時間だ！\nサクサクドーナツと\nもちもちドーナツ、\nどっちにしようかな～", 0, 2, 2, 2, 1, 1, 136201, 9582);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うーん、眠くなって\nきちゃった…\nみんなはまだまだ\n夜ふかしするの～？", 0, 3, 3, 2, 1, 1, 136201, 9583);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("訓練の後はちゃんと\n休むのが大事だよ\n…ナーナはいつも\n休んでるけどっ…", 0, 2, 0, 3, 1, 1, 136201, 9585);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたもナーナの\nお友達になっちゃお？\n「ウン、イイヨ！」\nやったぁ～♪", 0, 3, 0, 3, 1, 1, 136201, 9586);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい匂～い♪\nこの匂いつけたら\nナーナもお洒落さんに\nなれるかな～", 0, 4, 0, 3, 1, 1, 136201, 9587);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、あったかーい♪\nあっでも、お耳が\n焦げないように\n気をつけなきゃ…！", 0, 5, 0, 3, 1, 1, 136201, 9588);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いくら食べても\nなくならないなんて…\nすごすぎるよぉ～っ！\n絶対ふとっちゃう～！", 0, 7, 0, 3, 1, 1, 136201, 9590);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("むずかしそーな本だ！\nふむふむどれどれ…\nうん、むずかしい！", 0, 8, 0, 3, 1, 1, 136201, 9591);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスの時期は\nやりたいことが\nたくさんあって…\n忙しいけど楽しいね", 0, 1, 0, 1, 1, 1, 136401, 9595);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんながウキウキ\nしてるの、\n伝わってくるな♪", 0, 2, 0, 1, 1, 1, 136401, 9596);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("思い切っておしゃれ\nしてみたけど…\nちょっと照れちゃう", 0, 3, 0, 1, 1, 1, 136401, 9597);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誘惑に負けて\n限定のスイーツセット\n買っちゃった…！", 0, 4, 0, 1, 1, 1, 136401, 9598);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("帽子だけでも、\n印象が変わるんだよね\n新しい自分に\nなれたかな♪", 0, 5, 0, 1, 1, 1, 136401, 9599);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物のお料理…\nわたしも騎士クンに\n教えてもらおうかな…", 0, 101, 0, 1, 4, 1, 136401, 9600);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クンの温もりが\n恋しくなっちゃうのも\n寒い冬だから…だよね", 0, 102, 0, 1, 8, 1, 136401, 9601);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人っぽいコーデで、\nちょっと背伸びした\n気分…なんてねっ♪", 0, 1, 0, 2, 1, 1, 136401, 9602);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度一緒に\nお出かけしようよ\n騎士クンのお洋服\n選んであげるから", 0, 2, 0, 2, 1, 1, 136401, 9603);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度はここで\nパーティーしようよ\nきっと楽しいから", 0, 3, 0, 2, 1, 1, 136401, 9604);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("風邪には気をつけてね\nわたしが温めてあげ…\nな、なんでもない！", 0, 4, 0, 2, 1, 1, 136401, 9605);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒にゆっくり\nおしゃべりしよう？\nいくらでも付き合うよ", 0, 101, 0, 2, 4, 1, 136401, 9606);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士クン、\nぎゅーってさせて？", 0, 102, 0, 2, 8, 1, 136401, 9607);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう♪\n昨夜はわたし、\n騎士クンと夢の中でも\nデートしちゃった", 0, 1, 1, 2, 1, 1, 136401, 9608);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんの代わりに\nケーキは\nさ、さすがに\nいけないよね？", 0, 2, 2, 2, 1, 1, 136401, 9609);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あのね、一緒に\n夜更かし、しない？\n今夜だけ…ね？", 0, 3, 3, 2, 1, 1, 136401, 9610);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ん～、気持ちいい\nよかったら騎士クンも\n一緒に…", 0, 2, 0, 3, 1, 1, 136401, 9612);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみも\n楽しそうっ\nふふっ、かわいい♪", 0, 3, 0, 3, 1, 1, 136401, 9613);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アロマオイルとかも\nプレゼントの定番\nだよね…", 0, 4, 0, 3, 1, 1, 136401, 9614);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冷えた体が\nあったまって…\nね、眠くなっちゃう…\nふわぁ…", 0, 5, 0, 3, 1, 1, 136401, 9615);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛情のこもった\nお料理って、\nいくらでも\n食べられちゃう…！", 0, 7, 0, 3, 1, 1, 136401, 9617);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夢占いかぁ…\n昨夜の夢は、\nどんな意味なんだろ？\n…えぇっ、そんな…！", 0, 8, 0, 3, 1, 1, 136401, 9618);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("次のプレゼントは\nこういう本もいいかも\n騎士クンも\n喜んでくれそう…♪", 0, 14, 0, 3, 1, 1, 136401, 9622);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわもこだけど、\n動くのは大変っ…", 0, 15, 0, 3, 1, 1, 136401, 9623);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今からギルドハウスを\nクリスマス風に改造\nしちゃいます♪\nイイコトですよね★", 0, 1, 0, 1, 1, 1, 136301, 9624);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ええっと…飾りつけを\nするには、まず\nテレポーテーションで\nツリーをもってきて…", 0, 2, 0, 1, 1, 1, 136301, 9625);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスとはずっと\n無縁な人生でしたし\n普通にそれっぽいコト\nしてみたいですねー", 0, 3, 0, 1, 1, 1, 136301, 9626);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おうちでまったりも\nイイカンジです★\nあまーいココアでも\n淹れてみましょうか", 0, 4, 0, 1, 1, 1, 136301, 9627);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ケーキを食べ過ぎると\nいつかのユイさん\nみたいになっちゃう\nので要注意ですね★", 0, 5, 0, 1, 1, 1, 136301, 9628);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんは他の子と\nクリスマスデート中\nなんですかねー？\n邪魔しにいこうかなー", 0, 101, 0, 1, 4, 1, 136301, 9629);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士さんと\nクリスマスデート…\nふふっ、考えると\nニヤニヤしちゃいます", 0, 102, 0, 1, 8, 1, 136301, 9630);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、騎士さん\nお邪魔してまーす★\nクリスマスも一緒に\nイイコトしましょうか", 0, 1, 0, 2, 1, 1, 136301, 9631);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("外が寒すぎなので\n今日はイイコトクラブ\nも休部中ですよ★\nゆっくりしましょう♪", 0, 2, 0, 2, 1, 1, 136301, 9632);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この衣装ふわふわして\nついつい触りたく\nなっちゃいますよね？\n好きなだけイイですよ", 0, 3, 0, 2, 1, 1, 136301, 9633);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この白い衣装を血で\n真っ赤に染め上げる\n…なーんて事件は\n起きませんよ、多分", 0, 4, 0, 2, 1, 1, 136301, 9634);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クリスマスプレゼント\nのお届けでーす★\nプレゼントはもちろん\nわ・た・し、ですよ♥", 0, 101, 0, 2, 4, 1, 136301, 9635);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このギルドハウスは\nキスをしないと出られ\nないみたいですねー\n騎士さんどうしましょ", 0, 102, 0, 2, 8, 1, 136301, 9636);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぅ～、寒さで\n目が覚めちゃいました\n風邪引きたくないので\nぎゅっ★　しますね♪", 0, 1, 1, 2, 1, 1, 136301, 9637);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと気分転換に\n散歩でもいきますか\n雪が積もっていたら\n雪だるま作りましょう", 0, 2, 2, 2, 1, 1, 136301, 9638);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("サンタさんがそろそろ\n来る時間ですかね？\nやることやってベッド\nにいきましょうか★", 0, 3, 3, 2, 1, 1, 136301, 9639);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…\n聖夜騎姫★\nチャーミングスカイも\n充電が必要なんです", 0, 2, 0, 3, 1, 1, 136301, 9641);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぺんぽこりんはクビで\nこの子を戦わせるのも\nアリですね★\n壊れちゃいますけど♪", 0, 3, 0, 3, 1, 1, 136301, 9642);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…イイ香り♪\nクリスマスに\nピッタリですね", 0, 4, 0, 3, 1, 1, 136301, 9643);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかーい♪\nもうここから\n動けないですー", 0, 5, 0, 3, 1, 1, 136301, 9644);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これだけ食べたら\n冬眠もできそうです\n春になったら\n起こしてくださーい♪", 0, 7, 0, 3, 1, 1, 136301, 9646);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("へー、クリスマス\nケーキの作り方…\nランファさんにも後で\nシェアしてみますか", 0, 8, 0, 3, 1, 1, 136301, 9647);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あはっ、イイですねー\nバイオレンスな展開\nはなくてもちゃんと\n面白くなるんですね★", 0, 14, 0, 3, 1, 1, 136301, 9651);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こうして遊んでいると\nぺんぽこりんの\n着ぐるみもほしく\nなっちゃいます♪", 0, 15, 0, 3, 1, 1, 136301, 9652);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お父さまのような\n威厳のある佇まいを\n心がけたいものです", 0, 1, 0, 1, 1, 1, 137601, 9653);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見慣れた部屋が\n少し小さく感じます\nこの体の感覚にも\n早く慣れなければ…", 0, 2, 0, 1, 1, 1, 137601, 9654);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…おや？\n以前は見えなかった\n高いところの埃が…\nすぐに対処いたします", 0, 3, 0, 1, 1, 1, 137601, 9655);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わんわんの主さまも\n驚いたご様子でした\n人の成長は早いものと\n思われたでしょうか…", 0, 4, 0, 1, 1, 1, 137601, 9656);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すらりとした長い足…\n自分のものと\n分かっていても、つい\n見つめてしまいます…", 0, 5, 0, 1, 1, 1, 137601, 9657);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのために\nできることも\n増えました…\nふふ、胸が躍ります", 0, 101, 0, 1, 4, 1, 137601, 9658);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたくしの願いは、\n主さまと共にあること\nいわば、生涯を\n添い遂げるように…", 0, 102, 0, 1, 8, 1, 137601, 9659);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("新たな姿でも変わらず\nおはようから\nおやすみまで\nお供いたしますよ", 0, 1, 0, 2, 1, 1, 137601, 9660);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("装いも、大人の体に\n相応しいものに…\nエレガントさを\n心がけてみました", 0, 2, 0, 2, 1, 1, 137601, 9661);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日の買い出しでは\n少々買いすぎましたが\n大荷物でも平気でした\nすばらしいです…♪", 0, 3, 0, 2, 1, 1, 137601, 9662);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("主さまのための\n大事な体ですからね\n長い髪の手入れも\n念入りにいたします", 0, 4, 0, 2, 1, 1, 137601, 9663);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本日の添い寝は\n大人と子ども、\nどちらの姿に\nいたしましょうか", 0, 101, 0, 2, 4, 1, 137601, 9664);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたさま…\nあぁいえ、その…\n少し違う呼び名を\n試してみようかと", 0, 102, 0, 2, 8, 1, 137601, 9665);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n主さまとのご挨拶で\n始まる一日…\nワクワクいたします", 0, 1, 1, 2, 1, 1, 137601, 9666);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おや、もうお昼時…\nお腹の空き具合が\n違うと、少々感覚が\n鈍ってしまいますね", 0, 2, 2, 2, 1, 1, 137601, 9667);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おやすみの際には\nわたくしの子守唄を…\n安眠の力も以前より\n増しておりますよ♪", 0, 3, 3, 2, 1, 1, 137601, 9668);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつでも主さまに\n尽くせるよう、\n体を休めることも\n大事です…ふぅ", 0, 2, 0, 3, 1, 1, 137601, 9670);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("愛らしいものを\n慈しむ心は、\n大人になっても\n変わりません…", 0, 3, 0, 3, 1, 1, 137601, 9671);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人の体になると、\n匂いの感じかたも\n少し変わるような…？\n不思議なものです", 0, 4, 0, 3, 1, 1, 137601, 9672);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手足が冷えないよう\nしっかり温めて…\n冷え性は大人の悩みと\n伺いましたので", 0, 5, 0, 3, 1, 1, 137601, 9673);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("胃のほうも、前より\n大きくなった模様です\n手が止まりません…\nもぐもぐ…", 0, 7, 0, 3, 1, 1, 137601, 9675);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("久々に、主さまに\n本の読み聞かせを\nしましょうか\nふふ、楽しみです", 0, 8, 0, 3, 1, 1, 137601, 9676);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんは何が好きかな\n縁起物がいっぱいの\nおせち料理を\n食べてほしいんだよね", 0, 1, 0, 1, 1, 1, 136501, 9682);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと…帯がきつい\nかも…おせち料理の\n食べすぎかな？\n気を付けなくちゃ", 0, 2, 0, 1, 1, 1, 136501, 9683);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初日の出は見なくちゃ\n新しい一年の始まりを\n告げるお日さまに\n挨拶しておきたいし", 0, 3, 0, 1, 1, 1, 136501, 9684);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘酒って不思議…\nすっごく寒い日に\n飲むと、もっと\nおいしくなるんだもん", 0, 4, 0, 1, 1, 1, 136501, 9685);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("着物のお姉ちゃん♪\nいつもとは違う格好で\n弟くんをドキドキ\nさせちゃおっと♪", 0, 5, 0, 1, 1, 1, 136501, 9686);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うふふ…弟くんの寝顔\nかわいかったなぁ♪\nもはや国宝級だよ！", 0, 101, 0, 1, 4, 1, 136501, 9687);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんの着物姿、\nかっこよかった～♪\nはぁぁ…思い出したら\nドキドキしてきた…♪", 0, 102, 0, 1, 8, 1, 136501, 9688);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私の着物が気になる？\n触ってもいいよ\n肌触りがよくって、\n着心地も最高なんだ～", 0, 1, 0, 2, 1, 1, 136501, 9689);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("初詣に行くときは手を\n繋ごうね。人混みの\n中ではぐれたりしたら\n大変だもんっ", 0, 2, 0, 2, 1, 1, 136501, 9690);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("叶えたいことが\nあったら言ってね？\nお姉ちゃんが全力で\n協力するから！", 0, 3, 0, 2, 1, 1, 136501, 9691);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月は一緒に\n過ごしてお買い物も\nして…ラブラブな\n時間を楽しもうねっ♪", 0, 4, 0, 2, 1, 1, 136501, 9692);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…大好きだよ、弟くん\nふふっ、急にごめんね\nどうしても今、伝えた\nいって思っちゃったの", 0, 101, 0, 2, 4, 1, 136501, 9693);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弟くんにもらった指輪\n宝物だよ♪　だけど\nいつか本当の新婚さん\nになりたいな…♪", 0, 102, 0, 2, 8, 1, 136501, 9694);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月の朝は空気が\n冷たいよね。こんな\nときは、太陽の光を\n浴びながらお散歩しよ", 0, 1, 1, 2, 1, 1, 136501, 9695);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はお雑煮！\n出汁も具材も\nこだわったから、\n楽しみにしててね♪", 0, 2, 2, 2, 1, 1, 136501, 9696);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝よっか？\nそうだ、添い寝をして\nあげる！　寒いとなか\nなか寝付けないでしょ", 0, 3, 3, 2, 1, 1, 136501, 9697);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("座り方には気を付け\nないと。きれいな\n着物に、しわは作り\nたくないもんね", 0, 2, 0, 3, 1, 1, 136501, 9699);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわでかわいいね\nこの子たちも、\n弟くんとの生活、\nお祝いしてくれてる？", 0, 3, 0, 3, 1, 1, 136501, 9700);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…神社のお香\nみたい♪　いいこと\nありそうな気が\nしてきたよ", 0, 4, 0, 3, 1, 1, 136501, 9701);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒い日に暖炉はありが\nたいな～♪　ここで\nお餅を焼けば、お腹も\n膨れて一石二鳥かも♪", 0, 5, 0, 3, 1, 1, 136501, 9702);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹いっぱい…でも\nまだ食べたい！　う～\nこれじゃ、正月太りへ\nまっしぐらだよ～", 0, 7, 0, 3, 1, 1, 136501, 9704);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ラブラブだけじゃなく\nもくもくと一緒に本を\n読むのもいいよね♪\nお正月は時間もあるし", 0, 8, 0, 3, 1, 1, 136501, 9705);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『囲い完全』の絵馬を\n吊るしてきました！\nこれで家の中は\nもう大丈夫ですね！", 0, 1, 0, 1, 1, 1, 137901, 9711);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("正月遊びも雪遊びも\n全部やりたいです！\nえへへ、ちょっぴり\n欲張りでしょうか？", 0, 2, 0, 1, 1, 1, 137901, 9712);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マスターから\nお年玉貰えましたー！\n何に使おうか\n迷っちゃいますね～♪", 0, 3, 0, 1, 1, 1, 137901, 9713);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ついだらっとしちゃう\nお正月だからこそ！\n楽しかったって言える\n思い出を作るんです♪", 0, 4, 0, 1, 1, 1, 137901, 9714);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おせち♪　おせち♪\n中でも昆布と数の子が\n好きなんですよ～♪", 0, 5, 0, 1, 1, 1, 137901, 9715);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今年の恋愛運は大吉♪\n一歩踏み出すチャンス\n絶対逃さずに\n掴み取りますよ～！", 0, 101, 0, 1, 4, 1, 137901, 9716);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっそりポストに\nお兄ちゃんへの\n年賀状を投入☆\nいつ気付くかな～♪", 0, 102, 0, 1, 8, 1, 137901, 9717);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お正月の初夢は…\n一兄二姉三マスター\nでした！　縁起が\nいいです♪", 0, 1, 0, 2, 1, 1, 137901, 9718);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃん、お餅つき\nしませんか？\n兄妹のチームワークで\n沢山作りますよ！", 0, 2, 0, 2, 1, 1, 137901, 9719);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("さむ～い…\n…お兄ちゃん、\nポケット失礼しますね\n…えへへっ♪", 0, 3, 0, 2, 1, 1, 137901, 9720);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お掃除はお任せあれ！\n頼りになる妹目指して\nお手伝いしますよー！", 0, 4, 0, 2, 1, 1, 137901, 9721);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄ちゃんと過ごす\nお正月は毎年\n大大吉ですよ☆", 0, 101, 0, 2, 4, 1, 137901, 9722);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寒いなら\n私が妹ゆたんぽに\nなってあげますよ♪\nぎゅってして下さい☆", 0, 102, 0, 2, 8, 1, 137901, 9723);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("朝ごはんにお雑煮は\nどうですか？\nマスター秘伝のレシピ\nアレンジしてみました", 0, 1, 1, 2, 1, 1, 137901, 9724);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼になっても\nお正月は冷えますね～\n一緒にこたつに入って\nぬくぬくしませんか？", 0, 2, 2, 2, 1, 1, 137901, 9725);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もう寝る時間ですね～\nお兄ちゃんも\nいい初夢が\n見られますように♪", 0, 3, 3, 2, 1, 1, 137901, 9726);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…\nあ、ここちょっとだけ\nお兄ちゃんの匂いが…\nくんくんくんくん…", 0, 2, 0, 3, 1, 1, 137901, 9728);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子たちにも\n初日の出を見せて\nあげたいですね～♪\n連れていけるかな？", 0, 3, 0, 3, 1, 1, 137901, 9729);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これがお兄ちゃんの\n好みの香りですね\nメモしておきましょう", 0, 4, 0, 3, 1, 1, 137901, 9730);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こう暖かいと\nだんだん眠く…\nふわぁ～…", 0, 5, 0, 3, 1, 1, 137901, 9731);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしい～☆\nでも、着物の時は\nちゃんと抑えめに\nしておかないと…！", 0, 7, 0, 3, 1, 1, 137901, 9733);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『黎明界完全攻略本』\n作って入れておいたら\n誰かの役に立つ日が\n来るかも…？", 0, 8, 0, 3, 1, 1, 137901, 9734);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("冥界ではないのに\n落ち着きますわ\n騎士様の気配が\nあるからでしょうか…", 0, 1, 0, 1, 1, 1, 138001, 9740);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("普段食が細いせいか\n少し食べすぎると\nすぐ体重が…気を付け\nなくてはいけませんね", 0, 2, 0, 1, 1, 1, 138001, 9741);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ジオ・テオゴニアには\nお菓子の城があるとか\n本当に童話のようです\n想像が膨らみますわ", 0, 3, 0, 1, 1, 1, 138001, 9742);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("刺激的な料理の数々\nジオ・ゲヘナの強さは\nきっと食生活の影響も\n大きいのでしょうね", 0, 4, 0, 1, 1, 1, 138001, 9743);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの魚は大き\nくて活きが良いとか\n釣り…わたくしでも\nできるでしょうか？", 0, 5, 0, 1, 1, 1, 138001, 9744);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("解決すべき問題は沢山\nありますが、騎士様と\n共に、乗り越えられる\nと信じておりますわ", 0, 101, 0, 1, 4, 1, 138001, 9745);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この装い…風が吹くと\nすぐ裾がめくれて…\n騎士様に見られたら\n大変です…！", 0, 102, 0, 1, 8, 1, 138001, 9746);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魚の捌き方なら\nおまかせください♪\n体が覚えるまで何度も\n練習しましたから", 0, 1, 0, 2, 1, 1, 138001, 9747);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理の楽しさを知って\nしまいました…♪\n大切な人と食卓を共に\nする、その尊さも…", 0, 2, 0, 2, 1, 1, 138001, 9748);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手、ですか？\nばんそうこうだらけで\nお恥ずかしいですが…\nこれも勲章です", 0, 3, 0, 2, 1, 1, 138001, 9749);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本日は視察の公務が\nありまして。あの…\n騎士様。一緒に来ては\nいただけませんか…？", 0, 4, 0, 2, 1, 1, 138001, 9750);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べた人の服が\n弾けないように\nするにはどうしたら\n良いのでしょうか…", 0, 101, 0, 2, 4, 1, 138001, 9751);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理の道は一日にして\n成らず…日々の精進で\n騎士様に飽きられない\n味を目指します…！", 0, 102, 0, 2, 8, 1, 138001, 9752);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n清々しい朝ですね…♪\nっくしゅん！　肌寒い\nのは困りものですが…", 0, 1, 1, 2, 1, 1, 138001, 9753);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼を食べたら一休み\nいたしましょう\n騎士様と共に過ごす\n時間が幸せです…♪", 0, 2, 2, 2, 1, 1, 138001, 9754);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士様、お夜食は\n必要ですか？\n練習で作ってみたので\nその…よければ…", 0, 3, 3, 2, 1, 1, 138001, 9755);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ…身も心も\n溶けてしまいそう…♪\nこの姿は、他の誰にも\n見せられませんね", 0, 2, 0, 3, 1, 1, 138001, 9757);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なんて愛らしい…♪\n霊獣たちの仲間に\n迎えられたりしない\nでしょうか…♪", 0, 3, 0, 3, 1, 1, 138001, 9758);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("落ち着きますわね…\n心を静める香りに\n今は少しだけ\n心をゆだねましょう", 0, 4, 0, 3, 1, 1, 138001, 9759);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あら？　一緒にいた\nあの子たちはどこに…\n…もしかして乾燥や\n蒸発が怖いのかしら", 0, 5, 0, 3, 1, 1, 138001, 9760);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美味しい…♪\n作り手の真心を\n感じますわね\nもう一ついただきます", 0, 7, 0, 3, 1, 1, 138001, 9762);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの料理…\nレシピがあれば、\nわたくしにも作れる\nでしょうか…？", 0, 8, 0, 3, 1, 1, 138001, 9763);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("万博の余韻に\n心がふわふわとして…\nいつもより浮いて\nしまっているかも…♪", 0, 1, 0, 1, 1, 1, 138101, 9769);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルはまるで\nペコリーヌ姫のよう\n国民を見れば彼女の\n人柄が感じられます", 0, 2, 0, 1, 1, 1, 138101, 9770);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マスコットキャラ…\nわが国でも導入すべき\nでしょうか。クルルに\n相談してみましょう", 0, 3, 0, 1, 1, 1, 138101, 9771);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("後腐れのない\n公平な勝負であれば\n全力で臨みますよ\nふふ、腕が鳴ります", 0, 4, 0, 1, 1, 1, 138101, 9772);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弱気になったとき、\n身近な人の存在が、\nわたしに前を向かせる\n力をくれるのです", 0, 5, 0, 1, 1, 1, 138101, 9773);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お菓子を食べたときの\n笑顔が見たくて\nお菓子を作っているの\nかもしれません", 0, 101, 0, 1, 4, 1, 138101, 9774);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("種族も、生まれすら、\n世界が違っても、\nわたしたちはきっと\n心を通わせられます", 0, 102, 0, 1, 8, 1, 138101, 9775);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("信じていますからね、\n騎士？　もしめくろう\nとしたら…天罰です♪", 0, 1, 0, 2, 1, 1, 138101, 9776);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("意外と力はあるんです\nよ。お菓子作りに力は\n必要なので。試しに\n腕相撲をしてみます？", 0, 2, 0, 2, 1, 1, 138101, 9777);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("気分転換に部屋の模様\n替えをしませんか？\nジオ・テオゴニア風に\nお菓子の家具とか♪", 0, 3, 0, 2, 1, 1, 138101, 9778);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お茶にしましょうね\n先日採ったはちみつ、\n持ってきたんです♪\n何杯入れますか？", 0, 4, 0, 2, 1, 1, 138101, 9779);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食べたいお菓子は\nありますか？\nいつでも作りますよ\nお礼は笑顔で十分です", 0, 101, 0, 2, 4, 1, 138101, 9780);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなた…ふふっ♪\nすみません、なぜだか\nそう呼んでみたく\nなったんです…♪", 0, 102, 0, 2, 8, 1, 138101, 9781);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわふわパンケーキに\nハチミツをたっぷり…\n朝食がまだなら一緒に\nいかがですか？　騎士", 0, 1, 1, 2, 1, 1, 138101, 9782);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はハニートースト\nです♪　甘いものを\nたくさん食べて、午後\nもがんばりましょう", 0, 2, 2, 2, 1, 1, 138101, 9783);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夕飯はドーナツです\nそれも食べ放題♪\nお腹いっぱいになる\nまで食べてくださいね", 0, 3, 3, 2, 1, 1, 138101, 9784);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腰を下ろす時間も必要\nですね。浮いていては\n大事なことを見逃す\nかもしれませんから", 0, 2, 0, 3, 1, 1, 138101, 9786);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見た目のかわいらしさ\n触れたときの柔らかさ\nお菓子と同じ、調和が\n大切ですね…♪", 0, 3, 0, 3, 1, 1, 138101, 9787);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("素敵な香りですね…\n今日のティータイムは\nこの香りに合う\nお菓子を出しますね", 0, 4, 0, 3, 1, 1, 138101, 9788);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかいと、安心感\nで、つい…まだ秘密に\nするはずの気持ちも\n話してしまいそうです", 0, 5, 0, 3, 1, 1, 138101, 9789);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食は人を幸せにします\n…とはいえ、食べすぎ\nには注意、ですね", 0, 7, 0, 3, 1, 1, 138101, 9791);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『アストルムの珍味\n100選』？　これは\n興味深い…甘いものも\nあるでしょうか？", 0, 8, 0, 3, 1, 1, 138101, 9792);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦を忘れ、我が家にて\n憩ふ時こそ至高也\nゆるりゆるりと…♪", 0, 1, 0, 1, 1, 1, 138201, 9798);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("美食巡りし冒険\n御暇なる折にでも\nお聞きしたくありんす", 0, 2, 0, 1, 1, 1, 138201, 9799);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("身丈異なれば\n見ゆるものも異にして\n趣深く候。騎士殿の\n御顔も近うなれば…♪", 0, 3, 0, 1, 1, 1, 138201, 9800);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ランドソルの食の祭典\n煮炊きの技を競うとは\n新奇なる験。大変\n美味しゅう御座んした", 0, 4, 0, 1, 1, 1, 138201, 9801);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("種種様様なる国の御饗\n正しく千差万別也\n腹が千切れる程味わい\nましょうぞ、騎士殿や", 0, 5, 0, 1, 1, 1, 138201, 9802);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("他者に信を置くは\n思いの他に至難極みて\n難しきこと也", 0, 101, 0, 1, 4, 1, 138201, 9803);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士殿は只在るが侭に\nその御身体も御心も\nわっちが身命を賭して\n御守りします故", 0, 102, 0, 1, 8, 1, 138201, 9804);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いけませぬ、騎士殿や\n今のわっちが如何に\n『ないすばでぃ』と\nいえど戯れは程々に♪", 0, 1, 0, 2, 1, 1, 138201, 9805);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("食を求めし旅路\nわっちを連れ給はんや\n騎士殿や？", 0, 2, 0, 2, 1, 1, 138201, 9806);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よき縁こそ\n万事に代えべからざる\n至宝なりけり", 0, 3, 0, 2, 1, 1, 138201, 9807);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("此の装束の生地は\n最上の膚触りに候\n騎士殿であれば\n撫で給へど苦しからず", 0, 4, 0, 2, 1, 1, 138201, 9808);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("時には媛としての\n公の事を離れ\n羽を伸ばすも一興\nさ、参ろうぞ騎士殿や", 0, 101, 0, 2, 4, 1, 138201, 9809);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士殿や\nもっと御傍に\n─コロコロコロ\n愛い顔でありんすの", 0, 102, 0, 2, 8, 1, 138201, 9810);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一日の計は朝に\nありと申しんす\n御目覚めのほどは\n如何かえ騎士殿や", 0, 1, 1, 2, 1, 1, 138201, 9811);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はや昼時を迎え候\n共に昼餉の支度を\nしませむか", 0, 2, 2, 2, 1, 1, 138201, 9812);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宵の明くるまで\n起き明かすは体に毒\n我が身を労わりて疾く\nお休みくだしゃんせ", 0, 3, 3, 2, 1, 1, 138201, 9813);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("実に優れたる座し心地\nわっちの蛇も\n僻みてしまうやも\nしれませぬ喃", 0, 2, 0, 3, 1, 1, 138201, 9814);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どれ\n稚児らの土産に\n斯様が如き玩具でも\n買うて帰りましょうや", 0, 3, 0, 3, 1, 1, 138201, 9815);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…此の香り\n鬼岩城砦の薫物として\n取り入れたく候", 0, 4, 0, 3, 1, 1, 138201, 9816);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("暖かき心地も\nジオ・ゲヘナの地に\n住まえば清新とすら\n覚えまする", 0, 5, 0, 3, 1, 1, 138201, 9817);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("斯様な佳肴も\n皆で食してこそ\n味わい際立つもので\nありんしょう", 0, 7, 0, 3, 1, 1, 138201, 9818);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("異なる国々の\n『れしぴ』を蒐集し\nモネらに振る舞うも\n一興やもしれぬ喃", 0, 8, 0, 3, 1, 1, 138201, 9819);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この国の矜持は\nユースティアナの\n矜持でもあります！", 0, 1, 0, 1, 1, 1, 138301, 9820);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹も心もいっぱい！\n今なら書類も、完璧に\nこなしてみせますよ\n…たぶん…", 0, 2, 0, 1, 1, 1, 138301, 9821);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("至高のおにぎり…\n考えるだけで\nお腹がペコペコに…", 0, 3, 0, 1, 1, 1, 138301, 9822);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなさんがわたしを\n想ってくれたように\nわたしの想いも\n伝えていきたいです", 0, 4, 0, 1, 1, 1, 138301, 9823);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みなさんから\nお預かりした力…\n大切に使いますね", 0, 5, 0, 1, 1, 1, 138301, 9824);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("えへへ☆\nお腹が空くって\n幸せなことですね！", 0, 101, 0, 1, 4, 1, 138301, 9825);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人がにぎって\nくれたおにぎり…\nまた食べたくなって\nきちゃいました☆", 0, 102, 0, 1, 8, 1, 138301, 9826);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日はどんな食卓に\nしましょうか？\n幸せなごはん、\nたくさん作りましょう", 0, 1, 0, 2, 1, 1, 138301, 9827);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("料理が愛で\nできているように、\nわたしの体も愛で\nできているんですよね", 0, 2, 0, 2, 1, 1, 138301, 9828);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("覚醒とは関係なく\nあなたのおにぎりを\nお腹も胸も弾けるほど\nいっぱい食べたいです", 0, 3, 0, 2, 1, 1, 138301, 9829);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰にも奪わせない…\nわたしの決意が\n女神アストライアに\n伝わったんでしょうか", 0, 4, 0, 2, 1, 1, 138301, 9830);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと半分こした\nあのおにぎりは\n幸せの味がしました☆\nごちそうさまです♪", 0, 101, 0, 2, 4, 1, 138301, 9831);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたと食卓を囲う\n幸せ…あの日常が\nあるから、今日の\nわたしも元気です☆", 0, 102, 0, 2, 8, 1, 138301, 9832);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹がペコペコで\n目が覚めちゃいました\nあなたもですか？\nおそろいですね☆", 0, 1, 1, 2, 1, 1, 138301, 9833);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("矜持だけでは\nお腹は膨れません…\nということでランチ♪\nあなたもどうですか？", 0, 2, 2, 2, 1, 1, 138301, 9834);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝る準備を…\nの前に、お夜食です☆\nあなたとゆっくり、\nおしゃべりしながら…", 0, 3, 3, 2, 1, 1, 138301, 9835);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プリンセスにも\n休憩は必要\nですよね～…", 0, 2, 0, 3, 1, 1, 138301, 9837);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいくて\n食べちゃいたい…\nもちろん冗談ですよ～", 0, 3, 0, 3, 1, 1, 138301, 9838);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はわわ～…\nいい香りでお腹も\nグーって言ってます…", 0, 4, 0, 3, 1, 1, 138301, 9839);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～♪\nぬくぬくですね…\nあの人もいたら\nもっとぬくぬくなのに", 0, 5, 0, 3, 1, 1, 138301, 9840);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はむはむはむ…♪\nお腹が空くって\n幸せですね☆", 0, 7, 0, 3, 1, 1, 138301, 9842);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『この大陸には\n星の女神の名が\n与えられた』って\n書いてありますね", 0, 8, 0, 3, 1, 1, 138301, 9843);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士きゅんのために\nスライム風呂でも\n用意しとくか～", 0, 103, 0, 1, 12, 1, 123301, 9849);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おねえちゃんの肌\nぷるっぷるっしょ～？\n触ってイイよ～♡", 0, 103, 0, 2, 12, 1, 123301, 9850);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この水着どうですか？\n黒、なんて…大胆？\n背伸びしすぎたかも…", 0, 1, 0, 1, 1, 1, 138701, 9851);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お尻を鍛えたせいで\nちょっとムチムチに…\n元からじゃないですっ", 0, 2, 0, 1, 1, 1, 138701, 9852);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着を着てるうちに\nバンディシャーク号の\n洗車やっちゃおうかな", 0, 3, 0, 1, 1, 1, 138701, 9853);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("真冬はサマー！\n…考えたひとは\n悪魔だと思ってます…\n真冬は真冬です…", 0, 4, 0, 1, 1, 1, 138701, 9854);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("常夏のリゾート\nメリゾでのんびり…\nとっても楽しかったな\nまた行きましょうね", 0, 5, 0, 1, 1, 1, 138701, 9855);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ずっと水着でいると\n感覚が麻痺してきて…\nお尻を突き出すのも\n慣れちゃって…はぅぅ", 0, 101, 0, 1, 4, 1, 138701, 9856);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("せっかくの水着だし\n今度は海にいきたいな\nもちろん騎士さんと\n一緒に…えへへ♪", 0, 102, 0, 1, 8, 1, 138701, 9857);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("買い物してたら\n決勝見ましたって人に\n握手をせがまれて…\nわたしって、有名人？", 0, 1, 0, 2, 1, 1, 138701, 9858);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("修行したおかげで\nたくさん洗い物しても\n腰が痛くないんです！", 0, 2, 0, 2, 1, 1, 138701, 9859);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("伝説の桃闘者…\nそれが、わたし？\nで、伝説のままで\nいいんじゃないかな…", 0, 3, 0, 2, 1, 1, 138701, 9860);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ウォータースライダー\n一緒に滑りましょう\n泳げなくても大丈夫\nわたしが支えますから", 0, 4, 0, 2, 1, 1, 138701, 9861);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしのお尻、\n『桃尻』らしいけど…\n褒められてるのかな？\n自分じゃ見えないし…", 0, 101, 0, 2, 4, 1, 138701, 9862);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("尻文字であいうえお…\n特訓で繰り返したから\n今でも勝手にお尻が\n動いちゃう…", 0, 102, 0, 2, 8, 1, 138701, 9863);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n朝ごはんできてますよ\nあまーい卵焼きです", 0, 1, 1, 2, 1, 1, 138701, 9864);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼は何つくろう…\n朝の残りの卵を使って\nオムライスとか？", 0, 2, 2, 2, 1, 1, 138701, 9865);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泳ぎ疲れた時は\n早めに寝るのが一番\nお布団ひきますね", 0, 3, 3, 2, 1, 1, 138701, 9866);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こういうの\nバンディシャーク号\nにも置きたいな…", 0, 2, 0, 3, 1, 1, 138701, 9868);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かわいいけど\nいざ買うってなると\nそのお金でおかずを…\nって考えちゃうなあ", 0, 3, 0, 3, 1, 1, 138701, 9869);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カレーのアロマって\nないのかな…？\n食欲増進によさそう？", 0, 4, 0, 3, 1, 1, 138701, 9870);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はあ…暖かい…\n雪山での特訓は\nつらかったなぁ…", 0, 5, 0, 3, 1, 1, 138701, 9871);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無限キャベツは\n作ったことあるけど\nこれは太りそう…\nでも、止まらない～", 0, 7, 0, 3, 1, 1, 138701, 9873);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スポーツ選手名鑑に\nワカナって載ってる！\nミフユコーチ、\n仕事速すぎっ！", 0, 8, 0, 3, 1, 1, 138701, 9874);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい乗り心地\nスパイクちゃん達より\n速いのかな…？", 0, 10, 0, 3, 1, 1, 138701, 9876);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この貝の中に入って\nじっとしてたら\nいつかわたしも\n輝く真珠に…？", 0, 11, 0, 3, 1, 1, 138701, 9877);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着を着てると、\nいつもより少し大胆に\nなれる気がする…", 0, 1, 0, 1, 1, 1, 138801, 9880);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やってみたいこと、\nいろいろ増えたなぁ\nあの人もきっと\n応援してくれるよね", 0, 2, 0, 1, 1, 1, 138801, 9881);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法のお尻、\nピュアリーピーチっ\n…す、すみません\n冗談です", 0, 3, 0, 1, 1, 1, 138801, 9882);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("防水加工したら、\nプールでも読書できる\nよね。ぷかぷか浮いて\n読書なんて…素敵だな", 0, 4, 0, 1, 1, 1, 138801, 9883);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("濡れた耳や尻尾は\nしっかり乾かして…\n毛並みが乱れちゃうと\n直すのが大変", 0, 5, 0, 1, 1, 1, 138801, 9884);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人のお尻は\nどんな感じなんだろ…\nはっ、私ったら\nいったい何を…？", 0, 101, 0, 1, 4, 1, 138801, 9885);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("強くなればその分、\nあの人の隣で戦える\n最強の桃闘者として…\nは、やめておこう…", 0, 102, 0, 1, 8, 1, 138801, 9886);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昨日、買い物中に\n声をかけられたんです\nもしかして私、\n有名人になってる…？", 0, 1, 0, 2, 1, 1, 138801, 9887);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で過ごしてると\n動きやすくていいな～\nなんて思っちゃいます\n慣れって怖いですね", 0, 2, 0, 2, 1, 1, 138801, 9888);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腕も脚も、前より\n力がついてると\n思うんです\n…触ってみます？", 0, 3, 0, 2, 1, 1, 138801, 9889);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特訓の成果で、感覚が\n鋭くなった気がします\nあなたの声も\n聞き逃しませんよ", 0, 4, 0, 2, 1, 1, 138801, 9890);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの、その…\n私のお尻、あなたも\n魅力的だって\n思いますか…？", 0, 101, 0, 2, 4, 1, 138801, 9891);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたが何かに\n挑戦するときは、\n私も精いっぱい\nサポートしますっ…", 0, 102, 0, 2, 8, 1, 138801, 9892);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n体を動かすと質のいい\n睡眠をとれるみたい\n早起きできましたよ♪", 0, 1, 1, 2, 1, 1, 138801, 9893);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはん、一緒に\nどうですか？　また\nピーチクラッシュ・\nフェアに行きたくて", 0, 2, 2, 2, 1, 1, 138801, 9894);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("寝る前はストレッチ\n一緒にしませんか\nそれともマッサージが\nいいですか？", 0, 3, 3, 2, 1, 1, 138801, 9895);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この感触、あの人の\nふくらはぎと同じ…？", 0, 2, 0, 3, 1, 1, 138801, 9897);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぬいぐるみさんも、\nヒップレスリングの\n練習してみる？", 0, 3, 0, 3, 1, 1, 138801, 9898);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この香り…\nはちみっさに少し\n似てるような…？\nき、気のせいだよね", 0, 4, 0, 3, 1, 1, 138801, 9899);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("水着で冷えた体が\n温まるの、ほっとする\nこれが冬の醍醐味…？", 0, 5, 0, 3, 1, 1, 138801, 9900);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("日々の食事が\n健康な体を作る…\nよく食べてよく鍛える\nそれが全ての基本♪", 0, 7, 0, 3, 1, 1, 138801, 9902);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スポーツ名鑑かぁ…\n…えっ、私のことが\nもう載ってる…？", 0, 8, 0, 3, 1, 1, 138801, 9903);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい乗り心地だけど…\n夢中になってたら\nニャットちゃんが\n拗ねちゃうかも", 0, 10, 0, 3, 1, 1, 138801, 9905);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このクッション、\n気持ちいいなぁ\nこう、お尻にぴたっと\nフィットする感じで…", 0, 11, 0, 3, 1, 1, 138801, 9906);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おふくろの味が恋しい\nです…まぁ、キョウカ\nお嬢様のお義母さんの\nことなんですけどね", 0, 1, 0, 1, 1, 1, 138901, 9909);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あれ？　もしかして私\nここに入り浸りすぎ？\nもはや地縛霊ですね\n…それも悪くないか", 0, 2, 0, 1, 1, 1, 138901, 9910);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("守護騎士をクビに\nなったときはショック\nでしたね。一人きり\nだったらグレてたかも", 0, 3, 0, 1, 1, 1, 138901, 9911);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士氏へのお礼にドッ\nキリプレゼントとか\nしたいですね。心臓が\n止まるレベルのやつ", 0, 4, 0, 1, 1, 1, 138901, 9912);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よっ、ふっ、はっ！\n…やはり幽霊たるもの\nポールダンスができて\nこそ一人前です", 0, 5, 0, 1, 1, 1, 138901, 9913);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヒマです。騎士氏でも\n捕まえてヒマつぶしに\n付き合ってもらうしか\nないですね。騎士氏～", 0, 101, 0, 1, 4, 1, 138901, 9914);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士氏の好物を調査\nしておきますか。これ\nから先、まだまだお世\n話になりそうですから", 0, 102, 0, 1, 8, 1, 138901, 9915);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私が呪われるのって\nズルくないですか？\nこちとら当たり判定が\n曖昧な幽霊なのに", 0, 1, 0, 2, 1, 1, 138901, 9916);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("油断大敵ですよ。いつ\n誰が背後に忍び寄るか\nわかりませんからね\nたとえば私みたいに", 0, 2, 0, 2, 1, 1, 138901, 9917);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("立ってる棒を見ると、\nポールダンスができる\nか確かめますよね\n…あれ、私だけ？", 0, 3, 0, 2, 1, 1, 138901, 9918);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はーい、ウサギちゃん\nへのお触りは禁止です\nよー。次にやったら\n首ちょんぱでーす", 0, 4, 0, 2, 1, 1, 138901, 9919);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("生きる上で知識は必要\n…ということで勉強を\n教えたい気分なので、\nそこに座ってください", 0, 101, 0, 2, 4, 1, 138901, 9920);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("やはり私を飼いたいの\nでしょう？　罪な女で\nすね私は…糸くずがつ\nいてただけ？　…ちっ", 0, 102, 0, 2, 8, 1, 138901, 9921);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("起きていたのですね。\n寝起きドッキリを\n仕掛けようとして\nいたのに。残念無念", 0, 1, 1, 2, 1, 1, 138901, 9922);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食を食べずに午後を\n乗り切ろうなんて思わ\nないでくださいね。\n死にたいんですか？", 0, 2, 2, 2, 1, 1, 138901, 9923);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここからは大人の\n時間…さっさと\n寝ないと、枕元で\nポールダンスしますよ", 0, 3, 3, 2, 1, 1, 138901, 9924);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("なかなかのふわふわ\n具合。私のお尻に\nついてるポンポンと\nいい勝負です。やるな", 0, 2, 0, 3, 1, 1, 138901, 9926);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("貴方、ウサギ耳を\nつけてみませんか？\n実は私、仲間を増やし\nたくて暗躍中なんです", 0, 3, 0, 3, 1, 1, 138901, 9927);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…キョウカ\nお嬢様たちと過ごした\n家の匂いみたい…安心\nするんですよね何故か", 0, 4, 0, 3, 1, 1, 138901, 9928);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一発芸。飛んで火に\n入るウサギちゃん！\nって感じで火に飛び\n込むのウケるかな…？", 0, 5, 0, 3, 1, 1, 138901, 9929);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ポールダンスは全身\n運動ですからね。しっ\nかり食べてエネルギー\nを補給しておかないと", 0, 7, 0, 3, 1, 1, 138901, 9931);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『ウサギの飼い方』？\n…やはり騎士氏は私を\n飼いたいとか？　一応\n私も読んでおきますか", 0, 8, 0, 3, 1, 1, 138901, 9932);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キレイなお洋服です\nからちゃんとお手入れ\nもしないと…よし♪", 0, 1, 0, 1, 1, 1, 139001, 9938);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("怖くない幽霊さんも\nいるんですね\n…グレイスさんとか、\nグレイスさんとか…", 0, 2, 0, 1, 1, 1, 139001, 9939);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなとお嬢様ごっこ\n楽しかったな\nまたみんなを誘って\nやってみようかな", 0, 3, 0, 1, 1, 1, 139001, 9940);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お嬢様の練習\nもう少ししようかな\n…誰も見てないよね？\nおほほ、ほほほほっ♪", 0, 4, 0, 1, 1, 1, 139001, 9941);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ネクロマンシーの本\n読んでみようかな\n怖いけど…ゾンビに\n詳しくなれるかも…？", 0, 5, 0, 1, 1, 1, 139001, 9942);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの人が執事に\nなってくれたら…\nどんな感じなんだろ？", 0, 101, 0, 1, 4, 1, 139001, 9943);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("幽霊になっても\n一緒にいたい人…\n…な、なんで\nあの人の顔が…！", 0, 102, 0, 1, 8, 1, 139001, 9944);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日もお勉強手伝って\nくれますか？\nひ、一人でもできます\nけど…ダメですか？", 0, 1, 0, 2, 1, 1, 139001, 9945);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("宿題が終わったら\n一緒に遊びましょう\nだからまずはお勉強！", 0, 2, 0, 2, 1, 1, 139001, 9946);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度の休みは\n図書館に行きましょう\n静かでいいですよ", 0, 3, 0, 2, 1, 1, 139001, 9947);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("手を繋いでください\n鎖の代わりです\n離さないでくださいね", 0, 4, 0, 2, 1, 1, 139001, 9948);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鎖がなくたって\nちゃんと面倒見て\nあげます。あなたの\nこと、心配ですから", 0, 101, 0, 2, 4, 1, 139001, 9949);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日は執事として私に\n付き合ってください\nあ、あくまで\nおままごとですから！", 0, 102, 0, 2, 8, 1, 139001, 9950);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい朝ですね\nじゃなかった…\nいい朝ですわね\nおほほほ♪", 0, 1, 1, 2, 1, 1, 139001, 9951);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("執事、今日のお昼は\nなにかしら？\nなんて…えへへ♪", 0, 2, 2, 2, 1, 1, 139001, 9952);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好なら\n夜更かしも平気…\nん…ふわぁ…", 0, 3, 3, 2, 1, 1, 139001, 9953);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("勉強の休憩時間です\nサボりじゃないです\nちゃんと戻ります", 0, 2, 0, 3, 1, 1, 139001, 9954);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お揃いのドレスを\n着たらかわいいかも♪\nそしたら一緒に\nお出かけもできそう", 0, 3, 0, 3, 1, 1, 139001, 9955);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("青い薔薇の香り\nあったらいいのに…\n探してみようかな", 0, 4, 0, 3, 1, 1, 139001, 9956);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ぽかぽか優しい温かさ\nだけど、ゾンビは\n腐敗が進んじゃう\nのかな…？", 0, 5, 0, 3, 1, 1, 139001, 9957);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("もぐもぐ…お嬢様は\nきっとにんじんも\nピーマンも優雅に\n食べるはず…っ", 0, 7, 0, 3, 1, 1, 139001, 9958);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふしんしゃ取りが\nふしんしゃになる…\n気を付けないと！", 0, 8, 0, 3, 1, 1, 139001, 9959);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("覇瞳天星…\n陛下は自在に\n使いこなしてた\nあたしも必ず…！", 0, 1, 0, 1, 1, 1, 139101, 9960);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鼻血はもう慣れた…\nって言ったら\n負けな気がする…", 0, 2, 0, 1, 1, 1, 139101, 9961);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スズナのメモ\nあたしが言った通りに\n書いてあるのかしら\n全然読めないけど", 0, 3, 0, 1, 1, 1, 139101, 9962);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物レース場で\n魔物が暴走するなんて\n元調教師としては\n見過ごせないわね…", 0, 4, 0, 1, 1, 1, 139101, 9963);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("失敗したって凹んで\nられないわ。スズナの\n言う通りこれも一種の\nアオハルなのかもね", 0, 5, 0, 1, 1, 1, 139101, 9964);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつの未来にさ\nあたしは…いるのかな\n…いたいな、ずっと", 0, 101, 0, 1, 4, 1, 139101, 9965);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あいつのこと考えると\nこの瞳がなくても\n未来が明るく視える\n…何言ってんのあたし", 0, 102, 0, 1, 8, 1, 139101, 9966);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ねえ、一緒におでん\n作りましょ。がんもに\nこんにゃく、大根に卵\nフーフーしてよね？", 0, 1, 0, 2, 1, 1, 139101, 9967);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい？　あの水晶玉で\n視たあたしたちの未来\n二人だけの秘密よ？\n絶対よ？", 0, 2, 0, 2, 1, 1, 139101, 9968);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日も訓練に行くわよ\n休んだらなまっちゃう\nかもしれないでしょ\n付き合いなさい", 0, 3, 0, 2, 1, 1, 139101, 9969);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この瞳の力\nなじんできたかも\nちょっとすごくない？\n褒めていいわよ♪", 0, 4, 0, 2, 1, 1, 139101, 9970);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの時は膝枕ありがと\n今度はあたしがして\nあげる。やってほしい\n時に言いなさい♪", 0, 101, 0, 2, 4, 1, 139101, 9971);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あんたの未来\nあたしが独占するから\n…覚悟しなさいよ", 0, 102, 0, 2, 8, 1, 139101, 9972);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ\n予知しなくても分かる\n今日はいい日になるわ", 0, 1, 1, 2, 1, 1, 139101, 9973);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お腹すいたわ～\n訓練三昧でへとへと\nなんか作って…\nメニューはお任せで", 0, 2, 2, 2, 1, 1, 139101, 9974);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("変な夢見そうで\n寝つけないのよ…\n…別に怖くないけど\n…コラ！頭なでんな！", 0, 3, 3, 2, 1, 1, 139101, 9975);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～…\n頭を休ませないと\n予知がブレるのよ", 0, 2, 0, 3, 1, 1, 139101, 9976);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつかあいつと一緒に\n住むなら部屋に置いて\nみたり…なんちゃって", 0, 3, 0, 3, 1, 1, 139101, 9977);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\n疲れきった頭に\nすっごく沁みるわ…", 0, 4, 0, 3, 1, 1, 139101, 9978);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かいと落ち着くわ\n猫の本能ってやつ？\n陛下は…どうなんだろ", 0, 5, 0, 3, 1, 1, 139101, 9979);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("鼻血の出し過ぎで\n貧血ぎみだわ…\nもう一個食べとこ…", 0, 7, 0, 3, 1, 1, 139101, 9980);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("占い横丁ガイドブック\nランドソルの母特集…\nって、これあたし！？\nいつの間に！？", 0, 8, 0, 3, 1, 1, 139101, 9981);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の勉強を、もっと\nしたいな。大切な人を\n守るためには、強さと\n知識が必要だから", 0, 1, 0, 1, 1, 1, 139201, 9982);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お姉ちゃんが弓を引く\n姿、カッコいいなぁ～\n…あの耳も、すっごく\nかわいいんだよね♪", 0, 2, 0, 1, 1, 1, 139201, 9983);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エリカさんはやっぱり\n頼りになるな。仲間と\nしてそばにいてくれる\nと、すごく心強いんだ", 0, 3, 0, 1, 1, 1, 139201, 9984);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("学校のみんなに、\nアストルムのことを\n話したら…信じて\nもらえるかな…？", 0, 4, 0, 1, 1, 1, 139201, 9985);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物ってたくさん\n種類があるんだね\nおいしいとか、\nおいしくないとか…", 0, 5, 0, 1, 1, 1, 139201, 9986);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この格好、わたしに\n似合ってるかな…？\n学校のみんなが見たら\nびっくりするかも♪", 0, 101, 0, 1, 4, 1, 139201, 9987);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に過ごした時間は\n短いけれど…友だちの\nためなら、いくらでも\nがんばれますっ！", 0, 102, 0, 1, 8, 1, 139201, 9988);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あの子　会いたや\nあの海越えて…♪\nはっ…もしかして今の\n聞いてました…！？", 0, 1, 0, 2, 1, 1, 139201, 9989);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("偶然かもしれないけど\n偶然で終わらせたく\nないんだ。わたしが\nこの世界に来た意味を", 0, 2, 0, 2, 1, 1, 139201, 9990);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔物を食べると健康に\nいいのかな？\nなんだか元気が\n有り余っちゃって…！", 0, 3, 0, 2, 1, 1, 139201, 9991);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ちょっと相談に乗って\nもらっていいですか？\nこの世界だからできる\n戦術を相談したくって", 0, 4, 0, 2, 1, 1, 139201, 9992);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みんなのこと、知り\nたいです。一緒に戦う\nためだけじゃなくて…\n仲良くなりたいから", 0, 101, 0, 2, 4, 1, 139201, 9993);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦車道をやってみませ\nんか？　あなたなら\nきっと立派な戦車道を\n歩めると思うから", 0, 102, 0, 2, 8, 1, 139201, 9994);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます！\n寝坊した時は最悪を\n想定しつつ、次はどう\nするかを考えましょう", 0, 1, 1, 2, 1, 1, 139201, 9995);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ごはんは海鮮に\nしませんか？　街を\nお散歩してたらいい\nお店を見つけたの", 0, 2, 2, 2, 1, 1, 139201, 9996);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ眠る時間だね\n演習があってもなく\nても、睡眠はしっかり\nとりましょうね", 0, 3, 3, 2, 1, 1, 139201, 9997);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか～♪\n車内のクッションに\nこれも足したら\nみんな喜ぶかな♪", 0, 2, 0, 3, 1, 1, 139201, 9998);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わ～、かわいい～♪\n戦車の中に置いておい\nたら、ピンチのときに\n落ち着かせてくれそう", 0, 3, 0, 3, 1, 1, 139201, 9999);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り～♪　ふふ、\n前に見せてもらった\n生け花を思い出すなあ", 0, 4, 0, 3, 1, 1, 139201, 10000);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたまりながら干し\n芋を焼こうかな。おい\nしい匂いに人が集まっ\nてきちゃったりして♪", 0, 5, 0, 3, 1, 1, 139201, 10001);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界は違っても、\nおいしいものはたくさ\nんあるんだ♪　いくら\nでも食べられちゃうな", 0, 7, 0, 3, 1, 1, 139201, 10002);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("魔法の本は内容が難し\nいけど、ちゃんと読ん\nで、なにができるのか\nを理解しなくっちゃ！", 0, 8, 0, 3, 1, 1, 139201, 10003);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("弓の命中率はまだ上げ\nられる。打てば必中、\nその矜持を返上する\nつもりはないからな", 0, 1, 0, 1, 1, 1, 139301, 10004);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("まさか自分に獣の耳が\nあるとはな…慣れると\n便利だが…見た目が\nかわいくて困るな…", 0, 2, 0, 1, 1, 1, 139301, 10005);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界が変わっても\nわたしがやることは\n変わらない。西住流は\nわたしが守る", 0, 3, 0, 1, 1, 1, 139301, 10006);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("積み重ねた訓練が\n裏切ることはない\n自らを信じ、一射に\n魂を込めて放つだけだ", 0, 4, 0, 1, 1, 1, 139301, 10007);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("エリカにはもっと自信\nを持ってほしい。わた\nしが信頼を置き指名し\nた次期隊長なのだから", 0, 5, 0, 1, 1, 1, 139301, 10008);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ほしいのは勝利のみ\n…だが負けることで\n得られるものもある\n難しいものだな", 0, 101, 0, 1, 4, 1, 139301, 10009);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("不確定要素が多い状況\nでなら、みほを隊長に\n推すのは必定。きっと\n力を発揮してくれる", 0, 102, 0, 1, 8, 1, 139301, 10010);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("【美食殿】の活動方針\nには共感を覚えるよ\nおいしい食事は、隊の\n士気を左右するからな", 0, 1, 0, 2, 1, 1, 139301, 10011);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦車でなく生身で戦う\nとなるとあなたたち\nには遠く及ばない\n今後も精進せねばな", 0, 2, 0, 2, 1, 1, 139301, 10012);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この足音は…やはり\nあなたか。マホ姫の\nおかげで、以前よりも\n感覚が磨かれたよ", 0, 3, 0, 2, 1, 1, 139301, 10013);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お互い作戦を伝えたり\n指揮をしたり\nする身だ、\n体調には気を付けよう", 0, 4, 0, 2, 1, 1, 139301, 10014);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("油断大敵だ。数的有利\nだとしても戦術次第で\n対等に戦えるのだから\n…経験から得た教訓だ", 0, 101, 0, 2, 4, 1, 139301, 10015);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あなたの援護には感謝\nしている。想定以上の\n動きができるのは敵に\nとっても脅威だからな", 0, 102, 0, 2, 8, 1, 139301, 10016);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう。朝食は\nしっかりとるように\n腹が減っては戦も\n訓練もできないからな", 0, 1, 1, 2, 1, 1, 139301, 10017);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("みほとエリカを誘って\n昼食にするとしよう\n午後も演習があるし…\nここはカレーにしよう", 0, 2, 2, 2, 1, 1, 139301, 10018);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ就寝時間だ\n健康な心身を保つため\nにも、良質な睡眠は\n欠かせない", 0, 3, 3, 2, 1, 1, 139301, 10019);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("休息時間はまだだぞ\nしかし…うう、この\n柔らかさの誘惑には\n抗いがたいな…", 0, 2, 0, 3, 1, 1, 139301, 10020);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…かわいいな\nボコとは違うがみほの\n好みに近い気がする", 0, 3, 0, 3, 1, 1, 139301, 10021);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香りだ。戦車で\n走る草原の匂い。土の\n匂い…かすかな火薬の\n匂いもする…", 0, 4, 0, 3, 1, 1, 139301, 10022);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あたたかい…そして\n熱い。まるで人の心だ\n誰もが胸に炎を抱えて\nいるものだからな", 0, 5, 0, 3, 1, 1, 139301, 10023);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("泊りがけの演習に持参\nしたいな…食事が質素\nだと悪い結末になるの\nは歴史が証明している", 0, 7, 0, 3, 1, 1, 139301, 10024);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふむ…この世界にある\n戦術が書かれた本か\n興味深い。熟読させて\nもらうとしよう", 0, 8, 0, 3, 1, 1, 139301, 10025);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("双剣使い…いいわね♪\nわたしの戦場は後方\nではなく前線という\nことなのでしょう？", 0, 1, 0, 1, 1, 1, 139401, 10026);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("本来の自分を忘れる\nなんて…不可抗力でも\nあってはならない失敗\nよ…あぁっ、もうっ！", 0, 2, 0, 1, 1, 1, 139401, 10027);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("西住隊長がいる。ただ\nそれだけで安心感が\nある。…わたしもそん\nな隊長になりたいな…", 0, 3, 0, 1, 1, 1, 139401, 10028);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("元副隊長には絶対に\n負けないわ！　競争\nじゃないし今は仲間\nだけど…それでも…！", 0, 4, 0, 1, 1, 1, 139401, 10029);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("双剣の手入れをして\nおこうかしら。今の\nわたしの相棒は、\nこの剣なんだもの", 0, 5, 0, 1, 1, 1, 139401, 10030);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハンバーグは…いいわ\n肉肉しさとジューシー\nな味わいが、わたしに\nパワーをくれるのよね", 0, 101, 0, 1, 4, 1, 139401, 10031);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("相手が誰だろうと\n無様な姿は見せないわ\nそれが私の果たすべき\n責務でしょう？", 0, 102, 0, 1, 8, 1, 139401, 10032);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしがキャルと\n似てる…？\nそんなことないわよ！\n…そうでしょ？", 0, 1, 0, 2, 1, 1, 139401, 10033);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この世界に来られて\n一応感謝してるのよ\n代え難い経験を\nさせてもらったもの", 0, 2, 0, 2, 1, 1, 139401, 10034);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("士気の維持は、みんな\n苦労するのよ。でも、\nあなたはやってのける\n…すごいわ、本当に", 0, 3, 0, 2, 1, 1, 139401, 10035);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("クローチェさんって\n面白い人よね。また\nアイアシェッケを\n採りにいきましょ", 0, 4, 0, 2, 1, 1, 139401, 10036);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰にでも力になりたい\n人はいるわ。わたしに\nも、あなたにも。お互\nい、がんばりましょう", 0, 101, 0, 2, 4, 1, 139401, 10037);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("これだけ長く離れて\nいたからこそ…次に\n乗る時はもっと戦車道\nを突き詰められそうよ", 0, 102, 0, 2, 8, 1, 139401, 10038);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう。朝食は必ず\n食べなさいよ。食事は\n一日の基本だもの\nなにをするにもね", 0, 1, 1, 2, 1, 1, 139401, 10039);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("昼食もだけど、休憩も\n忘れてはだめよ。少し\n眠ると訓練の質が\nあがるのよ…ふわぁ…", 0, 2, 2, 2, 1, 1, 139401, 10040);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ寝たほうが\nいいわ。今日の疲れを\n明日に持ち越すのは\n愚者のすることよ", 0, 3, 3, 2, 1, 1, 139401, 10041);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふかふか…たまらない\nわね…疲れてるときに\n横になったら、逃げ\nられない気がするわ", 0, 2, 0, 3, 1, 1, 139401, 10042);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("守るものがあると人は\n強くなれることもある\n…あなたには我が隊に\n入る許可を与えるわ", 0, 3, 0, 3, 1, 1, 139401, 10043);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はぁ～…心が落ち着く\nいい匂い…エルフの里\nに流れる空気を\n思い出す爽やかさだわ", 0, 4, 0, 3, 1, 1, 139401, 10044);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("見ていると心が穏やか\nになるわ…ケンカした\n相手とも素直に\nなれたりするかしら", 0, 5, 0, 3, 1, 1, 139401, 10045);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいものが無限に\n出てくる？　なんて\n恐ろしいものを置いて\nるの…？　…はむはむ", 0, 7, 0, 3, 1, 1, 139401, 10046);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『おいしいカレーの作\nり方』を読んで新たな\n『エリカレー』を\n隊長に振る舞うわ…！", 0, 8, 0, 3, 1, 1, 139401, 10047);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("掃除のしがいがある\n部屋でしゅね～\nいきましゅよ～！", 0, 1, 0, 1, 1, 1, 136901, 10048);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("タコ足マッサージは\nキャンセル待ちでしゅ\nにゅるにゅるでしゅ♪", 0, 2, 0, 1, 1, 1, 136901, 10049);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たっくしゃんの卵から\n生き残り大きくなった\nラッキーガールでしゅ\nエンギモノでしゅ♪", 0, 3, 0, 1, 1, 1, 136901, 10050);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("姫姉しゃまのところに\n初めて来た時のこと\nかすかに覚えてましゅ", 0, 4, 0, 1, 1, 1, 136901, 10051);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこかにタコ壺を\n置きたいでしゅね\nそうしたらもっと\n快適に過ごせましゅ", 0, 5, 0, 1, 1, 1, 136901, 10052);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士しゃんもお世話が\n必要でしゅ。あたち、\n姫姉しゃまの小姓と\n両方やりましゅ！", 0, 101, 0, 1, 4, 1, 136901, 10053);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("騎士しゃんを見てると\nお腹が空くのは\nどうちてでしょうか\nうじゅ…", 0, 102, 0, 1, 8, 1, 136901, 10054);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しゅけしゅけお洋服は\nおしゃれでせくちー、\n深海ファッションの\nとれんどなんでしゅよ", 0, 1, 0, 2, 1, 1, 136901, 10055);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("小姓は忙ちいんでしゅ\n騎士しゃんも一緒に\nお仕事どうでしゅか？\n小姓一日入門でしゅ！", 0, 2, 0, 2, 1, 1, 136901, 10056);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("部屋に体色を同化して\nカモフラージュ…♪\nうじゅ！？　なんで\n見つかったんでしゅ？", 0, 3, 0, 2, 1, 1, 136901, 10057);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ひゃ、ごめんなしゃい\nデュラ爺しゃん～\n…あれ？　違いまちた\nびっくりちまちたよ！", 0, 4, 0, 2, 1, 1, 136901, 10058);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『イケてるタコには\n毒がある』んでしゅ\nあたちは…持ってない\nでしゅ…うじゅる…", 0, 101, 0, 2, 4, 1, 136901, 10059);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("先のほうはちょっと\nビンカンなので\nやさちく、ぎゅって\nつないでほちいでしゅ", 0, 102, 0, 2, 8, 1, 136901, 10060);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("しゅっきりお目覚め\nくしゅぐりコースで…\nうじゅうじゅうじゅ♪\n逃がしましぇんよ～", 0, 1, 1, 2, 1, 1, 136901, 10061);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("特製タコパスタなら\nすぐご用意できましゅ\nぶちぶちっ！\n…ちぎりすぎまちた", 0, 2, 2, 2, 1, 1, 136901, 10062);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("子守唄を歌いましゅ\n深海の深～い眠りに\nいざなってあげるの\nでしゅ！", 0, 3, 3, 2, 1, 1, 136901, 10063);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("じゅるじゅるじゅる…\nっと、油断すると\nお口が崩れて…\nこうちて…よち、と", 0, 2, 0, 3, 1, 1, 136901, 10065);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いいこいいこ～\nみなしゃんに\nかわいがられる\nマスコットでしゅね～", 0, 3, 0, 3, 1, 1, 136901, 10066);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふわ～いい香りでしゅ\nお肌も、足も、\nちっとりぬるぬる、\nぷるぷるでしゅ～", 0, 4, 0, 3, 1, 1, 136901, 10067);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どこからか焼きタコの\n香ばしい匂いが…♪\nうじゅ！？\nあたちからでちた！", 0, 5, 0, 3, 1, 1, 136901, 10068);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここに、もうひと味…\nぱっぱっぱ、っと♪\nコショーはやっぱり\n役に立ちましゅ", 0, 7, 0, 3, 1, 1, 136901, 10070);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("王子しゃまを好きに\nなった人魚しゃん…\n一緒に海に帰らな\nかったんでしゅね…", 0, 8, 0, 3, 1, 1, 136901, 10071);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("スミレ様にはお世話に\nなってばかりで…\nいつかこのご恩を\nお返ししたいです", 0, 1, 0, 1, 1, 1, 139501, 10077);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様の周りは強いお方\nばかり。皆様について\nいくためにも、より\n強い自分になります", 0, 2, 0, 1, 1, 1, 139501, 10078);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("多くの人に笑顔に\nなってもらいたい\nわたくしの力は、その\nために使いたいのです", 0, 3, 0, 1, 1, 1, 139501, 10079);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『繋がりの巫女』の\n力で外出中の兄様と\n会話ができたりも…？\nもっと修業します…！", 0, 4, 0, 1, 1, 1, 139501, 10080);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…今は羽を休める\nとしましょう。ギルド\nハウスでは常在戦場も\n少しだけ緩めて…", 0, 5, 0, 1, 1, 1, 139501, 10081);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("妄想に似た理想は、\nいりません。等身大の\n兄様だけを、この瞳に\n映し続けたいのです", 0, 101, 0, 1, 4, 1, 139501, 10082);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("…お帰りになるまで\nあと何分でしょう？\n一日千秋の思いで\nお待ちしております", 0, 102, 0, 1, 8, 1, 139501, 10083);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("白と黒だとどちらが\n好きですか？　兄様の\n好みを知りたくて…\nあ、服装の話ですよ？", 0, 1, 0, 2, 1, 1, 139501, 10084);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄様のことをもっと\n教えてくださいませ\nたとえば…味の好みや\n寝る時の格好なども", 0, 2, 0, 2, 1, 1, 139501, 10085);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("戦場の誉れもうれしい\nものですが、兄様から\nのお言葉がなによりも\nうれしいのです", 0, 3, 0, 2, 1, 1, 139501, 10086);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("抜けた羽で羽毛布団を\n作れないでしょうか？\nもちろん作った布団は\n兄様に贈ります…♪", 0, 4, 0, 2, 1, 1, 139501, 10087);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("また、お手合わせを\nお願いします、兄様\n…稽古のときは二人で\nいられますから…♪", 0, 101, 0, 2, 4, 1, 139501, 10088);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("白は、何色にでも\n染まることができる色\nどうぞ、兄様が思う\nように染めてください", 0, 102, 0, 2, 8, 1, 139501, 10089);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはようございます\n今日も兄様に朝から\nご挨拶ができて、\nわたくしは幸福です♪", 0, 1, 1, 2, 1, 1, 139501, 10090);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ご飯を食べて、\n今は羽を休めましょう\n宜しければ、わたくし\n手料理に挑戦をっ…", 0, 2, 2, 2, 1, 1, 139501, 10091);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("そろそろ就寝の時間\nですね。成長するため\nには、修業だけでなく\n睡眠も大事です", 0, 3, 3, 2, 1, 1, 139501, 10092);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あぁ…なんという\nふかふかさ…いくら\n修業を重ねてもこれに\n抗うことは不可能です", 0, 2, 0, 3, 1, 1, 139501, 10094);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("無生物とも『繋がる』\nことはできるのでしょ\nうか…？　試して\nみたいと思います", 0, 3, 0, 3, 1, 1, 139501, 10095);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…嗅いでいる\nと自然の中にいるよう\nで、集中したいときに\n重宝しそうです", 0, 4, 0, 3, 1, 1, 139501, 10096);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("滝行の後は体が冷えて\nしまって…はぁ…♪\nぽかぽかで、心まで\n温かくなります…♪", 0, 5, 0, 3, 1, 1, 139501, 10097);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("最近はカロリー消費が\n多いことばかりなので\nたくさん食べられます\n…もぐもぐっ♪", 0, 7, 0, 3, 1, 1, 139501, 10099);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("『薔薇の下の契り』？\nだ、男性同士で…！？\nこのような観念が\n存在していたとは…っ", 0, 8, 0, 3, 1, 1, 139501, 10100);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("かえる、ばしょ\nかえり、まつ、ばしょ\nいつでも、きれいに\nめざせ、しゅふ", 0, 1, 0, 1, 1, 1, 139701, 10106);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つばさ、おそろい\nハッピーちゃんと\nうれしみ", 0, 2, 0, 1, 1, 1, 139701, 10107);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このやり、ふぉーく\nないふ、も\nひつよう、なので\nリリのやり、かりるね", 0, 3, 0, 1, 1, 1, 139701, 10108);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("はね、おちる\nいつの、まにか\nたいへん、おそうじ", 0, 4, 0, 1, 1, 1, 139701, 10109);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄の、かえり。まつ\nおふろ、じゅんび\nきっと、よろこぶ", 0, 5, 0, 1, 1, 1, 139701, 10110);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パパ。はなし、たい\nよんでみよ\nまほうじん、かく。", 0, 101, 0, 1, 4, 1, 139701, 10111);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしたち、なかよし\nまぶだち、こえてる\nじっしつ、ふうふ？", 0, 102, 0, 1, 8, 1, 139701, 10112);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄、おかえり\nつかれて、ない？\nまっさーじ、する？", 0, 1, 0, 2, 1, 1, 139701, 10113);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("つばさ、おおきい\nうで、とどかない\nお兄。リボン、よろ", 0, 2, 0, 2, 1, 1, 139701, 10114);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おいしいもの\nどこか、ないかな\nあ、お兄。みっけ", 0, 3, 0, 2, 1, 1, 139701, 10115);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("このやり、つかって\nちーず、ふぉんでゅ\nしよう、お兄", 0, 4, 0, 2, 1, 1, 139701, 10116);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄。どこにも\nいかないで\nまつの、さびしい", 0, 101, 0, 2, 4, 1, 139701, 10117);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄、ほめて\nそうじ、せいとん\nかんりょう", 0, 102, 0, 2, 8, 1, 139701, 10118);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよ\nあさごはん、べーこん\n…ハッピーちゃん？", 0, 1, 1, 2, 1, 1, 139701, 10119);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふあ…ちょい、ねむ\nらんち、まんぷく\nお兄。おひるね、しよ", 0, 2, 2, 2, 1, 1, 139701, 10120);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("よぞら、おさんぽ\nほし、きらきら\nきれい", 0, 3, 3, 2, 1, 1, 139701, 10121);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("すわる、ねる\nつばさ、ぽじしょん\nなやむ。いつも", 0, 2, 0, 3, 1, 1, 139701, 10123);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いつも、あざます\nだっこ、させてくれて\nこんごとも、よろ", 0, 3, 0, 3, 1, 1, 139701, 10124);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしの、つばさ。も\nいいにおい、する\nおひさま、みたい", 0, 4, 0, 3, 1, 1, 139701, 10125);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハッピーちゃん\nやけど、気をつけて\nちゃーしゅー、なる", 0, 5, 0, 3, 1, 1, 139701, 10126);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("うぷ。\nおなか、はちきれ\nしあわせと、ひきかえ", 0, 7, 0, 3, 1, 1, 139701, 10128);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("パパがくれた、ほん\nちょいむず\nおとなの、かいだん", 0, 8, 0, 3, 1, 1, 139701, 10129);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("槍のお手入れって\nお花の世話に似てます\n心を込めてこまめに…\n人の心も同じですね", 0, 1, 0, 1, 1, 1, 139601, 10135);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("帰る場所があるって…\n帰りたい所があるって\n幸せなことですね…♪", 0, 2, 0, 1, 1, 1, 139601, 10136);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("総長ちゃんって\n呼ばれるの、慣れない\nけど…実はちょっと\n気に入ってます♪", 0, 3, 0, 1, 1, 1, 139601, 10137);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日の夕飯は\nメンチカツに\nしようかな？", 0, 4, 0, 1, 1, 1, 139601, 10138);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("モネちゃんにもらった\n髪飾りつけて、一緒に\nお出かけしたいな…♪\n今度誘ってみよう", 0, 5, 0, 1, 1, 1, 139601, 10139);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ホンネで話すのって\n恥ずかしいけど…\nもっと仲良くなれる\n気がします", 0, 101, 0, 1, 4, 1, 139601, 10140);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("聖女なんかじゃなくて\n戦乙女として、\n一緒に戦いたい\n後悔しないためにも", 0, 102, 0, 1, 8, 1, 139601, 10141);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("誰かを癒すこと…もう\n躊躇いません。だから\n小さなケガでも教えて\nくださいね？", 0, 1, 0, 2, 1, 1, 139601, 10142);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたし、悪い子です\nわたしを甘やかす\nお兄さんも共犯者\nですよ。ふふっ…", 0, 2, 0, 2, 1, 1, 139601, 10143);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ヴァルキュリア…\n部屋の中だとちょっと\n窮屈ですかね…？", 0, 3, 0, 2, 1, 1, 139601, 10144);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あ、お部屋に羽根が…\nわたしが居た証拠？\n…じゃなくって、\nすぐお掃除しますねっ", 0, 4, 0, 2, 1, 1, 139601, 10145);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お兄さん、また\n二人でお出かけ\nしたいです…♪", 0, 101, 0, 2, 4, 1, 139601, 10146);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("一緒に空飛びます？\nわたしがお兄さんを\n抱っこして\nあげますよ～っ♪", 0, 102, 0, 2, 8, 1, 139601, 10147);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今日一日、\nお兄さんのこと\n独り占めして\nいいですか？", 0, 1, 1, 2, 1, 1, 139601, 10148);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼ですよ。ごはん\n食べに行きませんか？\n今日は、二人だけで\nあ、明日も明後日も♪", 0, 2, 2, 2, 1, 1, 139601, 10149);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("わたしが寝かしつけて\nあげます♪\nえへへ、ひそかな夢\nだったんです、実は", 0, 3, 3, 2, 1, 1, 139601, 10150);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふぅ…\n羽も心も\n休まります…", 0, 2, 0, 3, 1, 1, 139601, 10152);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この子もちょっと\nあざといんじゃない\nかな～？\n仲間ですねっえへへ♪", 0, 3, 0, 3, 1, 1, 139601, 10153);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り♪\n今度お兄さんに\n教えてあげたいな", 0, 4, 0, 3, 1, 1, 139601, 10154);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あったかくて\nしあわせで\nお兄さんのこと\n思い出しちゃう", 0, 5, 0, 3, 1, 1, 139601, 10155);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("たくさん食べて\n体力つけようっと\n恋も戦いも、\n体が資本だから", 0, 7, 0, 3, 1, 1, 139601, 10157);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こ、恋占いの本\n読んじゃおっかな…\nわたしとお兄さんの\n相性は…ドキドキ", 0, 8, 0, 3, 1, 1, 139601, 10158);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この姿だと冷凍\nトゥンヌスが素早く\n完璧に作れるみたい\n覚醒の無駄遣いかしら", 0, 1, 0, 1, 1, 1, 139801, 10164);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("兄さんは私の\n赤ちゃん化のこと\nどう思ってたんだろう\n怖くて聞けないけど…", 0, 2, 0, 1, 1, 1, 139801, 10165);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("コッコロマ…っ\n…いけない、また\n口が滑っちゃった…\n覚醒でもダメなのね…", 0, 3, 0, 1, 1, 1, 139801, 10166);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("プレシアちゃんに\n「せんぱい」って…\nふふ、悪くないわね", 0, 4, 0, 1, 1, 1, 139801, 10167);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("アイス食べたいわ\nチョコミントのダブル\n特訓で頑張ったご褒美\nってことにしましょ♪", 0, 5, 0, 1, 1, 1, 139801, 10168);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("甘える練習、なかなか\n難しかったわ。今度は\nどんな風に甘えよう…\nはっ、癖になってる…", 0, 101, 0, 1, 4, 1, 139801, 10169);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("好きって気持ち、\n抑えきれなくなってる\nこれって覚醒の副作用\nだったりしないわよね", 0, 102, 0, 1, 8, 1, 139801, 10170);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("腕の紋章も大きくなる\nって不思議ね。成長の\n証？　あなたが言うと\n誇らしく思えるわね♪", 0, 1, 0, 2, 1, 1, 139801, 10171);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("今度一緒に空を飛んで\nみない？　大丈夫\n私が抱えてあげる\n大きい翼が役に立つわ", 0, 2, 0, 2, 1, 1, 139801, 10172);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("覚醒するとお腹が減る\nなんて知らなかったわ\nペコリーヌさんは共感\nしてくれたけど…", 0, 3, 0, 2, 1, 1, 139801, 10173);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("キャルが翼の手入れの\n仕方を教えてくれたの\nこれって猫の毛繕い\nみたいなものかしら？", 0, 4, 0, 2, 1, 1, 139801, 10174);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この翼であなたを\n守りたい…でも本当は\nあなたが私を守って\nくれてるのよね…♪", 0, 101, 0, 2, 4, 1, 139801, 10175);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ね…、ちょっとだけ\n甘えてもいい？\n兄さんに甘えるのとは\n違う甘え方で…", 0, 102, 0, 2, 8, 1, 139801, 10176);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい朝ね。朝日が\n眩しくて二度寝でき\nないなら、翼で日陰を\n作ってあげるわよ？", 0, 1, 1, 2, 1, 1, 139801, 10177);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お昼はお弁当を持って\nどこか行かない？\n兄さんも誘って３人で", 0, 2, 2, 2, 1, 1, 139801, 10178);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("夜遅くまで起きて…\n眠れないの？\n…私が子守唄、歌う？", 0, 3, 3, 2, 1, 1, 139801, 10179);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ここでなら\n赤ちゃん化しても\n安全…よね？", 0, 2, 0, 3, 1, 1, 139801, 10181);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふ、かわいい…\nホマレさんに見せたら\nスケッチされそうね", 0, 3, 0, 3, 1, 1, 139801, 10182);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("いい香り…\n…チョコミントの\nアロマとかないかしら", 0, 4, 0, 3, 1, 1, 139801, 10183);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("温かくて落ち着くわ\n彼の隣にいるときと\n同じぬくもり…\nなんてね", 0, 5, 0, 3, 1, 1, 139801, 10184);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("覚醒してると\n消耗が激しくて…\nホマレさんを\n見習わなきゃね", 0, 7, 0, 3, 1, 1, 139801, 10186);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("恋愛の指南書、一冊\n読んでみようかな\n「甘え上手な彼女に\nなる方法」ふむふむ…", 0, 8, 0, 3, 1, 1, 139801, 10187);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("こっちの過激な水着は\n最終兵器として、\nとっておこうっと", 0, 1, 0, 1, 1, 1, 139901, 10193);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダーリンのために特製\nトロピカルドリンクを\n錬成しておかなくちゃ\nいつでも飲めるように", 0, 2, 0, 1, 1, 1, 139901, 10194);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("お部屋で水着…\nもしかして私って\nすごく破廉恥！？", 0, 3, 0, 1, 1, 1, 139901, 10195);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("塩飴の錬成完了！\n暑い日のお出かけも\nばっちりね", 0, 4, 0, 1, 1, 1, 139901, 10196);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("イロハちゃんと\nソノさんの水着も\n錬成できたわ！", 0, 5, 0, 1, 1, 1, 139901, 10197);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ダーリンの視線を\n釘付けにするポーズ…\nこ、こうかしら？", 0, 101, 0, 1, 4, 1, 139901, 10198);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ふふっ\nダーリンの帰りを\n水着姿でお出迎え♪\n刺激が強すぎるかな…", 0, 102, 0, 1, 8, 1, 139901, 10199);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("大人の階段…\n大人の階段…\nち、違っ！階段で昇降\n運動しようと思って！", 0, 1, 0, 2, 1, 1, 139901, 10200);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("バ、バナナボートって\nなんだか…ううん\n分からないならいいの", 0, 2, 0, 2, 1, 1, 139901, 10201);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("私、この夏が人生で\n一番楽しいわ。だって\nあなたがいるから", 0, 3, 0, 2, 1, 1, 139901, 10202);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("桃色の本が落ちてた？\nわ、私のじゃないわ\nでも預かっておくわね", 0, 4, 0, 2, 1, 1, 139901, 10203);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("カップルストローを\n買ってきちゃった\nまた一緒に飲まない？", 0, 101, 0, 2, 4, 1, 139901, 10204);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("世界で一番\n水着が似合う女の子に\nなってみせるわ\n楽しみにしてて♪", 0, 102, 0, 2, 8, 1, 139901, 10205);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("おはよう。わ、寝汗\nすごいわね！　制汗の\n秘薬を塗ってあげる", 0, 1, 1, 2, 1, 1, 139901, 10206);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("どんなに暑くても\n私はあなたと\nくっついてたいな♪", 0, 2, 2, 2, 1, 1, 139901, 10207);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("ハート型の花火を\n買ったの。まるで\n私たちの心みたいね♪", 0, 3, 3, 2, 1, 1, 139901, 10208);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("セクシーな\n寝ころびポーズで\nダーリンを悩殺よ♪", 0, 2, 0, 3, 1, 1, 139901, 10210);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("派手な水着に\nキュートなぬいぐるみ\nいい組み合わせかも♪", 0, 3, 0, 3, 1, 1, 139901, 10211);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くんくん…\n汗の匂い大丈夫かな…\nこれでいい匂いに\nなったよね？", 0, 4, 0, 3, 1, 1, 139901, 10212);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あつっ！　水着で\n近づいたらお肌が\nヒリヒリしちゃう…", 0, 5, 0, 3, 1, 1, 139901, 10213);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("くびれが気になるけど\n食べるときはしっかり\n食べないと…ね？", 0, 7, 0, 3, 1, 1, 139901, 10215);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("マサオはミツコの\n水着をずらし…ごくり\nす、すごい本だわ！", 0, 8, 0, 3, 1, 1, 139901, 10216);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("あっ、背中の突起が\n当たって…\nく、くすぐったい…", 0, 10, 0, 3, 1, 1, 139901, 10218);
INSERT INTO `v1_32cc6538b740a413ca16800f62f411ff3f1c3a5e4efce74d466af1bc281a7147` VALUES ("この上でダーリンと\nいちゃいちゃ…\nへ、えへへ…", 0, 11, 0, 3, 1, 1, 139901, 10219);
